    # Test/CI fallback: real app still uses Streamlit when installed.
    class _DummyContext:
        def __enter__(self):
            return self
        def __exit__(self, exc_type, exc, tb):
            return False

    class _DummyStreamlit:
        session_state: dict[str, Any] = {}
        sidebar = _DummyContext()
        def cache_data(self, *args, **kwargs):
            def decorator(func):
                return func
            if args and callable(args[0]) and len(args) == 1 and not kwargs:
                return args[0]
            return decorator
        def __getattr__(self, name):
            if name in {"columns", "tabs"}:
                def _cols(spec, *args, **kwargs):
                    n = spec if isinstance(spec, int) else len(spec)
                    return [_DummyContext() for _ in range(max(int(n), 1))]
                return _cols
            if name in {"expander", "container", "form", "popover"}:
                return lambda *args, **kwargs: _DummyContext()
            if name in {"radio", "selectbox", "number_input", "text_input", "date_input", "checkbox", "slider"}:
                return lambda *args, **kwargs: kwargs.get("value", args[1][0] if name in {"radio", "selectbox"} and len(args) > 1 and args[1] else None)
            return lambda *args, **kwargs: None

    class _DummyComponents:
        def html(self, *args, **kwargs):
            return None

    st = _DummyStreamlit()
    components = _DummyComponents()
