@st.cache_data(ttl=60, show_spinner=False)
def load_json_cached(path_str: str, mtime_ns: int = 0, file_size: int = 0) -> dict[str, Any]:
    path = Path(path_str)
    if file_size <= 0 or not path.exists():
        return {}
    try:
        data = json.loads(path.read_text(encoding="utf-8-sig"))
        return data if isinstance(data, dict) else {}
    except Exception:
        try:
            data = json.loads(path.read_text(encoding="utf-8"))
            return data if isinstance(data, dict) else {}
        except Exception:
            return {}


@st.cache_data(ttl=60, show_spinner=False)
def load_csv_cached(path_str: str, mtime_ns: int = 0, file_size: int = 0, dtype_str: bool = True) -> pd.DataFrame:
    path = Path(path_str)
    if file_size <= 0 or not path.exists():
        return pd.DataFrame()
    kwargs: dict[str, Any] = {"low_memory": False}
    if dtype_str:
        kwargs["dtype"] = str
    for encoding in ("utf-8-sig", "utf-8", "cp949"):
        try:
            return pd.read_csv(path, encoding=encoding, **kwargs).fillna("")
        except Exception:
            continue
    return pd.DataFrame()


def _file_cache_token(path: Path) -> tuple[int, int]:
    try:
        stat = path.stat()
        return int(stat.st_mtime_ns), int(stat.st_size)
    except Exception:
        return 0, 0


def read_json_cached(path: Path) -> dict[str, Any]:
    mtime_ns, file_size = _file_cache_token(path)
    data = load_json_cached(str(path), mtime_ns, file_size)
    return dict(data) if isinstance(data, dict) else {}


def read_csv_cached(path: Path, *, dtype_str: bool = True) -> pd.DataFrame:
    mtime_ns, file_size = _file_cache_token(path)
    return load_csv_cached(str(path), mtime_ns, file_size, dtype_str).copy()


