def _inject_app_bootstrap_css() -> None:
    """첫 프레임이 검은 빈 화면으로 보이지 않도록 최소 배경·로딩 패널 스타일을 주입한다."""
    st.markdown(
        """
        <style>
        [data-testid="stAppViewContainer"], [data-testid="stMain"], .main {
            background: #08111f !important;
            color: #f3f7ff !important;
        }
        .app-bootstrap-panel {
            border: 1px solid rgba(148,163,184,.22);
            border-radius: 14px;
            padding: 14px 16px;
            margin: 0 0 12px 0;
            background: linear-gradient(135deg, rgba(30,64,175,.18), rgba(15,23,42,.72));
            color: #e2e8f0;
            font-weight: 700;
        }
        .app-bootstrap-muted { color: #94a3b8; font-size: .86rem; margin-top: 6px; }
        </style>
        """,
        unsafe_allow_html=True,
    )


def _render_app_bootstrap_loading(stage_index: int = 0) -> Any:
    """상단 로딩 플레이스홀더. graft 라우터가 단계별로 갱신한 뒤 비운다."""
    idx = max(0, min(int(stage_index), len(_APP_BOOTSTRAP_STAGE_MESSAGES) - 1))
    msg = _APP_BOOTSTRAP_STAGE_MESSAGES[idx]
    hint = _APP_BOOTSTRAP_STAGE_MESSAGES[min(idx + 1, len(_APP_BOOTSTRAP_STAGE_MESSAGES) - 1)]
    ph = st.empty()
    with ph.container():
        st.markdown(
            f'<div class="app-bootstrap-panel">{msg}</div>'
            f'<div class="app-bootstrap-muted">다음: {hint}</div>',
            unsafe_allow_html=True,
        )
    return ph


def _update_app_bootstrap_loading(placeholder: Any, stage_index: int) -> None:
    if placeholder is None:
        return
    idx = max(0, min(int(stage_index), len(_APP_BOOTSTRAP_STAGE_MESSAGES) - 1))
    msg = _APP_BOOTSTRAP_STAGE_MESSAGES[idx]
    with placeholder.container():
        st.markdown(f'<div class="app-bootstrap-panel">{msg}</div>', unsafe_allow_html=True)


def _clear_app_bootstrap_loading(placeholder: Any) -> None:
    if placeholder is not None:
        placeholder.empty()


def _page_data_tier(page_id: str) -> str:
    if page_id in {"page_home", "page_today_summary", "page_daily_plan", "page_premarket"}:
        return "home"
    if page_id == "page_probability":
        return "probability"
    if page_id.startswith("page_intraday_"):
        return "intraday"
    if page_id in {"page_update_full", "page_swing_board", "page_stock_quality", "page_catalyst", "page_historical", "page_chase_risk", "page_strong_watch", "page_sell_hold"}:
        return "swing_reports"
    if page_id in {"page_holdings", "page_holdings_pnl", "page_buy_decision", "page_sell_decision", "page_ranking", "page_buy_dashboard"}:
        return "predictions"
    if page_id == "page_watch_chart":
        return "watch_charts"
    if page_id == "page_symbol_chart":
        return "symbol_chart"
    return "light"


def _lazy_load_page_data(page_id: str, market: str | None = None) -> None:
    """사이드바 화면 전환 시 해당 페이지에 필요한 reports만 선로드 (mtime 캐시 활용)."""
    prev = st.session_state.get("_active_nav_page_id")
    if prev != page_id:
        st.session_state["_active_nav_page_id"] = page_id
    tier = _page_data_tier(page_id)
    st.session_state["_page_data_tier"] = tier
    if tier == "home":
        for path in (
            REPORT_DIR / "market_regime_summary.json",
            REPORT_DIR / "daily_quality_summary.json",
            REPORT_DIR / "portfolio_risk_summary.json",
            REPORT_DIR / "api_data_quality_summary.json",
        ):
            _safe_report_json(path)
    elif tier == "probability" or tier == "swing_reports":
        if market:
            _load_swing_candidate_reports(market)
    elif tier == "intraday":
        for path in (
            REPORT_DIR / "intraday_realtime_summary.json",
            REPORT_DIR / "intraday_data_coverage_diagnosis.json",
        ):
            _safe_report_json(path)
    elif tier == "predictions":
        try:
            load_prediction_log()
        except Exception:
            pass


def clear_report_file_caches() -> None:
    """수동 갱신·장중 리프레시 후 reports 재읽기."""
    st.cache_data.clear()
    for key in ("_home_json_preloaded", "_active_nav_page_id", "_page_data_tier"):
        st.session_state.pop(key, None)


