def render_standard_score_panel(row: Any, market: str, extra_context: dict[str, Any] | None = None) -> None:
    """표준 100점 점수표를 한 종목/예측행 기준으로 표시한다."""
    from core.standard_score_engine import calculate_standard_100_score

    result = calculate_standard_100_score(row, market, extra_context=extra_context)
    m1, m2, m3 = st.columns(3)
    m1.metric("최종 점수", f"{result.get('total_score', 0)}점 / 100점")
    m2.metric("판단 등급", str(result.get("grade", "관망 우위")))
    m3.metric("최종 판단", str(result.get("final_judgment", "관망 우위")))
    missing = result.get("missing_items", []) or []
    if missing:
        st.warning("확인 필요 항목: " + " / ".join(map(str, missing)))
    table = pd.DataFrame(result.get("items", []))
    if table.empty:
        st.info("표준 점수표를 만들 데이터가 부족합니다.")
    else:
        st.dataframe(table[["항목", "점수", "배점", "상태", "해석"]], use_container_width=True, hide_index=True)


def render_risk_decision_panel(row: Any, market: str = "", extra_context: dict[str, Any] | None = None) -> None:
    """리스크 필터 최종 판단을 보수적 실전 운용 관점으로 표시한다."""
    extra_context = extra_context or {}
    try:
        from core.risk_decision_engine import final_risk_decision_engine, news_quality_filter, overheating_filter, rr_filter

        data = dict(row.to_dict() if hasattr(row, "to_dict") else dict(row or {}))
        if not str(data.get("risk_final_decision", "")).strip():
            overheat_result = overheating_filter(data)
            rr_result = rr_filter(
                {
                    "entry_price": data.get("preferred_entry", data.get("entry_price")),
                    "stop_loss": data.get("stop_loss"),
                    "take_profit1": data.get("take_profit1"),
                }
            )
            news_result = news_quality_filter(data)
            risk_result = final_risk_decision_engine(
                {
                    **data,
                    "base_decision": data.get("final_decision_after_no_buy_filter") or data.get("final_judgment") or data.get("primary_action"),
                    "confidence_score": data.get("confidence_score_after_no_buy_filter", data.get("confidence_score")),
                    "overheat_result": overheat_result,
                    "rr_result": rr_result,
                    "news_result": news_result,
                    "data_missing_items": data.get("risk_missing_items", "").split("/") if data.get("risk_missing_items") else [],
                }
            )
            data.update(
                {
                    "risk_final_decision": risk_result.get("risk_final_decision", "관망 우위"),
                    "risk_confidence_score": risk_result.get("risk_confidence_score", 0),
                    "risk_decision_reasons": " / ".join(map(str, risk_result.get("risk_decision_reasons", []))),
                    "risk_warning_flags": " / ".join(map(str, risk_result.get("risk_warning_flags", []))),
                    "risk_missing_items": " / ".join(map(str, risk_result.get("missing_items", []))),
                    "overheat_level": overheat_result.get("overheat_level", ""),
                    "overheat_reasons": " / ".join(map(str, overheat_result.get("overheat_reasons", []))),
                    "chase_risk": int(bool(overheat_result.get("chase_risk"))),
                    "rr": rr_result.get("rr", ""),
                    "rr_level": rr_result.get("rr_level", ""),
                    "rr_pass": int(bool(rr_result.get("rr_pass"))),
                    "news_grade": news_result.get("news_grade", "Unknown"),
                    "sell_the_news_risk": int(bool(news_result.get("sell_the_news_risk"))),
                }
            )
        m1, m2, m3, m4 = st.columns(4)
        m1.metric("리스크 필터 최종 판단", str(data.get("risk_final_decision") or "관망 우위"))
        m2.metric("리스크 신뢰도", f"{safe_float(data.get('risk_confidence_score'), 0):.0f}점")
        m3.metric("과열도", str(data.get("overheat_level") or "확인 필요"))
        rr_text = str(data.get("rr_level") or "확인 필요")
        rr_value = safe_float(data.get("rr"), np.nan)
        if not np.isnan(rr_value):
            rr_text = f"{rr_text} / {rr_value:.2f}"
        m4.metric("손익비", rr_text)
        st.dataframe(
            pd.DataFrame(
                [
                    {
                        "최종 판단": data.get("risk_final_decision", "관망 우위"),
                        "신뢰도": data.get("risk_confidence_score", ""),
                        "과열도": data.get("overheat_level", ""),
                        "과열 사유": data.get("overheat_reasons", ""),
                        "추격 위험": data.get("chase_risk", ""),
                        "손익비": data.get("rr", ""),
                        "손익비 등급": data.get("rr_level", ""),
                        "손익비 통과": data.get("rr_pass", ""),
                        "뉴스 등급": data.get("news_grade", "Unknown"),
                        "뉴스 선반영": data.get("sell_the_news_risk", ""),
                        "경고": data.get("risk_warning_flags", ""),
                        "판단 이유": data.get("risk_decision_reasons", ""),
                        "데이터 부족": data.get("risk_missing_items", ""),
                    }
                ]
            ),
            use_container_width=True,
            hide_index=True,
        )
    except Exception as exc:
        st.warning(f"리스크 필터 최종 판단을 표시하지 못했습니다. 보수적으로 관망 우위로 확인하세요. ({exc})")


def render_news_quality_panel() -> None:
    """뉴스 3분류/리스크 분류를 수동 확인하는 보조 패널."""
    from core.standard_score_engine import classify_news_quality

    st.markdown("#### 뉴스 3분류")
    title = st.text_input("뉴스 제목", value="", key="standard_news_quality_title")
    snippet = st.text_area("뉴스 본문/요약", value="", height=90, key="standard_news_quality_snippet")
    linked = st.checkbox("공시로 확인된 뉴스", value=False, key="standard_news_quality_disclosure")
    if title or snippet:
        info = classify_news_quality(title, snippet, linked_disclosure=linked)
        st.dataframe(pd.DataFrame([info]), use_container_width=True, hide_index=True)
    else:
        st.info("뉴스 제목이나 요약을 입력하면 일회성/실적 연결/구조적 변화/리스크 뉴스로 분류합니다.")


def enrich_news_quality_items_for_app(items: list[dict[str, Any]] | None) -> list[dict[str, Any]]:
    """기존 뉴스 수집 결과에 뉴스 유형/품질 필드를 추가한다. 실패해도 원본을 그대로 반환한다."""
    try:
        from core.standard_score_engine import enrich_news_quality_items

        return enrich_news_quality_items(items or [])
    except Exception:
        return list(items or [])


def render_standard_score_review_page() -> None:
    """최근 예측행 기준 표준 점수와 뉴스 분류를 검토한다."""
    _render_inner_page_heading("표준 점수/뉴스 분류", as_subheader=True)
    st.caption("기존 예측값, 보정, 시장필터, 매수금지 결과를 삭제하지 않고 100점 기준 보조 점수표로만 표시합니다.")
    pred_path = _ops_first_existing_path([
        Path("predictions.csv"),
        Path("data/predictions.csv"),
        Path("data/decision_system/predictions.csv"),
        Path("stock_ai_app_new/data/predictions.csv"),
    ])
    if pred_path is None:
        st.info("predictions.csv가 없어 표준 점수표를 표시할 수 없습니다.")
        with st.expander("뉴스 3분류 수동 확인", expanded=False):
            render_news_quality_panel()
        return

    df = _read_error_review_csv(pred_path)
    if df.empty:
        st.info(f"{pred_path} 파일이 비어 있습니다.")
        return
    recent = df.tail(500).copy()
    ticker_col = next((c for c in ["ticker", "symbol", "종목코드", "종목"] if c in recent.columns), "")
    market_col = next((c for c in ["market", "시장"] if c in recent.columns), "")
    labels = []
    for i, row in recent.reset_index(drop=True).iterrows():
        ticker = str(row.get(ticker_col, "")) if ticker_col else str(i)
        target = str(row.get("target_date", row.get("date", "")))
        decision = str(row.get("final_decision_after_no_buy_filter", row.get("final_decision", "")))
        labels.append(f"{i}: {ticker} {target} {decision}".strip())
    selected = st.selectbox("표준 점수표를 볼 최근 예측행", labels, index=max(0, len(labels) - 1), key="standard_score_prediction_row")
    idx = int(str(selected).split(":", 1)[0])
    row = recent.reset_index(drop=True).iloc[idx]
    ticker_value = str(row.get(ticker_col, "")) if ticker_col else ""
    market = str(row.get(market_col, "")) if market_col else ""
    if not market:
        market = "미국주식" if re.match(r"^[A-Za-z.\-]+$", ticker_value) else "한국주식"
    with st.expander("리스크 필터 최종 판단", expanded=True):
        render_risk_decision_panel(row, market)
    with st.expander("표준 100점 항목별 점수표", expanded=True):
        render_standard_score_panel(row, market)
    with st.expander("뉴스 3분류 수동 확인", expanded=False):
        render_news_quality_panel()
    with st.expander("원본 예측행", expanded=False):
        st.dataframe(pd.DataFrame([row.to_dict()]), use_container_width=True, hide_index=True)


def render_portfolio_allocation_panel(holdings_df: pd.DataFrame, market_context: dict[str, Any] | None = None) -> None:
    """보유종목 현재 평가금액 기준 권장 비중을 보조 평가한다."""
    from core.portfolio_allocation_engine import detect_portfolio_concentration, evaluate_portfolio_allocation

    if holdings_df is None or holdings_df.empty:
        st.info("보유종목 데이터가 없어 권장비중을 계산할 수 없습니다.")
        return
    alloc = evaluate_portfolio_allocation(holdings_df, market_context=market_context)
    if alloc.empty:
        st.info("평가금액 데이터가 부족해 권장비중을 계산하지 못했습니다.")
        return
    st.dataframe(alloc, use_container_width=True, hide_index=True)
    notes = detect_portfolio_concentration(holdings_df)
    st.caption(" / ".join(notes))


