def resolve_watchlist_file(market: str, prefer_existing: bool = True) -> Path:
    """현재 폴더의 관심종목 파일을 자동 선택.
    - 최신 기본명: watchlist_us_growth.csv / watchlist_kr_growth.csv
    - 구버전 호환명: watchlist_us.csv / watchlist_kr.csv
    존재하는 파일을 우선 사용하고, 없으면 최신 기본명으로 새로 저장합니다.
    """
    if market == "한국주식":
        candidates = [WATCHLIST_KR_FILE, WATCHLIST_KR_LEGACY_FILE]
    else:
        candidates = [WATCHLIST_US_FILE, WATCHLIST_US_LEGACY_FILE]
    if prefer_existing:
        for p in candidates:
            try:
                if p.exists():
                    return p
            except Exception:
                pass
    return candidates[0]

def safe_float(value: Any, default: float = 0.0) -> float:
    try:
        if pd.isna(value):
            return default
        return float(value)
    except Exception:
        return default


# Streamlit Arrow 표시 경고 방지용 전역 dataframe 래퍼
# - object 컬럼에 숫자와 빈 문자열이 섞여도 화면 표시 단계에서만 문자열로 정리합니다.
# - 원본 CSV/계산값은 변경하지 않습니다.
if not hasattr(st, "_original_dataframe_arrow_safe"):
    st._original_dataframe_arrow_safe = st.dataframe
if not hasattr(st, "_original_table_arrow_safe"):
    st._original_table_arrow_safe = st.table
if not hasattr(st, "_original_write_arrow_safe"):
    st._original_write_arrow_safe = st.write
if not hasattr(st, "_original_data_editor_label_safe"):
    st._original_data_editor_label_safe = st.data_editor


def _arrow_safe_display_data(data: Any) -> Any:
    try:
        if isinstance(data, pd.Series):
            df = data.to_frame().T.copy()
        elif isinstance(data, pd.DataFrame):
            df = data.copy()
        else:
            return data
        for col in df.columns:
            try:
                if pd.api.types.is_object_dtype(df[col]) or pd.api.types.is_string_dtype(df[col]):
                    value_formatter = globals().get("_user_display_value")
                    df[col] = df[col].map(
                        lambda x: ""
                        if pd.isna(x)
                        else (value_formatter(x) if callable(value_formatter) else str(x))
                    )
            except Exception:
                try:
                    df[col] = df[col].astype(str)
                except Exception:
                    pass
        # 화면 표시 단계에서만 공통 영어 컬럼명을 한글화한다. 원본 CSV/JSON/DataFrame은 변경하지 않는다.
        try:
            column_map = dict(globals().get("KOREAN_COLUMN_MAP", {}) or {})
            column_map.update(globals().get("USER_COLUMN_LABEL_OVERRIDES", {}) or {})
            if column_map:
                seen: dict[str, int] = {}
                renamed: list[str] = []
                for col in df.columns:
                    label = str(column_map.get(str(col), col))
                    seen[label] = seen.get(label, 0) + 1
                    if seen[label] > 1:
                        label = f"{label} {seen[label]}"
                    renamed.append(label)
                df.columns = renamed
        except Exception:
            pass
        return df
    except Exception:
        return data


def safe_dataframe(data: Any, *args: Any, **kwargs: Any) -> None:
    """st.dataframe Arrow 경고 방지용 래퍼.

    기존 st.dataframe과 동일하게 쓰되, 표시 직전에만 mixed object 컬럼을 정리합니다.
    """
    st._original_dataframe_arrow_safe(_arrow_safe_display_data(data), *args, **kwargs)


def safe_table(data: Any, *args: Any, **kwargs: Any) -> None:
    st._original_table_arrow_safe(_arrow_safe_display_data(data), *args, **kwargs)


def safe_write(*args: Any, **kwargs: Any) -> None:
    converted = tuple(_arrow_safe_display_data(arg) for arg in args)
    st._original_write_arrow_safe(*converted, **kwargs)


def _display_column_config_for_editor(data: Any, existing: Any = None) -> Any:
    if not isinstance(data, pd.DataFrame):
        return existing
    base = dict(existing) if isinstance(existing, dict) else {}
    column_map = dict(globals().get("KOREAN_COLUMN_MAP", {}) or {})
    column_map.update(globals().get("USER_COLUMN_LABEL_OVERRIDES", {}) or {})
    for col in data.columns:
        key = str(col)
        label = column_map.get(key)
        if label and key not in base:
            base[key] = str(label)
    return base if base else existing


def safe_data_editor(data: Any, *args: Any, **kwargs: Any) -> Any:
    kwargs["column_config"] = _display_column_config_for_editor(data, kwargs.get("column_config"))
    return st._original_data_editor_label_safe(data, *args, **kwargs)


# 기존 코드의 st.dataframe 호출도 모두 안전 래퍼를 통과하도록 연결합니다.
st.dataframe = safe_dataframe
st.table = safe_table
st.write = safe_write
st.data_editor = safe_data_editor


