def load_finnhub_api_key() -> str:
    """Finnhub API key: environment variable first, then local json config."""
    key = os.environ.get("FINNHUB_API_KEY", "").strip()
    if key:
        return key
    try:
        if FINNHUB_CONFIG_FILE.exists():
            cfg = json.loads(FINNHUB_CONFIG_FILE.read_text(encoding="utf-8"))
            if bool(cfg.get("enabled", True)):
                return str(cfg.get("api_key", "")).strip()
    except Exception:
        return ""
    return ""


def has_finnhub_api_key() -> bool:
    return bool(load_finnhub_api_key())


def mask_api_key(key: str) -> str:
    key = str(key or "").strip()
    if not key:
        return "-"
    if len(key) <= 8:
        return key[:2] + "****"
    return key[:4] + "****" + key[-4:]


def is_finnhub_quote_symbol(symbol: str) -> bool:
    """Finnhub quote endpoint for US stocks/ETFs. Skip Yahoo-specific symbols."""
    s = str(symbol or "").strip().upper()
    if not s:
        return False
    if s.startswith("^") or "=" in s or s.endswith(".KS") or s.endswith(".KQ"):
        return False
    if "-" in s:  # BTC-USD etc. use yfinance fallback for now
        return False
    if s.isdigit():
        return False
    return bool(re.fullmatch(r"[A-Z]{1,6}(\.[A-Z])?", s))


@st.cache_data(ttl=15, show_spinner=False)
def fetch_finnhub_quote_snapshot(symbol: str, api_key: str) -> dict[str, Any]:
    """Finnhub /quote snapshot. Falls back silently if unavailable."""
    result = {
        "ticker": symbol, "last_price": np.nan, "prev_close": np.nan,
        "change_abs": np.nan, "change_pct": np.nan,
        "open": np.nan, "high": np.nan, "low": np.nan,
        "last_time": "", "volume": np.nan, "source": "Finnhub",
        "finnhub_ok": False, "finnhub_error": "",
    }
    if not api_key or not is_finnhub_quote_symbol(symbol):
        result["finnhub_error"] = "not_eligible_or_no_key"
        return result
    try:
        import requests
        url = "https://finnhub.io/api/v1/quote"
        r = requests.get(url, params={"symbol": str(symbol).upper(), "token": api_key}, timeout=6)
        if r.status_code != 200:
            result["finnhub_error"] = f"http_{r.status_code}"
            return result
        data = r.json() or {}
        c = safe_float(data.get("c"), np.nan)
        pc = safe_float(data.get("pc"), np.nan)
        if np.isnan(c) or c <= 0:
            result["finnhub_error"] = "empty_price"
            return result

        result["last_price"] = c
        result["prev_close"] = pc
        result["change_abs"] = safe_float(data.get("d"), np.nan)
        result["change_pct"] = safe_float(data.get("dp"), np.nan)
        result["open"] = safe_float(data.get("o"), np.nan)
        result["high"] = safe_float(data.get("h"), np.nan)
        result["low"] = safe_float(data.get("l"), np.nan)
        t = safe_float(data.get("t"), np.nan)
        if not np.isnan(t) and t > 0:
            result["last_time"] = datetime.fromtimestamp(int(t), tz=ZoneInfo("UTC")).astimezone(KST).strftime("%m-%d %H:%M KST")
        result["finnhub_ok"] = True
        return result
    except Exception as e:
        result["finnhub_error"] = str(e)[:120]
        return result


def realtime_snapshot(symbol: str) -> dict[str, Any]:
    """Finnhub first for US stocks/ETFs, yfinance fallback for unsupported assets."""
    key = load_finnhub_api_key()
    if key and is_finnhub_quote_symbol(symbol):
        snap = fetch_finnhub_quote_snapshot(str(symbol).upper(), key)
        if bool(snap.get("finnhub_ok")):
            return snap
    return fetch_extended_snapshot(symbol)


def finnhub_config_status_text() -> str:
    key = load_finnhub_api_key()
    if key:
        return f"연결됨: {mask_api_key(key)}"
    return "미설정: SET_FINNHUB_KEY.bat 실행 필요"


def safe_pct(numerator: float, denominator: float) -> float:
    try:
        n = float(numerator)
        d = float(denominator)
        if d == 0 or np.isnan(n) or np.isnan(d):
            return np.nan
        return (n / d - 1) * 100
    except Exception:
        return np.nan


def _normalize_financial_df(raw: Any) -> pd.DataFrame:
    """yfinance financial statement frames can be transposed or empty. Convert to time-indexed rows."""
    try:
        if raw is None or len(raw) == 0:
            return pd.DataFrame()
        df = raw.copy()
        if isinstance(df.index, pd.DatetimeIndex):
            # already period rows
            out = df.copy()
        else:
            out = df.T.copy()
        out.index = pd.to_datetime(out.index, errors="coerce")
        out = out[~out.index.isna()].sort_index()
        return out
    except Exception:
        return pd.DataFrame()


def _pick_first_value(row: pd.Series, candidates: list[str], default: float = np.nan) -> float:
    for c in candidates:
        if c in row.index:
            v = safe_float(row.get(c), np.nan)
            if not np.isnan(v):
                return v
    return default


@st.cache_data(ttl=60 * 60 * 12, show_spinner=False)
def fetch_yfinance_fundamentals(symbol: str) -> dict[str, Any]:
    """US fundamentals via yfinance. Best-effort only; failures return neutral values."""
    result = {
        "symbol": symbol,
        "source": "yfinance",
        "revenue_growth_qoq": np.nan,
        "revenue_growth_3y": np.nan,
        "op_margin": np.nan,
        "op_margin_trend": np.nan,
        "net_income_trend": np.nan,
        "roe": np.nan,
        "debt_to_equity": np.nan,
        "free_cashflow_positive": np.nan,
        "per": np.nan,
        "pbr": np.nan,
        "earnings_surprise_pct": np.nan,
        "earnings_date": "",
        "summary": "-",
        "ok": False,
        "error": "",
    }
    try:
        import yfinance as yf
        ticker = yf.Ticker(str(symbol).upper())
        info = {}
        try:
            info = ticker.info or {}
        except Exception:
            info = {}

        qfin = _normalize_financial_df(getattr(ticker, "quarterly_financials", pd.DataFrame()))
        afin = _normalize_financial_df(getattr(ticker, "financials", pd.DataFrame()))
        qcf = _normalize_financial_df(getattr(ticker, "quarterly_cashflow", pd.DataFrame()))

        # Quarterly revenue trend
        if not qfin.empty:
            rev_col = next((c for c in ["Total Revenue", "Operating Revenue"] if c in qfin.columns), None)
            op_col = next((c for c in ["Operating Income", "EBIT"] if c in qfin.columns), None)
            ni_col = next((c for c in ["Net Income", "Net Income Common Stockholders"] if c in qfin.columns), None)
            if rev_col:
                rev = pd.to_numeric(qfin[rev_col], errors="coerce").dropna().tail(4)
                if len(rev) >= 2:
                    result["revenue_growth_qoq"] = safe_pct(rev.iloc[-1], rev.iloc[-2])
                if len(rev) >= 4:
                    # 3 consecutive quarterly revenue expansion flag as percent-like score
                    result["revenue_3q_up"] = bool(rev.iloc[-1] > rev.iloc[-2] > rev.iloc[-3])
            if rev_col and op_col:
                tmp = qfin[[rev_col, op_col]].dropna().tail(4)
                if len(tmp) >= 2:
                    margins = (pd.to_numeric(tmp[op_col], errors="coerce") / pd.to_numeric(tmp[rev_col], errors="coerce")) * 100
                    result["op_margin"] = safe_float(margins.iloc[-1], np.nan)
                    result["op_margin_trend"] = safe_float(margins.iloc[-1] - margins.iloc[0], np.nan)
            if ni_col:
                ni = pd.to_numeric(qfin[ni_col], errors="coerce").dropna().tail(4)
                if len(ni) >= 2:
                    result["net_income_trend"] = safe_pct(ni.iloc[-1], abs(ni.iloc[0]) if ni.iloc[0] != 0 else np.nan)

        # Annual 3y revenue trend
        if not afin.empty:
            rev_col = next((c for c in ["Total Revenue", "Operating Revenue"] if c in afin.columns), None)
            if rev_col:
                rev = pd.to_numeric(afin[rev_col], errors="coerce").dropna().tail(4)
                if len(rev) >= 3:
                    result["revenue_growth_3y"] = safe_pct(rev.iloc[-1], rev.iloc[0])

        # Cashflow
        if not qcf.empty:
            fcf_col = next((c for c in ["Free Cash Flow", "FreeCashFlow"] if c in qcf.columns), None)
            if fcf_col:
                fcf = pd.to_numeric(qcf[fcf_col], errors="coerce").dropna().tail(4)
                if len(fcf):
                    result["free_cashflow_positive"] = bool((fcf > 0).sum() >= max(1, len(fcf) // 2))

        # Info metrics
        result["roe"] = safe_float(info.get("returnOnEquity"), np.nan)
        if not np.isnan(result["roe"]):
            result["roe"] *= 100
        result["debt_to_equity"] = safe_float(info.get("debtToEquity"), np.nan)
        result["per"] = safe_float(info.get("trailingPE") or info.get("forwardPE"), np.nan)
        result["pbr"] = safe_float(info.get("priceToBook"), np.nan)

        # Earnings surprise from earnings_dates if available
        try:
            ed = ticker.get_earnings_dates(limit=4)
            if isinstance(ed, pd.DataFrame) and not ed.empty:
                surprise_col = next((c for c in ed.columns if "Surprise" in str(c)), None)
                if surprise_col:
                    s = pd.to_numeric(ed[surprise_col], errors="coerce").dropna()
                    if len(s):
                        result["earnings_surprise_pct"] = safe_float(s.iloc[0], np.nan)
                result["earnings_date"] = str(ed.index[0].date()) if hasattr(ed.index[0], "date") else str(ed.index[0])
        except Exception:
            pass

        result["ok"] = True
        result["summary"] = "재무 데이터 수집 완료"
        return result
    except Exception as e:
        result["error"] = str(e)[:160]
        return result


@st.cache_data(ttl=60 * 60 * 6, show_spinner=False)
def fetch_kr_naver_supply(symbol: str) -> dict[str, Any]:
    """KR investor supply via Naver Finance page. Best-effort scraping, may fail silently."""
    result = {
        "symbol": symbol,
        "foreign_hold_pct": np.nan,
        "foreign_change_hint": "",
        "institution_hint": "",
        "source": "Naver Finance",
        "ok": False,
        "error": "",
    }
    try:
        import requests
        from bs4 import BeautifulSoup
        code = normalize_ticker(symbol, "한국주식").replace(".KS", "").replace(".KQ", "")
        url = f"https://finance.naver.com/item/main.naver?code={code}"
        headers = {"User-Agent": "Mozilla/5.0"}
        r = requests.get(url, headers=headers, timeout=6)
        if r.status_code != 200:
            result["error"] = f"http_{r.status_code}"
            return result
        soup = BeautifulSoup(r.text, "html.parser")
        text_all = soup.get_text(" ", strip=True)
        # Simple heuristic around foreign ownership
        m = re.search(r"외국인소진율\s*([0-9.]+)%", text_all)
        if not m:
            m = re.search(r"외국인.*?([0-9.]+)%", text_all)
        if m:
            result["foreign_hold_pct"] = safe_float(m.group(1), np.nan)
        result["ok"] = True
        return result
    except Exception as e:
        result["error"] = str(e)[:160]
        return result


def score_fundamental_snapshot(snapshot: dict[str, Any], market: str = "미국주식") -> dict[str, Any]:
    """Convert fundamentals into a conservative -20~+20 score."""
    score = 0
    reasons: list[str] = []
    warnings: list[str] = []

    rev_qoq = safe_float(snapshot.get("revenue_growth_qoq"), np.nan)
    rev_3y = safe_float(snapshot.get("revenue_growth_3y"), np.nan)
    op_margin = safe_float(snapshot.get("op_margin"), np.nan)
    op_trend = safe_float(snapshot.get("op_margin_trend"), np.nan)
    roe = safe_float(snapshot.get("roe"), np.nan)
    debt = safe_float(snapshot.get("debt_to_equity"), np.nan)
    fcf_pos = snapshot.get("free_cashflow_positive", np.nan)
    surprise = safe_float(snapshot.get("earnings_surprise_pct"), np.nan)

    if snapshot.get("revenue_3q_up") is True:
        score += 4
        reasons.append("분기 매출 3연속 증가")
    elif not np.isnan(rev_qoq):
        if rev_qoq > 5:
            score += 3
            reasons.append(f"분기 매출 증가 {rev_qoq:.1f}%")
        elif rev_qoq < -5:
            score -= 4
            warnings.append(f"분기 매출 감소 {rev_qoq:.1f}%")

    if not np.isnan(rev_3y):
        if rev_3y > 20:
            score += 3
            reasons.append(f"3년 매출 성장 {rev_3y:.1f}%")
        elif rev_3y < -10:
            score -= 3
            warnings.append(f"3년 매출 감소 {rev_3y:.1f}%")

    if not np.isnan(op_margin):
        if op_margin >= 15:
            score += 3
            reasons.append(f"영업이익률 양호 {op_margin:.1f}%")
        elif op_margin < 0:
            score -= 4
            warnings.append("영업적자")
    if not np.isnan(op_trend):
        if op_trend > 2:
            score += 3
            reasons.append(f"영업이익률 개선 {op_trend:+.1f}%p")
        elif op_trend < -2:
            score -= 3
            warnings.append(f"영업이익률 악화 {op_trend:+.1f}%p")

    if not np.isnan(roe):
        if roe >= 15:
            score += 2
            reasons.append(f"ROE 양호 {roe:.1f}%")
        elif roe < 0:
            score -= 3
            warnings.append("ROE 마이너스")

    # US yfinance debtToEquity is often percent-like; KR rule still useful as warning threshold.
    if not np.isnan(debt):
        if debt >= 200:
            score -= 5
            warnings.append(f"부채비율/부채자본비율 높음 {debt:.0f}%")
        elif debt <= 80:
            score += 1
            reasons.append(f"부채 부담 낮음 {debt:.0f}%")

    if fcf_pos is True:
        score += 2
        reasons.append("최근 FCF 양호")
    elif fcf_pos is False:
        score -= 2
        warnings.append("최근 FCF 부진")

    if not np.isnan(surprise):
        if surprise >= 10:
            score += 4
            reasons.append(f"어닝 서프라이즈 {surprise:.1f}%")
        elif surprise <= -10:
            score -= 4
            warnings.append(f"어닝 쇼크 {surprise:.1f}%")

    score = int(max(-20, min(20, score)))
    if score >= 8:
        label = "재무 우호"
    elif score >= 2:
        label = "재무 보통+"
    elif score <= -8:
        label = "재무 위험"
    elif score <= -2:
        label = "재무 부담"
    else:
        label = "재무 중립"

    return {
        "score": score,
        "label": label,
        "reasons": reasons[:5],
        "warnings": warnings[:5],
        "summary": " / ".join((reasons[:3] or warnings[:3] or ["재무 데이터 제한"])),
    }


def sector_cycle_score(sector: str, market: str = "미국주식") -> dict[str, Any]:
    """Theme cycle score based on current user-defined watchlist themes."""
    s = str(sector or "").lower()
    score = 0
    reasons = []
    strong_keys = ["반도체", "ai", "전력", "원전", "조선", "방산", "우주", "데이터센터", "semiconductor", "power", "nuclear", "defense"]
    weak_keys = ["건설", "화학", "소재", "2차전지", "전기차", "소형주"]
    if any(k in s for k in strong_keys):
        score += 5
        reasons.append("우선 추적 테마")
    if any(k in s for k in weak_keys):
        score -= 1
        reasons.append("사이클 확인 필요")
    return {"score": int(score), "label": "업종 우호" if score > 0 else "업종 중립/확인", "reasons": reasons}


def composite_quality_score_for_symbol(symbol: str, market: str, sector: str = "") -> dict[str, Any]:
    """Fundamental + earnings + supply/theme quality, used as AI prediction adjustment."""
    if market == "미국주식":
        snap = fetch_yfinance_fundamentals(display_symbol(symbol, market))
        fscore = score_fundamental_snapshot(snap, market)
        supply_score = 0
        supply_label = "수급 데이터 제한"
        supply_summary = "미장은 현재 Finnhub quote 중심, 기관/외국인 수급은 미반영"
    else:
        snap = {}
        fscore = {"score": 0, "label": "재무 데이터 제한", "summary": "국장 재무 자동수집 제한", "warnings": [], "reasons": []}
        supply = fetch_kr_naver_supply(symbol)
        foreign_hold = safe_float(supply.get("foreign_hold_pct"), np.nan)
        if not np.isnan(foreign_hold):
            supply_score = 2 if foreign_hold >= 10 else 0
            supply_label = "외국인 보유 참고"
            supply_summary = f"외국인 보유율 {foreign_hold:.2f}%"
        else:
            supply_score = 0
            supply_label = "수급 데이터 제한"
            supply_summary = "외국인/기관 3개월 순매수 자동수집은 추가 보강 필요"

    cyc = sector_cycle_score(sector, market)
    total = int(max(-25, min(25, safe_float(fscore.get("score"), 0) + supply_score + safe_float(cyc.get("score"), 0))))
    if total >= 12:
        label = "품질 우호"
    elif total >= 4:
        label = "품질 보통+"
    elif total <= -10:
        label = "품질 위험"
    elif total <= -4:
        label = "품질 부담"
    else:
        label = "품질 중립"

    summary_parts = [fscore.get("summary", "-"), supply_summary]
    if cyc.get("reasons"):
        summary_parts.append(" / ".join(cyc["reasons"]))

    return {
        "quality_score": total,
        "quality_label": label,
        "fundamental_score": fscore.get("score", 0),
        "fundamental_label": fscore.get("label", "-"),
        "fundamental_summary": fscore.get("summary", "-"),
        "fundamental_warnings": " / ".join(fscore.get("warnings", [])) or "-",
        "supply_score": supply_score,
        "supply_label": supply_label,
        "supply_summary": supply_summary,
        "sector_cycle_score": cyc.get("score", 0),
        "sector_cycle_label": cyc.get("label", "-"),
        "quality_summary": " / ".join([p for p in summary_parts if p and p != "-"]),
    }



def current_rr_label(current_price: float, stop_loss: float, take_profit1: float) -> str:
    """보유종목 현재 손익비 라벨."""
    cur = safe_float(current_price, np.nan)
    stop = safe_float(stop_loss, np.nan)
    tp1 = safe_float(take_profit1, np.nan)
    if np.isnan(cur) or np.isnan(stop) or np.isnan(tp1) or cur <= 0 or stop <= 0 or tp1 <= 0:
        return "-"
    if cur <= stop:
        return "🔴 손절 이탈"
    risk = cur - stop
    reward = tp1 - cur
    if risk <= 0:
        return "🔴 손절 이탈"
    rr = reward / risk
    if rr >= 2.0:
        return f"✅ 1:{rr:.2f}"
    if rr >= 1.5:
        return f"🟡 1:{rr:.2f}"
    if rr >= 1.0:
        return f"⚠️ 1:{rr:.2f}"
    return f"🚫 1:{rr:.2f}"


def calculate_position_units_v994(
    entry: float,
    stop: float,
    account_size: float,
    risk_pct: float,
    max_position_pct: float,
    market: str = "미국주식",
    allow_fractional: bool = False,
) -> dict[str, Any]:
    """총수량 + 1차 50% / 2차 30% / 3차 20% 분할수량 계산."""
    entry = safe_float(entry, np.nan)
    stop = safe_float(stop, np.nan)
    account_size = safe_float(account_size, 0.0)
    risk_pct = safe_float(risk_pct, 0.7)
    max_position_pct = safe_float(max_position_pct, 20.0)
    result = {
        "total_qty": 0.0, "total_amount": 0.0, "risk_amount": 0.0,
        "split1_qty": 0.0, "split2_qty": 0.0, "split3_qty": 0.0,
        "split1_amount": 0.0, "split2_amount": 0.0, "split3_amount": 0.0,
        "risk_limit": account_size * risk_pct / 100,
        "reason": "계산 불가",
    }
    if np.isnan(entry) or np.isnan(stop) or entry <= 0 or stop <= 0 or entry <= stop or account_size <= 0:
        return result
    risk_per_share = entry - stop
    risk_limit = max(0.0, account_size * risk_pct / 100)
    max_position = max(0.0, account_size * max_position_pct / 100)
    qty_by_risk = risk_limit / risk_per_share if risk_per_share > 0 else 0
    qty_by_cap = max_position / entry if entry > 0 else 0
    qty = max(0.0, min(qty_by_risk, qty_by_cap))
    if not allow_fractional or market != "미국주식":
        qty = float(int(qty))
    s1 = qty * 0.50
    s2 = qty * 0.30
    s3 = qty - s1 - s2
    if not allow_fractional or market != "미국주식":
        s1 = float(int(s1))
        s2 = float(int(s2))
        s3 = max(0.0, float(int(qty) - int(s1) - int(s2)))
    result.update({
        "total_qty": qty,
        "total_amount": qty * entry,
        "risk_amount": qty * risk_per_share,
        "split1_qty": s1,
        "split2_qty": s2,
        "split3_qty": s3,
        "split1_amount": s1 * entry,
        "split2_amount": s2 * entry,
        "split3_amount": s3 * entry,
        "reason": "리스크 한도/종목당 최대비중 중 작은 값 기준",
    })
    return result


def event_alert_banner_message(event_context: dict[str, Any] | None) -> tuple[str, str]:
    """이벤트 임박 경고 배너 등급."""
    ctx = event_context or {}
    risk_mult = safe_float(ctx.get("risk_mult"), 1.0)
    joined = " ".join(map(str, ctx.get("event_names", []) + ctx.get("event_types", []))).lower()
    red_tags = ["earnings", "실적", "fomc", "cpi", "ppi", "고용", "payroll", "news_alarm_block"]
    if risk_mult >= 1.4 or any(t in joined for t in red_tags):
        return "red", f"🔴 이벤트 변동성 경고: risk_mult {risk_mult:.2f} · 실적/FOMC/CPI/PPI/고용/강한 뉴스 알람 확인 필요"
    if risk_mult >= 1.15:
        return "yellow", f"🟡 이벤트 주의: risk_mult {risk_mult:.2f} · 비중 축소 또는 진입가 대기 우선"
    return "green", f"🟢 이벤트 부담 낮음: risk_mult {risk_mult:.2f}"


def ensemble_dynamic_label(score: float) -> str:
    """사이드바 no_buy_min_ensemble 기준으로 앙상블 방향 라벨을 동적 표시."""
    base = safe_float(st.session_state.get("no_buy_min_ensemble", 45.0), 45.0)
    s = safe_float(score, np.nan)
    if np.isnan(s):
        return "앙상블 점수 없음"
    strong = min(90.0, base + 23)
    good = min(82.0, base + 13)
    neutral = min(72.0, base + 3)
    weak = max(20.0, base - 7)
    if s >= strong:
        label = "강한 우위"
    elif s >= good:
        label = "우위"
    elif s >= neutral:
        label = "중립+"
    elif s >= weak:
        label = "약함"
    else:
        label = "매우 약함"
    return f"{label} ({s:.0f}점 / 약함기준 {base:.0f})"


def render_v994_event_banner(event_context: dict[str, Any] | None) -> None:
    grade, msg = event_alert_banner_message(event_context)
    if grade == "red":
        st.error(msg)
    elif grade == "yellow":
        st.warning(msg)
    else:
        st.info(msg)


def render_v994_learning_profile(ticker: str, market: str, log_df: pd.DataFrame | None, sector: str = "") -> None:
    """단일 종목 분석 하단용 학습 프로파일."""
    with st.expander("🧬 종목 학습 프로파일", expanded=False):
        profile = learning_profile_for_symbol(log_df, ticker, market) if "learning_profile_for_symbol" in globals() else {"학습보정": "학습기록 부족", "학습점수": 0, "학습요약": "-", "학습기록": 0}
        quality = composite_quality_score_for_symbol(ticker, market, sector) if "composite_quality_score_for_symbol" in globals() else {"quality_score": 0, "quality_label": "-", "fundamental_summary": "-"}
        c1, c2, c3 = st.columns(3)
        c1.metric("학습점수", f"{safe_float(profile.get('학습점수'), 0):+.0f}")
        c2.metric("보정 레이블", str(profile.get("학습보정", "-")))
        c3.metric("펀더멘털 복합", f"{safe_float(quality.get('quality_score'), 0):+.0f} · {quality.get('quality_label', '-')}")
        st.caption(f"학습요약: {profile.get('학습요약', '-')}")
        st.caption(f"품질요약: {quality.get('quality_summary', quality.get('fundamental_summary', '-'))}")


def render_v994_trade_checklist(event_context: dict[str, Any] | None = None) -> None:
    """실전 체크리스트를 수치 기준으로 표시."""
    with st.expander("✅ 실전 체크리스트 · 수치 기준", expanded=False):
        base = safe_float(st.session_state.get("no_buy_min_ensemble", 45.0), 45.0)
        st.markdown(f"""
- **진입가 괴리**: 현재가가 우선진입가보다 **+3% 이상**이면 추격주의, **+5% 이상**이면 신규매수 금지.
- **손익비**: 최소 1:{safe_float(st.session_state.get("no_buy_min_rr", 1.2), 1.2):.1f} 미만이면 제외, 1:1.5 미만이면 비중 축소.
- **학습점수**: 음수이면서 주의사유가 있으면 판정을 한 단계 낮춤. -8 이하는 관망 우위.
- **앙상블**: 현재 약함 기준은 **{base:.0f}점**. {base:.0f}점 미만이면 우선확인보다 대기/관망.
- **이벤트**: risk_mult 1.4 이상 또는 실적/FOMC/CPI/PPI/고용지표 임박이면 분할·소액 또는 관망.
- **보유종목**: 현재손익비가 🚫 또는 🔴이면 신규추가보다 축소/손절 기준 확인.
""")
        render_v994_event_banner(event_context)


def split_buy_plan(entry: float, stop: float, total_budget: float = 0.0, market: str = "미국주식") -> dict[str, Any]:
    """3-step buy plan: 30% / 30% / 40%."""
    entry = safe_float(entry, np.nan)
    stop = safe_float(stop, np.nan)
    total_budget = safe_float(total_budget, 0.0)
    if np.isnan(entry) or entry <= 0:
        return {"plan_text": "-", "avg_price": np.nan, "max_loss_pct": np.nan}
    p1 = entry
    p2 = entry * 0.95
    p3 = entry * 1.015
    avg = p1 * 0.30 + p2 * 0.30 + p3 * 0.40
    max_loss_pct = (avg / stop - 1) * 100 if stop and not np.isnan(stop) and stop > 0 else np.nan
    if market == "한국주식":
        plan = f"1차 {fmt_price(p1, market)} 30% / 2차 {fmt_price(p2, market)} 30% / 3차 {fmt_price(p3, market)} 40%"
    else:
        plan = f"1차 ${p1:,.2f} 30% / 2차 ${p2:,.2f} 30% / 3차 ${p3:,.2f} 40%"
    return {"plan_text": plan, "avg_price": avg, "max_loss_pct": max_loss_pct}


