def normalize_symbol_key(value: Any) -> str:
    """매핑용 키 정규화: 공백/BOM/제로폭/괄호/기호 제거."""
    s = str(value or "").strip()
    s = s.replace("\ufeff", "").replace("\u200b", "").replace("\u200c", "").replace("\u200d", "")
    s = re.sub(r"\s+", "", s)
    s = re.sub(r"[\(\)\[\]\{\}·ㆍ,]", "", s)
    return s


def is_us_like_market(market: Any) -> bool:
    m = str(market or "").strip().lower()
    return ("미국" in m) or (m in {"us", "usa", "미장", "미국주식", "united states"})


def _kr_symbol_key(value: Any) -> str:
    s = str(value or "").strip().upper()
    s = s.replace("KRX:", "").replace("KOSDAQ:", "").strip()
    s = s.replace(".KS", "").replace(".KQ", "")
    if s.isdigit():
        s = s.zfill(6)
    return s


def korean_name_from_symbol(value: Any, fallback: Any = "") -> str:
    raw = str(value or "").strip()
    fb = str(fallback or "").strip()
    target = raw or fb
    if not target:
        return ""
    # 이미 한글 이름으로 들어온 경우 그대로 사용
    if any("\uac00" <= ch <= "\ud7a3" for ch in target):
        return target
    try:
        key = _kr_symbol_key(target)
        wl = load_watchlist_df("한국주식")
        if wl is not None and not wl.empty and "symbol" in wl.columns:
            for _, r in wl.iterrows():
                sym_key = _kr_symbol_key(r.get("symbol", ""))
                if sym_key == key:
                    nm = str(r.get("name", "") or "").strip()
                    if nm:
                        return nm
    except Exception:
        pass
    return target


def korean_symbol_from_name(value: Any) -> str:
    raw = str(value or "").strip()
    if not raw:
        return raw
    try:
        wl = load_watchlist_df("한국주식")
        if wl is None or wl.empty or "symbol" not in wl.columns:
            return raw
        name_cols = [c for c in ["name", "종목명", "company"] if c in wl.columns]
        if not name_cols:
            return raw
        raw_norm = normalize_symbol_key(raw).lower()
        exact: list[str] = []
        partial: list[str] = []
        for _, r in wl.iterrows():
            sym = str(r.get("symbol", "")).strip()
            for nc in name_cols:
                nv = str(r.get(nc, "")).strip()
                if not nv:
                    continue
                nv_norm = normalize_symbol_key(nv).lower()
                if nv_norm == raw_norm or nv == raw:
                    exact.append(_kr_symbol_key(sym))
                elif raw_norm in nv_norm or nv_norm in raw_norm:
                    if min(len(raw_norm), len(nv_norm)) >= 3:
                        partial.append(_kr_symbol_key(sym))
        if len(exact) == 1:
            return exact[0]
        if not exact and len(set(partial)) == 1:
            return partial[0]
        if exact:
            return exact[0]
    except Exception:
        pass
    return raw


def display_symbol(value: Any, market: str = "미국주식", fallback: Any = "") -> str:
    """화면 표시용 종목명. 미장은 저장값이 한글이어도 META/NVDA/SNDK처럼 티커로 강제 표시."""
    raw = str(value or "").strip()
    fb = str(fallback or "").strip()

    # 원본/정규화 키 모두 매핑
    for candidate in [raw, fb]:
        c = str(candidate or "").strip()
        if not c:
            continue

        keys = [
            c,
            c.upper(),
            normalize_symbol_key(c),
            normalize_symbol_key(c).upper(),
        ]
        for k in keys:
            mapped = KOREAN_US_TICKER_MAP.get(k)
            if mapped:
                return mapped

    if not is_us_like_market(market):
        return korean_name_from_symbol(raw or fb, fb)

    # 미장일 때는 티커 형태를 최우선
    for candidate in [raw, fb]:
        c = str(candidate or "").strip()
        if not c:
            continue
        cleaned = (
            c.replace(".US", "")
            .replace("NASDAQ:", "")
            .replace("NYSE:", "")
            .replace("AMEX:", "")
            .replace("$", "")
            .replace("\ufeff", "")
            .replace("\u200b", "")
            .strip()
        )
        if re.fullmatch(r"[A-Za-z][A-Za-z0-9.\-]{0,9}", cleaned):
            return cleaned.upper()

    # 알 수 없는 미장명은 최소한 대문자
    return raw.upper() if raw else fb.upper()


def normalize_us_tickers_in_log(df: pd.DataFrame) -> pd.DataFrame:
    """기존 predictions.csv 안에 한글명으로 저장된 미장 ticker/종목을 앱 로딩 시 자동 정리."""
    if df is None or df.empty:
        return df
    out = df.copy()
    market_col = out["market"].astype(str) if "market" in out.columns else pd.Series(["미국주식"] * len(out), index=out.index)
    us_mask = market_col.apply(is_us_like_market)

    if "ticker" in out.columns:
        out.loc[us_mask, "ticker"] = [
            display_symbol(t, "미국주식")
            for t in out.loc[us_mask, "ticker"].astype(str).tolist()
        ]

    if "종목" in out.columns:
        if "ticker" in out.columns:
            out.loc[us_mask, "종목"] = [
                display_symbol(t, "미국주식", s)
                for t, s in zip(out.loc[us_mask, "ticker"].astype(str), out.loc[us_mask, "종목"].astype(str))
            ]
        else:
            out.loc[us_mask, "종목"] = [
                display_symbol(s, "미국주식")
                for s in out.loc[us_mask, "종목"].astype(str).tolist()
            ]

    return out


def normalize_us_ticker_fields_in_df(df: pd.DataFrame, market_aware: bool = True) -> pd.DataFrame:
    """미국주식 관련 컬럼의 한글명/회사명을 티커로 정리."""
    if df is None or df.empty:
        return df
    out = df.copy()
    if market_aware and "market" in out.columns:
        mask = out["market"].astype(str).apply(is_us_like_market)
    else:
        mask = pd.Series([True] * len(out), index=out.index)

    # ticker/symbol/종목은 티커로 강제
    for col in ["ticker", "symbol", "종목", "티커", "심볼"]:
        if col in out.columns:
            out.loc[mask, col] = out.loc[mask, col].apply(lambda x: display_symbol(x, "미국주식"))

    # 미국 watchlist에서 name/회사명도 한글이 보이는 문제를 막기 위해 symbol이 있으면 symbol로 맞춤
    for col in ["name", "회사명"]:
        if col in out.columns:
            if "symbol" in out.columns:
                out.loc[mask, col] = out.loc[mask, "symbol"].apply(lambda x: display_symbol(x, "미국주식"))
            elif "ticker" in out.columns:
                out.loc[mask, col] = out.loc[mask, "ticker"].apply(lambda x: display_symbol(x, "미국주식"))
            else:
                out.loc[mask, col] = out.loc[mask, col].apply(lambda x: display_symbol(x, "미국주식"))

    return out


def persist_us_ticker_cleanup(path: Path, market_aware: bool = True) -> int:
    """CSV 파일 자체를 티커 기준으로 정리. 변경 시 자동 백업 후 저장."""
    try:
        if not path.exists():
            return 0
        df = pd.read_csv(path, dtype=str).fillna("")
        cleaned = normalize_us_ticker_fields_in_df(df, market_aware=market_aware)
        before = df.astype(str)
        after = cleaned.astype(str)
        changed = int((before != after).any(axis=1).sum())
        if changed > 0:
            BACKUP_DIR.mkdir(exist_ok=True)
            stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
            backup_path = BACKUP_DIR / f"{path.stem}_ticker_auto_backup_{stamp}{path.suffix}"
            df.to_csv(backup_path, index=False, encoding="utf-8-sig")
            cleaned.to_csv(path, index=False, encoding="utf-8-sig")
        return changed
    except Exception:
        return 0


def force_us_symbol_column(df: pd.DataFrame, market: str) -> pd.DataFrame:
    """DataFrame 표시 직전에 미장 종목 컬럼을 티커로 강제 변환."""
    if df is None or df.empty:
        return df
    if not is_us_like_market(market):
        return df
    out = df.copy()
    if "종목" in out.columns:
        if "ticker" in out.columns:
            out["종목"] = [display_symbol(t, "미국주식", s) for t, s in zip(out["ticker"], out["종목"])]
        else:
            out["종목"] = out["종목"].apply(lambda x: display_symbol(x, "미국주식"))
    if "ticker" in out.columns:
        out["ticker"] = out["ticker"].apply(lambda x: display_symbol(x, "미국주식"))
    return out



def fmt_price(value: float, market: str = "미국주식") -> str:
    value = safe_float(value)
    if market == "한국주식":
        return f"{value:,.0f}원"
    return f"${value:,.2f}"


def pct(n: float) -> str:
    sign = "+" if n >= 0 else ""
    return f"{sign}{n:.2f}%"


# --- UI-only display formatting helpers (v7) ---
# Keep CSV/data columns numeric/raw for tests and pipelines. Apply commas/currency
# only immediately before rendering Streamlit tables/cards.
_UI_PRICE_COLUMNS = {
    "현재가", "실시간현재가", "조건부 진입가", "매수가", "우선진입가", "관찰 기준가",
    "손절가", "목표가", "1차 목표가", "2차 목표가", "1차익절가", "2차익절가",
    "평단가", "평균단가", "매수단가", "익절가", "진입가",
}

_UI_PERCENT_COLUMNS = {
    "수익률", "손절가여유", "1차익절여유", "현재가와 매수가 차이",
    "목표가까지 여력", "손절가까지 거리", "기대수익률", "손절위험",
}


def _ui_is_missing_value(value: Any) -> bool:
    text = str(value).strip() if value is not None else ""
    return text in {"", "-", "N/A", "NA", "None", "none", "nan", "NaN", "저장값 없음", "가격 기준 미산출", "현재가 미수신", "데이터 부족", "확인 필요"}


def _ui_price_text(value: Any, market: str) -> str:
    if _ui_is_missing_value(value):
        return str(value).strip() if str(value).strip() else "-"
    text = str(value).strip()
    # Already formatted values are left alone.
    if "원" in text or "$" in text:
        return text
    num = _display_price_num(value) if "_display_price_num" in globals() else safe_float(value, np.nan)
    if isinstance(num, float) and not math.isnan(num):
        return fmt_price(num, market)
    return text


def _ui_pct_text(value: Any) -> str:
    if _ui_is_missing_value(value):
        return str(value).strip() if str(value).strip() else "-"
    text = str(value).strip()
    if text.endswith("%"):
        return text
    num = safe_float(value, np.nan)
    if not math.isnan(num):
        return f"{num:+.2f}%"
    return text


def _ui_market_for_row(row: Any, fallback: str) -> str:
    raw = ""
    for col in ("시장", "market", "market_name", "market_type"):
        try:
            raw = str(row.get(col, "") or "").strip()
        except Exception:
            raw = ""
        if raw:
            break
    raw = raw or fallback or "한국주식"
    try:
        return _normalize_app_market(raw) or raw
    except Exception:
        return raw


def _format_ui_table_values(df: pd.DataFrame, market: str | None = None) -> pd.DataFrame:
    """Format visible Streamlit tables only; never use before writing CSV/tests."""
    if df is None or df.empty:
        return df
    out = df.copy()
    fallback_market = market or ""
    for idx, row in out.iterrows():
        row_market = _ui_market_for_row(row, fallback_market)
        for col in [c for c in out.columns if c in _UI_PRICE_COLUMNS]:
            out.at[idx, col] = _ui_price_text(row.get(col, ""), row_market)
        for col in [c for c in out.columns if c in _UI_PERCENT_COLUMNS]:
            out.at[idx, col] = _ui_pct_text(row.get(col, ""))
    return out
# --- end UI-only display formatting helpers ---


def normalize_ticker(ticker: str, market: str) -> str:
    raw = str(ticker).strip()
    t = raw.upper()
    if market == "한국주식":
        t = t.replace("KRX:", "").replace("KOSDAQ:", "").strip()
        # 한글 종목명 입력도 watchlist 기준 코드로 변환
        if any("\uac00" <= ch <= "\ud7a3" for ch in raw):
            by_name = korean_symbol_from_name(raw)
            if by_name and by_name != raw:
                t = str(by_name).strip().upper()
        if t.endswith(".KS") or t.endswith(".KQ"):
            return t
        if t.isdigit():
            return t.zfill(6)
    return t


def market_data_symbol_candidates(symbol: str, market: str) -> list[str]:
    s = str(symbol or "").strip().upper()
    if market != "한국주식":
        return [s] if s else []
    if s.endswith(".KS") or s.endswith(".KQ"):
        return [s]
    key = _kr_symbol_key(s)
    if key.isdigit():
        return [f"{key}.KS", f"{key}.KQ", key]
    return [s]


@st.cache_data(ttl=300, show_spinner=False)
def fetch_watch_sparkline_data(symbol: str, market: str) -> pd.DataFrame:
    try:
        import yfinance as yf
    except Exception:
        return pd.DataFrame()
    for cand in market_data_symbol_candidates(symbol, market):
        try:
            raw = yf.download(cand, period="5d", interval="30m", progress=False, auto_adjust=False, prepost=True)
            if raw is None or raw.empty:
                raw = yf.download(cand, period="1mo", interval="1d", progress=False, auto_adjust=False)
            if raw is None or raw.empty:
                continue
            df = flatten_yf_columns(raw.reset_index())
            if "Close" not in df.columns:
                continue
            df["Close"] = pd.to_numeric(df["Close"], errors="coerce")
            df = df.dropna(subset=["Close"]).tail(64)
            if not df.empty:
                return df
        except Exception:
            continue
    return pd.DataFrame()


INTRADAY_REALTIME_SNAPSHOT_FILE = REPORT_DIR / "intraday_realtime_snapshot.csv"

WATCH_QUOTE_SOURCE_DISPLAY: dict[str, str] = {
    "kis_us_quote": "KIS 현재가",
    "kis_inquire_price": "KIS 현재가",
    "finnhub_quote": "Finnhub 보조 수신",
    "csv_fallback": "저장 가격 사용",
    "missing": "현재가 미수신",
    "candidate_last_price": "후보 CSV 가격",
    "candidate_current_price": "후보 CSV 가격",
    "candidate_close": "후보 CSV 가격",
    "watchlist_saved": "관심종목 저장값",
    "predictions_history": "예측 기록 가격",
}


@st.cache_data(ttl=60, show_spinner=False)
def _load_watch_intraday_snapshot_index() -> dict[str, tuple[str, dict[str, Any]]]:
    """symbol → (market, row) from reports/intraday_realtime_snapshot.csv (no network)."""
    index: dict[str, tuple[str, dict[str, Any]]] = {}
    mtime_ns, file_size = _file_cache_token(INTRADAY_REALTIME_SNAPSHOT_FILE)
    df = load_csv_cached(str(INTRADAY_REALTIME_SNAPSHOT_FILE), mtime_ns, file_size, True)
    if df.empty or "symbol" not in df.columns:
        return index
    if "market" not in df.columns:
        df = df.copy()
        df["market"] = ""
    for _, row in df.iterrows():
        sym = str(row.get("symbol", "")).strip().upper()
        if not sym:
            continue
        mkt = str(row.get("market", "")).strip()
        index[(sym, mkt)] = (mkt, row.to_dict())
        index[(sym, "")] = (mkt, row.to_dict())
    return index


def _watch_quote_source_label(quote_source: Any) -> str:
    text = str(quote_source or "").strip().lower()
    if not text:
        return WATCH_QUOTE_SOURCE_DISPLAY["missing"]
    if text in WATCH_QUOTE_SOURCE_DISPLAY:
        return WATCH_QUOTE_SOURCE_DISPLAY[text]
    if text.startswith("fallback_candidate_") or text.startswith("fallback_"):
        return WATCH_QUOTE_SOURCE_DISPLAY["csv_fallback"]
    return text


def _candidate_csv_paths_for_market(market: str) -> list[Path]:
    if market == "미국주식":
        return [
            SWING_SCAN_US_TOPA_FILE,
            SWING_SCAN_US_B_FILE,
            SWING_SCAN_US_C_FILE,
            SWING_SCAN_US_FILE,
            CANDIDATE_US_FILE,
            WATCHLIST_US_FILE,
            WATCHLIST_US_LEGACY_FILE,
        ]
    return [
        SWING_SCAN_KR_TOPA_FILE,
        SWING_SCAN_KR_B_FILE,
        SWING_SCAN_KR_C_FILE,
        SWING_SCAN_KR_FILE,
        CANDIDATE_KR_FILE,
        WATCHLIST_KR_FILE,
        WATCHLIST_KR_LEGACY_FILE,
    ]


def _price_from_candidate_csvs(symbol: str, market: str) -> dict[str, Any]:
    sym_key = str(symbol or "").strip().upper()
    if not sym_key:
        return {}
    for path in _candidate_csv_paths_for_market(market):
        try:
            df = read_csv_cached(path)
        except Exception:
            continue
        if df.empty:
            continue
        sym_col = None
        for col in ("symbol", "ticker", "종목코드", "종목"):
            if col in df.columns:
                sym_col = col
                break
        if not sym_col:
            continue
        work = df.copy()
        work["_sym"] = work[sym_col].astype(str).str.strip().str.upper()
        if market == "미국주식":
            work["_sym"] = work["_sym"].apply(lambda x: display_symbol(x, "미국주식"))
        else:
            work["_sym"] = work["_sym"].apply(lambda x: normalize_ticker(x, market))
        hit = work.loc[work["_sym"].eq(sym_key)]
        if hit.empty:
            continue
        row = hit.iloc[0]
        for price_col, source_key in (
            ("last_price", "candidate_last_price"),
            ("current_price", "candidate_current_price"),
            ("close", "candidate_close"),
            ("price", "candidate_close"),
        ):
            if price_col not in row.index:
                continue
            price = safe_float(row.get(price_col), np.nan)
            if math.isnan(price) or price <= 0:
                continue
            change = safe_float(row.get("intraday_change_pct", row.get("change_pct")), np.nan)
            return {
                "last_price": price,
                "change_pct": change,
                "quote_source": source_key,
                "data_status": "후보 CSV",
            }
    return {}


def fetch_watch_snapshot_offline(symbol: str, market: str) -> dict[str, Any]:
    """관심종목 카드용 — reports/저장 데이터만 사용 (렌더 중 API 호출 없음)."""
    sym = str(symbol or "").strip().upper()
    if market == "미국주식":
        sym = display_symbol(sym, "미국주식")
    else:
        sym = normalize_ticker(sym, market)
    result: dict[str, Any] = {
        "symbol": symbol,
        "used_symbol": sym,
        "last_price": np.nan,
        "change_pct": np.nan,
        "quote_source": "missing",
        "quote_source_label": WATCH_QUOTE_SOURCE_DISPLAY["missing"],
        "data_status": "현재가 미수신",
        "ok": False,
    }
    if not sym:
        return result

    snap_index = _load_watch_intraday_snapshot_index()
    row_pack = snap_index.get((sym, market)) or snap_index.get((sym, ""))
    if row_pack:
        _, row = row_pack
        last = safe_float(row.get("last_price"), np.nan)
        if math.isnan(last) or last <= 0:
            last = safe_float(row.get("quote_fallback_price"), np.nan)
        change = safe_float(row.get("intraday_change_pct"), np.nan)
        source = str(row.get("quote_source", "") or row.get("intraday_data_source", "")).strip().lower()
        status = str(row.get("intraday_fetch_status", "") or "").strip()
        warning = str(row.get("intraday_warning", "") or "").strip()
        if not math.isnan(last) and last > 0:
            data_status = "정상" if status in {"success", "fallback"} else (warning or status or "장중 리포트")
            result.update({
                "last_price": last,
                "change_pct": change,
                "quote_source": source or "kis_us_quote",
                "quote_source_label": _watch_quote_source_label(source),
                "data_status": data_status[:80] if data_status else "장중 리포트",
                "ok": True,
            })
            return result

    cand = _price_from_candidate_csvs(sym, market)
    if cand:
        result.update({
            "last_price": cand["last_price"],
            "change_pct": cand.get("change_pct", np.nan),
            "quote_source": cand.get("quote_source", "candidate_close"),
            "quote_source_label": _watch_quote_source_label(cand.get("quote_source")),
            "data_status": cand.get("data_status", "후보 CSV"),
            "ok": True,
        })
        return result

    try:
        wl = load_watchlist_df(market)
        if wl is not None and not wl.empty and "symbol" in wl.columns:
            for _, wrow in wl.iterrows():
                ws = str(wrow.get("symbol", "")).strip().upper()
                if market == "미국주식":
                    ws = display_symbol(ws, "미국주식")
                else:
                    ws = normalize_ticker(ws, market)
                if ws != sym:
                    continue
                for col in ("last_price", "current_price", "close", "price"):
                    if col not in wrow.index:
                        continue
                    price = safe_float(wrow.get(col), np.nan)
                    if not math.isnan(price) and price > 0:
                        result.update({
                            "last_price": price,
                            "change_pct": safe_float(wrow.get("change_pct"), np.nan),
                            "quote_source": "watchlist_saved",
                            "quote_source_label": WATCH_QUOTE_SOURCE_DISPLAY["watchlist_saved"],
                            "data_status": "관심종목 저장",
                            "ok": True,
                        })
                        return result
    except Exception:
        pass
    return result


@st.cache_data(ttl=120, show_spinner=False)
def fetch_watch_sparkline_data_offline(symbol: str, market: str) -> pd.DataFrame:
    """predictions.csv 등 로컬 기록만으로 미니차트용 시계열 (API 없음)."""
    sym = str(symbol or "").strip().upper()
    if market == "미국주식":
        sym = display_symbol(sym, "미국주식")
    else:
        sym = normalize_ticker(sym, market)
    try:
        pred = read_csv_cached(PREDICTION_FILE)
    except Exception:
        return pd.DataFrame()
    if pred.empty:
        return pd.DataFrame()
    ticker_col = None
    for col in ("ticker", "symbol", "종목", "종목코드"):
        if col in pred.columns:
            ticker_col = col
            break
    if not ticker_col:
        return pd.DataFrame()
    work = pred.copy()
    work["_sym"] = work[ticker_col].astype(str).str.strip().str.upper()
    if market == "미국주식":
        work["_sym"] = work["_sym"].apply(lambda x: display_symbol(x, "미국주식"))
    else:
        work["_sym"] = work["_sym"].apply(lambda x: normalize_ticker(x, market))
    sub = work.loc[work["_sym"].eq(sym)].copy()
    if sub.empty:
        return pd.DataFrame()
    date_col = None
    for col in ("target_date", "date", "prediction_date", "trade_date"):
        if col in sub.columns:
            date_col = col
            break
    close_col = None
    for col in ("actual_close", "close", "last_price", "predicted_close"):
        if col in sub.columns:
            close_col = col
            break
    if not date_col or not close_col:
        return pd.DataFrame()
    sub[close_col] = pd.to_numeric(sub[close_col], errors="coerce")
    sub = sub.dropna(subset=[close_col])
    if date_col in sub.columns:
        try:
            sub = sub.sort_values(date_col)
        except Exception:
            pass
    sub = sub.tail(64)
    if sub.empty:
        return pd.DataFrame()
    out = pd.DataFrame({"Date": sub[date_col].astype(str), "Close": sub[close_col]})
    return out


def make_watch_sparkline_offline(symbol: str, market: str) -> go.Figure | None:
    df = fetch_watch_sparkline_data_offline(symbol, market)
    if df is None or df.empty:
        return None
    x_col = "Datetime" if "Datetime" in df.columns else ("Date" if "Date" in df.columns else df.columns[0])
    fig = go.Figure()
    fig.add_trace(
        go.Scatter(
            x=df[x_col],
            y=df["Close"],
            mode="lines",
            line=dict(color="#6ea8ff", width=2),
            showlegend=False,
        )
    )
    fig.update_layout(
        height=64,
        margin=dict(l=0, r=0, t=0, b=0),
        paper_bgcolor="#07111d",
        plot_bgcolor="#07111d",
        xaxis=dict(visible=False),
        yaxis=dict(visible=False),
    )
    return fig


def make_watch_sparkline(symbol: str, market: str) -> go.Figure | None:
    """미니차트 — 로컬 데이터 우선, 없으면 None (화면에서는 offline 경로 사용)."""
    return make_watch_sparkline_offline(symbol, market)


def render_daily_watch_mini_quote_card(
    symbol: str,
    market: str,
    symbol_to_label: dict[str, str],
    *,
    card_key: str,
) -> None:
    """관심종목 1종목 카드 — reports/저장 데이터만 사용."""
    snap = fetch_watch_snapshot_offline(symbol, market)
    chg = safe_float(snap.get("change_pct"), np.nan)
    last_price = safe_float(snap.get("last_price"), np.nan)
    source_label = str(snap.get("quote_source_label", "") or "현재가 미수신")
    data_status = str(snap.get("data_status", "") or ("정상" if snap.get("ok") else "현재가 미수신"))
    if snap.get("ok") and not math.isnan(last_price) and last_price > 0:
        chg_text = pct(chg) if not np.isnan(chg) else "-"
        price_text = fmt_price(last_price, market)
        chg_color = "#35e37a" if (not np.isnan(chg) and chg >= 0) else "#ff4d5a" if not np.isnan(chg) else "#ffca54"
    else:
        chg_text = "-" if math.isnan(chg) else pct(chg)
        price_text = "현재가 미수신"
        chg_color = "#ffca54"
    used_symbol = str(snap.get("used_symbol", symbol) or symbol)
    display_name = symbol if market == "미국주식" else korean_name_from_symbol(symbol, symbol)
    label = symbol_to_label.get(symbol, display_name)
    if market != "미국주식" and label:
        display_name = label.split(" (")[0] if " (" in label else label
    st.markdown(
        f"<div style='display:flex;justify-content:space-between;gap:8px;margin:6px 0 2px 0;align-items:center'>"
        f"<div><b>{display_name}</b>"
        f"<div class='small'>{used_symbol}</div></div>"
        f"<div style='text-align:right'>"
        f"<div style='font-weight:900;color:{chg_color};font-size:0.98rem'>{chg_text}</div>"
        f"<div class='small' style='color:#cbd5e1'>{price_text}</div>"
        f"</div></div>",
        unsafe_allow_html=True,
    )
    st.caption(f"데이터 출처: {source_label} · 상태: {data_status}")
    spark = make_watch_sparkline_offline(symbol, market)
    if spark is not None:
        st.plotly_chart(spark, width="stretch", config={"displayModeBar": False}, key=f"{card_key}_spark_{symbol}")
    else:
        st.caption("차트 데이터 없음")


def render_daily_watch_mini_charts_panel(
    market: str,
    *,
    key_prefix: str = "watch",
    compact: bool = False,
    hide_title: bool = False,
) -> None:
    """관심종목 미니차트 — 진입 시 기본 5종목 자동 표시 (API/runner 자동 실행 없음)."""
    if not hide_title:
        st.markdown("### 관심종목 미니차트")
    st.caption(
        "마지막으로 갱신된 장중 리포트 기준으로 관심종목을 표시합니다. "
        "최신 데이터가 필요하면 PowerShell에서 python run_intraday_refresh.py를 실행해 주세요."
    )
    labels, label_to_symbol = _watchlist_selection_options(market)
    if not labels:
        st.info("등록된 관심종목이 없습니다. 설정 / 관리에서 관심종목을 추가해 주세요.")
        return

    saved_symbols = load_daily_watch_selection(market, labels, label_to_symbol)
    symbol_to_label = {v: k for k, v in label_to_symbol.items()}
    default_labels = [symbol_to_label[s] for s in saved_symbols if s in symbol_to_label]
    if not default_labels:
        default_labels = labels[:5]

    picker_key = f"{key_prefix}_daily_watch_5_select_{market}"
    if picker_key not in st.session_state or not st.session_state.get(picker_key):
        st.session_state[picker_key] = default_labels[:5]

    selected_labels = st.multiselect(
        "오늘 볼 관심종목 (최대 5개)",
        labels,
        max_selections=5,
        key=picker_key,
        help="선택 즉시 아래 카드가 갱신됩니다. 새 API 조회는 하지 않습니다.",
    )
    selected_symbols = [label_to_symbol[x] for x in selected_labels if x in label_to_symbol][:5]
    if selected_symbols != saved_symbols[:5]:
        save_daily_watch_selection(market, selected_symbols)

    if not selected_symbols:
        selected_symbols = [label_to_symbol[x] for x in labels[:5] if x in label_to_symbol][:5]

    if not selected_symbols:
        st.info("표시할 관심종목이 없습니다.")
        return

    if len(selected_symbols) < 5:
        st.caption(f"현재 {len(selected_symbols)}개 표시 · 최대 5개까지 선택 가능")
    else:
        st.caption("선택 5개 표시 중")

    display_symbols = selected_symbols[:5]
    if compact:
        for idx, ws in enumerate(display_symbols):
            with st.container(border=True):
                render_daily_watch_mini_quote_card(
                    ws,
                    market,
                    symbol_to_label,
                    card_key=f"{key_prefix}_{market}_{idx}",
                )
    else:
        for row_start in range(0, len(display_symbols), 2):
            row_syms = display_symbols[row_start : row_start + 2]
            cols = st.columns(len(row_syms))
            for idx, (slot, ws) in enumerate(zip(cols, row_syms)):
                with slot:
                    with st.container(border=True):
                        render_daily_watch_mini_quote_card(
                            ws,
                            market,
                            symbol_to_label,
                            card_key=f"{key_prefix}_{market}_{row_start + idx}",
                        )


def _watchlist_selection_options(market: str) -> tuple[list[str], dict[str, str]]:
    """Sidebar watchlist selection options: label list and label->symbol map."""
    try:
        wl = load_watchlist_df(market)
    except Exception:
        wl = pd.DataFrame()
    labels: list[str] = []
    label_to_symbol: dict[str, str] = {}
    seen: set[str] = set()
    if wl is None or wl.empty or "symbol" not in wl.columns:
        return labels, label_to_symbol
    for _, row in wl.iterrows():
        raw_sym = str(row.get("symbol", "") or "").strip()
        if not raw_sym:
            continue
        sym = display_symbol(raw_sym, "미국주식") if market == "미국주식" else normalize_ticker(raw_sym, market)
        if not sym or sym in seen:
            continue
        seen.add(sym)
        name = str(row.get("name", "") or "").strip()
        if market == "미국주식":
            label = sym
        else:
            label = f"{name} ({sym})" if name and name != sym else sym
        labels.append(label)
        label_to_symbol[label] = sym
    return labels, label_to_symbol


def load_daily_watch_selection(market: str, labels: list[str], label_to_symbol: dict[str, str]) -> list[str]:
    """Load today's selected watch symbols. Falls back to first 5 watchlist items."""
    today_key = datetime.now(KST).strftime("%Y-%m-%d")
    market_key = "US" if market == "미국주식" else "KR"
    available = set(label_to_symbol.values())
    try:
        if DAILY_WATCH_SELECTION_FILE.exists():
            data = json.loads(DAILY_WATCH_SELECTION_FILE.read_text(encoding="utf-8"))
            item = data.get(market_key, {}) if isinstance(data, dict) else {}
            if item.get("date") == today_key:
                selected = [str(x).strip() for x in item.get("symbols", []) if str(x).strip()]
                selected = [x for x in selected if x in available]
                if selected:
                    return selected[:5]
    except Exception:
        pass
    return [label_to_symbol[x] for x in labels[:5]]


def save_daily_watch_selection(market: str, symbols: list[str]) -> None:
    """Persist today's selected watch symbols so the sidebar keeps the user's daily picks."""
    today_key = datetime.now(KST).strftime("%Y-%m-%d")
    market_key = "US" if market == "미국주식" else "KR"
    data: dict[str, Any] = {}
    try:
        if DAILY_WATCH_SELECTION_FILE.exists():
            loaded = json.loads(DAILY_WATCH_SELECTION_FILE.read_text(encoding="utf-8"))
            if isinstance(loaded, dict):
                data = loaded
    except Exception:
        data = {}
    data[market_key] = {
        "date": today_key,
        "symbols": [str(x).strip() for x in symbols if str(x).strip()][:5],
        "updated_at": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S KST"),
    }
    try:
        DAILY_WATCH_SELECTION_FILE.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass


def render_sidebar_daily_watch_cards(market: str) -> None:
    """사이드바: 화면 기준(시장) 아래 관심종목 5개 현재가·미니차트."""
    render_daily_watch_mini_charts_panel(market, key_prefix="sidebar_watch_cards", compact=True)


def _render_sidebar_watch_live_rows(selected_symbols: list[str], symbol_to_label: dict[str, str], market: str) -> None:
    """Sidebar live quote/sparkline rows for selected watchlist symbols.

    This is intentionally separated from render_sidebar_daily_watch_summary()
    to avoid recursive rendering while still keeping the first screen lightweight.
    """
    if not selected_symbols:
        st.info("표시할 관심종목이 없습니다.")
        return
    for ws in selected_symbols[:5]:
        try:
            snap = fetch_watch_snapshot(ws, market)
            chg = safe_float(snap.get("change_pct"), np.nan)
            last_price = safe_float(snap.get("last_price"), np.nan)
            chg_text = pct(chg) if not np.isnan(chg) else "-"
            price_text = fmt_price(last_price, market) if not np.isnan(last_price) and last_price > 0 else "-"
            chg_color = "#35e37a" if (not np.isnan(chg) and chg >= 0) else "#ff4d5a" if not np.isnan(chg) else "#ffca54"
            used_symbol = str(snap.get("used_symbol", ws) or ws)
            display_name = ws if market == "미국주식" else korean_name_from_symbol(ws, ws)
            label = symbol_to_label.get(ws, display_name)
            if market != "미국주식" and label:
                display_name = label
            st.markdown(
                f"<div style='display:flex;justify-content:space-between;gap:8px;margin:10px 0 4px 0;align-items:center'>"
                f"<div><b>{display_name}</b><div class='small'>{used_symbol}</div></div>"
                f"<div style='text-align:right'>"
                f"<div style='font-weight:900;color:{chg_color};font-size:0.98rem'>{chg_text}</div>"
                f"<div class='small' style='color:#cbd5e1'>{price_text}</div>"
                f"</div>"
                f"</div>",
                unsafe_allow_html=True,
            )
            spark = make_watch_sparkline(ws, market)
            if spark is not None:
                st.plotly_chart(spark, width="stretch", config={"displayModeBar": False})
        except Exception as e:
            st.caption(f"{ws}: 현재가/미니차트 조회 실패 - {str(e)[:80]}")


