def _watch_quote_status_note(snap: dict[str, Any], market: str) -> str:
    """현재가 스냅샷 실패 시 사용자용 상태 문구."""
    last_price = safe_float(snap.get("last_price"), np.nan)
    ok = bool(snap.get("ok"))
    if ok and not math.isnan(last_price) and last_price > 0:
        return ""
    try:
        sess = market_session_context(market)
        label = str(sess.get("session_label", "") or "")
        if "마감" in label or "휴장" in label or "장전" in label:
            return "장마감/미지원"
    except Exception:
        pass
    if market == "미국주식":
        try:
            if "finnhub" in str(finnhub_config_status_text()).lower() and "미설정" in finnhub_config_status_text():
                return "장마감/미지원"
        except Exception:
            pass
    return "현재가 미수신"


def render_daily_watch_symbol_picker(
    market: str,
    *,
    key_prefix: str = "watch_mini",
) -> tuple[list[str], dict[str, str], list[str]]:
    """오늘 볼 관심종목 최대 5개 선택 UI. (선택 심볼, label→symbol, 전체 labels) 반환."""
    labels, label_to_symbol = _watchlist_selection_options(market)
    if not labels:
        return [], {}, []
    saved_symbols = load_daily_watch_selection(market, labels, label_to_symbol)
    symbol_to_label = {v: k for k, v in label_to_symbol.items()}
    default_labels = [symbol_to_label[s] for s in saved_symbols if s in symbol_to_label]
    if not default_labels:
        default_labels = labels[:5]
    selected_labels = st.multiselect(
        "오늘 볼 관심종목 (최대 5개)",
        labels,
        default=default_labels[:5],
        max_selections=5,
        key=f"{key_prefix}_daily_watch_5_select_{market}",
        help="매일 확인할 종목을 고릅니다. 선택은 당일 저장됩니다.",
    )
    selected_symbols = [label_to_symbol[x] for x in selected_labels if x in label_to_symbol][:5]
    if selected_symbols != saved_symbols[:5]:
        save_daily_watch_selection(market, selected_symbols)
    if len(selected_symbols) < 5:
        st.caption(f"현재 {len(selected_symbols)}개 선택 · 최대 5개")
    else:
        st.caption("선택 5개 표시 중")
    return selected_symbols, label_to_symbol, labels


def render_watchlist_mini_quote_card(
    symbol: str,
    market: str,
    symbol_to_label: dict[str, str],
    *,
    card_key: str,
) -> None:
    """관심종목 1종목 현재가·등락률·미니차트 카드 (expander 없음)."""
    snap = fetch_watch_snapshot(symbol, market)
    chg = safe_float(snap.get("change_pct"), np.nan)
    last_price = safe_float(snap.get("last_price"), np.nan)
    status_note = _watch_quote_status_note(snap, market)
    if status_note:
        chg_text = status_note
        price_text = status_note if math.isnan(last_price) or last_price <= 0 else fmt_price(last_price, market)
        chg_color = "#ffca54"
    else:
        chg_text = pct(chg) if not np.isnan(chg) else "-"
        price_text = fmt_price(last_price, market) if not np.isnan(last_price) and last_price > 0 else "현재가 미수신"
        chg_color = "#35e37a" if (not np.isnan(chg) and chg >= 0) else "#ff4d5a" if not np.isnan(chg) else "#ffca54"
    used_symbol = str(snap.get("used_symbol", symbol) or symbol)
    display_name = symbol if market == "미국주식" else korean_name_from_symbol(symbol, symbol)
    label = symbol_to_label.get(symbol, display_name)
    if market != "미국주식" and label:
        display_name = label
    market_label = "미국주식" if market == "미국주식" else "한국주식"
    st.markdown(
        f"<div style='display:flex;justify-content:space-between;gap:8px;margin:6px 0 2px 0;align-items:center'>"
        f"<div><b>{display_name}</b>"
        f"<div class='small'>{used_symbol} · {market_label}</div></div>",
        f"<div style='text-align:right'>"
        f"<div style='font-weight:900;color:{chg_color};font-size:0.98rem'>{chg_text}</div>"
        f"<div class='small' style='color:#cbd5e1'>{price_text}</div>"
        f"</div></div>",
        unsafe_allow_html=True,
    )
    spark = make_watch_sparkline(symbol, market)
    if spark is not None:
        st.plotly_chart(spark, width="stretch", config={"displayModeBar": False}, key=f"{card_key}_spark_{symbol}")
    else:
        st.caption("미니차트: 일봉 데이터 미수신")


def _format_selected_flow_value_v15(value: Any) -> str:
    text = str(value if value is not None else "").strip()
    if not text or text.lower() in {"nan", "none", "nat"} or text == "-":
        return "미수신"
    num = safe_float(value, np.nan)
    if math.isnan(num):
        return text
    if abs(num) >= 1:
        return f"{num:,.0f}"
    return f"{num:.2f}"


def _render_selected_kr_flow_under_chart_v15(symbol: str, market: str) -> None:
    """국장 종목 봉차트 아래에 선택 종목 수급만 가볍게 표시한다."""
    if str(market) != "한국주식" or not symbol:
        return
    sym = str(symbol).strip().replace(".KS", "").replace(".KQ", "")
    if sym.endswith(".0"):
        sym = sym[:-2]
    if sym.isdigit():
        sym = sym.zfill(6)
    paths = [
        REPORT_DIR / "intraday_flow_snapshot.csv",
        REPORT_DIR / "intraday_flow_report.csv",
        REPORT_DIR / "intraday_flow_failure_detail.csv",
    ]
    flow_df = pd.DataFrame()
    for path in paths:
        try:
            if path.exists() and path.stat().st_size > 0:
                flow_df = pd.read_csv(path, dtype=str, encoding="utf-8-sig").fillna("")
                if not flow_df.empty:
                    break
        except Exception:
            continue
    if flow_df.empty or "symbol" not in flow_df.columns:
        st.caption("선택 종목 수급: 저장된 장중 수급 데이터 없음")
        return
    work = flow_df.copy()
    work["_sym"] = work["symbol"].astype(str).str.replace(".KS", "", regex=False).str.replace(".KQ", "", regex=False).str.replace(r"\.0$", "", regex=True)
    work["_sym"] = work["_sym"].map(lambda x: str(x).zfill(6) if str(x).isdigit() else str(x).upper())
    matched = work.loc[work["_sym"].eq(sym)]
    if matched.empty:
        st.caption(f"선택 종목 수급: {sym} 데이터 없음")
        return
    row = matched.iloc[0]
    name = str(row.get("name", "") or row.get("stock_name", "") or row.get("종목명", "") or korean_name_from_symbol(sym, sym))
    foreign = _format_selected_flow_value_v15(row.get("foreign_net_buy"))
    institution = _format_selected_flow_value_v15(row.get("institution_net_buy"))
    individual = _format_selected_flow_value_v15(row.get("individual_net_buy"))
    program = _format_selected_flow_value_v15(row.get("program_net_buy"))
    score = str(row.get("intraday_flow_score", row.get("flow_score", "-")) or "-")
    updated = str(row.get("updated_at", row.get("last_updated_at", "")) or "")
    st.markdown("### 선택 종목 수급")
    st.caption(f"{name} · {sym}" + (f" · 갱신 {updated}" if updated else ""))
    c1, c2, c3, c4, c5 = st.columns(5)
    c1.metric("외국인", foreign)
    c2.metric("기관", institution)
    c3.metric("개인", individual)
    c4.metric("프로그램", program)
    c5.metric("수급점수", score)


