@st.cache_data(ttl=120, show_spinner=False)
def fetch_watch_snapshot(symbol: str, market: str) -> dict[str, Any]:
    """사이드바 관심종목용 현재가/등락률 스냅샷.

    국장은 yfinance가 005930 단독 조회에 실패하는 경우가 많아서
    005930.KS → 005930.KQ → 005930 순서로 재시도한다.
    차트는 나오는데 등락률이 '-'로 보이던 문제를 방지하기 위한 전용 함수.
    """
    result = {
        "symbol": symbol,
        "used_symbol": symbol,
        "last_price": np.nan,
        "prev_close": np.nan,
        "change_pct": np.nan,
        "last_time": "",
        "source": "-",
        "ok": False,
    }
    try:
        import yfinance as yf
    except Exception:
        return result

    # 미장은 기존 Finnhub/yfinance 스냅샷을 그대로 우선 사용
    if market != "한국주식":
        snap = fetch_extended_snapshot(symbol)
        result.update(snap or {})
        result["ok"] = not np.isnan(safe_float(result.get("change_pct"), np.nan))
        return result

    for cand in market_data_symbol_candidates(symbol, market):
        try:
            raw = yf.download(cand, period="10d", interval="1d", progress=False, auto_adjust=False)
            if raw is None or raw.empty:
                continue
            df = flatten_yf_columns(raw.reset_index())
            if "Close" not in df.columns:
                continue
            df["Close"] = pd.to_numeric(df["Close"], errors="coerce")
            df = df.dropna(subset=["Close"])
            if df.empty:
                continue

            last_close = safe_float(df["Close"].iloc[-1], np.nan)
            prev_close = safe_float(df["Close"].iloc[-2], np.nan) if len(df) >= 2 else np.nan
            if np.isnan(last_close) or last_close <= 0:
                continue

            change_pct = np.nan
            if not np.isnan(prev_close) and prev_close > 0:
                change_pct = (last_close / prev_close - 1) * 100

            date_col = "Date" if "Date" in df.columns else ("Datetime" if "Datetime" in df.columns else df.columns[0])
            last_time = ""
            try:
                last_time = format_kst_full_label(df[date_col].iloc[-1])
            except Exception:
                last_time = str(df[date_col].iloc[-1]) if date_col in df.columns else ""

            result.update({
                "used_symbol": cand,
                "last_price": last_close,
                "prev_close": prev_close,
                "change_pct": change_pct,
                "last_time": last_time,
                "source": "yfinance daily",
                "ok": not np.isnan(change_pct),
            })
            return result
        except Exception:
            continue

    return result


def next_weekday(d: date) -> date:
    d = d + timedelta(days=1)
    while d.weekday() >= 5:
        d += timedelta(days=1)
    return d


def previous_weekday(d: date) -> date:
    d = d - timedelta(days=1)
    while d.weekday() >= 5:
        d -= timedelta(days=1)
    return d


KST = ZoneInfo("Asia/Seoul")
US_ET = ZoneInfo("America/New_York")


def us_session_context(now_kst: datetime | None = None) -> dict[str, Any]:
    """
    한국 시간 기준 현재 시각을 미국 동부시간으로 변환해 장 상태와 예측 대상일을 계산한다.

    핵심 원칙:
    - 미국 프리마켓/정규장 중 저장한 예측은 그날 미국장 target_date로 기록
    - 미국 장마감 후/휴장 시간 저장한 예측은 다음 미국 거래일 target_date로 기록
    - 한국 오전 7시 실행은 직전 완료된 예측의 실제 OHLC 업데이트용
    """
    if now_kst is None:
        now_kst = datetime.now(KST)
    elif now_kst.tzinfo is None:
        now_kst = now_kst.replace(tzinfo=KST)

    now_et = now_kst.astimezone(US_ET)
    et_date = now_et.date()
    et_time = now_et.time()

    premarket_start = datetime.combine(et_date, datetime.min.time().replace(hour=4, minute=0), tzinfo=US_ET).time()
    market_open = datetime.combine(et_date, datetime.min.time().replace(hour=9, minute=30), tzinfo=US_ET).time()
    market_close = datetime.combine(et_date, datetime.min.time().replace(hour=16, minute=0), tzinfo=US_ET).time()
    afterhours_end = datetime.combine(et_date, datetime.min.time().replace(hour=20, minute=0), tzinfo=US_ET).time()

    is_weekday = et_date.weekday() < 5

    if not is_weekday:
        session = "closed_weekend"
        target = next_trading_day_auto("미국주식", et_date)
        label = "주말/휴장 추정 → 다음 거래일 예측"
    elif premarket_start <= et_time < market_open:
        session = "premarket"
        target = et_date
        label = "프리마켓 → 오늘 미국장 예측"
    elif market_open <= et_time < market_close:
        session = "regular"
        target = et_date
        label = "정규장 진행 중 → 오늘 미국장 결과와 비교"
    elif market_close <= et_time < afterhours_end:
        session = "afterhours"
        target = next_trading_day_auto("미국주식", et_date)
        label = "장마감 후/애프터마켓 → 다음 거래일 예측"
    else:
        session = "closed_after_market"
        target = next_trading_day_auto("미국주식", et_date) if et_time >= afterhours_end else et_date
        while not is_trading_day_auto("미국주식", target):
            target = next_trading_day_auto("미국주식", target)
        label = "미장 휴장 시간 → 다음 거래일 예측"

    return {
        "now_kst": now_kst,
        "now_et": now_et,
        "session": session,
        "session_label": label,
        "target_date": target,
        "et_date": et_date,
        "is_market_active": session in {"premarket", "regular"},
    }




def korean_session_context(now_kst: datetime | None = None) -> dict[str, Any]:
    """
    한국장 기준 장 상태와 예측 대상일을 계산한다.
    증권사 API 없이 자동화에 가장 가까운 방식:
    - 장전/정규장 중 예측: 오늘 한국장 target_date
    - 장마감 후/주말 예측: 다음 한국 거래일 target_date
    - 휴일 캘린더는 별도 API가 없으므로 평일 기준으로 보수 적용
    """
    if now_kst is None:
        now_kst = datetime.now(KST)
    elif now_kst.tzinfo is None:
        now_kst = now_kst.replace(tzinfo=KST)

    k_date = now_kst.date()
    k_time = now_kst.time()
    is_weekday = k_date.weekday() < 5

    preopen = datetime.combine(k_date, datetime.min.time().replace(hour=8, minute=30), tzinfo=KST).time()
    market_open = datetime.combine(k_date, datetime.min.time().replace(hour=9, minute=0), tzinfo=KST).time()
    market_close = datetime.combine(k_date, datetime.min.time().replace(hour=15, minute=30), tzinfo=KST).time()

    if not is_weekday:
        session = "closed_weekend"
        target = next_trading_day_auto("한국주식", k_date)
        label = "주말/휴장 추정 → 다음 국장 거래일 예측"
    elif k_time < preopen:
        session = "before_preopen"
        target = k_date
        label = "국장 장전(~08:29) → 오늘 국장 예측 · 전일 정규장 OHLC 기준"
    elif preopen <= k_time < market_open:
        session = "expected_open"
        target = k_date
        label = "08:30~08:59 예상체결가 참고 가능 → 오늘 국장 예측"
    elif market_open <= k_time < market_close:
        session = "regular"
        target = k_date
        label = "국장 정규장 진행 중 → 오늘 국장 결과와 비교"
    else:
        session = "afterclose"
        target = next_trading_day_auto("한국주식", k_date)
        label = "국장 마감 후 → 다음 국장 거래일 예측"

    return {
        "now_kst": now_kst,
        "now_et": datetime.now(US_ET),
        "session": session,
        "session_label": label,
        "target_date": target,
        "et_date": k_date,
        "is_market_active": session in {"expected_open", "regular"},
    }


def market_session_context(market: str) -> dict[str, Any]:
    if market == "한국주식":
        return korean_session_context()
    return us_session_context()


def load_watchlist_df(market: str) -> pd.DataFrame:
    """앱 폴더의 watchlist CSV만 읽는다. 국장은 파일이 없거나 symbol이 없으면 빈 목록(자동 생성·임의 기본값 없음)."""
    kr_cols = ["symbol", "name", "theme", "group", "type", "sector_proxy", "risk_level"]
    path = resolve_watchlist_file(market)
    if path.exists():
        try:
            if market == "미국주식":
                pass
            df = read_csv_cached(path, dtype_str=True).fillna("")
            if market == "미국주식":
                df = normalize_us_ticker_fields_in_df(df, market_aware=False)
            if "symbol" in df.columns:
                df = df[df["symbol"].astype(str).str.strip() != ""]
                if market == "한국주식":
                    return df if not df.empty else pd.DataFrame(columns=kr_cols)
                return drop_excluded_us_stock_rows(df, market) if not df.empty else pd.DataFrame(columns=kr_cols)
        except Exception:
            pass

    if market == "한국주식":
        return pd.DataFrame(columns=kr_cols)
    fallback = [(t, "", growth_theme_for_ticker(t), "기본", "growth", infer_sector(t), "중") for t in default_growth_watchlist()]
    fb = pd.DataFrame(fallback, columns=["symbol", "name", "theme", "group", "type", "sector_proxy", "risk_level"])
    return drop_excluded_us_stock_rows(fb, market)


def watchlist_symbols(market: str) -> list[str]:
    df = load_watchlist_df(market)
    if df.empty or "symbol" not in df.columns:
        return default_growth_watchlist() if market == "미국주식" else []
    if market == "한국주식":
        return [normalize_ticker(x, "한국주식") for x in df["symbol"].astype(str).tolist() if str(x).strip()]
    return [str(x).strip().upper() for x in df["symbol"].astype(str).tolist() if str(x).strip()]


def watchlist_meta_map(market: str) -> dict[str, dict[str, Any]]:
    df = load_watchlist_df(market)
    out: dict[str, dict[str, Any]] = {}
    if df.empty or "symbol" not in df.columns:
        return out
    for _, r in df.iterrows():
        sym = normalize_ticker(r.get("symbol", ""), market)
        out[sym] = {k: r.get(k, "") for k in df.columns}
    return out


def korean_theme_score(symbol: str, meta: dict[str, Any], us_bench_df: pd.DataFrame, event_context: dict[str, Any]) -> int:
    """
    국장 자동화용 1차 테마 점수.
    증권사 API 없이 전일 미국장·섹터 ETF·테마 분류를 반영하는 보수 점수.
    """
    theme = str(meta.get("theme", "")) + " " + str(meta.get("group", "")) + " " + str(meta.get("sector_proxy", ""))
    auto_market = calculate_auto_market_score(us_bench_df) if not us_bench_df.empty else 0
    score = auto_market

    # 미국 AI/반도체 강세 → 한국 반도체/HBM 가점
    smh = 0.0
    qqq = 0.0
    try:
        us_bench_df = normalize_benchmark_df(us_bench_df)
        if not us_bench_df.empty:
            sym_col = "symbol" if "symbol" in us_bench_df.columns else "ticker"
            smh_rows = us_bench_df[us_bench_df[sym_col].isin(["SMH", "SOXX"])]
            qqq_rows = us_bench_df[us_bench_df[sym_col].isin(["QQQ"])]
            smh = float(smh_rows["change_pct"].mean()) if not smh_rows.empty else 0.0
            qqq = float(qqq_rows["change_pct"].mean()) if not qqq_rows.empty else 0.0
    except Exception:
        pass

    if any(k in theme for k in ["반도체", "HBM", "AI"]):
        score += 2 if smh >= 1.0 else 1 if smh > 0 else -1 if smh < -1 else 0
    if any(k in theme for k in ["전력", "전선", "원전"]):
        score += 1 if qqq > 0 else 0
    if any(k in theme for k in ["방산", "우주", "조선", "로봇"]):
        score += 1 if auto_market >= 1 else 0
    if event_context.get("risk_mult", 1.0) >= 1.55:
        score -= 1

    return int(max(-3, min(3, score)))


def scan_candidate_tickers_kr(
    tickers: list[str],
    log_df: pd.DataFrame,
    bench_df: pd.DataFrame,
    event_context: dict[str, Any],
    max_count: int = 30,
    min_score: int = 0,
) -> pd.DataFrame:
    """국장 후보 스캐너. API 없이 일봉+전일 미장+테마+오차 기록을 반영."""
    meta_map = watchlist_meta_map("한국주식")
    rows = []

    for raw in tickers[:max_count]:
        t = normalize_ticker(raw, "한국주식")
        if not t:
            continue

        meta = meta_map.get(t, {})
        df = load_stock_data(t, "한국주식", 0.75)
        if df.empty or len(df) < 50:
            continue

        df = calculate_indicators(df)
        sr = calculate_support_resistance(df)
        trade = calculate_trade_score(df, sr)
        last = df.iloc[-1]
        cur = safe_float(last.get("Close"), 0.0)
        prev = safe_float(df.iloc[-2].get("Close"), cur) if len(df) >= 2 else cur
        chg = (cur / prev - 1) * 100 if prev else 0.0
        rsi = safe_float(last.get("RSI"), 50)
        vol_ratio = safe_float(last.get("VOL_RATIO"), 1)
        close_20 = safe_float(df.iloc[-20].get("Close"), cur) if len(df) >= 20 else cur
        close_60 = safe_float(df.iloc[-60].get("Close"), cur) if len(df) >= 60 else cur
        mom20 = (cur / close_20 - 1) * 100 if close_20 else 0
        mom60 = (cur / close_60 - 1) * 100 if close_60 else 0
        sector_score = korean_theme_score(t, meta, bench_df, event_context)
        bias = get_recent_bias_adjustment(log_df, t, event_context)
        confidence = calculate_confidence_score(
            bias, {}, bench_df, event_context,
            safe_float(last.get("ATR"), 0) / max(cur, 1) * 100,
            sector_score, calculate_auto_market_score(bench_df) if not bench_df.empty else 0,
        )
        pred = calculate_prediction(
            df=df, sr=sr, market="한국주식",
            market_score=calculate_auto_market_score(bench_df) if not bench_df.empty else 0,
            sector_score=sector_score, news_score=0,
            premarket_price=None, premarket_weight=0,
            open_bias_adjustment_pct=bias.get("open_bias_pct", 0.0),
            close_bias_adjustment_pct=bias.get("close_bias_pct", 0.0),
            event_context=event_context, confidence=confidence,
        )

        risk_level = str(meta.get("risk_level", "중"))
        risk_penalty = 8 if risk_level == "매우 높음" else 4 if risk_level == "높음" else 0
        theme_bonus = 7 if str(meta.get("type", "")) in {"growth", "speculative"} else 3
        momentum_bonus = max(-10, min(14, mom20 * 0.45 + mom60 * 0.15))
        liquidity_bonus = 5 if vol_ratio >= 1.3 else 0
        no_buy_penalty = 10 if pred.get("no_buy_flags") else 0
        candidate_score = int(max(0, min(100, round(
            trade["score"] * 0.30
            + momentum_bonus
            + sector_score * 6
            + confidence["score"] * 0.16
            + theme_bonus
            + liquidity_bonus
            + (6 if 45 <= rsi <= 68 else -8 if rsi >= 75 else 0)
            - risk_penalty
            - no_buy_penalty
        ))))

        if candidate_score < min_score:
            continue

        if candidate_score >= 82:
            label = "상승 후보 강함"
        elif candidate_score >= 70:
            label = "조건부 상승 후보"
        elif candidate_score >= 58:
            label = "관찰 후보"
        else:
            label = "관망 우위"

        notes = []
        if rsi >= 75:
            notes.append("RSI 과열")
        if vol_ratio < 0.7:
            notes.append("거래량 약함")
        if event_context.get("risk_mult", 1) >= 1.55:
            notes.append("대형 이벤트 변동성")
        if pred.get("no_buy_flags"):
            notes += pred.get("no_buy_flags", [])[:2]

        rows.append({
            "순위점수": candidate_score,
            "종목": t,
            "회사명": meta.get("name", ""),
            "성장테마": meta.get("theme", ""),
            "분류": meta.get("group", ""),
            "위험도": risk_level,
            "최근가": fmt_price(cur, "한국주식"),
            "전일대비": pct(chg),
            "20일모멘텀": pct(mom20),
            "60일모멘텀": pct(mom60),
            "거래량배율": f"{vol_ratio:.2f}배",
            "기술점수": trade["score"],
            "테마점수": sector_score,
            "신뢰도": confidence["score"],
            "예상시초가": fmt_price(pred["pred_open_mid"], "한국주식"),
            "예상종가범위": f"{fmt_price(pred['pred_close_low'], '한국주식')} ~ {fmt_price(pred['pred_close_high'], '한국주식')}",
            "주문판단": label,
            "우선진입가": fmt_price(pred["preferred_entry"], "한국주식"),
            "손절가": fmt_price(pred["stop_loss"], "한국주식"),
            "1차익절가": fmt_price(pred["take_profit1"], "한국주식"),
            "주의사유": " / ".join(notes) if notes else "-",
            "관찰이유": meta.get("why_watch", ""),
            "확인트리거": meta.get("watch_trigger", ""),
            "회피조건": meta.get("avoid_condition", ""),
        })

    if not rows:
        return pd.DataFrame()
    return pd.DataFrame(rows).sort_values("순위점수", ascending=False).reset_index(drop=True)


def scan_candidate_tickers_auto(
    tickers: list[str],
    market: str,
    log_df: pd.DataFrame,
    bench_df: pd.DataFrame,
    event_context: dict[str, Any],
    max_count: int = 25,
    lesser_known_only: bool = False,
    min_score: int = 0,
) -> pd.DataFrame:
    if market == "한국주식":
        return scan_candidate_tickers_kr(
            tickers=tickers, log_df=log_df, bench_df=bench_df,
            event_context=event_context, max_count=max_count, min_score=min_score,
        )
    return scan_candidate_tickers(
        tickers=tickers, log_df=log_df, bench_df=bench_df,
        event_context=event_context, max_count=max_count,
        lesser_known_only=lesser_known_only, min_score=min_score,
    )


def infer_target_date_from_created_at(created_at: Any, fallback: date | None = None) -> tuple[date | None, str]:
    """기존 predictions.csv에서 장중 예측인데 target_date가 다음 거래일로 밀린 기록을 보정하기 위한 함수."""
    try:
        dt = pd.to_datetime(created_at).to_pydatetime()
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=KST)
        ctx = us_session_context(dt.astimezone(KST))
        return ctx["target_date"], ctx["session"]
    except Exception:
        return fallback, "unknown"


def repair_prediction_target_dates(log_df: pd.DataFrame) -> tuple[pd.DataFrame, int]:
    """
    v3.5 이전 기록 중 미국 장전/장중 예측이 다음 거래일로 밀린 케이스를 자동 보정한다.
    예: 한국시간 00:57 = 미국 정규장 중인데 target_date가 월요일로 저장된 경우.
    """
    if log_df.empty or "target_date" not in log_df.columns:
        return log_df, 0

    df = log_df.copy()
    df = ensure_object_columns(df, TEXT_LOG_COLUMNS)
    repaired = 0

    for col, default in [
        ("target_repaired", False),
        ("target_repair_note", ""),
        ("session_type", ""),
        ("session_label", ""),
        ("original_target_date", ""),
    ]:
        if col not in df.columns:
            df[col] = default

    for idx, row in df.iterrows():
        if str(row.get("market", "미국주식")) != "미국주식":
            continue

        # 이미 실제 결과가 들어간 기록은 건드리지 않음
        if "actual_close" in df.columns and pd.notna(row.get("actual_close")):
            continue

        created = row.get("created_at")
        old_target_raw = row.get("target_date")
        if pd.isna(created) or pd.isna(old_target_raw):
            continue

        old_target = pd.to_datetime(old_target_raw, errors="coerce")
        if pd.isna(old_target):
            continue

        inferred, session = infer_target_date_from_created_at(created, fallback=old_target.date())
        if inferred is None:
            continue

        old_date = old_target.date()

        # 프리마켓/정규장 저장분은 그날 결과와 비교해야 함
        if session in {"premarket", "regular"} and inferred != old_date:
            df.loc[idx, "original_target_date"] = str(old_date)
            df.loc[idx, "target_date"] = str(inferred)
            df.loc[idx, "target_repaired"] = True
            df.loc[idx, "target_repair_note"] = f"v3.6 자동보정: {session} 예측은 {inferred} 결과와 비교"
            df.loc[idx, "session_type"] = session
            repaired += 1
        elif not str(row.get("session_type", "")).strip():
            df.loc[idx, "session_type"] = session

    return df, repaired


def third_friday(year: int, month: int) -> date:
    d = date(year, month, 1)
    while d.weekday() != 4:
        d += timedelta(days=1)
    return d + timedelta(days=14)


def infer_sector(ticker: str) -> str:
    t = str(ticker).upper()
    return SECTOR_HINTS.get(t, LESSER_KNOWN_SECTOR_HINTS.get(t, "지수형"))


def score_from_pct(change_pct: float, inverse: bool = False) -> int:
    """등락률을 -3~+3 점수로 변환."""
    if np.isnan(change_pct):
        return 0
    if change_pct >= 1.5:
        score = 3
    elif change_pct >= 0.7:
        score = 2
    elif change_pct >= 0.2:
        score = 1
    elif change_pct <= -1.5:
        score = -3
    elif change_pct <= -0.7:
        score = -2
    elif change_pct <= -0.2:
        score = -1
    else:
        score = 0
    return -score if inverse else score


@st.cache_data(ttl=60, show_spinner=False)
@st.cache_data(ttl=45, show_spinner=False)
def fetch_wti_cl_snapshot() -> dict[str, Any]:
    """WTI(CL=F) 긴급 복구 스냅샷.
    1) Yahoo Chart API 직접조회
    2) yfinance Ticker.history
    3) yfinance download
    4) fast_info
    순서로 CL=F만 조회한다. Brent/USO 대체 없음.
    """
    result = {
        "ticker": "CL=F",
        "last_price": np.nan,
        "prev_close": np.nan,
        "change_pct": np.nan,
        "last_time": "",
        "volume": np.nan,
        "source": "WTI CL=F",
        "data_note": "WTI 선물(CL=F) · 무료 데이터 지연 가능",
    }

    def _apply_price(px: Any, pc: Any = np.nan, ts: Any = "", volume: Any = np.nan, source: str = "") -> bool:
        p = safe_float(px, np.nan)
        if np.isnan(p) or p <= 0:
            return False
        result["last_price"] = p
        prev = safe_float(pc, np.nan)
        if not np.isnan(prev) and prev > 0:
            result["prev_close"] = prev
        if ts:
            try:
                dt = datetime.fromtimestamp(int(ts), tz=timezone.utc).astimezone(KST)
                result["last_time"] = dt.strftime("%m-%d %H:%M KST")
            except Exception:
                try:
                    kt = to_kst_datetime(ts)
                    result["last_time"] = kt.strftime("%m-%d %H:%M KST") if pd.notna(kt) else str(ts)
                except Exception:
                    result["last_time"] = str(ts)
        v = safe_float(volume, np.nan)
        if not np.isnan(v):
            result["volume"] = v
        if source:
            result["source"] = source
        return True

    # 1) Yahoo Chart API 직접조회: yfinance가 비어도 chart endpoint는 살아있는 경우가 많음
    try:
        import requests
        from urllib.parse import quote
        encoded = quote("CL=F", safe="")
        for interval in ["1m", "5m", "15m", "30m"]:
            url = f"https://query1.finance.yahoo.com/v8/finance/chart/{encoded}"
            params = {
                "range": "5d",
                "interval": interval,
                "includePrePost": "true",
                "events": "div,splits",
            }
            headers = {"User-Agent": "Mozilla/5.0"}
            r = requests.get(url, params=params, headers=headers, timeout=7)
            if r.status_code != 200:
                continue
            payload = r.json() or {}
            chart = (payload.get("chart") or {}).get("result") or []
            if not chart:
                continue
            data = chart[0]
            meta = data.get("meta") or {}
            prev = safe_float(
                meta.get("chartPreviousClose")
                or meta.get("previousClose")
                or meta.get("regularMarketPreviousClose"),
                np.nan,
            )
            timestamps = data.get("timestamp") or []
            quote_data = ((data.get("indicators") or {}).get("quote") or [{}])[0]
            closes = quote_data.get("close") or []
            volumes = quote_data.get("volume") or []
            valid = []
            for idx, close in enumerate(closes):
                c = safe_float(close, np.nan)
                if not np.isnan(c) and c > 0:
                    valid.append((idx, c))
            if valid:
                idx, px = valid[-1]
                ts = timestamps[idx] if idx < len(timestamps) else ""
                vol = volumes[idx] if idx < len(volumes) else np.nan
                if _apply_price(px, prev, ts, vol, f"Yahoo Chart CL=F {interval}"):
                    break
    except Exception:
        pass

    # 2) yfinance Ticker.history fallback
    if np.isnan(safe_float(result.get("last_price"), np.nan)):
        try:
            import yfinance as yf
            obj = yf.Ticker("CL=F")
            for interval in ["1m", "5m", "15m", "30m", "1d"]:
                try:
                    hist = obj.history(period="5d", interval=interval, prepost=True, auto_adjust=False)
                    if hist is None or hist.empty or "Close" not in hist.columns:
                        continue
                    closes = pd.to_numeric(hist["Close"], errors="coerce").dropna()
                    if closes.empty:
                        continue
                    px = float(closes.iloc[-1])
                    prev = np.nan
                    if len(closes) >= 2 and interval == "1d":
                        prev = float(closes.iloc[-2])
                    ts = hist.index[-1]
                    vol = hist["Volume"].iloc[-1] if "Volume" in hist.columns else np.nan
                    if _apply_price(px, prev, ts, vol, f"yfinance history CL=F {interval}"):
                        break
                except Exception:
                    continue
        except Exception:
            pass

    # 3) yfinance download fallback
    if np.isnan(safe_float(result.get("last_price"), np.nan)):
        try:
            import yfinance as yf
            for interval in ["5m", "15m", "30m", "1d"]:
                raw = yf.download("CL=F", period="5d", interval=interval, prepost=True, progress=False, auto_adjust=False)
                if raw is None or raw.empty:
                    continue
                df = flatten_yf_columns(raw.reset_index())
                if "Close" not in df.columns:
                    continue
                df["Close"] = pd.to_numeric(df["Close"], errors="coerce")
                df = df.dropna(subset=["Close"])
                if df.empty:
                    continue
                last = df.iloc[-1]
                px = safe_float(last.get("Close"), np.nan)
                prev = np.nan
                if interval == "1d" and len(df) >= 2:
                    prev = safe_float(df["Close"].iloc[-2], np.nan)
                time_col = "Datetime" if "Datetime" in df.columns else ("Date" if "Date" in df.columns else df.columns[0])
                ts = last.get(time_col, "")
                vol = last.get("Volume", np.nan) if "Volume" in df.columns else np.nan
                if _apply_price(px, prev, ts, vol, f"yfinance download CL=F {interval}"):
                    break
        except Exception:
            pass

    # 4) fast_info previous_close/last_price 보강
    try:
        import yfinance as yf
        obj = yf.Ticker("CL=F")
        fi = getattr(obj, "fast_info", {}) or {}
        if hasattr(fi, "get"):
            if np.isnan(safe_float(result.get("last_price"), np.nan)):
                _apply_price(fi.get("last_price"), np.nan, "", np.nan, "yfinance fast_info CL=F")
            if np.isnan(safe_float(result.get("prev_close"), np.nan)):
                pc = safe_float(
                    fi.get("previous_close")
                    or fi.get("regular_market_previous_close")
                    or fi.get("last_close"),
                    np.nan,
                )
                if not np.isnan(pc) and pc > 0:
                    result["prev_close"] = pc
    except Exception:
        pass

    # previous close 최종 보강: 일봉 전일값
    if np.isnan(safe_float(result.get("prev_close"), np.nan)):
        try:
            import yfinance as yf
            daily = yf.download("CL=F", period="10d", interval="1d", progress=False, auto_adjust=False)
            if daily is not None and not daily.empty:
                d = flatten_yf_columns(daily.reset_index())
                d["Close"] = pd.to_numeric(d["Close"], errors="coerce")
                closes = d["Close"].dropna()
                if len(closes) >= 2:
                    result["prev_close"] = float(closes.iloc[-2])
                elif len(closes) == 1:
                    result["prev_close"] = float(closes.iloc[-1])
        except Exception:
            pass

    lp = safe_float(result.get("last_price"), np.nan)
    pc = safe_float(result.get("prev_close"), np.nan)
    if not np.isnan(lp) and not np.isnan(pc) and pc > 0:
        result["change_pct"] = (lp / pc - 1) * 100

    if np.isnan(lp):
        result["data_note"] = "CL=F 조회 실패 · Yahoo 선물 데이터 일시 비어 있음"
        result["source"] = "CL=F unavailable"

    return result


def fetch_extended_snapshot(ticker: str) -> dict[str, Any]:
    """Finnhub key가 있으면 미장 주식/ETF는 Finnhub 우선, 실패 시 yfinance fallback."""
    if str(ticker).upper().strip() == "CL=F":
        return fetch_wti_cl_snapshot()
    result = {
        "ticker": ticker, "last_price": np.nan, "prev_close": np.nan,
        "change_pct": np.nan, "last_time": "", "volume": np.nan, "source": "yfinance",
    }
    try:
        api_key = load_finnhub_api_key()
        if api_key and is_finnhub_quote_symbol(str(ticker).upper()):
            fh = fetch_finnhub_quote_snapshot(str(ticker).upper(), api_key)
            if bool(fh.get("finnhub_ok")):
                return fh
        import yfinance as yf
        t = str(ticker).upper()
        try:
            obj = yf.Ticker(t)
            fi = getattr(obj, "fast_info", {}) or {}
            if hasattr(fi, "get"):
                result["prev_close"] = safe_float(
                    fi.get("previous_close")
                    or fi.get("regular_market_previous_close")
                    or fi.get("last_close"),
                    np.nan,
                )
        except Exception:
            pass
        if np.isnan(safe_float(result.get("prev_close"), np.nan)):
            daily = yf.download(t, period="5d", interval="1d", progress=False, auto_adjust=False)
            if daily is not None and not daily.empty:
                daily = flatten_yf_columns(daily.reset_index())
                closes = pd.to_numeric(daily["Close"], errors="coerce").dropna()
                if len(closes) >= 2:
                    result["prev_close"] = float(closes.iloc[-2])
                elif len(closes) >= 1:
                    result["prev_close"] = float(closes.iloc[-1])
        intraday = yf.download(t, period="2d", interval="1m", prepost=True, progress=False, auto_adjust=False)
        if intraday is not None and not intraday.empty:
            intraday = flatten_yf_columns(intraday.reset_index())
            price_col = "Close" if "Close" in intraday.columns else intraday.columns[-1]
            intraday[price_col] = pd.to_numeric(intraday[price_col], errors="coerce")
            intraday = intraday.dropna(subset=[price_col])
            if not intraday.empty:
                last = intraday.iloc[-1]
                result["last_price"] = float(last[price_col])
                time_col = "Datetime" if "Datetime" in intraday.columns else ("Date" if "Date" in intraday.columns else intraday.columns[0])
                result["last_time"] = format_kst_short_label(last[time_col])
                if "Volume" in intraday.columns:
                    result["volume"] = safe_float(last.get("Volume"), np.nan)
        if not np.isnan(result["last_price"]) and not np.isnan(result["prev_close"]) and result["prev_close"] > 0:
            result["change_pct"] = (result["last_price"] / result["prev_close"] - 1) * 100
        return result
    except Exception:
        return result


@st.cache_data(ttl=3600, show_spinner=False)
def fetch_company_profile(ticker: str) -> dict[str, Any]:
    """스캐너 보조용 회사 프로필. 실패해도 앱이 멈추지 않게 최소 정보만 반환."""
    result = {"ticker": ticker, "name": "", "market_cap": np.nan, "avg_volume": np.nan, "sector": ""}
    try:
        import yfinance as yf
        obj = yf.Ticker(str(ticker).upper())
        info = getattr(obj, "fast_info", {}) or {}
        result["market_cap"] = safe_float(info.get("market_cap"), np.nan) if hasattr(info, "get") else np.nan
        result["avg_volume"] = safe_float(info.get("ten_day_average_volume"), np.nan) if hasattr(info, "get") else np.nan
        # info 호출은 느릴 수 있어 필요한 경우만 보조적으로 사용
        try:
            infod = obj.get_info()
            result["name"] = infod.get("shortName") or infod.get("longName") or ""
            result["sector"] = infod.get("sector", "")
            if np.isnan(result["market_cap"]):
                result["market_cap"] = safe_float(infod.get("marketCap"), np.nan)
            if np.isnan(result["avg_volume"]):
                result["avg_volume"] = safe_float(infod.get("averageVolume"), np.nan)
        except Exception:
            pass
        return result
    except Exception:
        return result


@st.cache_data(ttl=180, show_spinner=False)
def analyze_premarket_quality(ticker: str) -> dict[str, Any]:
    """프리마켓/확장세션 가격을 얼마나 믿을지 판단하는 품질 점수.

    무료 yfinance 데이터 기준이라 지연/누락이 있을 수 있습니다.
    핵심은 등락률 자체보다 '거래량이 충분한가'를 반영해 프리마켓 반영 비중을 조정하는 것입니다.
    """
    result = {
        "premarket_volume": np.nan,
        "avg_daily_volume": np.nan,
        "volume_ratio": np.nan,
        "quality_score": 45,
        "quality_label": "미확인",
        "weight_factor": 0.70,
        "reason": "프리마켓 거래량 확인 불가",
    }
    try:
        import yfinance as yf
        t = str(ticker).upper()
        daily = yf.download(t, period="30d", interval="1d", progress=False, auto_adjust=False)
        if daily is not None and not daily.empty:
            daily = flatten_yf_columns(daily.reset_index())
            if "Volume" in daily.columns:
                vols = pd.to_numeric(daily["Volume"], errors="coerce").dropna()
                if len(vols) > 0:
                    result["avg_daily_volume"] = float(vols.tail(20).mean())

        intraday = yf.download(t, period="5d", interval="1m", prepost=True, progress=False, auto_adjust=False)
        if intraday is None or intraday.empty:
            return result
        intraday = flatten_yf_columns(intraday.reset_index())
        time_col = "Datetime" if "Datetime" in intraday.columns else ("Date" if "Date" in intraday.columns else intraday.columns[0])
        intraday[time_col] = pd.to_datetime(intraday[time_col], errors="coerce")
        intraday = intraday.dropna(subset=[time_col])
        if intraday.empty or "Volume" not in intraday.columns:
            return result

        dt = intraday[time_col]
        try:
            if getattr(dt.dt, "tz", None) is not None:
                dt_et = dt.dt.tz_convert("America/New_York")
            else:
                dt_et = dt
        except Exception:
            dt_et = dt
        intraday = intraday.assign(_dt_et=dt_et)
        last_day = intraday["_dt_et"].dt.date.max()
        cur_day = intraday[intraday["_dt_et"].dt.date == last_day].copy()
        if cur_day.empty:
            return result
        times = cur_day["_dt_et"].dt.time
        # 미국 프리마켓 04:00~09:30 ET. 장후 데이터만 있는 경우도 포함해 확장세션 거래량으로 해석.
        import datetime as _dt
        pm_mask = (times >= _dt.time(4, 0)) & (times < _dt.time(9, 30))
        ah_mask = (times >= _dt.time(16, 0)) & (times <= _dt.time(20, 0))
        ext = cur_day[pm_mask | ah_mask]
        if ext.empty:
            ext = cur_day.tail(120)
        vol = pd.to_numeric(ext["Volume"], errors="coerce").fillna(0)
        pm_vol = float(vol.sum())
        result["premarket_volume"] = pm_vol
        avg_vol = safe_float(result["avg_daily_volume"], np.nan)
        ratio = pm_vol / avg_vol if avg_vol and not np.isnan(avg_vol) and avg_vol > 0 else np.nan
        result["volume_ratio"] = ratio
        if np.isnan(ratio):
            return result
        if ratio >= 0.10:
            result.update({"quality_score": 88, "quality_label": "강함", "weight_factor": 1.08, "reason": f"확장세션 거래량이 20일 평균의 {ratio*100:.1f}%로 높음"})
        elif ratio >= 0.045:
            result.update({"quality_score": 72, "quality_label": "보통 이상", "weight_factor": 0.92, "reason": f"확장세션 거래량이 20일 평균의 {ratio*100:.1f}%"})
        elif ratio >= 0.015:
            result.update({"quality_score": 55, "quality_label": "보통", "weight_factor": 0.72, "reason": f"확장세션 거래량이 20일 평균의 {ratio*100:.1f}%로 제한적"})
        else:
            result.update({"quality_score": 35, "quality_label": "약함", "weight_factor": 0.45, "reason": f"확장세션 거래량이 20일 평균의 {ratio*100:.1f}%에 불과"})
        return result
    except Exception:
        return result


@st.cache_data(ttl=21600, show_spinner=False)
def fetch_fundamental_growth_score(ticker: str) -> dict[str, Any]:
    """덜 알려진 성장 후보 스캐너용 간단한 펀더멘털 성장 점수.

    yfinance info가 비어 있으면 점수는 중립 이하로 처리합니다. 재무 데이터는 지연/누락 가능성이 있습니다.
    """
    result = {"score": 0, "label": "미확인", "reasons": [], "red_flags": []}
    try:
        import yfinance as yf
        info = yf.Ticker(str(ticker).upper()).get_info() or {}
        score = 0
        reasons: list[str] = []
        flags: list[str] = []
        revenue_growth = safe_float(info.get("revenueGrowth"), np.nan)
        earnings_growth = safe_float(info.get("earningsGrowth"), np.nan)
        gross_margin = safe_float(info.get("grossMargins"), np.nan)
        operating_margin = safe_float(info.get("operatingMargins"), np.nan)
        debt_to_equity = safe_float(info.get("debtToEquity"), np.nan)
        free_cashflow = safe_float(info.get("freeCashflow"), np.nan)
        current_ratio = safe_float(info.get("currentRatio"), np.nan)
        market_cap = safe_float(info.get("marketCap"), np.nan)
        beta = safe_float(info.get("beta"), np.nan)

        if not np.isnan(revenue_growth):
            if revenue_growth >= 0.30:
                score += 22; reasons.append(f"매출 성장률 {revenue_growth*100:.1f}%")
            elif revenue_growth >= 0.15:
                score += 15; reasons.append(f"매출 성장률 {revenue_growth*100:.1f}%")
            elif revenue_growth >= 0.05:
                score += 7; reasons.append(f"매출 성장률 {revenue_growth*100:.1f}%")
            elif revenue_growth < 0:
                score -= 10; flags.append(f"매출 역성장 {revenue_growth*100:.1f}%")
        else:
            flags.append("매출 성장률 데이터 없음")

        if not np.isnan(earnings_growth):
            if earnings_growth >= 0.25:
                score += 12; reasons.append(f"이익 성장률 {earnings_growth*100:.1f}%")
            elif earnings_growth >= 0.05:
                score += 6; reasons.append(f"이익 성장률 {earnings_growth*100:.1f}%")
            elif earnings_growth < -0.15:
                score -= 8; flags.append(f"이익 성장 부진 {earnings_growth*100:.1f}%")

        if not np.isnan(gross_margin):
            if gross_margin >= 0.55:
                score += 8; reasons.append("높은 매출총이익률")
            elif gross_margin < 0.20:
                score -= 4; flags.append("낮은 매출총이익률")
        if not np.isnan(operating_margin):
            if operating_margin >= 0.15:
                score += 8; reasons.append("영업이익률 양호")
            elif operating_margin < -0.10:
                score -= 8; flags.append("영업손실 폭 큼")
        if not np.isnan(free_cashflow):
            if free_cashflow > 0:
                score += 8; reasons.append("FCF 양수")
            else:
                score -= 4; flags.append("FCF 음수")
        if not np.isnan(debt_to_equity):
            if debt_to_equity <= 80:
                score += 5; reasons.append("부채 부담 낮음")
            elif debt_to_equity >= 200:
                score -= 8; flags.append("부채비율 높음")
        if not np.isnan(current_ratio):
            if current_ratio >= 1.2:
                score += 3
            elif current_ratio < 0.8:
                score -= 4; flags.append("유동비율 낮음")
        if not np.isnan(market_cap):
            if 1_000_000_000 <= market_cap <= 80_000_000_000:
                score += 6; reasons.append("중소·중견 성장주 구간")
            elif market_cap < 500_000_000:
                score -= 8; flags.append("초소형주 유동성/변동성 리스크")
        if not np.isnan(beta) and beta >= 2.5:
            flags.append("고베타 변동성 큼")
            score -= 3
        score = int(max(0, min(100, score)))
        if score >= 65:
            label = "성장성 양호"
        elif score >= 45:
            label = "성장성 보통"
        elif score >= 25:
            label = "검증 필요"
        else:
            label = "취약/미확인"
        result.update({"score": score, "label": label, "reasons": reasons[:5], "red_flags": flags[:5]})
        return result
    except Exception:
        return result


def calculate_order_backtest_stats(log_df: pd.DataFrame, ticker: str | None = None) -> dict[str, Any]:
    """저장 기록에서 주문 기준가가 실제 장중 가격에 닿았는지 요약."""
    if log_df is None or log_df.empty:
        return {"n": 0, "entry_rate": np.nan, "tp1_rate": np.nan, "tp2_rate": np.nan, "stop_rate": np.nan, "clean_tp1_rate": np.nan, "label": "기록 부족"}
    df = log_df.copy()
    if ticker:
        df = df[df.get("ticker", "").astype(str).str.upper() == str(ticker).upper()]
    if df.empty:
        return {"n": 0, "entry_rate": np.nan, "tp1_rate": np.nan, "tp2_rate": np.nan, "stop_rate": np.nan, "clean_tp1_rate": np.nan, "label": "기록 부족"}
    for c in ["entry_touched", "tp1_touched", "tp2_touched", "stop_touched"]:
        if c not in df.columns:
            df[c] = np.nan
    done = df[pd.to_numeric(df.get("actual_close"), errors="coerce").notna()].copy()
    if done.empty:
        return {"n": 0, "entry_rate": np.nan, "tp1_rate": np.nan, "tp2_rate": np.nan, "stop_rate": np.nan, "clean_tp1_rate": np.nan, "label": "업데이트 기록 없음"}
    def bmean(col: str) -> float:
        return done[col].astype(str).str.lower().isin(["true", "1"]).mean()
    entry = bmean("entry_touched")
    tp1 = bmean("tp1_touched")
    tp2 = bmean("tp2_touched")
    stop = bmean("stop_touched")
    clean_tp1 = (done["entry_touched"].astype(str).str.lower().isin(["true", "1"]) & done["tp1_touched"].astype(str).str.lower().isin(["true", "1"]) & ~done["stop_touched"].astype(str).str.lower().isin(["true", "1"])).mean()
    if len(done) < 5:
        label = "기록 부족"
    elif clean_tp1 >= 0.45 and stop <= 0.35:
        label = "주문 기준 양호"
    elif stop >= 0.55:
        label = "손절 터치 과다"
    elif entry < 0.30:
        label = "진입가 과도하게 보수적"
    else:
        label = "보통"
    return {"n": int(len(done)), "entry_rate": entry, "tp1_rate": tp1, "tp2_rate": tp2, "stop_rate": stop, "clean_tp1_rate": clean_tp1, "label": label}


def build_rejection_reasons(
    ticker: str,
    pred: dict[str, Any],
    rsi: float,
    premkt_quality: dict[str, Any],
    fundamental: dict[str, Any],
    earnings: dict[str, Any],
    profile: dict[str, Any],
    event_context: dict[str, Any],
) -> list[str]:
    reasons: list[str] = []
    if pred.get("no_buy_flags"):
        reasons.extend(pred.get("no_buy_flags", [])[:3])
    if rsi >= 75:
        reasons.append("RSI 과열")
    if premkt_quality.get("quality_score", 0) < 45:
        reasons.append("프리마켓 거래량 약함")
    if fundamental.get("score", 0) < 25:
        reasons.append("펀더멘털 성장성 미확인/취약")
    if fundamental.get("red_flags"):
        reasons.extend(fundamental.get("red_flags", [])[:2])
    if earnings.get("earnings_near"):
        reasons.append("실적 이벤트 근접")
    if event_context.get("risk_mult", 1) >= 1.55:
        reasons.append("대형 매크로 이벤트 변동성")
    if safe_float(profile.get("avg_volume"), 0) < 300_000:
        reasons.append("평균 거래량 낮음")
    # 중복 제거하면서 순서 유지
    out = []
    for r in reasons:
        if r and r not in out:
            out.append(str(r))
    return out[:6]


@st.cache_data(ttl=3600, show_spinner=False)
def fetch_earnings_context(ticker: str, target: str | date) -> dict[str, Any]:
    """실적 발표 일정/결과/가이던스 이벤트 감지.

    원칙:
    - 예측 전에 이미 알 수 있는 실적 예정/결과/가이던스는 예측에 반영한다.
    - 예측 후 발생한 실적/공시는 원본 예측을 덮어쓰지 않고 장중 사건/복기 사유로 남긴다.
    - 데이터가 없으면 조용히 중립 반환한다.
    """
    result = {
        "earnings_near": False,
        "earnings_date": "",
        "event_text": "",
        "event_type": "",
        "earnings_event_phase": "none",   # scheduled / pre_result / post_result / guidance / none
        "earnings_event_timing": "unknown",
        "earnings_risk_mult": 1.0,
        "earnings_volatility_boost": 1.0,
        "earnings_confidence_penalty": 0,
        "earnings_direction_score": 0,
        "earnings_prediction_rule": "실적 관련 확인 정보 없음",
        "earnings_snapshot_text": "",
    }
    try:
        import yfinance as yf
        target_date = pd.to_datetime(target).date()
        t = str(ticker or "").upper().strip()
        if not t:
            return result

        # 1) yfinance calendar에서 실적 예정일/발표일 추출
        candidates: list[date] = []
        try:
            cal = yf.Ticker(t).calendar
            if isinstance(cal, pd.DataFrame) and not cal.empty:
                for v in cal.values.flatten():
                    try:
                        candidates.append(pd.to_datetime(v).date())
                    except Exception:
                        pass
            elif isinstance(cal, dict):
                for v in cal.values():
                    vals = v if isinstance(v, (list, tuple, set)) else [v]
                    for item in vals:
                        try:
                            candidates.append(pd.to_datetime(item).date())
                        except Exception:
                            pass
        except Exception:
            candidates = []

        candidates = sorted(set(candidates))
        nearest = None
        nearest_diff = None
        for d in candidates:
            diff = (d - target_date).days
            if nearest is None or abs(diff) < abs(nearest_diff):
                nearest = d
                nearest_diff = diff

        if nearest is not None and abs(nearest_diff) <= 3:
            result["earnings_near"] = True
            result["earnings_date"] = str(nearest)
            if nearest_diff > 0:
                timing = f"D-{nearest_diff}"
                phase = "scheduled"
                rule = "예측 전 실적 예정 감지 → 변동성 확대, 범위 확대, 추격매수 금지/소액 분할 우선"
            elif nearest_diff == 0:
                timing = "D-Day"
                phase = "scheduled"
                rule = "실적 당일 → 변동성 최대 구간, 방향 확신보다 리스크 관리 우선"
            else:
                timing = f"D+{abs(nearest_diff)}"
                phase = "post_result"
                rule = "최근 실적 발표 이후 → 뉴스/가이던스 방향을 함께 확인해 예측에 반영"
            result.update({
                "event_text": f"실적 이벤트 {timing}({nearest})",
                "event_type": "EARNINGS",
                "earnings_event_phase": phase,
                "earnings_event_timing": timing,
                "earnings_risk_mult": 1.85 if nearest_diff == 0 else 1.70 if abs(nearest_diff) <= 1 else 1.35,
                "earnings_volatility_boost": 1.28 if nearest_diff == 0 else 1.18 if abs(nearest_diff) <= 1 else 1.08,
                "earnings_confidence_penalty": 14 if nearest_diff == 0 else 10 if abs(nearest_diff) <= 1 else 5,
                "earnings_prediction_rule": rule,
            })

        # 2) 이미 나온 실적/가이던스 뉴스 방향 감지: 예측 전에 나온 뉴스는 예측 반영 대상
        # fetch_ticker_news_context는 이 함수보다 아래에 정의되어 있지만 실행 시점에는 존재한다.
        news_ctx = {}
        if "fetch_ticker_news_context" in globals():
            try:
                news_ctx = fetch_ticker_news_context(t, lookback_hours=72) or {}
            except Exception:
                news_ctx = {}
        news_items = news_ctx.get("auto_news_source_items", []) or []
        hit_titles: list[str] = []
        direction = 0
        severity_max = 0
        neg_terms = ["miss", "misses", "cut", "cuts guidance", "guidance cut", "lower", "weak guidance", "downgrade", "실적 쇼크", "가이던스 하향", "하향", "어닝 쇼크"]
        pos_terms = ["beat", "beats", "raises guidance", "raise guidance", "record revenue", "strong guidance", "upgrade", "실적 호조", "서프라이즈", "가이던스 상향", "상향"]
        key_terms = ["earnings", "revenue", "eps", "guidance", "outlook", "실적", "매출", "영업이익", "가이던스", "전망"]
        for item in news_items[:20]:
            title = str(item.get("title", "") or "")
            low = title.lower()
            if not any(k in low or k in title for k in key_terms):
                continue
            sev = int(safe_float(item.get("severity", 0), 0)) if "safe_float" in globals() else 0
            severity_max = max(severity_max, sev)
            local = 0
            if any(k in low or k in title for k in pos_terms):
                local += 1
            if any(k in low or k in title for k in neg_terms):
                local -= 1
            if local == 0:
                # 기존 뉴스 방향 라벨이 있으면 보조 반영
                dlabel = str(item.get("direction", ""))
                if "우호" in dlabel:
                    local += 1
                elif "부담" in dlabel or "악재" in dlabel:
                    local -= 1
            direction += local
            hit_titles.append(title[:110])

        if hit_titles:
            result["earnings_near"] = True
            if direction > 0:
                phase = "pre_result" if result.get("earnings_event_phase") in {"none", "scheduled"} else result.get("earnings_event_phase")
                label = "실적/가이던스 우호 뉴스 감지"
                dir_score = min(3, direction)
                rule = "실적/가이던스 우호 뉴스는 예측에 반영하되, 갭상승 과열이면 추격매수 금지"
            elif direction < 0:
                phase = "pre_result" if result.get("earnings_event_phase") in {"none", "scheduled"} else result.get("earnings_event_phase")
                label = "실적/가이던스 부담 뉴스 감지"
                dir_score = max(-3, direction)
                rule = "실적/가이던스 악재는 매수금지/관망 가중 및 손절 위험 확대"
            else:
                phase = result.get("earnings_event_phase") if result.get("earnings_event_phase") != "none" else "guidance"
                label = "실적/가이던스 관련 뉴스 감지"
                dir_score = 0
                rule = "실적 관련 뉴스가 있으나 방향 혼재 → 변동성 확대 중심으로 반영"
            result.update({
                "event_text": result.get("event_text") or label,
                "event_type": "EARNINGS",
                "earnings_event_phase": phase,
                "earnings_risk_mult": max(safe_float(result.get("earnings_risk_mult"), 1.0), 1.65 if severity_max >= 6 else 1.45),
                "earnings_volatility_boost": max(safe_float(result.get("earnings_volatility_boost"), 1.0), 1.15),
                "earnings_confidence_penalty": max(int(result.get("earnings_confidence_penalty", 0) or 0), 8),
                "earnings_direction_score": dir_score,
                "earnings_prediction_rule": rule,
                "earnings_snapshot_text": " / ".join(hit_titles[:3]),
            })
            if result["event_text"] and label not in result["event_text"]:
                result["event_text"] = f"{result['event_text']} · {label}"

        return result
    except Exception:
        return result


def earnings_context_to_event_extra_v9963(earnings: dict[str, Any]) -> dict[str, Any]:
    """fetch_earnings_context 결과를 event_context 병합용 dict로 변환."""
    if not earnings or not earnings.get("earnings_near"):
        return {}
    event_text = str(earnings.get("event_text") or "실적 이벤트 감지")
    return {
        "event_names": [event_text],
        "event_types": ["EARNINGS"],
        "risk_mult": max(1.0, safe_float(earnings.get("earnings_risk_mult"), 1.0)),
        "auto_earnings_date": earnings.get("earnings_date", ""),
        "earnings_event_phase": earnings.get("earnings_event_phase", ""),
        "earnings_event_timing": earnings.get("earnings_event_timing", ""),
        "earnings_risk_mult": earnings.get("earnings_risk_mult", 1.0),
        "earnings_volatility_boost": earnings.get("earnings_volatility_boost", 1.0),
        "earnings_confidence_penalty": earnings.get("earnings_confidence_penalty", 0),
        "earnings_direction_score": earnings.get("earnings_direction_score", 0),
        "earnings_prediction_rule": earnings.get("earnings_prediction_rule", ""),
        "earnings_snapshot_text": earnings.get("earnings_snapshot_text", ""),
    }

def growth_theme_for_ticker(ticker: str) -> str:
    t = str(ticker).upper()
    for theme, symbols in LESSER_KNOWN_GROWTH_UNIVERSE.items():
        if t in symbols:
            return theme
    return "사용자 관심종목"


@st.cache_data(ttl=120, show_spinner=False)
def fetch_benchmark_snapshots() -> pd.DataFrame:
    if os.environ.get("STREAMLIT_APP_ENABLE_LIVE_API", "0") != "1":
        return pd.DataFrame()
    rows = []
    for symbol, name in US_BENCHMARKS.items():
        snap = fetch_extended_snapshot(symbol)
        raw_time = snap.get("last_time", "")
        rows.append({
            "symbol": symbol,
            "name": name,
            "last_price": snap.get("last_price"),
            "change_pct": snap.get("change_pct"),
            "score": score_from_pct(safe_float(snap.get("change_pct"), np.nan), inverse=(symbol == "^VIX")),
            "last_time": format_kst_short_label(raw_time),
            "time_status": freshness_status_from_time(raw_time),
        })
    return normalize_benchmark_df(pd.DataFrame(rows))


def normalize_benchmark_df(bench_df: pd.DataFrame) -> pd.DataFrame:
    """벤치마크 DataFrame 컬럼을 symbol/score/change_pct 기준으로 통일한다.

    fetch_benchmark_snapshots(symbol), macro 대시보드(심볼), 캐시/CSV(ticker) 등
    서로 다른 컬럼명이 들어와도 점수 함수가 동일하게 동작하도록 한다.
    """
    if bench_df is None or not isinstance(bench_df, pd.DataFrame) or bench_df.empty:
        return pd.DataFrame()
    df = bench_df.copy()
    sym_src = next((c for c in ("symbol", "ticker", "심볼", "Symbol", "TICKER") if c in df.columns), None)
    if not sym_src:
        return pd.DataFrame()
    df["symbol"] = df[sym_src].astype(str).str.strip()
    if "ticker" not in df.columns:
        df["ticker"] = df["symbol"]
    if "change_pct" not in df.columns and "등락률" in df.columns:
        raw = (
            df["등락률"]
            .astype(str)
            .str.replace("%", "", regex=False)
            .str.replace("+", "", regex=False)
            .str.strip()
        )
        df["change_pct"] = pd.to_numeric(raw, errors="coerce")
    if "score" not in df.columns and "change_pct" in df.columns:
        df["score"] = [
            score_from_pct(
                safe_float(r.get("change_pct"), np.nan),
                inverse=(str(r.get("symbol", "")) == "^VIX"),
            )
            for _, r in df.iterrows()
        ]
    elif "score" not in df.columns and "영향점수" in df.columns:
        df["score"] = pd.to_numeric(df["영향점수"], errors="coerce")
    df = df[df["symbol"].astype(str).str.len() > 0]
    if df.empty:
        return pd.DataFrame()
    return df.drop_duplicates(subset=["symbol"], keep="last").reset_index(drop=True)


