# v9.9.8 WTI Chart Recovery
# - WTI 현재가 스냅샷과 별도로 차트용 OHLC 히스토리를 복구합니다.
# - 가짜 가격 데이터는 만들지 않습니다. 실패하면 실패 카드를 화면에 표시합니다.
# ══════════════════════════════════════════════
WTI_CHART_LAST_STATUS: dict[str, Any] = {
    "ok": False,
    "source": "",
    "error": "not_loaded",
    "rows": 0,
    "last_update": "",
}
MACRO_HISTORY_LAST_STATUS: dict[str, dict[str, Any]] = {}


def _macro_period_to_yahoo_range_interval(period_label: str) -> tuple[str, str]:
    """앱의 기간 라벨을 Yahoo Chart API range/interval로 변환."""
    cfg = MACRO_CHART_PERIODS.get(period_label) or MACRO_CHART_PERIODS.get("1일 · 15분봉") or {}
    period = str(cfg.get("period", "1d"))
    interval = str(cfg.get("interval", "15m"))
    range_map = {
        "1d": "1d",
        "5d": "5d",
        "1mo": "1mo",
        "3mo": "3mo",
        "6mo": "6mo",
        "1y": "1y",
    }
    return range_map.get(period, period), interval


def _standardize_ohlcv_frame(raw: pd.DataFrame, source: str) -> pd.DataFrame:
    """Yahoo/yfinance 응답을 Date/Open/High/Low/Close/Volume 형식으로 표준화."""
    if raw is None or raw.empty:
        return pd.DataFrame()
    df = raw.copy()
    if isinstance(df.columns, pd.MultiIndex):
        df.columns = [c[0] if isinstance(c, tuple) else c for c in df.columns]
    df = flatten_yf_columns(df.reset_index()) if "Close" not in df.columns else flatten_yf_columns(df.reset_index())
    date_col = "Datetime" if "Datetime" in df.columns else ("Date" if "Date" in df.columns else df.columns[0])
    required = ["Open", "High", "Low", "Close"]
    if not all(c in df.columns for c in required):
        return pd.DataFrame()
    for c in required:
        df[c] = pd.to_numeric(df[c], errors="coerce")
    if "Volume" not in df.columns:
        df["Volume"] = np.nan
    df["Volume"] = pd.to_numeric(df["Volume"], errors="coerce")
    out = df[[date_col, "Open", "High", "Low", "Close", "Volume"]].rename(columns={date_col: "Date"})
    out = out.dropna(subset=["Date", "Open", "High", "Low", "Close"])
    out["Date"] = out["Date"].apply(to_kst_datetime)
    out = out.dropna(subset=["Date"]).sort_values("Date")
    out["_source"] = source
    return out


@st.cache_data(ttl=90, show_spinner=False)
def fetch_wti_chart_history(period_label: str = "1일 · 15분봉") -> dict[str, Any]:
    """WTI(CL=F) 차트용 OHLC 히스토리 전용 조회.

    우선순위:
    1) Yahoo Chart API 직접조회
    2) yfinance Ticker.history
    3) yfinance download

    실패 시 가짜 데이터를 생성하지 않고 ok=false를 반환합니다.
    """
    symbol = "CL=F"
    rng, interval = _macro_period_to_yahoo_range_interval(period_label)
    result: dict[str, Any] = {
        "ok": False,
        "data": pd.DataFrame(),
        "source": "",
        "error": "",
        "rows": 0,
        "last_update": "",
    }

    # 1) Yahoo Chart API 직접조회
    try:
        import requests
        from urllib.parse import quote
        encoded = quote(symbol, safe="")
        url = f"https://query1.finance.yahoo.com/v8/finance/chart/{encoded}"
        params = {
            "range": rng,
            "interval": interval,
            "includePrePost": "true",
            "events": "div,splits",
        }
        headers = {"User-Agent": "Mozilla/5.0"}
        r = requests.get(url, params=params, headers=headers, timeout=8)
        if r.status_code == 200:
            payload = r.json() or {}
            chart = (payload.get("chart") or {}).get("result") or []
            if chart:
                data = chart[0]
                timestamps = data.get("timestamp") or []
                quote_data = ((data.get("indicators") or {}).get("quote") or [{}])[0]
                if timestamps and quote_data:
                    df = pd.DataFrame({
                        "Date": [datetime.fromtimestamp(int(t), tz=timezone.utc) for t in timestamps],
                        "Open": quote_data.get("open") or [],
                        "High": quote_data.get("high") or [],
                        "Low": quote_data.get("low") or [],
                        "Close": quote_data.get("close") or [],
                        "Volume": quote_data.get("volume") or [],
                    })
                    std = _standardize_ohlcv_frame(df, f"Yahoo Chart CL=F {interval}")
                    if not std.empty:
                        result.update({
                            "ok": True,
                            "data": std,
                            "source": f"Yahoo Chart CL=F {interval}",
                            "rows": int(len(std)),
                            "last_update": format_kst_full_label(std["Date"].iloc[-1]),
                            "error": "",
                        })
                        return result
        else:
            result["error"] = f"Yahoo Chart HTTP {r.status_code}"
    except Exception as e:
        result["error"] = f"Yahoo Chart error: {str(e)[:180]}"

    # 2) yfinance Ticker.history fallback
    try:
        import yfinance as yf
        cfg = MACRO_CHART_PERIODS.get(period_label) or MACRO_CHART_PERIODS.get("1일 · 15분봉") or {}
        period = str(cfg.get("period", "1d"))
        yf_interval = str(cfg.get("interval", "15m"))
        hist = yf.Ticker(symbol).history(period=period, interval=yf_interval, prepost=True, auto_adjust=False)
        std = _standardize_ohlcv_frame(hist, f"yfinance Ticker.history CL=F {yf_interval}")
        if not std.empty:
            result.update({
                "ok": True,
                "data": std,
                "source": f"yfinance Ticker.history CL=F {yf_interval}",
                "rows": int(len(std)),
                "last_update": format_kst_full_label(std["Date"].iloc[-1]),
                "error": "",
            })
            return result
    except Exception as e:
        result["error"] = (result.get("error") + " | " if result.get("error") else "") + f"history error: {str(e)[:160]}"

    # 3) yfinance download fallback
    try:
        import yfinance as yf
        cfg = MACRO_CHART_PERIODS.get(period_label) or MACRO_CHART_PERIODS.get("1일 · 15분봉") or {}
        period = str(cfg.get("period", "1d"))
        yf_interval = str(cfg.get("interval", "15m"))
        raw = yf.download(symbol, period=period, interval=yf_interval, progress=False, auto_adjust=False, prepost=True)
        std = _standardize_ohlcv_frame(raw, f"yfinance download CL=F {yf_interval}")
        if not std.empty:
            result.update({
                "ok": True,
                "data": std,
                "source": f"yfinance download CL=F {yf_interval}",
                "rows": int(len(std)),
                "last_update": format_kst_full_label(std["Date"].iloc[-1]),
                "error": "",
            })
            return result
    except Exception as e:
        result["error"] = (result.get("error") + " | " if result.get("error") else "") + f"download error: {str(e)[:160]}"

    if not result.get("error"):
        result["error"] = "CL=F 히스토리 데이터 없음"
    return result


def _record_macro_status(symbol: str, ok: bool, source: str = "", rows: int = 0, error: str = "") -> None:
    try:
        MACRO_HISTORY_LAST_STATUS[str(symbol)] = {
            "ok": bool(ok),
            "source": str(source or ""),
            "rows": int(rows or 0),
            "error": str(error or "")[:240],
            "checked_at": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S KST"),
        }
        if str(symbol) == "CL=F":
            WTI_CHART_LAST_STATUS.update(MACRO_HISTORY_LAST_STATUS[str(symbol)])
    except Exception:
        pass


