def calculate_auto_market_score(bench_df: pd.DataFrame) -> int:
    bench_df = normalize_benchmark_df(bench_df)
    if bench_df.empty or "symbol" not in bench_df.columns or "score" not in bench_df.columns:
        return 0
    scores = []
    for sym, weight in [("QQQ", 0.45), ("SPY", 0.25), ("^VIX", 0.30)]:
        row = bench_df[bench_df["symbol"] == sym]
        if not row.empty:
            scores.append(float(row.iloc[0]["score"]) * weight)
    return int(round(max(-3, min(3, sum(scores))))) if scores else 0


def calculate_auto_sector_score(sector: str, bench_df: pd.DataFrame) -> int:
    bench_df = normalize_benchmark_df(bench_df)
    if bench_df.empty or "symbol" not in bench_df.columns or "score" not in bench_df.columns:
        return 0
    symbols = SECTOR_ETFS.get(sector, ["QQQ"])
    scores = []
    for sym in symbols:
        row = bench_df[bench_df["symbol"] == sym]
        if not row.empty:
            scores.append(float(row.iloc[0]["score"]))
    if not scores:
        return 0
    return int(round(max(-3, min(3, np.mean(scores)))))


def detect_event_context(target: date, manual_events: list[str] | None = None) -> dict[str, Any]:
    manual_events = manual_events or []
    names = []
    event_types = []
    risk_mult = 1.0
    target_dt = pd.to_datetime(target).date()

    for ev in DEFAULT_MACRO_EVENTS:
        ev_date = pd.to_datetime(ev["date"]).date()
        diff = abs((target_dt - ev_date).days)
        if diff == 0:
            names.append(ev["name"])
            event_types.append(ev["type"])
            risk_mult = max(risk_mult, float(ev.get("risk_mult", 1.4)))
        elif diff == 1:
            names.append(f"{ev['name']} ±1일")
            event_types.append(ev["type"])
            risk_mult = max(risk_mult, 1.20)

    if target_dt == third_friday(target_dt.year, target_dt.month):
        names.append("미국 월간 옵션만기일")
        event_types.append("OPEX")
        risk_mult = max(risk_mult, 1.25)

    manual_risk = {
        "CPI": 1.55, "PPI": 1.35, "고용지표": 1.45, "실적 발표 전후": 1.80,
        "대형 개별 뉴스": 1.60, "옵션 만기/수급 이벤트": 1.35,
    }
    for ev in manual_events:
        names.append(ev)
        event_types.append(ev)
        risk_mult = max(risk_mult, manual_risk.get(ev, 1.25))

    if not names:
        names = ["주요 이벤트 없음"]
        event_types = ["NORMAL"]

    return {
        "event_names": names,
        "event_types": event_types,
        "event_label": ", ".join(names),
        "risk_mult": min(risk_mult, 2.5),
        "has_major_event": any(t != "NORMAL" for t in event_types),
    }


def _clean_event_context(ctx: dict[str, Any]) -> dict[str, Any]:
    """중복 이벤트 라벨을 정리하고 NORMAL만 있을 때는 주요 이벤트 없음으로 정리."""
    names = [str(x) for x in ctx.get("event_names", []) if str(x).strip()]
    types = [str(x) for x in ctx.get("event_types", []) if str(x).strip()]
    pairs = []
    for n, t in zip(names, types if len(types) == len(names) else [""] * len(names)):
        if n == "주요 이벤트 없음" and len(names) > 1:
            continue
        if (n, t) not in pairs:
            pairs.append((n, t))
    if not pairs:
        pairs = [("주요 이벤트 없음", "NORMAL")]
    ctx["event_names"] = [p[0] for p in pairs]
    ctx["event_types"] = [p[1] if p[1] else "AUTO" for p in pairs]
    ctx["event_label"] = ", ".join(ctx["event_names"])
    ctx["has_major_event"] = any(t != "NORMAL" for t in ctx["event_types"])
    ctx["risk_mult"] = min(max(safe_float(ctx.get("risk_mult"), 1.0), 1.0), 2.8)
    return ctx


def merge_event_context(base: dict[str, Any], extra: dict[str, Any] | None) -> dict[str, Any]:
    """FOMC/BLS/실적/뉴스 이벤트 정보를 하나의 event_context로 병합."""
    ctx = dict(base or {})
    extra = extra or {}
    ctx.setdefault("event_names", [])
    ctx.setdefault("event_types", [])
    if extra.get("event_names"):
        ctx["event_names"] = list(ctx.get("event_names", [])) + list(extra.get("event_names", []))
    if extra.get("event_types"):
        ctx["event_types"] = list(ctx.get("event_types", [])) + list(extra.get("event_types", []))
    ctx["risk_mult"] = max(safe_float(ctx.get("risk_mult"), 1.0), safe_float(extra.get("risk_mult"), 1.0))
    for key in ["auto_macro_events", "auto_news_items", "auto_news_score", "auto_news_label", "auto_news_quality", "auto_news_updated_at", "auto_news_updated_ts", "auto_news_raw_count", "auto_news_unique_count", "auto_news_dedup_removed", "auto_news_summary_unique_count", "auto_news_summary_dedup_removed", "auto_news_scored_count", "auto_news_refresh_note", "auto_news_latest_published_at", "auto_news_latest_published_ts", "auto_news_time_note", "auto_news_source_items", "auto_earnings_date"]:
        if key in extra and extra.get(key) not in (None, "", []):
            if isinstance(extra.get(key), list):
                ctx[key] = list(ctx.get(key, [])) + list(extra.get(key, []))
            else:
                ctx[key] = extra.get(key)
    return _clean_event_context(ctx)


@st.cache_data(ttl=60 * 60 * 12, show_spinner=False)
def fetch_bls_macro_context(target: str | date) -> dict[str, Any]:
    """BLS 발표일 캘린더에서 CPI/PPI/고용지표 이벤트를 자동 감지.

    무료 웹 페이지 파싱 방식이라 실패할 수 있으며, 실패 시 조용히 미확인 반환.
    """
    result = {"event_names": [], "event_types": [], "risk_mult": 1.0, "auto_macro_events": []}
    try:
        import requests
        from bs4 import BeautifulSoup
        target_dt = pd.to_datetime(target).date()
        url = f"https://www.bls.gov/schedule/{target_dt.year}/home.htm"
        html = requests.get(url, timeout=8, headers={"User-Agent": "Mozilla/5.0"}).text
        soup = BeautifulSoup(html, "html.parser")
        text = soup.get_text("\n")
        # 날짜별 페이지가 표 구조를 바꿀 수 있어, 날짜 문자열 주변 텍스트를 보수적으로 검색
        date_markers = [
            target_dt.strftime("%A, %B %-d, %Y") if hasattr(target_dt, 'strftime') else "",
            target_dt.strftime("%B %-d, %Y") if hasattr(target_dt, 'strftime') else "",
            target_dt.strftime("%A, %B %d, %Y"),
            target_dt.strftime("%B %d, %Y"),
        ]
        # Windows 호환 strftime 보정: %-d가 안 되는 환경 대비
        date_markers += [
            target_dt.strftime("%A, %B ") + str(target_dt.day) + target_dt.strftime(", %Y"),
            target_dt.strftime("%B ") + str(target_dt.day) + target_dt.strftime(", %Y"),
        ]
        lower_text = text.lower()
        found_window = ""
        for marker in date_markers:
            if not marker:
                continue
            pos = lower_text.find(marker.lower())
            if pos >= 0:
                found_window = lower_text[pos:pos + 2500]
                break
        if not found_window:
            return result
        mapping = [
            ("consumer price index", "CPI", 1.55, "CPI 발표일"),
            ("producer price index", "PPI", 1.35, "PPI 발표일"),
            ("employment situation", "고용지표", 1.45, "고용보고서 발표일"),
            ("real earnings", "CPI", 1.25, "실질임금/CPI 관련 발표"),
        ]
        for keyword, evtype, mult, label in mapping:
            if keyword in found_window:
                result["event_names"].append(label)
                result["event_types"].append(evtype)
                result["auto_macro_events"].append(label)
                result["risk_mult"] = max(result["risk_mult"], mult)
        return result
    except Exception:
        return result


@st.cache_data(ttl=60 * 8, show_spinner=False)
def fetch_finnhub_company_news_items(symbol: str, lookback_days: int = 3, max_items: int = 12) -> list[dict[str, Any]]:
    """Finnhub Company News. API 키가 없거나 실패하면 빈 리스트."""
    items: list[dict[str, Any]] = []
    key = load_finnhub_api_key()
    s = str(symbol or "").strip().upper()
    if not key or not is_finnhub_quote_symbol(s):
        return items
    try:
        import requests
        to_dt = datetime.now(KST).date()
        from_dt = to_dt - timedelta(days=max(1, int(lookback_days)))
        url = "https://finnhub.io/api/v1/company-news"
        r = requests.get(url, params={"symbol": s, "from": str(from_dt), "to": str(to_dt), "token": key}, timeout=7)
        if r.status_code != 200:
            return []
        data = r.json() or []
        for n in data[:max_items]:
            title = str(n.get("headline", "") or "").strip()
            if not title:
                continue
            ts = safe_float(n.get("datetime"), np.nan)
            published = ""
            published_ts = ""
            time_label = "-"
            if not np.isnan(ts) and ts > 0:
                dt = datetime.fromtimestamp(int(ts), tz=timezone.utc).astimezone(KST)
                published = dt.isoformat()
                published_ts = published
                time_label = dt.strftime("%m-%d %H:%M KST")
            items.append({
                "title": strip_news_publisher_suffix(title),
                "source": "Finnhub",
                "time": time_label,
                "published_raw": published,
                "published_ts": published_ts,
                "url": str(n.get("url", "") or ""),
                "origin": "finnhub_company_news",
                "related_ticker": s,
            })
    except Exception:
        return []
    return items


def fetch_google_ticker_news_items(symbol: str, company_name: str = "", lookback_days: int = 1, max_items: int = 10) -> list[dict[str, Any]]:
    """Google News RSS ticker/company query."""
    items: list[dict[str, Any]] = []
    try:
        import feedparser
        from urllib.parse import quote_plus
    except Exception:
        return items
    s = str(symbol or "").strip().upper()
    if not s:
        return items
    q_parts = [s, company_name.strip()] if company_name else [s]
    q = f'when:{max(1, int(lookback_days))}d ("{s}" OR "{company_name}") stock earnings guidance analyst news'
    if not company_name:
        q = f'when:{max(1, int(lookback_days))}d "{s}" stock earnings guidance analyst news'
    url = f"https://news.google.com/rss/search?q={quote_plus(q)}&hl=en-US&gl=US&ceid=US:en"
    try:
        feed = feedparser.parse(url)
        for entry in getattr(feed, "entries", [])[:max_items]:
            title = getattr(entry, "title", "")
            if not title:
                continue
            published = getattr(entry, "published", "") or getattr(entry, "updated", "")
            pub_ts = parse_news_time_to_kst(published)
            link = getattr(entry, "link", "") or url
            items.append({
                "title": strip_news_publisher_suffix(title),
                "source": "Google News",
                "time": format_news_time(published),
                "published_raw": published,
                "published_ts": pub_ts.isoformat() if pd.notna(pub_ts) else "",
                "url": link,
                "origin": "google_ticker_news",
                "related_ticker": s,
            })
    except Exception:
        return []
    return items


def news_alarm_severity(title: str) -> tuple[int, int, list[str]]:
    """긴급 뉴스 알람 점수: severity, direction, reasons."""
    low = str(title or "").lower()
    severity = 0
    direction = 0
    reasons = []
    negative_terms = {
        "guidance cut": 7, "cuts guidance": 7, "misses": 5, "miss": 4, "downgrade": 4,
        "investigation": 6, "sec": 5, "lawsuit": 5, "probe": 5, "recall": 5,
        "offering": 7, "dilution": 7, "bankruptcy": 8, "halts": 6, "halt": 6,
        "resigns": 4, "layoffs": 4, "data breach": 6, "fraud": 8,
        "가이던스 하향": 7, "실적 쇼크": 6, "유상증자": 8, "전환사채": 7, "소송": 5, "조사": 5,
    }
    positive_terms = {
        "beats": 4, "beat": 3, "raises guidance": 6, "raises": 3, "upgrade": 3,
        "contract": 4, "partnership": 3, "approval": 5, "record revenue": 4,
        "수주": 4, "계약": 4, "승인": 5, "실적 호조": 4,
    }
    macro_terms = {
        "fed": 4, "powell": 4, "cpi": 5, "ppi": 4, "pce": 4, "payrolls": 4,
        "tariff": 6, "china": 3, "oil": 4, "iran": 4, "israel": 4, "war": 5,
        "연준": 4, "파월": 4, "물가": 4, "관세": 6, "유가": 4, "전쟁": 5,
    }
    for k, v in negative_terms.items():
        if k in low:
            severity += v
            direction -= 1
            reasons.append(k)
    for k, v in positive_terms.items():
        if k in low:
            severity += v
            direction += 1
            reasons.append(k)
    for k, v in macro_terms.items():
        if k in low:
            severity += v
            reasons.append(k)
    severity = int(max(0, min(20, severity)))
    direction = 1 if direction > 0 else -1 if direction < 0 else 0
    return severity, direction, reasons[:5]


def fetch_ticker_news_context(ticker: str, lookback_hours: int = 72) -> dict[str, Any]:
    """v9.9.7 WTI Emergency: Finnhub + Google News + yfinance/Yahoo 종목별 뉴스 점수화."""
    result = {
        "event_names": [], "event_types": [], "risk_mult": 1.0,
        "auto_news_items": [], "auto_news_score": 0, "auto_news_label": "뉴스 미확인",
        "auto_news_source_items": [], "auto_news_raw_count": 0, "auto_news_scored_count": 0,
    }
    t = str(ticker or "").upper().strip()
    if not t:
        return result

    items: list[dict[str, Any]] = []
    # 1) Finnhub Company News
    items.extend(fetch_finnhub_company_news_items(t, lookback_days=max(1, int(lookback_hours / 24)), max_items=14))

    # 2) Google News ticker/company query
    company_name = ""
    try:
        wl = load_watchlist_df("미국주식")
        if not wl.empty and "symbol" in wl.columns:
            row = wl[wl["symbol"].astype(str).str.upper().eq(t)]
            if not row.empty:
                company_name = str(row.iloc[0].get("name", ""))
    except Exception:
        company_name = ""
    items.extend(fetch_google_ticker_news_items(t, company_name=company_name, lookback_days=max(1, int(lookback_hours / 24)), max_items=12))

    # 3) yfinance raw news
    now_ts = datetime.now().timestamp()
    try:
        import yfinance as yf
        raw_news = yf.Ticker(t).news or []
        for n in raw_news[:14]:
            title = n.get("title") or n.get("content", {}).get("title", "") if isinstance(n, dict) else ""
            ts = n.get("providerPublishTime") if isinstance(n, dict) else None
            if ts and (now_ts - float(ts)) > lookback_hours * 3600:
                continue
            if title:
                time_label = "-"
                published_ts = ""
                if ts:
                    dt = datetime.fromtimestamp(int(ts), tz=timezone.utc).astimezone(KST)
                    time_label = dt.strftime("%m-%d %H:%M KST")
                    published_ts = dt.isoformat()
                items.append({
                    "title": strip_news_publisher_suffix(title),
                    "source": "yfinance",
                    "time": time_label,
                    "published_raw": str(ts or ""),
                    "published_ts": published_ts,
                    "url": str(n.get("link", "") or n.get("content", {}).get("canonicalUrl", {}).get("url", "") or ""),
                    "origin": "yfinance",
                    "related_ticker": t,
                })
    except Exception:
        pass

    # 4) Yahoo Finance RSS fallback
    try:
        import feedparser
        feed = feedparser.parse(f"https://feeds.finance.yahoo.com/rss/2.0/headline?s={t}&region=US&lang=en-US")
        for entry in feed.entries[:14]:
            title = getattr(entry, "title", "")
            if title:
                published = getattr(entry, "published", "") or getattr(entry, "updated", "")
                pub_ts = parse_news_time_to_kst(published)
                items.append({
                    "title": strip_news_publisher_suffix(title),
                    "source": "Yahoo Finance",
                    "time": format_news_time(published),
                    "published_raw": published,
                    "published_ts": pub_ts.isoformat() if pd.notna(pub_ts) else "",
                    "url": getattr(entry, "link", ""),
                    "origin": "yahoo_rss",
                    "related_ticker": t,
                })
    except Exception:
        pass

    raw_count = len(items)
    items, removed = dedupe_news_items(items, threshold=0.54)
    result["auto_news_raw_count"] = raw_count
    result["auto_news_unique_count"] = len(items)
    result["auto_news_dedup_removed"] = removed

    if not items:
        return result

    score = 0
    impact_count = 0
    samples = []
    source_items = []
    blocker = False

    for item in items[:20]:
        title = str(item.get("title", ""))
        severity, direction, reasons = news_alarm_severity(title)
        relevance, sent, tags = market_moving_headline_score(title)
        final_direction = direction if direction != 0 else sent
        local_score = max(-3, min(3, final_direction * max(1, int(severity / 4)) if severity else sent))
        score += local_score
        if severity >= 6 or abs(local_score) >= 2 or relevance >= 5:
            impact_count += 1
        if severity >= 7 and final_direction < 0:
            blocker = True
        importance = "높음" if severity >= 7 or relevance >= 7 else "중간" if severity >= 4 or relevance >= 4 else "낮음"
        direction_label = "우호" if final_direction > 0 else "부담" if final_direction < 0 else "중립/변동성"
        source_items.append({
            **item,
            "importance": importance,
            "direction": direction_label,
            "severity": severity,
            "alarm_reasons": reasons,
        })
        if importance != "낮음":
            samples.append(f"[{importance}/{direction_label}] {title}")

    score = int(max(-5, min(5, score)))
    if blocker:
        result["event_names"].append(f"News Alarm 악재감지({t})")
        result["event_types"].append("NEWS_ALARM_BLOCK")
        result["risk_mult"] = 1.90
    elif impact_count >= 1 or abs(score) >= 2:
        result["event_names"].append(f"News Alarm 자동감지({t})")
        result["event_types"].append("NEWS_ALARM")
        result["risk_mult"] = 1.50 if impact_count >= 2 else 1.25

    result["auto_news_items"] = samples[:6] if samples else [str(x.get("title", "")) for x in items[:5]]
    result["auto_news_score"] = score
    result["auto_news_source_items"] = enrich_news_quality_items_for_app(source_items[:15])
    result["auto_news_scored_count"] = impact_count
    if score > 0:
        result["auto_news_label"] = f"News Alarm +{score} · {t}"
    elif score < 0:
        result["auto_news_label"] = f"News Alarm {score} · {t}"
    else:
        result["auto_news_label"] = f"News Alarm 중립 · {t}"
    return result


def fetch_url_titles_safe(url: str, max_items: int = 20) -> list[str]:
    """경제뉴스 페이지에서 제목 후보만 추출. requests/bs4가 없어도 앱은 꺼지지 않음."""
    titles: list[str] = []
    try:
        import requests
        from bs4 import BeautifulSoup
    except Exception:
        return titles

    try:
        headers = {
            "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 Chrome/122 Safari/537.36",
            "Accept-Language": "ko-KR,ko;q=0.9,en-US;q=0.8,en;q=0.7",
        }
        r = requests.get(url, headers=headers, timeout=8)
        if r.status_code >= 400:
            return []
        soup = BeautifulSoup(r.text, "html.parser")
        for tag in soup.find_all(["h1", "h2", "h3", "a", "span"]):
            title = " ".join(tag.get_text(" ", strip=True).split())
            if len(title) < 8 or len(title) > 180:
                continue
            low = title.lower()
            if any(x in low for x in ["로그인", "회원가입", "privacy", "copyright", "advertisement", "subscribe"]):
                continue
            if title not in titles:
                titles.append(title)
            if len(titles) >= max_items:
                break
    except Exception:
        return []
    return titles



def news_source_label(url: str) -> str:
    """뉴스 URL을 화면용 출처명으로 변환."""
    u = str(url or "").lower()
    if "pickmiju" in u:
        return "PickMiju"
    if "investing.com" in u:
        return "Investing.com"
    if "finance.yahoo" in u or "yahoo.com" in u:
        return "Yahoo Finance"
    if "marketwatch" in u:
        return "MarketWatch"
    if "cnbc" in u:
        return "CNBC"
    if "reuters" in u:
        return "Reuters"
    if "benzinga" in u:
        return "Benzinga"
    if "finnhub" in u:
        return "Finnhub"
    if "alphavantage" in u:
        return "Alpha Vantage"
    if "seekingalpha" in u:
        return "Seeking Alpha"
    if "naver.com" in u:
        return "네이버금융"
    if "hankyung" in u:
        return "한국경제"
    if "yna.co.kr" in u:
        return "연합뉴스"
    if "google.com" in u or "news.google" in u:
        return "Google News"
    return "뉴스소스"


def format_news_time(value: Any) -> str:
    """RSS/웹 게시시간을 KST 기준으로 가볍게 표시."""
    try:
        ts = pd.to_datetime(value, errors="coerce", utc=True)
        if pd.isna(ts):
            return "-"
        return ts.tz_convert("Asia/Seoul").strftime("%m-%d %H:%M KST")
    except Exception:
        return "-"


def parse_news_time_to_kst(value: Any) -> pd.Timestamp:
    """뉴스 원문 시간을 KST Timestamp로 변환. 실패하면 NaT."""
    try:
        ts = pd.to_datetime(value, errors="coerce", utc=True)
        if pd.isna(ts):
            return pd.NaT
        return ts.tz_convert("Asia/Seoul")
    except Exception:
        return pd.NaT


def news_time_status(items: list[dict[str, Any]], now_kst: datetime | None = None) -> dict[str, Any]:
    """뉴스 조회시각과 기사 게시시각을 분리해서 보여주기 위한 상태값."""
    if now_kst is None:
        now_kst = datetime.now(KST)
    parsed = []
    for item in items or []:
        raw = item.get("published_ts") or item.get("published_raw") or item.get("time")
        ts = parse_news_time_to_kst(raw)
        if pd.notna(ts):
            parsed.append(ts)
    if not parsed:
        return {
            "latest_label": "-",
            "latest_iso": "",
            "time_note": "기사 게시시각 확인 불가",
            "is_stale": False,
        }
    latest = max(parsed)
    latest_py = latest.to_pydatetime()
    age_hours = max(0.0, (now_kst - latest_py).total_seconds() / 3600)
    latest_label = latest.strftime("%Y-%m-%d %H:%M KST")
    if latest.date() < now_kst.date():
        note = f"최신 기사시각 {latest_label} · 조회는 현재 했지만 소스 최신 기사가 전일자일 수 있음"
        stale = True
    elif age_hours >= 12:
        note = f"최신 기사시각 {latest_label} · {age_hours:.0f}시간 전 기사 중심"
        stale = True
    else:
        note = f"최신 기사시각 {latest_label}"
        stale = False
    return {
        "latest_label": latest_label,
        "latest_iso": latest.isoformat(),
        "time_note": note,
        "is_stale": stale,
    }


