def render_news_source_links(event_context: dict[str, Any], *, widget_namespace: str = "news_src") -> None:
    """뉴스 원문 기사 링크를 접기 영역에 표시."""
    items = event_context.get("auto_news_source_items", []) if event_context else []
    if not items:
        return
    if st.toggle(
        "📰 원문 기사 링크 보기",
        value=False,
        key=f"{widget_namespace}_src_toggle_v9982",
    ):
        st.caption(
            "제목을 누르면 원문 기사 페이지가 열립니다. 무료 RSS/Google News 기준이라 일부 원문은 언론사 페이지나 Google News 중간 페이지로 열릴 수 있습니다."
        )
        for i, item in enumerate(items[:10], start=1):
            title = str(item.get("title", "")).strip()
            url = str(item.get("url", "")).strip()
            source = str(item.get("source", "뉴스소스")).strip()
            tm = str(item.get("time", "-")).strip()
            importance = str(item.get("importance", "-")).strip()
            direction = str(item.get("direction", "-")).strip()
            if not title:
                continue
            dup_n = len(item.get("duplicate_sources", []) or [])
            meta = f"{source} · {tm} · 중요도 {importance} · 영향 {direction}"
            if dup_n:
                meta += f" · 유사기사 {dup_n}건 묶음"
            if url.startswith("http"):
                st.markdown(f"{i}. [{title}]({url})  \n   <span style='color:#94a3b8;font-size:0.85rem'>{meta}</span>", unsafe_allow_html=True)
            else:
                st.markdown(f"{i}. {title}  \n   <span style='color:#94a3b8;font-size:0.85rem'>{meta}</span>", unsafe_allow_html=True)



def _news_badge_style_v9965(value: str) -> tuple[str, str]:
    v = str(value or "").strip()
    if any(k in v for k in ["높음", "강함", "우호", "+"]):
        return "#16a34a", "rgba(22,163,74,0.16)"
    if any(k in v for k in ["부담", "악재", "위험", "경고", "-"]):
        return "#ef4444", "rgba(239,68,68,0.16)"
    if any(k in v for k in ["중간", "변동", "주의"]):
        return "#f59e0b", "rgba(245,158,11,0.16)"
    return "#60a5fa", "rgba(96,165,250,0.14)"


def render_news_card_feed_v9965(event_context: dict[str, Any], market: str, limit: int = 8) -> None:
    """한투/토스 스타일의 뉴스 카드 피드. 표 대신 출처·시간·중요도·영향을 카드로 표시."""
    items = list(event_context.get("auto_news_source_items", []) or []) if event_context else []
    summaries = list(event_context.get("auto_news_items", []) or []) if event_context else []
    if not items and not summaries:
        st.info("표시할 시장 뉴스가 없습니다. 뉴스 소스 응답이 비어 있거나 필터 기준에 걸린 뉴스가 없습니다.")
        return

    st.markdown(
        """
        <style>
        .news-card-v9965{
            border:1px solid rgba(148,163,184,.20);
            border-radius:18px;
            padding:14px 16px;
            margin:10px 0;
            background:linear-gradient(180deg, rgba(15,23,42,.88), rgba(2,6,23,.55));
            box-shadow:0 10px 24px rgba(2,6,23,.18);
        }
        .news-card-v9965 .top{display:flex;justify-content:space-between;gap:12px;align-items:flex-start;margin-bottom:8px;}
        .news-card-v9965 .source{font-size:.82rem;color:#94a3b8;font-weight:700;}
        .news-card-v9965 .title{font-size:1rem;line-height:1.45;color:#f8fafc;font-weight:850;letter-spacing:-.02em;}
        .news-card-v9965 .meta{font-size:.8rem;color:#cbd5e1;margin-top:8px;display:flex;gap:8px;flex-wrap:wrap;}
        .news-card-v9965 .badge{border-radius:999px;padding:3px 9px;font-weight:850;font-size:.78rem;display:inline-block;white-space:nowrap;}
        .news-card-v9965 a{color:#f8fafc;text-decoration:none;}
        .news-card-v9965 a:hover{text-decoration:underline;}
        </style>
        """,
        unsafe_allow_html=True,
    )

    # 원문이 있으면 원문 카드 우선, 없으면 요약 카드로 fallback
    if items:
        for item in items[:limit]:
            title = str(item.get("title", "") or "").strip()
            if not title:
                continue
            url = str(item.get("url", "") or "").strip()
            source = str(item.get("source", "뉴스소스") or "뉴스소스").strip()
            tm = str(item.get("time", "-") or "-").strip()
            importance = str(item.get("importance", "중간") or "중간").strip()
            direction = str(item.get("direction", "중립/변동성") or "중립/변동성").strip()
            rel = item.get("relevance", item.get("severity", ""))
            b1_color, b1_bg = _news_badge_style_v9965(importance)
            b2_color, b2_bg = _news_badge_style_v9965(direction)
            link_title = f"<a href='{url}' target='_blank'>{title}</a>" if url.startswith("http") else title
            rel_txt = f"점수 {rel}" if str(rel).strip() not in {"", "nan", "None"} else "실시간 뉴스"
            st.markdown(
                f"""
                <div class="news-card-v9965">
                    <div class="top">
                        <div class="source">{source} · {tm}</div>
                        <div>
                            <span class="badge" style="color:{b1_color};background:{b1_bg};">{importance}</span>
                            <span class="badge" style="color:{b2_color};background:{b2_bg};">{direction}</span>
                        </div>
                    </div>
                    <div class="title">{link_title}</div>
                    <div class="meta"><span>{rel_txt}</span><span>{'국장' if market == '한국주식' else '미장'} 영향 확인</span></div>
                </div>
                """,
                unsafe_allow_html=True,
            )
