def build_auto_event_context(
    target: date,
    ticker: str,
    manual_events: list[str] | None = None,
    use_bls_macro: bool = True,
    use_earnings: bool = True,
    use_news: bool = True,
    market: str = "미국주식",
) -> dict[str, Any]:
    """수동 이벤트 + FOMC/OPEX + BLS CPI/PPI/고용 + 실적 + 뉴스 자동 감지를 통합."""
    ctx = detect_event_context(target, manual_events)
    ctx["target_date"] = str(pd.to_datetime(target).date())
    if use_bls_macro:
        ctx = merge_event_context(ctx, fetch_bls_macro_context(target))
    if use_earnings and ticker:
        earnings = fetch_earnings_context(ticker, target)
        if earnings.get("earnings_near"):
            ctx = merge_event_context(ctx, earnings_context_to_event_extra_v9963(earnings))
    if use_news:
        ctx = merge_event_context(ctx, fetch_market_shock_news_context(market))
    if use_news and ticker:
        ctx = merge_event_context(ctx, fetch_ticker_news_context(ticker))
    return _clean_event_context(ctx)
# ══════════════════════════════════════════════
# 데이터 로드
# ══════════════════════════════════════════════
def flatten_yf_columns(df: pd.DataFrame) -> pd.DataFrame:
    if isinstance(df.columns, pd.MultiIndex):
        df.columns = [c[0] for c in df.columns]
    df.columns = [str(c).strip() for c in df.columns]
    return df


def load_stock_data(ticker: str, market: str, period_years: float = 1.0) -> pd.DataFrame:
    ticker = normalize_ticker(ticker, market)
    end_date = datetime.today() + timedelta(days=1)
    start_date = datetime.today() - timedelta(days=int(period_years * 365) + 10)

    try:
        if market == "미국주식":
            import yfinance as yf

            raw = yf.download(
                ticker,
                start=start_date.strftime("%Y-%m-%d"),
                end=end_date.strftime("%Y-%m-%d"),
                interval="1d",
                progress=False,
                auto_adjust=False,
            )
            if raw.empty:
                return pd.DataFrame()
            raw = flatten_yf_columns(raw.reset_index())
            date_col = "Date" if "Date" in raw.columns else raw.columns[0]
            raw = raw.rename(columns={date_col: "Date"})
            # Adj Close가 있어도 실제 주문 기준은 OHLC 원데이터를 우선 사용
            df = raw[["Date", "Open", "High", "Low", "Close", "Volume"]].copy()
        else:
            import FinanceDataReader as fdr

            raw = fdr.DataReader(ticker, start_date, end_date)
            if raw.empty:
                return pd.DataFrame()
            raw = raw.reset_index()
            raw.columns = [str(c).strip() for c in raw.columns]
            if "Date" not in raw.columns:
                raw = raw.rename(columns={raw.columns[0]: "Date"})
            df = raw[["Date", "Open", "High", "Low", "Close", "Volume"]].copy()

        df["Date"] = pd.to_datetime(df["Date"]).dt.tz_localize(None)
        for c in ["Open", "High", "Low", "Close", "Volume"]:
            df[c] = pd.to_numeric(df[c], errors="coerce")
        df = df.dropna(subset=["Open", "High", "Low", "Close"]).sort_values("Date").reset_index(drop=True)
        return df
    except Exception as e:
        st.error(f"데이터 로드 오류: {e}")
        return pd.DataFrame()


def fetch_actual_day(ticker: str, market: str, target_date: str | date) -> dict[str, Any] | None:
    """대상일 이후 첫 거래일의 OHLC를 반환. 휴장/주말 보정용."""
    t = normalize_ticker(ticker, market)
    target = pd.to_datetime(target_date).date()
    start = target - timedelta(days=1)
    end = target + timedelta(days=7)

    try:
        if market == "미국주식":
            import yfinance as yf

            raw = yf.download(
                t,
                start=start.strftime("%Y-%m-%d"),
                end=end.strftime("%Y-%m-%d"),
                interval="1d",
                progress=False,
                auto_adjust=False,
            )
            if raw.empty:
                return None
            raw = flatten_yf_columns(raw.reset_index())
            if "Date" not in raw.columns:
                raw = raw.rename(columns={raw.columns[0]: "Date"})
        else:
            import FinanceDataReader as fdr

            raw = fdr.DataReader(t, start, end).reset_index()
            if raw.empty:
                return None
            raw.columns = [str(c).strip() for c in raw.columns]
            if "Date" not in raw.columns:
                raw = raw.rename(columns={raw.columns[0]: "Date"})

        raw["Date"] = pd.to_datetime(raw["Date"]).dt.date
        raw = raw[raw["Date"] >= target].sort_values("Date")
        if raw.empty:
            return None
        r = raw.iloc[0]
        return {
            "actual_date": str(r["Date"]),
            "actual_open": safe_float(r["Open"]),
            "actual_high": safe_float(r["High"]),
            "actual_low": safe_float(r["Low"]),
            "actual_close": safe_float(r["Close"]),
            "actual_volume": safe_float(r.get("Volume", 0.0)),
            "actual_source": "yfinance" if market == "미국주식" else "FinanceDataReader",
        }
    except Exception:
        return None


# ══════════════════════════════════════════════
# 지표 계산
# ══════════════════════════════════════════════
def calculate_indicators(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    close = df["Close"]
    high = df["High"]
    low = df["Low"]
    volume = df["Volume"]

    for w in [5, 10, 20, 60, 120]:
        df[f"MA{w}"] = close.rolling(w, min_periods=1).mean()

    delta = close.diff()
    gain = delta.clip(lower=0).rolling(14, min_periods=1).mean()
    loss = (-delta.clip(upper=0)).rolling(14, min_periods=1).mean()
    rs = gain / loss.replace(0, np.nan)
    df["RSI"] = 100 - (100 / (1 + rs))
    df.loc[(loss == 0) & (gain > 0), "RSI"] = 100
    df.loc[(gain == 0) & (loss > 0), "RSI"] = 0
    df["RSI"] = df["RSI"].replace([np.inf, -np.inf], np.nan).fillna(50)

    ema12 = close.ewm(span=12, adjust=False).mean()
    ema26 = close.ewm(span=26, adjust=False).mean()
    df["MACD"] = ema12 - ema26
    df["MACD_Signal"] = df["MACD"].ewm(span=9, adjust=False).mean()
    df["MACD_Hist"] = df["MACD"] - df["MACD_Signal"]

    df["BB_Mid"] = close.rolling(20, min_periods=1).mean()
    df["BB_Std"] = close.rolling(20, min_periods=1).std()
    df["BB_Upper"] = df["BB_Mid"] + 2 * df["BB_Std"]
    df["BB_Lower"] = df["BB_Mid"] - 2 * df["BB_Std"]

    tr = pd.concat([high - low, (high - close.shift()).abs(), (low - close.shift()).abs()], axis=1).max(axis=1)
    df["ATR"] = tr.rolling(14, min_periods=1).mean()
    df["VOL_MA20"] = volume.rolling(20, min_periods=1).mean()
    df["VOL_RATIO"] = volume / df["VOL_MA20"].replace(0, np.nan)
    df["CHANGE_PCT"] = close.pct_change() * 100
    return df


def _cluster_price_levels(candidates: list[dict[str, Any]], cur: float, tolerance: float) -> list[dict[str, Any]]:
    """여러 방식으로 나온 가격 후보를 가까운 가격끼리 묶어 강도를 계산."""
    if not candidates:
        return []

    tolerance = max(tolerance, cur * 0.002 if cur else 0.01)
    clean = []
    for c in candidates:
        price = safe_float(c.get("price"), np.nan)
        if np.isnan(price) or price <= 0:
            continue
        clean.append({
            "price": price,
            "weight": safe_float(c.get("weight"), 1.0),
            "source": str(c.get("source", "기타")),
            "date_idx": int(c.get("date_idx", -1)),
            "volume": safe_float(c.get("volume"), 0.0),
        })

    clean = sorted(clean, key=lambda x: x["price"])
    clusters: list[list[dict[str, Any]]] = []
    for item in clean:
        if not clusters:
            clusters.append([item])
            continue
        center = np.average([x["price"] for x in clusters[-1]], weights=[max(x["weight"], 0.1) for x in clusters[-1]])
        if abs(item["price"] - center) <= tolerance:
            clusters[-1].append(item)
        else:
            clusters.append([item])

    levels = []
    for group in clusters:
        weights = [max(x["weight"], 0.1) for x in group]
        price = float(np.average([x["price"] for x in group], weights=weights))
        sources = list(dict.fromkeys([x["source"] for x in group]))
        recency_idx = max([x["date_idx"] for x in group] + [-1])
        touches = len(group)
        vol_sum = sum([safe_float(x.get("volume"), 0.0) for x in group])
        distance_pct = abs(price / cur - 1) * 100 if cur else np.nan

        # 점수: 많이 겹칠수록, 최근일수록, 현재가와 너무 멀지 않을수록, 거래량 있는 날일수록 가중
        source_bonus = min(28, len(sources) * 7)
        touch_bonus = min(30, touches * 4)
        dist_bonus = max(0, 22 - min(22, safe_float(distance_pct, 99) * 2.1))
        recency_bonus = 0 if recency_idx < 0 else min(14, max(0, recency_idx / 8))
        vol_bonus = min(10, math.log10(max(vol_sum, 1)) - 4) if vol_sum > 0 else 0
        score = int(max(0, min(100, 18 + source_bonus + touch_bonus + dist_bonus + recency_bonus + vol_bonus)))

        levels.append({
            "price": price,
            "score": score,
            "touches": touches,
            "distance_pct": distance_pct,
            "sources": ", ".join(sources[:5]),
            "label": "강함" if score >= 72 else "보통" if score >= 52 else "약함",
        })

    return sorted(levels, key=lambda x: (x["score"], -x["distance_pct"]), reverse=True)


def _sr_horizon_from_sources(sources: str) -> str:
    """지지/저항 근거를 단기/중기/장기로 분류."""
    s = str(sources or "")
    short_terms = ["피봇", "아래꼬리", "위꼬리", "10일", "20일", "MA10", "MA20", "BB"]
    mid_terms = ["40일", "60일", "MA50", "MA60", "피보"]
    long_terms = ["100일", "120일", "200일", "MA100", "MA120", "MA200"]

    short = sum(1 for t in short_terms if t in s)
    mid = sum(1 for t in mid_terms if t in s)
    long = sum(1 for t in long_terms if t in s)

    if long >= 2 and (short + mid) >= 2:
        return "복합/장기"
    if long > max(short, mid):
        return "장기"
    if mid >= max(short, long):
        return "중기"
    return "단기"


def _zone_width_for_level(lv: dict[str, Any], atr: float, cur: float, tolerance: float, side: str) -> float:
    """가격선 하나를 실제 매매용 존 폭으로 변환."""
    score = safe_float(lv.get("score"), 50)
    distance_pct = safe_float(lv.get("distance_pct"), 0)
    touches = safe_float(lv.get("touches"), 1)

    # 강도가 높고 터치가 많으면 존을 조금 넓혀 실제 흔들림을 흡수.
    base = max(tolerance * 0.90, atr * 0.28, cur * 0.004)
    score_mult = 1.18 if score >= 78 else 1.05 if score >= 62 else 0.90
    touch_mult = 1.12 if touches >= 4 else 1.0
    dist_mult = 0.92 if distance_pct <= 2.0 else 1.04
    width = base * score_mult * touch_mult * dist_mult

    # 과도한 박스 방지
    return float(max(cur * 0.003, min(width, cur * 0.035)))


def _apply_zone_to_levels(levels: list[dict[str, Any]], side: str, cur: float, atr: float, tolerance: float) -> list[dict[str, Any]]:
    """지지/저항 후보에 존 하단/상단과 운용 기준을 부여."""
    out = []
    for lv in levels:
        price = safe_float(lv.get("price"), np.nan)
        if np.isnan(price) or price <= 0:
            continue

        width = _zone_width_for_level(lv, atr, cur, tolerance, side)
        if side == "support":
            zone_low = price - width * 0.72
            zone_high = price + width * 0.38
            action = "존 상단 분할진입 / 하단 이탈 손절"
        else:
            zone_low = price - width * 0.38
            zone_high = price + width * 0.72
            action = "존 하단부터 분할익절 / 상단 돌파 시 추세 확인"

        sources = str(lv.get("sources", ""))
        horizon = _sr_horizon_from_sources(sources)
        strength = "핵심" if safe_float(lv.get("score"), 0) >= 80 else "강함" if safe_float(lv.get("score"), 0) >= 65 else "보통" if safe_float(lv.get("score"), 0) >= 50 else "약함"

        new_lv = dict(lv)
        new_lv.update({
            "side": side,
            "zone_low": max(0.0, float(zone_low)),
            "zone_high": max(0.0, float(zone_high)),
            "zone_width_pct": (zone_high / max(zone_low, 1e-9) - 1) * 100 if zone_low > 0 else np.nan,
            "horizon": horizon,
            "strength": strength,
            "action": action,
        })
        out.append(new_lv)

    return out


def _best_trade_support_zone(sr: dict[str, Any], open_mid: float, atr: float, atr_pct: float) -> dict[str, Any] | None:
    """다음 장 진입에 사용할 지지존 후보 선택."""
    zones = list(sr.get("support_levels", []) or [])
    if not zones:
        return None

    # 예상시초가 기준 너무 멀지 않은 강한 지지존 선호
    max_gap = min(0.075, max(0.022, atr_pct * 0.90 / 100))
    min_price = open_mid * (1 - max_gap * 1.25)
    max_price = open_mid * 1.012

    candidates = []
    for z in zones:
        high = safe_float(z.get("zone_high", z.get("price")), np.nan)
        low = safe_float(z.get("zone_low", z.get("price")), np.nan)
        score = safe_float(z.get("score"), 0)
        if np.isnan(high) or np.isnan(low) or high <= 0:
            continue
        if high < min_price or low > max_price:
            continue
        # 가까우면서 강도 높은 존
        gap = abs(high / max(open_mid, 1e-9) - 1)
        candidates.append((score - gap * 280, z))

    if candidates:
        return sorted(candidates, key=lambda x: x[0], reverse=True)[0][1]

    # 후보가 없으면 제일 가까운 지지존
    below = [z for z in zones if safe_float(z.get("zone_high", z.get("price")), 0) <= open_mid * 1.02]
    if below:
        return sorted(below, key=lambda z: abs(safe_float(z.get("zone_high", z.get("price")), 0) / max(open_mid, 1e-9) - 1))[0]
    return None


def _best_trade_resistance_zone(sr: dict[str, Any], entry: float) -> dict[str, Any] | None:
    """1차 익절 후보가 될 저항존 선택."""
    zones = list(sr.get("resistance_levels", []) or [])
    valid = []
    for z in zones:
        low = safe_float(z.get("zone_low", z.get("price")), np.nan)
        score = safe_float(z.get("score"), 0)
        if np.isnan(low) or low <= entry:
            continue
        distance = low / max(entry, 1e-9) - 1
        if 0.018 <= distance <= 0.28:
            valid.append((score - distance * 95, z))
    if not valid:
        above = [z for z in zones if safe_float(z.get("zone_low", z.get("price")), 0) > entry]
        if above:
            return sorted(above, key=lambda z: safe_float(z.get("zone_low", z.get("price")), 9e9))[0]
        return None
    return sorted(valid, key=lambda x: x[0], reverse=True)[0][1]


def calculate_support_resistance(df: pd.DataFrame, window: int = 5) -> dict[str, Any]:
    """
    v9.7.4 지지/저항 정밀화
    - 최근 피봇 저점/고점
    - 거래량 동반 반전봉
    - 20/50/100/200 이평선
    - 볼린저밴드 하단/상단
    - 최근 스윙 기준 피보나치 되돌림
    - 20/40/60일 롤링 고저점
    위 후보를 가격 클러스터로 묶어 점수화한다.
    """
    if df is None or df.empty:
        return {"support1": 0.0, "support2": 0.0, "resistance1": 0.0, "resistance2": 0.0}

    recent = df.tail(160).copy().reset_index(drop=True)
    if len(recent) < 20:
        recent = df.copy().reset_index(drop=True)

    cur = safe_float(df["Close"].iloc[-1])
    atr = safe_float(df["ATR"].iloc[-1] if "ATR" in df.columns else cur * 0.02, cur * 0.02)
    if atr <= 0:
        atr = cur * 0.02

    highs = recent["High"].astype(float).values
    lows = recent["Low"].astype(float).values
    closes = recent["Close"].astype(float).values
    volumes = recent["Volume"].astype(float).values if "Volume" in recent.columns else np.zeros(len(recent))
    vol_ma = pd.Series(volumes).rolling(20).mean().fillna(pd.Series(volumes).mean() if len(volumes) else 0).values

    candidates: list[dict[str, Any]] = []

    # 1) 피봇 고점/저점
    for i in range(window, len(recent) - window):
        left_high = highs[i - window:i]
        right_high = highs[i + 1:i + window + 1]
        left_low = lows[i - window:i]
        right_low = lows[i + 1:i + window + 1]
        vboost = 1.4 if vol_ma[i] and volumes[i] >= vol_ma[i] * 1.25 else 1.0

        if len(left_low) and len(right_low) and lows[i] <= min(left_low.min(), right_low.min()):
            candidates.append({"price": float(lows[i]), "weight": 5.0 * vboost, "source": "피봇저점", "date_idx": i, "volume": volumes[i]})
        if len(left_high) and len(right_high) and highs[i] >= max(left_high.max(), right_high.max()):
            candidates.append({"price": float(highs[i]), "weight": 5.0 * vboost, "source": "피봇고점", "date_idx": i, "volume": volumes[i]})

    # 2) 거래량 동반 아래꼬리/위꼬리 반전 후보
    for i in range(max(1, len(recent) - 80), len(recent)):
        o = safe_float(recent.loc[i, "Open"], closes[i])
        h = highs[i]
        l = lows[i]
        c = closes[i]
        rng = max(h - l, 1e-9)
        lower_wick = min(o, c) - l
        upper_wick = h - max(o, c)
        vboost = 1.35 if vol_ma[i] and volumes[i] >= vol_ma[i] * 1.2 else 1.0
        if lower_wick / rng >= 0.45:
            candidates.append({"price": float(l), "weight": 4.0 * vboost, "source": "아래꼬리수요", "date_idx": i, "volume": volumes[i]})
        if upper_wick / rng >= 0.45:
            candidates.append({"price": float(h), "weight": 4.0 * vboost, "source": "위꼬리공급", "date_idx": i, "volume": volumes[i]})

    # 3) 이평선/볼린저밴드 동적 지지·저항
    last = df.iloc[-1]
    for ma in ["MA10", "MA20", "MA50", "MA60", "MA100", "MA120", "MA200"]:
        if ma in df.columns:
            value = safe_float(last.get(ma), np.nan)
            if not np.isnan(value) and value > 0:
                weight = 5.5 if ma in ["MA20", "MA50", "MA60"] else 4.0
                candidates.append({"price": value, "weight": weight, "source": ma, "date_idx": len(recent) - 1, "volume": volumes[-1] if len(volumes) else 0})
    for bb, name in [("BB_Lower", "BB하단"), ("BB_Mid", "BB중심"), ("BB_Upper", "BB상단")]:
        if bb in df.columns:
            value = safe_float(last.get(bb), np.nan)
            if not np.isnan(value) and value > 0:
                candidates.append({"price": value, "weight": 4.0, "source": name, "date_idx": len(recent) - 1, "volume": volumes[-1] if len(volumes) else 0})

    # 4) 롤링 고저점
    for n in [10, 20, 40, 60, 120]:
        if len(recent) >= n:
            candidates.append({"price": float(pd.Series(lows).tail(n).min()), "weight": 4.5, "source": f"{n}일저점", "date_idx": len(recent) - 1, "volume": volumes[-1] if len(volumes) else 0})
            candidates.append({"price": float(pd.Series(highs).tail(n).max()), "weight": 4.5, "source": f"{n}일고점", "date_idx": len(recent) - 1, "volume": volumes[-1] if len(volumes) else 0})

    # 5) 최근 스윙 피보나치 되돌림
    look = recent.tail(min(120, len(recent))).reset_index(drop=True)
    if not look.empty:
        swing_low = safe_float(look["Low"].min(), np.nan)
        swing_high = safe_float(look["High"].max(), np.nan)
        if not np.isnan(swing_low) and not np.isnan(swing_high) and swing_high > swing_low:
            for ratio in [0.236, 0.382, 0.5, 0.618, 0.786]:
                fib = swing_high - (swing_high - swing_low) * ratio
                candidates.append({"price": float(fib), "weight": 3.6, "source": f"피보{ratio:.3f}", "date_idx": len(recent) - 1, "volume": volumes[-1] if len(volumes) else 0})

    tolerance = max(atr * 0.22, cur * 0.006)
    levels = _cluster_price_levels(candidates, cur, tolerance)

    supports = sorted([lv for lv in levels if lv["price"] < cur], key=lambda x: (x["score"], -abs(x["price"] - cur)), reverse=True)
    resistances = sorted([lv for lv in levels if lv["price"] > cur], key=lambda x: (x["score"], -abs(x["price"] - cur)), reverse=True)

    # 현재가와 너무 가까운 라인은 체결 노이즈일 수 있어 보조로 두되, 후보가 부족하면 사용
    if len(supports) < 2:
        fallback_sup = sorted({float(p) for p in recent["Low"].rolling(10).min().dropna().unique() if float(p) < cur}, reverse=True)
        for p in fallback_sup[:4]:
            supports.append({"price": p, "score": 42, "touches": 1, "distance_pct": abs(p / cur - 1) * 100, "sources": "롤링저점보완", "label": "보완"})
    if len(resistances) < 2:
        fallback_res = sorted({float(p) for p in recent["High"].rolling(10).max().dropna().unique() if float(p) > cur})
        for p in fallback_res[:4]:
            resistances.append({"price": p, "score": 42, "touches": 1, "distance_pct": abs(p / cur - 1) * 100, "sources": "롤링고점보완", "label": "보완"})

    supports = sorted(supports, key=lambda x: (x["score"], -x["distance_pct"]), reverse=True)
    resistances = sorted(resistances, key=lambda x: (x["score"], -x["distance_pct"]), reverse=True)

    supports = _apply_zone_to_levels(supports, "support", cur, atr, tolerance)
    resistances = _apply_zone_to_levels(resistances, "resistance", cur, atr, tolerance)

    s1 = supports[0]["price"] if len(supports) > 0 else cur * 0.97
    s2 = supports[1]["price"] if len(supports) > 1 else cur * 0.94
    r1 = resistances[0]["price"] if len(resistances) > 0 else cur * 1.03
    r2 = resistances[1]["price"] if len(resistances) > 1 else cur * 1.06

    return {
        "support1": s1,
        "support2": s2,
        "resistance1": r1,
        "resistance2": r2,
        "support_levels": supports[:6],
        "resistance_levels": resistances[:6],
        "support_zones": supports[:6],
        "resistance_zones": resistances[:6],
        "level_tolerance": tolerance,
        "sr_method": "피봇·거래량·이평선·BB·피보나치·롤링고저점 클러스터 점수화 + 존 박스",
    }

def calculate_trade_score(df: pd.DataFrame, sr: dict[str, float]) -> dict[str, Any]:
    last = df.iloc[-1]
    cur = safe_float(last["Close"])
    score = 0
    reasons: list[str] = []

    ma20 = safe_float(last["MA20"])
    ma60 = safe_float(last["MA60"])
    rsi = safe_float(last["RSI"], 50.0)
    macd = safe_float(last["MACD"])
    sig = safe_float(last["MACD_Signal"])
    vol = safe_float(last["Volume"])
    vol_ma = safe_float(last["VOL_MA20"], 1.0)

    if ma20 > 0 and cur > ma20:
        score += 15
        reasons.append("현재가 MA20 위")
    if ma20 > 0 and ma60 > 0 and ma20 > ma60:
        score += 15
        reasons.append("MA20 > MA60")
    if ma60 > 0 and cur > ma60:
        score += 10
        reasons.append("현재가 MA60 위")
    if 45 <= rsi <= 65:
        score += 15
        reasons.append(f"RSI 적정({rsi:.1f})")
    elif 30 <= rsi < 45:
        score += 8
        reasons.append(f"RSI 저점권({rsi:.1f})")
    elif rsi >= 70:
        score -= 10
        reasons.append(f"RSI 과열({rsi:.1f})")
    if macd > sig:
        score += 15
        reasons.append("MACD > Signal")
    if vol_ma > 0 and vol > vol_ma:
        score += 10
        reasons.append("거래량 MA20 상회")
    if cur > 0 and cur < sr["resistance1"] and (sr["resistance1"] - cur) / cur <= 0.03:
        score -= 5
        reasons.append("1차 저항선 3% 이내")
    if cur > 0 and abs(cur - sr["support1"]) / cur <= 0.03:
        score += 10
        reasons.append("1차 지지선 근처")

    score = max(0, min(100, score))
    if score >= 80:
        verdict, color = "눌림목 매수 가능", "#00c94a"
    elif score >= 65:
        verdict, color = "돌파 확인 후 접근", "#7ecef4"
    elif score >= 45:
        verdict, color = "관망 우위", "#f0c040"
    elif score >= 30:
        verdict, color = "비중 축소 우선", "#f07840"
    else:
        verdict, color = "손절 우선", "#e03030"
    return {"score": score, "verdict": verdict, "color": color, "reasons": reasons}


# ══════════════════════════════════════════════
# 예측 및 주문 기준가
# ══════════════════════════════════════════════
def infer_event_learning_bucket_v9988(
    event_context: dict[str, Any] | None = None,
    row: pd.Series | dict[str, Any] | None = None,
    market: str | None = None,
) -> str:
    """Classify prediction records so similar event days learn from each other first."""
    try:
        ctx = event_context or {}

        def _row_get(key: str, default: Any = "") -> Any:
            if row is None:
                return default
            try:
                return row.get(key, default)  # type: ignore[union-attr]
            except Exception:
                return default

        explicit = str(ctx.get("event_learning_bucket", "") or "").strip().lower()
        if explicit and explicit not in {"nan", "none", "-", "normal"}:
            return explicit

        phase_text = str(ctx.get("earnings_event_phase", "") or _row_get("earnings_event_phase", "") or "").strip().lower()
        if phase_text and phase_text not in {"none", "nan", "-", "unknown"}:
            return "earnings"

        parts: list[str] = []
        for key in ["event_label", "earnings_snapshot_text", "sector", "news_source"]:
            v = ctx.get(key, "")
            if v:
                parts.append(str(v))
            rv = _row_get(key, "")
            if rv is not None and not pd.isna(rv):
                parts.append(str(rv))
        for key in ["event_types", "event_names", "auto_news_items", "auto_news_source_items", "auto_macro_events"]:
            v = ctx.get(key, [])
            if isinstance(v, (list, tuple, set)):
                parts.extend([str(x) for x in v])
            elif v:
                parts.append(str(v))

        text = " ".join(parts).lower()
        if any(k in text for k in ["earnings", "guidance", "eps", "revenue", "실적", "가이던스", "매출"]):
            return "earnings"
        if any(k in text for k in ["fomc", "fed", "powell", "연준", "파월"]):
            return "fomc"
        if any(k in text for k in ["cpi", "consumer price", "inflation", "물가", "인플레이션"]):
            return "cpi"
        if any(k in text for k in ["ppi", "pce", "producer price"]):
            return "inflation"
        if any(k in text for k in ["payroll", "employment", "unemployment", "고용", "실업"]):
            return "jobs"
        if any(k in text for k in ["oil", "crude", "wti", "brent", "opec", "유가", "원유"]):
            return "oil"
        if any(k in text for k in ["iran", "israel", "middle east", "war", "attack", "missile", "이란", "이스라엘", "중동", "전쟁", "공격"]):
            return "geopolitical"
        if any(k in text for k in ["semiconductor", "chip", "nvidia", "amd", "intel", "qualcomm", "ai", "반도체", "엔비디아"]):
            return "semiconductor"
        if any(k in text for k in ["dollar", "yield", "treasury", "rate", "환율", "달러", "금리", "국채"]):
            return "rates_fx"
        if any(k in text for k in ["dart", "공시", "supply", "수급", "기관", "외국인"]):
            return "flow_disclosure" if str(market or _row_get("market", "")).strip() == "한국주식" else "flow"
        return "normal"
    except Exception:
        return "normal"


def _event_bucket_series_v9988(df: pd.DataFrame, market: str | None = None) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=str)
    if "event_learning_bucket" in df.columns:
        explicit = df["event_learning_bucket"].astype(str).str.strip().str.lower()
    else:
        explicit = pd.Series([""] * len(df), index=df.index)
    inferred = df.apply(lambda r: infer_event_learning_bucket_v9988(row=r, market=market), axis=1)
    return explicit.where(~explicit.isin(["", "nan", "none", "-", "normal"]), inferred).fillna("normal")


def get_recent_bias_adjustment(log_df: pd.DataFrame, ticker: str, event_context: dict[str, Any] | None = None) -> dict[str, float]:
    """종목별 최근 오차 가중 보정. 최근 5회 50%, 10회 30%, 전체 20%."""
    empty = {
        "open_bias_pct": 0.0, "close_bias_pct": 0.0, "n": 0,
        "open_abs_error_avg": np.nan, "close_abs_error_avg": np.nan,
        "recent5_open": 0.0, "recent10_open": 0.0, "all_open": 0.0,
    }
    if log_df.empty or "ticker" not in log_df.columns or "open_error_pct" not in log_df.columns:
        return empty
    d = log_df[log_df["ticker"].astype(str).str.upper() == ticker.upper()].copy()
    d["open_error_pct"] = pd.to_numeric(d.get("open_error_pct"), errors="coerce")
    d["close_error_pct"] = pd.to_numeric(d.get("close_error_pct"), errors="coerce")
    d = d[d["open_error_pct"].notna()]
    if d.empty:
        return empty

    # 이벤트가 있는 날은 이벤트 기록이 5건 이상 있을 때만 따로 우선 적용
    if event_context and event_context.get("has_major_event") and "event_label" in d.columns:
        ev_d = d[d["event_label"].astype(str).str.contains("|".join(event_context.get("event_types", [])), regex=True, na=False)]
        if len(ev_d) >= 5:
            d = ev_d
    current_bucket = infer_event_learning_bucket_v9988(event_context, market=str(d["market"].iloc[0]) if "market" in d.columns and not d.empty else None)
    if current_bucket != "normal":
        bucket_d = d[_event_bucket_series_v9988(d, market=str(d["market"].iloc[0]) if "market" in d.columns and not d.empty else None).eq(current_bucket)].copy()
        if len(bucket_d) >= 2:
            d = bucket_d

    open_all = d["open_error_pct"].dropna()
    close_all = d["close_error_pct"].dropna()
    open5 = open_all.tail(5)
    open10 = open_all.tail(10)
    close5 = close_all.tail(5)
    close10 = close_all.tail(10)

    def weighted(s5, s10, sall):
        parts = []
        if len(s5): parts.append((float(s5.mean()), 0.50))
        if len(s10): parts.append((float(s10.mean()), 0.30))
        if len(sall): parts.append((float(sall.mean()), 0.20))
        if not parts:
            return 0.0
        return sum(v*w for v, w in parts) / sum(w for _, w in parts)

    return {
        "open_bias_pct": weighted(open5, open10, open_all),
        "close_bias_pct": weighted(close5, close10, close_all),
        "n": int(len(d)),
        "open_abs_error_avg": float(open_all.abs().tail(10).mean()) if len(open_all) else np.nan,
        "close_abs_error_avg": float(close_all.abs().tail(10).mean()) if len(close_all) else np.nan,
        "recent5_open": float(open5.mean()) if len(open5) else 0.0,
        "recent10_open": float(open10.mean()) if len(open10) else 0.0,
        "all_open": float(open_all.mean()) if len(open_all) else 0.0,
    }


def build_learning_adjustment_v9987(
    log_df: pd.DataFrame,
    ticker: str,
    market: str,
    event_context: dict[str, Any] | None = None,
    min_records: int = 2,
) -> dict[str, Any]:
    """Convert recent validation/replay results into next-prediction controls."""
    empty = {
        "n": 0,
        "confidence_delta": 0,
        "entry_offset_pct": 0.0,
        "range_multiplier": 1.0,
        "quantity_factor": 1.0,
        "premarket_weight_delta": 0,
        "guard_reason": "",
        "event_learning_bucket": infer_event_learning_bucket_v9988(event_context, market=market),
        "event_learning_sample_n": 0,
        "event_learning_used": 0,
        "reason": "completed validation records are not enough",
    }
    try:
        if log_df is None or log_df.empty or "ticker" not in log_df.columns:
            return empty
        d = log_df[log_df["ticker"].astype(str).str.upper().eq(str(ticker).upper())].copy()
        if "market" in d.columns:
            d = d[d["market"].astype(str).eq(str(market))]
        if "actual_close" not in d.columns:
            return empty
        d["actual_close"] = pd.to_numeric(d["actual_close"], errors="coerce")
        d = d[d["actual_close"].notna()].copy()
        if d.empty or len(d) < min_records:
            return empty | {"n": int(len(d))}

        current_bucket = infer_event_learning_bucket_v9988(event_context, market=market)
        event_sample_n = 0
        event_learning_used = 0
        if current_bucket != "normal":
            buckets = _event_bucket_series_v9988(d, market=market)
            event_d = d[buckets.eq(current_bucket)].copy()
            event_sample_n = int(len(event_d))
            if len(event_d) >= min_records:
                d = event_d
                event_learning_used = 1

        d = d.tail(20).copy()
        recent = d.tail(8).copy()

        def _num(col: str) -> pd.Series:
            if col not in recent.columns:
                return pd.Series(dtype=float)
            return pd.to_numeric(recent[col], errors="coerce")

        def _rate(col: str) -> float:
            if col not in recent.columns or recent.empty:
                return np.nan
            return float(recent[col].apply(_boolish_v9956).mean())

        open_abs = float(_num("open_abs_error_pct").dropna().mean()) if len(_num("open_abs_error_pct").dropna()) else np.nan
        close_abs = float(_num("close_abs_error_pct").dropna().mean()) if len(_num("close_abs_error_pct").dropna()) else np.nan
        open_hit = _rate("open_in_range")
        close_hit = _rate("close_in_range")
        dir_hit = _rate("direction_hit")
        fill_rate = _rate("virtual_entry_filled")
        stop_rate = _rate("stop_touched")
        tp1_rate = _rate("tp1_touched")
        net = _num("virtual_net_return_pct")
        avg_net = float(net.dropna().mean()) if len(net.dropna()) else np.nan

        confidence_delta = 0
        entry_offset_pct = 0.0
        range_multiplier = 1.0
        quantity_factor = 1.0
        premarket_weight_delta = 0
        reasons: list[str] = []
        guard_reasons: list[str] = []

        if not np.isnan(open_abs) and open_abs >= 2.0:
            range_multiplier *= 1.08
            premarket_weight_delta += 6 if market == "미국주식" else 0
            reasons.append(f"recent open error {open_abs:.1f}%")
        if not np.isnan(close_abs) and close_abs >= 3.0:
            range_multiplier *= 1.12
            confidence_delta -= 4
            reasons.append(f"recent close error {close_abs:.1f}%")
        if not np.isnan(open_hit) and open_hit < 0.55:
            range_multiplier *= 1.08
            reasons.append(f"open range hit {open_hit*100:.0f}%")
        if not np.isnan(close_hit) and close_hit < 0.55:
            range_multiplier *= 1.12
            confidence_delta -= 3
            reasons.append(f"close range hit {close_hit*100:.0f}%")
        if not np.isnan(dir_hit) and dir_hit < 0.45:
            confidence_delta -= 6
            quantity_factor *= 0.85
            guard_reasons.append("방향 적중률 낮음")
        if not np.isnan(stop_rate) and stop_rate >= 0.45:
            entry_offset_pct -= 0.9
            confidence_delta -= 6
            quantity_factor *= 0.75
            guard_reasons.append("최근 손절 빈도 높음")
        if not np.isnan(avg_net) and avg_net <= -1.0:
            entry_offset_pct -= 0.7
            confidence_delta -= 5
            quantity_factor *= 0.80
            guard_reasons.append(f"가상매매 평균 {avg_net:.1f}%")
        if not np.isnan(fill_rate) and fill_rate < 0.35 and (np.isnan(avg_net) or avg_net >= -0.5):
            entry_offset_pct += 0.35
            reasons.append("진입가 미도달 반복")
        if not np.isnan(tp1_rate) and tp1_rate >= 0.45 and (np.isnan(avg_net) or avg_net > 0):
            confidence_delta += 3
            quantity_factor *= 1.05
            reasons.append("익절 도달률 양호")

        reliability = 0.65 if len(d) < 5 else 0.85 if len(d) < 10 else 1.0
        range_multiplier = 1.0 + (range_multiplier - 1.0) * reliability
        entry_offset_pct = entry_offset_pct * reliability
        quantity_factor = 1.0 + (quantity_factor - 1.0) * reliability
        confidence_delta = int(round(confidence_delta * reliability))

        range_multiplier = float(max(0.85, min(1.55, range_multiplier)))
        entry_offset_pct = float(max(-2.5, min(0.8, entry_offset_pct)))
        quantity_factor = float(max(0.35, min(1.10, quantity_factor)))
        confidence_delta = int(max(-18, min(8, confidence_delta)))
        premarket_weight_delta = int(max(0, min(12, premarket_weight_delta)))
        if current_bucket != "normal":
            reasons.insert(0, f"event bucket {current_bucket}: {'used' if event_learning_used else 'fallback'} {event_sample_n} records")
        reason = " / ".join(dict.fromkeys(reasons + guard_reasons)) or "recent validation is stable"
        guard_reason = " / ".join(dict.fromkeys(guard_reasons))
        return {
            "n": int(len(d)),
            "event_learning_bucket": current_bucket,
            "event_learning_sample_n": event_sample_n,
            "event_learning_used": event_learning_used,
            "confidence_delta": confidence_delta,
            "entry_offset_pct": entry_offset_pct,
            "range_multiplier": range_multiplier,
            "quantity_factor": quantity_factor,
            "premarket_weight_delta": premarket_weight_delta,
            "guard_reason": guard_reason,
            "reason": reason,
            "open_abs_error_avg": open_abs,
            "close_abs_error_avg": close_abs,
            "direction_hit_rate": dir_hit,
            "fill_rate": fill_rate,
            "stop_rate": stop_rate,
            "avg_virtual_net_return_pct": avg_net,
        }
    except Exception:
        return empty


def apply_learning_to_confidence_v9987(confidence: dict[str, Any], learning: dict[str, Any]) -> dict[str, Any]:
    out = dict(confidence or {})
    delta = int(safe_float(learning.get("confidence_delta"), 0))
    base = int(safe_float(out.get("score"), 50))
    score = int(max(0, min(100, base + delta)))
    out["score"] = score
    if score >= 80:
        out["label"] = "높음"
    elif score >= 65:
        out["label"] = "양호"
    elif score >= 45:
        out["label"] = "보통"
    else:
        out["label"] = "낮음"
    reasons = list(out.get("reasons", []) or [])
    if int(learning.get("n", 0) or 0) >= 2:
        sign = "+" if delta > 0 else ""
        reasons.append(f"검증학습 보정 {sign}{delta}점: {learning.get('reason', '-')}")
    out["reasons"] = reasons
    return out


def apply_learning_to_prediction_v9987(prediction: dict[str, Any], learning: dict[str, Any], market: str) -> dict[str, Any]:
    out = dict(prediction or {})
    try:
        if int(learning.get("n", 0) or 0) < 2:
            out["learning_adjustment_applied"] = 0
            return out
        offset = safe_float(learning.get("entry_offset_pct"), 0.0)
        old_entry = safe_float(out.get("preferred_entry"), np.nan)
        old_stop = safe_float(out.get("stop_loss"), np.nan)
        old_tp1 = safe_float(out.get("take_profit1"), np.nan)
        old_tp2 = safe_float(out.get("take_profit2"), np.nan)
        if not np.isnan(old_entry) and old_entry > 0 and abs(offset) >= 0.05:
            new_entry = old_entry * (1 + offset / 100)
            stop_gap = (old_entry - old_stop) / old_entry if not np.isnan(old_stop) and old_stop > 0 and old_stop < old_entry else 0.035
            tp1_gap = (old_tp1 - old_entry) / old_entry if not np.isnan(old_tp1) and old_tp1 > old_entry else max(stop_gap * 1.5, 0.045)
            tp2_gap = (old_tp2 - old_entry) / old_entry if not np.isnan(old_tp2) and old_tp2 > old_entry else max(tp1_gap * 1.45, 0.08)
            out["preferred_entry"] = new_entry
            out["stop_loss"] = max(0.0, new_entry * (1 - stop_gap))
            out["take_profit1"] = new_entry * (1 + tp1_gap)
            out["take_profit2"] = max(out["take_profit1"], new_entry * (1 + tp2_gap))
            risk = out["preferred_entry"] - out["stop_loss"]
            out["rr1"] = (out["take_profit1"] - out["preferred_entry"]) / risk if risk > 0 else out.get("rr1", np.nan)
            basis = str(out.get("entry_basis", "") or "")
            out["entry_basis"] = (basis + " / " if basis else "") + f"검증학습 {offset:+.2f}% 진입가 보정"
        no_buy_flags = list(out.get("no_buy_flags", []) or [])
        guard = str(learning.get("guard_reason", "") or "").strip()
        if guard:
            no_buy_flags.append(f"검증학습 주의: {guard}")
        out["no_buy_flags"] = list(dict.fromkeys([str(x) for x in no_buy_flags if str(x).strip()]))
        out["confidence_score"] = int(max(0, min(100, safe_float(out.get("confidence_score"), 50) + safe_float(learning.get("confidence_delta"), 0))))
        out["learning_adjustment_applied"] = 1
        out["learning_adjustment_reason"] = learning.get("reason", "")
        out["learning_entry_offset_pct"] = safe_float(learning.get("entry_offset_pct"), 0.0)
        out["learning_range_multiplier"] = safe_float(learning.get("range_multiplier"), 1.0)
        out["learning_quantity_factor"] = safe_float(learning.get("quantity_factor"), 1.0)
        out["learning_guard_reason"] = learning.get("guard_reason", "")
        return out
    except Exception:
        out["learning_adjustment_applied"] = 0
        return out


def infer_stock_sensitivity_group_v9989(symbol: str, market: str, sector: str = "", meta: dict[str, Any] | None = None) -> dict[str, str]:
    """Classify how a ticker usually reacts to macro/news shocks."""
    raw_u = str(symbol or "").upper().replace(".KS", "").replace(".KQ", "").strip()
    try:
        sym = display_symbol(symbol, market) if "display_symbol" in globals() else str(symbol or "")
    except Exception:
        sym = str(symbol or "")
    sym_u = str(sym or "").upper().replace(".KS", "").replace(".KQ", "").strip()
    meta = meta or {}
    text = " ".join([
        sym_u,
        str(sector or ""),
        str(meta.get("name", "")),
        str(meta.get("theme", "")),
        str(meta.get("group", "")),
        str(meta.get("sector", "")),
    ]).lower()

    semi_us = {"NVDA", "AMD", "AVGO", "QCOM", "INTC", "MU", "TSM", "ASML", "ARM", "SMCI", "SOXX", "SMH"}
    semi_kr = {"005930", "000660", "042700", "058470", "039030", "240810", "000990", "036930", "403870"}
    high_beta = {"TSLA", "PLTR", "RKLB", "COIN", "MSTR", "HOOD", "SOFI", "RBLX", "OPEN", "IONQ", "AI"}
    mega_growth = {"AAPL", "MSFT", "AMZN", "GOOGL", "GOOG", "META", "NFLX", "QQQ"}
    energy = {"XOM", "CVX", "OXY", "COP", "010950", "096770", "267250"}
    oil_sensitive = {"AAL", "DAL", "UAL", "LUV", "CCL", "RCL", "003490", "180640", "089590"}
    financial = {"JPM", "BAC", "WFC", "GS", "MS", "C", "055550", "105560", "086790", "316140"}
    export_fx = {"005380", "000270", "012330", "066570", "011070", "051910", "373220"}
    utility_power = {"015760", "036460", "018670"}
    shipbuilding = {"009540", "010140", "329180", "042660"}
    platform_growth = {"035420", "035720", "259960", "293490"}
    etfs = {"SPY", "QQQ", "IWM", "SOXX", "SMH", "DIA", "VTI", "VOO"}

    if sym_u in semi_us or raw_u in semi_us or sym_u in semi_kr or raw_u in semi_kr or any(k in text for k in ["반도체", "semiconductor", "chip", "hbm", "ai"]):
        return {"group": "semiconductor_ai", "label": "AI/반도체 민감", "reason": "AI·반도체 뉴스와 금리/성장주 변동성에 민감"}
    if sym_u in high_beta or raw_u in high_beta or any(k in text for k in ["성장주", "고변동", "우주", "crypto", "coin", "ark"]):
        return {"group": "high_beta_growth", "label": "고베타 성장주", "reason": "금리·유동성·위험선호 변화에 민감"}
    if sym_u in mega_growth or raw_u in mega_growth or any(k in text for k in ["빅테크", "software", "cloud", "플랫폼"]):
        return {"group": "large_growth_rate", "label": "대형 성장/금리 민감", "reason": "금리와 나스닥 방향성에 민감"}
    if sym_u in export_fx or raw_u in export_fx or any(k in text for k in ["자동차", "수출", "배터리", "환율", "export"]):
        return {"group": "export_fx", "label": "수출/환율 민감", "reason": "원달러 환율과 글로벌 수요 변화에 민감"}
    if sym_u in energy or raw_u in energy or any(k in text for k in ["정유", "에너지", "energy", "oil"]):
        return {"group": "energy_oil", "label": "에너지/유가 수혜", "reason": "유가 상승과 지정학 이벤트에 민감"}
    if sym_u in oil_sensitive or raw_u in oil_sensitive or any(k in text for k in ["항공", "여행", "해운", "airline", "cruise"]):
        return {"group": "oil_cost_sensitive", "label": "유가 비용 민감", "reason": "유가 상승 시 비용 부담이 커지는 업종"}
    if sym_u in financial or raw_u in financial or any(k in text for k in ["은행", "증권", "금융", "bank", "financial"]):
        return {"group": "financial_rate", "label": "금리/금융 민감", "reason": "금리 경로와 경기 전망에 민감"}
    if sym_u in utility_power or raw_u in utility_power or any(k in text for k in ["전력", "전기", "utility", "power"]):
        return {"group": "utility_power", "label": "전력/방어 민감", "reason": "전력수요·요금·방어주 흐름에 민감"}
    if sym_u in shipbuilding or raw_u in shipbuilding or any(k in text for k in ["조선", "선박", "shipbuilding"]):
        return {"group": "shipbuilding_cycle", "label": "조선/산업 사이클", "reason": "유가·환율·수주 사이클에 민감"}
    if sym_u in platform_growth or raw_u in platform_growth:
        return {"group": "platform_growth", "label": "플랫폼 성장주", "reason": "금리와 성장주 심리에 민감"}
    if sym_u in etfs or raw_u in etfs or "etf" in text:
        return {"group": "index_etf", "label": "지수/ETF", "reason": "개별 뉴스보다 지수·섹터 흐름 영향이 큼"}
    return {"group": "neutral", "label": "일반 민감도", "reason": "특정 매크로 민감도 분류가 강하지 않음"}


def news_event_impact_profile_v9989(
    event_context: dict[str, Any] | None,
    market: str,
    sensitivity_group: str = "neutral",
    base_score: float | None = None,
) -> dict[str, Any]:
    """Convert raw news score into a ticker-aware impact score."""
    ctx = event_context or {}
    bucket = infer_event_learning_bucket_v9988(ctx, market=market)
    raw = safe_float(base_score if base_score is not None else ctx.get("auto_news_score", 0), 0)
    score = int(max(-5, min(5, round(raw))))
    group = str(sensitivity_group or "neutral")
    reasons: list[str] = []

    def adjust(delta: int, reason: str) -> None:
        nonlocal score
        score = int(max(-5, min(5, score + delta)))
        if reason:
            reasons.append(reason)

    if bucket in {"cpi", "fomc", "inflation", "jobs", "rates_fx"}:
        if group in {"semiconductor_ai", "high_beta_growth", "large_growth_rate", "platform_growth"}:
            if score < 0:
                adjust(-1, "금리·물가 부담 뉴스라 성장주 민감도를 한 단계 보수적으로 반영")
            elif score > 0:
                adjust(1, "금리 부담 완화 뉴스라 성장주 민감도를 한 단계 우호적으로 반영")
            else:
                adjust(-1, "매크로 이벤트 확인 전까지 성장주는 보수 가중")
        elif group == "financial_rate" and score != 0:
            adjust(1 if score > 0 else -1, "금리 경로 변화에 금융주 민감도 반영")
    elif bucket == "semiconductor" and group == "semiconductor_ai" and score != 0:
        adjust(1 if score > 0 else -1, "AI·반도체 직접 뉴스라 종목 민감도 확대")
    elif bucket == "oil":
        if group == "energy_oil":
            adjust(1 if score >= 0 else -1, "유가 이벤트는 에너지주에 직접 영향")
        elif group == "oil_cost_sensitive":
            adjust(-1, "유가 상승/변동성은 비용 민감 업종에 부담")
    elif bucket == "geopolitical":
        if group in {"high_beta_growth", "semiconductor_ai", "oil_cost_sensitive"} and score <= 0:
            adjust(-1, "지정학 리스크는 고베타·공급망 민감 종목에 부담")
        elif group == "energy_oil" and score >= 0:
            adjust(1, "지정학 이벤트의 유가 경로를 에너지 민감도에 반영")
    elif bucket == "flow_disclosure" and market == "한국주식":
        if score != 0:
            adjust(1 if score > 0 else -1, "공시·수급성 뉴스는 국장 단기 흐름에 직접 반영")

    label = "우호" if score >= 2 else "부담" if score <= -2 else "중립/확인"
    reason = " / ".join(dict.fromkeys(reasons)) or "뉴스 원점수 유지"
    return {
        "news_impact_bucket": bucket,
        "news_impact_score": score,
        "news_impact_label": label,
        "news_impact_reason": reason,
    }


def build_event_performance_summary_v9989(log_df: pd.DataFrame, market: str) -> pd.DataFrame:
    """Aggregate post-market validation by event bucket."""
    if log_df is None or log_df.empty:
        return pd.DataFrame()
    df = enrich_virtual_trade_columns_v9956(log_df).copy()
    if "market" in df.columns:
        df = df[df["market"].astype(str).eq(str(market))].copy()
    if df.empty or "actual_close" not in df.columns:
        return pd.DataFrame()
    df["actual_close"] = pd.to_numeric(df.get("actual_close"), errors="coerce")
    df = df[df["actual_close"].notna()].copy()
    if df.empty:
        return pd.DataFrame()
    df["event_learning_bucket"] = _event_bucket_series_v9988(df, market=market)

    for c in ["open_in_range", "close_in_range", "direction_hit", "virtual_entry_filled", "tp1_touched", "stop_touched"]:
        if c in df.columns:
            df[c] = df[c].apply(lambda x: 1 if _boolish_v9956(x) else 0)
    for c in ["close_abs_error_pct", "virtual_net_return_pct"]:
        if c in df.columns:
            df[c] = pd.to_numeric(df[c], errors="coerce")

    rows: list[dict[str, Any]] = []
    for bucket, g in df.groupby("event_learning_bucket", dropna=False):
        n = len(g)
        if n <= 0:
            continue
        close_hit = g["close_in_range"].mean() * 100 if "close_in_range" in g.columns else np.nan
        dir_hit = g["direction_hit"].mean() * 100 if "direction_hit" in g.columns else np.nan
        avg_ret = g["virtual_net_return_pct"].mean() if "virtual_net_return_pct" in g.columns else np.nan
        stop_rate = g["stop_touched"].mean() * 100 if "stop_touched" in g.columns else np.nan
        priority = "표본부족"
        if n >= 3:
            if (not pd.isna(close_hit) and close_hit < 55) or (not pd.isna(avg_ret) and avg_ret < 0) or (not pd.isna(stop_rate) and stop_rate >= 45):
                priority = "보정필요"
            else:
                priority = "유지"
        rows.append({
            "이벤트유형": str(bucket or "normal"),
            "검증건수": int(n),
            "시초가범위적중률": g["open_in_range"].mean() * 100 if "open_in_range" in g.columns else np.nan,
            "종가범위적중률": close_hit,
            "방향적중률": dir_hit,
            "진입체결률": g["virtual_entry_filled"].mean() * 100 if "virtual_entry_filled" in g.columns else np.nan,
            "1차익절률": g["tp1_touched"].mean() * 100 if "tp1_touched" in g.columns else np.nan,
            "손절률": stop_rate,
            "평균종가오차%": g["close_abs_error_pct"].mean() if "close_abs_error_pct" in g.columns else np.nan,
            "평균가상순수익%": avg_ret,
            "다음보정": priority,
        })
    out = pd.DataFrame(rows)
    if out.empty:
        return out
    order = {"보정필요": 0, "표본부족": 1, "유지": 2}
    out["_order"] = out["다음보정"].map(order).fillna(9)
    out = out.sort_values(["_order", "검증건수"], ascending=[True, False]).drop(columns=["_order"])
    return out.reset_index(drop=True)


def render_event_performance_dashboard_v9989(log_df: pd.DataFrame, market: str) -> None:
    try:
        perf = build_event_performance_summary_v9989(log_df, market)
        if perf.empty:
            return
        st.markdown("#### 이벤트별 예측 성과")
        st.caption("CPI/FOMC/실적/반도체/유가처럼 성격이 다른 장에서는 따로 성적을 보고 다음 예측 보정을 다르게 적용합니다.")
        view = perf.copy()
        for c in ["시초가범위적중률", "종가범위적중률", "방향적중률", "진입체결률", "1차익절률", "손절률", "평균종가오차%", "평균가상순수익%"]:
            if c in view.columns:
                view[c] = pd.to_numeric(view[c], errors="coerce").round(2)
        st.dataframe(view, use_container_width=True, hide_index=True)
    except Exception as e:
        st.caption(f"이벤트별 성과표 표시 중 오류: {e}")



def _to_bool_series(series: pd.Series) -> pd.Series:
    """CSV에 bool/문자열이 섞여도 True/False로 안정 변환."""
    return series.astype(str).str.lower().isin(["true", "1", "yes", "y"])


def calculate_atr_calibration_stats(
    log_df: pd.DataFrame,
    ticker: str,
    event_context: dict[str, Any] | None = None,
    target_coverage: float = 0.75,
) -> dict[str, Any]:
    """
    저장된 예측 결과로 ATR 예측 범위 보정배수를 계산한다.
    - 범위 적중률이 낮으면 다음 예측 범위를 넓힘
    - 범위 적중률이 지나치게 높고 범위가 과하게 넓으면 다음 예측 범위를 좁힘
    - 최근 5회/10회/전체를 가중 반영
    """
    empty = {
        "n": 0,
        "open_hit_rate": np.nan,
        "close_hit_rate": np.nan,
        "overall_hit_rate": np.nan,
        "open_band_coverage": np.nan,
        "close_band_coverage": np.nan,
        "open_range_width_avg_pct": np.nan,
        "close_range_width_avg_pct": np.nan,
        "open_abs_error_avg_pct": np.nan,
        "close_abs_error_avg_pct": np.nan,
        "suggested_multiplier": 1.0,
        "range_quality_label": "기록 부족",
        "reason": "완료된 예측 기록이 부족하여 ATR 보정배수 1.00배 유지",
    }
    if log_df.empty or "ticker" not in log_df.columns:
        return empty

    d = log_df[log_df["ticker"].astype(str).str.upper() == str(ticker).upper()].copy()
    need = [
        "actual_open", "actual_close", "pred_open_low", "pred_open_high",
        "pred_close_low", "pred_close_high", "pred_open_mid", "pred_close_mid",
        "open_abs_error_pct", "close_abs_error_pct",
    ]
    for col in need:
        if col not in d.columns:
            d[col] = np.nan
        d[col] = pd.to_numeric(d[col], errors="coerce")
    d = d[d["actual_close"].notna()].copy()
    if d.empty:
        return empty

    # 이벤트일은 기록이 충분할 때만 별도 보정. 아니면 일반 기록과 합산.
    if event_context and event_context.get("has_major_event") and "event_label" in d.columns:
        ev_types = event_context.get("event_types", []) or []
        if ev_types:
            ev_d = d[d["event_label"].astype(str).str.contains("|".join(ev_types), regex=True, na=False)]
            if len(ev_d) >= 5:
                d = ev_d

    # 적중 여부 계산. 기존 컬럼이 있더라도 재계산하여 일관성 확보.
    d["open_hit_calc"] = (d["pred_open_low"] <= d["actual_open"]) & (d["actual_open"] <= d["pred_open_high"])
    d["close_hit_calc"] = (d["pred_close_low"] <= d["actual_close"]) & (d["actual_close"] <= d["pred_close_high"])

    # 범위 폭 대비 실제 오차 비율. 1 초과면 범위 바깥으로 벗어난 것.
    open_half_band = (d["pred_open_high"] - d["pred_open_low"]).abs() / 2
    close_half_band = (d["pred_close_high"] - d["pred_close_low"]).abs() / 2
    open_abs_dollar = (d["actual_open"] - d["pred_open_mid"]).abs()
    close_abs_dollar = (d["actual_close"] - d["pred_close_mid"]).abs()
    d["open_band_coverage"] = open_abs_dollar / open_half_band.replace(0, np.nan)
    d["close_band_coverage"] = close_abs_dollar / close_half_band.replace(0, np.nan)
    d["open_range_width_pct"] = (d["pred_open_high"] - d["pred_open_low"]).abs() / d["pred_open_mid"].replace(0, np.nan) * 100
    d["close_range_width_pct"] = (d["pred_close_high"] - d["pred_close_low"]).abs() / d["pred_close_mid"].replace(0, np.nan) * 100

    recent5 = d.tail(5)
    recent10 = d.tail(10)

    def wavg(metric: str) -> float:
        parts = []
        for frame, weight in [(recent5, 0.50), (recent10, 0.30), (d, 0.20)]:
            vals = pd.to_numeric(frame[metric], errors="coerce").dropna()
            if len(vals):
                parts.append((float(vals.mean()), weight))
        return sum(v * w for v, w in parts) / sum(w for _, w in parts) if parts else np.nan

    open_hit = wavg("open_hit_calc")
    close_hit = wavg("close_hit_calc")
    overall_hit = np.nanmean([open_hit, close_hit])
    open_band_cov = wavg("open_band_coverage")
    close_band_cov = wavg("close_band_coverage")
    band_cov = np.nanmean([open_band_cov, close_band_cov])
    open_abs_err = wavg("open_abs_error_pct")
    close_abs_err = wavg("close_abs_error_pct")

    # 보정배수 규칙. 목표 적중률보다 낮으면 확대, 너무 넓으면 축소.
    multiplier = 1.0
    reasons = []
    target = max(0.55, min(0.90, target_coverage))
    if not np.isnan(overall_hit):
        if overall_hit < target - 0.20:
            multiplier *= 1.35; reasons.append("범위 적중률이 목표보다 크게 낮아 ATR 범위 확대")
        elif overall_hit < target - 0.10:
            multiplier *= 1.20; reasons.append("범위 적중률이 목표보다 낮아 ATR 범위 확대")
        elif overall_hit > target + 0.12 and not np.isnan(band_cov) and band_cov < 0.45:
            multiplier *= 0.88; reasons.append("범위가 과하게 넓어 ATR 범위 축소")
        elif overall_hit > target + 0.08 and not np.isnan(band_cov) and band_cov < 0.60:
            multiplier *= 0.94; reasons.append("범위 여유가 커서 ATR 범위 소폭 축소")
        else:
            reasons.append("범위 적중률이 목표권에 가까워 ATR 범위 유지")

    if event_context and event_context.get("has_major_event"):
        multiplier *= 1.05
        reasons.append("이벤트일은 돌발 변동성 고려하여 5% 추가 확대")

    multiplier = float(max(0.65, min(2.20, multiplier)))
    if np.isnan(overall_hit):
        label = "기록 부족"
    elif overall_hit < target - 0.10:
        label = "범위 과소"
    elif overall_hit > target + 0.12 and not np.isnan(band_cov) and band_cov < 0.60:
        label = "범위 과대"
    else:
        label = "적정"

    return {
        "n": int(len(d)),
        "open_hit_rate": float(open_hit) if not np.isnan(open_hit) else np.nan,
        "close_hit_rate": float(close_hit) if not np.isnan(close_hit) else np.nan,
        "overall_hit_rate": float(overall_hit) if not np.isnan(overall_hit) else np.nan,
        "open_band_coverage": float(open_band_cov) if not np.isnan(open_band_cov) else np.nan,
        "close_band_coverage": float(close_band_cov) if not np.isnan(close_band_cov) else np.nan,
        "open_range_width_avg_pct": float(wavg("open_range_width_pct")) if not np.isnan(wavg("open_range_width_pct")) else np.nan,
        "close_range_width_avg_pct": float(wavg("close_range_width_pct")) if not np.isnan(wavg("close_range_width_pct")) else np.nan,
        "open_abs_error_avg_pct": float(open_abs_err) if not np.isnan(open_abs_err) else np.nan,
        "close_abs_error_avg_pct": float(close_abs_err) if not np.isnan(close_abs_err) else np.nan,
        "suggested_multiplier": multiplier,
        "range_quality_label": label,
        "reason": " / ".join(reasons),
    }


def calculate_confidence_score(
    bias_info: dict[str, float],
    premarket_snapshot: dict[str, Any],
    bench_df: pd.DataFrame,
    event_context: dict[str, Any],
    atr_pct: float,
    sector_score: int,
    market_score: int,
) -> dict[str, Any]:
    score = 50
    reasons = []

    n = int(bias_info.get("n", 0))
    open_abs = safe_float(bias_info.get("open_abs_error_avg"), np.nan)
    if n >= 20:
        score += 15; reasons.append("예측 기록 20건 이상")
    elif n >= 10:
        score += 10; reasons.append("예측 기록 10건 이상")
    elif n >= 3:
        score += 5; reasons.append("예측 기록 3건 이상")
    else:
        score -= 10; reasons.append("종목별 예측 기록 부족")

    if not np.isnan(open_abs):
        if open_abs <= 0.5:
            score += 15; reasons.append("최근 시초가 평균 절대오차 0.5% 이하")
        elif open_abs <= 1.0:
            score += 8; reasons.append("최근 시초가 평균 절대오차 1.0% 이하")
        elif open_abs >= 2.0:
            score -= 12; reasons.append("최근 시초가 오차가 큼")

    premkt = safe_float(premarket_snapshot.get("change_pct"), np.nan)
    if not np.isnan(premkt):
        score += 12; reasons.append("프리마켓/확장세션 가격 반영")
    else:
        score -= 8; reasons.append("프리마켓 가격 미확인")

    if abs(market_score) >= 2 and abs(sector_score) >= 2 and np.sign(market_score) == np.sign(sector_score):
        score += 8; reasons.append("시장·섹터 방향 일치")
    elif np.sign(market_score) != 0 and np.sign(sector_score) != 0 and np.sign(market_score) != np.sign(sector_score):
        score -= 8; reasons.append("시장·섹터 방향 불일치")

    if event_context.get("has_major_event"):
        score -= 15; reasons.append(f"이벤트 변동성: {event_context.get('event_label')}")
    else:
        score += 5; reasons.append("대형 이벤트 없음")

    if atr_pct <= 2.5:
        score += 5; reasons.append("ATR 변동성 안정")
    elif atr_pct >= 5.0:
        score -= 10; reasons.append("ATR 변동성 과대")

    score = int(max(0, min(100, score)))
    if score >= 80: label = "높음"
    elif score >= 65: label = "양호"
    elif score >= 45: label = "보통"
    else: label = "낮음"
    return {"score": score, "label": label, "reasons": reasons}


def calculate_prediction(
    df: pd.DataFrame,
    sr: dict[str, float],
    market: str,
    market_score: int,
    sector_score: int,
    news_score: int,
    premarket_price: float | None,
    premarket_weight: float,
    open_bias_adjustment_pct: float,
    close_bias_adjustment_pct: float,
    event_context: dict[str, Any],
    confidence: dict[str, Any] | None = None,
    atr_range_multiplier: float = 1.0,
    atr_calibration: dict[str, Any] | None = None,
) -> dict[str, Any]:
    last = df.iloc[-1]
    prev_close = safe_float(last["Close"])
    atr = safe_float(last["ATR"], prev_close * 0.02)
    if atr <= 0:
        atr = prev_close * 0.02

    ma20 = safe_float(last["MA20"], prev_close)
    ma60 = safe_float(last["MA60"], prev_close)
    rsi = safe_float(last["RSI"], 50.0)
    vol_ratio = safe_float(last["VOL_RATIO"], 1.0)
    macd = safe_float(last["MACD"])
    sig = safe_float(last["MACD_Signal"])

    tech_score = 0
    if prev_close > ma20: tech_score += 1
    else: tech_score -= 1
    if ma20 > ma60: tech_score += 1
    if macd > sig: tech_score += 1
    else: tech_score -= 1
    if rsi >= 70: tech_score -= 1
    elif rsi <= 35: tech_score += 1
    if vol_ratio >= 1.5 and prev_close > ma20: tech_score += 1

    # 기본 갭률 모델: 프리마켓과 시장/섹터/뉴스 점수, 최근 오차 보정 반영
    raw_model_gap_pct = (
        market_score * 0.23
        + sector_score * 0.32
        + news_score * 0.42
        + tech_score * 0.13
    )
    model_gap_pct = raw_model_gap_pct + open_bias_adjustment_pct
    model_open = prev_close * (1 + model_gap_pct / 100)

    if premarket_price and premarket_price > 0:
        w = max(0.0, min(1.0, premarket_weight / 100))
        open_mid = premarket_price * w + model_open * (1 - w)
        premarket_gap_pct = (premarket_price / prev_close - 1) * 100
    else:
        open_mid = model_open
        premarket_gap_pct = np.nan

    atr_pct = atr / prev_close * 100 if prev_close else 2.0
    event_mult = safe_float(event_context.get("risk_mult", 1.0), 1.0)
    earnings_phase = str(event_context.get("earnings_event_phase", "") or "")
    earnings_vol_boost = safe_float(event_context.get("earnings_volatility_boost", 1.0), 1.0)
    earnings_conf_penalty = safe_float(event_context.get("earnings_confidence_penalty", 0), 0)
    if earnings_phase and earnings_phase != "none":
        event_mult = max(event_mult, safe_float(event_context.get("earnings_risk_mult", 1.0), 1.0))
    confidence_score = safe_float((confidence or {}).get("score"), 50) - earnings_conf_penalty
    confidence_factor = 1.15 if confidence_score < 50 else (0.92 if confidence_score >= 80 else 1.0)
    atr_range_multiplier = max(0.60, min(2.50, safe_float(atr_range_multiplier, 1.0)))
    calibration_reason = (atr_calibration or {}).get("reason", "ATR 보정 기록 없음")
    range_quality_label = (atr_calibration or {}).get("range_quality_label", "기본")

    uncertainty_pct = max(
        0.30,
        min(7.5, (atr_pct * 0.32 + abs(news_score) * 0.08 + abs(market_score) * 0.05) * event_mult * confidence_factor * atr_range_multiplier),
    )
    # v9.9.63: 실적/가이던스 이벤트는 방향 예측보다 변동성 확대가 핵심이므로 범위를 추가 확대
    if earnings_phase and earnings_phase != "none":
        uncertainty_pct = min(9.5, uncertainty_pct * max(1.0, earnings_vol_boost))
    open_low = open_mid * (1 - uncertainty_pct / 100)
    open_high = open_mid * (1 + uncertainty_pct / 100)

    direction = np.sign(model_gap_pct if not np.isnan(model_gap_pct) else 0)
    close_mid = open_mid + atr * 0.22 * direction + atr * 0.07 * tech_score
    close_mid = close_mid * (1 + close_bias_adjustment_pct / 100)
    close_band = max(atr * 0.62 * event_mult * confidence_factor * atr_range_multiplier, prev_close * 0.006)
    close_low = max(0.0, close_mid - close_band)
    close_high = close_mid + close_band

    pullback_buy = max(min(sr["support1"] * 1.003, open_mid * 0.995), 0.0)
    breakout_buy = sr["resistance1"] * 1.003
    chase_risk = open_mid > sr["resistance1"] * 1.02 or (not np.isnan(premarket_gap_pct) and premarket_gap_pct >= 3.0)

    if chase_risk:
        primary_action = "갭상승/과열 가능: 추격매수 금지, 돌파선 지지 확인"
        preferred_entry = sr["resistance1"] * 1.003
    elif open_mid < sr["support1"] * 0.99:
        primary_action = "갭하락 출발 가능: 초반 매수 금지, 지지 회복 확인"
        preferred_entry = sr["support1"] * 1.002
    elif abs(open_mid - sr["support1"]) / max(open_mid, 1e-9) <= 0.025:
        primary_action = "지지선 근처 출발: 반등 확인형 눌림목 후보"
        preferred_entry = pullback_buy
    elif abs(open_mid - sr["resistance1"]) / max(open_mid, 1e-9) <= 0.025:
        primary_action = "저항선 근처 출발: 돌파 확인 전 선매수 금지"
        preferred_entry = breakout_buy
    else:
        primary_action = "중립 구간 출발: 시초가 지지/이탈 확인"
        preferred_entry = min(open_mid * 0.995, pullback_buy if pullback_buy > 0 else open_mid)

    # v9.7.3 실전근사 진입가 보정
    # 기존 preferred_entry는 깊은 지지선/저항선을 그대로 따르면서 현재 가격권과 과도하게 벌어질 수 있었다.
    # 이제 우선진입가는 예상시초가와 ATR 근처로 보정하고, 기존 기술 기준가는 보수대기선으로 분리한다.
    technical_entry = preferred_entry
    conservative_entry = technical_entry
    ma20_entry = safe_float(last.get("MA20"), prev_close)
    if np.isnan(ma20_entry) or ma20_entry <= 0:
        ma20_entry = prev_close

    near_candidates = [
        open_mid - atr * 0.35,
        prev_close - atr * 0.25,
        open_mid * 0.985,
        ma20_entry,
    ]
    near_candidates = [x for x in near_candidates if x and not np.isnan(x) and x > 0]
    chart_near_entry = float(np.median(near_candidates)) if near_candidates else open_mid * 0.985

    # 종목 변동성에 따라 예상시초가 대비 허용 괴리폭을 다르게 둔다.
    max_entry_gap_pct = min(0.065, max(0.018, atr_pct * 0.70 / 100))
    entry_floor = open_mid * (1 - max_entry_gap_pct)
    entry_ceiling = open_mid * 1.008
    adjusted_entry = min(entry_ceiling, max(entry_floor, chart_near_entry))

    # v9.8.0: 가장 가까운 강한 지지존을 진입 기준에 직접 연결
    support_zone = _best_trade_support_zone(sr, open_mid, atr, atr_pct)
    resistance_zone = None
    zone_entry = np.nan
    zone_stop = np.nan
    support_zone_label = "-"
    support_zone_low = np.nan
    support_zone_high = np.nan
    support_zone_score = np.nan
    support_zone_horizon = "-"

    if support_zone:
        support_zone_low = safe_float(support_zone.get("zone_low"), np.nan)
        support_zone_high = safe_float(support_zone.get("zone_high"), np.nan)
        support_zone_score = safe_float(support_zone.get("score"), np.nan)
        support_zone_horizon = str(support_zone.get("horizon", "-"))
        support_zone_label = f"{support_zone_horizon} {support_zone.get('strength', '')} 지지존"
        if not np.isnan(support_zone_high) and support_zone_high > 0:
            # 존 상단~중심 사이를 실전 진입 근사치로 사용
            zone_center = (support_zone_low + support_zone_high) / 2 if not np.isnan(support_zone_low) else support_zone_high
            zone_entry = min(open_mid * 0.998, max(zone_center, support_zone_high - atr * 0.08))
            adjusted_entry = min(entry_ceiling, max(entry_floor, zone_entry))

    # 갭상승/저항 돌파 상황은 선매수 대신 돌파 확인선 근처를 남겨둔다.
    if chase_risk or "돌파" in primary_action:
        adjusted_entry = min(max(adjusted_entry, open_mid * 0.995), max(open_mid * 1.008, sr["resistance1"] * 1.002))

    if support_zone and not np.isnan(zone_entry):
        entry_basis = f"지지존 기반: {support_zone_label} 상단/중심 근사 / 예상시초가 기준 {max_entry_gap_pct*100:.1f}% 이내"
    elif abs(technical_entry / max(open_mid, 1e-9) - 1) >= max_entry_gap_pct * 1.20:
        entry_basis = f"실전근사: 예상시초가 기준 {max_entry_gap_pct*100:.1f}% 이내 / ATR 눌림 / 기존 기술선은 보수대기선"
    else:
        entry_basis = f"차트근사: ATR 눌림 + 기존 기술선 / 예상시초가 기준 {max_entry_gap_pct*100:.1f}% 이내"

    preferred_entry = adjusted_entry

    min_stop_gap = min(0.075, max(0.012, atr_pct * 0.55 / 100))
    max_stop_gap = min(0.16, max(0.045, atr_pct * 1.45 / 100))
    if support_zone and not np.isnan(support_zone_low) and support_zone_low > 0:
        zone_stop = support_zone_low - atr * 0.15
        stop_candidate = min(zone_stop, preferred_entry - atr * 0.45)
    else:
        stop_candidate = min(sr["support1"] * 0.992, preferred_entry - atr * 0.65)

    stop_floor_by_gap = preferred_entry * (1 - max_stop_gap)
    stop_ceiling_by_gap = preferred_entry * (1 - min_stop_gap)
    stop_loss = max(0.0, min(stop_ceiling_by_gap, max(stop_floor_by_gap, stop_candidate)))
    if stop_loss >= preferred_entry:
        stop_loss = preferred_entry * (1 - min_stop_gap)

    risk = max(preferred_entry - stop_loss, atr * 0.35)

    resistance_zone = _best_trade_resistance_zone(sr, preferred_entry)
    resistance_zone_low = safe_float((resistance_zone or {}).get("zone_low"), np.nan)
    resistance_zone_high = safe_float((resistance_zone or {}).get("zone_high"), np.nan)
    resistance_zone_score = safe_float((resistance_zone or {}).get("score"), np.nan)
    resistance_zone_horizon = str((resistance_zone or {}).get("horizon", "-"))
    resistance_zone_label = f"{resistance_zone_horizon} {(resistance_zone or {}).get('strength', '')} 저항존" if resistance_zone else "-"

    # v9.7.2: 저항선/패턴 목표가가 과도하게 멀리 잡히면 손익비가 비정상적으로 커질 수 있어 상한을 둔다.
    if resistance_zone and not np.isnan(resistance_zone_low) and resistance_zone_low > preferred_entry:
        raw_take_profit1 = max(preferred_entry + risk * 1.45, resistance_zone_low)
        raw_take_profit2 = max(preferred_entry + risk * 2.15, resistance_zone_high if not np.isnan(resistance_zone_high) else sr["resistance2"])
    else:
        raw_take_profit1 = max(sr["resistance1"], preferred_entry + risk * 1.5)
        raw_take_profit2 = max(sr["resistance2"], preferred_entry + risk * 2.3)
    target_cap_pct = min(0.28, max(0.06, atr_pct * 2.8 / 100))
    target2_cap_pct = min(0.45, max(0.10, atr_pct * 4.2 / 100))
    take_profit1 = min(raw_take_profit1, preferred_entry * (1 + target_cap_pct))
    take_profit2 = min(raw_take_profit2, preferred_entry * (1 + target2_cap_pct))
    if take_profit2 < take_profit1:
        take_profit2 = take_profit1
    sell_zone = max(close_high, take_profit1)

    # 매수 금지 필터
    no_buy_flags = []
    if not np.isnan(premarket_gap_pct) and premarket_gap_pct >= 5:
        no_buy_flags.append("프리마켓 +5% 이상 급등: 추격매수 금지")
    if rsi >= 75:
        no_buy_flags.append("RSI 75 이상 과열")
    if abs(open_mid - sr["resistance1"]) / max(open_mid, 1e-9) <= 0.01:
        no_buy_flags.append("시초 예상가가 1차 저항선 1% 이내")
    if event_context.get("risk_mult", 1) >= 1.55:
        no_buy_flags.append("대형 이벤트일: 변동성 확대")
    if earnings_phase and earnings_phase != "none":
        _earn_rule = str(event_context.get("earnings_prediction_rule", "실적 이벤트: 예측범위 확대/추격주의"))
        no_buy_flags.append(_earn_rule[:90])
    rr1 = (take_profit1 - preferred_entry) / risk if risk > 0 else 0

    entry_gap_open_pct = (preferred_entry / open_mid - 1) * 100 if open_mid else np.nan
    stop_gap_pct = (preferred_entry - stop_loss) / max(preferred_entry, 1e-9) * 100
    tp1_gap_pct = (take_profit1 / max(preferred_entry, 1e-9) - 1) * 100

    if rr1 < 1.5:
        no_buy_flags.append(f"손익비 부족: 1차 R:R {rr1:.2f}")
    if not np.isnan(entry_gap_open_pct) and abs(entry_gap_open_pct) >= 6.0:
        no_buy_flags.append(f"우선진입가가 예상시초가와 {entry_gap_open_pct:+.1f}% 괴리: 즉시매수 금지")
    if stop_gap_pct <= 0.45:
        no_buy_flags.append(f"손절폭 과소({stop_gap_pct:.2f}%): 손익비 왜곡 가능")
    if stop_gap_pct >= 18:
        no_buy_flags.append(f"손절폭 과대({stop_gap_pct:.1f}%): 비중 축소 필요")
    if tp1_gap_pct >= 25:
        no_buy_flags.append(f"1차익절가 과대({tp1_gap_pct:.1f}%): 목표가 보수 확인")

    try:
        w_lab, _wsc = _swing_weekly_trend(df)
    except Exception:
        w_lab = ""
    lp_close = safe_float(last.get("Close"), np.nan)
    cur_px = float(premarket_price) if premarket_price and premarket_price > 0 else (float(lp_close) if not np.isnan(lp_close) else np.nan)
    _rule_merge = evaluate_no_buy_rules(
        market=market,
        rr=float(rr1),
        weekly_trend_label=str(w_lab or ""),
        current_price=cur_px,
        preferred_entry=float(preferred_entry) if not np.isnan(safe_float(preferred_entry, np.nan)) else np.nan,
        chase_gap_pct=5.0,
        bad_news="-",
        event_context=event_context,
        data_fetch_ok=True,
        atr_calc_ok=bool(not np.isnan(atr) and atr > 0),
        volume_ok=True,
        gap_overheated=(rsi >= 75),
        expectancy_n=0,
        expectancy_avg=0.0,
        already_flagged=[str(x) for x in no_buy_flags],
        rr_minimum=1.5,
    )
    for _msg in _rule_merge.get("reasons", []):
        if _msg and _msg not in no_buy_flags:
            no_buy_flags.append(_msg)

    return {
        "prev_close": prev_close,
        "atr": atr,
        "atr_pct": atr_pct,
        "technical_score_for_prediction": tech_score,
        "raw_model_gap_pct": raw_model_gap_pct,
        "model_gap_pct": model_gap_pct,
        "premarket_gap_pct": premarket_gap_pct,
        "pred_open_low": open_low,
        "pred_open_mid": open_mid,
        "pred_open_high": open_high,
        "pred_close_low": close_low,
        "pred_close_mid": close_mid,
        "pred_close_high": close_high,
        "uncertainty_pct": uncertainty_pct,
        "atr_range_multiplier": atr_range_multiplier,
        "range_quality_label": range_quality_label,
        "atr_calibration_reason": calibration_reason,
        "pred_open_range_pct": (open_high - open_low) / max(open_mid, 1e-9) * 100,
        "pred_close_range_pct": (close_high - close_low) / max(close_mid, 1e-9) * 100,
        "event_risk_mult": event_mult,
        "confidence_score": int(confidence_score),
        "confidence_label": (confidence or {}).get("label", "보통"),
        "primary_action": primary_action,
        "preferred_entry": preferred_entry,
        "conservative_entry": conservative_entry,
        "technical_entry": technical_entry,
        "entry_basis": entry_basis,
        "support_zone_low": support_zone_low,
        "support_zone_high": support_zone_high,
        "support_zone_score": support_zone_score,
        "support_zone_label": support_zone_label,
        "support_zone_horizon": support_zone_horizon,
        "resistance_zone_low": resistance_zone_low,
        "resistance_zone_high": resistance_zone_high,
        "resistance_zone_score": resistance_zone_score,
        "resistance_zone_label": resistance_zone_label,
        "resistance_zone_horizon": resistance_zone_horizon,
        "pullback_buy": pullback_buy,
        "breakout_buy": breakout_buy,
        "stop_loss": stop_loss,
        "take_profit1": take_profit1,
        "take_profit2": take_profit2,
        "sell_zone": sell_zone,
        "rr1": rr1,
        "no_buy_flags": no_buy_flags,
    }


def prediction_to_row(
    ticker: str,
    market: str,
    target_date: date,
    df: pd.DataFrame,
    sr: dict[str, float],
    trade_score: dict[str, Any],
    prediction: dict[str, Any],
    inputs: dict[str, Any],
) -> dict[str, Any]:
    last = df.iloc[-1]
    out = {
        "prediction_id": str(uuid.uuid4())[:8],
        "created_at": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S"),
        "target_date": str(target_date),
        "session_type": inputs.get("session_type", ""),
        "session_label": inputs.get("session_label", ""),
        "run_time_kst": inputs.get("run_time_kst", ""),
        "run_time_et": inputs.get("run_time_et", ""),
        "target_rule": inputs.get("target_rule", ""),
        "market": market,
        "ticker": normalize_ticker(ticker, market),
        "symbol": normalize_ticker(ticker, market),
        "data_date": str(pd.to_datetime(last["Date"]).date()),
        "prev_close": prediction["prev_close"],
        "market_score": inputs["market_score"],
        "sector_score": inputs["sector_score"],
        "news_score": inputs["news_score"],
        "auto_market_score": inputs.get("auto_market_score", 0),
        "auto_sector_score": inputs.get("auto_sector_score", 0),
        "manual_market_adj": inputs.get("manual_market_adj", 0),
        "manual_sector_adj": inputs.get("manual_sector_adj", 0),
        "sector": inputs.get("sector", ""),
        "event_label": inputs.get("event_label", ""),
        "event_learning_bucket": inputs.get("event_learning_bucket", infer_event_learning_bucket_v9988(row=inputs, market=market)),
        "sensitivity_group": inputs.get("sensitivity_group", ""),
        "sensitivity_label": inputs.get("sensitivity_label", ""),
        "sensitivity_reason": inputs.get("sensitivity_reason", ""),
        "news_impact_bucket": inputs.get("news_impact_bucket", inputs.get("event_learning_bucket", "")),
        "news_impact_score": inputs.get("news_impact_score", inputs.get("auto_news_score", inputs.get("news_score", 0))),
        "news_impact_label": inputs.get("news_impact_label", ""),
        "news_impact_reason": inputs.get("news_impact_reason", ""),
        "earnings_event_phase": inputs.get("earnings_event_phase", ""),
        "earnings_event_timing": inputs.get("earnings_event_timing", ""),
        "earnings_risk_mult": inputs.get("earnings_risk_mult", np.nan),
        "earnings_direction_score": inputs.get("earnings_direction_score", np.nan),
        "earnings_prediction_rule": inputs.get("earnings_prediction_rule", ""),
        "earnings_snapshot_text": inputs.get("earnings_snapshot_text", ""),
        "post_prediction_event_policy": inputs.get("post_prediction_event_policy", "장전 예측은 고정, 장중 사건은 근거/복기 사유로만 기록"),
        "quality_score": inputs.get("quality_score", np.nan),
        "quality_label": inputs.get("quality_label", ""),
        "fundamental_score": inputs.get("fundamental_score", np.nan),
        "fundamental_label": inputs.get("fundamental_label", ""),
        "fundamental_summary": inputs.get("fundamental_summary", ""),
        "fundamental_warnings": inputs.get("fundamental_warnings", ""),
        "supply_score": inputs.get("supply_score", np.nan),
        "supply_label": inputs.get("supply_label", ""),
        "supply_summary": inputs.get("supply_summary", ""),
        "sector_cycle_score": inputs.get("sector_cycle_score", np.nan),
        "sector_cycle_label": inputs.get("sector_cycle_label", ""),
        "quality_summary": inputs.get("quality_summary", ""),
        "event_risk_mult": prediction.get("event_risk_mult", 1.0),
        "confidence_score": prediction.get("confidence_score", np.nan),
        "confidence_label": prediction.get("confidence_label", ""),
        "atr_range_multiplier": prediction.get("atr_range_multiplier", 1.0),
        "range_quality_label": prediction.get("range_quality_label", ""),
        "atr_calibration_reason": prediction.get("atr_calibration_reason", ""),
        "learning_adjustment_applied": prediction.get("learning_adjustment_applied", inputs.get("learning_adjustment_applied", 0)),
        "learning_adjustment_score": inputs.get("learning_adjustment_score", prediction.get("confidence_score", np.nan)),
        "learning_adjustment_reason": prediction.get("learning_adjustment_reason", inputs.get("learning_adjustment_reason", "")),
        "learning_entry_offset_pct": prediction.get("learning_entry_offset_pct", inputs.get("learning_entry_offset_pct", 0.0)),
        "learning_range_multiplier": prediction.get("learning_range_multiplier", inputs.get("learning_range_multiplier", 1.0)),
        "learning_quantity_factor": prediction.get("learning_quantity_factor", inputs.get("learning_quantity_factor", 1.0)),
        "learning_guard_reason": prediction.get("learning_guard_reason", inputs.get("learning_guard_reason", "")),
        "event_learning_sample_n": inputs.get("event_learning_sample_n", np.nan),
        "event_learning_used": inputs.get("event_learning_used", 0),
        "pred_open_range_pct": prediction.get("pred_open_range_pct", np.nan),
        "pred_close_range_pct": prediction.get("pred_close_range_pct", np.nan),
        "premarket_price": inputs.get("premarket_price") or np.nan,
        "premarket_gap_pct": prediction.get("premarket_gap_pct", np.nan),
        "premarket_weight": inputs.get("premarket_weight", 0),
        "premarket_quality_score": inputs.get("premarket_quality_score", np.nan),
        "premarket_volume_ratio": inputs.get("premarket_volume_ratio", np.nan),
        "premarket_quality_label": inputs.get("premarket_quality_label", ""),
        "adjustment_applied": prediction.get("adjustment_applied", 0),
        "adjustment_reason": prediction.get("adjustment_reason", "누적 데이터 부족"),
        "open_bias_adjustment_pct": prediction.get("open_bias_adjustment_pct", inputs.get("open_bias_adjustment_pct", 0)),
        "close_bias_adjustment_pct": prediction.get("close_bias_adjustment_pct", inputs.get("close_bias_adjustment_pct", 0)),
        "atr_multiplier_adjustment": prediction.get("atr_multiplier_adjustment", 0),
        "entry_adjustment_pct": prediction.get("entry_adjustment_pct", 0),
        "stop_adjustment_pct": prediction.get("stop_adjustment_pct", 0),
        "tp_adjustment_pct": prediction.get("tp_adjustment_pct", 0),
        "confidence_penalty": prediction.get("confidence_penalty", 0),
        "decision_downgrade": prediction.get("decision_downgrade", 0),
        "final_decision_before_adjustment": prediction.get("final_decision_before_adjustment", prediction.get("primary_action", "")),
        "final_decision_after_adjustment": prediction.get("final_decision_after_adjustment", prediction.get("primary_action", "")),
        "confidence_score_before_adjustment": prediction.get("confidence_score_before_adjustment", prediction.get("confidence_score", np.nan)),
        "confidence_score_after_adjustment": prediction.get("confidence_score_after_adjustment", prediction.get("confidence_score", np.nan)),
        "market_regime": prediction.get("market_regime", "데이터 부족"),
        "market_risk_score": prediction.get("market_risk_score", 50),
        "market_filter_applied": prediction.get("market_filter_applied", 0),
        "market_filter_reason": prediction.get("market_filter_reason", "시장 데이터 부족으로 필터 미적용"),
        "final_decision_before_market_filter": prediction.get("final_decision_before_market_filter", prediction.get("primary_action", "")),
        "final_decision_after_market_filter": prediction.get("final_decision_after_market_filter", prediction.get("primary_action", "")),
        "confidence_score_before_market_filter": prediction.get("confidence_score_before_market_filter", prediction.get("confidence_score", np.nan)),
        "confidence_score_after_market_filter": prediction.get("confidence_score_after_market_filter", prediction.get("confidence_score", np.nan)),
        "no_buy_market_reason": prediction.get("no_buy_market_reason", ""),
        "no_buy_score": prediction.get("no_buy_score", np.nan),
        "no_buy_level": prediction.get("no_buy_level", ""),
        "no_buy_reasons": prediction.get("no_buy_reasons", ""),
        "no_buy_filter_applied": prediction.get("no_buy_filter_applied", 0),
        "final_decision_before_no_buy_filter": prediction.get("final_decision_before_no_buy_filter", prediction.get("primary_action", "")),
        "final_decision_after_no_buy_filter": prediction.get("final_decision_after_no_buy_filter", prediction.get("primary_action", "")),
        "confidence_score_before_no_buy_filter": prediction.get("confidence_score_before_no_buy_filter", prediction.get("confidence_score", np.nan)),
        "confidence_score_after_no_buy_filter": prediction.get("confidence_score_after_no_buy_filter", prediction.get("confidence_score", np.nan)),
        "model_gap_pct": prediction["model_gap_pct"],
        "pred_open_low": prediction["pred_open_low"],
        "pred_open_mid": prediction["pred_open_mid"],
        "pred_open_high": prediction["pred_open_high"],
        "pred_close_low": prediction["pred_close_low"],
        "pred_close_mid": prediction["pred_close_mid"],
        "pred_close_high": prediction["pred_close_high"],
        "support1": sr["support1"],
        "support2": sr["support2"],
        "resistance1": sr["resistance1"],
        "resistance2": sr["resistance2"],
        "preferred_entry": prediction["preferred_entry"],
        "conservative_entry": prediction.get("conservative_entry", np.nan),
        "technical_entry": prediction.get("technical_entry", np.nan),
        "entry_basis": prediction.get("entry_basis", ""),
        "support_zone_low": prediction.get("support_zone_low", np.nan),
        "support_zone_high": prediction.get("support_zone_high", np.nan),
        "support_zone_score": prediction.get("support_zone_score", np.nan),
        "support_zone_label": prediction.get("support_zone_label", ""),
        "support_zone_horizon": prediction.get("support_zone_horizon", ""),
        "resistance_zone_low": prediction.get("resistance_zone_low", np.nan),
        "resistance_zone_high": prediction.get("resistance_zone_high", np.nan),
        "resistance_zone_score": prediction.get("resistance_zone_score", np.nan),
        "resistance_zone_label": prediction.get("resistance_zone_label", ""),
        "resistance_zone_horizon": prediction.get("resistance_zone_horizon", ""),
        "pullback_buy": prediction["pullback_buy"],
        "breakout_buy": prediction["breakout_buy"],
        "stop_loss": prediction["stop_loss"],
        "take_profit1": prediction["take_profit1"],
        "take_profit2": prediction["take_profit2"],
        "rr1": prediction.get("rr1", np.nan),
        "no_buy_flags": prediction.get("no_buy_flags", "") if isinstance(prediction.get("no_buy_flags", ""), str) else " | ".join(prediction.get("no_buy_flags", [])),
        "technical_score": trade_score["score"],
        "technical_verdict": trade_score["verdict"],
        "primary_action": prediction["primary_action"],
        "memo": inputs.get("memo", ""),
        "failure_tags": inputs.get("failure_tags", ""),
        "prediction_source": inputs.get("prediction_source", "app_model_v9956"),
        "price_source": inputs.get("price_source", "KIS Open API 우선" if market == "한국주식" else "Finnhub/yfinance"),
        "chart_source": inputs.get("chart_source", "KIS Open API 우선" if market == "한국주식" else "yfinance"),
        "news_source": inputs.get("news_source", "뉴스 자동수집"),
        "comparison_rule": inputs.get("comparison_rule", "우선진입가 체결 가정 · 손절/익절 동시터치 시 손절 우선"),
        "snapshot_fixed_at": inputs.get("snapshot_fixed_at", datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S KST")),
        "kis_price_ok": inputs.get("kis_price_ok", np.nan),
        "kis_chart_ok": inputs.get("kis_chart_ok", np.nan),
        "dart_checked": inputs.get("dart_checked", "DART 보조" if market == "한국주식" else "해당없음"),
        "news_checked": inputs.get("news_checked", np.nan),
        "prediction_quality_score": inputs.get("prediction_quality_score", np.nan),
        "prediction_quality_grade": inputs.get("prediction_quality_grade", ""),
        "prediction_quality_reason": inputs.get("prediction_quality_reason", ""),
        "actual_source": "",
        "actual_date": "",
        "actual_open": np.nan,
        "actual_high": np.nan,
        "actual_low": np.nan,
        "actual_close": np.nan,
        "actual_volume": np.nan,
        "actual_quality_flag": "",
        "actual_quality_note": "",
        "open_error_pct": np.nan,
        "close_error_pct": np.nan,
        "open_abs_error_pct": np.nan,
        "close_abs_error_pct": np.nan,
        "open_in_range": np.nan,
        "close_in_range": np.nan,
        "direction_hit": np.nan,
        "entry_touched": np.nan,
        "stop_touched": np.nan,
        "tp1_touched": np.nan,
        "tp2_touched": np.nan,
        "virtual_entry_filled": np.nan,
        "virtual_exit_price": np.nan,
        "virtual_result_label": "",
        "virtual_return_pct": np.nan,
        "virtual_net_return_pct": np.nan,
        "virtual_r_multiple": np.nan,
        "virtual_rule": "",
        "prediction_error_reason": "",
    }
    if market == "한국주식":
        code6 = _kr_symbol_key(normalize_ticker(ticker, market))
        dlast = pd.to_datetime(last.get("Date"), errors="coerce")
        bs_date = str(dlast.date()) if pd.notna(dlast) else ""
        bo = safe_float(last.get("Open"), np.nan)
        bh = safe_float(last.get("High"), np.nan)
        bl = safe_float(last.get("Low"), np.nan)
        bc = safe_float(last.get("Close"), np.nan)
        bv = safe_float(last.get("Volume"), np.nan)
        cp_at = inputs.get("current_price_at_prediction", np.nan)
        bv_ok, bi_issue = validate_kr_prediction_basis_fields(
            target_date, bs_date, bo, bh, bl, bc, bv, cp_at,
        )
        nb_flags = prediction.get("no_buy_flags", []) or []
        flags_txt = " | ".join([str(x) for x in nb_flags]) if nb_flags else ""
        out.update({
            "stock_code": code6,
            "stock_name": korean_name_from_symbol(code6, ticker),
            "basis_ohlc_date": bs_date,
            "basis_open": bo,
            "basis_high": bh,
            "basis_low": bl,
            "basis_close": bc,
            "basis_volume": bv,
            "basis_source": str(inputs.get("chart_source", inputs.get("price_source", "일봉(정규장)"))),
            "current_price_at_prediction": cp_at,
            "current_price_source": str(inputs.get("current_price_source", "")),
            "invalidation_condition": flags_txt,
            "final_judgment": str(prediction.get("primary_action", "") or ""),
            "suggested_action": str(prediction.get("primary_action", "") or ""),
            "risk_reward_ratio": prediction.get("rr1", np.nan),
            "reason": str(prediction.get("entry_basis", "") or ""),
            "buy_reason": str(prediction.get("entry_basis", "") or ""),
            "risk_reason": flags_txt,
            "data_status": str(inputs.get("prediction_quality_grade", "") or "saved"),
            "basis_ohlc_valid": bv_ok,
            "basis_ohlc_issue": bi_issue,
            "prediction_freshness": "TODAY_OK" if bv_ok == "OK" else "DATA_MISSING",
            "prediction_freshness_issue": "" if bv_ok == "OK" else bi_issue,
        })
    try:
        from core.risk_decision_engine import (
            final_risk_decision_engine,
            news_quality_filter,
            overheating_filter,
            rr_filter,
        )

        close_px = safe_float(last.get("Close"), np.nan)
        open_px = safe_float(last.get("Open"), np.nan)
        high_px = safe_float(last.get("High"), np.nan)
        low_px = safe_float(last.get("Low"), np.nan)
        prev_close_px = safe_float(prediction.get("prev_close"), np.nan)
        ma10 = safe_float(last.get("MA10", last.get("MA5")), np.nan)
        ma20 = safe_float(last.get("MA20"), np.nan)
        rsi = safe_float(last.get("RSI"), np.nan)
        volume = safe_float(last.get("Volume"), np.nan)
        avg_volume20 = safe_float(pd.to_numeric(df.get("Volume"), errors="coerce").tail(20).mean(), np.nan) if "Volume" in df.columns else np.nan
        volume_ratio = volume / avg_volume20 if not np.isnan(volume) and not np.isnan(avg_volume20) and avg_volume20 > 0 else np.nan
        candle_range = high_px - low_px if not np.isnan(high_px) and not np.isnan(low_px) else np.nan
        upper_shadow_pct = (
            (high_px - max(open_px, close_px)) / candle_range * 100
            if not np.isnan(candle_range) and candle_range > 0 and not np.isnan(open_px) and not np.isnan(close_px)
            else np.nan
        )
        gap_up_pct = (
            (open_px / prev_close_px - 1) * 100
            if not np.isnan(open_px) and not np.isnan(prev_close_px) and prev_close_px > 0
            else safe_float(prediction.get("premarket_gap_pct"), np.nan)
        )
        body_pct = (
            abs(close_px - open_px) / max(abs(close_px), 1e-9) * 100
            if not np.isnan(open_px) and not np.isnan(close_px)
            else np.nan
        )
        consecutive_rise_days = 0
        try:
            closes = pd.to_numeric(df.get("Close"), errors="coerce").dropna().tail(8).tolist()
            for i in range(len(closes) - 1, 0, -1):
                if closes[i] > closes[i - 1]:
                    consecutive_rise_days += 1
                else:
                    break
        except Exception:
            consecutive_rise_days = 0

        overheat_result = overheating_filter(
            {
                "close": close_px,
                "ma10": ma10,
                "ma20": ma20,
                "rsi": rsi,
                "volume_ratio": volume_ratio,
                "upper_shadow_pct": upper_shadow_pct,
                "gap_up_pct": gap_up_pct,
                "consecutive_rise_days": consecutive_rise_days,
                "candle_body_pct": body_pct,
            }
        )
        news_title = str(inputs.get("news_title", inputs.get("event_label", "")) or "")
        news_summary = " / ".join(
            str(x or "")
            for x in [
                inputs.get("news_impact_reason", ""),
                inputs.get("earnings_snapshot_text", ""),
                inputs.get("fundamental_summary", ""),
            ]
            if str(x or "").strip()
        )
        disclosure_text = f"{out.get('dart_checked', '')} {out.get('sec_checked', '')} {out.get('disclosure_confirmed', '')}"
        linked_disclosure = bool(disclosure_text.strip()) and not any(
            bad in disclosure_text for bad in ["해당없음", "없음", "미해당", "not applicable", "N/A"]
        )
        news_result = news_quality_filter(
            {
                "news_title": news_title,
                "news_summary": news_summary,
                "linked_disclosure": linked_disclosure,
                "price_runup_before_news_pct": max(0.0, gap_up_pct if not np.isnan(gap_up_pct) else 0.0),
                "volume_confirmed": bool(not np.isnan(volume_ratio) and volume_ratio >= 1.0),
                "source": inputs.get("news_source", ""),
            }
        )
        rr_result = rr_filter(
            {
                "entry_price": out.get("preferred_entry"),
                "stop_loss": out.get("stop_loss"),
                "take_profit1": out.get("take_profit1"),
            }
        )
        missing_items = []
        for label, value in [
            ("과열", overheat_result.get("overheat_reasons", [])),
            ("손익비", rr_result.get("rr_pass")),
            ("뉴스", news_result.get("news_grade")),
        ]:
            if label == "과열" and any("데이터 부족" in str(x) for x in value):
                missing_items.append(label)
            elif label == "손익비" and not bool(value):
                missing_items.append(label)
            elif label == "뉴스" and str(value) == "Unknown":
                missing_items.append(label)
        market_risk_score = safe_float(out.get("market_risk_score"), np.nan)
        market_risk_level = "매우 높음" if not np.isnan(market_risk_score) and market_risk_score >= 80 else ""
        risk_result = final_risk_decision_engine(
            {
                **out,
                "base_decision": out.get("final_decision_after_no_buy_filter") or out.get("primary_action"),
                "confidence_score": out.get("confidence_score_after_no_buy_filter", out.get("confidence_score")),
                "market_risk_level": market_risk_level,
                "market_force_downgrade": bool(not np.isnan(market_risk_score) and market_risk_score >= 80),
                "overheat_result": overheat_result,
                "rr_result": rr_result,
                "news_result": news_result,
                "data_missing_items": missing_items,
                "current_price": close_px,
                "resistance_near": bool(
                    not np.isnan(close_px)
                    and not np.isnan(safe_float(out.get("resistance1"), np.nan))
                    and close_px >= safe_float(out.get("resistance1"), np.nan) * 0.98
                ),
                "support_holding": bool(not np.isnan(close_px) and not np.isnan(safe_float(out.get("support1"), np.nan)) and close_px >= safe_float(out.get("support1"), np.nan)),
            }
        )
        out.update(
            {
                "risk_final_decision": risk_result.get("risk_final_decision", "관망 우위"),
                "risk_confidence_score": risk_result.get("risk_confidence_score", 0),
                "risk_decision_reasons": " / ".join(map(str, risk_result.get("risk_decision_reasons", []))),
                "risk_warning_flags": " / ".join(map(str, risk_result.get("risk_warning_flags", []))),
                "risk_missing_items": " / ".join(map(str, risk_result.get("missing_items", []))),
                "overheat_level": overheat_result.get("overheat_level", ""),
                "overheat_score": overheat_result.get("overheat_score", ""),
                "overheat_reasons": " / ".join(map(str, overheat_result.get("overheat_reasons", []))),
                "chase_risk": int(bool(overheat_result.get("chase_risk"))),
                "rr": rr_result.get("rr", ""),
                "rr_level": rr_result.get("rr_level", ""),
                "rr_pass": int(bool(rr_result.get("rr_pass"))),
                "news_grade": news_result.get("news_grade", "Unknown"),
                "news_filter_score": news_result.get("news_score", ""),
                "news_filter_reasons": " / ".join(map(str, news_result.get("news_reasons", []))),
                "sell_the_news_risk": int(bool(news_result.get("sell_the_news_risk"))),
            }
        )
    except Exception as risk_ex:
        out.update(
            {
                "risk_final_decision": "관망 우위",
                "risk_confidence_score": 0,
                "risk_decision_reasons": f"리스크 엔진 예외로 보수 판단: {risk_ex}",
                "risk_warning_flags": "RISK_ENGINE_ERROR",
                "risk_missing_items": "risk_engine",
                "overheat_level": "",
                "overheat_reasons": "",
                "chase_risk": 0,
                "rr": "",
                "rr_level": "",
                "rr_pass": 0,
                "news_grade": "Unknown",
                "sell_the_news_risk": 0,
            }
        )
    return out


@st.cache_data(ttl=45, show_spinner=False)
def _load_prediction_log_cached_v9975(path_str: str, mtime_ns: int, file_size: int) -> pd.DataFrame:
    path = Path(path_str)
    df = pd.read_csv(path)
    df = ensure_object_columns(df, TEXT_LOG_COLUMNS)
    df = normalize_us_tickers_in_log(df)
    df = normalize_us_ticker_fields_in_df(df, market_aware=True)
    return df


def load_prediction_log() -> pd.DataFrame:
    if not PREDICTION_FILE.exists():
        return pd.DataFrame()
    try:
        stat = PREDICTION_FILE.stat()
        return _load_prediction_log_cached_v9975(str(PREDICTION_FILE), int(stat.st_mtime_ns), int(stat.st_size))
    except Exception:
        return pd.DataFrame()


def enrich_prediction_file_with_review_safely(path: Path = PREDICTION_FILE) -> None:
    """Keep review-learning columns attached after prediction saves without changing prediction logic."""
    try:
        if not path.exists() or path.stat().st_size == 0:
            return
        from core.review_learning_engine import enrich_predictions_with_review

        df = pd.read_csv(path, dtype=str, low_memory=False).fillna("")
        if df.empty:
            return
        enriched = enrich_predictions_with_review(df)
        review_cols = {
            "prediction_result",
            "max_profit_pct",
            "max_drawdown_pct",
            "entry_touched",
            "tp1_touched",
            "tp2_touched",
            "stop_touched",
            "decision_success",
            "failure_reason",
            "review_tags",
        }
        if review_cols.intersection(enriched.columns):
            enriched.to_csv(path, index=False, encoding="utf-8-sig")
    except Exception as exc:
        try:
            log_app_event("review_learning", "warning", f"prediction review enrichment skipped: {exc}")
        except Exception:
            pass


def save_prediction_row(row: dict[str, Any], dedupe: bool = True, upsert: bool = False) -> bool:
    """예측 1건 저장.

    - 기본값(dedupe=True, upsert=False): 같은 target_date+ticker+market이면 중복 저장하지 않음.
    - upsert=True: 같은 target_date+ticker+market 기록이 있으면 새로 추가하지 않고 예측 관련 컬럼만 갱신.
      실제 결과(actual_*, error_*, touched 등)는 이미 값이 있으면 보존합니다.

    Returns True if inserted or updated, False if skipped.
    """
    # 신규 저장부터 미장 종목명은 무조건 티커로 저장
    if is_us_like_market(row.get("market", "미국주식")):
        row = dict(row)
        row["ticker"] = display_symbol(row.get("ticker", ""), "미국주식", row.get("종목", ""))
        if "종목" in row:
            row["종목"] = display_symbol(row.get("ticker", ""), "미국주식", row.get("종목", ""))
        if "name" in row:
            row["name"] = row["ticker"]

    df = load_prediction_log()
    key_cols = ["target_date", "ticker", "market"]
    has_key = (not df.empty) and all(c in df.columns for c in key_cols)

    if dedupe and has_key:
        mask = (
            df["target_date"].astype(str).eq(str(row.get("target_date")))
            & df["ticker"].astype(str).str.upper().eq(str(row.get("ticker", "")).upper())
            & df["market"].astype(str).eq(str(row.get("market", "미국주식")))
        )
        if mask.any():
            if not upsert:
                return False

            # 같은 날짜/종목 예측은 중복으로 늘리지 않고 최신 계산값으로 갱신한다.
            idx = df[mask].index[-1]
            protected_prefixes = ("actual_",)
            protected_cols = {
                "actual_date", "open_error_pct", "close_error_pct", "open_abs_error_pct",
                "close_abs_error_pct", "open_in_range", "close_in_range", "direction_hit",
                "entry_touched", "stop_touched", "tp1_touched", "tp2_touched",
                "actual_source", "virtual_entry_filled", "virtual_exit_price", "virtual_result_label",
                "virtual_return_pct", "virtual_net_return_pct", "virtual_r_multiple", "virtual_rule",
                "prediction_error_reason",
                "open_range_width_pct", "close_range_width_pct", "open_band_coverage", "close_band_coverage",
                "open_range_diagnosis", "close_range_diagnosis",
            }
            for k, v in row.items():
                if k not in df.columns:
                    df[k] = np.nan
                # 이미 실제 결과가 채워진 컬럼은 보존
                if k in protected_cols or any(str(k).startswith(pref) for pref in protected_prefixes):
                    current = df.loc[idx, k] if k in df.columns else np.nan
                    if pd.notna(current) and str(current).strip() != "":
                        continue
                if isinstance(v, str):
                    df[k] = df[k].astype("object")
                df.loc[idx, k] = v
            df.loc[idx, "is_duplicate"] = False
            df.loc[idx, "memo"] = str(row.get("memo", "")) + " · upsert 갱신"
            df.to_csv(PREDICTION_FILE, index=False, encoding="utf-8-sig")
            enrich_prediction_file_with_review_safely(PREDICTION_FILE)
            return True

    new_row = pd.DataFrame([row])
    df = pd.concat([df, new_row], ignore_index=True)
    df.to_csv(PREDICTION_FILE, index=False, encoding="utf-8-sig")
    enrich_prediction_file_with_review_safely(PREDICTION_FILE)
    return True


def count_prediction_rows(market: str, target_date: date | str | None = None) -> dict[str, int]:
    df = load_prediction_log()
    if df.empty:
        return {"total": 0, "market": 0, "target": 0, "open_target": 0}
    total = int(len(df))
    mdf = df[df.get("market", "").astype(str).eq(str(market))].copy() if "market" in df.columns else pd.DataFrame()
    target_count = 0
    open_target = 0
    if target_date is not None and not mdf.empty and "target_date" in mdf.columns:
        tdf = mdf[mdf["target_date"].astype(str).eq(str(target_date))]
        target_count = int(len(tdf))
        if "actual_close" in tdf.columns:
            open_target = int(pd.to_numeric(tdf["actual_close"], errors="coerce").isna().sum())
        else:
            open_target = target_count
    return {"total": total, "market": int(len(mdf)), "target": target_count, "open_target": open_target}


def read_startup_sync_state() -> dict[str, Any]:
    try:
        if STARTUP_SYNC_STATE_FILE.exists():
            return json.loads(STARTUP_SYNC_STATE_FILE.read_text(encoding="utf-8"))
    except Exception:
        pass
    return {}


def write_startup_sync_state(state: dict[str, Any]) -> None:
    try:
        STARTUP_SYNC_STATE_FILE.write_text(json.dumps(state, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception:
        pass


def append_startup_sync_log(message: str) -> None:
    try:
        STARTUP_SYNC_LOG_FILE.parent.mkdir(exist_ok=True)
        with STARTUP_SYNC_LOG_FILE.open("a", encoding="utf-8") as f:
            f.write(f"[{datetime.now(KST).strftime('%Y-%m-%d %H:%M:%S KST')}] {message}\n")
    except Exception:
        pass


def ensure_object_columns(df: pd.DataFrame, cols: list[str]) -> pd.DataFrame:
    """문자열이 들어갈 수 있는 컬럼을 object 타입으로 강제해 pandas dtype 충돌을 방지."""
    for col in cols:
        if col in df.columns:
            df[col] = df[col].astype("object")
    return df


