def _column_hidden_in_operational(col: str) -> bool:
    """일반 운용 화면 표시 컬럼 필터."""
    name = str(col or "").strip()
    if not name:
        return True
    if name.startswith("raw_"):
        return True
    if name in USER_HIDDEN_RAW_COLUMNS or name in OPERATIONAL_HIDDEN_COLUMNS:
        return True
    low = name.lower()
    return any(part in low for part in OPERATIONAL_HIDDEN_NAME_PARTS)


def _filter_columns_for_screen(columns: list[str], df: pd.DataFrame | None = None) -> list[str]:
    """점검·복기가 아니면 운용용 컬럼만."""
    if _is_inspection_screen_area():
        if df is not None and not df.empty:
            return [c for c in columns if c in df.columns and not str(c).startswith("raw_")]
        return [c for c in columns if not str(c).startswith("raw_")]
    if df is not None and not df.empty:
        avail = set(df.columns)
        return [c for c in columns if c in avail and not _column_hidden_in_operational(c)]
    return [c for c in columns if not _column_hidden_in_operational(c)]

