def sanitize_user_title(text: Any) -> str:
    """사용자 화면 제목·메뉴명에서 이모지·동그라미 번호·구버전 태그를 제거."""
    s = str(text or "").strip()
    if not s:
        return ""
    for _ in range(8):
        prev = s
        s = _CIRCLED_NUM_TITLE_RE.sub("", s)
        s = _VERSION_IN_TITLE_RE.sub("", s).strip()
        for emo in _LEADING_TITLE_EMOJIS:
            if s.startswith(emo):
                s = s[len(emo):].lstrip()
                break
        s = re.sub(r"^\s*[\-–—·]\s*", "", s).strip()
        if s == prev:
            break
    return re.sub(r"\s{2,}", " ", s).strip()


def _graft_nav_show_page_title() -> bool:
    return bool(st.session_state.get("_graft_nav_show_page_title", True))


def _render_nav_page_title(title: str) -> None:
    if _graft_nav_show_page_title():
        st.markdown(f"### {sanitize_user_title(title)}")


def _render_inner_page_heading(title: str, *, as_subheader: bool = False) -> None:
    """graft 상단 제목이 있으면 동일 문구의 내부 제목은 생략."""
    if not _graft_nav_show_page_title():
        return
    clean = sanitize_user_title(title)
    if not clean:
        return
    if as_subheader:
        st.subheader(clean)
    else:
        st.markdown(f"### {clean}")


def render_grafted_nav_header(page_id: str, sub_label: str, nav_group: str) -> None:
    """사이드바에서 고른 화면의 본문 상단 제목(중복 방지)."""
    st.session_state["_graft_nav_show_page_title"] = False
    if page_id == "page_general_today" and not _is_admin_view_mode():
        return
    st.markdown(f"### {sanitize_user_title(sub_label)}")
    if _is_admin_view_mode():
        intro = NAV_PAGE_INTROS.get(page_id, "")
        if intro:
            st.caption(intro)


