def sanitize_display_symbols(display: pd.DataFrame) -> pd.DataFrame:
    """화면에 내보내기 직전 종목/티커 컬럼의 한글 미장 종목명을 티커로 강제 변환."""
    if display is None or display.empty:
        return display
    out = display.copy()

    # 컬럼명이 한글화되기 전/후 모두 처리
    for col in ["ticker", "티커", "symbol", "심볼", "종목"]:
        if col in out.columns:
            out[col] = out[col].apply(lambda x: display_symbol(x, "미국주식"))

    # 회사명 컬럼이 종목처럼 쓰이는 화면이 있어 미장 한글명만 티커로 치환
    for col in ["회사명", "name"]:
        if col in out.columns:
            out[col] = out[col].apply(lambda x: KOREAN_US_TICKER_MAP.get(str(x).strip(), x))

    return out


def normalize_final_judgment_display(value: Any, row: Any = None) -> str:
    """화면 최종 행동 문구를 5개 표준 문구로만 표시한다."""
    try:
        from core.standard_score_engine import FINAL_JUDGMENTS, normalize_final_judgment

        text = str(value or "").strip()
        if text in FINAL_JUDGMENTS:
            return text
        base_row = row if row is not None else {}
        score = safe_float(base_row.get("standard_total_score", base_row.get("total_score", base_row.get("score", 60))) if hasattr(base_row, "get") else 60, 60)
        return normalize_final_judgment(score, row=base_row)
    except Exception:
        text = str(value or "").strip()
        if any(k in text for k in ["손절", "이탈"]):
            return "손절 우선"
        if any(k in text for k in ["축소", "금지", "위험", "리스크"]):
            return "비중 축소 우선"
        if "돌파" in text:
            return "돌파 확인 후 접근"
        if any(k in text for k in ["눌림", "매수"]):
            return "눌림목 매수 가능"
        return "관망 우위"


def normalize_final_judgment_columns_for_display(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return df
    out = df.copy()
    final_cols = [
        "risk_final_decision",
        "final_decision", "final_judgment", "final_action", "action_label",
        "final_decision_after_no_buy_filter", "final_decision_after_market_filter",
        "final_decision_after_adjustment", "최종판단", "최종 판단", "실전최종판정",
        "카드최종판단", "오늘 행동", "오늘행동",
    ]
    for col in final_cols:
        if col in out.columns:
            out[col] = out.apply(lambda r: normalize_final_judgment_display(r.get(col), r), axis=1)
    return out


def to_korean_display(df: pd.DataFrame, compact: bool = True) -> pd.DataFrame:
    """화면 표시용으로만 컬럼명을 한글화한다. 실제 CSV 저장 컬럼은 영문 그대로 유지."""
    if df is None or df.empty:
        return df
    display = normalize_final_judgment_columns_for_display(df.copy())
    display = sanitize_display_symbols(display)
    display = display.rename(columns={c: KOREAN_COLUMN_MAP.get(c, c) for c in display.columns})
    display = sanitize_display_symbols(display)
    if compact:
        front = [c for c in PREDICTION_DISPLAY_PRIORITY if c in display.columns]
        rest = [c for c in display.columns if c not in front]
        display = display[front + rest]
    return display


def _user_display_value(value: Any) -> Any:
    """사용자 화면에서 원본 코드값이 그대로 보이지 않도록 최소 변환한다."""
    if isinstance(value, (bool, np.bool_)):
        return "예" if bool(value) else "아니오"
    if value is None:
        return "-"
    try:
        if pd.isna(value):
            return "-"
    except Exception:
        pass
    text = str(value).strip()
    if text in USER_VALUE_MAP:
        return USER_VALUE_MAP[text]
    if text.lower() in USER_VALUE_MAP:
        return USER_VALUE_MAP[text.lower()]
    if text in {"", "nan", "NaN", "NAN", "nat", "NaT"}:
        return "-"
    if "_" in text:
        replaced = text
        for raw, label in USER_VALUE_MAP.items():
            if "_" in str(raw) and str(raw) in replaced:
                replaced = replaced.replace(str(raw), str(label))
        if replaced != text:
            return replaced
    return value


def clean_user_display_frame(df: pd.DataFrame) -> pd.DataFrame:
    """기본 화면 표에서 개발자용 원본 컬럼과 코드값을 숨긴다."""
    if df is None or df.empty:
        return df
    out = df.copy()
    if _is_inspection_screen_area():
        raw_cols = [
            c for c in out.columns
            if str(c) in USER_HIDDEN_RAW_COLUMNS
            or str(c).lower() in USER_HIDDEN_RAW_COLUMNS
            or str(c).startswith("raw_")
        ]
    else:
        raw_cols = [c for c in out.columns if _column_hidden_in_operational(c)]
    if raw_cols:
        out = out.drop(columns=raw_cols, errors="ignore")
    for col in out.columns:
        if out[col].dtype == object or str(out[col].dtype).startswith("bool"):
            out[col] = out[col].apply(_user_display_value)
    return out


def mark_zero_values_when_data_missing(df: pd.DataFrame) -> pd.DataFrame:
    """미수신/미지원 행에서 0.0이 실제 0처럼 보이지 않게 표시한다."""
    if df is None or df.empty:
        return df
    out = df.copy()
    unavailable_cols = [
        c for c in [
            "intraday_data_available",
            "orderbook_data_available",
            "flow_data_available",
            "quote_available",
            "orderbook_available",
            "flow_available",
        ] if c in out.columns
    ]
    status_cols = [
        c for c in ["intraday_fetch_status", "orderbook_fetch_status", "intraday_failure_reason", "orderbook_failure_reason"]
        if c in out.columns
    ]
    if not unavailable_cols and not status_cols:
        return out
    zero_sensitive = [
        c for c in out.columns
        if any(k in c for k in [
            "price", "volume", "trading_value", "change_pct", "ratio", "imbalance",
            "spread_pct", "execution_strength", "bid_total_volume", "ask_total_volume",
        ])
    ]
    if not zero_sensitive:
        return out
    for idx, row in out.iterrows():
        unavailable = False
        for col in unavailable_cols:
            unavailable = unavailable or not _row_bool(row.get(col), False)
        status_text = " ".join(str(row.get(c, "")) for c in status_cols).lower()
        unsupported = any(x in status_text for x in ["unsupported", "미지원", "해당 시장 미지원"])
        missing = unavailable or any(x in status_text for x in ["no_data", "api_response_empty", "market_closed", "장중 데이터 미수신"])
        if not missing and not unsupported:
            continue
        label = "미지원" if unsupported else "미수신"
        for col in zero_sensitive:
            val = safe_float(row.get(col), np.nan)
            if not math.isnan(val) and abs(val) <= 1e-12:
                out.at[idx, col] = label
    return out


