def _future_prob_default_empty(col: str) -> Any:
    return np.nan if col in _FUTURE_PROB_NUMERIC_COLS else ""


def _normalize_future_probability_scope_dtypes(df: pd.DataFrame | None) -> pd.DataFrame:
    """Merge 단계에서 StringDtype 컬럼에 float이 들어가는 TypeError를 방지한다."""
    if df is None or df.empty:
        return pd.DataFrame() if df is None else df.copy()
    out = df.copy()
    for col in list(out.columns):
        if pd.api.types.is_string_dtype(out[col]):
            out[col] = out[col].astype("object")
    for col in list(out.columns):
        if col in _FUTURE_PROB_NUMERIC_COLS:
            out[col] = pd.to_numeric(out[col], errors="coerce")
        elif col in _FUTURE_PROB_STRING_COLS:
            out[col] = out[col].apply(
                lambda v: "" if _future_prob_cell_empty(v) else str(v).strip()
            )
    return out


def _future_prob_put_at(df: pd.DataFrame, idx: Any, col: str, val: Any) -> None:
    if col not in df.columns:
        df[col] = _future_prob_default_empty(col)
    if col in _FUTURE_PROB_NUMERIC_COLS:
        if pd.api.types.is_string_dtype(df[col]):
            df[col] = df[col].astype("object")
        num = safe_float(val, np.nan)
        df.at[idx, col] = num if not math.isnan(num) else np.nan
        return
    if pd.api.types.is_string_dtype(df[col]):
        df[col] = df[col].astype("object")
    df.at[idx, col] = "" if _future_prob_cell_empty(val) else str(val).strip()


def _format_prob_percent_cell(val: Any) -> str:
    text = str(val).strip() if val is not None else ""
    if text in {"", "-", "nan", "None", "확인 필요"}:
        return "-"
    if text.endswith("%"):
        return text
    num = safe_float(val, np.nan)
    if math.isnan(num):
        return text or "-"
    if abs(num) <= 1.0 and num not in (0.0, 1.0):
        num *= 100.0
    return f"{num:.2f}%"


def _format_expected_return_cell(val: Any) -> str:
    text = str(val).strip() if val is not None else ""
    if text in {"", "-", "nan", "None", "확인 필요"}:
        return "-"
    if text.endswith("%"):
        num = safe_float(text.rstrip("%").lstrip("+"), np.nan)
        if math.isnan(num):
            return text
        sign = "+" if num > 0 else ""
        return f"{sign}{num:.2f}%"
    num = safe_float(val, np.nan)
    if math.isnan(num):
        return text or "-"
    sign = "+" if num > 0 else ""
    return f"{sign}{num:.2f}%"


def _future_prob_symbol_key(symbol: Any, market: Any) -> str:
    m = str(market or "").strip()
    s = str(symbol or "").strip()
    if not s:
        return ""
    if _is_kr_market_label(m):
        return f"KR:{_kr_symbol_key(s)}"
    return f"US:{normalize_ticker(s, '미국주식').upper()}"


def _future_prob_cell_empty(val: Any) -> bool:
    text = str(val).strip() if val is not None else ""
    return text in {"", "-", "nan", "None", "확인 필요"}


def _format_price_display_cell(val: Any, market: Any) -> str:
    if _future_prob_cell_empty(val):
        return "-"
    num = safe_float(val, np.nan)
    if not math.isnan(num):
        return fmt_price(num, str(market or "한국주식"))
    return str(val).strip()


