def _merge_candidate_display_prices(df: pd.DataFrame, market: str | None = None) -> pd.DataFrame:
    """후보 표시용 가격·수익률·장중 상태만 병합한다. CSV/예측 엔진 결과는 변경하지 않는다."""
    if df is None or df.empty:
        return pd.DataFrame() if df is None else df.copy()
    out = df.copy()
    target_market = _normalize_app_market(market)
    lookup = _display_price_lookup_cache(target_market, _display_price_cache_sig(target_market))
    ob_index: dict[str, pd.Series] = {}
    ob_snap = _safe_report_csv(REPORT_DIR / "intraday_orderbook_snapshot.csv")
    if ob_snap is not None and not ob_snap.empty:
        for _, ob_row in ob_snap.iterrows():
            row_market = _normalize_app_market(ob_row.get("market", "")) or target_market or "미국주식"
            if target_market and row_market != target_market:
                continue
            sym = _display_row_symbol(ob_row, row_market)
            key = _display_key(sym, row_market)
            if key and key not in ob_index:
                ob_index[key] = ob_row

    for col in (
        "current_price",
        "basis_price",
        "pullback_wait_price",
        "conditional_entry",
        "preferred_entry",
        "entry",
        "entry_price",
        "buy_price",
        "stop_loss",
        "stop",
        "take_profit1",
        "take_profit2",
        "target_price",
        "tp1",
        "tp2",
        "rr",
        "risk_reward",
        "expected_return_5d",
        "target_upside_pct",
        "prob_stop_5d",
        "stop_distance_pct",
    ):
        if col not in out.columns:
            out[col] = np.nan

    for idx, row in out.iterrows():
        row_market = _normalize_app_market(row.get("market", "")) or target_market or "미국주식"
        sym = _display_row_symbol(row, row_market)
        key = _display_key(sym, row_market)
        src = lookup.get(key, {})
        for target, aliases, lookup_field in (
            ("current_price", _DISPLAY_CURRENT_PRICE_ALIASES, "current_price"),
            ("basis_price", _CANDIDATE_WATCH_PRICE_ALIASES, "basis_price"),
            ("pullback_wait_price", _CANDIDATE_WATCH_PRICE_ALIASES, "basis_price"),
            ("conditional_entry", _CANDIDATE_CONDITIONAL_ENTRY_ALIASES, ""),
            ("preferred_entry", _DISPLAY_ENTRY_ALIASES, "preferred_entry"),
            ("stop_loss", _DISPLAY_STOP_ALIASES, "stop_loss"),
            ("take_profit1", _DISPLAY_TARGET_ALIASES, "take_profit1"),
            ("take_profit2", ("take_profit2", "tp2", "active_scenario_take_profit_2", "2차 목표가"), "take_profit2"),
        ):
            cur = _display_price_num(out.at[idx, target])
            if math.isnan(cur):
                cur = _display_first_price(row, aliases)
            if math.isnan(cur) and lookup_field:
                cur = _display_price_num(src.get(lookup_field))
            if not math.isnan(cur):
                out.at[idx, target] = cur
        for pct_col, lookup_field in (
            ("expected_return_5d", "expected_return_5d"),
            ("target_upside_pct", "target_upside_pct"),
            ("prob_stop_5d", "prob_stop_5d"),
            ("stop_distance_pct", "stop_distance_pct"),
        ):
            cur = safe_float(out.at[idx, pct_col], np.nan)
            if math.isnan(cur):
                cur = safe_float(row.get(pct_col, ""), np.nan)
            if math.isnan(cur) and lookup_field in src:
                cur = safe_float(src.get(lookup_field), np.nan)
            if not math.isnan(cur):
                out.at[idx, pct_col] = cur
        ob_row = ob_index.get(key)
        if ob_row is not None:
            for field in (
                "orderbook_data_available",
                "orderbook_fetch_status",
                "spread_pct",
                "intraday_fetch_status",
                "data_status",
                "flow_data_available",
            ):
                if field not in out.columns:
                    out[field] = ""
                existing = str(out.at[idx, field]).strip()
                incoming = ob_row.get(field, "")
                if existing in {"", "-", "nan", "None"} and _candidate_nonempty(incoming):
                    out.at[idx, field] = incoming
    return out


def _display_price_cache_sig(market: str | None) -> tuple[int, ...]:
    paths = [
        REPORT_DIR / "intraday_realtime_snapshot.csv",
        REPORT_DIR / "intraday_orderbook_snapshot.csv",
        REPORT_DIR / "buy_priority_candidates.csv",
        REPORT_DIR / "watchlist_buy_candidates.csv",
        REPORT_DIR / "swing_candidates.csv",
        REPORT_DIR / "swing_candidates_kr.csv",
        REPORT_DIR / "swing_candidates_us.csv",
        REPORT_DIR / "swing_candidates_kr_B_watch.csv",
        REPORT_DIR / "swing_candidates_us_B_watch.csv",
        REPORT_DIR / "fundamental_valuation_detail.csv",
        Path("predictions.csv"),
        Path("holdings_us.csv"),
        Path("holdings_kr.csv"),
        Path("data/holdings_us.csv"),
        Path("data/holdings_kr.csv"),
        resolve_watchlist_file("한국주식"),
        resolve_watchlist_file("미국주식"),
    ]
    sig: list[int] = []
    for p in paths:
        try:
            if p.exists():
                stt = p.stat()
                sig.extend([int(stt.st_mtime_ns), int(stt.st_size)])
        except Exception:
            sig.append(0)
    sig.append(1 if _normalize_app_market(market) == "한국주식" else 2)
    return tuple(sig)


def enrich_display_price_frame(df: pd.DataFrame, market: str | None = None) -> pd.DataFrame:
    """표시용 DataFrame에서만 현재가/매수가/손절가/목표가를 보강한다."""
    if df is None or df.empty:
        return pd.DataFrame() if df is None else df.copy()
    try:
        base = enrich_candidate_frame(df.copy(), market, ensure_common_columns=True)
    except Exception:
        base = df.copy()
    out = _merge_candidate_display_prices(base, market)
    target_market = _normalize_app_market(market)
    lookup = _display_price_lookup_cache(target_market, _display_price_cache_sig(target_market))
    for col in ("current_price", "preferred_entry", "stop_loss", "take_profit1", "take_profit2", "basis_price", "rr"):
        if col not in out.columns:
            out[col] = np.nan
    for idx, row in out.iterrows():
        row_market = _normalize_app_market(row.get("market", "")) or target_market or "미국주식"
        sym = _display_row_symbol(row, row_market)
        src = lookup.get(_display_key(sym, row_market), {})
        values = {
            "current_price": src.get("current_price", np.nan),
            "preferred_entry": src.get("preferred_entry", np.nan),
            "stop_loss": src.get("stop_loss", np.nan),
            "take_profit1": src.get("take_profit1", np.nan),
            "take_profit2": src.get("take_profit2", np.nan),
            "basis_price": src.get("basis_price", np.nan),
            "rr": src.get("rr", np.nan),
        }
        fallback_aliases = {
            "current_price": _DISPLAY_CURRENT_PRICE_ALIASES,
            "preferred_entry": _DISPLAY_ENTRY_ALIASES,
            "stop_loss": _DISPLAY_STOP_ALIASES,
            "take_profit1": _DISPLAY_TARGET_ALIASES,
            "take_profit2": ("take_profit2", "tp2", "active_scenario_take_profit_2", "2차 목표가"),
            "basis_price": _DISPLAY_BASIS_ALIASES,
            "rr": ("rr", "risk_reward", "active_scenario_risk_reward", "손익비"),
        }
        for col, aliases in fallback_aliases.items():
            if col == "rr":
                existing_rr = safe_float(out.at[idx, col], np.nan)
                incoming_rr = safe_float(values.get(col), np.nan)
                if math.isnan(existing_rr):
                    for alias in aliases:
                        incoming_rr = safe_float(row.get(alias, "") if hasattr(row, "get") else "", np.nan)
                        if not math.isnan(incoming_rr):
                            break
                if math.isnan(existing_rr) and not math.isnan(incoming_rr):
                    out.at[idx, col] = incoming_rr
                continue
            cur = _display_price_num(out.at[idx, col])
            if math.isnan(cur):
                cur = _display_price_num(values.get(col))
            if math.isnan(cur):
                cur = _display_first_price(row, aliases)
            if not math.isnan(cur):
                out.at[idx, col] = cur
        cur = _display_price_num(out.at[idx, "current_price"])
        basis = _display_price_num(out.at[idx, "basis_price"])
        entry = _display_price_num(out.at[idx, "preferred_entry"])
        stop = _display_price_num(out.at[idx, "stop_loss"])
        target = _display_price_num(out.at[idx, "take_profit1"])
        if "display_price_reason" not in out.columns:
            out["display_price_reason"] = ""
        has_saved_levels = any(
            not math.isnan(_display_price_num(out.at[idx, c]))
            for c in ("basis_price", "preferred_entry", "stop_loss", "take_profit1", "take_profit2")
            if c in out.columns
        )
        if math.isnan(cur) and not has_saved_levels:
            out.at[idx, "display_price_reason"] = "현재가 미수신"
        if not math.isnan(cur) and not math.isnan(basis):
            out.at[idx, "display_return_pct"] = (cur / basis - 1.0) * 100.0
        elif not math.isnan(cur) and not math.isnan(entry):
            out.at[idx, "display_return_pct"] = (cur / entry - 1.0) * 100.0
        if not math.isnan(cur) and not math.isnan(entry):
            out.at[idx, "entry_gap_pct"] = (cur / entry - 1.0) * 100.0
        if not math.isnan(cur) and not math.isnan(target):
            out.at[idx, "target_upside_pct"] = (target / cur - 1.0) * 100.0
        if not math.isnan(cur) and not math.isnan(stop):
            out.at[idx, "stop_distance_pct"] = (cur / stop - 1.0) * 100.0
    return out


def _format_price_or_reason(row: Any, col: str, market: str, missing: str) -> str:
    alias_map = {
        "current_price": ("current_price", "last_price", "현재가"),
        "preferred_entry": ("preferred_entry", "entry", "entry_price", "buy_price", "매수가", "조건부 진입가", "active_scenario_entry_price"),
        "basis_price": ("basis_price", "pullback_wait_price", "active_scenario_pullback_price", "관찰 기준가"),
        "stop_loss": ("stop_loss", "stop", "손절가", "active_scenario_stop_loss"),
        "take_profit1": ("take_profit1", "tp1", "target1", "target_price", "1차 목표가", "목표가", "active_scenario_take_profit_1"),
        "take_profit2": ("take_profit2", "tp2", "2차 목표가", "active_scenario_take_profit_2"),
    }
    aliases = alias_map.get(col, (col,))
    val = ""
    if hasattr(row, "get"):
        for alias in aliases:
            val = row.get(alias, "")
            if not math.isnan(_display_price_num(val)):
                break
    num = _display_price_num(val)
    if not math.isnan(num):
        return fmt_price(num, market)
    reason = str(row.get("display_price_reason", "") if hasattr(row, "get") else "").strip()
    price_status = str(row.get("price_data_status", row.get("데이터 상태", "")) if hasattr(row, "get") else "").strip()
    if price_status in {"저장된 후보 기준", "마감 후 저장값"}:
        return "저장값 없음"
    if col == "current_price" and reason:
        return reason
    if missing in {"가격 기준 미산출", "가격 기준 없음", "예측값 없음", "현재가 미수신"}:
        return "저장값 없음"
    return missing


def _format_pct_or_reason(value: Any, missing: str = "-") -> str:
    num = safe_float(value, np.nan)
    if math.isnan(num):
        return missing
    return f"{num:+.2f}%"


def enrich_future_probability_with_predictions(
    df: pd.DataFrame,
    pred_log: pd.DataFrame | None = None,
) -> pd.DataFrame:
    """미래 확률표 표시용 — 후보 CSV는 그대로 두고 predictions.csv 최신 예측가만 병합."""
    if df is None or df.empty:
        return pd.DataFrame()
    out = _normalize_future_probability_scope_dtypes(df)
    for dst, src in _FUTURE_PROB_SWING_PRICE_FALLBACK.items():
        if dst not in out.columns:
            out[dst] = np.nan
        if src in out.columns:
            dst_num = pd.to_numeric(out[dst], errors="coerce")
            src_num = pd.to_numeric(out[src], errors="coerce")
            mask = dst_num.isna()
            out.loc[mask, dst] = src_num[mask]

    pred = pred_log if pred_log is not None else load_prediction_log()
    if pred is None or pred.empty:
        return out

    work = pred.copy()
    if "ticker" not in work.columns and "symbol" in work.columns:
        work["ticker"] = work["symbol"]
    if "symbol" not in work.columns and "ticker" in work.columns:
        work["symbol"] = work["ticker"]
    work["_sym_key"] = work.apply(
        lambda r: _future_prob_symbol_key(r.get("ticker", r.get("symbol", "")), r.get("market", "")),
        axis=1,
    )
    work = work[work["_sym_key"].astype(str).str.len() > 0]
    if work.empty:
        return out

    sort_cols: list[str] = []
    for col in ("created_at", "target_date"):
        if col in work.columns:
            work[f"_{col}_dt"] = pd.to_datetime(work[col], errors="coerce")
            sort_cols.append(f"_{col}_dt")
    if sort_cols:
        work = work.sort_values(sort_cols, ascending=False, na_position="last")
    latest = work.drop_duplicates(subset=["_sym_key"], keep="first").set_index("_sym_key")

    for col in _FUTURE_PROB_PRED_MERGE_COLS:
        if col not in out.columns:
            out[col] = _future_prob_default_empty(col)

    for idx, row in out.iterrows():
        key = _future_prob_symbol_key(row.get("symbol", ""), row.get("market", ""))
        if not key or key not in latest.index:
            continue
        prow = latest.loc[key]
        if isinstance(prow, pd.DataFrame):
            prow = prow.iloc[0]
        market = row.get("market", prow.get("market", ""))
        for col in _FUTURE_PROB_PRED_MERGE_COLS:
            if _future_prob_cell_empty(out.at[idx, col]):
                val = prow.get(col, "")
                if not _future_prob_cell_empty(val):
                    _future_prob_put_at(out, idx, col, val)
        if _future_prob_cell_empty(out.at[idx, "preferred_entry"]):
            for alt in ("entry", "active_scenario_entry_price"):
                val = prow.get(alt, row.get(alt, ""))
                if not _future_prob_cell_empty(val):
                    _future_prob_put_at(out, idx, "preferred_entry", val)
                    break
        if _future_prob_cell_empty(out.at[idx, "stop_loss"]):
            for alt in ("stop", "active_scenario_stop_loss"):
                val = prow.get(alt, row.get(alt, ""))
                if not _future_prob_cell_empty(val):
                    _future_prob_put_at(out, idx, "stop_loss", val)
                    break
        if _future_prob_cell_empty(out.at[idx, "take_profit1"]):
            for alt in ("tp1", "active_scenario_take_profit_1"):
                val = prow.get(alt, row.get(alt, ""))
                if not _future_prob_cell_empty(val):
                    _future_prob_put_at(out, idx, "take_profit1", val)
                    break
        _ = market
    return _normalize_future_probability_scope_dtypes(out)


def _future_probability_has_values(row: Any) -> bool:
    for col in ("prob_up_1d", "prob_up_3d", "prob_up_5d", "prob_up_10d", "prob_tp1_5d", "prob_stop_5d"):
        try:
            val = row.get(col, "")
            if _future_prob_cell_empty(val):
                continue
            num = safe_float(val, np.nan)
            if not math.isnan(num):
                return True
            return True
        except Exception:
            continue
    return False


def _source_group_from_path(path: str) -> str:
    low = str(path or "").lower().replace("\\", "/")
    if "c_excluded" in low:
        return "C_excluded"
    if "a_top3" in low or "_a_top" in low:
        return "A_top3"
    if "b_watch" in low:
        return "B_watch"
    return ""


def _candidate_group_from_path(path: str) -> str:
    low = str(path or "").lower().replace("\\", "/")
    if "c_excluded" in low:
        return "C 제외/관망"
    if "a_top3" in low or "_a_top" in low:
        return "A 후보"
    if "b_watch" in low:
        return "B 관찰"
    return ""


def _future_scope_flag_yes(series: pd.Series) -> pd.Series:
    return series.astype(str).str.strip().isin(["예", "true", "True", "1", "1.0", "yes", "Y"])


def _future_first_existing(row: Any, columns: tuple[str, ...]) -> Any:
    for col in columns:
        try:
            val = row.get(col, "")
        except Exception:
            val = ""
        if not _future_prob_cell_empty(val):
            return val
    return ""


def _future_market_matches(row_market: Any, target_market: str | None) -> bool:
    """행 시장 라벨과 사이드바 시장(미국주식/한국주식) 일치 여부."""
    if not target_market:
        return True
    target = _normalize_app_market(target_market) or str(target_market).strip()
    row_norm = _normalize_app_market(str(row_market or "").strip())
    if not row_norm:
        return True
    return row_norm == target


def _future_candidate_group(row: Any) -> str:
    grade = str(row.get("grade", "") if hasattr(row, "get") else "").strip().upper()
    label = str(row.get("grade_label", "") if hasattr(row, "get") else "").strip()
    if grade == "C" or "제외" in label or "금지" in label:
        return "C 제외/관망"
    if grade == "A" or "A급" in label:
        return "A 후보"
    if grade == "B" or "관찰" in label:
        return "B 관찰"
    return ""


def _future_bool_label(value: bool) -> str:
    text = str(value).strip().lower()
    truthy = {"true", "1", "1.0", "yes", "y", "on", "예"}
    falsy = {"false", "0", "0.0", "no", "n", "off", "", "nan", "none", "nat", "아니오"}
    if text in truthy:
        return "예"
    if text in falsy:
        return "아니오"
    return "예" if value is True else "아니오"


def _future_join_labels(labels: list[str]) -> str:
    clean = [str(x).strip() for x in labels if str(x).strip()]
    if not clean:
        return "-"
    return "+".join(dict.fromkeys(clean))


def _future_symbol_from_row(row: Any, market: str) -> str:
    for col in ("symbol", "ticker", "종목코드", "종목", "티커", "code"):
        try:
            val = str(row.get(col, "")).strip()
        except Exception:
            val = ""
        if val and val.lower() not in {"nan", "none", "nat", "-", "null"}:
            return normalize_ticker(val, market)
    return ""


def _read_csv_if_exists(path: Path) -> pd.DataFrame:
    return read_csv_cached(path, dtype_str=True)


def load_future_probability_holdings_sources(market: str | None = None) -> pd.DataFrame:
    """미래확률표 표시용 보유종목 소스. 원본 파일은 수정하지 않는다."""
    market = _normalize_app_market(market)
    paths = [
        Path("data/holdings_us.csv"),
        Path("data/holdings_kr.csv"),
        Path("holdings_us.csv"),
        Path("holdings_kr.csv"),
        Path("data/holdings.csv"),
    ]
    rows: list[dict[str, Any]] = []
    for path in paths:
        df = _read_csv_if_exists(path)
        if df.empty:
            continue
        inferred_market = "한국주식" if "kr" in path.name.lower() else ("미국주식" if "us" in path.name.lower() else "")
        for _, row in df.iterrows():
            row_market = str(row.get("market", "") or inferred_market or market or "").strip()
            if not row_market:
                raw_symbol = str(row.get("ticker", row.get("symbol", "")) or "")
                row_market = "한국주식" if _kr_symbol_key(raw_symbol) and raw_symbol.replace(".KS", "").replace(".KQ", "").isdigit() else "미국주식"
            if not _future_market_matches(row_market, market):
                continue
            sym = _future_symbol_from_row(row, row_market)
            if not sym:
                continue
            name = row.get("name", row.get("종목명", ""))
            if _future_prob_cell_empty(name):
                name = sym
            avg_raw = _future_first_existing(row, ("avg_price", "avg_buy_price", "평균단가"))
            qty_raw = _future_first_existing(row, ("quantity", "shares", "보유수량"))
            cur_raw = _future_first_existing(row, ("current_price", "last_price", "현재가", "close", "price"))
            rows.append({
                "symbol": sym,
                "name": name,
                "market": _normalize_app_market(row_market) or row_market,
                "source_file": path.as_posix(),
                "is_holding": True,
                "avg_price": safe_float(avg_raw, np.nan),
                "current_price": safe_float(cur_raw, np.nan),
                "quantity": safe_float(qty_raw, np.nan),
            })
    return _normalize_future_probability_scope_dtypes(pd.DataFrame(rows))


def load_future_probability_watchlist_sources(market: str | None = None) -> pd.DataFrame:
    """미래확률표 표시용 관심종목 소스. 기존 watchlist 로직과 보조 파일을 안전하게 읽는다."""
    market = _normalize_app_market(market)
    markets = [market] if market in {"미국주식", "한국주식"} else ["미국주식", "한국주식"]
    rows: list[dict[str, Any]] = []
    frames: list[pd.DataFrame] = []
    for m in markets:
        try:
            wl = load_watchlist_df(m)
            if not wl.empty:
                wl = wl.copy()
                wl["market"] = m
                wl["source_file"] = resolve_watchlist_file(m).as_posix()
                frames.append(wl)
        except Exception:
            pass
    extra_paths = [
        Path("watchlist_us.csv"),
        Path("watchlist_kr.csv"),
        Path("watchlist_us_growth.csv"),
        Path("watchlist_kr_growth.csv"),
        Path("watchlist_us_symbols_only.csv"),
        Path("daily_watch_selection.json"),
        Path("data/watchlist.csv"),
        Path("config/watchlist.csv"),
        Path("data/decision_system/watchlist_user_us.csv"),
        Path("data/decision_system/watchlist_user_kr.csv"),
    ]
    for path in extra_paths:
        if path.suffix.lower() == ".json" and path.name == "daily_watch_selection.json":
            try:
                if path.exists():
                    payload = json.loads(path.read_text(encoding="utf-8"))
                    if isinstance(payload, dict):
                        for mkey, block in payload.items():
                            if not isinstance(block, dict):
                                continue
                            inferred = "미국주식" if str(mkey).upper() == "US" else "한국주식"
                            if market and inferred != market:
                                continue
                            for raw_sym in block.get("symbols", []) or []:
                                sym = _future_symbol_from_row({"symbol": raw_sym}, inferred)
                                if sym:
                                    rows.append({
                                        "symbol": sym,
                                        "name": "",
                                        "market": inferred,
                                        "source_file": path.as_posix(),
                                        "is_watchlist": True,
                                    })
            except Exception:
                pass
            continue
        df = _read_csv_if_exists(path)
        if df.empty:
            continue
        inferred_market = "한국주식" if "kr" in path.name.lower() else ("미국주식" if "us" in path.name.lower() else "")
        if market and inferred_market and market != inferred_market:
            continue
        df = df.copy()
        if "market" not in df.columns or df["market"].astype(str).str.strip().eq("").all():
            df["market"] = inferred_market or market or ""
        df["source_file"] = path.as_posix()
        frames.append(df)
    if frames:
        for _, row in pd.concat(frames, ignore_index=True, sort=False).iterrows():
            row_market = str(row.get("market", "") or market or "").strip()
            if not _future_market_matches(row_market, market):
                continue
            if not row_market:
                raw_symbol = str(row.get("symbol", row.get("ticker", "")) or "")
                row_market = "한국주식" if raw_symbol.replace(".KS", "").replace(".KQ", "").isdigit() else "미국주식"
            sym = _future_symbol_from_row(row, row_market)
            if not sym:
                continue
            name = row.get("name", row.get("종목명", row.get("company", "")))
            if _future_prob_cell_empty(name):
                name = sym
            rows.append({
                "symbol": sym,
                "name": name,
                "market": _normalize_app_market(row_market) or row_market,
                "source_file": row.get("source_file", ""),
                "is_watchlist": True,
            })
    return _normalize_future_probability_scope_dtypes(pd.DataFrame(rows))


def _iter_swing_candidate_rows_for_future_prob(market: str | None = None) -> list[tuple[pd.Series, str]]:
    """후보 CSV를 파일별로 읽어 source_file·후보 구분 메타를 유지한다."""
    market = _normalize_app_market(market)
    paths = [
        SWING_SCAN_US_TOPA_FILE,
        SWING_SCAN_US_B_FILE,
        SWING_SCAN_US_C_FILE,
        SWING_SCAN_KR_TOPA_FILE,
        SWING_SCAN_KR_B_FILE,
        SWING_SCAN_KR_C_FILE,
    ]
    rows: list[tuple[pd.Series, str]] = []
    for path in paths:
        df = _safe_report_csv(path)
        if df.empty:
            continue
        src = path.as_posix()
        for _, row in df.iterrows():
            rows.append((row, src))
    if not rows:
        for fallback in (SWING_SCAN_US_FILE, SWING_SCAN_KR_FILE):
            df = _safe_report_csv(fallback)
            if df.empty:
                continue
            src = fallback.as_posix()
            for _, row in df.iterrows():
                rows.append((row, src))
    if not rows or not market:
        return rows
    filtered: list[tuple[pd.Series, str]] = []
    for row, src in rows:
        row_market = str(row.get("market", "") or "").strip()
        if not row_market:
            row_market = "한국주식" if "kr" in src.lower() else "미국주식"
        if not _future_market_matches(row_market, market):
            continue
        filtered.append((row, src))
    return filtered


def build_future_probability_scope_df(
    candidate_df: pd.DataFrame | None = None,
    *,
    market: str | None = None,
    pred_log: pd.DataFrame | None = None,
) -> pd.DataFrame:
    """후보·보유·관심종목을 미래확률표 한 화면에 합친다. 계산값은 만들지 않고 표시 행만 보강."""
    market = _normalize_app_market(market)
    holdings = load_future_probability_holdings_sources(market)
    watch = load_future_probability_watchlist_sources(market)

    merged: dict[str, dict[str, Any]] = {}

    def _ensure_row(symbol: str, row_market: str) -> tuple[str, dict[str, Any]]:
        key = _future_prob_symbol_key(symbol, row_market)
        if key not in merged:
            merged[key] = {
                "symbol": normalize_ticker(symbol, row_market),
                "market": row_market,
                "source_files": [],
            }
        return key, merged[key]

    # 미래확률표는 파일명 자체가 후보 구분(A/B/C)의 권위 있는 출처다.
    # 화면에서 전달되는 병합 DataFrame은 source_file이 빠질 수 있으므로 6개 후보 CSV를 우선 읽는다.
    candidate_rows: list[tuple[pd.Series, str]] = _iter_swing_candidate_rows_for_future_prob(market)
    if not candidate_rows and candidate_df is not None and not candidate_df.empty:
        work = candidate_df.copy()
        if market and "market" in work.columns:
            work = _intraday_filter_market(work, market)
        for _, row in work.iterrows():
            src = str(row.get("source_file", "") or "").strip()
            if src.lower() in {"nan", "none", "nat", "null"}:
                src = ""
            if not src and row.get("source_files"):
                parts = row.get("source_files")
                if isinstance(parts, list) and parts:
                    src = str(parts[0])
            candidate_rows.append((row, src))

    for row, source_file in candidate_rows:
        row_market = str(row.get("market", "") or market or "").strip()
        if not row_market:
            row_market = "한국주식" if "kr" in source_file.lower() else "미국주식"
        if not _future_market_matches(row_market, market):
            continue
        row_market = _normalize_app_market(row_market) or row_market
        sym = _future_symbol_from_row(row, row_market)
        if not sym:
            continue
        _, out = _ensure_row(sym, row_market)
        for col, val in row.items():
            if col not in out or _future_prob_cell_empty(out.get(col, "")):
                out[col] = val
        if source_file:
            out["source_file"] = source_file
            out["source_group_normalized"] = _source_group_from_path(source_file)
        path_group = _candidate_group_from_path(source_file)
        grade_group = _future_candidate_group(row)
        new_group = path_group or grade_group
        if new_group:
            if new_group == "C 제외/관망" or not str(out.get("candidate_group", "")).strip():
                out["candidate_group"] = new_group
            elif not out.get("candidate_group"):
                out["candidate_group"] = new_group
        out["_candidate_source"] = True

    for source_df, flag in ((holdings, "is_holding"), (watch, "is_watchlist")):
        if source_df is None or source_df.empty:
            continue
        for _, row in source_df.iterrows():
            row_market = str(row.get("market", "") or market or "").strip() or ("한국주식" if market == "한국주식" else "미국주식")
            if not _future_market_matches(row_market, market):
                continue
            row_market = _normalize_app_market(row_market) or row_market
            sym = _future_symbol_from_row(row, row_market)
            if not sym:
                continue
            _, out = _ensure_row(sym, row_market)
            out[flag] = True
            if _future_prob_cell_empty(out.get("name", "")):
                nm = row.get("name", row.get("종목명", ""))
                out["name"] = nm if not _future_prob_cell_empty(nm) else sym
            for src_col, aliases in {
                "avg_price": ("avg_price", "avg_buy_price", "평균단가"),
                "quantity": ("quantity", "shares", "보유수량"),
            }.items():
                if _future_prob_cell_empty(out.get(src_col, "")):
                    val = _future_first_existing(row, aliases)
                    if not _future_prob_cell_empty(val):
                        out[src_col] = val
            if not isinstance(out.get("source_files"), list):
                out["source_files"] = []
            if row.get("source_file"):
                out["source_files"].append(str(row.get("source_file")))

    if not merged:
        return pd.DataFrame()
    out = pd.DataFrame(list(merged.values()))
    for col in FUTURE_PROBABILITY_COLUMNS:
        if col not in out.columns:
            out[col] = _future_prob_default_empty(col)
    out = _normalize_future_probability_scope_dtypes(out)
    out["is_holding"] = out["is_holding"].apply(lambda v: _row_bool(v, False))
    out["is_watchlist"] = out["is_watchlist"].apply(lambda v: _row_bool(v, False))
    out = enrich_future_probability_with_predictions(out, pred_log=pred_log)

    display_groups: list[str] = []
    statuses: list[str] = []
    for _, row in out.iterrows():
        cand = str(row.get("candidate_group", "") or "").strip()
        if cand.lower() in {"nan", "none", "-"}:
            cand = ""
        is_holding = _row_bool(row.get("is_holding"), False)
        is_watch = _row_bool(row.get("is_watchlist"), False)
        parts: list[str] = []
        if is_holding:
            parts.append("보유종목")
        if is_watch:
            parts.append("관심종목")
        if cand:
            parts.append(cand)
        if is_holding and is_watch and not cand:
            display_groups.append("보유+관심")
        elif is_holding and cand:
            display_groups.append(f"보유+{cand}")
        elif is_watch and cand:
            display_groups.append(f"관심+{cand}")
        else:
            display_groups.append(_future_join_labels(parts))

        has_prob = _future_probability_has_values(row)
        if has_prob:
            statuses.append("계산 완료")
        elif is_holding or is_watch:
            statuses.append("계산 대기")
        elif cand == "C 제외/관망":
            statuses.append("미래확률 미생성")
        elif cand:
            statuses.append("미래확률 미생성")
        else:
            statuses.append("계산 대기")
    out["display_group"] = display_groups
    out["future_probability_status"] = statuses
    if "source_group_normalized" not in out.columns:
        out["source_group_normalized"] = ""
    if "source_file" in out.columns:
        empty_sg = out["source_group_normalized"].astype(str).str.strip().eq("")
        out.loc[empty_sg, "source_group_normalized"] = (
            out.loc[empty_sg, "source_file"].astype(str).map(_source_group_from_path)
        )
    out["is_holding"] = out["is_holding"].apply(_future_bool_label)
    out["is_watchlist"] = out["is_watchlist"].apply(_future_bool_label)

    def _future_data_source_label(row: Any) -> str:
        files: list[str] = []
        sf = str(row.get("source_file", "") or "").strip()
        if sf and sf.lower() not in {"nan", "none", "nat", "null", "-"}:
            files.extend([p.strip() for p in sf.split("|") if p.strip()])
        extras = row.get("source_files", [])
        if isinstance(extras, list):
            for extra in extras:
                text = str(extra).strip()
                if text and text.lower() not in {"nan", "none", "nat", "null", "-"} and text not in files:
                    files.append(text)
        elif extras is not None and not (isinstance(extras, float) and pd.isna(extras)):
            text = str(extras).strip()
            if text and text.lower() not in {"nan", "none", "nat", "null", "-"} and text not in files:
                files.append(text)
        tags = str(row.get("source_tags", "") or "").strip()
        if files:
            return _future_join_labels([Path(p).name for p in files[:3]]) + (f" (+{len(files)-3})" if len(files) > 3 else "")
        if tags:
            return tags.replace("|", "+")
        return "-"

    out["data_source"] = out.apply(_future_data_source_label, axis=1)
    out["risk_final_decision"] = out.apply(
        lambda r: "매수 제외/관망(참고)" if str(r.get("candidate_group", "")) == "C 제외/관망"
        else r.get("risk_final_decision") if not _future_prob_cell_empty(r.get("risk_final_decision", ""))
        else ("보유 상태 점검" if r.get("is_holding") == "예" else "판단 대기"),
        axis=1,
    )
    sort_rank = {
        "보유종목": 0,
        "관심종목": 1,
        "A 후보": 2,
        "B 관찰": 3,
        "C 제외/관망": 4,
    }
    out["_sort_rank"] = out["display_group"].apply(lambda x: min([sort_rank.get(p, 9) for p in str(x).split("+") if p] or [9]))
    out["_prob_ready_sort"] = out["future_probability_status"].eq("계산 완료").astype(int)
    out = out.sort_values(["_sort_rank", "_prob_ready_sort", "symbol"], ascending=[True, False, True])
    return out.reset_index(drop=True)


def count_future_probability_scope_rows(df: pd.DataFrame | None) -> dict[str, int]:
    """표시 범위별 row 수 (디버그·캡션용)."""
    scopes = [
        "전체",
        "보유종목",
        "관심종목",
        "A/B 후보",
        "C 제외/관망 포함",
        "미래확률 계산 완료만",
        "미래확률 계산 대기만",
    ]
    if df is None or df.empty:
        return {s: 0 for s in scopes}
    out: dict[str, int] = {"전체": int(len(df))}
    for scope in scopes[1:]:
        out[scope] = int(len(filter_future_probability_display_scope(df, scope)))
    return out


def future_probability_scope_empty_message(
    scope: str,
    filtered: pd.DataFrame,
    full_df: pd.DataFrame | None = None,
    *,
    holdings_rows: int = 0,
    watchlist_rows: int = 0,
) -> str:
    if filtered is not None and not filtered.empty:
        return ""
    if scope == "보유종목":
        if holdings_rows <= 0:
            return "등록된 보유종목이 없습니다."
        return "보유종목이 있으나 현재 시장/필터 조건에 맞는 행이 없습니다."
    if scope == "관심종목":
        if watchlist_rows <= 0:
            return "등록된 관심종목이 없습니다."
        return "관심종목이 있으나 현재 시장/필터 조건에 맞는 행이 없습니다."
    if scope == "A/B 후보":
        return "현재 A/B 후보가 없습니다."
    if scope == "C 제외/관망 포함":
        full = full_df if full_df is not None else pd.DataFrame()
        c_n = 0
        if not full.empty:
            cand = full.get("candidate_group", pd.Series("", index=full.index)).astype(str)
            sg = full.get("source_group_normalized", pd.Series("", index=full.index)).astype(str)
            c_n = int(cand.eq("C 제외/관망").sum() + sg.eq("C_excluded").sum())
        if c_n > 0:
            return "C 제외/관망 후보가 병합 테이블에 있으나 필터 결과가 비었습니다. 표시 범위를 ‘전체’로 확인해 주세요."
        return "C 제외/관망 후보 CSV가 비어 있거나 현재 시장 필터에 해당하지 않습니다."
    if scope == "미래확률 계산 완료만":
        return "미래확률 값(prob_up_*)이 있는 종목이 없습니다."
    if scope == "미래확률 계산 대기만":
        return "계산 대기·미생성 상태 종목이 없습니다."
    if scope == "전체":
        full_n = int(len(full_df)) if full_df is not None and not full_df.empty else 0
        if full_n > 0:
            return (
                f"병합 테이블에는 {full_n}건이 있으나 표시 필터 결과가 비었습니다. "
                "표시 범위를 ‘전체’로 두고 새로고침해 주세요."
            )
        return "후보·보유·관심종목 소스에서 읽을 수 있는 행이 없습니다."
    return f"{scope} 범위에 표시할 종목이 없습니다."


def filter_future_probability_display_scope(df: pd.DataFrame, scope: str) -> pd.DataFrame:
    if df is None or df.empty or scope == "전체":
        return df.copy() if df is not None else pd.DataFrame()
    text = df.get("display_group", pd.Series("", index=df.index)).astype(str)
    status = df.get("future_probability_status", pd.Series("", index=df.index)).astype(str)
    cand = df.get("candidate_group", pd.Series("", index=df.index)).astype(str)
    sg = df.get("source_group_normalized", pd.Series("", index=df.index)).astype(str)
    holding = _future_scope_flag_yes(df.get("is_holding", pd.Series("아니오", index=df.index)))
    watch = _future_scope_flag_yes(df.get("is_watchlist", pd.Series("아니오", index=df.index)))
    prob_ready = df.apply(_future_probability_has_values, axis=1)
    if scope == "보유종목":
        return df[holding].copy()
    if scope == "관심종목":
        return df[watch | text.str.contains("관심", na=False)].copy()
    if scope == "A/B 후보":
        return df[cand.isin(["A 후보", "B 관찰"])].copy()
    if scope == "C 제외/관망 포함":
        mask = (
            cand.eq("C 제외/관망")
            | sg.eq("C_excluded")
            | text.str.contains("C 제외/관망", na=False)
        )
        return df[mask].copy()
    if scope == "미래확률 계산 완료만":
        return df[status.eq("계산 완료") | prob_ready].copy()
    if scope == "미래확률 계산 대기만":
        hw = holding | watch
        return df[status.eq("계산 대기") | (hw & ~prob_ready)].copy()
    return df.copy()


