def _canonicalize_prediction_validation_frame(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    work = df.copy()
    for target, candidates in _PREDICTION_VALIDATION_ALIASES.items():
        if target in work.columns:
            continue
        for cand in candidates:
            if cand in work.columns:
                work[target] = work[cand]
                break
        if target not in work.columns:
            work[target] = ""
    return work


def _format_validation_error_pct(val: Any) -> str:
    num = safe_float(val, np.nan)
    if math.isnan(num):
        return "-"
    sign = "+" if num > 0 else ""
    return f"{sign}{num:.2f}%"


def _format_validation_touch(val: Any) -> str:
    if isinstance(val, bool):
        return "터치" if val else "미터치"
    text = str(val).strip().lower()
    if text in {"1", "true", "yes", "y", "터치", "touched"}:
        return "터치"
    if text in {"0", "false", "no", "n", "미터치", "not touched"}:
        return "미터치"
    if text in {"", "-", "nan", "none"}:
        return "미확인"
    return str(val).strip()


def _format_validation_direction_hit(val: Any) -> str:
    if isinstance(val, bool):
        return "일치" if val else "불일치"
    text = str(val).strip().lower()
    if text in {"1", "true", "yes", "y", "hit", "일치"}:
        return "일치"
    if text in {"0", "false", "no", "n", "miss", "불일치"}:
        return "불일치"
    return str(val).strip() if text not in {"", "-", "nan", "none"} else "미확인"


def prepare_prediction_validation_display(df: pd.DataFrame, *, limit: int = 80) -> pd.DataFrame:
    """복기/보정 화면 — 예측 vs 실제 검증 표 (원본 CSV 컬럼은 변경하지 않음)."""
    work = _canonicalize_prediction_validation_frame(df)
    if work.empty:
        return pd.DataFrame()

    if "actual_open" in work.columns:
        actual_open = pd.to_numeric(work["actual_open"], errors="coerce")
        work = work[actual_open.notna()].copy()
    if "target_date" in work.columns:
        work = work.sort_values("target_date", ascending=False)

    rows: list[dict[str, Any]] = []
    for _, row in work.head(limit).iterrows():
        market = row.get("market", "한국주식")
        result = str(row.get("decision_result", "") or "").strip()
        if not result:
            result = str(row.get("failure_reason", "") or "").strip() or "미확인"
        rows.append({
            "ticker": display_symbol(row.get("ticker", ""), str(market)),
            "prediction_date": str(row.get("prediction_date", "") or "-")[:19],
            "target_date": str(row.get("target_date", "") or "-")[:10],
            "predicted_open_mid": _format_price_display_cell(row.get("predicted_open_mid"), market),
            "actual_open": _format_price_display_cell(row.get("actual_open"), market),
            "open_error_pct": _format_validation_error_pct(row.get("open_error_pct")),
            "predicted_close_mid": _format_price_display_cell(row.get("predicted_close_mid"), market),
            "actual_close": _format_price_display_cell(row.get("actual_close"), market),
            "close_error_pct": _format_validation_error_pct(row.get("close_error_pct")),
            "preferred_entry": _format_price_display_cell(row.get("preferred_entry"), market),
            "entry_touched": _format_validation_touch(row.get("entry_touched")),
            "stop_loss": _format_price_display_cell(row.get("stop_loss"), market),
            "stop_touched": _format_validation_touch(row.get("stop_touched")),
            "take_profit1": _format_price_display_cell(row.get("take_profit1"), market),
            "tp1_touched": _format_validation_touch(row.get("tp1_touched")),
            "direction_hit": _format_validation_direction_hit(row.get("direction_hit")),
            "decision_result": result,
        })
    out = pd.DataFrame(rows)
    out = out.rename(columns=PREDICTION_VALIDATION_KOREAN_MAP)
    ordered = [PREDICTION_VALIDATION_KOREAN_MAP[c] for c in PREDICTION_VALIDATION_SOURCE_COLUMNS]
    return out[ordered]


def prepare_future_probability_display(
    df: pd.DataFrame,
    *,
    limit: int = 80,
    pred_log: pd.DataFrame | None = None,
    column_set: list[str] | None = None,
) -> pd.DataFrame:
    """미래 확률표 화면 전용 — 컬럼 한글화·확률 % 포맷·표시 순서 (CSV 원본은 변경하지 않음)."""
    if df is None or df.empty:
        return pd.DataFrame()
    enriched = enrich_future_probability_with_predictions(df, pred_log=pred_log)
    base_cols = column_set or FUTURE_PROBABILITY_COLUMNS
    # Keep user-facing probability tables stable even when optional prediction columns
    # are not available in the source frame yet.
    if column_set is None:
        for _col in ("pred_open_mid", "pred_close_mid"):
            if _col not in enriched.columns:
                enriched[_col] = ""
    cols = [c for c in base_cols if c in enriched.columns]
    if not cols:
        return pd.DataFrame()
    view = normalize_final_judgment_columns_for_display(enriched.copy())
    if "risk_final_decision" in enriched.columns:
        view["risk_final_decision"] = enriched["risk_final_decision"]
    view = sanitize_display_symbols(view)
    view = view[cols].head(limit)
    for col in _FUTURE_PROB_PERCENT_COLS:
        if col in view.columns:
            view[col] = view[col].apply(_format_prob_percent_cell)
    if "market" in view.columns:
        for col in _FUTURE_PROB_PRICE_COLS:
            if col in view.columns:
                view[col] = [
                    _format_price_display_cell(v, m)
                    for v, m in zip(view[col], view["market"], strict=False)
                ]
    else:
        for col in _FUTURE_PROB_PRICE_COLS:
            if col in view.columns:
                view[col] = view[col].apply(_format_price_display_cell)
    if "expected_return_5d" in view.columns:
        view["expected_return_5d"] = view["expected_return_5d"].apply(_format_expected_return_cell)
    if "forecast_confidence" in view.columns:
        view["forecast_confidence"] = view["forecast_confidence"].apply(
            lambda v: "-" if str(v).strip() in {"", "nan", "None"} else str(v).strip()
        )
    for col in ("display_group", "is_holding", "is_watchlist", "candidate_group", "future_probability_status"):
        if col in view.columns:
            view[col] = view[col].apply(
                lambda v: "-" if str(v).strip().lower() in {"", "nan", "none", "nat"} else str(v).strip()
            )
    view = view.rename(columns={c: FUTURE_PROBABILITY_KOREAN_MAP[c] for c in view.columns})
    ordered = [FUTURE_PROBABILITY_KOREAN_MAP[c] for c in base_cols if c in enriched.columns]
    return view[ordered]


def _row_bool(value: Any, default: bool = False) -> bool:
    if isinstance(value, bool):
        return value
    text = str(value or "").strip().lower()
    if text in {"true", "1", "1.0", "yes", "y", "on"}:
        return True
    if text in {"false", "0", "0.0", "no", "n", "off", ""}:
        return default
    return default


def _is_us_market_label(market: Any) -> bool:
    text = str(market or "").strip().lower()
    return text in {"미국주식", "us", "미장", "미국", "us stock"} or "us" in text or "미국" in text


def _is_kr_market_label(market: Any) -> bool:
    text = str(market or "").strip()
    return text in {"한국주식", "KR", "국장", "한국"} or "한국" in text or "국장" in text


def _flow_net_display_value(row: pd.Series, col: str) -> str:
    market = row.get("market", "")
    available = _row_bool(row.get("flow_data_available"), False)
    if not available:
        if _is_us_market_label(market):
            return "미지원"
        return "미수신"
    num = safe_float(row.get(col), np.nan)
    if math.isnan(num):
        text = str(row.get(col, "")).strip()
        return text if text not in {"", "-", "nan", "None"} else "-"
    if abs(num) >= 1:
        return f"{num:,.0f}"
    return f"{num:.2f}"


def prepare_intraday_flow_display(df: pd.DataFrame, *, limit: int = 80) -> pd.DataFrame:
    """수급·프로그램 화면 전용 — 미지원/미수신과 실제 0을 구분 (원본 CSV는 변경하지 않음)."""
    if df is None or df.empty:
        return pd.DataFrame()
    view = df.head(limit).copy()
    rows: list[dict[str, Any]] = []
    for _, row in view.iterrows():
        market = row.get("market", "")
        available = _row_bool(row.get("flow_data_available"), False)
        label = str(row.get("intraday_flow_label", "") or "").strip()
        warning = str(row.get("intraday_flow_warning", "") or "").strip()
        if not available:
            if _is_us_market_label(market):
                label = "수급 데이터 제한"
                warning = "미국주식 수급/프로그램 데이터 미지원 가능성"
            else:
                label = "수급 판단 보류"
                warning = "장마감/장전/API 미수신 가능성"
        sym = str(row.get("symbol", "") or "").strip()
        nm = str(row.get("name", "") or row.get("stock_name", "") or row.get("종목명", "") or "")
        if _is_kr_market_label(market) and sym and not nm:
            nm = korean_name_from_symbol(sym, sym)
        rows.append({
            "종목코드": sym,
            "종목명": nm or "-",
            "시장": market,
            "외국인 수급": _flow_net_display_value(row, "foreign_net_buy"),
            "기관 수급": _flow_net_display_value(row, "institution_net_buy"),
            "개인 수급": _flow_net_display_value(row, "individual_net_buy"),
            "프로그램 수급": _flow_net_display_value(row, "program_net_buy"),
            "수급 상태": label or "-",
            "수급 경고": warning or "-",
            "수급 점수": row.get("intraday_flow_score", "-"),
        })
    return pd.DataFrame(rows)


_INTRADAY_FLOW_GUIDANCE_KR = (
    "한국주식 수급은 외국인/기관/개인/프로그램 순매수 기준입니다. "
    "미수신은 실제 순매수 0이 아니라 API 미수신을 의미합니다."
)
_INTRADAY_FLOW_GUIDANCE_US = (
    "미국주식은 한국식 외국인/기관/개인/프로그램 수급 대신 "
    "현재가, 거래량, 거래대금, 체결강도, 호가 압력 중심으로 대체 판단합니다."
)


def _intraday_snapshot_index(df: pd.DataFrame | None) -> dict[tuple[str, str], dict[str, Any]]:
    """symbol+market → row dict (reports CSV 병합용, 네트워크 없음)."""
    index: dict[tuple[str, str], dict[str, Any]] = {}
    if df is None or df.empty or "symbol" not in df.columns:
        return index
    work = df.copy()
    if "market" not in work.columns:
        work["market"] = ""
    for _, row in work.iterrows():
        sym = str(row.get("symbol", "")).strip().upper()
        if not sym:
            continue
        mkt = str(row.get("market", "")).strip()
        if _is_us_market_label(mkt):
            sym = display_symbol(sym, "미국주식")
        pack = row.to_dict()
        index[(sym, mkt)] = pack
        index[(sym, "")] = pack
    return index


def _flow_pick_first(*sources: dict[str, Any] | None, keys: tuple[str, ...]) -> Any:
    for src in sources:
        if not src:
            continue
        for key in keys:
            if key not in src:
                continue
            value = src.get(key)
            if value is None:
                continue
            text = str(value).strip()
            if text.lower() in {"", "nan", "none", "nat", "-"}:
                continue
            return value
    return None


def _us_flow_metric_present(row: pd.Series, *cols: str) -> bool:
    for col in cols:
        value = row.get(col)
        if value is None:
            continue
        text = str(value).strip()
        if text.lower() in {"", "nan", "none", "nat", "-"}:
            continue
        num = safe_float(value, np.nan)
        if not math.isnan(num):
            return True
    return False


def _us_flow_metric_display(row: pd.Series, col: str, *alt_cols: str) -> str:
    for key in (col,) + alt_cols:
        value = row.get(key)
        if value is None:
            continue
        text = str(value).strip()
        if text.lower() in {"", "nan", "none", "nat", "-"}:
            continue
        num = safe_float(value, np.nan)
        if math.isnan(num):
            return text
        if key.endswith("_pct") or key in {"intraday_change_pct", "orderbook_pressure", "orderbook_imbalance"}:
            return f"{num:.2f}%"
        if key in {"last_price", "current_price", "quote_fallback_price", "intraday_trading_value"}:
            return fmt_price(num, str(row.get("market", "미국주식") or "미국주식"))
        if abs(num) >= 1:
            return f"{num:,.2f}"
        return f"{num:.4f}"
    return "미수신"


def _us_flow_data_status(row: pd.Series) -> str:
    has_price = _us_flow_metric_present(
        row, "last_price", "current_price", "quote_fallback_price"
    )
    has_vol_or_value = _us_flow_metric_present(
        row, "intraday_volume", "intraday_trading_value"
    )
    if has_price and has_vol_or_value:
        return "수신"
    if has_price:
        return "일부 수신"
    return "미수신"


def _us_flow_momentum_display(row: pd.Series) -> str:
    if _us_flow_metric_present(row, "intraday_momentum_score"):
        return _us_flow_metric_display(row, "intraday_momentum_score")
    has_price = _us_flow_metric_present(row, "last_price", "current_price", "quote_fallback_price")
    has_change = _us_flow_metric_present(row, "intraday_change_pct")
    has_vol = _us_flow_metric_present(row, "intraday_volume", "intraday_trading_value")
    if has_price and has_vol:
        return "참고 가능"
    if has_price or has_change or has_vol:
        return "부분 수신"
    return "미수신"


def _us_flow_source_display(row: pd.Series) -> str:
    label = str(row.get("quote_source_label", "") or "").strip()
    if label and label.lower() not in {"nan", "none", "-", "미수신"}:
        return label
    quote = row.get("quote_source")
    if quote is not None and str(quote).strip():
        mapped = format_quote_source_display(quote)
        if mapped and mapped not in {"-", "미수신"}:
            return mapped
    flow_src = str(row.get("flow_data_source", "") or "").strip()
    if not flow_src or flow_src.lower() in {"미수신", "missing", "unknown", "no_data"}:
        return "미수신"
    parts: list[str] = []
    for token in flow_src.replace("+", ",").split(","):
        piece = format_quote_source_display(token.strip())
        if piece and piece not in {"-", "미수신"} and piece not in parts:
            parts.append(piece)
    return " · ".join(parts) if parts else flow_src


@st.cache_data(ttl=120, show_spinner=False)
def _build_intraday_symbol_name_map(market: str) -> dict[str, str]:
    """후보 CSV·관심종목·보유종목에서 symbol→name (표시용)."""
    market_norm = _normalize_app_market(market) or market
    names: dict[str, str] = {}
    for path in _candidate_csv_paths_for_market(market_norm):
        try:
            df = read_csv_cached(path)
        except Exception:
            continue
        if df.empty:
            continue
        sym_col = next((c for c in ("symbol", "ticker", "종목코드", "종목") if c in df.columns), None)
        if not sym_col:
            continue
        name_col = next((c for c in ("name", "종목명", "symbol_name") if c in df.columns), None)
        for _, row in df.iterrows():
            raw_sym = str(row.get(sym_col, "")).strip().upper()
            if not raw_sym:
                continue
            sym = display_symbol(raw_sym, market_norm) if market_norm == "미국주식" else normalize_ticker(raw_sym, market_norm)
            nm = str(row.get(name_col, "") or "").strip() if name_col else ""
            if nm and sym not in names:
                names[sym] = nm
    try:
        wl = load_watchlist_df(market_norm)
        if wl is not None and not wl.empty and "symbol" in wl.columns:
            for _, row in wl.iterrows():
                raw_sym = str(row.get("symbol", "")).strip().upper()
                if not raw_sym:
                    continue
                sym = display_symbol(raw_sym, market_norm) if market_norm == "미국주식" else normalize_ticker(raw_sym, market_norm)
                nm = str(row.get("name", "") or "").strip()
                if nm and sym not in names:
                    names[sym] = nm
    except Exception:
        pass
    hold_paths = (
        [Path("holdings_us.csv"), Path("data/holdings_us.csv")]
        if market_norm == "미국주식"
        else [Path("holdings_kr.csv"), Path("data/holdings_kr.csv")]
    )
    for path in hold_paths:
        try:
            if not path.exists():
                continue
            hdf = read_csv_cached(path)
        except Exception:
            continue
        if hdf.empty:
            continue
        sym_col = next((c for c in ("ticker", "symbol", "종목코드") if c in hdf.columns), None)
        if not sym_col:
            continue
        name_col = next((c for c in ("name", "종목명") if c in hdf.columns), None)
        for _, row in hdf.iterrows():
            raw_sym = str(row.get(sym_col, "")).strip().upper()
            if not raw_sym:
                continue
            sym = display_symbol(raw_sym, market_norm) if market_norm == "미국주식" else normalize_ticker(raw_sym, market_norm)
            nm = str(row.get(name_col, "") or "").strip() if name_col else ""
            if nm and sym not in names:
                names[sym] = nm
    return names


def _us_flow_row_key(symbol: Any, market: Any) -> tuple[str, str]:
    sym = str(symbol or "").strip().upper()
    mkt = str(market or "").strip() or "미국주식"
    if _is_us_market_label(mkt):
        sym = display_symbol(sym, "미국주식")
    return sym, mkt


def _merge_us_intraday_flow_for_display(
    flow_df: pd.DataFrame,
    realtime_df: pd.DataFrame,
    orderbook_df: pd.DataFrame,
    *,
    market: str | None = None,
) -> pd.DataFrame:
    """미국주식 flow/realtime/orderbook CSV 병합 (렌더 시 API 호출 없음)."""
    rt_index = _intraday_snapshot_index(realtime_df)
    ob_index = _intraday_snapshot_index(orderbook_df)
    name_map = _build_intraday_symbol_name_map(market or "미국주식")

    keys: set[tuple[str, str]] = set()
    flow_by_key: dict[tuple[str, str], dict[str, Any]] = {}
    if flow_df is not None and not flow_df.empty and "symbol" in flow_df.columns:
        for _, row in flow_df.iterrows():
            if "market" in flow_df.columns and not _is_us_market_label(row.get("market", market)):
                continue
            sym, mkt = _us_flow_row_key(row.get("symbol"), row.get("market", market))
            if not sym:
                continue
            keys.add((sym, mkt))
            flow_by_key[(sym, mkt)] = row.to_dict()

    for df in (realtime_df, orderbook_df):
        if df is None or df.empty or "symbol" not in df.columns:
            continue
        for _, row in df.iterrows():
            if "market" in df.columns and not _is_us_market_label(row.get("market", market)):
                continue
            sym, mkt = _us_flow_row_key(row.get("symbol"), row.get("market", market))
            if sym:
                keys.add((sym, mkt))

    rows: list[dict[str, Any]] = []
    for sym, mkt in sorted(keys):
        flow = flow_by_key.get((sym, mkt), {})
        rt = rt_index.get((sym, mkt)) or rt_index.get((sym, ""), {})
        ob = ob_index.get((sym, mkt)) or ob_index.get((sym, ""), {})
        srcs = (flow, rt, ob)

        merged: dict[str, Any] = dict(flow)
        merged.update({
            "symbol": sym,
            "market": mkt,
            "flow_mode": str(merged.get("flow_mode") or "us_momentum"),
            "last_price": _flow_pick_first(*srcs, keys=("last_price", "current_price", "quote_fallback_price")),
            "intraday_change_pct": _flow_pick_first(*srcs, keys=("intraday_change_pct",)),
            "intraday_volume": _flow_pick_first(*srcs, keys=("intraday_volume",)),
            "intraday_trading_value": _flow_pick_first(*srcs, keys=("intraday_trading_value",)),
            "volume_growth_pct": _flow_pick_first(
                *srcs, keys=("volume_growth_pct", "intraday_volume_ratio")
            ),
            "trading_value_growth_pct": _flow_pick_first(
                *srcs, keys=("trading_value_growth_pct", "intraday_trading_value_ratio")
            ),
            "execution_strength": _flow_pick_first(*srcs, keys=("execution_strength",)),
            "orderbook_pressure": _flow_pick_first(
                *srcs, keys=("orderbook_pressure", "orderbook_imbalance")
            ),
            "intraday_momentum_score": _flow_pick_first(*srcs, keys=("intraday_momentum_score",)),
            "quote_source": _flow_pick_first(rt, flow, keys=("quote_source",)),
            "quote_source_label": _flow_pick_first(rt, flow, keys=("quote_source_label",)),
            "orderbook_fetch_status": _flow_pick_first(ob, flow, keys=("orderbook_fetch_status",)),
        })
        nm = _flow_pick_first(flow, rt, keys=("name", "symbol_name")) or name_map.get(sym, "")
        merged["name"] = str(nm).strip() if nm else ""

        series = pd.Series(merged)
        has_quote = _us_flow_metric_present(
            series, "last_price", "current_price", "quote_fallback_price"
        )
        has_vol_tv = _us_flow_metric_present(series, "intraday_volume", "intraday_trading_value")
        quote_ok = _row_bool(rt.get("quote_available"), False) if rt else False
        merged["flow_data_available"] = bool(
            has_quote or has_vol_tv or quote_ok or _row_bool(flow.get("flow_data_available"), False)
        )
        if not merged.get("flow_data_source"):
            merged["flow_data_source"] = _flow_pick_first(rt, flow, keys=("flow_data_source", "intraday_data_source")) or ""
        rows.append(merged)

    return pd.DataFrame(rows)


def _merge_intraday_flow_for_display(
    flow_df: pd.DataFrame,
    realtime_df: pd.DataFrame,
    orderbook_df: pd.DataFrame,
    *,
    market: str | None = None,
) -> pd.DataFrame:
    """한국은 flow CSV 그대로, 미국은 realtime/orderbook 병합."""
    if flow_df is None:
        flow_df = pd.DataFrame()
    market_norm = _normalize_app_market(market) or market

    if flow_df.empty:
        if market_norm == "미국주식":
            return _merge_us_intraday_flow_for_display(flow_df, realtime_df, orderbook_df, market=market_norm)
        return flow_df

    if "market" not in flow_df.columns:
        if market_norm == "미국주식":
            return _merge_us_intraday_flow_for_display(flow_df, realtime_df, orderbook_df, market=market_norm)
        return flow_df

    us_mask = flow_df["market"].astype(str).map(_is_us_market_label)
    kr_part = flow_df.loc[~us_mask].copy()
    us_part = flow_df.loc[us_mask].copy()
    us_merged = _merge_us_intraday_flow_for_display(
        us_part, realtime_df, orderbook_df, market=market_norm or "미국주식"
    )
    if kr_part.empty:
        return us_merged
    if us_merged.empty:
        return kr_part
    return pd.concat([kr_part, us_merged], ignore_index=True)


def _flow_metric_display(row: pd.Series, col: str) -> str:
    if col in {"foreign_net_buy", "institution_net_buy", "individual_net_buy", "program_net_buy"}:
        return _flow_net_display_value(row, col)
    value = row.get(col)
    if value is None:
        return "미수신"
    text = str(value).strip()
    if text.lower() in {"", "nan", "none", "nat", "-"}:
        return "미수신"
    num = safe_float(value, np.nan)
    if math.isnan(num):
        return text if text else "미수신"
    if col.endswith("_pct") or col in {"intraday_change_pct", "orderbook_pressure"}:
        return f"{num:.2f}%"
    if abs(num) >= 1:
        return f"{num:,.2f}"
    return f"{num:.4f}"


def prepare_intraday_kr_flow_display(df: pd.DataFrame, *, limit: int = 80) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    view = df.head(limit).copy()
    rows: list[dict[str, Any]] = []
    for _, row in view.iterrows():
        available = _row_bool(row.get("flow_data_available"), False)
        label = str(row.get("intraday_flow_label", "") or "").strip()
        warning = str(row.get("intraday_flow_warning", "") or "").strip()
        if not available:
            label = "수급 판단 보류"
            warning = warning or "장마감/장전/API 미수신 가능성"
        sym = str(row.get("symbol", "") or "").strip()
        nm = str(row.get("name", "") or row.get("stock_name", "") or row.get("종목명", "") or "")
        if sym and not nm:
            nm = korean_name_from_symbol(sym, sym)
        rows.append({
            "종목코드": sym,
            "종목명": nm or "-",
            "시장": row.get("market", ""),
            "외국인 수급": _flow_net_display_value(row, "foreign_net_buy"),
            "기관 수급": _flow_net_display_value(row, "institution_net_buy"),
            "개인 수급": _flow_net_display_value(row, "individual_net_buy"),
            "프로그램 수급": _flow_net_display_value(row, "program_net_buy"),
            "수급 상태": label or "-",
            "수급 경고": warning or "-",
            "수급 점수": row.get("intraday_flow_score", "-"),
        })
    return pd.DataFrame(rows)


def prepare_intraday_us_flow_display(df: pd.DataFrame, *, limit: int = 80) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    view = df.head(limit).copy()
    rows: list[dict[str, Any]] = []
    for _, row in view.iterrows():
        warning = str(row.get("intraday_flow_warning", row.get("flow_warning", "")) or "").strip()
        if not warning and _us_flow_data_status(row) == "미수신":
            warning = "장중 수급 대체 지표 미수신"
        name = str(row.get("name", row.get("symbol_name", "")) or "").strip() or "-"
        exec_disp = _us_flow_metric_display(row, "execution_strength")
        ob_status = str(row.get("orderbook_fetch_status", "")).strip().lower()
        if exec_disp == "미수신" and ob_status in {
            "unsupported", "unsupported_market", "market_closed"
        }:
            exec_disp = "미지원 가능"
        rows.append({
            "종목코드": row.get("symbol", ""),
            "종목명": name,
            "현재가": _us_flow_metric_display(row, "last_price", "current_price", "quote_fallback_price"),
            "등락률": _us_flow_metric_display(row, "intraday_change_pct"),
            "거래량": _us_flow_metric_display(row, "intraday_volume"),
            "거래대금": _us_flow_metric_display(row, "intraday_trading_value"),
            "거래량 증가율": _us_flow_metric_display(
                row, "volume_growth_pct", "intraday_volume_ratio"
            ),
            "거래대금 증가율": _us_flow_metric_display(
                row, "trading_value_growth_pct", "intraday_trading_value_ratio"
            ),
            "체결강도": exec_disp,
            "호가 압력": _us_flow_metric_display(row, "orderbook_pressure", "orderbook_imbalance"),
            "장중 모멘텀": _us_flow_momentum_display(row),
            "데이터 상태": _us_flow_data_status(row),
            "데이터 출처": _us_flow_source_display(row),
            "수급 경고": warning or "-",
        })
    return pd.DataFrame(rows)


def render_intraday_flow_table(df: pd.DataFrame, *, limit: int = 80, empty_label: str = "표시할 수급·프로그램 데이터 없음") -> None:
    if df is None or df.empty:
        st.info(empty_label)
        return
    kr_df = df.loc[df["market"].astype(str).map(_is_kr_market_label)] if "market" in df.columns else pd.DataFrame()
    us_df = df.loc[df["market"].astype(str).map(_is_us_market_label)] if "market" in df.columns else pd.DataFrame()
    if kr_df.empty and us_df.empty:
        kr_df = df.loc[~df["market"].astype(str).map(_is_us_market_label)] if "market" in df.columns else df
        us_df = df.loc[df["market"].astype(str).map(_is_us_market_label)] if "market" in df.columns else pd.DataFrame()

    if not kr_df.empty:
        st.markdown("**한국주식 수급**")
        st.caption(_INTRADAY_FLOW_GUIDANCE_KR)
        try:
            kr_display = prepare_intraday_kr_flow_display(kr_df, limit=limit)
        except Exception:
            kr_display = pd.DataFrame()
        if kr_display.empty:
            st.info("표시할 한국주식 수급 데이터 없음")
        else:
            st.dataframe(kr_display, use_container_width=True, hide_index=True)

    if not us_df.empty:
        st.markdown("**미국주식 장중 수급 대체**")
        st.caption(_INTRADAY_FLOW_GUIDANCE_US)
        try:
            us_display = prepare_intraday_us_flow_display(us_df, limit=limit)
        except Exception:
            us_display = pd.DataFrame()
        if us_display.empty:
            st.info("표시할 미국주식 장중 수급 대체 데이터 없음")
        else:
            st.dataframe(us_display, use_container_width=True, hide_index=True)

    if kr_df.empty and us_df.empty:
        st.info(empty_label)


def format_user_facing_status_label(status: Any) -> str:
    text = str(status or "").strip()
    upper = text.upper()
    if upper in {"OK_WITH_NOTICE", "OK WITH NOTICE"}:
        return "정상 · 주의 있음"
    if upper == "OK":
        return "정상"
    if upper == "WARNING":
        return "주의"
    if upper == "ERROR":
        return "오류"
    if upper in {"MARKET_CLOSED", "CLOSED"}:
        return "장마감/장전"
    return text or "-"


def format_intraday_reception_rate(
    rate: float,
    coverage: dict[str, Any] | None = None,
    *,
    data_type: str | None = None,
    market: str | None = None,
) -> str:
    """장마감/미지원/정상 수신률을 데이터 종류·시장별로 구분해 표시한다."""
    cov = coverage or {}
    pct = f"{float(rate or 0.0) * 100:.1f}%"
    market_norm = _normalize_app_market(market)
    mc = cov.get("market_coverage") if isinstance(cov.get("market_coverage"), dict) else {}
    if market_norm == "미국주식" and isinstance(mc.get("미국주식"), dict):
        if data_type == "quote":
            rate = float(mc["미국주식"].get("quote_available_rate", rate) or 0.0)
        elif data_type == "orderbook":
            rate = float(mc["미국주식"].get("orderbook_available_rate", rate) or 0.0)
        elif data_type == "flow":
            rate = float(mc["미국주식"].get("flow_available_rate", rate) or 0.0)
        pct = f"{rate * 100:.1f}%"
        if rate <= 0.001:
            return f"미수신 · {pct}"
        return pct
    if market_norm == "한국주식" and isinstance(mc.get("한국주식"), dict):
        if data_type == "quote":
            rate = float(mc["한국주식"].get("quote_available_rate", rate) or 0.0)
        elif data_type == "orderbook":
            rate = float(mc["한국주식"].get("orderbook_available_rate", rate) or 0.0)
        elif data_type == "flow":
            rate = float(mc["한국주식"].get("flow_available_rate", rate) or 0.0)
        pct = f"{rate * 100:.1f}%"
        if rate <= 0.001:
            return f"장마감/장전 · {pct}"
        return pct

    target = int(cov.get("total_symbol_count", cov.get("target_count", 0)) or 0)
    market_closed = int(cov.get("market_closed_count", 0) or 0)
    if data_type in {"orderbook", "flow"} and float(rate or 0.0) <= 0.001:
        us_unsup = 0
        if isinstance(mc.get("미국주식"), dict):
            key = "orderbook_available_rate" if data_type == "orderbook" else "flow_available_rate"
            us_unsup = int(mc["미국주식"].get("symbol_count", 0) or 0) if float(mc["미국주식"].get(key, 0) or 0) <= 0 else 0
        if us_unsup > 0 and market_closed < max(1, target - us_unsup):
            return f"미지원(API) · {pct}"
    if target > 0 and market_closed >= max(1, int(target * 0.8)):
        return f"장마감/장전 · {pct}"
    if float(rate or 0.0) <= 0.001 and market_closed > 0 and data_type == "quote":
        return f"장마감/장전 · {pct}"
    return pct


