# v3.8 자동 운영 보강 기능
# ══════════════════════════════════════════════
def read_market_holidays() -> dict[str, set[date]]:
    """market_holidays.csv가 있으면 휴장일을 읽는다. 없으면 빈 값으로 둔다."""
    holidays: dict[str, set[date]] = {"미국주식": set(), "한국주식": set()}
    if not HOLIDAY_FILE.exists():
        return holidays
    try:
        df = pd.read_csv(HOLIDAY_FILE)
        for _, r in df.iterrows():
            m = str(r.get("market", "")).strip()
            d = pd.to_datetime(r.get("date"), errors="coerce")
            if pd.isna(d):
                continue
            if m in holidays:
                holidays[m].add(d.date())
    except Exception:
        pass
    return holidays


def is_trading_day_auto(market: str, d: date) -> bool:
    """주말 + 선택적 휴장일 CSV + pandas_market_calendars를 사용한 보수적 거래일 판단."""
    if d.weekday() >= 5:
        return False
    holidays = read_market_holidays()
    if d in holidays.get(market, set()):
        return False
    try:
        import pandas_market_calendars as mcal
        cal_name = "NYSE" if market == "미국주식" else "XKRX"
        cal = mcal.get_calendar(cal_name)
        sched = cal.schedule(start_date=str(d), end_date=str(d))
        return not sched.empty
    except Exception:
        return True


def next_trading_day_auto(market: str, d: date) -> date:
    """다음 거래일을 자동 계산. 외부 캘린더 실패 시 주말만 피한다."""
    cur = d + timedelta(days=1)
    guard = 0
    while guard < 14:
        if is_trading_day_auto(market, cur):
            return cur
        cur += timedelta(days=1)
        guard += 1
    return next_weekday(d)


def backup_predictions_file(reason: str = "manual") -> str:
    """predictions.csv 자동 백업."""
    if not PREDICTION_FILE.exists():
        return ""
    BACKUP_DIR.mkdir(exist_ok=True)
    stamp = datetime.now(KST).strftime("%Y%m%d_%H%M%S")
    out = BACKUP_DIR / f"predictions_backup_{stamp}_{reason}.csv"
    try:
        shutil.copy2(PREDICTION_FILE, out)
        return str(out)
    except Exception:
        return ""


def auto_failure_reason_tags_from_row(row: pd.Series) -> str:
    """실제 결과 업데이트 후 예측 실패 원인을 자동 태그로 추정."""
    tags: list[str] = []
    try:
        open_err = safe_float(row.get("open_error_pct"), np.nan)
        close_err = safe_float(row.get("close_error_pct"), np.nan)
        open_in = str(row.get("open_in_range", "")).lower() in ("true", "1")
        close_in = str(row.get("close_in_range", "")).lower() in ("true", "1")
        pm_gap = safe_float(row.get("premarket_gap_pct"), np.nan)
        risk_mult = safe_float(row.get("event_risk_mult"), 1.0)
        news = safe_float(row.get("news_score"), 0.0)
        event_label = str(row.get("event_label", ""))

        if not open_in and abs(open_err) >= 1.0:
            tags.append("시초가 범위 이탈")
        if not close_in and abs(close_err) >= 1.5:
            tags.append("종가 범위 이탈")
        if not np.isnan(pm_gap) and abs(pm_gap) >= 2.5 and not open_in:
            tags.append("프리마켓 과대/과소 반영")
        if risk_mult >= 1.45 or any(k in event_label for k in ["FOMC", "CPI", "PPI", "고용", "실적"]):
            tags.append("이벤트 변동성")
        if news < 0 and close_err < -1:
            tags.append("악재 반영 부족")
        if str(row.get("stop_touched", "")).lower() in ("true", "1"):
            tags.append("손절가 도달")
        if str(row.get("entry_touched", "")).lower() not in ("true", "1"):
            tags.append("진입가 미도달")
    except Exception:
        pass
    return " | ".join(dict.fromkeys(tags)) if tags else ""


def enrich_failure_tags(log_df: pd.DataFrame) -> pd.DataFrame:
    """업데이트된 기록에 자동 실패 태그를 채운다."""
    if log_df.empty:
        return log_df
    df = log_df.copy()
    if "auto_failure_tags" not in df.columns:
        df["auto_failure_tags"] = ""
    for idx, row in df.iterrows():
        if pd.notna(row.get("actual_close")) and not str(row.get("auto_failure_tags", "")).strip():
            df.loc[idx, "auto_failure_tags"] = auto_failure_reason_tags_from_row(row)
    return df


def classify_candidate_display(df: pd.DataFrame) -> pd.DataFrame:
    """후보 스캐너 결과를 돌파/눌림/관망/매수금지로 분류."""
    if df is None or df.empty:
        return df
    out = df.copy()

    def _score(row):
        for c in ["순위점수", "score", "점수"]:
            if c in row:
                return safe_float(row.get(c), 0)
        return 0

    def _warn(row):
        txt = " ".join(str(row.get(c, "")) for c in ["주의사유", "탈락/주의사유", "매수금지", "회피조건"])
        return txt

    classes = []
    for _, r in out.iterrows():
        s = _score(r)
        warn = _warn(r)
        if any(k in warn for k in ["추격", "과열", "손익비", "실적", "대형 이벤트", "급등락"]):
            classes.append("매수주의/조건확인")
        elif s >= 82:
            classes.append("돌파 후보")
        elif s >= 70:
            classes.append("눌림목 후보")
        elif s >= 58:
            classes.append("관찰 후보")
        else:
            classes.append("관망 후보")
    out.insert(1, "후보분류", classes)
    return out


def no_buy_candidates_from_scan(scan_df: pd.DataFrame) -> pd.DataFrame:
    """스캐너 결과 중 매수 주의/금지 후보만 추출."""
    if scan_df is None or scan_df.empty:
        return pd.DataFrame()
    warn_cols = [c for c in ["주의사유", "탈락/주의사유", "매수금지", "회피조건"] if c in scan_df.columns]
    if not warn_cols:
        return pd.DataFrame()
    mask = pd.Series(False, index=scan_df.index)
    for c in warn_cols:
        s = scan_df[c].astype(str)
        mask |= s.ne("-") & s.ne("") & ~s.str.lower().isin(["nan", "none"])
    cols = [c for c in ["종목", "회사명", "후보분류", "순위점수", "주문판단", "주의사유", "탈락/주의사유", "매수금지", "회피조건"] if c in scan_df.columns]
    return scan_df.loc[mask, cols].head(15)




def _safe_file_mtime(path: Path) -> datetime | None:
    try:
        return datetime.fromtimestamp(path.stat().st_mtime, tz=KST)
    except Exception:
        return None


def _fmt_dt(dt: datetime | None) -> str:
    if not dt:
        return "-"
    try:
        return dt.strftime("%Y-%m-%d %H:%M:%S")
    except Exception:
        return "-"


def read_last_lines(path: Path, n: int = 40) -> str:
    try:
        text = path.read_text(encoding="utf-8", errors="ignore")
        return "\n".join(text.splitlines()[-n:])
    except Exception:
        return ""


def runner_log_status(path: Path) -> dict[str, Any]:
    """logs 폴더의 runner 로그를 읽어 성공/오류/진행상태를 추정."""
    tail = read_last_lines(path, 80)
    status = "확인필요"
    if "[runner] done" in tail:
        status = "정상"
    elif "Traceback" in tail or "[runner] ERROR" in tail or "Error" in tail or "ERROR" in tail:
        status = "오류"
    elif tail.strip():
        status = "진행중/중단가능"
    return {
        "파일": path.name,
        "수정시각": _fmt_dt(_safe_file_mtime(path)),
        "상태": status,
        "마지막내용": tail[-250:].replace("\n", " / ") if tail else "",
    }


def automation_status_df() -> pd.DataFrame:
    """자동 runner 실행 상태 요약."""
    logs_dir = Path("logs")
    expected = [
        "runner_us_update.log",
        "runner_us_predict.log",
        "runner_kr_update.log",
        "runner_kr_predict.log",
    ]
    rows = []
    for name in expected:
        p = logs_dir / name
        if p.exists():
            rows.append(runner_log_status(p))
        else:
            rows.append({"파일": name, "수정시각": "-", "상태": "미실행", "마지막내용": ""})
    return pd.DataFrame(rows)


def prediction_duplicate_mask(log_df: pd.DataFrame) -> pd.Series:
    """같은 시장+종목+예측대상일 중 최신 1건을 제외한 중복 기록 표시."""
    if log_df is None or log_df.empty:
        return pd.Series(dtype=bool)
    df = log_df.copy()
    required = ["market", "ticker", "target_date"]
    for c in required:
        if c not in df.columns:
            return pd.Series(False, index=df.index)

    created = pd.to_datetime(df.get("created_at"), errors="coerce") if "created_at" in df.columns else pd.Series(pd.NaT, index=df.index)
    df["_created_dt"] = created
    # 실제 결과가 이미 반영된 기록은 복기용이므로 중복 정리 대상에서 제외
    actual_done = pd.to_numeric(df.get("actual_close"), errors="coerce").notna() if "actual_close" in df.columns else pd.Series(False, index=df.index)
    pending_idx = df.index[~actual_done]
    if len(pending_idx) == 0:
        return pd.Series(False, index=df.index)

    pending = df.loc[pending_idx].sort_values("_created_dt", ascending=False)
    dup = pending.duplicated(subset=required, keep="first")
    mask = pd.Series(False, index=df.index)
    mask.loc[pending.index[dup]] = True
    return mask


def duplicate_summary(log_df: pd.DataFrame) -> dict[str, Any]:
    if log_df is None or log_df.empty:
        return {"duplicate_rows": 0, "duplicate_groups": 0}
    mask = prediction_duplicate_mask(log_df)
    groups = 0
    if mask.any():
        d = log_df.loc[mask].copy()
        groups = d.groupby(["market", "ticker", "target_date"], dropna=False).ngroups if all(c in d.columns for c in ["market", "ticker", "target_date"]) else 0
    return {"duplicate_rows": int(mask.sum()), "duplicate_groups": int(groups)}


def cleanup_duplicate_predictions(log_df: pd.DataFrame) -> tuple[pd.DataFrame, int]:
    """미완료 예측 중 중복 기록을 제거하고 최신 1건만 유지."""
    if log_df is None or log_df.empty:
        return log_df, 0
    mask = prediction_duplicate_mask(log_df)
    removed = int(mask.sum())
    if removed <= 0:
        return log_df, 0
    cleaned = log_df.loc[~mask].copy()
    backup_predictions_file("before_duplicate_cleanup")
    cleaned.to_csv(PREDICTION_FILE, index=False, encoding="utf-8-sig")
    return cleaned, removed


def prediction_data_status(log_df: pd.DataFrame, market: str | None = None) -> pd.DataFrame:
    """predictions.csv 기준 데이터 최신성/반영상태 요약."""
    if log_df is None or log_df.empty:
        return pd.DataFrame()
    df = log_df.copy()
    if market and "market" in df.columns:
        df = df[df["market"].astype(str).eq(market)]
    df = drop_excluded_us_stock_rows(df, market)
    if df.empty:
        return pd.DataFrame()

    rows = []
    for mk, g in df.groupby("market" if "market" in df.columns else lambda _: "전체"):
        total = len(g)
        pending = pd.to_numeric(g.get("actual_close"), errors="coerce").isna().sum() if "actual_close" in g.columns else total
        done = total - pending
        latest_created = pd.to_datetime(g.get("created_at"), errors="coerce").max() if "created_at" in g.columns else pd.NaT
        latest_target = pd.to_datetime(g.get("target_date"), errors="coerce").max() if "target_date" in g.columns else pd.NaT
        latest_data = pd.to_datetime(g.get("data_date"), errors="coerce").max() if "data_date" in g.columns else pd.NaT
        latest_actual = pd.to_datetime(g.get("actual_date"), errors="coerce").max() if "actual_date" in g.columns else pd.NaT
        dup = duplicate_summary(g)
        rows.append({
            "시장": mk,
            "전체기록": total,
            "실제반영완료": done,
            "미완료예측": int(pending),
            "중복예측": dup["duplicate_rows"],
            "최근예측저장": str(latest_created)[:19] if not pd.isna(latest_created) else "-",
            "최근예측대상일": str(latest_target.date()) if not pd.isna(latest_target) else "-",
            "최근기준데이터일": str(latest_data.date()) if not pd.isna(latest_data) else "-",
            "최근실제반영일": str(latest_actual.date()) if not pd.isna(latest_actual) else "-",
        })
    return pd.DataFrame(rows)


def failure_review_df(log_df: pd.DataFrame, market: str | None = None, limit: int = 80) -> pd.DataFrame:
    """예측 실패/오차 큰 기록 복기용 표."""
    if log_df is None or log_df.empty:
        return pd.DataFrame()
    df = log_df.copy()
    if market and "market" in df.columns:
        df = df[df["market"].astype(str).eq(market)]
    if df.empty or "actual_close" not in df.columns:
        return pd.DataFrame()

    done = df[pd.to_numeric(df.get("actual_close"), errors="coerce").notna()].copy()
    if done.empty:
        return pd.DataFrame()

    # 실패 조건
    open_abs = pd.to_numeric(done.get("open_abs_error_pct"), errors="coerce")
    close_abs = pd.to_numeric(done.get("close_abs_error_pct"), errors="coerce")
    open_in = done.get("open_in_range", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"])
    close_in = done.get("close_in_range", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"])
    stop_touch = done.get("stop_touched", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"])
    high_conf = pd.to_numeric(done.get("confidence_score"), errors="coerce").fillna(0) >= 70

    fail_mask = (
        (open_abs >= 1.5)
        | (close_abs >= 2.0)
        | (~open_in)
        | (~close_in)
        | stop_touch
        | (high_conf & (close_abs >= 1.5))
    )
    out = done.loc[fail_mask].copy()
    if out.empty:
        return pd.DataFrame()

    if "auto_failure_tags" not in out.columns:
        out = enrich_failure_tags(out)

    def _reason(row):
        reasons = []
        if safe_float(row.get("open_abs_error_pct"), 0) >= 1.5:
            reasons.append("시초가 오차 큼")
        if safe_float(row.get("close_abs_error_pct"), 0) >= 2.0:
            reasons.append("종가 오차 큼")
        if str(row.get("open_in_range", "")).lower() not in ("true", "1"):
            reasons.append("시초가 범위 이탈")
        if str(row.get("close_in_range", "")).lower() not in ("true", "1"):
            reasons.append("종가 범위 이탈")
        if str(row.get("stop_touched", "")).lower() in ("true", "1"):
            reasons.append("손절가 도달")
        if safe_float(row.get("confidence_score"), 0) >= 70 and safe_float(row.get("close_abs_error_pct"), 0) >= 1.5:
            reasons.append("고신뢰도 예측 실패")
        tag = str(row.get("auto_failure_tags", ""))
        if tag and tag not in ["nan", "None"]:
            reasons.append(tag)
        return " / ".join(dict.fromkeys(reasons))

    out["복기포인트"] = out.apply(_reason, axis=1)
    if "created_at" in out.columns:
        out["_created_dt"] = pd.to_datetime(out["created_at"], errors="coerce")
        out = out.sort_values("_created_dt", ascending=False)

    cols = [
        "target_date", "ticker", "confidence_score", "actual_open", "actual_close",
        "open_abs_error_pct", "close_abs_error_pct", "open_in_range", "close_in_range",
        "stop_touched", "tp1_touched", "auto_failure_tags", "복기포인트",
    ]
    return to_korean_display(out[[c for c in cols if c in out.columns]], compact=False).head(limit)




def _string_has_real_warning(value: Any) -> bool:
    txt = str(value or "").strip()
    if txt in {"", "-", "nan", "None", "[]", "{}"}:
        return False
    return True


def assess_execution_grade(raw_row: pd.Series, log_df: pd.DataFrame, market: str) -> dict[str, Any]:
    """
    실전 매매 의사결정 엔진.
    예측 신뢰도와 매매 적합도를 분리한 뒤, 실제 주문 관점에서 제외/관망/조건부/진입 후보를 판단한다.
    """
    conf, conf_notes = calibrated_confidence_for_row(raw_row, log_df, market)
    fit, fit_label, fit_notes = trade_suitability_for_row(raw_row, conf)
    stats = symbol_prediction_stats(log_df, str(raw_row.get("ticker", "")), market)

    entry = safe_float(raw_row.get("preferred_entry"), np.nan)
    stop = safe_float(raw_row.get("stop_loss"), np.nan)
    tp1 = safe_float(raw_row.get("take_profit1"), np.nan)
    tp2 = safe_float(raw_row.get("take_profit2"), np.nan)
    prev = safe_float(raw_row.get("prev_close"), np.nan)
    rr1 = safe_float(raw_row.get("rr1"), np.nan)

    stop_gap = abs(entry - stop) / entry * 100 if entry and not np.isnan(stop) else np.nan
    upside1 = (tp1 - entry) / entry * 100 if entry and not np.isnan(tp1) else np.nan
    expected_mid = safe_float(raw_row.get("pred_close_mid"), np.nan)
    expected_pct = (expected_mid / prev - 1) * 100 if prev and not np.isnan(expected_mid) else np.nan
    event_mult = safe_float(raw_row.get("event_risk_mult"), 1.0)
    warning_text = str(raw_row.get("no_buy_flags", "") or raw_row.get("auto_failure_tags", "") or "")
    has_warning = _string_has_real_warning(warning_text)

    reasons: list[str] = []
    decision = "관망"
    order_type = "주문 보류"
    priority = 0

    if conf < 55:
        reasons.append("보정신뢰도 55점 미만")
    if fit < 55:
        reasons.append("매매적합도 55점 미만")
    if not np.isnan(rr1) and rr1 < 1.0:
        reasons.append("손익비 1.0 미만")
    if not np.isnan(stop_gap) and stop_gap > 8:
        reasons.append("손절폭 8% 초과")
    if has_warning:
        reasons.append("주의사유 존재")
    if event_mult >= 1.55:
        reasons.append("대형 이벤트 변동성")
    if stats.get("history_count", 0) < 5:
        reasons.append("예측 기록 5건 미만")

    hard_exclude = (
        conf < 50
        or fit < 50
        or (not np.isnan(rr1) and rr1 < 0.9)
        or (not np.isnan(stop_gap) and stop_gap > 10)
    )

    if hard_exclude:
        decision = "제외"
        order_type = "매수 금지"
        priority = 0
    elif has_warning or event_mult >= 1.55 or stats.get("history_count", 0) < 5:
        decision = "조건부 관찰"
        order_type = "확인 후 지정가"
        priority = max(20, min(69, int(conf * 0.45 + fit * 0.35)))
    elif conf >= 78 and fit >= 75 and (np.isnan(rr1) or rr1 >= 1.5) and (np.isnan(stop_gap) or stop_gap <= 6):
        decision = "진입 후보"
        order_type = "지정가 대기"
        priority = int(min(100, conf * 0.45 + fit * 0.45 + 10))
    elif conf >= 70 and fit >= 68 and (np.isnan(rr1) or rr1 >= 1.3):
        decision = "조건부 진입"
        order_type = "눌림 확인 지정가"
        priority = int(min(89, conf * 0.45 + fit * 0.45))
    else:
        decision = "관망"
        order_type = "추가 확인"
        priority = int(max(10, min(65, conf * 0.4 + fit * 0.35)))

    if not reasons:
        reasons.append("핵심 조건 충족")

    return {
        "ticker": str(raw_row.get("ticker", "")),
        "decision": decision,
        "order_type": order_type,
        "priority": priority,
        "conf": conf,
        "fit": fit,
        "rr1": rr1,
        "stop_gap": stop_gap,
        "upside1": upside1,
        "expected_pct": expected_pct,
        "entry": entry,
        "stop": stop,
        "tp1": tp1,
        "tp2": tp2,
        "reasons": reasons,
        "conf_notes": conf_notes,
        "fit_notes": fit_notes,
        "history_count": stats.get("history_count", 0),
        "recent_close_error": stats.get("avg_close_abs_error", np.nan),
    }


def build_execution_plan_df(
    pending_df: pd.DataFrame,
    log_df: pd.DataFrame,
    market: str,
    account_size: float,
    available_cash: float,
    risk_pct: float,
    max_position_pct: float,
    allow_fractional: bool = False,
) -> pd.DataFrame:
    """리스크 기반 주문 수량/금액 계산표.

    session_state 운용 기준(계좌·현금·손실허용·최대비중)을 그대로 사용한다.
    """
    if pending_df is None or pending_df.empty:
        return pd.DataFrame()
    pending_df = drop_excluded_us_stock_rows(pending_df, market)
    if pending_df.empty:
        return pd.DataFrame()

    account_size = safe_float(account_size, 0.0)
    available_cash = safe_float(available_cash, account_size)
    risk_pct = safe_float(risk_pct, 0.7)
    max_position_pct = safe_float(max_position_pct, 20.0)

    rows = []
    risk_budget = max(0.0, account_size * risk_pct / 100)
    max_position_by_pct = max(0.0, account_size * max_position_pct / 100)
    max_position = max(0.0, min(available_cash, max_position_by_pct))

    for _, raw in pending_df.iterrows():
        a = assess_execution_grade(raw, log_df, market)
        entry = a["entry"]
        stop = a["stop"]

        risk_per_share = np.nan
        qty = 0.0
        order_amount = 0.0
        risk_amount = 0.0
        qty_reason = "계산 불가"

        if np.isnan(entry) or np.isnan(stop) or entry <= 0 or stop <= 0 or entry <= stop:
            qty_reason = "진입가/손절가 기준 부족"
        else:
            risk_per_share = entry - stop
            qty_by_risk = risk_budget / risk_per_share if risk_per_share > 0 else 0
            qty_by_cap = max_position / entry if entry > 0 else 0
            raw_qty = max(0.0, min(qty_by_risk, qty_by_cap))

            if market == "미국주식" and allow_fractional:
                qty = math.floor(raw_qty * 1000) / 1000
            else:
                qty = math.floor(raw_qty)

            order_amount = qty * entry
            risk_amount = qty * risk_per_share

            if qty <= 0:
                qty_reason = "리스크/현금 한도상 매수 단위 0"
            elif qty_by_risk < qty_by_cap:
                qty_reason = "손절 리스크 한도 기준"
            else:
                qty_reason = "투입금액 한도 기준"

        split_plan = calculate_position_units_v994(
            entry, stop, account_size, risk_pct, max_position_pct, market,
            allow_fractional=bool(st.session_state.get("allow_fractional_shares", False)),
        )

        rows.append({
            "우선순위": a["priority"],
            "종목": a["ticker"],
            "최종판단": a["decision"],
            "주문방식": a["order_type"],
            "보정신뢰도": a["conf"],
            "매매적합도": a["fit"],
            "우선진입가": fmt_price(a["entry"], market),
            "손절가": fmt_price(a["stop"], market),
            "1차익절가": fmt_price(a["tp1"], market),
            "1주당위험": fmt_price(risk_per_share, market) if not np.isnan(safe_float(risk_per_share, np.nan)) else "-",
            "손절폭": f"{a['stop_gap']:.2f}%" if not np.isnan(a["stop_gap"]) else "-",
            "손익비": f"{a['rr1']:.2f}" if not np.isnan(a["rr1"]) else "-",
            "권장수량": units_label(qty, market),
            "예상주문금액": fmt_price(order_amount, market),
            "예상손실액": fmt_price(risk_amount, market),
            "수량근거": qty_reason,
            "판단근거": " / ".join(a["reasons"][:4]),
            "누적기록": a["history_count"],
            "최근종가오차": f"{a['recent_close_error']:.2f}%" if not pd.isna(a["recent_close_error"]) else "-",
        })

    out = pd.DataFrame(rows)
    if out.empty:
        return out
    return out.sort_values(["우선순위", "보정신뢰도", "매매적합도"], ascending=False).reset_index(drop=True)


def render_execution_plan_panel(pending_df: pd.DataFrame, log_df: pd.DataFrame, market: str) -> None:
    """실전 주문계획 패널.

    화면에서 수정한 운용 기준(session_state)을 즉시 읽어 주문 수량·금액을 계산한다.
    """
    st.markdown('<div class="dashboard-panel">', unsafe_allow_html=True)
    st.subheader("실전 주문계획")
    st.caption(
        "아래 운용 기준을 수정하면 주문계획에 바로 반영됩니다. 자동주문이 아니라 참고용 계산입니다."
    )

    c_form, c_metrics = st.columns([1, 1])
    with c_form:
        render_operation_settings_form(market, show_save_button=True)

    default_account = 10000.0 if market == "미국주식" else 10000000.0
    account_size = operation_setting_float("account_capital", default_account)
    available_cash = operation_setting_float("available_cash", account_size)
    risk_pct = operation_setting_float("risk_per_trade_pct", 0.7)
    max_position_pct = operation_setting_float("max_position_pct", 20.0)
    allow_fractional = operation_setting_bool("allow_fractional_shares", False)

    risk_budget = max(0.0, account_size * risk_pct / 100)
    max_position_by_pct = max(0.0, account_size * max_position_pct / 100)
    max_position = max(0.0, min(available_cash, max_position_by_pct))

    with c_metrics:
        st.markdown("##### 적용 운용 기준")
        b1, b2 = st.columns(2)
        b3, b4 = st.columns(2)
        with b1:
            st.metric("계좌 기준금액", fmt_price(account_size, market))
        with b2:
            st.metric("매수 가능 현금", fmt_price(available_cash, market))
        with b3:
            st.metric("손실 허용률", f"{risk_pct:.2f}%")
        with b4:
            st.metric("종목당 최대 비중", f"{max_position_pct:.2f}%")
        st.metric("1회 최대 손실", fmt_price(risk_budget, market))
        st.metric("종목당 최대 투입", fmt_price(max_position, market))

    plan = build_execution_plan_df(
        pending_df=pending_df,
        log_df=log_df,
        market=market,
        account_size=account_size,
        available_cash=available_cash,
        risk_pct=risk_pct,
        max_position_pct=max_position_pct,
        allow_fractional=allow_fractional,
    )

    if plan.empty:
        st.info("주문계획을 계산할 예측 기록이 없습니다.")
        st.markdown('</div>', unsafe_allow_html=True)
        return

    # 핵심 분류
    tradable = plan[plan["최종판단"].isin(["진입 후보", "조건부 진입"])]
    excluded = plan[plan["최종판단"].eq("제외")]
    hold = plan[plan["최종판단"].isin(["관망", "조건부 관찰"])]

    k1, k2, k3, k4 = st.columns(4)
    with k1:
        st.metric("진입 가능 후보", f"{len(tradable)}건")
    with k2:
        st.metric("관망/조건부", f"{len(hold)}건")
    with k3:
        st.metric("제외", f"{len(excluded)}건")
    with k4:
        st.metric("1회 최대 손실", fmt_price(risk_budget, market))

    st.markdown(
        """
        <div class="cn-oper-board">
          <div><span>진입</span><b>우선진입가 근처 눌림 확인 전 신규매수 금지</b></div>
          <div><span>손절</span><b>손절가 이탈 시 보유/신규 모두 방어 우선</b></div>
          <div><span>익절</span><b>1차익절가 도달 시 분할익절 기준 확인</b></div>
          <div><span>금지</span><b>신뢰도 50 미만·앙상블 0점·조건 충족 전은 관망 우위</b></div>
          <div><span>행동</span><b>오늘은 카드별 결론에 따라 확인 또는 신규매수 금지</b></div>
        </div>
        """,
        unsafe_allow_html=True,
    )

    plan_cards = plan.copy()
    if "권장수량" in plan_cards.columns and "추천수량" not in plan_cards.columns:
        plan_cards["추천수량"] = plan_cards["권장수량"]
    if "최종판단" in plan_cards.columns and "매수행동" not in plan_cards.columns:
        plan_cards["매수행동"] = plan_cards["최종판단"].map({
            "진입 후보": "우선 확인",
            "조건부 진입": "진입가 대기",
            "조건부 관찰": "진입가 대기",
            "관망": "관망/제외",
            "제외": "관망/제외",
        }).fillna("관망/제외")
    render_card_news_candidates(
        plan_cards,
        market,
        title="실전 운용 보드",
        target_label="-",
        top_n=6,
        subtitle="진입/손절/익절/금지/행동 기준을 주문계획 카드로 재구성했습니다.",
    )

    tabs = st.tabs(["진입 후보", "관망/조건부", "제외", "전체 주문계획"])
    with tabs[0]:
        if tradable.empty:
            st.warning("현재 기준으로 바로 진입 후보로 분류된 종목은 없습니다.")
        else:
            st.dataframe(tradable, use_container_width=True, hide_index=True)
    with tabs[1]:
        if hold.empty:
            st.success("관망/조건부 후보가 없습니다.")
        else:
            st.dataframe(hold, use_container_width=True, hide_index=True)
    with tabs[2]:
        if excluded.empty:
            st.success("제외 후보가 없습니다.")
        else:
            st.dataframe(excluded, use_container_width=True, hide_index=True)
    with tabs[3]:
        st.dataframe(plan, use_container_width=True, hide_index=True)

    st.caption("권장수량은 우선진입가와 손절가 차이를 기준으로 계산한 참고값입니다. 실제 주문 전에는 호가·체결강도·뉴스·이벤트를 다시 확인해야 합니다.")
    st.markdown('</div>', unsafe_allow_html=True)


