def _ui_escape_v9976(value: Any) -> str:
    try:
        import html
        return html.escape(str(value if value is not None else "-"))
    except Exception:
        return str(value if value is not None else "-")




def _ag_tone_v9980(*values: Any) -> str:
    text = " ".join([str(v or "") for v in values])
    if any(k in text for k in ["금지", "제외", "관망", "손절", "위험", "주의", "약함"]):
        return "red"
    if any(k in text for k in ["대기", "조건", "확인", "보수", "중립"]):
        return "yellow"
    if any(k in text for k in ["우선", "진입", "양호", "강함", "수익"]):
        return "green"
    return "blue"


def _ag_pill_v9980(text: Any, tone: str = "blue") -> str:
    return f'<span class="ag-pill ag-pill-{tone}">{_ui_escape_v9976(text)}</span>'


def is_excluded_us_stock_symbol(value: Any) -> bool:
    """미국주식 후보 화면에서 제외할 비주식성 심볼."""
    raw = str(value or "").strip()
    if not raw:
        return False
    upper = raw.upper().replace(" ", "")
    if upper in {"BTC-USD", "BTCUSD", "BTCUSDT", "BTC-USDT"}:
        return True
    try:
        normalized = display_symbol(raw, "미국주식", raw)
        return str(normalized).upper().replace(" ", "") in {"BTC-USD", "BTCUSD", "BTCUSDT", "BTC-USDT"}
    except Exception:
        return False


def drop_excluded_us_stock_rows(df: pd.DataFrame, market: str | None = None) -> pd.DataFrame:
    """BTC-USD 같은 비주식 후보가 미국주식 결과/후보군에 섞이지 않게 제거."""
    if df is None or df.empty or market != "미국주식":
        return df
    cols = [c for c in ["symbol", "ticker", "종목", "name"] if c in df.columns]
    if not cols:
        return df
    mask = pd.Series(False, index=df.index)
    for col in cols:
        mask = mask | df[col].apply(is_excluded_us_stock_symbol)
    return df.loc[~mask].copy()


def _card_value(value: Any, fallback: str = "확인 필요") -> str:
    s = str(value if value is not None else "").strip()
    if not s or s.lower() in {"nan", "none", "nat"} or s == "-":
        return fallback
    return s


def _card_bool(value: Any) -> bool:
    try:
        if isinstance(value, bool):
            return value
        return str(value).strip().lower() in {"true", "1", "yes", "y", "매수금지", "신규매수 금지"}
    except Exception:
        return False


def _card_split_reasons(*values: Any) -> list[str]:
    out: list[str] = []
    for value in values:
        text = str(value or "").strip()
        if not text or text in {"-", "nan", "None", "[]"}:
            continue
        for sep in [" / ", "|", "·", "\n"]:
            text = text.replace(sep, "||")
        for part in text.split("||"):
            p = part.strip(" -•")
            if p and p not in {"-", "nan", "None"} and p not in out:
                out.append(p[:90])
    while len(out) < 3:
        defaults = ["우선진입가 근처 눌림 확인 필요", "손절가 이탈 시 신규 진입 금지", "장중 현재가·뉴스 재확인 필요"]
        out.append(defaults[len(out)])
    return out[:3]


def _card_row_assessment(row: pd.Series, market: str) -> dict[str, Any]:
    conf = safe_float(row.get("보정신뢰도"), 0)
    fit = safe_float(row.get("매매적합도"), 0)
    ens_raw = row.get("앙상블추정점수", np.nan)
    ens = safe_float(ens_raw, np.nan)
    ens_missing = np.isnan(ens)
    if ens_missing:
        ens = 1
    rr = safe_float(row.get("손익비"), np.nan)
    action = _card_value(row.get("매수행동", row.get("주문방식")), "관망/제외")
    verdict = _card_value(row.get("실전최종판정", row.get("판정", row.get("최종판단"))), "관망 우위")
    warn = _card_value(row.get("주의사유"), "")
    ban_reason = _card_value(row.get("금지사유"), "")
    sanity = _card_value(row.get("주문검증"), "확인 필요")
    no_buy = _card_bool(row.get("매수금지", False))

    forced_reasons: list[str] = []
    if conf < 50:
        forced_reasons.append("보정신뢰도 50점 미만")
    if not ens_missing and ens <= 0:
        forced_reasons.append("앙상블 점수 0점")
    if action in {"진입가 대기", "관망/제외"}:
        forced_reasons.append("조건 충족 전")
    if no_buy or ban_reason:
        forced_reasons.append("매수금지 조건")

    final = normalize_final_judgment_display(verdict, row)
    if forced_reasons or "관망" in action or "제외" in action or "금지" in action or "관망" in verdict or "제외" in verdict:
        final = "관망 우위"
    buy_allowed = (
        final != "관망 우위"
        and not no_buy
        and action == "우선 확인"
        and conf >= 50
        and ens > 0
    )

    entry = _card_value(row.get("우선진입가"), "조건 충족 전")
    stop = _card_value(row.get("손절가"), "확인 필요")
    tp1 = _card_value(row.get("1차익절가"), "확인 필요")
    qty = _card_value(row.get("추천수량", row.get("권장수량")), "확인 필요")
    if not buy_allowed:
        qty = "신규매수 금지"

    entry_num = parse_price_label(entry)
    chase_limit = chase_limit_price_v9955(entry_num, market) if not np.isnan(entry_num) else np.nan
    chase_condition = (
        f"{fmt_price(chase_limit, market)} 이상이면 신규매수 금지"
        if not np.isnan(chase_limit)
        else "우선진입가 확인 전 추격 금지"
    )

    if buy_allowed:
        entry_condition = f"우선진입가 {entry} 근처에서 체결 흐름 확인"
        today_action = "우선진입가 근처에서만 분할 진입 검토"
        conclusion = "오늘은 우선진입가 근처 확인 시에만 제한적 신규매수 허용"
    else:
        entry_condition = f"조건 충족 전: 우선진입가 {entry} 근처 눌림 확인 필요"
        today_action = "신규매수 금지, 조건 확인만"
        conclusion = "오늘은 추격 금지, 우선진입가 근처 눌림 확인만 허용"

    rr_text = f"1:{rr:.2f}" if not np.isnan(rr) else "확인 필요"
    no_buy_text = "신규매수 가능" if buy_allowed else "신규매수 금지"
    reasons = _card_split_reasons(
        " / ".join(forced_reasons),
        row.get("실전판정이유"),
        row.get("행동이유"),
        row.get("주의사유"),
        row.get("금지사유"),
        row.get("진입근거"),
        row.get("품질요약"),
    )
    tone = "red" if not buy_allowed else _ag_tone_v9980(action, final, warn, ban_reason)
    return {
        "ticker": display_symbol(row.get("종목", row.get("ticker", "-")), market),
        "final": final,
        "conf": conf,
        "fit": fit,
        "ens": ens,
        "buy_allowed": buy_allowed,
        "no_buy_text": no_buy_text,
        "entry_condition": entry_condition,
        "chase_condition": chase_condition,
        "stop": stop,
        "tp1": tp1,
        "rr": rr_text,
        "qty": qty,
        "today_action": today_action,
        "reasons": reasons,
        "conclusion": conclusion,
        "tone": tone,
        "warn": warn,
        "ban_reason": ban_reason,
        "sanity": sanity,
    }


def _card_metric(label: str, value: Any, cls: str = "") -> str:
    cls_attr = f" {cls}" if cls else ""
    return (
        f'<div class="cn-metric{cls_attr}">'
        f'<span>{_ui_escape_v9976(label)}</span>'
        f'<b>{_ui_escape_v9976(value)}</b>'
        f'</div>'
    )


def _card_news_html(row: pd.Series, market: str, rank: int) -> str:
    a = _card_row_assessment(row, market)
    tone = a["tone"] if a["tone"] in {"red", "yellow", "green", "blue"} else "blue"
    top_badge = '<span class="cn-ban">신규 매수 금지</span>' if not a["buy_allowed"] else '<span class="cn-ok">신규매수 가능</span>'
    reasons = "".join(f"<li>{_ui_escape_v9976(r)}</li>" for r in a["reasons"])
    return f"""
    <article class="cn-card {tone}">
      <div class="cn-head">
        <div>
          <div class="cn-rank">#{rank} 확인 후보</div>
          <div class="cn-symbol">{_ui_escape_v9976(a["ticker"])}</div>
        </div>
        {top_badge}
      </div>
      <div class="cn-divider"></div>
      <div class="cn-judgment">
        <span>최종판단</span>
        <b>{_ui_escape_v9976(a["final"])}</b>
      </div>
      <div class="cn-grid">
        {_card_metric("종목명", a["ticker"])}
        {_card_metric("보정신뢰도", f'{a["conf"]:.0f}점')}
        {_card_metric("신규매수 가능/금지", a["no_buy_text"], "danger" if not a["buy_allowed"] else "ok")}
        {_card_metric("진입 조건", a["entry_condition"])}
        {_card_metric("추격 금지 조건", a["chase_condition"], "danger")}
        {_card_metric("손절가", a["stop"])}
        {_card_metric("1차 익절가", a["tp1"])}
        {_card_metric("손익비", a["rr"])}
        {_card_metric("추천수량", a["qty"], "danger" if not a["buy_allowed"] else "")}
        {_card_metric("오늘 행동", a["today_action"])}
      </div>
      <div class="cn-reason-title">판단 사유 3개</div>
      <ol class="cn-reasons">{reasons}</ol>
      <div class="cn-conclusion">{_ui_escape_v9976(a["conclusion"])}</div>
    </article>
    """


def render_card_news_candidates(
    action_df: pd.DataFrame,
    market: str,
    title: str = "확인 후보 TOP3",
    target_label: str = "-",
    top_n: int = 3,
    subtitle: str | None = None,
    use_realtime_guard: bool = True,
    reliability_result: dict[str, Any] | None = None,
) -> None:
    """미국주식 결과 화면용 카드뉴스형 후보 카드."""
    if action_df is None or action_df.empty:
        st.info("표시할 확인 후보가 없습니다.")
        return
    try:
        if "_native_card_css_once" in globals():
            _native_card_css_once()
    except Exception:
        pass
    reliability = reliability_result or compute_app_reliability_score(market)
    if bool(reliability.get("block_top3", False)):
        score = int(reliability.get("score", 0))
        st.warning(f"오늘은 데이터 신뢰도 낮음 / 관망 우선 · 앱 신뢰도 {score}점")
        st.caption("60점 미만이면 TOP3를 표시하지 않습니다. 현재가·뉴스·시장지표·오류 로그를 확인한 뒤 다시 판단하세요.")
        return
    rel_score = int(reliability.get("score", 0))
    if not bool(reliability.get("show_a_grade_top3", rel_score >= 80)):
        st.markdown(f"### {str(title) if title else '확인 후보'}")
        st.warning(f"앱 신뢰도 {rel_score}점: A급 TOP3 카드는 80점 이상에서만 확정 표시합니다. 아래 표는 참고용입니다.")
        df_ref = build_unified_decision_df(action_df.copy(), None, market, use_realtime_guard=use_realtime_guard)
        if df_ref.empty:
            st.info("참고용 후보 표를 만들 데이터가 없습니다.")
            return
        if "실전우선순위" in df_ref.columns:
            df_ref["_cn_sort"] = pd.to_numeric(df_ref["실전우선순위"], errors="coerce").fillna(-999)
        else:
            df_ref["_cn_sort"] = pd.to_numeric(df_ref.get("보정신뢰도", pd.Series(0, index=df_ref.index)), errors="coerce").fillna(0)
        df_ref = df_ref.sort_values("_cn_sort", ascending=False)
        _dedupe_col = "종목" if "종목" in df_ref.columns else ("ticker" if "ticker" in df_ref.columns else None)
        if _dedupe_col:
            df_ref = df_ref.drop_duplicates(subset=[_dedupe_col], keep="first")
        df_ref = df_ref.head(top_n)
        ref_cols = [c for c in [
            "종목", "카드종목명", "실전최종판정", "보정신뢰도", "매매적합도", "손익비",
            "우선진입가", "손절가", "1차익절가", "2차익절가", "매수행동", "주의사유",
        ] if c in df_ref.columns]
        st.dataframe(df_ref[ref_cols] if ref_cols else df_ref, use_container_width=True, hide_index=True)
        st.caption("신뢰도가 80점 이상이 되면 카드뉴스형 A급 TOP3로 동일 정보를 다시 확인하세요.")
        return
    df = build_unified_decision_df(action_df.copy(), None, market, use_realtime_guard=use_realtime_guard)
    if df.empty:
        st.info("BTC-USD 등 비주식 후보를 제외한 뒤 표시할 미국주식 후보가 없습니다.")
        return
    if "실전우선순위" in df.columns:
        df["_cn_sort"] = pd.to_numeric(df["실전우선순위"], errors="coerce").fillna(-999)
    else:
        df["_cn_sort"] = pd.to_numeric(df.get("보정신뢰도", pd.Series(0, index=df.index)), errors="coerce").fillna(0)
    df = df.sort_values("_cn_sort", ascending=False)
    _dedupe_col2 = "종목" if "종목" in df.columns else ("ticker" if "ticker" in df.columns else None)
    if _dedupe_col2:
        df = df.drop_duplicates(subset=[_dedupe_col2], keep="first")
    df = df.head(top_n)
    cards = "".join(_card_news_html(row, market, i + 1) for i, (_, row) in enumerate(df.iterrows()))
    sub = subtitle or f"{market} / 예측대상일 {target_label} · 진입·손절·익절·금지·행동 기준을 한 카드에서 확인합니다."
    st.markdown(
        f"""
        <section class="cn-section">
          <div class="cn-kicker">CARD NEWS DECISION</div>
          <div class="cn-title">{_ui_escape_v9976(title)}</div>
          <div class="cn-sub">{_ui_escape_v9976(sub)}</div>
          <div class="cn-card-grid">{cards}</div>
        </section>
        """,
        unsafe_allow_html=True,
    )


def build_unified_decision_df(
    df: pd.DataFrame,
    log_df: pd.DataFrame | None = None,
    market: str = "미국주식",
    use_realtime_guard: bool = True,
) -> pd.DataFrame:
    """화면 렌더링 전에 최종 판단/금지/행동 기준을 하나의 카드용 데이터로 정규화."""
    if df is None or df.empty:
        return pd.DataFrame()
    work = drop_excluded_us_stock_rows(df.copy(), market)
    if work.empty:
        return pd.DataFrame()

    if "보정신뢰도" not in work.columns or "종목" not in work.columns:
        try:
            work = build_next_prediction_view_v39(work, log_df if log_df is not None else pd.DataFrame(), market)
        except Exception:
            work = df.copy()
        work = drop_excluded_us_stock_rows(work, market)
        if work.empty:
            return pd.DataFrame()

    if "매수행동" not in work.columns or "실전최종판정" not in work.columns or "추천수량" not in work.columns:
        try:
            work = add_buy_action_columns(work, log_df=log_df, market=market, use_realtime_guard=use_realtime_guard)
        except Exception:
            work = work.copy()

    rows = []
    for _, row in work.iterrows():
        assessed = _card_row_assessment(row, market)
        rows.append({
            "카드종목명": assessed["ticker"],
            "카드최종판단": assessed["final"],
            "카드신규매수": assessed["no_buy_text"],
            "카드진입조건": assessed["entry_condition"],
            "카드추격금지": assessed["chase_condition"],
            "카드오늘행동": assessed["today_action"],
            "카드한줄결론": assessed["conclusion"],
            "카드톤": assessed["tone"],
            "카드판단사유": " / ".join(assessed["reasons"]),
        })
    if rows:
        card_df = pd.DataFrame(rows, index=work.index)
        for col in card_df.columns:
            work[col] = card_df[col]
    return _apply_operational_trade_column_labels(work.reset_index(drop=True))


def _ag_card_v9980(label: Any, value: Any, note: Any = "", tone: str = "") -> str:
    tone_cls = f" {tone}" if tone in {"good", "warn", "bad"} else ""
    return (
        f'<div class="ag-mini-card{tone_cls}">'
        f'<div class="ag-mini-label">{_ui_escape_v9976(label)}</div>'
        f'<div class="ag-mini-value">{_ui_escape_v9976(value)}</div>'
        f'<div class="ag-mini-note">{_ui_escape_v9976(note)}</div>'
        f'</div>'
    )


def _ag_bool_v9980(value: Any) -> bool:
    try:
        if isinstance(value, bool):
            return value
        return str(value).strip().lower() in {"true", "1", "yes", "y", "매수금지"}
    except Exception:
        return False


