def render_final_judgment_strip(view: pd.DataFrame, market: str, target_label: str) -> None:
    """첫 화면 최상단: 최종 판단만 빠르게 보는 카드 영역."""
    if view is None or view.empty:
        return

    ranked = view.copy()
    if "보정신뢰도" not in ranked.columns or "종목" not in ranked.columns:
        try:
            ranked = build_next_prediction_view_v39(ranked, pd.DataFrame(), market)
        except Exception:
            ranked = view.copy()
    if ranked is None or ranked.empty:
        return
    conf = pd.to_numeric(ranked.get("보정신뢰도"), errors="coerce").fillna(0)
    fit = pd.to_numeric(ranked.get("매매적합도"), errors="coerce").fillna(0)
    warn = ranked.get("주의사유", pd.Series("-", index=ranked.index)).astype(str)
    warn_penalty = np.where(warn.eq("-"), 0, 10)
    ranked["_final_score"] = conf * 0.52 + fit * 0.48 - warn_penalty
    ranked = ranked.sort_values(["_final_score", "보정신뢰도", "매매적합도"], ascending=False).reset_index(drop=True)

    try:
        action_df = add_buy_action_columns(ranked.head(3), log_df=None, market=market)
    except Exception:
        action_df = ranked.head(3).copy()
    render_card_news_candidates(
        action_df,
        market,
        title="오늘 1순위 확인 후보",
        target_label=target_label,
        top_n=1,
        subtitle="최종판단·신규매수 금지·진입/손절/익절 기준을 카드 하나로 정리했습니다.",
    )


def render_market_decision_bridge(
    market: str,
    final_market_score: int,
    final_sector_score: int,
    final_news_score: int,
    macro_market_score: int,
    event_context: dict[str, Any],
) -> None:
    """시장 확인 후 예측/추천으로 넘어가기 전 운영 모드 요약."""
    mode_label = "국장" if market == "한국주식" else "미장"
    macro_adj = 1 if macro_market_score >= 2 else -1 if macro_market_score <= -2 else 0
    total = int(max(-9, min(9, final_market_score + final_sector_score + final_news_score + macro_adj)))
    risk_mult = safe_float(event_context.get("risk_mult", 1.0), 1.0)

    if total >= 4 and risk_mult < 1.6:
        stance = "공격적 후보 선별 가능"
        order = "상위 후보 → 진입가 → 손절폭 → 차트 순서로 확인"
        caution = "추격매수보다 우선진입가와 손익비를 먼저 확인"
    elif total >= 1:
        stance = "선별 접근"
        order = "보정신뢰도 높은 종목부터 확인"
        caution = "뉴스 반전·금리·환율 변화를 같이 확인"
    elif total <= -4:
        stance = "방어 우선"
        order = "매수 후보보다 관망/손절 기준 확인"
        caution = "시장 부담이 큰 구간이라 신규 진입은 보수적으로 판단"
    elif total <= -1:
        stance = "보수적 관망"
        order = "주의사유 없는 종목만 제한적으로 확인"
        caution = "시장 점수 회복 전까지 비중 확대는 신중"
    else:
        stance = "중립 확인"
        order = "최종판단과 차트가 같은 방향인지 확인"
        caution = "방향성이 약하므로 돌파/이탈 확인이 중요"

    if risk_mult >= 1.6:
        caution = f"이벤트 변동성 {risk_mult:.2f}배 구간입니다. 손절폭과 비중을 줄여 확인하세요."

    st.markdown("##### ✅ 시장 확인 후 운영 모드")
    b1, b2, b3 = st.columns(3)
    with b1:
        st.metric(f"{mode_label} 운영 모드", stance, f"종합 {total:+d}")
    with b2:
        st.metric("다음 확인 순서", "예측/추천 후보", "주문계획 → 차트")
        st.caption(order)
    with b3:
        st.metric("주의 포인트", "리스크 체크")
        st.caption(caution)

    # 운용 모드별 진입 기준 명시
    if total >= 4:
        st.success("✅ 공격적 후보 선별 — 앙상블 65점↑ + 손익비 1:1.5↑ 충족 종목 진입 가능")
    elif total >= 1:
        st.info("🟡 선별 접근 — 앙상블 70점↑ + 손익비 1:1.8↑ + 주의사유 없음 조건 강화")
    elif total <= -4:
        st.error("🔴 방어 우선 — 신규 매수 자제. 기존 포지션 손절가 재확인")
    else:
        st.warning("⚠️ 보수적 관망 — 앙상블 75점↑ 이상만, 비중 축소 기준 우선")



def _latest_runner_segment(lines: list[str]) -> list[str]:
    """Return latest runner attempt segment so old failures do not poison current status."""
    meaningful = [str(x).strip() for x in lines if str(x).strip()]
    if not meaningful:
        return []
    last_start = -1
    for i, line in enumerate(meaningful):
        low = line.lower()
        if "[runner] bat_start" in low or "[runner] start" in low:
            last_start = i
    if last_start >= 0:
        return meaningful[last_start:]
    return meaningful[-40:]


def _classify_runner_segment(segment: list[str]) -> tuple[str, str]:
    """Classify latest runner attempt. yfinance earnings warnings are not fatal."""
    if not segment:
        return "로그 없음", "-"
    joined = "\n".join(segment)
    upper = joined.upper()
    tail = segment[-1][:220]

    nonfatal_patterns = [
        "NO EARNINGS DATES FOUND",
        "SYMBOL MAY BE DELISTED",
        "POSSIBLY DELISTED",
        "NO PRICE DATA FOUND",
        "YFINANCE",
    ]
    fatal_patterns = [
        "TRACEBACK",
        "NAMEERROR",
        "MODULENOTFOUNDERROR",
        "FILENOTFOUNDERROR",
        "DID NOT FIND EXECUTABLE",
        "EXIT_CODE 103",
        "EXIT_CODE 1",
        "EXIT_CODE 2",
        "ERROR:",
        "[ERROR]",
    ]

    has_success = ("EXIT_CODE 0" in upper) or ("[RUNNER] DONE" in upper) or ("[RUNNER] END" in upper and "EXIT_CODE" not in upper)
    has_fatal = any(p in upper for p in fatal_patterns)
    only_nonfatal = any(p in upper for p in nonfatal_patterns) and not has_fatal

    # If latest segment ended successfully, treat nonfatal yfinance warnings as data warning, not failure.
    if has_success and not has_fatal:
        if any(p in upper for p in nonfatal_patterns):
            return "데이터 경고", tail
        return "정상", tail
    if "[RUNNER] BAT_START" in upper and "[RUNNER] END" not in upper and "[RUNNER] DONE" not in upper:
        return "실행 중", tail
    if only_nonfatal:
        return "데이터 경고", tail
    if has_fatal:
        return "확인 필요", tail
    return "실행 기록", tail


def read_runner_log_status() -> pd.DataFrame:
    """작업스케줄러 runner 로그의 최신 실행 구간만 요약."""
    log_dir = Path("logs")
    specs = [
        ("미장 예측", log_dir / "runner_us_predict.log"),
        ("미장 업데이트", log_dir / "runner_us_update.log"),
        ("국장 예측", log_dir / "runner_kr_predict.log"),
        ("국장 업데이트", log_dir / "runner_kr_update.log"),
    ]
    rows = []
    for label, path in specs:
        if not path.exists():
            rows.append({"작업": label, "상태": "로그 없음", "마지막수정": "-", "마지막문구": "-", "파일": str(path)})
            continue
        try:
            raw = path.read_text(encoding="utf-8", errors="ignore").splitlines()
            segment = _latest_runner_segment(raw)
            status, tail = _classify_runner_segment(segment)
            modified = datetime.fromtimestamp(path.stat().st_mtime).strftime("%Y-%m-%d %H:%M")
            rows.append({
                "작업": label,
                "상태": status,
                "마지막수정": modified,
                "마지막문구": tail,
                "파일": str(path),
            })
        except Exception as e:
            rows.append({"작업": label, "상태": "읽기 실패", "마지막수정": "-", "마지막문구": str(e), "파일": str(path)})
    return pd.DataFrame(rows)


def render_runner_log_status_panel() -> None:
    """앱 안에서 최신 runner 로그 상태 확인."""
    df = read_runner_log_status()
    if df.empty:
        return
    st.markdown("##### 🧾 작업스케줄러 로그 상태")
    c1, c2, c3, c4 = st.columns(4)
    ok_n = int(df["상태"].astype(str).isin(["정상", "데이터 경고"]).sum()) if "상태" in df.columns else 0
    running_n = int(df["상태"].astype(str).eq("실행 중").sum()) if "상태" in df.columns else 0
    warn_n = int(df["상태"].astype(str).isin(["확인 필요", "읽기 실패"]).sum()) if "상태" in df.columns else 0
    no_log_n = int(df["상태"].astype(str).eq("로그 없음").sum()) if "상태" in df.columns else 0
    with c1:
        st.metric("정상/경고", f"{ok_n}개")
    with c2:
        st.metric("실행 중", f"{running_n}개")
    with c3:
        st.metric("확인 필요", f"{warn_n}개")
    with c4:
        st.metric("로그 없음", f"{no_log_n}개")
    st.dataframe(df, use_container_width=True, hide_index=True)
    st.caption("상태판은 최신 [runner] bat_start 이후 구간만 판정합니다. yfinance의 earnings 경고는 데이터 경고로 분리합니다.")


def build_finnhub_realtime_df(market: str, limit: int = 21) -> pd.DataFrame:
    """고정 관심종목의 Finnhub 실시간 현재가 보드."""
    if market != "미국주식":
        return pd.DataFrame()
    wl = load_watchlist_df(market)
    if wl.empty or "symbol" not in wl.columns:
        return pd.DataFrame()
    symbols = []
    for raw in wl["symbol"].astype(str).tolist():
        sym = display_symbol(raw, "미국주식")
        if sym and sym not in symbols:
            symbols.append(sym)
        if len(symbols) >= limit:
            break

    rows = []
    for sym in symbols:
        snap = realtime_snapshot(sym)
        last_price = safe_float(snap.get("last_price"), np.nan)
        prev_close = safe_float(snap.get("prev_close"), np.nan)
        change_pct = safe_float(snap.get("change_pct"), np.nan)
        rows.append({
            "종목": sym,
            "현재가": f"${last_price:,.2f}" if not np.isnan(last_price) else "-",
            "등락률": f"{change_pct:+.2f}%" if not np.isnan(change_pct) else "-",
            "전일종가": f"${prev_close:,.2f}" if not np.isnan(prev_close) else "-",
            "시가": f"${safe_float(snap.get('open'), np.nan):,.2f}" if not np.isnan(safe_float(snap.get("open"), np.nan)) else "-",
            "고가": f"${safe_float(snap.get('high'), np.nan):,.2f}" if not np.isnan(safe_float(snap.get("high"), np.nan)) else "-",
            "저가": f"${safe_float(snap.get('low'), np.nan):,.2f}" if not np.isnan(safe_float(snap.get("low"), np.nan)) else "-",
            "업데이트": str(snap.get("last_time", "-") or "-"),
            "출처": str(snap.get("source", "-")),
        })
    return pd.DataFrame(rows)


def build_realtime_order_gap_df(log_df: pd.DataFrame, market: str, limit: int = 21) -> pd.DataFrame:
    """실시간 현재가와 우선진입가의 괴리율 확인."""
    if market != "미국주식":
        return pd.DataFrame()
    status_df = build_watchlist_status_df(log_df, market)
    if status_df.empty or "종목" not in status_df.columns:
        return pd.DataFrame()

    rows = []
    for _, r in status_df.head(limit).iterrows():
        sym = display_symbol(r.get("종목", ""), "미국주식")
        if not sym:
            continue
        snap = realtime_snapshot(sym)
        cur = safe_float(snap.get("last_price"), np.nan)
        entry = parse_price_label(r.get("우선진입가", np.nan))
        stop = parse_price_label(r.get("손절가", np.nan))
        tp1 = parse_price_label(r.get("1차익절가", np.nan))
        gap = (cur / entry - 1) * 100 if entry and not np.isnan(entry) and not np.isnan(cur) else np.nan
        if np.isnan(cur):
            action = "현재가 미확인"
        elif np.isnan(entry) or entry <= 0:
            action = "예측 미생성"
        elif gap >= 3:
            action = "진입가 위 - 추격주의"
        elif gap <= -3:
            action = "진입가 아래 - 재계산/확인"
        elif -1 <= gap <= 1:
            action = "진입가 근처"
        else:
            action = "대기/확인"
        rows.append({
            "종목": sym,
            "현재가": f"${cur:,.2f}" if not np.isnan(cur) else "-",
            "우선진입가": r.get("우선진입가", "-"),
            "현재가-진입가": f"{gap:+.2f}%" if not np.isnan(gap) else "-",
            "손절가": r.get("손절가", "-"),
            "1차익절가": r.get("1차익절가", "-"),
            "판정": action,
            "출처": str(snap.get("source", "-")),
            "업데이트": str(snap.get("last_time", "-") or "-"),
        })
    return pd.DataFrame(rows)


