def stability_file_info(label: str, path: Path) -> dict[str, Any]:
    try:
        return {
            "label": label,
            "path": str(path),
            "exists": bool(path.exists()),
            "size": int(path.stat().st_size) if path.exists() else 0,
            "mtime": datetime.fromtimestamp(path.stat().st_mtime, tz=KST).strftime("%Y-%m-%d %H:%M:%S KST") if path.exists() else "-",
        }
    except Exception as ex:
        return {"label": label, "path": str(path), "exists": False, "size": 0, "mtime": "-", "error": str(ex)}


def stability_df_health(name: str, df: pd.DataFrame, required_cols: list[str] | None = None, key_cols: list[str] | None = None) -> dict[str, Any]:
    required_cols = required_cols or []
    key_cols = key_cols or []
    result = {"name": name, "rows": 0, "ok": True, "warnings": []}
    try:
        if df is None or not isinstance(df, pd.DataFrame):
            result["ok"] = False
            result["warnings"].append("DataFrame 아님")
            return result
        result["rows"] = int(len(df))
        if df.empty:
            result["warnings"].append("데이터 없음")
        cols = list(map(str, df.columns))
        dup_cols = sorted({c for c in cols if cols.count(c) > 1})
        if dup_cols:
            result["ok"] = False
            result["warnings"].append("중복 컬럼: " + ", ".join(dup_cols[:10]))
        missing = [c for c in required_cols if c not in df.columns]
        if missing:
            result["ok"] = False
            result["warnings"].append("필수 컬럼 없음: " + ", ".join(missing))
        nan_notes = []
        for c in key_cols:
            if c in df.columns:
                try:
                    n = int(pd.to_numeric(df[c], errors="coerce").isna().sum())
                    if n:
                        nan_notes.append(f"{c} {n}건")
                except Exception:
                    pass
        if nan_notes:
            result["warnings"].append("NaN/계산불가: " + ", ".join(nan_notes[:8]))
        return result
    except Exception as ex:
        result["ok"] = False
        result["warnings"].append(str(ex))
        return result


def build_stability_diagnostic(log_df: pd.DataFrame | None, market: str) -> dict[str, Any]:
    """캡처 없이 앱 상태를 확인할 수 있는 구조화 진단 데이터."""
    checks: list[dict[str, str]] = []
    files = [
        stability_file_info("predictions.csv", PREDICTION_FILE),
        stability_file_info("watchlist_us_growth.csv", WATCHLIST_US_FILE),
        stability_file_info("watchlist_kr_growth.csv", WATCHLIST_KR_FILE),
        stability_file_info("candidate_universe_us.csv", CANDIDATE_US_FILE),
        stability_file_info("candidate_universe_kr.csv", CANDIDATE_KR_FILE),
        stability_file_info("finnhub_config.json", FINNHUB_CONFIG_FILE),
        stability_file_info("app_error_log.csv", APP_ERROR_LOG_FILE),
        stability_file_info("app_error_log.txt", STABILITY_ERROR_TXT),
    ]

    for f in files:
        if f["label"] in ["predictions.csv"]:
            checks.append({"level": "ok" if f["exists"] else "warn", "message": f"{f['label']} {'존재' if f['exists'] else '없음'}"})
        elif f["label"].startswith("watchlist"):
            checks.append({"level": "ok" if f["exists"] and f["size"] > 0 else "warn", "message": f"{f['label']} size={f['size']}"})

    try:
        wl = load_watchlist_df(market)
    except Exception as ex:
        wl = pd.DataFrame()
        checks.append({"level": "error", "message": f"관심종목 로드 실패: {ex}"})

    pred_health = stability_df_health("예측 로그", log_df if isinstance(log_df, pd.DataFrame) else pd.DataFrame(), ["ticker", "market"], ["preferred_entry", "stop_loss", "take_profit1"])
    wl_health = stability_df_health("관심종목", wl, ["symbol"], [])
    for h in [pred_health, wl_health]:
        if h["ok"] and not h["warnings"]:
            checks.append({"level": "ok", "message": f"{h['name']} 정상 · {h['rows']}건"})
        elif h["ok"]:
            checks.append({"level": "warn", "message": f"{h['name']} 확인 필요 · " + " / ".join(h["warnings"])})
        else:
            checks.append({"level": "error", "message": f"{h['name']} 오류 · " + " / ".join(h["warnings"])})

    try:
        key_status = finnhub_config_status_text() if market == "미국주식" else "국장 화면"
        checks.append({"level": "ok" if "연결됨" in key_status or market != "미국주식" else "warn", "message": f"Finnhub API: {key_status}"})
    except Exception as ex:
        checks.append({"level": "warn", "message": f"Finnhub 상태 확인 실패: {ex}"})

    runner_logs = []
    for p in sorted(Path("logs").glob("runner_*.log")):
        try:
            lines = p.read_text(encoding="utf-8", errors="ignore").splitlines()
            tail = "\n".join(lines[-12:])
            has_bad = any(x.upper().find("TRACEBACK") >= 0 or x.upper().find("ERROR") >= 0 for x in lines[-40:])
            ok_done = any("[runner] done" in x or "exit_code 0" in x or "[runner] end" in x for x in lines[-40:])
            runner_logs.append({"file": p.name, "mtime": datetime.fromtimestamp(p.stat().st_mtime, tz=KST).strftime("%Y-%m-%d %H:%M:%S KST"), "status": "확인 필요" if has_bad else "정상" if ok_done else "실행 기록", "tail": tail})
        except Exception as ex:
            runner_logs.append({"file": p.name, "status": "읽기 실패", "tail": str(ex)})
    if runner_logs:
        bad = [r for r in runner_logs if r.get("status") == "확인 필요"]
        checks.append({"level": "warn" if bad else "ok", "message": f"runner 로그 {len(runner_logs)}개 / 확인필요 {len(bad)}개"})
    else:
        checks.append({"level": "warn", "message": "runner 로그 없음 · 작업스케줄러 실행 전이면 정상"})

    if STABILITY_ERROR_TXT.exists() and STABILITY_ERROR_TXT.stat().st_size > 0:
        checks.append({"level": "warn", "message": "섹션 오류 로그 존재: reports/app_error_log.txt"})
    else:
        checks.append({"level": "ok", "message": "섹션 오류 로그 없음"})

    top_rows = []
    try:
        if isinstance(log_df, pd.DataFrame) and not log_df.empty:
            top_rows = log_df.tail(10).replace({np.nan: None}).to_dict(orient="records")
    except Exception:
        top_rows = []

    return {
        "app_version": APP_VERSION,
        "generated_at_kst": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S KST"),
        "market": market,
        "python": sys.version.split()[0],
        "cwd": str(Path.cwd()),
        "files": files,
        "prediction_health": pred_health,
        "watchlist_health": wl_health,
        "runner_logs": runner_logs,
        "checks": checks,
        "recent_predictions": top_rows,
    }


def save_stability_diagnostic_report(data: dict[str, Any]) -> tuple[Path, Path]:
    REPORT_DIR.mkdir(exist_ok=True)
    STABILITY_DIAG_JSON.write_text(json.dumps(data, ensure_ascii=False, indent=2), encoding="utf-8")
    lines = []
    lines.append(f"{APP_VERSION} 안정성 진단 리포트")
    lines.append("=" * 70)
    lines.append(f"생성시각: {data.get('generated_at_kst')}")
    lines.append(f"시장: {data.get('market')}")
    lines.append(f"실행폴더: {data.get('cwd')}")
    lines.append(f"Python: {data.get('python')}")
    lines.append("")
    lines.append("[점검 결과]")
    for c in data.get("checks", []):
        prefix = {"ok": "정상", "warn": "확인필요", "error": "오류"}.get(c.get("level"), c.get("level"))
        lines.append(f"- {prefix}: {c.get('message')}")
    lines.append("")
    lines.append("[파일 상태]")
    for f in data.get("files", []):
        lines.append(f"- {f.get('label')}: exists={f.get('exists')}, size={f.get('size')}, mtime={f.get('mtime')}")
    lines.append("")
    lines.append("[Runner 로그]")
    for r in data.get("runner_logs", []):
        lines.append(f"- {r.get('file')}: {r.get('status')} / {r.get('mtime', '-')}")
    STABILITY_DIAG_TXT.write_text("\n".join(lines), encoding="utf-8")
    return STABILITY_DIAG_TXT, STABILITY_DIAG_JSON


def build_news_alarm_df(event_context: dict[str, Any], market: str) -> pd.DataFrame:
    """event_context의 원문 뉴스들을 News Alarm 표로 변환."""
    rows = []
    for item in (event_context or {}).get("auto_news_source_items", [])[:30]:
        title = str(item.get("title", "") or "").strip()
        if not title:
            continue
        severity = safe_float(item.get("severity"), np.nan)
        if np.isnan(severity):
            severity, direction, reasons = news_alarm_severity(title)
            direction_label = "우호" if direction > 0 else "부담" if direction < 0 else str(item.get("direction", "중립/변동성"))
        else:
            direction_label = str(item.get("direction", "중립/변동성"))
            reasons = item.get("alarm_reasons", []) or []
        rows.append({
            "알람": "🚨" if severity >= 7 and direction_label == "부담" else "⚠️" if severity >= 5 else "📰",
            "중요도": str(item.get("importance", "중간")),
            "영향": direction_label,
            "강도": int(severity) if not np.isnan(severity) else 0,
            "출처": str(item.get("source", "-")),
            "시간": str(item.get("time", "-")),
            "관련": str(item.get("related_ticker", "-")),
            "제목": title[:130],
            "근거키워드": ", ".join(map(str, reasons)) if reasons else "-",
            "링크": str(item.get("url", "")),
        })
    if not rows:
        return pd.DataFrame()
    df = pd.DataFrame(rows)
    return df.sort_values(["강도"], ascending=False)


def render_news_alarm_panel(
    event_context: dict[str, Any],
    market: str,
    *,
    use_outer_expander: bool = True,
) -> None:
    """v9.9.2: 뉴스 소식 강화 패널. use_outer_expander=False면 상위 expander 안에서도 안전하게 표시."""

    def _alarm_body() -> None:
        updated = str((event_context or {}).get("auto_news_updated_at", "-"))
        latest = str((event_context or {}).get("auto_news_latest_published_at", "-"))
        quality = str((event_context or {}).get("auto_news_quality", "-"))
        label = str((event_context or {}).get("auto_news_label", "-"))
        raw = int(safe_float((event_context or {}).get("auto_news_raw_count", 0), 0))
        unique = int(safe_float((event_context or {}).get("auto_news_unique_count", 0), 0))
        dedup = int(safe_float((event_context or {}).get("auto_news_dedup_removed", 0), 0))
        score = int(safe_float((event_context or {}).get("auto_news_score", 0), 0))

        c1, c2, c3, c4 = st.columns(4)
        c1.metric("뉴스점수", score)
        c2.metric("수집 후보", raw)
        c3.metric("중복 제거", dedup)
        c4.metric("고유 뉴스", unique)
        st.caption(f"조회시각: {updated} · 최신 기사시각: {latest} · {quality} · {label}")
        st.caption(
            "시장뉴스는 RSS/Google News를 넓게 보고, 미장 종목뉴스는 Finnhub Company News + Google News ticker + Yahoo/yfinance를 함께 봅니다."
        )

        alarm_df = build_news_alarm_df(event_context, market)
        if alarm_df.empty:
            st.info("현재 감지된 중요 뉴스 알람이 없습니다.")
        else:
            show_cols = ["알람", "중요도", "영향", "강도", "출처", "시간", "관련", "제목", "근거키워드"]
            st.dataframe(alarm_df[show_cols], use_container_width=True, hide_index=True)
            show_links = st.toggle(
                "원문 링크 펼치기",
                value=False,
                key=f"news_alarm_show_links_v2_{market}_{use_outer_expander}",
            )
            if show_links:
                for _, r in alarm_df.head(12).iterrows():
                    url = str(r.get("링크", ""))
                    title = str(r.get("제목", ""))
                    meta = f"{r.get('출처')} · {r.get('시간')} · 영향 {r.get('영향')} · 강도 {r.get('강도')}"
                    if url.startswith("http"):
                        st.markdown(
                            f"- [{title}]({url})  \n  <span style='color:#94a3b8;font-size:0.85rem'>{meta}</span>",
                            unsafe_allow_html=True,
                        )
                    else:
                        st.markdown(
                            f"- {title}  \n  <span style='color:#94a3b8;font-size:0.85rem'>{meta}</span>",
                            unsafe_allow_html=True,
                        )

        if st.button("뉴스 캐시 새로고침", use_container_width=True, key=f"clear_news_alarm_cache_{market}_{use_outer_expander}"):
            try:
                fetch_macro_rss_items_safe.clear()
                fetch_finnhub_company_news_items.clear()
                fetch_finnhub_quote_snapshot.clear()
            except Exception:
                pass
            st.success("뉴스 캐시를 초기화했습니다. 화면을 새로고침하면 다시 수집합니다.")

    if use_outer_expander:
        with st.expander("🚨 News Alarm · 강화 뉴스 감지", expanded=False):
            _alarm_body()
    else:
        st.markdown("##### 🚨 News Alarm · 강화 뉴스 감지")
        _alarm_body()


def render_stability_diagnostic_panel(log_df: pd.DataFrame | None, market: str) -> None:
    """v9.9.7 WTI Emergency 패치: 캡처 대신 진단 파일로 상태 확인."""
    with st.expander("🩺 안정성 자가진단 리포트", expanded=False):
        st.caption("문제가 생기면 캡처 대신 reports/diagnostic_report.txt 또는 diagnostic_data.json 파일을 보내면 됩니다.")
        try:
            data = build_stability_diagnostic(log_df, market)
            ok_n = sum(1 for c in data["checks"] if c.get("level") == "ok")
            warn_n = sum(1 for c in data["checks"] if c.get("level") == "warn")
            err_n = sum(1 for c in data["checks"] if c.get("level") == "error")
            c1, c2, c3, c4 = st.columns(4)
            c1.metric("정상", ok_n)
            c2.metric("확인 필요", warn_n)
            c3.metric("오류", err_n)
            c4.metric("Runner 로그", len(data.get("runner_logs", [])))

            for c in data["checks"]:
                if c.get("level") == "ok":
                    st.success(c.get("message"))
                elif c.get("level") == "warn":
                    st.warning(c.get("message"))
                else:
                    st.error(c.get("message"))

            if st.button("진단 리포트 저장", use_container_width=True, key="save_stability_diagnostic"):
                txt, js = save_stability_diagnostic_report(data)
                st.success(f"저장 완료: {txt} / {js}")
        except Exception as ex:
            stability_log_error("render_stability_diagnostic_panel", ex)
            st.error(f"자가진단 생성 실패: {ex}")


