def next_pending_predictions(log_df: pd.DataFrame, market: str | None = None, limit: int = 20) -> pd.DataFrame:
    """다음 장 예측 표시용 기록을 추린다.

    v9.9.20+:
    - 1순위: actual_close가 비어 있는 미완료 다음 장 예측
    - 2순위: 미완료 예측이 없으면 가장 최근 저장된 예측 배치
    - 앱 시작 자동 동기화가 실제값을 먼저 채워도 TOP 후보/차트 영역이 사라지지 않게 한다.
    """
    if log_df is None or log_df.empty:
        return pd.DataFrame()

    df = log_df.copy()
    if market and "market" in df.columns:
        df = df[df["market"].astype(str).eq(market)]
    if df.empty:
        return pd.DataFrame()

    if "target_date" not in df.columns:
        df["target_date"] = ""
    if "created_at" not in df.columns:
        df["created_at"] = ""

    df["_target_dt"] = pd.to_datetime(df["target_date"], errors="coerce")
    df["_created_dt"] = pd.to_datetime(df["created_at"], errors="coerce")

    work = df.copy()
    if "actual_close" in work.columns:
        actual_close = pd.to_numeric(work["actual_close"], errors="coerce")
        pending = work[actual_close.isna()].copy()
    else:
        pending = work.copy()

    if not pending.empty:
        valid = pending[pending["_target_dt"].notna()].copy()
        if not valid.empty:
            today = pd.Timestamp(datetime.now(KST).date()) if "KST" in globals() else pd.Timestamp.today().normalize()
            future = valid[valid["_target_dt"] >= today]
            selected_date = future["_target_dt"].min() if not future.empty else valid["_target_dt"].max()
            pending = valid[valid["_target_dt"].eq(selected_date)].copy()
        pending["_prediction_display_mode"] = "미완료 다음 장 예측"
        pending = pending.sort_values(["_target_dt", "_created_dt"], ascending=[True, False])
        return pending.drop(columns=[c for c in ["_target_dt", "_created_dt"] if c in pending.columns]).head(limit)

    valid_all = df[df["_target_dt"].notna()].copy()
    if valid_all.empty:
        valid_all = df.copy()

    if "_target_dt" in valid_all.columns and valid_all["_target_dt"].notna().any():
        latest_target = valid_all["_target_dt"].max()
        batch = valid_all[valid_all["_target_dt"].eq(latest_target)].copy()
    else:
        latest_created = valid_all["_created_dt"].max() if "_created_dt" in valid_all.columns else pd.NaT
        batch = valid_all[valid_all["_created_dt"].eq(latest_created)].copy() if pd.notna(latest_created) else valid_all.copy()

    if batch.empty:
        return pd.DataFrame()

    if "ticker" in batch.columns:
        batch = batch.sort_values("_created_dt", ascending=False)
        batch = batch.drop_duplicates(subset=["ticker"], keep="first")

    batch["_prediction_display_mode"] = "최근 저장 예측 배치"
    batch = batch.sort_values(["_target_dt", "_created_dt"], ascending=[False, False])
    return batch.drop(columns=[c for c in ["_target_dt", "_created_dt"] if c in batch.columns]).head(limit)

def format_zone_text(row: pd.Series, low_key: str, high_key: str, market: str) -> str:
    low = safe_float(row.get(low_key), np.nan)
    high = safe_float(row.get(high_key), np.nan)
    if np.isnan(low) or np.isnan(high) or low <= 0 or high <= 0:
        return "-"
    return f"{fmt_price(low, market)} ~ {fmt_price(high, market)}"


def build_next_prediction_view(pending_df: pd.DataFrame, market: str) -> pd.DataFrame:
    """첫 화면용 다음 장 예측 요약표."""
    if pending_df is None or pending_df.empty:
        return pd.DataFrame()
    pending_df = drop_excluded_us_stock_rows(pending_df, market)
    if pending_df.empty:
        return pd.DataFrame()

    rows = []
    for _, r in pending_df.iterrows():
        ticker = display_symbol(r.get("ticker", ""), market, r.get("종목", ""))
        pred_close_low = safe_float(r.get("pred_close_low"), np.nan)
        pred_close_high = safe_float(r.get("pred_close_high"), np.nan)
        pred_close_mid = safe_float(r.get("pred_close_mid"), np.nan)
        prev_close = safe_float(r.get("prev_close"), np.nan)
        expected_pct = ((pred_close_mid / prev_close) - 1) * 100 if prev_close and not np.isnan(pred_close_mid) else np.nan
        warn = str(r.get("no_buy_flags", "") or r.get("auto_failure_tags", "") or "")
        if warn in ["nan", "None"]:
            warn = ""
        rows.append({
            "예측대상일": r.get("target_date", ""),
            "종목": ticker,
            "전일종가": fmt_price(prev_close, market) if not np.isnan(prev_close) else "-",
            "예상시초가": fmt_price(safe_float(r.get("pred_open_mid"), np.nan), market),
            "예상종가범위": f"{fmt_price(pred_close_low, market)} ~ {fmt_price(pred_close_high, market)}",
            "예상중앙등락": pct(expected_pct) if not np.isnan(expected_pct) else "-",
            "우선진입가": fmt_price(safe_float(r.get("preferred_entry"), np.nan), market),
            "보수대기선": fmt_price(safe_float(r.get("conservative_entry"), np.nan), market) if not np.isnan(safe_float(r.get("conservative_entry"), np.nan)) else "-",
            "지지존": format_zone_text(r, "support_zone_low", "support_zone_high", market),
            "저항존": format_zone_text(r, "resistance_zone_low", "resistance_zone_high", market),
            "진입근거": str(r.get("entry_basis", "-")),
            "손절가": fmt_price(safe_float(r.get("stop_loss"), np.nan), market),
            "1차익절가": fmt_price(safe_float(r.get("take_profit1"), np.nan), market),
            "2차익절가": fmt_price(safe_float(r.get("take_profit2"), np.nan), market),
            "신뢰도": f"{safe_float(r.get('confidence_score'), 0):.0f}점",
            "전략": r.get("primary_action", r.get("technical_verdict", "")),
            "주의사유": warn if warn else "-",
            "장세션": r.get("session_label", ""),
        })
    return pd.DataFrame(rows)



def symbol_prediction_stats(log_df: pd.DataFrame, ticker: str, market: str | None = None, lookback: int = 10) -> dict[str, Any]:
    """종목별 최근 예측 성과를 계산한다."""
    if log_df is None or log_df.empty:
        return {
            "history_count": 0, "recent_count": 0, "open_hit_rate": np.nan, "close_hit_rate": np.nan,
            "avg_open_abs_error": np.nan, "avg_close_abs_error": np.nan,
        }

    df = log_df.copy()
    if "ticker" in df.columns:
        df = df[df["ticker"].astype(str).str.upper().eq(str(ticker).upper())]
    if market and "market" in df.columns:
        df = df[df["market"].astype(str).eq(market)]
    if df.empty:
        return {
            "history_count": 0, "recent_count": 0, "open_hit_rate": np.nan, "close_hit_rate": np.nan,
            "avg_open_abs_error": np.nan, "avg_close_abs_error": np.nan,
        }

    if "created_at" in df.columns:
        df["_created_dt"] = pd.to_datetime(df["created_at"], errors="coerce")
        df = df.sort_values("_created_dt", ascending=False)

    done = df[pd.to_numeric(df.get("close_abs_error_pct"), errors="coerce").notna()] if "close_abs_error_pct" in df.columns else pd.DataFrame()
    recent = done.head(lookback)
    if recent.empty:
        return {
            "history_count": len(done), "recent_count": 0, "open_hit_rate": np.nan, "close_hit_rate": np.nan,
            "avg_open_abs_error": np.nan, "avg_close_abs_error": np.nan,
        }

    open_hit = recent.get("open_in_range", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"]).mean() * 100
    close_hit = recent.get("close_in_range", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"]).mean() * 100
    open_err = pd.to_numeric(recent.get("open_abs_error_pct"), errors="coerce").mean()
    close_err = pd.to_numeric(recent.get("close_abs_error_pct"), errors="coerce").mean()
    return {
        "history_count": int(len(done)),
        "recent_count": int(len(recent)),
        "open_hit_rate": open_hit,
        "close_hit_rate": close_hit,
        "avg_open_abs_error": open_err,
        "avg_close_abs_error": close_err,
    }


def calibrated_confidence_for_row(row: pd.Series, log_df: pd.DataFrame, market: str) -> tuple[int, list[str]]:
    """
    표시용 보정신뢰도.
    원래 confidence_score를 그대로 쓰지 않고, 기록 수/실제 오차/범위 넓이/이벤트/국장 예상체결가 여부를 반영한다.
    """
    base = int(max(0, min(100, safe_float(row.get("confidence_score"), 50))))
    ticker = str(row.get("ticker", ""))
    stats = symbol_prediction_stats(log_df, ticker, market)
    score = base
    notes: list[str] = []

    count = stats["history_count"]
    if count < 5:
        score = min(score, 60)
        notes.append("기록 5건 미만: 신뢰도 상한 60")
    elif count < 15:
        score = min(score, 75)
        notes.append("기록 15건 미만: 신뢰도 상한 75")

    close_err = stats["avg_close_abs_error"]
    if not pd.isna(close_err):
        if close_err <= 1.0:
            score += 6
            notes.append("최근 종가오차 양호")
        elif close_err >= 3.0:
            score -= 12
            notes.append("최근 종가오차 큼")
        elif close_err >= 2.0:
            score -= 6
            notes.append("최근 종가오차 주의")

    prev = safe_float(row.get("prev_close"), np.nan)
    low = safe_float(row.get("pred_close_low"), np.nan)
    high = safe_float(row.get("pred_close_high"), np.nan)
    if prev and not np.isnan(low) and not np.isnan(high):
        width_pct = (high - low) / prev * 100
        if width_pct >= 8:
            score -= 10
            notes.append("예상범위 과도하게 넓음")
        elif width_pct >= 5:
            score -= 5
            notes.append("예상범위 넓음")

    event_mult = safe_float(row.get("event_risk_mult"), 1.0)
    if event_mult >= 1.55:
        score -= 10
        notes.append("대형 이벤트 변동성")
    elif event_mult >= 1.35:
        score -= 5
        notes.append("이벤트 변동성")

    if market == "한국주식":
        q_label = str(row.get("premarket_quality_label", ""))
        if "예상체결가" not in q_label:
            score = min(score, 72)
            notes.append("국장 예상체결가 미반영")

    warn = str(row.get("no_buy_flags", "") or row.get("auto_failure_tags", ""))
    if warn and warn not in ["nan", "None", "-", "[]"]:
        score -= 5
        notes.append("주의사유 존재")

    return int(max(0, min(100, round(score)))), notes


def trade_suitability_for_row(row: pd.Series, calibrated_confidence: int) -> tuple[int, str, list[str]]:
    """예측 신뢰도와 별도로 실제 매매 적합도를 계산한다."""
    score = calibrated_confidence * 0.45
    notes: list[str] = []

    rr = safe_float(row.get("rr1"), np.nan)
    if not np.isnan(rr):
        if rr >= 2.0:
            score += 22
            notes.append("손익비 2.0 이상")
        elif rr >= 1.5:
            score += 14
            notes.append("손익비 1.5 이상")
        elif rr < 1.0:
            score -= 18
            notes.append("손익비 1.0 미만")

    tech = safe_float(row.get("technical_score"), np.nan)
    if not np.isnan(tech):
        score += max(-10, min(18, (tech - 50) * 0.35))

    prev = safe_float(row.get("prev_close"), np.nan)
    entry = safe_float(row.get("preferred_entry"), np.nan)
    stop = safe_float(row.get("stop_loss"), np.nan)
    tp1 = safe_float(row.get("take_profit1"), np.nan)
    if not np.isnan(entry) and not np.isnan(stop) and entry:
        stop_gap = abs(entry - stop) / entry * 100
        if stop_gap > 7:
            score -= 10
            notes.append("손절폭 과도")
        elif stop_gap <= 3:
            score += 5
            notes.append("손절폭 관리 가능")
    if not np.isnan(entry) and not np.isnan(tp1) and entry:
        upside = (tp1 - entry) / entry * 100
        if upside >= 4:
            score += 6
            notes.append("1차 목표 여력 양호")

    warn = str(row.get("no_buy_flags", "") or "")
    if warn and warn not in ["nan", "None", "-", "[]"]:
        score -= 18
        notes.append("매수주의 사유 존재")

    score = int(max(0, min(100, round(score))))
    if score >= 80:
        label = "우선 후보"
    elif score >= 68:
        label = "조건부 진입"
    elif score >= 55:
        label = "관찰 후보"
    else:
        label = "관망 우위"
    return score, label, notes


def build_next_prediction_view_v39(pending_df: pd.DataFrame, log_df: pd.DataFrame, market: str) -> pd.DataFrame:
    """v3.9용 보기 좋은 다음 장 예측 요약표."""
    if pending_df is None or pending_df.empty:
        return pd.DataFrame()
    pending_df = drop_excluded_us_stock_rows(pending_df, market)
    if pending_df.empty:
        return pd.DataFrame()

    rows = []
    for _, r in pending_df.iterrows():
        ticker = display_symbol(r.get("ticker", ""), market, r.get("종목", ""))
        conf, conf_notes = calibrated_confidence_for_row(r, log_df, market)
        trade_score, trade_label, trade_notes = trade_suitability_for_row(r, conf)
        stats = symbol_prediction_stats(log_df, ticker, market)

        pred_close_low = safe_float(r.get("pred_close_low"), np.nan)
        pred_close_high = safe_float(r.get("pred_close_high"), np.nan)
        pred_close_mid = safe_float(r.get("pred_close_mid"), np.nan)
        prev_close = safe_float(r.get("prev_close"), np.nan)
        expected_pct = ((pred_close_mid / prev_close) - 1) * 100 if prev_close and not np.isnan(pred_close_mid) else np.nan
        warn = str(r.get("no_buy_flags", "") or r.get("auto_failure_tags", "") or "")
        if warn in ["nan", "None", "[]"]:
            warn = ""

        rows.append({
            "예측대상일": r.get("target_date", ""),
            "종목": ticker,
            "전일종가": fmt_price(prev_close, market) if not np.isnan(prev_close) else "-",
            "예상시초가": fmt_price(safe_float(r.get("pred_open_mid"), np.nan), market),
            "예상종가범위": f"{fmt_price(pred_close_low, market)} ~ {fmt_price(pred_close_high, market)}",
            "예상중앙등락": pct(expected_pct) if not np.isnan(expected_pct) else "-",
            "우선진입가": fmt_price(safe_float(r.get("preferred_entry"), np.nan), market),
            "보수대기선": fmt_price(safe_float(r.get("conservative_entry"), np.nan), market) if not np.isnan(safe_float(r.get("conservative_entry"), np.nan)) else "-",
            "지지존": format_zone_text(r, "support_zone_low", "support_zone_high", market),
            "저항존": format_zone_text(r, "resistance_zone_low", "resistance_zone_high", market),
            "진입근거": str(r.get("entry_basis", "-")),
            "손절가": fmt_price(safe_float(r.get("stop_loss"), np.nan), market),
            "1차익절가": fmt_price(safe_float(r.get("take_profit1"), np.nan), market),
            "2차익절가": fmt_price(safe_float(r.get("take_profit2"), np.nan), market),
            "손익비": f"{safe_float(r.get('rr1'), np.nan):.2f}" if not np.isnan(safe_float(r.get("rr1"), np.nan)) else "-",
            "품질점수": f"{safe_float(r.get('quality_score'), np.nan):.0f}" if not np.isnan(safe_float(r.get("quality_score"), np.nan)) else "-",
            "재무": str(r.get("fundamental_label", "-") or "-"),
            "수급": str(r.get("supply_label", "-") or "-"),
            "품질요약": str(r.get("quality_summary", "-") or "-")[:80],
            "보정신뢰도": conf,
            "매매적합도": trade_score,
            "판정": trade_label,
            "누적기록": stats["history_count"],
            "최근종가오차": f"{stats['avg_close_abs_error']:.2f}%" if not pd.isna(stats["avg_close_abs_error"]) else "-",
            "주의사유": warn if warn else "-",
            "신뢰도메모": " / ".join(conf_notes[:3]) if conf_notes else "-",
            "매매메모": " / ".join(trade_notes[:3]) if trade_notes else "-",
            **{
                k: r.get(k, "")
                for k in [
                    "created_at", "session_type", "session_label",
                    "basis_ohlc_date", "basis_open", "basis_high", "basis_low", "basis_close", "basis_volume", "basis_source",
                    "current_price_at_prediction", "current_price_source",
                    "stock_code", "stock_name",
                    "prediction_freshness", "prediction_freshness_issue", "basis_ohlc_valid", "basis_ohlc_issue",
                    "invalidation_condition", "data_status", "risk_reward_ratio", "final_judgment", "suggested_action",
                    "reason", "risk_reason", "buy_reason",
                ]
                if k in r.index
            },
        })

    df = pd.DataFrame(rows)
    if df.empty:
        return df
    return df.sort_values(["매매적합도", "보정신뢰도"], ascending=[False, False]).reset_index(drop=True)


