def resample_ohlcv(df: pd.DataFrame, rule: str) -> pd.DataFrame:
    """일봉 OHLCV를 주봉/월봉 OHLCV로 변환."""
    if df is None or df.empty:
        return pd.DataFrame()
    d = df.copy()
    d["Date"] = pd.to_datetime(d["Date"], errors="coerce")
    d = d.dropna(subset=["Date"]).sort_values("Date")
    if d.empty:
        return pd.DataFrame()
    d = d.set_index("Date")
    agg = {
        "Open": "first",
        "High": "max",
        "Low": "min",
        "Close": "last",
        "Volume": "sum",
    }
    out = d.resample(rule).agg(agg).dropna().reset_index()
    return out


def resample_ohlcv_weekly(df: pd.DataFrame) -> pd.DataFrame:
    return resample_ohlcv(df, "W-FRI")


def resample_ohlcv_monthly(df: pd.DataFrame) -> pd.DataFrame:
    return resample_ohlcv(df, "M")


def ensure_chart_moving_averages(df: pd.DataFrame) -> pd.DataFrame:
    """차트 표시 전 MA10/20/50/100/200 컬럼을 반드시 생성."""
    if df is None or df.empty or "Close" not in df.columns:
        return df
    out = df.copy()
    for n in [5, 10, 20, 50, 100, 200]:
        col = f"MA{n}"
        if col not in out.columns or out[col].isna().all():
            out[col] = out["Close"].rolling(n, min_periods=max(2, min(n, 5))).mean()
    return out



def reset_chart_widget_state(prefix: str) -> None:
    """차트 관련 Streamlit 위젯 상태 초기화."""
    for key in list(st.session_state.keys()):
        if isinstance(key, str) and key.startswith(prefix):
            del st.session_state[key]



def render_selected_prediction_chart(selected_row: pd.Series, market: str) -> None:
    """증권앱 흐름에 맞춘 일봉/주봉/월봉 차트."""
