def file_mtime_label(path: Path) -> tuple[str, str]:
    """파일 수정시각을 KST 기준 문자열과 상태로 반환."""
    try:
        if not path.exists():
            return "-", "없음"
        ts = datetime.fromtimestamp(path.stat().st_mtime, tz=KST)
        age_min = (datetime.now(KST) - ts).total_seconds() / 60
        if age_min <= 180:
            status = "정상"
        elif age_min <= 1440:
            status = "확인 필요"
        else:
            status = "오래됨"
        return ts.strftime("%Y-%m-%d %H:%M"), status
    except Exception:
        return "-", "확인불가"



