# v8.8~v9.2 운용 안정화/속도 최적화/실전 운용 보조
# ══════════════════════════════════════════════
def operation_setting_float(key: str, default: float) -> float:
    try:
        return float(st.session_state.get(key, default))
    except Exception:
        return float(default)


def operation_setting_bool(key: str, default: bool) -> bool:
    try:
        return bool(st.session_state.get(key, default))
    except Exception:
        return bool(default)


OPERATION_SETTING_KEYS: tuple[str, ...] = (
    "account_capital",
    "available_cash",
    "risk_per_trade_pct",
    "max_position_pct",
    "allow_fractional_shares",
)
USER_OPERATION_SETTINGS_FILE = Path("data") / "user_operation_settings.json"


def operation_setting_defaults_for_market(market: str) -> dict[str, float | bool]:
    default_account = 10_000.0 if market == "미국주식" else 10_000_000.0
    return {
        "account_capital": default_account,
        "available_cash": default_account,
        "risk_per_trade_pct": 0.7,
        "max_position_pct": 20.0,
        "allow_fractional_shares": False,
    }


def ensure_operation_settings_loaded() -> None:
    """세션에 운용 기준이 없으면 data/user_operation_settings.json에서 1회 로드."""
    if st.session_state.get("_operation_settings_loaded"):
        return
    defaults_applied = False
    try:
        if USER_OPERATION_SETTINGS_FILE.exists() and USER_OPERATION_SETTINGS_FILE.stat().st_size > 0:
            data = json.loads(USER_OPERATION_SETTINGS_FILE.read_text(encoding="utf-8"))
            if isinstance(data, dict):
                for key in OPERATION_SETTING_KEYS:
                    if key in data:
                        st.session_state[key] = data[key]
                defaults_applied = True
    except Exception:
        pass
    if not defaults_applied:
        for key, val in operation_setting_defaults_for_market("미국주식").items():
            st.session_state.setdefault(key, val)
    st.session_state["_operation_settings_loaded"] = True


def save_user_operation_settings() -> bool:
    """현재 session_state 운용 기준을 data/user_operation_settings.json에 저장."""
    try:
        USER_OPERATION_SETTINGS_FILE.parent.mkdir(parents=True, exist_ok=True)
        payload = {key: st.session_state.get(key) for key in OPERATION_SETTING_KEYS}
        USER_OPERATION_SETTINGS_FILE.write_text(
            json.dumps(payload, ensure_ascii=False, indent=2),
            encoding="utf-8",
        )
        return True
    except Exception:
        return False


def render_operation_settings_form(market: str, *, show_save_button: bool = True) -> None:
    """실전 운용 기준 입력 — session_state 키를 기존 주문계획 계산과 공유."""
    ensure_operation_settings_loaded()
    defaults = operation_setting_defaults_for_market(market)
    st.markdown("##### 운용 기준 설정")
    step = 100.0 if market == "미국주식" else 100_000.0
    st.session_state["account_capital"] = st.number_input(
        "계좌 기준금액",
        min_value=0.0,
        value=float(st.session_state.get("account_capital", defaults["account_capital"])),
        step=step,
    )
    st.session_state["available_cash"] = st.number_input(
        "매수 가능 현금",
        min_value=0.0,
        value=float(st.session_state.get("available_cash", defaults["available_cash"])),
        step=step,
    )
    st.session_state["risk_per_trade_pct"] = st.slider(
        "손실 허용률 (%)",
        0.1,
        5.0,
        float(st.session_state.get("risk_per_trade_pct", defaults["risk_per_trade_pct"])),
        0.1,
    )
    st.session_state["max_position_pct"] = st.slider(
        "종목당 최대 비중 (%)",
        1.0,
        100.0,
        float(st.session_state.get("max_position_pct", defaults["max_position_pct"])),
        1.0,
    )
    st.session_state["allow_fractional_shares"] = st.checkbox(
        "미장 소수점 주식 허용",
        value=bool(st.session_state.get("allow_fractional_shares", defaults["allow_fractional_shares"])),
        disabled=(market != "미국주식"),
    )
    if show_save_button:
        if st.button("운용 기준 저장", key=f"save_operation_settings_{market}", use_container_width=True):
            if save_user_operation_settings():
                st.success("운용 기준이 저장되었습니다")
            else:
                st.warning("운용 기준 저장에 실패했습니다. 잠시 후 다시 시도하세요.")


def log_app_event(
    section: str,
    level: str,
    message: str,
    *,
    function_name: str = "",
    market: str = "",
    ticker: str = "",
    resolution: str = "",
) -> None:
    """앱 내부 오류/상태 이벤트를 CSV로 남긴다. 실패해도 앱은 중단하지 않는다."""
    try:
        row = {
            "time_kst": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S"),
            "section": str(section)[:80],
            "level": str(level)[:20],
            "function_name": str(function_name)[:120],
            "market": str(market)[:40],
            "ticker": str(ticker)[:40],
            "message": str(message)[:500],
            "resolution": str(resolution)[:200],
        }
        def _append_error_row(path: Path) -> None:
            path.parent.mkdir(parents=True, exist_ok=True)
            if path.exists():
                try:
                    with path.open("r", encoding="utf-8-sig", errors="replace") as fh:
                        first = fh.readline()
                    if first and "function_name" not in first:
                        legacy = path.with_suffix(path.suffix + f".legacy_{datetime.now(KST).strftime('%Y%m%d_%H%M%S')}")
                        path.rename(legacy)
                except Exception:
                    pass
            exists = path.exists()
            pd.DataFrame([row]).to_csv(path, mode="a", index=False, header=not exists, encoding="utf-8-sig")

        for path in [APP_ERROR_LOG_FILE, SECONDARY_ERROR_LOG_FILE]:
            try:
                _append_error_row(path)
            except Exception:
                continue
    except Exception as e:
        try:
            REPORT_DIR.mkdir(parents=True, exist_ok=True)
            with STABILITY_ERROR_TXT.open("a", encoding="utf-8") as f:
                f.write(f"{datetime.now(KST).isoformat()} log_app_event_failed {section} {level} {e}\n")
        except Exception:
            return


def recent_error_log(limit: int = 20) -> pd.DataFrame:
    try:
        if not APP_ERROR_LOG_FILE.exists():
            return pd.DataFrame()
        df = pd.read_csv(APP_ERROR_LOG_FILE, dtype=str).fillna("")
        return df.tail(limit).sort_index(ascending=False)
    except Exception:
        return pd.DataFrame()


def _reliability_bool_text(ok: bool) -> str:
    return "정상" if ok else "확인 필요"


def _latest_market_prediction_batch_for_reliability(log_df: pd.DataFrame | None, market: str) -> pd.DataFrame:
    try:
        df = log_df.copy() if log_df is not None else load_prediction_log()
    except Exception as e:
        log_app_event("app_reliability", "warning", f"prediction log load failed: {e}")
        return pd.DataFrame()
    if df is None or df.empty:
        return pd.DataFrame()
    try:
        if "market" in df.columns:
            df = df[df["market"].astype(str).eq(market)].copy()
        if market == "미국주식":
            df = drop_excluded_us_stock_rows(normalize_us_tickers_in_log(df), market)
    except Exception as e:
        log_app_event("app_reliability", "warning", f"market filter failed: {e}")
    if df.empty:
        return pd.DataFrame()
    tcol = "target_date" if "target_date" in df.columns else ""
    if tcol:
        dt = pd.to_datetime(df[tcol], errors="coerce")
        if dt.notna().any():
            latest = dt.max()
            return df[dt.eq(latest)].copy()
    if "created_at" in df.columns:
        dt = pd.to_datetime(df["created_at"], errors="coerce")
        if dt.notna().any():
            latest = dt.max()
            return df[dt.eq(latest)].copy()
    return df.tail(30).copy()


def _reliability_column_has_value(df: pd.DataFrame, col: str) -> bool:
    if df is None or df.empty or col not in df.columns:
        return False
    s = df[col]
    if pd.api.types.is_numeric_dtype(s):
        return pd.to_numeric(s, errors="coerce").notna().any()
    text = s.astype(str).str.strip()
    return text.ne("").any() and text.str.lower().ne("nan").any() and text.ne("-").any()


def _reliability_any_true(df: pd.DataFrame, col: str) -> bool:
    if df is None or df.empty or col not in df.columns:
        return False
    text = df[col].astype(str).str.strip().str.lower()
    return text.isin({"true", "1", "yes", "y", "정상", "ok"}).any()


def _recent_log_has_problem(paths: list[Path], hours: int = 24) -> tuple[bool, str]:
    cutoff = datetime.now(KST) - timedelta(hours=hours)
    problem_words = (" error:", " fail", "traceback", "exception", "timeout", "api failure", "http_4", "http_5")
    try:
        for path in paths:
            if not path.exists():
                continue
            if path.suffix.lower() == ".csv":
                df = pd.read_csv(path, dtype=str).fillna("")
                if df.empty:
                    continue
                time_col = "time_kst" if "time_kst" in df.columns else df.columns[0]
                times = pd.to_datetime(df[time_col], errors="coerce")
                recent = df[times.ge(cutoff.replace(tzinfo=None))] if times.notna().any() else df.tail(20)
                for _, row in recent.iterrows():
                    joined = " ".join(str(x).lower() for x in row.values)
                    level = str(row.get("level", "")).lower() if "level" in recent.columns else ""
                    section = str(row.get("section", "")).lower() if "section" in recent.columns else ""
                    if section == "app_reliability" and "reliability low score" in joined:
                        continue
                    if level in {"error", "warn", "warning"} or any(w in joined for w in problem_words):
                        return True, f"{path.name}: {str(row.to_dict())[:160]}"
            else:
                if path.stat().st_mtime < cutoff.timestamp():
                    continue
                text = path.read_text(encoding="utf-8", errors="ignore")[-6000:].lower()
                if any(w in text for w in problem_words):
                    return True, path.name
    except Exception as e:
        log_app_event("app_reliability", "warning", f"log scan failed: {e}")
        return True, f"로그 확인 실패: {e}"
    return False, "최근 오류 없음"


def _prediction_file_writable() -> tuple[bool, str]:
    try:
        PREDICTION_FILE.parent.mkdir(parents=True, exist_ok=True)
        tmp = PREDICTION_FILE.parent / ".predictions_write_test.tmp"
        tmp.write_text("ok", encoding="utf-8")
        tmp.unlink(missing_ok=True)
        return True, "저장 가능"
    except Exception as e:
        log_app_event("app_reliability", "error", f"prediction write check failed: {e}")
        return False, f"저장 불가: {e}"


def compute_app_reliability_score(
    market: str,
    log_df: pd.DataFrame | None = None,
    overrides: dict[str, bool] | None = None,
) -> dict[str, Any]:
    """100점 기준 앱/데이터 신뢰도. 첫 화면 경량화를 위해 저장 결과를 우선 평가한다."""
    overrides = overrides or {}
    batch = _latest_market_prediction_batch_for_reliability(log_df, market)
    full_df = log_df.copy() if log_df is not None else pd.DataFrame()
    if full_df is None or full_df.empty:
        try:
            full_df = load_prediction_log()
        except Exception:
            full_df = pd.DataFrame()
    if full_df is not None and not full_df.empty and "market" in full_df.columns:
        full_df = full_df[full_df["market"].astype(str).eq(market)].copy()

    def num_col_ok(col: str) -> bool:
        return batch is not None and not batch.empty and col in batch.columns and pd.to_numeric(batch[col], errors="coerce").gt(0).any()

    latest_data_age_days = np.nan
    if batch is not None and not batch.empty and "data_date" in batch.columns:
        d = pd.to_datetime(batch["data_date"], errors="coerce")
        if d.notna().any():
            latest_data_age_days = (datetime.now(KST).date() - d.max().date()).days

    target_age_days = np.nan
    if batch is not None and not batch.empty and "target_date" in batch.columns:
        t = pd.to_datetime(batch["target_date"], errors="coerce")
        if t.notna().any():
            target_age_days = abs((datetime.now(KST).date() - t.max().date()).days)

    price_values = []
    for col in ["prev_close", "premarket_price", "actual_open", "actual_high", "actual_low", "actual_close"]:
        if batch is not None and not batch.empty and col in batch.columns:
            price_values.extend(pd.to_numeric(batch[col], errors="coerce").dropna().tolist())
    price_anomaly_ok = bool(price_values) and all(v > 0 for v in price_values)
    if batch is not None and not batch.empty:
        for low_col, high_col in [("pred_open_low", "pred_open_high"), ("pred_close_low", "pred_close_high")]:
            if low_col in batch.columns and high_col in batch.columns:
                lows = pd.to_numeric(batch[low_col], errors="coerce")
                highs = pd.to_numeric(batch[high_col], errors="coerce")
                if lows.notna().any() and highs.notna().any() and (highs.lt(lows).any() or lows.le(0).any()):
                    price_anomaly_ok = False

    completed_count = 0
    if full_df is not None and not full_df.empty and "actual_close" in full_df.columns:
        completed_count = int(pd.to_numeric(full_df["actual_close"], errors="coerce").notna().sum())

    csv_ok, csv_reason = _prediction_file_writable()
    recent_error_bad, recent_error_reason = _recent_log_has_problem([APP_ERROR_LOG_FILE, SECONDARY_ERROR_LOG_FILE], hours=24)
    api_bad, api_reason = _recent_log_has_problem(
        [Path("logs/runner_us_predict.log"), Path("logs/runner_kr_predict.log"), Path("logs/runner_us_update.log"), Path("logs/runner_kr_update.log")],
        hours=24,
    )
    # predict_locked는 장중 보호 동작이라 API 실패로 보지 않는다.
    if isinstance(api_reason, str) and "predict_locked" in api_reason:
        api_bad = False
        api_reason = "최근 runner 치명 오류 없음"

    checks = [
        ("현재가 조회 정상 여부", bool(_reliability_column_has_value(batch, "price_source") or _reliability_any_true(batch, "kis_price_ok") or num_col_ok("premarket_price")), "저장된 현재가/예상체결가/가격소스 확인", 7),
        ("전일 종가 조회 정상 여부", num_col_ok("prev_close"), "prev_close 양수 확인", 7),
        ("일봉 데이터 정상 여부", bool(_reliability_column_has_value(batch, "chart_source") or num_col_ok("prev_close")), "차트 소스 또는 일봉 기반 가격 확인", 7),
        ("주봉 데이터 정상 여부", bool(_reliability_column_has_value(batch, "technical_verdict") or _reliability_column_has_value(batch, "technical_score") or _reliability_column_has_value(batch, "chart_source")), "기술/차트 계산 결과 확인", 7),
        ("ATR 계산 가능 여부", bool(_reliability_column_has_value(batch, "atr_range_multiplier") or _reliability_column_has_value(batch, "open_range_width_pct") or _reliability_column_has_value(batch, "close_range_width_pct")), "ATR 보정/범위 계산값 확인", 7),
        ("시장지표 조회 정상 여부", bool(_reliability_column_has_value(batch, "market_score") or _reliability_column_has_value(batch, "auto_market_score")), "시장 점수 확인", 7),
        ("뉴스 조회 정상 여부", bool(_reliability_any_true(batch, "news_checked") or _reliability_column_has_value(batch, "news_source") or _reliability_column_has_value(batch, "news_score")), "뉴스 점수/소스 확인", 7),
        ("데이터 최신성", bool((not np.isnan(latest_data_age_days) and latest_data_age_days <= 7) or (not np.isnan(target_age_days) and target_age_days <= 3)), f"data_date 경과 {latest_data_age_days if not np.isnan(latest_data_age_days) else '확인 필요'}일", 7),
        ("데이터 지연 여부", bool((not np.isnan(latest_data_age_days) and latest_data_age_days <= 7) or (not np.isnan(target_age_days) and target_age_days <= 3)), "최근 배치 기준 지연 확인", 7),
        ("가격 이상치 여부", price_anomaly_ok, "가격/예측 범위 양수 및 역전 여부 확인", 7),
        ("predictions.csv 저장 가능 여부", csv_ok, csv_reason, 6),
        ("실제값 업데이트 가능 여부", bool(csv_ok and "fetch_actual_day" in globals() and "update_actual_results" in globals()), "업데이트 함수와 저장 가능 상태 확인", 6),
        ("최근 오류 로그 여부", not recent_error_bad, recent_error_reason, 6),
        ("최근 성과 데이터 충분 여부", completed_count >= 8, f"완료 예측 {completed_count}건", 6),
        ("외부 API 실패 여부", not api_bad, api_reason, 6),
    ]

    items = []
    score = 0
    for name, ok, detail, weight in checks:
        if name in overrides:
            ok = bool(overrides[name])
            detail = f"검증 override: {_reliability_bool_text(ok)}"
        if ok:
            score += weight
        items.append({"항목": name, "상태": _reliability_bool_text(bool(ok)), "점수": weight if ok else 0, "배점": weight, "세부": detail})

    score = int(max(0, min(100, score)))
    if score >= 80:
        label, action = "판단 사용 가능", "저장된 예측과 실행 기준을 사용할 수 있습니다."
    elif score >= 60:
        label, action = "조건부 참고", "TOP 후보는 참고하되 현재가/뉴스를 재확인하세요."
    else:
        label, action = "관망 우선", "오늘은 데이터 신뢰도 낮음 / 관망 우선"
    if score < 50:
        action = "TOP3 숨김 또는 생성 금지 / 신규 판단 보류"

    if score < 60 and not overrides:
        log_app_event("app_reliability", "warning", f"{market} reliability low score={score} label={label}")

    return {
        "score": score,
        "label": label,
        "action": action,
        "items": items,
        "batch_rows": 0 if batch is None else len(batch),
        "completed_count": completed_count,
        "block_top3": score < 60,
        "hide_top3": score < 50,
        "show_a_grade_top3": score >= 80,
    }


def render_app_reliability_panel(
    market: str,
    log_df: pd.DataFrame | None = None,
    expanded: bool = False,
    *,
    use_detail_expander: bool = True,
) -> dict[str, Any]:
    """use_detail_expander=False: 이미 상위 st.expander 안에서 호출할 때 중첩 오류를 피한다."""
    result = compute_app_reliability_score(market, log_df)
    score = int(result.get("score", 0))
    label = str(result.get("label", "확인 필요"))
    action = str(result.get("action", "확인 필요"))
    tone = "#34d399" if score >= 80 else "#fbbf24" if score >= 60 else "#fb7185"
    st.markdown(
        f"""
        <div style="border:1px solid rgba(148,163,184,.22);border-radius:16px;padding:14px 16px;margin:10px 0 14px 0;background:rgba(15,23,42,.58);">
          <div style="display:flex;justify-content:space-between;gap:12px;align-items:center;">
            <div>
              <div style="font-size:.82rem;color:#9fb1c8;font-weight:800;">앱 신뢰도</div>
              <div style="font-size:1.4rem;font-weight:950;color:{tone};">{score}점 · {label}</div>
            </div>
            <div style="text-align:right;color:#e5edf8;font-weight:850;">{action}</div>
          </div>
        </div>
        """,
        unsafe_allow_html=True,
    )
    detail = pd.DataFrame(result.get("items", []))
    cap = (
        "60점 미만이면 TOP3를 표시하지 않고 관망 우선으로 전환합니다. 50점 미만은 TOP3 생성/표시 금지 수준입니다. "
        "80점 미만이면 A급 TOP3 카드는 확정 표시하지 않고 참고용 표만 보여줍니다."
    )
    if use_detail_expander:
        with st.expander("앱 신뢰도 세부 항목", expanded=expanded):
            st.dataframe(detail, use_container_width=True, hide_index=True)
            st.caption(cap)
    else:
        st.markdown("##### 앱 신뢰도 세부 항목")
        st.dataframe(detail, use_container_width=True, hide_index=True)
        st.caption(cap)
    return result


