        "trade_allowed", "high_probability_candidate", "실전등급", "실전등급점수", "실전등급사유", "실전경고",
        *CATALYST_SCORE_COLUMNS,
        *FUNDAMENTAL_VALUATION_COLUMNS,
        *QUALITY_TRADE_ENTRY_COLUMNS,
        *AGGRESSIVE_DISCOVERY_COLUMNS,
