        "portfolio_risk_level", "total_exposure_pct", "sector_concentration_warning",
        "portfolio_expected_return", "max_expected_loss_pct", "portfolio_action", "portfolio_warnings",
        "performance_penalty_score", "adjusted_score_after_review", "performance_penalty_reasons", "recent_fail_pattern_hit",
        "strategy_mode", "strategy_adjustment_score", "strategy_adjusted_score", "strategy_adjusted_grade",
        "strategy_trade_allowed", "strategy_reasons", "strategy_warnings",
        "position_size_pct", "position_risk_level", "position_action", "position_reasons", "position_warnings",
        "observation_reason", "insufficient_conditions", "a_grade_upgrade_hint", "pullback_wait_price", "main_risks",
        "reason", "upgrade_condition", "last_price", "weekly_trend", "daily_setup", "volume_ratio", "sector_strength",
        "market_score", "rr", "entry", "stop", "tp1", "tp2", "expectancy", "news_risk", "news_risk_level", "news_risk_title",
