def _candidate_fundamental_score_text(row: Any, score_col: str, status_col: str, missing_label: str, partial_label: str) -> str:
    try:
        raw = row.get(score_col, "")
        status = str(row.get(status_col, "")).strip().lower()
    except Exception:
        raw = ""
        status = ""
    val = safe_float(raw, np.nan)
    if not math.isnan(val) and status not in {"data_missing", "missing", "no_data"}:
        return f"{val:.1f}"
    if status in {"partial", "limited"}:
        return partial_label
    return missing_label


def _candidate_fundamental_status_text(row: Any, status_col: str, reason_col: str, missing_label: str, partial_label: str) -> str:
    try:
        status = str(row.get(status_col, "")).strip().lower()
        reason = str(row.get(reason_col, "") or "").strip()
    except Exception:
        status = ""
        reason = ""
    if status in {"ok", "api_confirmed"}:
        return "계산 성공"
    if status in {"partial", "limited"}:
        return partial_label
    return reason[:80] if reason else missing_label


def _candidate_display_grade_series(df: pd.DataFrame) -> pd.Series:
    if df is None or df.empty:
        return pd.Series(dtype=str)
    for col in ("grade", "등급", "final_grade", "실전등급"):
        if col in df.columns:
            return df[col].astype(str).str.strip().str.upper()
    label_col = "grade_label" if "grade_label" in df.columns else ("등급 설명" if "등급 설명" in df.columns else "")
    if label_col:
        text = df[label_col].astype(str)
        return text.map(lambda v: "C" if ("C" in v or "제외" in v or "금지" in v) else ("B" if ("B" in v or "관찰" in v) else ("A" if "A" in v else "")))
    return pd.Series([""] * len(df), index=df.index, dtype=str)


def prepare_user_candidate_grade_table(df: pd.DataFrame, grade: str, market: str) -> pd.DataFrame:
    """일반 모드 B/C 후보표. 가격이 없어도 식별·근거·가격 안내 문구를 반드시 표시한다."""
    if df is None or df.empty:
        return pd.DataFrame()
    sources = _candidate_name_score_sources()
    original = df.copy().fillna("").reset_index(drop=True)
    try:
        enriched = enrich_display_price_frame(df.copy(), market).fillna("").reset_index(drop=True)
    except Exception:
        enriched = original.copy()
    grade = str(grade or "").upper()
    rows: list[dict[str, Any]] = []
    for idx, row in enriched.iterrows():
        if idx < len(original):
            merged_row = {**original.iloc[idx].to_dict(), **row.to_dict()}
            row = pd.Series(merged_row)
        row_market = _candidate_display_market(
            _candidate_pick_display_value(row, ("market", "시장"), market),
            market,
        )
        raw_symbol = _candidate_pick_display_value(row, ("symbol", "ticker", "종목코드", "코드", "티커"))
        symbol = _candidate_display_symbol(raw_symbol, row_market)
        name = _candidate_pick_display_value(row, ("name", "종목명", "symbol_name", "company_name"))
        if not name:
            name = _candidate_display_name(row, row_market, symbol, sources)
        score = _candidate_pick_display_value(
            row,
            ("score", "점수", "실전등급점수", "stock_attractiveness_score", "strategy_adjusted_score"),
            "-",
        )
        theme = _candidate_pick_display_value(row, ("theme", "테마", "theme_name"), "-")
        sector = _candidate_pick_display_value(row, ("sector", "섹터", "sector_name", "업종"), "-")
        reason = _candidate_pick_display_value(
            row,
            (
                "판단근거", "reason", "forecast_reasons", "observation_reason", "trade_fit_reasons",
                "aggressive_reasons", "실전등급사유", "grade_change_reason", "active_scenario_reason",
            ),
            _candidate_reason(row, grade),
        )
        action = _candidate_pick_display_value(
            row,
            ("권장 조치", "position_action", "portfolio_action", "active_scenario_decision", "final_decision", "risk_final_decision"),
            _candidate_action(row, grade),
        )
        grade_label = grade or _candidate_pick_display_value(row, ("grade", "등급"), "-")
        earnings_score_text = _candidate_fundamental_score_text(
            row, "earnings_score", "earnings_data_status", "실적 데이터 부족", "실적 일부 부족, 보수 반영"
        )
        earnings_status_text = _candidate_fundamental_status_text(
            row, "earnings_data_status", "earnings_reason", "실적 데이터 부족", "실적 일부 부족, 보수 반영"
        )
        valuation_score_text = _candidate_fundamental_score_text(
            row, "valuation_score", "valuation_data_status", "밸류 데이터 없음", "밸류 일부 부족"
        )
        valuation_status_text = _candidate_fundamental_status_text(
            row, "valuation_data_status", "valuation_reason", "밸류 데이터 없음", "밸류 일부 부족"
        )
        supply_score_text = _candidate_pick_display_value(
            row,
            ("supply_score", "수급점수", "flow_score", "investor_flow_score", "intraday_flow_score"),
            "수급 데이터 없음",
        )
        supply_status_text = _candidate_pick_display_value(
            row,
            ("flow_data_status", "수급상태", "flow_fetch_status", "flow_data_available"),
            "수급 데이터 없음",
        )
        if grade == "B":
            reason_display = (
                _candidate_reason_short(reason)
                if not _is_admin_view_mode()
                else (reason[:220] if reason else "데이터 부족")
            )
            base = {
                "등급": grade_label,
                "종목명": name or symbol,
                "종목코드": symbol or name,
                "점수": score,
                "테마": theme,
                "섹터": sector,
                "수급점수": supply_score_text,
                "수급상태": supply_status_text,
                "실적점수": earnings_score_text,
                "실적상태": earnings_status_text,
                "밸류에이션점수": valuation_score_text,
                "밸류상태": valuation_status_text,
                "판단근거": reason_display,
                "현재가": _candidate_pick_price(row, ("current_price", "last_price", "last", "stck_prpr"), row_market, "현재가 미수신"),
                "관찰 기준가": _candidate_pick_price(row, _CANDIDATE_WATCH_PRICE_ALIASES, row_market, "가격 기준 미산출"),
                "조건부 진입가": _candidate_pick_price(row, _CANDIDATE_CONDITIONAL_ENTRY_ALIASES, row_market, "가격 기준 미산출"),
                "손절가": _candidate_pick_price(row, ("stop_loss", "stop", "active_scenario_stop_loss"), row_market, "가격 기준 미산출"),
                "1차 목표가": _candidate_pick_price(row, ("take_profit1", "tp1", "target_price", "active_scenario_take_profit_1"), row_market, "가격 기준 미산출"),
                "2차 목표가": _candidate_pick_price(row, ("take_profit2", "tp2", "active_scenario_take_profit_2"), row_market, "가격 기준 미산출"),
                "손익비": _candidate_pick_display_value(row, ("rr", "손익비", "risk_reward", "active_scenario_risk_reward"), "가격 기준 미산출"),
                "기대수익률": _candidate_pick_pct(row, ("expected_return_5d", "target_upside_pct", "기대수익률"), "계산 기준 부족"),
                "손절위험": _candidate_pick_pct(row, ("prob_stop_5d", "stop_distance_pct", "손절위험"), "계산 기준 부족"),
                "진입 조건": _candidate_entry_condition_short(reason, grade),
                "데이터 상태": _candidate_data_status(row),
            }
        elif grade == "C":
            exclude_reason = _candidate_pick_display_value(
                row,
                ("제외 사유", "normalized_exclude_reason", "exclude_reason", "hard_block_reason", "trade_fit_warnings", "forecast_warnings"),
                _candidate_reason(row, grade),
            )
            current = _candidate_pick_price(row, ("current_price", "last_price", "last", "stck_prpr"), row_market, "-")
            base = {
                "등급": grade_label,
                "종목명": name or symbol,
                "종목코드": symbol or name,
                "점수": score,
                "테마": theme,
                "섹터": sector,
                "수급점수": supply_score_text,
                "수급상태": supply_status_text,
                "실적점수": earnings_score_text,
                "실적상태": earnings_status_text,
                "밸류에이션점수": valuation_score_text,
                "밸류상태": valuation_status_text,
                "제외 사유": exclude_reason[:180] if exclude_reason else "데이터 부족",
                "리스크": _candidate_first_nonempty(
                    row,
                    ("hard_block_reason", "exclude_reason", "main_risks", "trade_fit_warnings", "forecast_warnings"),
                    _candidate_reason(row, grade),
                ) or "데이터 부족",
                "권장 조치": action[:140] if action else "신규매수 금지",
                "판단근거": reason[:220] if reason else "데이터 부족",
                "현재가": current,
                "데이터 상태": _candidate_data_status(row),
            }
        else:
            base = {
                "등급": grade_label,
                "종목명": name or symbol,
                "종목코드": symbol or name,
                "점수": score,
                "테마": theme,
                "섹터": sector,
                "수급점수": supply_score_text,
                "수급상태": supply_status_text,
                "실적점수": earnings_score_text,
                "실적상태": earnings_status_text,
                "밸류에이션점수": valuation_score_text,
                "밸류상태": valuation_status_text,
                "판단근거": reason[:220] if reason else "데이터 부족",
                "데이터 상태": _candidate_data_status(row),
            }
        rows.append(base)
    out = pd.DataFrame(rows)
    if grade == "B" and not out.empty and not _is_admin_view_mode():
        ordered = [c for c in _B_GRADE_TABLE_COLUMNS if c in out.columns]
        return out[ordered] if ordered else out
    return out


def _swing_grade_counts(market: str | None) -> tuple[int, int, int]:
    if market in {None, "", "전체"}:
        a = int(len(_safe_report_csv(SWING_SCAN_KR_TOPA_FILE)) + len(_safe_report_csv(SWING_SCAN_US_TOPA_FILE)))
        b = int(len(_safe_report_csv(SWING_SCAN_KR_B_FILE)) + len(_safe_report_csv(SWING_SCAN_US_B_FILE)))
        c = int(len(_safe_report_csv(SWING_SCAN_KR_C_FILE)) + len(_safe_report_csv(SWING_SCAN_US_C_FILE)))
        return a, b, c
    paths = swing_scan_paths(market)
    return (
        int(len(_safe_report_csv(paths["a"]))),
        int(len(_safe_report_csv(paths["b"]))),
        int(len(_safe_report_csv(paths["c"]))),
    )


def _render_report_data_table(
    df: pd.DataFrame,
    path: Path,
    columns: list[str],
    *,
    status_col: str = "",
    reason_col: str = "",
    empty_label: str = "표시할 데이터 없음",
    missing_label: str = "리포트 파일 없음",
    limit: int = 80,
    include_display_names: bool = True,
) -> None:
    if not path.exists() or path.stat().st_size == 0:
        st.info(missing_label)
        return
    df = _intraday_apply_current_session_display(df)
    if include_display_names:
        df = _intraday_add_display_names(df)
        if "name" in df.columns and "name" not in columns:
            columns = ["symbol", "name"] + [c for c in columns if c != "symbol"]
    safe_columns = _filter_columns_for_screen(columns, df)
    view = _intraday_pick_columns(mark_zero_values_when_data_missing(df), safe_columns, limit=limit)
    if view.empty:
        st.info(empty_label)
        return
    if status_col and status_col in df.columns:
        hints = {
            _intraday_status_hint(str(row.get(status_col, "")), str(row.get(reason_col, "") if reason_col else ""))
            for _, row in df.head(30).iterrows()
        }
        hints.discard("")
        if hints:
            st.caption(" · ".join(sorted(hints)))
    try:
        display_view = to_korean_display(view, compact=False)
    except Exception:
        display_view = view
    display_view = clean_user_display_frame(display_view)
    st.dataframe(display_view, use_container_width=True, hide_index=True)


def _render_intraday_report_table(
    df: pd.DataFrame,
    path: Path,
    columns: list[str],
    *,
    status_col: str = "",
    reason_col: str = "",
    empty_label: str = "표시할 장중 데이터 없음",
    missing_label: str = "리포트 파일 없음",
    raw_key: str | None = None,
    include_display_names: bool = True,
) -> None:
    if not path.exists() or path.stat().st_size == 0:
        st.info(missing_label)
        return
    df = _intraday_apply_current_session_display(df)
    if include_display_names:
        df = _intraday_add_display_names(df)
        if "name" in df.columns and "name" not in columns:
            columns = ["symbol", "name"] + [c for c in columns if c != "symbol"]
    safe_columns = _filter_columns_for_screen(columns, df)
    view = _intraday_pick_columns(mark_zero_values_when_data_missing(df), safe_columns)
    if view.empty:
        st.info(empty_label)
        return
    if status_col and status_col in df.columns:
        hints = {
            _intraday_status_hint(str(row.get(status_col, "")), str(row.get(reason_col, "") if reason_col else ""))
            for _, row in df.head(30).iterrows()
        }
        hints.discard("")
        if hints:
            st.caption(" · ".join(sorted(hints)))
    try:
        display_view = _format_intraday_display_df(view)
    except Exception:
        display_view = to_korean_display(view, compact=False)
    display_view = clean_user_display_frame(display_view)
    st.dataframe(display_view, use_container_width=True, hide_index=True)
    checkbox_key = raw_key or f"intraday_raw_csv_{path.name}"
    if st.checkbox("원본 CSV 상세표", value=False, key=checkbox_key):
        st.caption("개발자용 — reports CSV 컬럼명·원본 값 그대로 (화면 포맷 미적용)")
        raw_cols = [c for c in columns if c in df.columns]
        raw_view = df[raw_cols].head(80).copy() if raw_cols else df.head(80).copy()
        st.dataframe(raw_view, use_container_width=True, hide_index=True)


def render_unified_update_results_panel(market: str | None = None, df: pd.DataFrame | None = None) -> None:
    """저장된 reports/CSV·JSON을 한 화면에 통합 표시한다 (계산 로직 없음)."""
    candidates = _load_swing_candidate_reports(market)
    market_regime_path = REPORT_DIR / "market_regime_summary.json"
    daily_quality_path = REPORT_DIR / "daily_quality_summary.json"
    portfolio_risk_path = REPORT_DIR / "portfolio_risk_summary.json"
    api_quality_path = REPORT_DIR / "api_data_quality_summary.json"
    catalyst_summary_path = REPORT_DIR / "catalyst_validation_summary.json"
    catalyst_report_path = REPORT_DIR / "catalyst_validation_report.csv"
    historical_stats_path = REPORT_DIR / "historical_pattern_stats.csv"
    fundamental_valuation_path = REPORT_DIR / "fundamental_valuation_summary.json"
    fundamental_valuation_detail_path = REPORT_DIR / "fundamental_valuation_detail.csv"

    market_regime = _safe_report_json(market_regime_path)
    daily_quality = _safe_report_json(daily_quality_path)
    portfolio_risk = _safe_report_json(portfolio_risk_path)
    api_quality = _safe_report_json(api_quality_path)
    catalyst_summary = _safe_report_json(catalyst_summary_path)
    fundamental_valuation = _safe_report_json(fundamental_valuation_path)
    coverage = _safe_report_json(REPORT_DIR / "intraday_data_coverage_diagnosis.json")

    a_cnt, b_cnt, c_cnt = _swing_grade_counts(market)
    c_trade, c_entry = _c_excluded_intraday_safety_counts()
    daily_check_status = _derive_daily_system_check_status(coverage)
    new_buy = market_regime.get("new_buy_allowed")
    new_buy_label = "가능" if new_buy is True else ("금지" if new_buy is False else "확인 필요")

    st.markdown("## 업데이트 결과 확인")
    st.caption(
        "업데이트 결과 — `reports/` CSV·JSON만 읽어 표시합니다. "
        "미수신·미지원·장마감은 오류가 아닙니다. "
        f"C 제외 후보 매수 가능 {c_trade}건 · 장중 진입 확인 {c_entry}건"
    )

    prob_cols = [
        "symbol",
        "name",
        "market",
        "prob_up_1d",
        "prob_up_3d",
        "prob_up_5d",
        "prob_up_10d",
        "prob_tp1_5d",
        "prob_stop_5d",
        "expected_return_5d",
        "forecast_label",
        "forecast_confidence",
        "risk_final_decision",
    ]
    quality_cols = [
        "symbol",
        "stock_attractiveness_score",
        "stock_quality_level",
        "stock_quality_reasons",
        "trade_fit_score",
        "price_fit_level",
        "entry_gap_pct",
        "trade_fit_reasons",
        "entry_position_type",
        "entry_position_score",
        "entry_position_reason",
    ]
    catalyst_cols = [
        "symbol",
        "catalyst_score",
        "news_importance_score",
        "news_freshness_score",
        "disclosure_score",
        "earnings_score",
        "supply_score",
        "catalyst_reasons",
        "catalyst_warnings",
        "decision_change_log",
    ]
    fundamental_cols = [
        "symbol",
        "market",
        "name",
        "earnings_score",
        "earnings_data_status",
        "earnings_reason",
        "earnings_source",
        "revenue_growth",
        "operating_income_growth",
        "net_income_growth",
        "valuation_score",
        "valuation_data_status",
        "valuation_reason",
        "valuation_source",
        "per",
        "pbr",
        "psr",
        "roe",
        "market_cap",
    ]
    hist_cols = [
        "symbol",
        "historical_condition_key",
        "historical_sample_count",
        "historical_tp1_hit_rate_5d",
        "historical_stop_hit_rate_5d",
        "historical_expected_return_5d",
        "historical_pattern_note",
    ]
    sell_cols = [
        "symbol",
        "sell_timing_label",
        "profit_taking_plan",
        "hold_or_sell_decision",
        "trailing_stop_level",
        "exit_invalid_condition",
        "sell_reasons",
        "sell_warnings",
    ]

    tab_summary, tab_prob, tab_quality, tab_catalyst, tab_fundamental, tab_hist, tab_sell, tab_port = st.tabs([
        "오늘 요약",
        "미래 확률표",
        "종목/가격/진입",
        "Catalyst",
        "실적/밸류",
        "유사조건",
        "매도/보유",
        "포트폴리오",
    ])

    with tab_summary:
        s1, s2, s3, s4, s5, s6, s7, s8 = st.columns(8)
        s1.metric("오늘 매수 가능 여부", new_buy_label)
        s2.metric("시장 상태", _user_display_value(market_regime.get("market_regime", market_regime.get("strategy_mode", "미생성"))))
        s3.metric("데이터 품질", format_user_facing_status_label(daily_quality.get("overall_status", daily_quality.get("summary_score", "-"))))
        s4.metric("API 상태", _api_overall_user_label(api_quality))
        s5.metric("포트폴리오 위험도", _user_display_value(portfolio_risk.get("portfolio_risk_level", "-")))
        s6.metric("장중 데이터 상태", format_user_facing_status_label(daily_check_status))
        s7.metric("A/B/C 후보", f"{a_cnt}/{b_cnt}/{c_cnt}")
        s8.metric("C/금지 안전성", "정상" if not (c_trade or c_entry) else "오류")
