def latest_log_time(log_df: pd.DataFrame, market: str, only_completed: bool = False) -> str:
    """예측 기록의 최근 생성/완료 시간을 반환."""
    try:
        if log_df is None or log_df.empty:
            return "-"
        df = log_df.copy()
        if "market" in df.columns:
            df = df[df["market"].astype(str).eq(market)]
        if df.empty:
            return "-"
        if only_completed:
            if "actual_close" not in df.columns:
                return "-"
            df["_actual_close_num"] = pd.to_numeric(df["actual_close"], errors="coerce")
            df = df[df["_actual_close_num"].notna()]
            if df.empty:
                return "-"
        if "created_at" not in df.columns:
            return "-"
        dt = pd.to_datetime(df["created_at"], errors="coerce").dropna()
        if dt.empty:
            return "-"
        return dt.max().strftime("%Y-%m-%d %H:%M")
    except Exception:
        return "-"


def latest_target_date_label(log_df: pd.DataFrame, market: str) -> str:
    """가장 최근 미완료 예측 대상일."""
    try:
        if log_df is None or log_df.empty:
            return "-"
        df = next_pending_predictions(log_df, market=market, limit=50)
        if df is None or df.empty or "target_date" not in df.columns:
            return "-"
        dates = pd.to_datetime(df["target_date"], errors="coerce").dropna()
        if dates.empty:
            return "-"
        return dates.max().strftime("%Y-%m-%d")
    except Exception:
        return "-"



def _runner_rows_for_market(market: str) -> pd.DataFrame:
    try:
        df = read_runner_log_status()
        if df is None or df.empty:
            return pd.DataFrame()
        keys = ["국장 예측", "국장 업데이트"] if market == "한국주식" else ["미장 예측", "미장 업데이트"]
        return df[df["작업"].astype(str).isin(keys)].copy()
    except Exception:
        return pd.DataFrame()


def render_scheduler_status_board(log_df: pd.DataFrame, market: str) -> None:
    """데이터 상태판. predictions.csv 기준과 runner 로그 기준을 분리 표시."""
    mode_label = "국장" if market == "한국주식" else "미장"
    pred_time = latest_log_time(log_df, market, only_completed=False)
    update_time = latest_log_time(log_df, market, only_completed=True)
    target_label = latest_target_date_label(log_df, market)
    file_time, file_status = file_mtime_label(PREDICTION_FILE)
    watch_file = resolve_watchlist_file(market)
    watch_time, watch_status = file_mtime_label(watch_file)

    pending = next_pending_predictions(log_df, market=market, limit=200)
    pending_count = 0 if pending is None or pending.empty else len(pending)
    runner_rows = _runner_rows_for_market(market)

    bad_runner = 0
    good_runner = 0
    running_runner = 0
    if not runner_rows.empty and "상태" in runner_rows.columns:
        s = runner_rows["상태"].astype(str)
        good_runner = int(s.isin(["정상", "데이터 경고"]).sum())
        running_runner = int(s.eq("실행 중").sum())
        bad_runner = int(s.isin(["확인 필요", "읽기 실패", "로그 없음"]).sum())

    if pred_time == "-":
        status = "예측 없음"
        status_delta = "예측 runner 실행 필요"
    elif bad_runner > 0:
        status = "확인 필요"
        status_delta = f"runner 확인 {bad_runner}건"
    elif running_runner > 0:
        status = "실행 중"
        status_delta = f"runner 실행 중 {running_runner}건"
    elif file_status == "정상":
        status = "정상"
        status_delta = f"미완료 예측 {pending_count}건"
    else:
        status = "파일 확인"
        status_delta = f"predictions.csv {file_status}"

    st.markdown('<div class="dashboard-panel">', unsafe_allow_html=True)
    st.subheader(f"🧭 {mode_label} 데이터 상태판")
    st.caption("위 4개 카드는 predictions.csv 기준입니다. 아래 작업스케줄러 로그는 runner 실행 기준이라 서로 다를 수 있습니다.")

    status_badge = "badge" if status == "정상" else ("badge-yellow" if status in ["확인 필요", "파일 확인", "실행 중"] else "badge-red")
    c1, c2, c3, c4 = st.columns(4)
    c1.markdown(
        f"<div class='card'><div class='small'>전체 상태</div><span class='badge {status_badge}'>{status}</span><div class='small' style='margin-top:8px'>{status_delta}</div></div>",
        unsafe_allow_html=True,
    )
    c2.markdown(
        f"<div class='card'><div class='small'>마지막 예측 생성</div><div class='big' style='font-size:1.1rem'>{pred_time}</div><div class='small'>CSV 기록 기준</div></div>",
        unsafe_allow_html=True,
    )
    c3.markdown(
        f"<div class='card'><div class='small'>마지막 결과 업데이트</div><div class='big' style='font-size:1.1rem'>{update_time}</div><div class='small'>actual_close 입력 기준</div></div>",
        unsafe_allow_html=True,
    )
    c4.markdown(
        f"<div class='card'><div class='small'>현재 예측 대상일</div><div class='big' style='font-size:1.1rem'>{target_label}</div><div class='small'>미완료 예측 기준</div></div>",
        unsafe_allow_html=True,
    )

    d1, d2, d3 = st.columns(3)
    with d1:
        st.caption(f"predictions.csv 수정: {file_time} · {file_status}")
    with d2:
        st.caption(f"watchlist 수정: {watch_time} · {watch_status}")
    with d3:
        if market == "미국주식":
            st.caption("자동화 권장: runner_us_predict 22:00 / runner_us_update 06:10")
        else:
            st.caption("자동화 권장: runner_kr_predict 16:10 / runner_kr_update 15:45")

    if not runner_rows.empty:
        with st.expander(f"{mode_label} runner 로그 기준 상세", expanded=False):
            st.dataframe(runner_rows, use_container_width=True, hide_index=True)
            st.caption("자동 예측/업데이트는 Windows 작업스케줄러 또는 runner_*.bat가 실행해야 갱신됩니다. 앱 화면은 기존 CSV를 읽어 보여주는 역할입니다.")

    st.markdown('</div>', unsafe_allow_html=True)



def render_top_action_cards(view: pd.DataFrame, log_df: pd.DataFrame | None, market: str, target_label: str) -> None:
    """매수 판단 보드 상위 후보 3개를 카드로 표시."""
    if view is None or view.empty:
        return
    try:
        action_df = add_buy_action_columns(view, log_df=log_df, market=market)
    except Exception:
        action_df = view.copy()
    if action_df is None or action_df.empty:
        return

    render_card_news_candidates(
        action_df,
        market,
        title="확인 후보 TOP3",
        target_label=target_label,
        top_n=3,
        subtitle="실제 매수 직전 최종판단·신규매수 금지·진입/손절/익절 기준을 먼저 확인하세요.",
    )


def build_action_candidate_df(log_df: pd.DataFrame, market: str, limit: int = 50) -> tuple[pd.DataFrame, str]:
    """다음 장 예측을 오늘 행동 판단용 DataFrame으로 변환."""
    pending = next_pending_predictions(log_df, market=market, limit=limit)
    if pending is None or pending.empty:
        return pd.DataFrame(), "-"
    target_dates = sorted(pending["target_date"].astype(str).dropna().unique().tolist()) if "target_date" in pending.columns else []
    target_label = target_dates[0] if target_dates else "-"
    view = force_us_symbol_column(build_next_prediction_view_v39(pending, log_df, market), market)
    if view.empty:
        return pd.DataFrame(), target_label
    action_df = add_buy_action_columns(view, log_df=log_df, market=market)
    return action_df, target_label


def summarize_action_counts(action_df: pd.DataFrame) -> dict[str, int]:
    if action_df is None or action_df.empty:
        return {"우선 확인": 0, "진입가 대기": 0, "관망/제외": 0, "매수금지": 0, "주의": 0}
    counts = action_df.get("매수행동", pd.Series(dtype=str)).astype(str).value_counts()
    no_buy_n = int(action_df.get("매수금지", pd.Series(False, index=action_df.index)).astype(bool).sum()) if "매수금지" in action_df.columns else 0
    warn_n = int(action_df.get("주의사유", pd.Series("-", index=action_df.index)).astype(str).ne("-").sum()) if "주의사유" in action_df.columns else 0
    return {
        "우선 확인": int(counts.get("우선 확인", 0)),
        "진입가 대기": int(counts.get("진입가 대기", 0)),
        "관망/제외": int(counts.get("관망/제외", 0)),
        "매수금지": no_buy_n,
        "주의": warn_n,
    }



def render_today_action_summary(action_df: pd.DataFrame, market: str, target_label: str) -> None:
    """상단에서 표를 다 읽기 전에 오늘 행동 방향을 카드형으로 요약."""
    if action_df is None or action_df.empty:
        return
    try:
        _native_card_css_once()
    except Exception:
        pass
    counts = summarize_action_counts(action_df)
    top_confirm = action_df[action_df["매수행동"].astype(str).eq("우선 확인")].head(5) if "매수행동" in action_df.columns else pd.DataFrame()
    wait_df = action_df[action_df["매수행동"].astype(str).eq("진입가 대기")].head(5) if "매수행동" in action_df.columns else pd.DataFrame()
    no_buy_df = action_df[action_df.get("매수금지", pd.Series(False, index=action_df.index)).astype(bool)].head(5) if "매수금지" in action_df.columns else pd.DataFrame()

    if counts["우선 확인"] > 0:
        overall = "조건 확인 후보 있음"
        state_label = "조건부 접근"
        tone = "green"
    elif counts["진입가 대기"] > 0:
        overall = "진입가 대기 우선"
        state_label = "추격 금지"
        tone = "yellow"
    else:
        overall = "관망 우위"
        state_label = "리스크 우선"
        tone = "red"

    def _join_symbols(df: pd.DataFrame) -> str:
        if df is None or df.empty or "종목" not in df.columns:
            return "-"
        return ", ".join([display_symbol(x, market) for x in df["종목"].astype(str).head(5).tolist()])

    stat_cards = "".join([
        _card_metric("우선 확인", f'{counts["우선 확인"]}개'),
        _card_metric("진입가 대기", f'{counts["진입가 대기"]}개'),
        _card_metric("관망/제외", f'{counts["관망/제외"]}개'),
        _card_metric("매수금지", f'{counts["매수금지"]}개', "danger"),
        _card_metric("주의", f'{counts["주의"]}개', "danger" if counts["주의"] else ""),
    ])
    html = f"""
    <section class="cn-summary-card {tone}">
      <div class="cn-summary-head">
        <div>
          <div class="cn-kicker">TODAY ACTION</div>
          <div class="cn-title">오늘 행동 요약: {_ui_escape_v9976(overall)}</div>
          <div class="cn-sub">{_ui_escape_v9976(market)} · 예측대상일 {_ui_escape_v9976(target_label)} · 신규 매수는 우선진입가/손절가/뉴스 재확인 후 판단</div>
        </div>
        <span class="cn-summary-badge {tone}">{_ui_escape_v9976(state_label)}</span>
      </div>
      <div class="cn-summary-grid">{stat_cards}</div>
      <div class="cn-oper-board">
        <div><span>우선 확인</span><b>{_ui_escape_v9976(_join_symbols(top_confirm))}</b></div>
        <div><span>진입가 대기</span><b>{_ui_escape_v9976(_join_symbols(wait_df))}</b></div>
        <div><span>추격/신규매수 주의</span><b>{_ui_escape_v9976(_join_symbols(no_buy_df))}</b></div>
        <div><span>오늘 행동</span><b>추격 금지, 조건 충족 전 신규매수 금지</b></div>
        <div><span>확인 순서</span><b>진입가 → 손절가 → 뉴스 → 현재가 괴리</b></div>
      </div>
    </section>
    """
    st.markdown(html, unsafe_allow_html=True)


def build_order_report_df(log_df: pd.DataFrame, market: str) -> tuple[pd.DataFrame, str]:
    action_df, target_label = build_action_candidate_df(log_df, market, limit=100)
    if action_df is None or action_df.empty:
        return pd.DataFrame(), target_label
    cols = [
        "실전우선순위", "실전최종판정", "실전판정이유", "상태", "매수행동", "매수금지", "종목", "판정",
        "실시간현재가", "실시간괴리", "실시간판정", "학습보정", "학습요약",
        "품질점수", "재무", "수급", "품질요약", "보정신뢰도", "매매적합도", "앙상블추정점수", "성과보정",
        "추천수량", "주문예상금액", "3분할계획", "예상평단", "평단손절위험", "1R위험금액", "매수단위근거",
        "손익비", "우선진입가", "보수대기선", "지지존", "저항존", "진입거리", "전일대비진입", "손절가", "손절폭", "1차익절가", "익절거리", "2차익절가",
        "예상시초가", "예상종가범위", "주문검증", "주문검증메모", "진입근거", "주의사유", "금지사유", "행동이유",
        "created_at", "session_type", "session_label",
        "basis_ohlc_date", "basis_open", "basis_high", "basis_low", "basis_close", "basis_volume", "basis_source",
        "current_price_at_prediction", "current_price_source",
        "stock_code", "stock_name",
        "prediction_freshness", "prediction_freshness_issue", "basis_ohlc_valid", "basis_ohlc_issue",
        "invalidation_condition", "data_status", "risk_reward_ratio", "final_judgment", "suggested_action",
        "reason", "risk_reason", "buy_reason",
    ]
    out = action_df[[c for c in cols if c in action_df.columns]].copy()
    out.insert(0, "시장", market)
    out.insert(1, "예측대상일", target_label)
    if not out.empty:
        out["report_generated_at"] = datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S")
    return out, target_label


def action_summary_text_from_df(report_df: pd.DataFrame, market: str, target_label: str) -> str:
    if report_df is None or report_df.empty:
        return f"{market} / {target_label}: 표시할 주문 계획이 없습니다."
    counts = report_df["매수행동"].astype(str).value_counts() if "매수행동" in report_df.columns else pd.Series(dtype=int)
    no_buy_n = int(report_df.get("매수금지", pd.Series(False, index=report_df.index)).astype(bool).sum()) if "매수금지" in report_df.columns else 0
    top = report_df.head(5)
    lines = [
        f"# {market} 오늘 행동 요약",
        f"- 예측대상일: {target_label}",
        f"- 우선 확인: {int(counts.get('우선 확인', 0))}개",
        f"- 진입가 대기: {int(counts.get('진입가 대기', 0))}개",
        f"- 관망/제외: {int(counts.get('관망/제외', 0))}개",
        f"- 매수금지: {no_buy_n}개",
        "",
        "## TOP 후보",
    ]
    for _, r in top.iterrows():
        lines.append(
            f"- {r.get('종목','-')} | {r.get('매수행동','-')} | 진입 {r.get('우선진입가','-')} | 손절 {r.get('손절가','-')} | 1차익절 {r.get('1차익절가','-')} | 손익비 {r.get('손익비','-')}"
        )
    lines += [
        "",
        "※ 이 리포트는 투자 조언이 아니라 매매 판단 보조 자료입니다. 실제 주문 전 현재가, 호가, 뉴스, 거래량을 다시 확인하세요.",
    ]
    return "\n".join(lines)


def save_latest_order_reports(log_df: pd.DataFrame, market: str) -> dict[str, str]:
    """작업스케줄러/버튼 실행 후 최신 주문계획 CSV/HTML/TXT 저장."""
    REPORT_DIR.mkdir(exist_ok=True)
    report_df, target_label = build_order_report_df(log_df, market)
    prefix = "kr" if market == "한국주식" else "us"
    stamp = datetime.now(KST).strftime("%Y%m%d_%H%M%S")

    latest_csv = REPORT_DIR / f"latest_{prefix}_order_plan.csv"
    latest_html = REPORT_DIR / f"latest_{prefix}_summary.html"
    latest_txt = REPORT_DIR / f"latest_{prefix}_summary.txt"
    stamped_csv = REPORT_DIR / f"order_plan_{prefix}_{stamp}.csv"
    stamped_html = REPORT_DIR / f"summary_{prefix}_{stamp}.html"

    if report_df.empty:
        text_summary = action_summary_text_from_df(report_df, market, target_label)
        latest_txt.write_text(text_summary, encoding="utf-8")
        latest_html.write_text(
            f"<html><head><meta charset='utf-8'></head><body><pre>{text_summary}</pre></body></html>",
            encoding="utf-8",
        )
        latest_json = REPORT_DIR / f"latest_{prefix}_result.json"
        latest_json.write_text(
            json.dumps(
                {
                    "market": market,
                    "target_label": target_label,
                    "row_count": 0,
                    "saved_at_kst": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S"),
                },
                ensure_ascii=False,
                indent=2,
            ),
            encoding="utf-8",
        )
        return {"txt": str(latest_txt), "html": str(latest_html), "json": str(latest_json)}

    report_df.to_csv(latest_csv, index=False, encoding="utf-8-sig")
    report_df.to_csv(stamped_csv, index=False, encoding="utf-8-sig")

    text_summary = action_summary_text_from_df(report_df, market, target_label)
    latest_txt.write_text(text_summary, encoding="utf-8")

    html_display_df = _arrow_safe_display_data(report_df)
    html_table = html_display_df.to_html(index=False, escape=False)
    html = f"""
<!doctype html>
<html lang="ko">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>{market} 오늘 주문계획</title>
<style>
body {{ font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; margin: 18px; background:#0f172a; color:#e2e8f0; }}
h1 {{ font-size: 22px; }}
.card {{ background:#111827; border:1px solid #334155; border-radius:14px; padding:14px; margin-bottom:14px; }}
pre {{ white-space: pre-wrap; line-height:1.55; }}
table {{ border-collapse: collapse; width: 100%; font-size: 13px; background:#020617; }}
th, td {{ border:1px solid #334155; padding:7px 8px; text-align:left; }}
th {{ background:#1e293b; position:sticky; top:0; }}
tr:nth-child(even) {{ background:#0b1220; }}
.warn {{ color:#fbbf24; }}
</style>
</head>
<body>
<h1>{market} 오늘 주문계획</h1>
<div class="card"><pre>{text_summary}</pre></div>
<div class="card">{html_table}</div>
<p class="warn">※ 투자 조언이 아니라 판단 보조 자료입니다. 실제 주문 전 현재가, 호가, 뉴스, 거래량을 다시 확인하세요.</p>
</body>
</html>
"""
    latest_html.write_text(html, encoding="utf-8")
    stamped_html.write_text(html, encoding="utf-8")
    latest_json = REPORT_DIR / f"latest_{prefix}_result.json"
    top_syms: list[str] = []
    if "종목" in report_df.columns:
        top_syms = report_df["종목"].astype(str).head(8).tolist()
    elif "ticker" in report_df.columns:
        top_syms = report_df["ticker"].astype(str).head(8).tolist()
    latest_json.write_text(
        json.dumps(
            {
                "market": market,
                "target_label": target_label,
                "row_count": int(len(report_df)),
                "top_symbols": top_syms,
                "saved_at_kst": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S"),
            },
            ensure_ascii=False,
            indent=2,
        ),
        encoding="utf-8",
    )
    return {
        "csv": str(latest_csv),
        "html": str(latest_html),
        "txt": str(latest_txt),
        "json": str(latest_json),
        "stamped_csv": str(stamped_csv),
        "stamped_html": str(stamped_html),
    }


def render_latest_report_panel(log_df: pd.DataFrame, market: str) -> None:
    """앱에서 latest 주문계획 리포트를 수동 생성."""
    with st.expander("📄 최신 주문 리포트 저장/확인", expanded=False):
        st.caption("작업스케줄러가 예측을 생성할 때 자동 저장되며, 여기서 수동으로 다시 만들 수도 있습니다.")
        if st.button("latest 주문계획 CSV/HTML/TXT 지금 저장", use_container_width=True, key=f"save_latest_report_v970_{market}"):
            paths = save_latest_order_reports(log_df, market)
            st.success("리포트 저장 완료")
            for k, v in paths.items():
                st.caption(f"{k}: {v}")
        prefix = "kr" if market == "한국주식" else "us"
        expected = [
            REPORT_DIR / f"latest_{prefix}_order_plan.csv",
            REPORT_DIR / f"latest_{prefix}_summary.html",
            REPORT_DIR / f"latest_{prefix}_summary.txt",
            REPORT_DIR / f"latest_{prefix}_result.json",
        ]
        for p in expected:
            if p.exists():
                st.caption(f"저장됨: {p} / 수정 {datetime.fromtimestamp(p.stat().st_mtime).strftime('%Y-%m-%d %H:%M')}")
            else:
                st.caption(f"아직 없음: {p}")



def render_next_prediction_dashboard(log_df: pd.DataFrame, market: str) -> None:
    """시장 확인 후 다음 장 예측/추천 후보를 보기 좋게 보여주는 대시보드."""
    pending = next_pending_predictions(log_df, market=market, limit=50)
    mode_label = "국장" if market == "한국주식" else "미장"
    runner_name = "runner_kr_predict" if market == "한국주식" else "runner_us_predict"
    watchlist_file = "watchlist_kr_growth.csv" if market == "한국주식" else "watchlist_us_growth.csv"

    st.markdown('<div class="dashboard-panel">', unsafe_allow_html=True)
    st.subheader(sanitize_user_title(f"{mode_label} 장전 예측 확정·TOP 후보"))
    st.caption(f"{mode_label} 장전 확정 예측입니다. 장중에는 예측값을 다시 계산하지 않고 무효화 경고만 확인합니다.")

    if pending.empty:
        st.warning(f"아직 {mode_label} 확정 예측 기록이 없습니다. 장전 예측 생성 시간 이후 다시 실행하거나 데이터 상태를 확인하세요.")
        c1, c2 = st.columns(2)
        with c1:
            st.markdown(f"**자동 생성 확인**  \n- 작업스케줄러/배치: `{runner_name}`  \n- 관심종목 파일: `{watchlist_file}`")
        with c2:
            st.markdown("**바로 확인 방법**  \n- 장전 1차/2차 배치 실행 여부 확인  \n- 작업스케줄러 실행 후 앱 새로고침")
        st.info("예측 기록이 생성되면 ① TOP 후보와 ② 우선진입가·손절가·익절가 실행 기준이 표시됩니다.")
        st.markdown('</div>', unsafe_allow_html=True)
        return

    target_dates = sorted(pending["target_date"].astype(str).dropna().unique().tolist()) if "target_date" in pending.columns else []
    target_label = target_dates[0] if target_dates else "-"
    display_mode = str(pending.get("_prediction_display_mode", pd.Series(["미완료 다음 장 예측"])).iloc[0]) if not pending.empty else ""
    if display_mode == "최근 저장 예측 배치":
        st.warning("현재 미완료 다음 장 예측이 없어, 가장 최근 저장된 예측 배치를 TOP 후보/차트 확인용으로 표시합니다. 앱 시작 자동 동기화가 지난 장 실제값을 이미 채웠을 때 정상적으로 발생할 수 있습니다.")
    st.caption(f"현재 표시 기준: {mode_label} / 예측대상일 {target_label} / 표시모드 {display_mode or '-'} / 표시 예측 {len(pending)}건 · ① TOP 후보 → ② 실행 기준 → 상세 차트 확인 순서로 봅니다.")

    view = force_us_symbol_column(build_next_prediction_view_v39(pending, log_df, market), market)
    if view.empty:
        st.info("표시할 다음 장 예측 데이터가 없습니다.")
        st.markdown('</div>', unsafe_allow_html=True)
        return

    reliability_result = compute_app_reliability_score(market, log_df)

    render_tradeability_banner_v9955(view, market)
    action_df = build_unified_decision_df(view, log_df, market)
    render_today_action_summary(action_df, market, target_label)

    # 단일 카드뉴스 흐름: 행동 요약 → 1순위 → TOP3 → 주문계획 → 상세 원본
    c1, c2, c3, c4, c5 = st.columns(5)
    with c1:
        st.metric("다음 장 예측", f"{len(action_df)}건")
    with c2:
        top_symbol = action_df.iloc[0].get("카드종목명", action_df.iloc[0].get("종목", "-")) if len(action_df) else "-"
        st.metric("TOP 후보", top_symbol)
    with c3:
        avg_conf = pd.to_numeric(action_df.get("보정신뢰도"), errors="coerce").mean()
        st.metric("평균 보정신뢰도", f"{avg_conf:.0f}점" if not np.isnan(avg_conf) else "-")
    with c4:
        avg_trade = pd.to_numeric(action_df.get("매매적합도"), errors="coerce").mean()
        st.metric("평균 매매적합도", f"{avg_trade:.0f}점" if not np.isnan(avg_trade) else "-")
    with c5:
        warn_n = int((action_df.get("주의사유", pd.Series("-", index=action_df.index)).astype(str) != "-").sum()) if not action_df.empty else 0
        st.metric("주의 필요", f"{warn_n}건")

    render_card_news_candidates(
        action_df,
        market,
        title="오늘 1순위 확인 후보",
        target_label=target_label,
        top_n=1,
        subtitle="최종판단·신규매수 금지·진입/손절/익절 기준을 카드 하나로 정리했습니다.",
        reliability_result=reliability_result,
    )
    render_card_news_candidates(
        action_df,
        market,
        title="확인 후보 TOP3",
        target_label=target_label,
        top_n=3,
        subtitle="실제 매수 직전 최종판단·신규매수 금지·진입/손절/익절 기준을 먼저 확인하세요.",
        reliability_result=reliability_result,
    )
    st.markdown("## ② 매수·매도 실행 기준")
    st.caption("①에서 확정된 TOP 후보를 실제 매수·매도 기준가로 바꾸는 영역입니다. 진입가·손절가·익절가·손익비를 먼저 확인합니다.")
    render_execution_plan_panel(pending, log_df, market)
    render_latest_report_panel(log_df, market)

    with st.expander("🔎 상세 표·차트·원본 기록 보기", expanded=False):
        tab1, tab2, tab3, tab4, tab5 = st.tabs(["📌 주문 기준표", "📈 차트 보기", "🚫 매수 주의", "📊 신뢰도/오차", "🧾 원본 기록"])
        with tab1:
            cols = ["예측대상일", "종목", "판정", "보정신뢰도", "매매적합도", "예상시초가", "예상종가범위", "우선진입가", "손절가", "1차익절가", "2차익절가"]
            st.dataframe(view[[c for c in cols if c in view.columns]], use_container_width=True, hide_index=True)
        with tab2:
            st.caption("표 안의 행을 직접 클릭해서 이동하는 방식 대신, 아래에서 종목을 선택하면 해당 종목 차트와 예측선을 바로 보여줍니다.")
            if market == "미국주식" and "ticker" in pending.columns:
                raw_names = pending.get("종목", pd.Series([""] * len(pending))).astype(str).tolist()
                options = [
                    display_symbol(t, market, s)
                    for t, s in zip(pending["ticker"].astype(str).tolist(), raw_names)
                ]
            else:
                options = [display_symbol(x, market) for x in view["종목"].astype(str).tolist()]
            options = list(dict.fromkeys(options))
            default_idx = 0
            selected_symbol = st.selectbox("차트로 볼 종목 선택", options, index=default_idx, key=f"next_chart_select_{market}_{target_label}")
            mapped_pending = pending.copy()
            pending_names = mapped_pending.get("종목", pd.Series([""] * len(mapped_pending))).astype(str).tolist()
            mapped_pending["_display_ticker"] = [
                display_symbol(t, market, s)
                for t, s in zip(mapped_pending.get("ticker", pd.Series([""] * len(mapped_pending))).astype(str).tolist(), pending_names)
            ]
            raw_row = mapped_pending[mapped_pending["_display_ticker"].astype(str).str.upper().eq(str(selected_symbol).upper())]
            if raw_row.empty:
                st.warning("선택한 종목의 원본 예측 기록을 찾지 못했습니다.")
            else:
                render_selected_prediction_chart(raw_row.iloc[0], market)
        with tab3:
            warn_df = view[view["주의사유"].astype(str) != "-"] if "주의사유" in view.columns else pd.DataFrame()
            if warn_df.empty:
                st.success("현재 다음 장 예측 기록 중 별도 주의사유가 표시된 종목은 없습니다.")
            else:
                cols = ["예측대상일", "종목", "판정", "보정신뢰도", "매매적합도", "우선진입가", "손절가", "주의사유"]
                st.dataframe(warn_df[[c for c in cols if c in warn_df.columns]], use_container_width=True, hide_index=True)
        with tab4:
            cols = ["종목", "보정신뢰도", "매매적합도", "누적기록", "최근종가오차", "신뢰도메모", "매매메모"]
            st.dataframe(view[[c for c in cols if c in view.columns]], use_container_width=True, hide_index=True)
            st.caption("보정신뢰도는 예측 범위가 맞을 가능성, 매매적합도는 손익비·손절폭·주의사유까지 반영한 실전 적합도입니다.")
        with tab5:
            st.dataframe(to_korean_display(pending, compact=True), use_container_width=True)

    st.markdown('</div>', unsafe_allow_html=True)



def daily_summary_markdown(log_df: pd.DataFrame, scan_df: pd.DataFrame | None = None, market: str = "미국주식") -> str:
    """매일 확인용 요약 리포트 생성."""
    today = datetime.now(KST).strftime("%Y-%m-%d %H:%M")
    lines = [
        f"# 자동 매매 보조 리포트",
        f"- 생성시각: {today}",
        f"- 시장: {market}",
        "",
    ]

    if log_df is not None and not log_df.empty:
        done = log_df[pd.to_numeric(log_df.get("open_error_pct"), errors="coerce").notna()] if "open_error_pct" in log_df.columns else pd.DataFrame()
        lines.append("## 1. 예측 결과 업데이트")
        lines.append(f"- 전체 예측 기록: {len(log_df)}건")
        lines.append(f"- 실제 결과 반영 완료: {len(done)}건")
        if not done.empty:
            open_abs = pd.to_numeric(done.get("open_abs_error_pct"), errors="coerce").mean()
            close_abs = pd.to_numeric(done.get("close_abs_error_pct"), errors="coerce").mean()
            open_hit = done.get("open_in_range", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"]).mean() * 100
            close_hit = done.get("close_in_range", pd.Series(dtype=object)).astype(str).str.lower().isin(["true", "1"]).mean() * 100
            lines += [
                f"- 평균 시초가 절대오차: {open_abs:.2f}%",
                f"- 평균 종가 절대오차: {close_abs:.2f}%",
                f"- 시초가 범위 적중률: {open_hit:.1f}%",
                f"- 종가 범위 적중률: {close_hit:.1f}%",
            ]
        lines.append("")
    else:
        lines += ["## 1. 예측 결과 업데이트", "- 저장된 예측 기록이 없습니다.", ""]

    if scan_df is not None and not scan_df.empty:
        lines.append("## 2. 확인 후보 TOP3")
        for _, r in scan_df.head(5).iterrows():
            sym = r.get("종목", "")
            score = r.get("순위점수", r.get("점수", ""))
            cls = r.get("후보분류", r.get("주문판단", ""))
            price = r.get("최근가/확장세션", r.get("최근가", ""))
            entry = r.get("우선진입가", "")
            stop = r.get("손절가", "")
            lines.append(f"- {sym}: {score}점 / {cls} / 최근가 {price} / 진입 {entry} / 손절 {stop}")
        nb = no_buy_candidates_from_scan(scan_df)
        if not nb.empty:
            lines.append("")
            lines.append("## 3. 매수 주의 후보")
            for _, r in nb.head(5).iterrows():
                sym = r.get("종목", "")
                why = " / ".join(str(r.get(c, "")) for c in ["주의사유", "탈락/주의사유", "매수금지", "회피조건"] if c in r and str(r.get(c, "")) not in ["", "-"])
                lines.append(f"- {sym}: {why[:120]}")
        lines.append("")

    lines.append("## 4. 주의")
    lines.append("- 이 리포트는 투자 조언이 아니라 예측 범위와 주문 기준선을 정리한 참고자료입니다.")
    lines.append("- 실제 주문은 손절가와 손익비를 확인한 뒤 본인 책임으로 결정해야 합니다.")
    return "\n".join(lines)


def save_daily_summary(log_df: pd.DataFrame, scan_df: pd.DataFrame | None = None, market: str = "미국주식") -> str:
    REPORT_DIR.mkdir(exist_ok=True)
    stamp = datetime.now(KST).strftime("%Y%m%d_%H%M%S")
    out = REPORT_DIR / f"daily_summary_{market}_{stamp}.md"
    text = daily_summary_markdown(log_df, scan_df, market)
    out.write_text(text, encoding="utf-8")
    return str(out)


def load_alert_config() -> dict[str, Any]:
    if not ALERT_CONFIG_FILE.exists():
        return {}
    try:
        return json.loads(ALERT_CONFIG_FILE.read_text(encoding="utf-8"))
    except Exception:
        return {}


def send_telegram_message(text: str) -> bool:
    """alert_config.json 또는 환경변수 기반 텔레그램 알림. 미설정이면 조용히 건너뜀."""
    cfg = load_alert_config()
    token = cfg.get("telegram_bot_token") or os.getenv("TELEGRAM_BOT_TOKEN")
    chat_id = cfg.get("telegram_chat_id") or os.getenv("TELEGRAM_CHAT_ID")
    if not token or not chat_id:
        return False
    try:
        import requests
        url = f"https://api.telegram.org/bot{token}/sendMessage"
        r = requests.post(url, data={"chat_id": chat_id, "text": text[:3900]}, timeout=10)
        return r.status_code == 200
    except Exception:
        return False


def send_email_summary(subject: str, body: str) -> bool:
    """SMTP 설정이 있을 때만 이메일 알림."""
    cfg = load_alert_config()
    host = cfg.get("smtp_host") or os.getenv("SMTP_HOST")
    port = int(cfg.get("smtp_port") or os.getenv("SMTP_PORT") or 587)
    user = cfg.get("smtp_user") or os.getenv("SMTP_USER")
    password = cfg.get("smtp_password") or os.getenv("SMTP_PASSWORD")
    to_addr = cfg.get("email_to") or os.getenv("EMAIL_TO")
    if not host or not user or not password or not to_addr:
        return False
    try:
        msg = EmailMessage()
        msg["Subject"] = subject
        msg["From"] = user
        msg["To"] = to_addr
        msg.set_content(body)
        with smtplib.SMTP(host, port, timeout=15) as s:
            s.starttls()
            s.login(user, password)
            s.send_message(msg)
        return True
    except Exception:
        return False


