def load_candidate_universe_df(market: str) -> pd.DataFrame:
    path = resolve_candidate_file(market)
    try:
        if path.exists():
            df = read_csv_cached(path, dtype_str=True).fillna("")
            return drop_excluded_us_stock_rows(autofill_watchlist_df(df, market), market)
    except Exception:
        pass
    return drop_excluded_us_stock_rows(default_candidate_universe_df(market), market)


def save_candidate_universe_df(df: pd.DataFrame, market: str) -> Path:
    path = resolve_candidate_file(market)
    filled = autofill_watchlist_df(df, market)
    filled.to_csv(path, index=False, encoding="utf-8-sig")
    return path


def candidate_symbols_to_scan(market: str) -> list[str]:
    candidates = load_candidate_universe_df(market)
    watch = set([str(x).upper() for x in watchlist_symbols(market)])
    out: list[str] = []
    if candidates.empty or "symbol" not in candidates.columns:
        return out
    for raw in candidates["symbol"].astype(str).tolist():
        sym = normalize_ticker(raw, market) if market == "한국주식" else display_symbol(raw, "미국주식")
        if not sym:
            continue
        if market == "미국주식" and is_excluded_us_stock_symbol(sym):
            continue
        if str(sym).upper() in watch:
            continue
        if sym not in out:
            out.append(sym)
    return out


def append_symbols_to_watchlist(symbols: list[str], market: str) -> tuple[int, Path]:
    """발굴 후보 중 사용자가 선택한 종목을 관심종목 CSV에 추가."""
    path = resolve_watchlist_file(market)
    try:
        base_df = load_watchlist_df(market)
    except Exception:
        base_df = pd.DataFrame(columns=WATCHLIST_COLUMNS)
    base_df = autofill_watchlist_df(base_df, market)
    existing = set(base_df["symbol"].astype(str).str.upper().tolist()) if not base_df.empty and "symbol" in base_df.columns else set()
    new_rows = []
    for s in symbols:
        sym = normalize_ticker(s, market) if market == "한국주식" else display_symbol(s, "미국주식")
        if not sym or str(sym).upper() in existing:
            continue
        meta = infer_watchlist_meta(sym, market)
        new_rows.append({"symbol": sym, **meta})
        existing.add(str(sym).upper())
    if new_rows:
        out = pd.concat([base_df, pd.DataFrame(new_rows)], ignore_index=True)
    else:
        out = base_df
    out = autofill_watchlist_df(out, market)
    out.to_csv(path, index=False, encoding="utf-8-sig")
    return len(new_rows), path


def add_discovery_labels(scan_df: pd.DataFrame) -> pd.DataFrame:
    """스캔 결과를 관심종목 편입 검토용 문구로 변환."""
    if scan_df is None or scan_df.empty:
        return scan_df
    out = scan_df.copy()
    labels = []
    reasons = []
    for _, r in out.iterrows():
        score = safe_float(r.get("순위점수"), 0)
        risk = str(r.get("위험도", ""))
        no_buy = str(r.get("매수금지", "-"))
        caution = str(r.get("탈락/주의사유", "-"))
        vol = str(r.get("거래량배율", ""))
        mom20 = str(r.get("20일모멘텀", ""))
        if score >= 78 and no_buy in {"-", "", "nan"}:
            label = "관심종목 추가 검토"
        elif score >= 65:
            label = "단기 관찰만"
        elif "거래량" in caution or "유동성" in caution:
            label = "유동성 부족 제외"
        elif "과열" in caution or risk == "매우 높음":
            label = "뉴스성 급등 주의"
        else:
            label = "제외/관망"
        reason_parts = []
        if score:
            reason_parts.append(f"스캔점수 {score:.0f}")
        if vol:
            reason_parts.append(f"거래량 {vol}")
        if mom20:
            reason_parts.append(f"20일 {mom20}")
        if caution and caution != "-":
            reason_parts.append(caution[:60])
        labels.append(label)
        reasons.append(" / ".join(reason_parts) if reason_parts else "-")
    out.insert(0, "편입판정", labels)
    out.insert(1, "추가검토이유", reasons)
    return out


def normalize_watchlist_match_symbol(value: Any, market: str, fallback: Any = "") -> str:
    """watchlist와 predictions.csv 비교용 종목키."""
    if market == "한국주식":
        raw = str(value or fallback or "").strip()
        return normalize_ticker(raw, "한국주식")
    return display_symbol(value, "미국주식", fallback).upper()


def add_prediction_match_key(df: pd.DataFrame, market: str) -> pd.DataFrame:
    """예측 기록에 관심종목 비교용 키를 추가."""
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "market" in out.columns:
        out = out[out["market"].astype(str).eq(market)].copy()
    if out.empty:
        return out

    keys = []
    for _, r in out.iterrows():
        primary = r.get("ticker", r.get("종목", r.get("symbol", "")))
        fallback = r.get("종목", r.get("symbol", ""))
        keys.append(normalize_watchlist_match_symbol(primary, market, fallback))
    out["_match_symbol"] = keys
    return out


def select_prediction_row_for_watchlist(pred_rows: pd.DataFrame, pending_rows: pd.DataFrame) -> pd.Series | None:
    """관심종목 현황판에 표시할 예측행 선택. 오늘 보드 반영분을 우선한다."""
    source = pending_rows if pending_rows is not None and not pending_rows.empty else pred_rows
    if source is None or source.empty:
        return None
    out = source.copy()
    if "target_date" in out.columns:
        out["_target_dt"] = pd.to_datetime(out["target_date"], errors="coerce")
    else:
        out["_target_dt"] = pd.NaT
    if "created_at" in out.columns:
        out["_created_dt"] = pd.to_datetime(out["created_at"], errors="coerce")
    else:
        out["_created_dt"] = pd.NaT
    out = out.sort_values(["_target_dt", "_created_dt"], ascending=[False, False])
    return out.iloc[0] if not out.empty else None


def prediction_price_text(row: pd.Series | None, col: str, market: str) -> str:
    if row is None or col not in row.index:
        return "-"
    val = safe_float(row.get(col), np.nan)
    if np.isnan(val) or val <= 0:
        return "-"
    return fmt_price(val, market)


def prediction_pct_text(row: pd.Series | None, col: str) -> str:
    if row is None or col not in row.index:
        return "-"
    val = safe_float(row.get(col), np.nan)
    if np.isnan(val):
        return "-"
    return f"{val:.2f}"


def prediction_text(row: pd.Series | None, col: str, default: str = "-") -> str:
    if row is None or col not in row.index:
        return default
    val = row.get(col)
    if pd.isna(val):
        return default
    s = str(val).strip()
    return s if s else default


def watchlist_order_status_from_prediction(row: pd.Series | None) -> str:
    """예측행 기반 주문상태 요약."""
    if row is None:
        return "예측 미생성"
    no_buy = prediction_text(row, "no_buy_flags", "")
    rr = safe_float(row.get("rr1"), np.nan) if "rr1" in row.index else np.nan
    if no_buy:
        return "매수주의"
    if not np.isnan(rr) and rr < 1.2:
        return "손익비 부족"
    return "조건부 검토"


def build_watchlist_status_df(log_df: pd.DataFrame, market: str) -> pd.DataFrame:
    """고정 관심종목별 예측 생성/오늘 보드 반영 및 주문 기준 현황."""
    watch = load_watchlist_df(market)
    watch = autofill_watchlist_df(watch, market)
    if watch is None or watch.empty:
        return pd.DataFrame()

    log_m = add_prediction_match_key(log_df, market)
    pending = next_pending_predictions(log_df, market=market, limit=1000)
    pending_m = add_prediction_match_key(pending, market)

    rows: list[dict[str, Any]] = []
    for _, r in watch.iterrows():
        symbol = normalize_watchlist_match_symbol(r.get("symbol", ""), market)
        if not symbol:
            continue

        pred_rows = log_m[log_m["_match_symbol"].astype(str).eq(symbol)] if not log_m.empty and "_match_symbol" in log_m.columns else pd.DataFrame()
        pending_rows = pending_m[pending_m["_match_symbol"].astype(str).eq(symbol)] if not pending_m.empty and "_match_symbol" in pending_m.columns else pd.DataFrame()

        has_prediction = not pred_rows.empty
        reflected = not pending_rows.empty
        selected_pred = select_prediction_row_for_watchlist(pred_rows, pending_rows)

        last_target = "-"
        last_created = "-"
        pending_target = "-"
        if has_prediction:
            if "target_date" in pred_rows.columns:
                target_vals = pd.to_datetime(pred_rows["target_date"], errors="coerce").dropna()
                if not target_vals.empty:
                    last_target = str(target_vals.max().date())
            if "created_at" in pred_rows.columns:
                created_vals = pd.to_datetime(pred_rows["created_at"], errors="coerce").dropna()
                if not created_vals.empty:
                    last_created = created_vals.max().strftime("%Y-%m-%d %H:%M")
        if reflected and "target_date" in pending_rows.columns:
            target_vals = pd.to_datetime(pending_rows["target_date"], errors="coerce").dropna()
            if not target_vals.empty:
                pending_target = str(target_vals.min().date())

        if reflected:
            status = "보드 반영"
            note = "오늘 매수 판단보드에 표시됨"
        elif has_prediction:
            status = "예측 있음/보드 미반영"
            note = "최근 예측 기준 주문값 표시. 단, 오늘 보드 대상일과 다를 수 있음"
        else:
            status = "예측 미생성"
            note = "작업스케줄러 또는 관심종목 예측 저장 필요"

        no_buy_text = prediction_text(selected_pred, "no_buy_flags", "-")
        primary_action = prediction_text(selected_pred, "primary_action", "-")
        order_status = watchlist_order_status_from_prediction(selected_pred)
        sanity = order_sanity_from_prediction_row(selected_pred, market)
        if sanity.get("주문검증") not in ["정상", "예측 미생성"]:
            order_status = sanity.get("주문검증", order_status)

        rows.append({
            "상태": status,
            "주문상태": order_status,
            "종목": symbol,
            "표시명": r.get("name", symbol),
            "테마": r.get("theme", ""),
            "그룹": r.get("group", ""),
            "유형": r.get("type", ""),
            "섹터": r.get("sector_proxy", ""),
            "위험도": r.get("risk_level", ""),
            "우선진입가": prediction_price_text(selected_pred, "preferred_entry", market),
            "보수대기선": prediction_price_text(selected_pred, "conservative_entry", market),
            "지지존": format_zone_text(selected_pred, "support_zone_low", "support_zone_high", market) if isinstance(selected_pred, pd.Series) and not selected_pred.empty else "-",
            "저항존": format_zone_text(selected_pred, "resistance_zone_low", "resistance_zone_high", market) if isinstance(selected_pred, pd.Series) and not selected_pred.empty else "-",
            "진입근거": prediction_text(selected_pred, "entry_basis", "-"),
            "손절가": prediction_price_text(selected_pred, "stop_loss", market),
            "1차익절가": prediction_price_text(selected_pred, "take_profit1", market),
            "2차익절가": prediction_price_text(selected_pred, "take_profit2", market),
            "손익비": prediction_pct_text(selected_pred, "rr1"),
            "예상시초가": prediction_price_text(selected_pred, "pred_open_mid", market),
            "예상종가": prediction_price_text(selected_pred, "pred_close_mid", market),
            "우선전략": primary_action,
            "매수주의사유": no_buy_text,
            "주문검증": sanity.get("주문검증", "-"),
            "진입거리": sanity.get("진입거리", "-"),
            "전일대비진입": sanity.get("전일대비진입", "-"),
            "손절폭": sanity.get("손절폭", "-"),
            "익절거리": sanity.get("익절거리", "-"),
            "주문검증메모": sanity.get("주문검증메모", "-"),
            "예측생성": "완료" if has_prediction else "미생성",
            "오늘보드": "반영" if reflected else "미반영",
            "오늘대상일": pending_target,
            "마지막예측일": last_target,
            "최근생성시각": last_created,
            "메모": note,
        })

    out = pd.DataFrame(rows)
    if not out.empty:
        status_order = {"보드 반영": 0, "예측 있음/보드 미반영": 1, "예측 미생성": 2}
        order_status_order = {"조건부 검토": 0, "정상": 0, "진입가 대기": 1, "돌파진입 주의": 1, "매수주의": 2, "손익비 부족": 3, "진입가 멀음": 4, "주문기준 이상": 5, "목표가 이상": 5, "손익비 이상": 5, "예측 미생성": 6}
        out["_order"] = out["상태"].map(status_order).fillna(9)
        out["_order2"] = out["주문상태"].map(order_status_order).fillna(9)
        out["_original_order"] = range(len(out))
        out = out.sort_values(["_order", "_order2", "_original_order"]).drop(columns=["_order", "_order2", "_original_order"])
    return out


def generate_predictions_for_symbols_now(
    symbols: list[str],
    market: str,
    period_years: float = 1.0,
    target_coverage: float = 0.75,
) -> tuple[int, list[str]]:
    """화면 버튼에서 선택 종목 예측을 즉시 생성."""
    clean_symbols = []
    for s in symbols or []:
        if not str(s).strip():
            continue
        clean_symbols.append(normalize_ticker(str(s), market) if market == "한국주식" else display_symbol(str(s), "미국주식"))
    clean_symbols = list(dict.fromkeys(clean_symbols))

    if not clean_symbols:
        return 0, ["생성할 종목이 없습니다."]

    session = market_session_context(market)
    target_date = session["target_date"]
    bench_df = fetch_benchmark_snapshots()
    event_context = build_auto_event_context(
        target=target_date,
        ticker="",
        manual_events=[],
        use_bls_macro=(market == "미국주식"),
        use_earnings=False,
        use_news=True,
        market=market,
    )
    saved_n, messages = auto_generate_predictions_for_watchlist(
        tickers=clean_symbols,
        market=market,
        target_date=target_date,
        period_years=period_years,
        log_df=load_prediction_log(),
        bench_df=bench_df,
        event_context=event_context,
        max_items=len(clean_symbols),
        target_coverage=target_coverage,
    )
    return saved_n, messages


def render_watchlist_status_board(log_df: pd.DataFrame, market: str) -> None:
    """관심종목 목록과 오늘 매수 판단보드 반영 여부를 분리해서 보여준다."""
    mode_label = "국장" if market == "한국주식" else "미장"
    watchlist_file = resolve_watchlist_file(market)
    status_df = build_watchlist_status_df(log_df, market)

    with st.expander(f"⑥-1 {mode_label} 등록 관심종목 현황", expanded=True):
        st.caption(
            "관심종목에 들어있어도 예측값이 생성되어야 오늘 매수 판단보드·주문 기준표에 표시됩니다. "
            "이 표는 관심종목 전체를 보여주면서, 예측이 있는 종목은 우선진입가·손절가·익절가·손익비까지 함께 표시합니다."
        )
        st.caption(f"관심종목 파일: `{watchlist_file}`")

        if status_df.empty:
            if market == "한국주식":
                st.info("등록된 국장 관심종목 없음. `watchlist_kr_growth.csv`(또는 `watchlist_kr.csv`)에 symbol을 추가한 뒤 저장하세요.")
            else:
                st.warning("관심종목 데이터가 없습니다. 관심종목 리스트 편집에서 종목코드를 추가하세요.")
            return

        total = len(status_df)
        reflected_n = int((status_df["오늘보드"].astype(str) == "반영").sum()) if "오늘보드" in status_df.columns else 0
        created_n = int((status_df["예측생성"].astype(str) == "완료").sum()) if "예측생성" in status_df.columns else 0
        missing_n = total - created_n
        order_ready_n = int((status_df["우선진입가"].astype(str) != "-").sum()) if "우선진입가" in status_df.columns else 0

        c1, c2, c3, c4, c5 = st.columns(5)
        with c1:
            st.metric("등록 관심종목", f"{total}개")
        with c2:
            st.metric("오늘 보드 반영", f"{reflected_n}개")
        with c3:
            st.metric("주문기준 있음", f"{order_ready_n}개")
        with c4:
            st.metric("예측 생성 완료", f"{created_n}개")
        with c5:
            st.metric("예측 미생성", f"{missing_n}개")

        missing_symbols = status_df.loc[status_df["예측생성"].astype(str).eq("미생성"), "종목"].astype(str).tolist()
        all_symbols = status_df["종목"].astype(str).tolist()

        a1, a2 = st.columns([1, 1])
        with a1:
            if st.button(
                f"예측 미생성 {len(missing_symbols)}개 지금 생성",
                use_container_width=True,
                disabled=(len(missing_symbols) == 0),
                key=f"generate_missing_watchlist_v964_{market}",
            ):
                with st.spinner("예측 미생성 종목을 생성 중입니다. 종목 수가 많으면 시간이 걸릴 수 있습니다."):
                    saved_n, msgs = generate_predictions_for_symbols_now(missing_symbols, market)
                st.success(f"예측 생성 완료: 저장 {saved_n}건 / 대상 {len(missing_symbols)}개")
                st.markdown("**생성 결과 상세**")
                for msg in msgs:
                    st.caption(msg)
                st.info("표를 최신 상태로 보려면 앱 화면을 새로고침하세요.")
        with a2:
            if st.button(
                f"전체 관심종목 {len(all_symbols)}개 예측 다시 생성",
                use_container_width=True,
                disabled=(len(all_symbols) == 0),
                key=f"generate_all_watchlist_v964_{market}",
            ):
                with st.spinner("전체 관심종목 예측을 생성 중입니다. 이미 같은 대상일 기록이 있으면 중복/건너뜀으로 표시될 수 있습니다."):
                    saved_n, msgs = generate_predictions_for_symbols_now(all_symbols, market)
                st.success(f"전체 예측 실행 완료: 신규 저장 {saved_n}건 / 대상 {len(all_symbols)}개")
                st.markdown("**생성 결과 상세**")
                for msg in msgs:
                    st.caption(msg)
                st.info("표를 최신 상태로 보려면 앱 화면을 새로고침하세요.")

        view_filter = st.selectbox(
            "표시 필터",
            ["전체", "주문기준 있음", "오늘 보드 반영", "보드 미반영", "예측 미생성", "매수주의"],
            index=0,
            key=f"watchlist_status_filter_v963_{market}",
        )
        view = status_df.copy()
        if view_filter == "주문기준 있음":
            view = view[view["우선진입가"].astype(str).ne("-")]
        elif view_filter == "오늘 보드 반영":
            view = view[view["오늘보드"].astype(str).eq("반영")]
        elif view_filter == "보드 미반영":
            view = view[view["오늘보드"].astype(str).ne("반영")]
        elif view_filter == "예측 미생성":
            view = view[view["예측생성"].astype(str).eq("미생성")]
        elif view_filter == "매수주의":
            view = view[view["주문상태"].astype(str).str.contains("주의|부족|멀음|이상|과대|대기", na=False)]

        cols = [
            "상태", "주문상태", "종목", "테마", "위험도",
            "우선진입가", "보수대기선", "지지존", "저항존", "진입근거", "손절가", "1차익절가", "2차익절가", "손익비",
            "예상시초가", "예상종가", "진입거리", "손절폭", "익절거리", "주문검증메모",
            "우선전략", "매수주의사유",
            "예측생성", "오늘보드", "오늘대상일", "마지막예측일", "최근생성시각", "메모",
            "그룹", "유형", "섹터",
        ]
        display_view = view.copy()
        if "종목" in display_view.columns:
            display_view["종목"] = display_view["종목"].apply(lambda x: display_symbol(x, market))
        st.dataframe(display_view[[c for c in cols if c in display_view.columns]], use_container_width=True, hide_index=True)

        if missing_n > 0:
            st.info(
                "예측 미생성 종목은 아직 predictions.csv에 계산값이 없어 우선진입가/손절가가 표시되지 않습니다. "
                "위의 '예측 미생성 지금 생성' 버튼을 누르거나, 사이드바 자동 저장 종목 수를 관심종목 수 이상으로 올린 뒤 자동 저장을 실행하면 보드에 반영됩니다."
            )
        elif reflected_n < total:
            st.info(
                "예측은 있지만 오늘 보드에 없는 종목은 실제 결과가 이미 반영됐거나, 현재 표시 중인 다음 대상일과 다른 기록일 수 있습니다."
            )



def render_candidate_discovery_board(
    market: str,
    log_df: pd.DataFrame,
    bench_df: pd.DataFrame,
    event_context: dict[str, Any],
    collapse_auto_sections: bool = True,
) -> None:
    """v9.6 신규 관심종목 발굴 보드."""
    title = "⑪ 신규 관심종목 발굴 보드"
    with st.expander(title, expanded=False if collapse_auto_sections else True):
        st.caption("관심종목 밖 후보군을 훑어서 새로 추적할 만한 종목을 제안합니다. 자동 매수가 아니라 관심종목 편입 검토용입니다.")
        cand_df = load_candidate_universe_df(market)
        watch_count = len(watchlist_symbols(market))
        scan_symbols = candidate_symbols_to_scan(market)
        c1, c2, c3, c4 = st.columns(4)
        with c1:
            st.metric("등록 관심종목", f"{watch_count}개")
        with c2:
            st.metric("발굴 후보군", f"{len(cand_df)}개")
        with c3:
            st.metric("스캔 대상", f"{len(scan_symbols)}개")
        with c4:
            st.metric("중복 제외", f"{max(0, len(cand_df)-len(scan_symbols))}개")

        settings = st.columns([1, 1, 1.2])
        with settings[0]:
            max_scan = st.slider("발굴 스캔 수", 5, 60, min(25, max(5, len(scan_symbols))), 5, key=f"discovery_max_{market}")
        with settings[1]:
            min_score = st.slider("추가 후보 최소점수", 0, 100, 58, 5, key=f"discovery_min_{market}")
        with settings[2]:
            exclude_large = st.checkbox("대형주보다 새 후보 우선", value=(market == "미국주식"), key=f"discovery_exclude_large_{market}")

        b1, b2 = st.columns([1, 1])
        with b1:
            run_discovery = st.button("신규 관심종목 후보 스캔", use_container_width=True, key=f"run_discovery_{market}")
        with b2:
            show_editor = st.checkbox("발굴 후보군 편집", value=False, key=f"show_candidate_editor_{market}")

        if show_editor:
            st.caption("candidate_universe 파일입니다. 여기는 고정 관심종목이 아니라 새로 발굴할 후보풀입니다.")
            edited = st.data_editor(
                cand_df,
                use_container_width=True,
                num_rows="dynamic",
                hide_index=True,
                key=f"candidate_editor_{market}_v960",
                column_config=watchlist_column_config(),
            )
            if st.button("발굴 후보군 저장", use_container_width=True, key=f"save_candidate_universe_{market}"):
                try:
                    path = save_candidate_universe_df(edited, market)
                    st.success(f"발굴 후보군 저장 완료: {path}")
                except Exception as e:
                    st.error(f"저장 실패: {e}")

        state_key = f"candidate_discovery_result_{market}"
        if run_discovery:
            if not scan_symbols:
                st.warning("스캔할 후보가 없습니다. 발굴 후보군을 편집하거나 관심종목과 중복되지 않는 종목을 추가하세요.")
            else:
                with st.spinner("신규 관심종목 후보 스캔 중... 후보군 차트/거래량/뉴스/손익비를 확인합니다."):
                    try:
                        raw_scan = scan_candidate_tickers_auto(
                            tickers=scan_symbols,
                            market=market,
                            log_df=log_df,
                            bench_df=bench_df,
                            event_context=event_context,
                            max_count=max_scan,
                            lesser_known_only=exclude_large,
                            min_score=min_score,
                        )
                    except Exception as e:
                        raw_scan = pd.DataFrame()
                        st.error(f"스캔 오류: {e}")
                    result_df = add_discovery_labels(raw_scan)
                    st.session_state[state_key] = result_df

        result_df = st.session_state.get(state_key, pd.DataFrame())
        if result_df is None or result_df.empty:
            st.info("아직 발굴 스캔 결과가 없습니다. '신규 관심종목 후보 스캔'을 눌러 후보를 확인하세요.")
            st.caption("추천 흐름: 후보군 스캔 → 관심종목 추가 검토 → 선택 종목만 watchlist에 편입 → 다음 장 예측 대상에 포함")
            return

        st.dataframe(to_korean_display(result_df, compact=False), use_container_width=True, hide_index=True)
        st.caption("편입판정은 관심종목 추가 검토용입니다. 실제 매수는 다음 장 예측/TOP 후보/손익비 확인 후 판단하세요.")

        candidate_options = result_df[result_df.get("편입판정", "").astype(str).isin(["관심종목 추가 검토", "단기 관찰만"])] if "편입판정" in result_df.columns else result_df
        symbols = candidate_options.get("종목", pd.Series(dtype=str)).astype(str).tolist() if not candidate_options.empty else []
        selected = st.multiselect(
            "관심종목에 추가할 종목 선택",
            options=symbols,
            default=symbols[:3] if len(symbols) <= 3 else [],
            key=f"discovery_select_add_{market}",
        )
        if st.button("선택 종목을 관심종목에 추가", use_container_width=True, key=f"discovery_add_watchlist_{market}"):
            if not selected:
                st.warning("추가할 종목을 선택하세요.")
            else:
                added, path = append_symbols_to_watchlist(selected, market)
                if added > 0:
                    st.success(f"관심종목에 {added}개 추가 완료: {path}")
                    st.caption("다음부터는 이 종목들이 고정 관심종목으로 예측/스캔 대상에 포함됩니다.")
                else:
                    st.info("이미 관심종목에 있거나 추가할 신규 종목이 없습니다.")


