def should_prioritize_kr_market(now_kst: datetime | None = None) -> bool:
    """국장 장전~장마감 직후에는 앱 첫 화면과 자동 동기화를 국장 우선으로 둔다."""
    try:
        if now_kst is None:
            now_kst = datetime.now(KST)
        elif now_kst.tzinfo is None:
            now_kst = now_kst.replace(tzinfo=KST)
        if now_kst.weekday() >= 5:
            return False
        hhmm = now_kst.hour * 60 + now_kst.minute
        # 06:00~16:30 KST: 국장 준비/진행/마감 업데이트 우선
        return (6 * 60) <= hhmm <= (16 * 60 + 30)
    except Exception:
        return False



def is_market_open_soon_10min_v9948(market: str, now_kst: datetime | None = None) -> bool:
    """장 시작 10분 전 자동 전체 예측 전환 구간.
    - 미장: 미국 동부시간 09:20~09:30
    - 국장: 한국시간 08:50~09:00
    """
    try:
        if now_kst is None:
            now_kst = datetime.now(KST)
        elif now_kst.tzinfo is None:
            now_kst = now_kst.replace(tzinfo=KST)

        if market == "한국주식":
            if now_kst.weekday() >= 5:
                return False
            hhmm = now_kst.hour * 60 + now_kst.minute
            return (8 * 60 + 50) <= hhmm < (9 * 60)

        now_et = now_kst.astimezone(US_ET)
        if now_et.weekday() >= 5:
            return False
        hhmm = now_et.hour * 60 + now_et.minute
        return (9 * 60 + 20) <= hhmm < (9 * 60 + 30)
    except Exception:
        return False


def effective_startup_sync_limit_v9948(market: str, selected_limit: int, preopen_full_sync: bool = True) -> int:
    """0 means unlimited/all watchlist in the existing startup sync code."""
    try:
        if preopen_full_sync and is_market_open_soon_10min_v9948(market):
            return 0
        return int(selected_limit)
    except Exception:
        return int(selected_limit or 10)


def sync_markets_in_order(markets: list[str], max_items: int = 10, force: bool = False, preopen_full_sync: bool = False) -> list[dict[str, Any]]:
    """국장 우선 등 여러 시장을 순서대로 동기화한다."""
    results: list[dict[str, Any]] = []
    seen: set[str] = set()
    for m in markets:
        if not m or m in seen:
            continue
        seen.add(m)
        effective_limit = effective_startup_sync_limit_v9948(m, max_items, preopen_full_sync)
        results.append(run_app_startup_sync(m, max_items=effective_limit, force=force))
    return results




