# v9.9.56 예측 신뢰도·가상수익률 검증 엔진
# - 목적: 앱의 예측값이 실제 시장 결과와 얼마나 비슷했는지, 그대로 실행했을 때 수익률이 어땠는지 누적 검증
# - 기존 예측 흐름은 유지하고, 저장/업데이트/화면표시 컬럼만 보강
# ══════════════════════════════════════════════
VIRTUAL_ROUND_TRIP_COST_PCT = 0.05  # 보수적 왕복 마찰비용 기본값. 실제 수수료/세금과 다를 수 있음.


def _boolish_v9956(value: Any) -> bool:
    """CSV에 1/0, True/False, 문자열이 섞여도 같은 의미로 처리."""
    try:
        if isinstance(value, str):
            return value.strip().lower() in {"1", "1.0", "true", "yes", "y", "도달", "체결"}
        if pd.isna(value):
            return False
        return bool(int(float(value)))
    except Exception:
        return False


def _rate_text_v9956(value: float) -> str:
    try:
        if pd.isna(value):
            return "-"
        return f"{float(value):.1f}%"
    except Exception:
        return "-"


def build_prediction_quality_metadata_v9956(
    market: str,
    confidence: dict[str, Any] | None = None,
    quality_info: dict[str, Any] | None = None,
    event_context: dict[str, Any] | None = None,
    prediction: dict[str, Any] | None = None,
    data_flags: dict[str, Any] | None = None,
) -> dict[str, Any]:
    """예측 1건이 얼마나 믿을 만한 데이터로 만들어졌는지 A/B/C 등급으로 저장."""
    confidence = confidence or {}
    quality_info = quality_info or {}
    event_context = event_context or {}
    prediction = prediction or {}
    data_flags = data_flags or {}

    score = 45.0
    reasons: list[str] = []

    conf_score = safe_float(confidence.get("score"), np.nan)
    if not np.isnan(conf_score):
        score += min(20, max(-10, (conf_score - 50) * 0.35))
        reasons.append(f"예측신뢰도 {conf_score:.0f}")

    q_score = safe_float(quality_info.get("quality_score"), np.nan)
    if not np.isnan(q_score):
        score += max(-10, min(10, q_score * 0.35))
        reasons.append(f"품질점수 {q_score:+.0f}")

    if market == "한국주식":
        if _boolish_v9956(data_flags.get("kis_price_ok")):
            score += 10
            reasons.append("KIS 현재가 확인")
        else:
            score -= 6
            reasons.append("KIS 현재가 미확인")
        if _boolish_v9956(data_flags.get("kis_chart_ok")):
            score += 10
            reasons.append("KIS 일봉 확인")
        else:
            score -= 6
            reasons.append("KIS 일봉 미확인")
    else:
        if data_flags.get("price_source"):
            score += 4
            reasons.append(str(data_flags.get("price_source"))[:28])

    news_score = safe_float(event_context.get("auto_news_score"), np.nan)
    if not np.isnan(news_score):
        score += min(6, max(-6, abs(news_score)))
        reasons.append("뉴스점수 반영")

    risk_mult = safe_float(event_context.get("risk_mult"), 1.0)
    if risk_mult >= 1.55:
        score -= 8
        reasons.append(f"이벤트 변동성 {risk_mult:.2f}")

    no_buy_flags = prediction.get("no_buy_flags", []) if isinstance(prediction, dict) else []
    if no_buy_flags:
        score -= min(15, 4 * len(no_buy_flags))
        reasons.append("주의사유 존재")

    score = int(max(0, min(100, round(score))))
    if score >= 82:
        grade = "A+"
    elif score >= 72:
        grade = "A"
    elif score >= 60:
        grade = "B"
    elif score >= 45:
        grade = "C"
    else:
        grade = "D"
    return {
        "prediction_quality_score": score,
        "prediction_quality_grade": grade,
        "prediction_quality_reason": " / ".join(reasons[:6]) if reasons else "기본 데이터 기준",
        "kis_price_ok": int(_boolish_v9956(data_flags.get("kis_price_ok"))) if market == "한국주식" else np.nan,
        "kis_chart_ok": int(_boolish_v9956(data_flags.get("kis_chart_ok"))) if market == "한국주식" else np.nan,
        "price_source": data_flags.get("price_source", "KIS Open API 우선" if market == "한국주식" else "Finnhub/yfinance"),
        "chart_source": data_flags.get("chart_source", "KIS Open API 우선" if market == "한국주식" else "yfinance"),
        "news_source": data_flags.get("news_source", "뉴스 자동수집"),
        "dart_checked": data_flags.get("dart_checked", "DART 보조" if market == "한국주식" else "해당없음"),
        "news_checked": data_flags.get("news_checked", 1 if event_context.get("auto_news_items") or event_context.get("auto_news_score") not in (None, "") else 0),
    }


def compute_virtual_trade_metrics_v9956(row: pd.Series | dict[str, Any], actual: dict[str, Any] | None = None) -> dict[str, Any]:
    """앱 예측을 그대로 실행했다고 가정한 보수적 가상손익 계산.
    일봉만으로 선후관계를 알 수 없으므로 손절/익절이 같은 날 모두 닿으면 손절 우선 처리.
    """
    actual = actual or {}
    getv = row.get if hasattr(row, "get") else lambda k, d=None: d
    entry = safe_float(getv("preferred_entry"), np.nan)
    stop = safe_float(getv("stop_loss"), np.nan)
    tp1 = safe_float(getv("take_profit1"), np.nan)
    tp2 = safe_float(getv("take_profit2"), np.nan)
    low = safe_float(actual.get("actual_low", getv("actual_low")), np.nan)
    high = safe_float(actual.get("actual_high", getv("actual_high")), np.nan)
    close = safe_float(actual.get("actual_close", getv("actual_close")), np.nan)

    result = {
        "virtual_entry_filled": np.nan,
        "virtual_exit_price": np.nan,
        "virtual_result_label": "계산불가",
        "virtual_return_pct": np.nan,
        "virtual_net_return_pct": np.nan,
        "virtual_r_multiple": np.nan,
        "virtual_rule": "우선진입가 체결 가정 · 손절/익절 동시터치 시 손절 우선",
    }
    if np.isnan(entry) or np.isnan(low) or np.isnan(high) or np.isnan(close) or entry <= 0:
        return result

    filled = low <= entry <= high
    result["virtual_entry_filled"] = int(filled)
    if not filled:
        result["virtual_result_label"] = "미체결"
        return result

    hit_stop = (not np.isnan(stop)) and stop > 0 and low <= stop
    hit_tp2 = (not np.isnan(tp2)) and tp2 > 0 and high >= tp2
    hit_tp1 = (not np.isnan(tp1)) and tp1 > 0 and high >= tp1

    if hit_stop and (hit_tp1 or hit_tp2):
        exit_price = stop
        label = "손절우선"
    elif hit_stop:
        exit_price = stop
        label = "손절"
    elif hit_tp2:
        exit_price = tp2
        label = "2차익절"
    elif hit_tp1:
        exit_price = tp1
        label = "1차익절"
    else:
        exit_price = close
        label = "종가청산"

    ret = (exit_price / entry - 1) * 100 if entry else np.nan
    net_ret = ret - VIRTUAL_ROUND_TRIP_COST_PCT if not np.isnan(ret) else np.nan
    risk = entry - stop if (not np.isnan(stop) and stop > 0) else np.nan
    r_mult = (exit_price - entry) / risk if risk and not np.isnan(risk) and risk > 0 else np.nan
    result.update({
        "virtual_exit_price": exit_price,
        "virtual_result_label": label,
        "virtual_return_pct": ret,
        "virtual_net_return_pct": net_ret,
        "virtual_r_multiple": r_mult,
    })
    return result


def classify_prediction_error_reason_v9956(row: pd.Series | dict[str, Any], virtual: dict[str, Any] | None = None) -> str:
    """틀린 이유를 완벽하게 단정하지 않고, 기록된 수치 기준으로 복기 태그를 자동 분류."""
    virtual = virtual or {}
    getv = row.get if hasattr(row, "get") else lambda k, d=None: d
    reasons: list[str] = []
    if getv("actual_close", np.nan) is None or pd.isna(pd.to_numeric(pd.Series([getv("actual_close", np.nan)]), errors="coerce").iloc[0]):
        return "실제값 미확정"
    if not _boolish_v9956(getv("open_in_range")) and str(getv("open_in_range", "")).lower() not in {"nan", "", "none"}:
        reasons.append("시초가 범위 이탈")
    if not _boolish_v9956(getv("close_in_range")) and str(getv("close_in_range", "")).lower() not in {"nan", "", "none"}:
        reasons.append("종가 범위 이탈")
    if not _boolish_v9956(getv("direction_hit")) and str(getv("direction_hit", "")).lower() not in {"nan", "", "none"}:
        reasons.append("방향 불일치")
    label = str(virtual.get("virtual_result_label", getv("virtual_result_label", "")))
    if "손절" in label:
        reasons.append("손절 기준 터치")
    elif label == "미체결":
        reasons.append("우선진입가 미도달")
    nb = str(getv("no_buy_flags", "") or "").strip()
    if nb:
        reasons.append("예측 당시 주의사유 존재")
    if not reasons:
        reasons.append("허용 범위 내")
    return " / ".join(dict.fromkeys(reasons))


def explain_prediction_gap_v9986(row: pd.Series | dict[str, Any], virtual: dict[str, Any] | None = None) -> dict[str, str]:
    """Turn numeric validation tags into a concise post-market explanation and next-run adjustment hint."""
    virtual = virtual or {}
    getv = row.get if hasattr(row, "get") else lambda k, d=None: d
    market = str(getv("market", "") or "")
    prev = safe_float(getv("prev_close"), np.nan)
    actual_open = safe_float(getv("actual_open"), np.nan)
    actual_high = safe_float(getv("actual_high"), np.nan)
    actual_low = safe_float(getv("actual_low"), np.nan)
    actual_close = safe_float(getv("actual_close"), np.nan)
    pred_open_mid = safe_float(getv("pred_open_mid"), np.nan)
    pred_close_mid = safe_float(getv("pred_close_mid"), np.nan)
    open_err = safe_float(getv("open_error_pct"), np.nan)
    close_err = safe_float(getv("close_error_pct"), np.nan)
    label = str(virtual.get("virtual_result_label", getv("virtual_result_label", "")) or "")
    net_ret = safe_float(virtual.get("virtual_net_return_pct", getv("virtual_net_return_pct")), np.nan)
    no_buy = str(getv("no_buy_flags", "") or "").strip()
    event_label = str(getv("event_label", "") or "").strip()
    technical = str(getv("technical_verdict", "") or "").strip()
    quality = str(getv("prediction_quality_grade", "") or "").strip()

    causes: list[str] = []
    adjustments: list[str] = []

    if not np.isnan(open_err) and abs(open_err) >= 3:
        side = "낮게" if open_err < 0 else "높게"
        causes.append(f"시초가가 예상 중앙값보다 {abs(open_err):.1f}% {side} 출발")
        adjustments.append("시초가 갭/예상체결가 보정폭 확대")
    elif not np.isnan(open_err):
        causes.append(f"시초가 오차 {abs(open_err):.1f}%로 범위 보정은 대체로 유효")

    if not np.isnan(close_err) and abs(close_err) >= 4:
        side = "강하게" if close_err > 0 else "약하게"
        causes.append(f"종가가 예상보다 {abs(close_err):.1f}% {side} 마감")
        adjustments.append("종가 ATR 범위와 당일 이벤트 변동성 배수 상향")
    elif not np.isnan(close_err):
        causes.append(f"종가 오차 {abs(close_err):.1f}%")

    if not np.isnan(prev) and prev > 0 and not np.isnan(actual_high) and not np.isnan(actual_low):
        intraday_range = (actual_high / actual_low - 1) * 100 if actual_low > 0 else np.nan
        close_move = (actual_close / prev - 1) * 100 if not np.isnan(actual_close) else np.nan
        if not np.isnan(intraday_range) and intraday_range >= (7.0 if market == "한국주식" else 4.5):
            causes.append(f"장중 변동폭 {intraday_range:.1f}%로 예측 범위보다 변동성 확대")
            adjustments.append("고변동 종목은 손절/익절 터치 판정과 추격금지 조건 강화")
        if not np.isnan(close_move) and abs(close_move) >= (5.0 if market == "한국주식" else 3.0):
            direction = "상승" if close_move > 0 else "하락"
            causes.append(f"전일 대비 {direction} {abs(close_move):.1f}%")

    if not _boolish_v9956(getv("direction_hit")) and str(getv("direction_hit", "")).strip().lower() not in {"", "nan", "none"}:
        causes.append("예상 방향과 실제 종가 방향이 달랐음")
        adjustments.append("방향 점수보다 뉴스·수급·지수 확인 전 관망 가중")
    if not _boolish_v9956(getv("close_in_range")) and str(getv("close_in_range", "")).strip().lower() not in {"", "nan", "none"}:
        adjustments.append("다음 동일 종목 예측에서 종가 범위 자동 보정 확대")
    if "손절" in label:
        causes.append("앱 기준 진입 시 손절선이 먼저/동시에 위험권")
        adjustments.append("우선진입가를 더 낮추고 손절폭 대비 손익비 재검증")
    elif label == "미체결":
        causes.append("우선진입가까지 눌림이 오지 않아 실제 체결은 보류")
        adjustments.append("체결률 개선보다 추격금지 유지, 대기선 분할만 허용")
    elif "익절" in label:
        causes.append("앱 기준 진입 시 익절가 터치 가능")
    elif label == "종가청산":
        causes.append("익절/손절 미도달 후 종가청산 기준")

    if no_buy and no_buy.lower() not in {"nan", "none", "[]", "-"}:
        causes.append("예측 당시 신규매수 금지/주의 조건 존재")
        adjustments.append("주의사유 존재 시 다음 후보도 관망 우위 유지")
    if event_label and event_label.lower() not in {"nan", "none", "-"}:
        causes.append(f"이벤트 변수: {event_label[:34]}")
    if technical and technical.lower() not in {"nan", "none", "-"} and technical not in {"관망 우위", "중립"}:
        causes.append(f"기술판단: {technical[:28]}")
    if quality and quality.upper() in {"C", "D"}:
        adjustments.append("저품질 예측은 추천수량 0 또는 확인 후보로 제한")

    if not causes:
        causes.append("예측 범위 안에서 움직여 큰 오차 원인은 제한적")
    if not adjustments:
        adjustments.append("현재 보정 유지, 동일 조건 기록 추가 축적")

    if label == "미체결":
        replay = "예측 기준대로라면 우선진입가 미도달로 매수 체결 없음"
    elif label:
        if not np.isnan(net_ret):
            replay = f"예측 기준 실행 시 {label}, 추정 순수익률 {net_ret:.2f}%"
        else:
            replay = f"예측 기준 실행 시 {label}"
    else:
        replay = "가상매매 결과 확인 필요"

    return {
        "prediction_cause_summary": " / ".join(dict.fromkeys(causes[:5])),
        "next_prediction_adjustment": " / ".join(dict.fromkeys(adjustments[:4])),
        "trade_replay_summary": replay,
    }


def enrich_virtual_trade_columns_v9956(df: pd.DataFrame) -> pd.DataFrame:
    """기존 predictions.csv에 신규 가상손익 컬럼이 없어도 화면에서 즉시 계산 가능하게 보강."""
    if df is None or df.empty:
        return df
    out = df.copy()
    needed = [
        "virtual_entry_filled", "virtual_exit_price", "virtual_result_label", "virtual_return_pct",
        "virtual_net_return_pct", "virtual_r_multiple", "prediction_error_reason", "virtual_rule",
        "prediction_cause_summary", "next_prediction_adjustment", "trade_replay_summary",
    ]
    text_cols = {
        "virtual_result_label", "prediction_error_reason", "virtual_rule",
        "prediction_cause_summary", "next_prediction_adjustment", "trade_replay_summary",
    }
    for c in needed:
        if c not in out.columns:
            out[c] = "" if c in text_cols else np.nan
    for c in text_cols:
        if c in out.columns:
            out[c] = out[c].astype("object")
    if not {"actual_low", "actual_high", "actual_close", "preferred_entry"}.issubset(out.columns):
        return out
    for idx, row in out.iterrows():
        if pd.isna(pd.to_numeric(pd.Series([row.get("actual_close", np.nan)]), errors="coerce").iloc[0]):
            continue
        if pd.isna(pd.to_numeric(pd.Series([row.get("virtual_return_pct", np.nan)]), errors="coerce").iloc[0]):
            virt = compute_virtual_trade_metrics_v9956(row)
            for k, v in virt.items():
                if k not in out.columns:
                    out[k] = np.nan
                out.loc[idx, k] = v
            out.loc[idx, "prediction_error_reason"] = classify_prediction_error_reason_v9956(out.loc[idx], virt)
            for ck, cv in explain_prediction_gap_v9986(out.loc[idx], virt).items():
                out.loc[idx, ck] = cv
    return out


def render_prediction_trust_scoreboard_v9956(log_df: pd.DataFrame, market: str) -> None:
    """상단 예측 결론 바로 아래/위에서 앱 예측 자체의 누적 검증상태를 보여주는 패널."""
    try:
        df = enrich_virtual_trade_columns_v9956(log_df)
        if df is None or df.empty:
            st.info("아직 누적 예측 검증 기록이 없습니다. predict/update가 쌓이면 이곳에 적중률과 가상수익률이 표시됩니다.")
            return
        if "market" in df.columns:
            df = df[df["market"].astype(str).eq(str(market))].copy()
        if df.empty:
            st.info("현재 시장의 검증 기록이 아직 없습니다.")
            return
        done = df[pd.to_numeric(df.get("actual_close"), errors="coerce").notna()].copy()
        if done.empty:
            st.info("예측은 저장되어 있지만 아직 장마감 실제값 업데이트가 없습니다. update 실행 후 적중률과 가상수익률이 표시됩니다.")
            return
        for c in ["open_in_range", "close_in_range", "direction_hit", "virtual_entry_filled"]:
            if c in done.columns:
                done[c] = done[c].apply(lambda x: 1 if _boolish_v9956(x) else 0)
        vret = pd.to_numeric(done.get("virtual_net_return_pct", done.get("virtual_return_pct")), errors="coerce")
        filled_vals = pd.to_numeric(done.get("virtual_entry_filled", pd.Series([0] * len(done), index=done.index)), errors="coerce").fillna(0)
        filled_mask = filled_vals.eq(1)
        filled = done[filled_mask].copy()
        filled_ret = pd.to_numeric(filled.get("virtual_net_return_pct", filled.get("virtual_return_pct")), errors="coerce") if not filled.empty else pd.Series(dtype=float)
        open_hit = done["open_in_range"].mean() * 100 if "open_in_range" in done.columns else np.nan
        close_hit = done["close_in_range"].mean() * 100 if "close_in_range" in done.columns else np.nan
        dir_hit = done["direction_hit"].mean() * 100 if "direction_hit" in done.columns else np.nan
        fill_rate = filled_mask.mean() * 100 if len(done) else np.nan
        win_rate = (filled_ret > 0).mean() * 100 if len(filled_ret.dropna()) else np.nan
        avg_return = filled_ret.mean() if len(filled_ret.dropna()) else np.nan
        quality_avg = pd.to_numeric(done.get("prediction_quality_score"), errors="coerce").mean() if "prediction_quality_score" in done.columns else np.nan

        st.markdown("#### 📌 앱 예측 검증 요약")
        st.caption("앱이 낸 예측을 실제 시장 결과와 비교하고, 우선진입가를 그대로 실행했다고 가정한 누적 성과입니다.")
        c1, c2, c3, c4, c5, c6 = st.columns(6)
        c1.metric("검증완료", f"{len(done):,}건")
        c2.metric("종가범위 적중", _rate_text_v9956(close_hit))
        c3.metric("방향 적중", _rate_text_v9956(dir_hit))
        c4.metric("가상체결률", _rate_text_v9956(fill_rate))
        c5.metric("실행 승률", _rate_text_v9956(win_rate))
        c6.metric("평균 순수익", "-" if pd.isna(avg_return) else f"{avg_return:+.2f}%")

        if not pd.isna(quality_avg):
            st.caption(f"평균 예측 신뢰도 점수: {quality_avg:.1f}점 · 데이터 출처/시점이 안정적으로 쌓일수록 이 지표를 기준으로 예측 필터를 더 엄격하게 만들 수 있습니다.")

        with st.expander("최근 예측 검증 상세", expanded=False):
            show_cols = [c for c in [
                "target_date", "ticker", "primary_action", "prediction_quality_grade", "prediction_quality_score",
                "price_source", "chart_source", "actual_source", "pred_close_mid", "actual_close",
                "close_abs_error_pct", "close_in_range", "direction_hit", "virtual_result_label",
                "virtual_net_return_pct", "prediction_error_reason", "prediction_cause_summary",
                "next_prediction_adjustment", "trade_replay_summary"
            ] if c in done.columns]
            tmp = done.sort_values("target_date", ascending=False) if "target_date" in done.columns else done
            view = tmp[show_cols].head(80).copy() if show_cols else tmp.head(80).copy()
            for c in ["prediction_quality_score", "pred_close_mid", "actual_close", "close_abs_error_pct", "virtual_net_return_pct"]:
                if c in view.columns:
                    view[c] = pd.to_numeric(view[c], errors="coerce").round(2)
            st.dataframe(to_korean_display(view, compact=False), use_container_width=True, hide_index=True)
    except Exception as e:
        st.warning(f"예측 검증 요약 표시 중 오류: {e}")

# v9.9.48 ② 예측 오차·가상손익 검증 패널
def _v9948_pick_col(df: pd.DataFrame, names: list[str]) -> str | None:
    for name in names:
        if name in df.columns:
            return name
    lower = {str(c).lower(): c for c in df.columns}
    for name in names:
        if str(name).lower() in lower:
            return lower[str(name).lower()]
    return None


def render_prediction_error_pnl_panel_v9948(log_df: pd.DataFrame, market: str) -> None:
    """예측값과 실제값 업데이트 후 오차/가상 손익을 검증한다."""
    try:
        if log_df is None or log_df.empty:
            return
        df = log_df.copy()
        if "market" in df.columns:
            df = df[df["market"].astype(str).eq(str(market))].copy()
        if df.empty:
            return

        ticker_col = _v9948_pick_col(df, ["ticker", "symbol", "종목"])
        target_col = _v9948_pick_col(df, ["target_date", "예측대상일", "date"])
        pred_close_col = _v9948_pick_col(df, ["pred_close_mid", "pred_close", "predicted_close", "예상종가", "예측종가"])
        entry_col = _v9948_pick_col(df, ["preferred_entry", "priority_entry", "entry_price", "우선진입가", "진입가"])
        stop_col = _v9948_pick_col(df, ["stop_loss", "stop_price", "손절가"])
        tp1_col = _v9948_pick_col(df, ["take_profit1", "take_profit", "target_price", "익절가", "1차익절가"])
        actual_high_col = _v9948_pick_col(df, ["actual_high", "실제고가"])
        actual_low_col = _v9948_pick_col(df, ["actual_low", "실제저가"])
        actual_close_col = _v9948_pick_col(df, ["actual_close", "실제종가"])

        required = [ticker_col, entry_col, actual_high_col, actual_low_col, actual_close_col]
        if any(c is None for c in required):
            with st.expander("📊 장마감 복기 표 · 예측 오차/가상손익", expanded=False):
                st.info("검증에 필요한 컬럼이 아직 부족합니다. 필요: 종목, 우선진입가, 실제고가, 실제저가, 실제종가")
            return

        for c in [pred_close_col, entry_col, stop_col, tp1_col, actual_high_col, actual_low_col, actual_close_col]:
            if c and c in df.columns:
                df[c] = pd.to_numeric(df[c], errors="coerce")

        done = df[df[entry_col].notna() & df[actual_high_col].notna() & df[actual_low_col].notna() & df[actual_close_col].notna()].copy()
        if done.empty:
            with st.expander("📊 장마감 복기 표 · 예측 오차/가상손익", expanded=False):
                st.info("아직 실제값 업데이트가 완료된 예측 기록이 없습니다. 장 종료 후 업데이트가 반영되면 오차/손익을 계산합니다.")
            return

        if target_col and target_col in done.columns:
            try:
                done["_sort_target"] = pd.to_datetime(done[target_col], errors="coerce")
                done = done.sort_values("_sort_target", ascending=False)
            except Exception:
                pass
        done = done.head(300).copy()

        done["진입체결"] = (done[actual_low_col] <= done[entry_col]) & (done[actual_high_col] >= done[entry_col])
        results = []
        exits = []
        for _, row in done.iterrows():
            if not bool(row.get("진입체결")):
                results.append("미체결")
                exits.append(np.nan)
                continue
            hit_stop = bool(stop_col and pd.notna(row.get(stop_col)) and row[actual_low_col] <= row[stop_col])
            hit_tp = bool(tp1_col and pd.notna(row.get(tp1_col)) and row[actual_high_col] >= row[tp1_col])
            if hit_stop:
                results.append("손절")
                exits.append(row.get(stop_col))
            elif hit_tp:
                results.append("익절")
                exits.append(row.get(tp1_col))
            else:
                results.append("종가청산")
                exits.append(row.get(actual_close_col))
        done["가상결과"] = results
        done["가상청산가"] = pd.to_numeric(pd.Series(exits, index=done.index), errors="coerce")
        done["가상수익률_%"] = np.nan
        mask = done["진입체결"] & done["가상청산가"].notna() & done[entry_col].notna()
        done.loc[mask, "가상수익률_%"] = ((done.loc[mask, "가상청산가"] / done.loc[mask, entry_col]) - 1) * 100

        if pred_close_col:
            done["종가예측오차_%"] = ((done[pred_close_col] - done[actual_close_col]) / done[actual_close_col] * 100).abs()
        elif "close_abs_error_pct" in done.columns:
            done["종가예측오차_%"] = pd.to_numeric(done["close_abs_error_pct"], errors="coerce").abs()
        else:
            done["종가예측오차_%"] = np.nan

        filled = done[done["진입체결"]].copy()
        win_rate = (filled["가상수익률_%"] > 0).mean() * 100 if not filled.empty else np.nan
        avg_return = filled["가상수익률_%"].mean() if not filled.empty else np.nan
        avg_error = pd.to_numeric(done["종가예측오차_%"], errors="coerce").mean()

        with st.expander("📊 장마감 복기 표 · 예측 오차/가상손익", expanded=False):
            st.caption("실제 고가·저가·종가 업데이트 후, 앱 예측 기준으로 진입했을 때의 체결 여부와 가상 손익을 검증합니다. 같은 날 손절/익절이 모두 닿은 경우는 보수적으로 손절 우선 처리합니다.")
            c1, c2, c3, c4, c5 = st.columns(5)
            c1.metric("검증 기록", f"{len(done):,}건")
            c2.metric("체결 기록", f"{len(filled):,}건")
            c3.metric("승률", "-" if pd.isna(win_rate) else f"{win_rate:.1f}%")
            c4.metric("평균 수익률", "-" if pd.isna(avg_return) else f"{avg_return:.2f}%")
            c5.metric("평균 종가오차", "-" if pd.isna(avg_error) else f"{avg_error:.2f}%")

            show_cols = []
            for c in [target_col, ticker_col, pred_close_col, actual_close_col, "종가예측오차_%", entry_col, stop_col, tp1_col, "진입체결", "가상결과", "가상청산가", "가상수익률_%"]:
                if c and c in done.columns and c not in show_cols:
                    show_cols.append(c)
            out = done[show_cols].copy()
            for c in ["종가예측오차_%", "가상수익률_%"]:
                if c in out.columns:
                    out[c] = pd.to_numeric(out[c], errors="coerce").round(2)
            st.dataframe(out.head(100), use_container_width=True, hide_index=True)
            st.caption("체결 기준: 실제저가 ≤ 우선진입가 ≤ 실제고가. 미체결 종목은 매매하지 않은 것으로 보고 손익에서 제외합니다.")
    except Exception as e:
        with st.expander("📊 장마감 복기 표 · 예측 오차/가상손익", expanded=False):
            st.warning(f"오차/손익 검증 패널 표시 중 오류: {e}")




