def _market_mode_to_market_v9977(mode: Any) -> str:
    return "한국주식" if str(mode or "").strip() == "국장" else "미국주식"


def _normalize_market_mode_v9977(mode: Any, default: str = "미장") -> str:
    m = str(mode or "").strip()
    if m in {"국장", "한국주식", "KR", "Korea", "XKRX"}:
        return "국장"
    if m in {"미장", "미국주식", "US", "USA", "NYSE", "NASDAQ"}:
        return "미장"
    return default


def _ensure_global_market_mode_v9977(default: str = "미장") -> str:
    """확장 기능 화면을 바꿔도 미장/국장 선택이 풀리지 않게 공통 세션 키로 고정한다."""
    key = "native_global_market_mode_v9977"
    if key not in st.session_state:
        candidates = [
            st.session_state.get("native_global_market_mode"),
            st.session_state.get("top_market_mode"),
            st.session_state.get("native_market_mode_home_news"),
            st.session_state.get("native_market_mode_ranking"),
            st.session_state.get("native_market_mode_buy_decision"),
            st.session_state.get("native_market_mode_sell_decision"),
        ]
        picked = next((x for x in candidates if str(x or "").strip()), default)
        st.session_state[key] = _normalize_market_mode_v9977(picked, default)
    st.session_state["native_global_market_mode"] = st.session_state[key]
    return st.session_state[key]


def _native_page_market_selector(key_suffix: str = "native") -> str:
    """확장 기능 전체에서 하나의 미장/국장 선택값을 공유한다.

    이전 버전은 화면별 key가 달라서 실행 화면을 바꿀 때마다 기본값인 미장으로
    돌아갔다. v9.9.77부터는 앱을 나가지 않는 동안 사용자가 바꾸지 않으면
    마지막 선택값을 계속 유지한다.
    graft 라우터는 사이드바에 화면 기준·미니차트를 한 번만 그린 뒤 여기서는 값만 읽는다.
    """
    if st.session_state.get("_graft_router_sidebar_built"):
        mode = _ensure_global_market_mode_v9977("미장")
        return _market_mode_to_market_v9977(mode)
    options = ["미장", "국장"]
    current = _ensure_global_market_mode_v9977("미장")
    with st.sidebar:
        st.markdown("### 시장 필터")
        mode = st.selectbox(
            "시장",
            options,
            index=options.index(current) if current in options else 0,
            key="native_global_market_mode_v9977",
            help="일반 모드의 매수·보유·매도·차트·예측·장중 요약에 공통 적용됩니다.",
        )
        st.caption(f"현재: {mode}")
    st.session_state["native_global_market_mode"] = mode
    return _market_mode_to_market_v9977(mode)


def _default_grafted_sidebar_market_mode() -> str:
    """국장 개장 중 → 국장, 국장 마감 후~미장 마감 전 → 미장, 휴장·양쪽 마감 → 마지막 선택 또는 미장."""
    prev = st.session_state.get(GRAFT_SIDEBAR_MARKET_KEY)
    if prev in ("국장", "미장"):
        fallback = prev
    else:
        fallback = _normalize_market_mode_v9977(
            st.session_state.get("native_global_market_mode_v9977")
            or st.session_state.get("top_market_mode")
            or "미장",
        )
    try:
        now = datetime.now(KST)
        if now.weekday() >= 5:
            return fallback
        if should_prioritize_kr_market(now):
            return "국장"
        kr_sess = market_session_context("한국주식")
        us_sess = market_session_context("미국주식")
        kr_session = str(kr_sess.get("session", "") or "")
        us_session = str(us_sess.get("session", "") or "")
        if kr_session == "regular":
            return "국장"
        if us_session == "regular":
            return "미장"
        if kr_session in {"pre", "preopen"} and us_session not in {"regular", "after", "post", "closed"}:
            return "국장"
        if kr_session in {"after", "post", "closed", "idle"} and us_session in {"regular", "pre", "preopen"}:
            return "미장"
    except Exception:
        pass
    return fallback


def _graft_sidebar_market_mode() -> str:
    mode = str(st.session_state.get(GRAFT_SIDEBAR_MARKET_KEY, "") or "").strip()
    if mode not in ("국장", "미장"):
        mode = _default_grafted_sidebar_market_mode()
        st.session_state[GRAFT_SIDEBAR_MARKET_KEY] = mode
    return mode


def _graft_market_token_from_mode(mode: str) -> str:
    return "한국주식" if str(mode or "").strip() == "국장" else "미국주식"


def _sync_graft_market_session(mode: str) -> str:
    token = _graft_market_token_from_mode(mode)
    mode_label = "국장" if token == "한국주식" else "미장"
    st.session_state["native_global_market_mode_v9977"] = mode_label
    st.session_state["native_global_market_mode"] = mode_label
    st.session_state["top_market_mode"] = mode_label
    st.session_state["general_mode_market_filter"] = token
    return token


def _render_grafted_sidebar_market_filter() -> str:
    """국장/미장 단일 시장 필터 (미니차트 제외)."""
    options = ["국장", "미장"]
    if st.session_state.get(GRAFT_SIDEBAR_MARKET_KEY) not in options:
        st.session_state[GRAFT_SIDEBAR_MARKET_KEY] = _default_grafted_sidebar_market_mode()
    st.markdown("### 시장 필터")
    mode = st.radio(
        "시장",
        options,
        horizontal=True,
        key=GRAFT_SIDEBAR_MARKET_KEY,
        help="운용 화면·차트·예측·장중 요약에 공통 적용됩니다.",
    )
    market = _sync_graft_market_session(mode)
    try:
        sess = market_session_context(market)
        st.caption(f"{mode} · {sess.get('session_label', '세션 확인 중')}")
    except Exception:
        st.caption(f"현재: **{mode}**")
    return market


def _render_grafted_sidebar_watch_mini(market: str) -> None:
    """선택 시장 관심종목 미니차트."""
    st.markdown("### 관심종목 미니차트")
    try:
        render_sidebar_daily_watch_summary(market)
    except Exception as exc:
        st.caption(f"표시 오류: {str(exc)[:120]}")
    st.caption("목록 편집: 관심·차트 → 관심종목")


def _render_grafted_sidebar_market_and_watch() -> str:
    """시장 필터 + 미니차트 (기존 호출부 호환)."""
    market = _render_grafted_sidebar_market_filter()
    st.divider()
    _render_grafted_sidebar_watch_mini(market)
    return market


def _native_ticker_col(df: pd.DataFrame) -> str | None:
    for c in ["ticker", "종목", "symbol", "티커", "심볼"]:
        if c in df.columns:
            return c
    return None


def _native_ticker_matches_selected_market(val: Any, market: str) -> bool:
    """국장/미장 화면에 상대 시장 티커가 섞여 보이지 않게 하는 보조 필터."""
    s = str(val or "").strip()
    if not s or s.lower() in {"nan", "none", "nat"}:
        return False
    u = s.upper().replace(" ", "")
    if market == "한국주식":
        if u.endswith(".KS") or u.endswith(".KQ"):
            return True
        nt = normalize_ticker(s, "한국주식")
        if nt.isdigit() and len(nt) == 6:
            return True
        letters = "".join(ch for ch in u if "A" <= ch <= "Z")
        digits = "".join(ch for ch in u if ch.isdigit())
        if letters and len(letters) <= 5 and not digits:
            return False
        return bool(digits)
    if u.endswith(".KS") or u.endswith(".KQ"):
        return False
    digits = "".join(ch for ch in s if ch.isdigit())
    letters = "".join(ch for ch in u if "A" <= ch <= "Z")
    if len(digits) == 6 and len(letters) == 0:
        return False
    return True


def _native_target_col(df: pd.DataFrame) -> str | None:
    for c in ["target_date", "예측대상일", "대상일", "date", "날짜"]:
        if c in df.columns:
            return c
    return None


def _native_market_filtered_log(market: str) -> pd.DataFrame:
    try:
        df = load_prediction_log()
    except Exception:
        df = pd.DataFrame()
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    if "market" in out.columns:
        out = out[out["market"].astype(str).eq(market)].copy()
    if market == "미국주식":
        out = normalize_us_tickers_in_log(out)
        out = drop_excluded_us_stock_rows(out, market)
    tc = _native_ticker_col(out)
    if tc:
        mask = out[tc].map(lambda x: _native_ticker_matches_selected_market(x, market))
        out = out.loc[mask].copy()
    return out


def _native_latest_prediction_batch(log_df: pd.DataFrame, market: str, prefer_pending: bool = True) -> pd.DataFrame:
    if log_df is None or log_df.empty:
        return pd.DataFrame()
    df = log_df.copy()
    df = drop_excluded_us_stock_rows(df, market)
    if df.empty:
        return pd.DataFrame()
    if prefer_pending and "actual_close" in df.columns:
        pending = df[pd.to_numeric(df["actual_close"], errors="coerce").isna()].copy()
        if not pending.empty:
            df = pending
    tcol = _native_target_col(df)
    if tcol:
        dt = pd.to_datetime(df[tcol], errors="coerce")
        if dt.notna().any():
            latest = dt.max()
            df = df[dt.eq(latest)].copy()
    elif "created_at" in df.columns:
        dt = pd.to_datetime(df["created_at"], errors="coerce")
        if dt.notna().any():
            latest = dt.max()
            df = df[dt.eq(latest)].copy()
    ticker_col = _native_ticker_col(df)
    if ticker_col:
        order = watchlist_symbols(market)
        keymap = {display_symbol(x, market): i for i, x in enumerate(order)} if market == "미국주식" else {normalize_ticker(x, market): i for i, x in enumerate(order)}
        df["_watch_order"] = df[ticker_col].apply(lambda x: keymap.get(display_symbol(x, market) if market == "미국주식" else normalize_ticker(x, market), 9999))
        df = df.sort_values(["_watch_order"]).drop(columns=["_watch_order"], errors="ignore")
        m2 = df[ticker_col].map(lambda x: _native_ticker_matches_selected_market(x, market))
        df = df.loc[m2].copy()
        # 동일 티커·동일 target_date 배치가 여러 번 쌓이면 watchlist 정렬 후에도 상단 N행이 같은 종목이 될 수 있음
        df = df.drop_duplicates(subset=[ticker_col], keep="first").reset_index(drop=True)
    return df


def _native_watchlist_df(market: str) -> pd.DataFrame:
    try:
        df = load_watchlist_df(market)
    except Exception:
        df = pd.DataFrame()
    if df is None:
        df = pd.DataFrame()
    if not df.empty and market == "미국주식":
        df = normalize_us_ticker_fields_in_df(df, market_aware=False)
    return df


def _native_show_prediction_table(df: pd.DataFrame, market: str, title: str = "예측 기록") -> None:
    st.markdown(f"#### {title}")
    if df is None or df.empty:
        st.warning("표시할 예측 기록이 없습니다. 장전 배치 실행 후 predictions.csv가 생성되면 이 화면에 반영됩니다.")
        return
    df = df.copy()
    tc = _native_ticker_col(df)
    if tc:
        m = df[tc].map(lambda x: _native_ticker_matches_selected_market(x, market))
        df = df.loc[m].copy()
    if "market" in df.columns:
        df = df[df["market"].astype(str).eq(market)].copy()
    show_cols = []
    wanted = [
        "target_date", "ticker", "종목", "final_action", "최종판단", "action_label", "confidence_score", "신뢰도",
        "preferred_entry", "우선진입가", "stop_loss", "손절가", "take_profit1", "1차익절가", "take_profit2", "2차익절가",
        "risk_reward", "손익비", "no_buy_flags", "매수주의사유", "created_at", "actual_close", "실제종가",
    ]
    for c in wanted:
        if c in df.columns and c not in show_cols:
            show_cols.append(c)
    if not show_cols:
        show_cols = list(df.columns[:18])
    st.dataframe(to_korean_display(df[show_cols].copy()), use_container_width=True, hide_index=True)



