def _html_escape_v9968(value: Any) -> str:
    try:
        import html
        return html.escape(str(value or ""))
    except Exception:
        return str(value or "")


def _plain_news_text_v9968(value: Any, max_len: int = 160) -> str:
    s = str(value or "").strip()
    # markdown bold/list markers and line breaks from summarize_market_news_ko_v78
    s = re.sub(r"\*\*|__|`", "", s)
    s = re.sub(r"\s*[-•]\s*", " ", s)
    s = re.sub(r"\n+", " ", s)
    s = re.sub(r"\s+", " ", s).strip()
    if len(s) > max_len:
        return s[:max_len].rstrip() + "..."
    return s


def _direction_chip_v9968(value: Any) -> tuple[str, str, str]:
    v = str(value or "중립").strip()
    if any(k in v for k in ["우호", "상승", "강세", "+", "개선", "호조"]):
        return "우호", "#22c55e", "rgba(34,197,94,.13)"
    if any(k in v for k in ["부담", "하락", "약세", "위험", "악재", "-", "경고"]):
        return "부담", "#ef4444", "rgba(239,68,68,.13)"
    if any(k in v for k in ["주의", "변동", "중간"]):
        return "변동성", "#f59e0b", "rgba(245,158,11,.14)"
    return "중립", "#60a5fa", "rgba(96,165,250,.13)"


