def _news_item_time_score_v9974(item: dict[str, Any]) -> float:
    for key in ("published_ts", "published_at", "datetime", "time"):
        raw = item.get(key)
        if not raw:
            continue
        try:
            ts = pd.to_datetime(raw, errors="coerce", utc=True)
            if pd.notna(ts):
                return float(ts.timestamp())
        except Exception:
            continue
    return 0.0


def _stock_news_symbols_v9974(market: str) -> list[str]:
    base = ["NVDA", "AMD", "AMZN", "AAPL", "MSFT", "GOOGL", "GOOG", "META", "TSLA", "AVGO", "INTC", "QCOM", "SMH", "QQQ", "SPY"]
    try:
        wl = [str(x).upper().strip() for x in watchlist_symbols(market)]
    except Exception:
        wl = []
    out: list[str] = []
    for sym in wl + base:
        sym = re.sub(r"[^A-Z0-9.\-]", "", sym)
        if sym and sym not in out and sym != "BTC-USD":
            out.append(sym)
    return out[:80]


def _news_item_tags_v9974(item: dict[str, Any], market: str) -> list[str]:
    text = " ".join(str(item.get(k, "") or "") for k in ("title", "summary", "description", "reason", "related_ticker", "ticker", "tickers", "theme", "alarm_reasons"))
    low = text.lower()
    tags: list[str] = []
    for raw in (item.get("related_ticker"), item.get("ticker"), item.get("tickers"), item.get("related_tickers")):
        if isinstance(raw, (list, tuple, set)):
            candidates = raw
        else:
            candidates = re.split(r"[;,/\s]+", str(raw or ""))
        for c in candidates:
            t = str(c or "").upper().strip()
            if t and t not in tags and t != "BTC-USD":
                tags.append(t)
    for sym in _stock_news_symbols_v9974(market):
        if re.search(rf"(?<![A-Z0-9]){re.escape(sym)}(?![A-Z0-9])", text.upper()) and sym not in tags:
            tags.append(sym)
    theme_rules = [
        ("CPI/물가", ("cpi", "consumer price", "inflation", "물가", "인플레이션")),
        ("금리", ("fed", "fomc", "rate", "yield", "treasury", "연준", "금리", "국채")),
        ("AI/반도체", ("ai", "chip", "semiconductor", "nvidia", "amd", "intel", "반도체", "엔비디아")),
        ("실적", ("earnings", "guidance", "revenue", "실적", "가이던스")),
    ]
    for label, keys in theme_rules:
        if any(k in low for k in keys) and label not in tags:
            tags.append(label)
    importance = str(item.get("importance", "") or "").strip()
    if importance and importance not in tags:
        tags.append(importance)
    direction = str(item.get("direction", "") or "").strip()
    if direction and direction not in tags:
        tags.append(direction)
    return tags[:6]


def _news_item_stock_relevance_v9974(item: dict[str, Any], market: str) -> float:
    text = " ".join(str(item.get(k, "") or "") for k in ("title", "summary", "description", "reason", "source", "theme", "alarm_reasons"))
    low = text.lower()
    score = safe_float(item.get("relevance"), 0) + safe_float(item.get("severity"), 0)
    macro_terms = ("cpi", "consumer price", "ppi", "pce", "inflation", "fomc", "fed", "rate", "yield", "treasury", "jobs", "payroll", "물가", "소비자물가", "생산자물가", "연준", "금리", "국채", "고용")
    stock_terms = ("stock", "stocks", "nasdaq", "s&p", "dow", "market", "earnings", "guidance", "ai", "chip", "semiconductor", "주식", "증시", "나스닥", "반도체", "실적")
    score += sum(8 for k in macro_terms if k in low)
    score += sum(5 for k in stock_terms if k in low)
    for sym in _stock_news_symbols_v9974(market):
        if re.search(rf"(?<![A-Z0-9]){re.escape(sym)}(?![A-Z0-9])", text.upper()):
            score += 10
    importance = str(item.get("importance", "") or "")
    if importance == "높음":
        score += 12
    elif importance == "중간":
        score += 5
    ts = _news_item_time_score_v9974(item)
    if ts:
        age_hours = max(0.0, (datetime.now(timezone.utc).timestamp() - ts) / 3600)
        score += max(0.0, 18 - min(age_hours, 72) * 0.25)
    return float(score)


def _news_text_v9977(item: dict[str, Any]) -> str:
    return " ".join(
        str(item.get(k, "") or "")
        for k in ("title", "summary", "description", "reason", "source", "theme", "alarm_reasons", "related_ticker", "ticker", "tickers", "related_tickers")
    )


def _news_us_symbol_hits_v9977(item: dict[str, Any], market: str) -> list[str]:
    text = _news_text_v9977(item).upper()
    hits: list[str] = []
    for sym in _stock_news_symbols_v9974(market):
        if sym.endswith(".KS") or sym.endswith(".KQ") or sym == "BTC-USD":
            continue
        if re.search(rf"(?<![A-Z0-9]){re.escape(sym)}(?![A-Z0-9])", text):
            hits.append(sym)
    return hits


def _news_kr_symbol_hits_v9982(item: dict[str, Any]) -> list[str]:
    text = _news_text_v9977(item).upper()
    hits = re.findall(r"(?<!\d)(\d{6}\.(?:KS|KQ))(?![A-Z0-9])", text)
    kr_names = {
        "삼성전자", "SK하이닉스", "하이닉스", "현대차", "LG에너지솔루션", "LG엔솔",
        "한국전력", "대한항공", "HD한국조선해양", "한국항공우주", "코스피", "코스닥",
    }
    for name in kr_names:
        if name.upper() in text and name not in hits:
            hits.append(name)
    return list(dict.fromkeys(hits))


def _news_item_matches_market_v9982(item: dict[str, Any], market: str) -> bool:
    """Route news to US/KR screens so the same broad feed does not show everywhere."""
    text = _news_text_v9977(item)
    low = text.lower()
    source = str(item.get("source", "") or "")
    item_market = str(item.get("market", "") or "").upper()
    origin = str(item.get("origin", "") or "")
    if origin in {"required_macro_watch", "macro_event_context"}:
        return True
    us_hits = _news_us_symbol_hits_v9977(item, "미국주식")
    kr_hits = _news_kr_symbol_hits_v9982(item)
    us_terms = any(k in low for k in (
        "nasdaq", "s&p", "dow", "wall street", "qqq", "spy", "nvidia", "amd", "tesla",
        "amazon", "apple", "microsoft", "meta", "google", "rocket lab", "rklb",
        "미국증시", "미국 주식", "뉴욕증시", "나스닥", "다우", "엔비디아", "테슬라",
    ))
    kr_terms = any(k in low for k in (
        "kospi", "kosdaq", "krx", "korea stock", "코스피", "코스닥", "국내증시", "국장",
        "한국 주식", "삼성전자", "sk하이닉스", "하이닉스", "현대차", "한국전력", "대한항공",
    ))
    us_dominant_terms = any(k in low for k in (
        "뉴욕증시", "미국증시", "미국 주식", "나스닥", "다우", "s&p", "wall street",
        "nvidia", "엔비디아", "amd", "intel", "qualcomm", "tesla", "트럼프", "cpi", "fomc",
    ))
    macro_terms = any(k in low for k in (
        "cpi", "ppi", "pce", "fomc", "fed", "yield", "treasury", "inflation",
        "물가", "금리", "연준", "국채",
    ))

    if market == "미국주식":
        if item_market in {"KR", "KOR", "한국", "국내"} and not (us_terms or us_hits or macro_terms):
            return False
        if source == "Korea Market RSS" and not (us_terms or us_hits or macro_terms):
            return False
        if kr_terms and not (us_terms or us_hits or macro_terms):
            return False
        return bool(us_terms or us_hits or macro_terms or item_market in {"US", "USA", "ALL"} or source == "Global Market RSS")

    if us_dominant_terms and not any(k in low for k in ("삼성전자", "sk하이닉스", "하이닉스", "코스피", "코스닥", "외국인", "기관", "환율", "원달러")):
        return False
    if item_market in {"US", "USA"} and not (kr_terms or kr_hits):
        return False
    if source == "Global Market RSS" and not (kr_terms or kr_hits):
        return False
    if (us_terms or us_hits) and not (kr_terms or kr_hits):
        return False
    return bool(kr_terms or kr_hits or item_market in {"KR", "KOR", "한국", "국내", "ALL"} or source == "Korea Market RSS")


