def _news_impact_bucket_v9981(item: dict[str, Any], market: str) -> str:
    low = _news_text_v9977(item).lower()
    hits = _news_us_symbol_hits_v9977(item, market)
    if market == "한국주식":
        if any(k in low for k in ("코스피", "코스닥", "국내증시", "장중 상승", "상승 전환", "최고치", "반등 성공")):
            if any(k in low for k in ("삼성전자", "sk하이닉스", "하이닉스", "반도체", "hbm")):
                return "kr_index_semiconductor_flow"
            return "kr_index_general_flow"
        if any(k in low for k in ("외국인", "기관", "순매수", "순매도")):
            if any(k in low for k in ("삼성전자", "sk하이닉스", "하이닉스", "반도체", "hbm")):
                return "kr_semiconductor_supply"
            return "kr_supply_general"
        if any(k in low for k in ("환율", "원달러", "원/달러")):
            return "kr_fx_flow"
        if any(k in low for k in ("실적", "호실적", "가이던스", "수주", "계약", "공급", "공시")):
            return "kr_company_event"
        if any(k in low for k in ("조선", "방산", "전력", "원전", "2차전지", "자동차")):
            return "kr_sector_theme"
    if any(k in low for k in ("cpi", "consumer price", "inflation", "물가", "인플레이션")):
        if any(k in low for k in ("semiconductor", "chip", "nvidia", "amd", "intel", "qualcomm", "반도체", "엔비디아")):
            return "macro_cpi_semiconductor"
        return "macro_cpi_market"
    if any(k in low for k in ("fomc", "fed", "powell", "rate", "yield", "treasury", "연준", "파월", "금리", "국채")):
        return "macro_fed_rates"
    if any(k in low for k in ("ppi", "pce", "payroll", "jobs", "unemployment", "고용", "생산자물가")):
        return "macro_other_data"
    if any(k in low for k in ("iran", "middle east", "hormuz", "war", "attack", "oil", "crude", "wti", "brent", "이란", "중동", "공격", "전쟁", "유가", "원유")):
        return "geopolitics_oil"
    if any(k in low for k in ("earnings", "revenue", "profit", "guidance", "실적", "매출", "가이던스")):
        return "earnings_" + ("_".join(hits[:2]) if hits else "general")
    if any(k in low for k in ("price target", "upgrade", "downgrade", "analyst", "목표가", "투자의견")):
        return "analyst_" + ("_".join(hits[:2]) if hits else "general")
    if any(k in low for k in ("semiconductor", "chip", "ai", "nvidia", "amd", "intel", "qualcomm", "broadcom", "반도체", "엔비디아")):
        return "sector_ai_semiconductor"
    if any(k in low for k in ("nasdaq", "s&p", "dow", "qqq", "spy", "stock market", "wall street", "나스닥", "다우", "증시")):
        return "index_market_move"
    if hits:
        return "ticker_" + "_".join(hits[:2])
    words = re.findall(r"[a-zA-Z가-힣0-9]+", low)
    stop = {"the", "and", "for", "with", "after", "today", "news", "market", "stock", "stocks", "주식", "뉴스", "시장"}
    core = [w for w in words if len(w) > 2 and w not in stop][:6]
    return "topic_" + "_".join(core)


def _dedupe_news_by_impact_v9981(items: list[dict[str, Any]], market: str, limit: int) -> list[dict[str, Any]]:
    deduped: list[dict[str, Any]] = []
    seen_buckets: set[str] = set()
    seen_titles: set[str] = set()
    for item in items:
        origin = str(item.get("origin", "") or "")
        title_key = re.sub(r"\W+", "", str(item.get("title", "") or "").lower())[:100]
        bucket = _news_impact_bucket_v9981(item, market)
        if origin == "required_macro_watch":
            deduped.append(item)
            continue
        if title_key and title_key in seen_titles:
            continue
        if bucket in seen_buckets:
            continue
        seen_titles.add(title_key)
        seen_buckets.add(bucket)
        deduped.append(item)
        if len(deduped) >= limit:
            break
    return deduped


