def _mvp_news_csv_paths_v9979() -> list[Path]:
    try:
        here = Path(__file__).resolve().parent
    except Exception:
        here = Path(".").resolve()
    candidates = [
        here / "data" / "news" / "today_news.csv",
        here.parent.parent / "stock_app _new" / "stock_app" / "data" / "news" / "today_news.csv",
    ]
    out: list[Path] = []
    for p in candidates:
        try:
            if p.exists() and p not in out:
                out.append(p)
        except Exception:
            continue
    return out


def _mvp_news_source_items_v9979(market: str, max_items: int = 40) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    seen = set()
    for path in _mvp_news_csv_paths_v9979():
        try:
            df = pd.read_csv(path, encoding="utf-8-sig").fillna("")
        except Exception:
            continue
        if df.empty:
            continue
        for _, r in df.head(160).iterrows():
            title = str(r.get("title", "") or "").strip()
            if not title:
                continue
            sample_text = " ".join(str(r.get(c, "") or "") for c in ("source", "collected_at", "datetime", "title"))
            if "샘플" in sample_text:
                continue
            key = re.sub(r"\W+", "", title.lower())[:90]
            if key in seen:
                continue
            seen.add(key)
            sentiment = str(r.get("sentiment", "중립") or "중립")
            direction = "우호" if sentiment == "긍정" else "부담" if sentiment in {"부정", "주의"} else "중립/변동성"
            importance_num = safe_float(r.get("importance"), 0)
            importance = "높음" if importance_num >= 75 else "중간" if importance_num >= 45 else "낮음"
            item = {
                "title": title,
                "source": str(r.get("source", "MVP 뉴스") or "MVP 뉴스"),
                "time": str(r.get("datetime", "-") or "-"),
                "published_ts": str(r.get("datetime", "") or ""),
                "summary": str(r.get("summary", "") or title),
                "url": str(r.get("url", "") or ""),
                "related_ticker": str(r.get("ticker", "") or ""),
                "theme": str(r.get("theme", "") or ""),
                "market": str(r.get("market", "") or ""),
                "importance": importance,
                "direction": direction,
                "sentiment": sentiment,
                "origin": "mvp_today_news_csv",
                "_mvp_importance": importance_num,
            }
            item["_stock_news_score"] = max(importance_num, _news_item_stock_relevance_v9974(item, market))
            item["_published_score"] = _news_item_time_score_v9974(item)
            if _news_item_matches_market_v9982(item, market) and _is_stock_relevant_news_v9976(item, market):
                items.append(item)
            if len(items) >= max_items:
                return items
    return items


def _is_stock_relevant_news_v9976(item: dict[str, Any], market: str) -> bool:
    text = _news_text_v9977(item)
    low = text.lower()
    origin = str(item.get("origin", "") or "")
    if origin in {"macro_event_context", "required_macro_watch"}:
        return True
    irrelevant_terms = (
        "sports", "football", "baseball", "basketball", "movie", "music", "celebrity",
        "여행", "맛집", "스포츠", "연예", "영화", "드라마", "축구", "야구",
    )
    if any(k in low for k in irrelevant_terms):
        return False
    if market == "한국주식" and not _kr_news_has_actionable_impact_v9983(item):
        return False
    source = str(item.get("source", "") or "")
    age_hours = _news_age_hours_v9977(item)
    has_impact = _news_has_trade_impact_terms_v9977(item)
    us_hits = _news_us_symbol_hits_v9977(item, market)
    if market == "미국주식":
        is_macro = any(k in low for k in ("cpi", "ppi", "pce", "fomc", "fed", "inflation", "yield", "treasury", "rate", "물가", "금리", "연준", "국채"))
        if "Korea Market RSS" in source and not is_macro and not (us_hits and has_impact):
            return False
        if age_hours is not None and age_hours > 72 and not is_macro:
            return False
        if us_hits and not has_impact and not is_macro:
            return False
    hard_market_terms = (
        "stock", "stocks", "nasdaq", "s&p", "dow", "market", "earnings", "guidance", "semiconductor", "chip",
        "fed", "fomc", "cpi", "ppi", "pce", "inflation", "yield", "treasury", "rate", "oil", "dollar",
        "주식", "증시", "나스닥", "실적", "가이던스", "반도체", "연준", "금리", "물가", "국채", "환율", "유가",
    )
    if any(k in low for k in hard_market_terms) and has_impact:
        return True
    upper = text.upper()
    for sym in _stock_news_symbols_v9974(market):
        if re.search(rf"(?<![A-Z0-9]){re.escape(sym)}(?![A-Z0-9])", upper):
            return has_impact
    if safe_float(item.get("_stock_news_score"), 0) >= 18 and has_impact:
        return True
    return False


def _required_macro_watch_item_v9976(event_context: dict[str, Any], market: str) -> dict[str, Any]:
    raw = []
    for key in ("auto_macro_events", "event_names", "macro_events"):
        value = (event_context or {}).get(key)
        if isinstance(value, (list, tuple, set)):
            raw.extend([str(x) for x in value if str(x).strip()])
        elif value:
            raw.append(str(value))
    joined = " / ".join(dict.fromkeys(raw))
    if joined:
        if market == "한국주식":
            summary = f"오늘 감지된 주요 이벤트: {joined}. 환율·외국인 수급·코스피/코스닥 변동성에 우선 반영합니다."
            title = "국장 매크로 체크: 환율·수급 영향 확인"
        else:
            summary = f"오늘 감지된 주요 이벤트: {joined}. CPI/FOMC/PPI/PCE/고용·금리 헤드라인은 성장주와 나스닥 변동성에 우선 반영합니다."
            title = "미장 매크로 체크: CPI·FOMC·금리 확인"
    else:
        if market == "한국주식":
            summary = "국장은 환율, 외국인 수급, 코스피/코스닥, 미국 장 마감 영향을 먼저 확인합니다."
            title = "국장 매크로 체크: 환율·미장 영향 확인"
        else:
            summary = "CPI, FOMC, PPI, PCE, 고용, 국채금리 뉴스는 종목 뉴스보다 먼저 확인합니다. 감지 이벤트가 없으면 나스닥·금리·달러 반응을 기준으로 판단합니다."
            title = "미장 매크로 체크: CPI·FOMC·금리 확인"
    return {
        "title": title,
        "source": "매크로 체크",
        "time": "상시 확인",
        "importance": "높음",
        "direction": "중립/변동성",
        "summary": summary,
        "url": "",
        "origin": "required_macro_watch",
        "_stock_news_score": 999.0,
        "_published_score": 0.0,
    }


def _macro_watch_html_v9976(event_context: dict[str, Any]) -> str:
    raw_text = " ".join(map(str, (event_context or {}).get("auto_macro_events", []) or [])) + " " + " ".join(map(str, (event_context or {}).get("event_names", []) or []))
    low = raw_text.lower()
    checks = [
        ("CPI", ("cpi", "consumer price", "물가", "소비자물가")),
        ("FOMC", ("fomc", "fed", "연준")),
        ("PPI/PCE", ("ppi", "pce", "생산자물가")),
        ("고용", ("jobs", "payroll", "unemployment", "고용")),
        ("금리", ("yield", "treasury", "rate", "국채", "금리")),
    ]
    parts = []
    for name, keys in checks:
        state = "감지됨" if any(k in low for k in keys) else "확인"
        parts.append(f"<div class='tk-macro-pill'><div class='tk-macro-name'>{_html_escape_v9968(name)}</div><div class='tk-macro-state'>{_html_escape_v9968(state)}</div></div>")
    return "<div class='tk-macro-strip'>" + "".join(parts) + "</div>"


