def _normalize_native_ui_market_v9982(market: str) -> str:
    """사이드바·레거시 값이 섞여도 스윙/예측 경로와 동일한 토큰으로 맞춘다."""
    m = str(market or "").strip()
    if m in ("한국주식", "국장", "KR", "XKRX", "Korea", "kr"):
        return "한국주식"
    if m in ("미국주식", "미장", "US", "USA", "NYSE", "NASDAQ", "us"):
        return "미국주식"
    return m


def _strip_bom_whitespace_columns_df(df: pd.DataFrame) -> pd.DataFrame:
    out = df.copy()
    out.columns = [str(c).strip().lstrip("\ufeff") for c in out.columns]
    return out


def _canonical_market_cell_v9982(val: Any) -> str:
    s = str(val or "").strip()
    if not s or s.lower() in ("nan", "none"):
        return ""
    if s in ("한국주식", "국장", "KR", "XKRX", "Korea", "kr"):
        return "한국주식"
    if s in ("미국주식", "미장", "US", "USA", "NYSE", "NASDAQ", "us"):
        return "미국주식"
    return ""


def _filter_swing_a_top3_df_for_market(df: pd.DataFrame, market: str) -> pd.DataFrame:
    """CSV의 market 열·BOM·티커 형식 차이로 상단 A급과 표가 어긋나지 않게 한다."""
    page_m = _normalize_native_ui_market_v9982(market)
    work = _strip_bom_whitespace_columns_df(df)
    mcol = next((c for c in ("market", "Market", "시장", "MARKET") if c in work.columns), None)
    if mcol:
        raw = work[mcol].astype(str).str.strip()
        canon = raw.map(_canonical_market_cell_v9982)
        mask = canon.eq(page_m) | raw.eq(page_m)
        sub = work.loc[mask].copy()
        if not sub.empty:
            return sub
        tcol = _native_ticker_col(work)
        if tcol:
            tm = work[tcol].apply(lambda x: _native_ticker_matches_selected_market(x, page_m))
            sub2 = work.loc[tm].copy()
            if not sub2.empty:
                return sub2
        return sub
    tcol = _native_ticker_col(work)
    if tcol:
        tm = work[tcol].apply(lambda x: _native_ticker_matches_selected_market(x, page_m))
        sub3 = work.loc[tm].copy()
        if not sub3.empty:
            return sub3
    return work


def _render_native_swing_a_top3_table_for_market(market: str) -> None:
    """첫 화면 A급과 동일한 swing_candidates_*_A_top3.csv 미리보기."""
    page_m = _normalize_native_ui_market_v9982(market)
    path = SWING_SCAN_KR_TOPA_FILE if page_m == "한국주식" else SWING_SCAN_US_TOPA_FILE
    st.markdown(f"#### 스윙 A급 TOP3 (`{path.name}`)")
    st.caption("스윙 스캔(runner) 결과입니다. 위쪽 **가격 예측 기반** TOP3(predictions.csv)과 목적·정렬이 다릅니다.")
    try:
        if not path.exists() or path.stat().st_size == 0:
            st.info(f"파일이 없습니다: `{path.name}` — runner_swing_scan 또는 predict 후 스캔을 실행하세요.")
            return
        df_raw = read_csv_cached(path, dtype_str=True).fillna("")
        df = _filter_swing_a_top3_df_for_market(df_raw, page_m)
        if df.empty:
            st.info(
                "스윙 A급 후보가 비어 있습니다. "
                f"(파일 행 {len(df_raw)} · 시장 필터 `{page_m}` · `market` 열·티커 기준)"
            )
            return
        st.dataframe(df.head(12), use_container_width=True, hide_index=True)
    except Exception as ex:
        st.warning(f"스윙 A CSV 읽기 실패: {ex}")


def _home_dashboard_view_scope_for_page_market(page_market: str) -> str:
    """첫 화면 `시장별 보기` 라디오 값(대시보드 렌더 직후 session_state에서 읽음)."""
    default = "한국장" if page_market == "한국주식" else "미국장"
    key = f"home_dash_view_scope_v2_{page_market}"
    v = str(st.session_state.get(key, default)).strip()
    return v if v in ("전체", "한국장", "미국장") else default


def _effective_market_from_home_view_scope(view_scope: str, page_market: str) -> str:
    if view_scope == "한국장":
        return "한국주식"
    if view_scope == "미국장":
        return "미국주식"
    return page_market


def render_native_prediction_hero_section(
    market: str,
    section_title: str = "가격 예측 기반 확인 후보 TOP3 (predictions.csv)",
    reliability_result: dict[str, Any] | None = None,
    log_df: pd.DataFrame | None = None,
) -> None:
    """new UI 홈/랭킹 상단에서 단일 카드뉴스 판단 흐름을 보여준다.

    중요:
    - predictions.csv를 읽어 화면에 보여주기만 한다.
    - 스윙 A급 TOP3(swing_candidates_*_A_top3.csv)와는 별도 개념이다.
    - 예측 생성/결과 업데이트/작업스케줄러/runner 로직은 호출하지 않는다.
    """
    log_df = log_df if log_df is not None else _native_market_filtered_log(market)
    batch = _native_latest_prediction_batch(log_df, market)
    if batch is None or batch.empty:
        st.info("최근 장전 예측 배치가 없습니다. 장전 작업스케줄러 실행 후 이 영역에 TOP 후보가 표시됩니다.")
        return
    target_label = _native_target_label(batch)
    try:
        view = force_us_symbol_column(build_next_prediction_view_v39(batch, log_df, market), market)
    except Exception:
        view = batch.copy()
    if view is None or view.empty:
        _native_show_prediction_table(batch, market, section_title)
        return

    st.markdown(f"### {section_title}")
    st.caption(
        f"{market} / 예측대상일 {target_label}. **predictions.csv** 기준이며, "
        f"스윙 A급 TOP3(`swing_candidates_{'kr' if market == '한국주식' else 'us'}_A_top3.csv`)와는 별도입니다."
    )
    try:
        action_df = build_unified_decision_df(view.head(12), log_df, market, use_realtime_guard=False)
        render_card_news_candidates(
            action_df,
            market,
            title="가격 예측 기반 확인 후보 TOP3 (스윙 A급과 별개)",
            target_label=target_label,
            top_n=3,
            use_realtime_guard=False,
            reliability_result=reliability_result,
        )
    except Exception:
        cols = ["예측대상일", "종목", "판정", "보정신뢰도", "매매적합도", "우선진입가", "손절가", "1차익절가", "주의사유"]
        st.dataframe(view[[c for c in cols if c in view.columns]].head(5), use_container_width=True, hide_index=True)


def _home_buy_signal_csv_path(file_name: str) -> Path | None:
    """레거시 `reports/` 또는 `stock_ai_app_new/data/` 중 비어 있지 않은 파일."""
    root = Path(__file__).resolve().parent
    for p in (REPORT_DIR / file_name, root / "stock_ai_app_new" / "data" / file_name):
        try:
            if p.is_file() and p.stat().st_size > 0:
                return p
        except OSError:
            continue
    return None


def _home_df_market_slice(df: pd.DataFrame, market: str) -> pd.DataFrame:
    if df.empty or "market" not in df.columns:
        return df
    return df[df["market"].astype(str).str.strip().eq(market)].copy()


def _home_pullback_rows(df: pd.DataFrame) -> pd.DataFrame:
    if df.empty:
        return df
    dec_c = None
    for c in ("final_judgment", "최종 판단", "final_decision", "primary_action"):
        if c in df.columns:
            dec_c = c
            break
    if dec_c is None:
        return pd.DataFrame()
    s = df[dec_c].astype(str)
    m = s.str.contains("눌림목", na=False) | s.str.contains("눌림", na=False)
    out = df.loc[m].copy()
    score_c = (
        "final_priority_score"
        if "final_priority_score" in out.columns
        else ("total_score" if "total_score" in out.columns else None)
    )
    if score_c:
        out = out.assign(_sc=pd.to_numeric(out[score_c], errors="coerce")).sort_values(
            "_sc", ascending=False, na_position="last"
        )
        out = out.drop(columns=["_sc"], errors="ignore")
    return out.head(8)


def _home_buy_three_display_cols(df: pd.DataFrame) -> list[str]:
    want = [
        "종목명",
        "name",
        "stock_name",
        "종목코드",
        "symbol",
        "ticker",
        "현재가",
        "current_price",
        "조건부 진입가",
        "entry",
        "손절가",
        "1차 목표가",
        "수급점수",
        "실적점수",
        "밸류에이션점수",
        "total_score",
        "종합점수",
        "final_judgment",
        "최종 판단",
        "buy_zone",
        "reason",
    ]
    return [c for c in want if c in df.columns][:8]


def render_home_buy_three_strip_v10030(
    market: str,
    *,
    reliability: dict[str, Any] | None = None,
) -> None:
    """저평가·눌림목·관심 후보 — 저장된 CSV만 읽음."""
    st.markdown("#### 오늘 후보 미리보기 · 저평가 · 눌림목 · 관심종목")
    st.caption(
        "급락·이벤트 장세에서는 예측 구간이 쉽게 어긋날 수 있습니다. 아래는 **구간·후보 참고용**이며, "
        "`runner_buy_dashboard` 등으로 갱신된 `undervalued_growth_candidates.csv`, "
        "`buy_priority_candidates.csv`, `watchlist_buy_candidates.csv`를 읽습니다."
    )
    rel = reliability or {}
    if bool(rel.get("block_top3", False)):
        st.warning(
            f"오늘은 데이터 신뢰도 낮음 / 관망 우선 ({rel.get('label', '')})".strip()
        )
    p_ud = _home_buy_signal_csv_path("undervalued_growth_candidates.csv")
    p_pri = _home_buy_signal_csv_path("buy_priority_candidates.csv")
    p_wl = _home_buy_signal_csv_path("watchlist_buy_candidates.csv")
    df_ud = _read_csv_flexible(p_ud) if p_ud else pd.DataFrame()
    df_pri = _read_csv_flexible(p_pri) if p_pri else pd.DataFrame()
    df_wl = _read_csv_flexible(p_wl) if p_wl else pd.DataFrame()
    try:
        df_ud = enrich_candidate_frame(df_ud, market, source_path=p_ud, ensure_common_columns=True) if not df_ud.empty else df_ud
        df_pri = enrich_candidate_frame(df_pri, market, source_path=p_pri, ensure_common_columns=True) if not df_pri.empty else df_pri
        df_wl = enrich_candidate_frame(df_wl, market, source_path=p_wl, ensure_common_columns=True) if not df_wl.empty else df_wl
    except Exception:
        pass
    df_ud = _home_df_market_slice(df_ud, market)
    df_pri = _home_df_market_slice(df_pri, market)
    df_wl = _home_df_market_slice(df_wl, market)
    pull_show = _home_pullback_rows(df_pri)
    if not df_ud.empty:
        for sc in ("undervaluation_score", "total_score", "final_score"):
            if sc in df_ud.columns:
                df_ud = (
                    df_ud.assign(_sc=pd.to_numeric(df_ud[sc], errors="coerce"))
                    .sort_values("_sc", ascending=False, na_position="last")
                    .drop(columns=["_sc"], errors="ignore")
                )
                break
        df_ud = df_ud.head(8)
    if not df_wl.empty:
        sc = "total_score" if "total_score" in df_wl.columns else ("final_score" if "final_score" in df_wl.columns else None)
        if sc:
            df_wl = (
                df_wl.assign(_sc=pd.to_numeric(df_wl[sc], errors="coerce"))
                .sort_values("_sc", ascending=False, na_position="last")
                .drop(columns=["_sc"], errors="ignore")
            )
        df_wl = df_wl.head(8)
    col_ud, col_pb, col_wl = st.columns(3)
    dc_ud = _home_buy_three_display_cols(df_ud)
    dc_pb = _home_buy_three_display_cols(pull_show)
    dc_wl = _home_buy_three_display_cols(df_wl)
    with col_ud:
        st.markdown("**저평가 성장**")
        st.caption(p_ud.name if p_ud else "파일 없음")
        if df_ud.empty:
            st.info("데이터 없음")
        else:
            st.dataframe(_format_ui_table_values(df_ud[dc_ud], market), use_container_width=True, hide_index=True, height=220)
    with col_pb:
        st.markdown("**눌림목(우선순위)**")
        st.caption(p_pri.name if p_pri else "파일 없음")
        if pull_show.empty:
            st.info("눌림목 판정 행 없음 또는 우선순위 파일 없음")
        else:
            st.dataframe(_format_ui_table_values(pull_show[dc_pb], market), use_container_width=True, hide_index=True, height=220)
    with col_wl:
        st.markdown("**관심종목 후보**")
        st.caption(p_wl.name if p_wl else "파일 없음")
        if df_wl.empty:
            st.info("데이터 없음")
        else:
            st.dataframe(_format_ui_table_values(df_wl[dc_wl], market), use_container_width=True, hide_index=True, height=220)


