def _ops_first_existing_path(paths: list[Path]) -> Path | None:
    for path in paths:
        try:
            if path.exists() and path.stat().st_size > 0:
                return path
        except Exception:
            continue
    return None


def _ops_read_csv(paths: list[Path]) -> tuple[pd.DataFrame, Path | None]:
    path = _ops_first_existing_path(paths)
    if path is None:
        return pd.DataFrame(), None
    try:
        return read_csv_cached(path, dtype_str=True).fillna(""), path
    except Exception:
        return pd.DataFrame(), path


def _ops_read_json(paths: list[Path]) -> tuple[dict[str, Any], Path | None]:
    path = _ops_first_existing_path(paths)
    if path is None:
        return {}, None
    try:
        data = read_json_cached(path)
        return data if isinstance(data, dict) else {}, path
    except Exception:
        return {}, path


def _ops_num(value: Any, default: float = float("nan")) -> float:
    try:
        text = str(value if value is not None else "").strip()
        text = text.replace(",", "").replace("%", "").replace("$", "").replace("원", "")
        if not text or text.lower() in {"nan", "none", "n/a", "na"}:
            return default
        return float(text)
    except Exception:
        return default


def _ops_pick_col(df: pd.DataFrame, names: list[str]) -> str | None:
    if df is None or df.empty:
        return None
    for name in names:
        if name in df.columns:
            return name
    return None


def _ops_market_match(series: pd.Series, market: str) -> pd.Series:
    text = series.astype(str)
    if market == "한국주식":
        return text.isin(["한국주식", "국장", "KR", "Korea", "KOSPI", "KOSDAQ"])
    if market == "미국주식":
        return text.isin(["미국주식", "미장", "US", "USA"])
    return pd.Series(True, index=series.index)


def _ops_latest_rows(df: pd.DataFrame) -> pd.DataFrame:
    if df is None or df.empty:
        return pd.DataFrame()
    date_col = _ops_pick_col(df, ["target_date", "목표일", "prediction_date", "date"])
    if not date_col:
        return df.tail(80).copy()
    work = df.copy()
    parsed = pd.to_datetime(work[date_col], errors="coerce")
    if parsed.notna().any():
        latest = parsed.max()
        return work[parsed.eq(latest)].copy()
    return work.tail(80).copy()


def _ops_final_decision(row: pd.Series) -> str:
    raw = ""
    for col in [
        "risk_final_decision",
        "final_decision_after_no_buy_filter",
        "final_decision_after_market_filter",
        "final_decision_after_adjustment",
        "final_decision",
        "최종판단",
    ]:
        if col in row.index and str(row.get(col, "")).strip():
            raw = str(row.get(col, "")).strip()
            break
    try:
        from core.standard_score_engine import FINAL_JUDGMENTS, normalize_final_judgment

        if raw in FINAL_JUDGMENTS:
            return raw
        score = _ops_num(row.get("standard_total_score", row.get("total_score", row.get("score", 60))), 60)
        return normalize_final_judgment(score, row=row)
    except Exception:
        if any(k in raw for k in ["손절", "이탈"]):
            return "손절 우선"
        if any(k in raw for k in ["축소", "금지", "리스크"]):
            return "비중 축소 우선"
        if any(k in raw for k in ["돌파"]):
            return "돌파 확인 후 접근"
        if any(k in raw for k in ["눌림", "매수"]):
            return "눌림목 매수 가능"
        return "관망 우위"


def _ops_confidence(row: pd.Series) -> float:
    for col in [
        "confidence_score_after_no_buy_filter",
        "confidence_score_after_market_filter",
        "confidence_score_after_adjustment",
        "confidence_score",
        "신뢰도",
    ]:
        if col in row.index:
            val = _ops_num(row.get(col), float("nan"))
            if not pd.isna(val):
                return val
    return 0.0


def _ops_rr(row: pd.Series) -> float:
    entry = _ops_num(row.get("preferred_entry", row.get("buy_price", "")), float("nan"))
    stop = _ops_num(row.get("stop_loss", ""), float("nan"))
    tp1 = _ops_num(row.get("take_profit1", row.get("target_price", "")), float("nan"))
    if pd.isna(entry) or pd.isna(stop) or pd.isna(tp1) or entry <= stop:
        return 0.0
    return max(0.0, (tp1 - entry) / (entry - stop))


def _ops_top_reasons(df: pd.DataFrame, col: str, limit: int = 5) -> pd.DataFrame:
    if df is None or df.empty or col not in df.columns:
        return pd.DataFrame(columns=["사유", "건수"])
    reasons: list[str] = []
    for text in df[col].astype(str):
        for part in text.replace("|", "/").split("/"):
            item = part.strip()
            if item and item.lower() not in {"nan", "none"}:
                reasons.append(item)
    if not reasons:
        return pd.DataFrame(columns=["사유", "건수"])
    out = pd.Series(reasons).value_counts().head(limit).reset_index()
    out.columns = ["사유", "건수"]
    return out


def _ops_build_top3_candidates(pred_df: pd.DataFrame, no_buy_df: pd.DataFrame, portfolio_df: pd.DataFrame, market: str) -> pd.DataFrame:
    if pred_df is None or pred_df.empty:
        return pd.DataFrame()
    work = pred_df.copy()
    market_col = _ops_pick_col(work, ["market", "시장"])
    if market_col:
        work = work[_ops_market_match(work[market_col], market)].copy()
    work = _ops_latest_rows(work)
    if work.empty:
        return pd.DataFrame()

    work["final_decision_view"] = work.apply(_ops_final_decision, axis=1)
    work["confidence_score_view"] = work.apply(_ops_confidence, axis=1)
    work["rr_view"] = work.apply(_ops_rr, axis=1)
    if "no_buy_score" in work.columns:
        work["no_buy_score_view"] = pd.to_numeric(work["no_buy_score"].map(_ops_num), errors="coerce").fillna(50)
    else:
        work["no_buy_score_view"] = 50
    if "no_buy_level" not in work.columns:
        work["no_buy_level"] = ""
    if "data_status" not in work.columns:
        work["data_status"] = ""

    positive = work["final_decision_view"].isin(["눌림목 매수 가능", "돌파 확인 후 접근"])
    safe_level = ~work["no_buy_level"].astype(str).isin(["매수금지", "강한 매수금지", "데이터 부족"])
    data_ready = ~work["data_status"].astype(str).str.upper().eq("DATA_MISSING")
    work = work[positive & safe_level & data_ready].copy()
    if work.empty:
        return pd.DataFrame()

    ticker_col = _ops_pick_col(work, ["ticker", "symbol", "종목코드", "종목"])
    market_col = _ops_pick_col(work, ["market", "시장"])
    if not no_buy_df.empty and ticker_col:
        nb_ticker = _ops_pick_col(no_buy_df, ["ticker", "symbol", "종목코드", "종목"])
        if nb_ticker and "no_buy_level" in no_buy_df.columns:
            blocked = set(no_buy_df.loc[no_buy_df["no_buy_level"].astype(str).isin(["매수금지", "강한 매수금지"]), nb_ticker].astype(str))
            work = work[~work[ticker_col].astype(str).isin(blocked)].copy()
    if not portfolio_df.empty and ticker_col and "portfolio_action" in portfolio_df.columns:
        pf_ticker = _ops_pick_col(portfolio_df, ["ticker", "symbol", "종목코드", "종목"])
        if pf_ticker:
            bad_actions = ["손절 우선", "비중 축소 우선", "추가매수 금지", "데이터 부족"]
            blocked = set(portfolio_df.loc[portfolio_df["portfolio_action"].astype(str).isin(bad_actions), pf_ticker].astype(str))
            wait_data = set(portfolio_df.loc[portfolio_df.get("data_status", pd.Series("", index=portfolio_df.index)).astype(str).str.upper().eq("DATA_MISSING"), pf_ticker].astype(str))
            work = work[~work[ticker_col].astype(str).isin(blocked | wait_data)].copy()
    if work.empty:
        return pd.DataFrame()

    work = work.sort_values(["no_buy_score_view", "confidence_score_view", "rr_view"], ascending=[True, False, False])
    cols = [
        ticker_col, market_col, "final_decision_view", "confidence_score_view",
        "preferred_entry", "stop_loss", "take_profit1", "no_buy_level",
        "adjustment_reason", "market_filter_reason", "no_buy_reasons",
    ]
    cols = [c for c in cols if c and c in work.columns]
    out = work[cols].head(3).copy()
    rename = {
        ticker_col: "ticker",
        market_col: "market",
        "final_decision_view": "final_decision",
        "confidence_score_view": "confidence_score",
    }
    return out.rename(columns={k: v for k, v in rename.items() if k})


def _ops_new_buy_label(market_data: dict[str, Any], no_buy_df: pd.DataFrame, perf_df: pd.DataFrame) -> tuple[str, str]:
    risk = _ops_num(market_data.get("market_risk_score"), 50)
    allowed = market_data.get("new_buy_allowed", True)
    regime = str(market_data.get("market_regime", "")).strip()
    strong_no_buy = 0
    total_no_buy = 0
    if not no_buy_df.empty and "no_buy_level" in no_buy_df.columns:
        levels = no_buy_df["no_buy_level"].astype(str)
        total_no_buy = int(levels.isin(["주의", "관망 우위", "매수금지", "강한 매수금지"]).sum())
        strong_no_buy = int(levels.isin(["매수금지", "강한 매수금지"]).sum())
    judgment = ""
    if str(allowed).lower() in {"false", "0", "no"}:
        judgment = "신규매수 관망 우위"
    elif risk >= 80:
        judgment = "신규매수 원칙적 관망"
    elif risk >= 60:
        judgment = "신규매수 소액/분할만"
    elif regime == "강한 상승장" and strong_no_buy <= 2:
        judgment = "신규매수 조건부 가능"
    else:
        judgment = "신규매수 조건부 가능"
    reasons = []
    if risk >= 60:
        reasons.append(f"시장위험 {risk:.0f}")
    if strong_no_buy:
        reasons.append(f"매수금지 후보 {strong_no_buy}개")
    elif total_no_buy:
        reasons.append(f"주의 후보 {total_no_buy}개")
    if not perf_df.empty and "summary_judgment" in perf_df.columns:
        sj = str(perf_df["summary_judgment"].iloc[-1])
        if "악화" in sj or "데이터 부족" in sj:
            reasons.append(f"보정 성과 {sj}")
    if not reasons:
        reasons.append("저장 데이터 기준 큰 차단 요인 없음")
    return judgment, " / ".join(reasons)


def _ops_today_action_text(market_data: dict[str, Any], top3: pd.DataFrame, no_buy_df: pd.DataFrame, portfolio_df: pd.DataFrame) -> str:
    risk = _ops_num(market_data.get("market_risk_score"), 50)
    actions = portfolio_df["portfolio_action"].astype(str) if not portfolio_df.empty and "portfolio_action" in portfolio_df.columns else pd.Series(dtype=str)
    data_status = portfolio_df["data_status"].astype(str) if not portfolio_df.empty and "data_status" in portfolio_df.columns else pd.Series(dtype=str)
    strong_no_buy = 0
    if not no_buy_df.empty and "no_buy_level" in no_buy_df.columns:
        strong_no_buy = int(no_buy_df["no_buy_level"].astype(str).isin(["매수금지", "강한 매수금지"]).sum())
    items: list[str] = []
    if risk >= 80:
        items.append("오늘은 신규매수보다 보유종목 리스크 관리가 우선입니다.")
    elif risk >= 60:
        items.append("시장위험이 높아 신규매수는 관망 우위로 두고, 조건 충족 시 분할만 검토하세요.")
    elif not top3.empty:
        items.append("조건부 접근 가능하지만, 진입가는 우선진입가 근처에서만 검토하세요.")
    else:
        items.append("오늘 조건을 만족하는 신규 매수 후보가 제한적입니다.")
    if int(actions.eq("손절 우선").sum()):
        items.append("손절 기준 이탈 여부 확인 필요 종목을 먼저 확인하세요.")
    if int(actions.eq("비중 축소 우선").sum()):
        items.append("비중 축소 후보 확인이 필요합니다.")
    if int(actions.eq("익절 분할").sum()):
        items.append("익절 분할 후보를 확인하세요.")
    if strong_no_buy >= 5:
        items.append("매수금지 후보가 많아 신규매수는 신중하게 보세요.")
    if int(data_status.str.upper().eq("DATA_MISSING").sum()):
        items.append("일부 보유종목은 최신 예측 데이터가 없어 다음 예측 후 재확인이 필요합니다.")
    return " ".join(items)


def _ops_runner_status_summary() -> tuple[pd.DataFrame, str]:
    rows: list[dict[str, Any]] = []
    run_status, run_path = _ops_read_json(_PRACTICAL_DASHBOARD_RUN_STATUS_PATHS)
    if run_status:
        items = run_status.items() if all(isinstance(v, dict) for v in run_status.values()) else [("run_status", run_status)]
        for name, item in items:
            if isinstance(item, dict):
                rows.append({
                    "runner": name,
                    "status": item.get("status", item.get("result", "미확인")),
                    "exit_code": item.get("exit_code", ""),
                    "last_run_at": item.get("last_run_at", item.get("updated_at", "")),
                    "error_message": item.get("error_message", item.get("error", "")),
                })
    for path in [Path("runner_status_kr.json"), Path("runner_status_us.json")]:
        data, _ = _ops_read_json([path])
        if data:
            rows.append({
                "runner": path.stem,
                "status": data.get("status", data.get("result", "미확인")),
                "exit_code": data.get("exit_code", data.get("last_exit_code", "")),
                "last_run_at": data.get("updated_at", data.get("last_run_at", "")),
                "error_message": data.get("error", data.get("error_message", "")),
            })
    return pd.DataFrame(rows), str(run_path) if run_path else "미확인"


def _ops_runner_failure_mask(runner_df: pd.DataFrame) -> pd.Series:
    if runner_df is None or runner_df.empty:
        return pd.Series(dtype=bool)
    status = runner_df.get("status", pd.Series("", index=runner_df.index)).astype(str).str.strip().str.lower()
    status_failed = status.isin(["failed", "fail", "error"])
    exit_raw = runner_df.get("exit_code", pd.Series("", index=runner_df.index)).astype(str).str.strip()
    exit_num = pd.to_numeric(exit_raw, errors="coerce")
    exit_failed = exit_num.notna() & exit_num.ne(0)
    return status_failed | exit_failed


def _ops_recent_error_summary() -> tuple[int, str, str, pd.DataFrame]:
    paths = [Path("logs/error_log.csv"), Path("app_error_log.csv")]
    rows: list[dict[str, str]] = []
    critical = ("Traceback", "KeyError", "FileNotFoundError", "PermissionError", "ImportError", "UnicodeDecodeError", "JSONDecodeError")
    for path in paths:
        if not path.exists() or path.stat().st_size == 0:
            continue
        try:
            lines = path.read_text(encoding="utf-8", errors="replace").splitlines()[-80:]
        except Exception:
            continue
        for line in lines:
            if any(token in line for token in critical):
                parts = line.split(",")
                rows.append({
                    "file": str(path),
                    "time": parts[0] if parts else "",
                    "feature": parts[1] if len(parts) > 1 else "",
                    "message": line[:220],
                })
    df = pd.DataFrame(rows)
    if df.empty:
        return 0, "최근 치명 오류 없음", "", df
    last = df.iloc[-1]
    return len(df), str(last.get("time", "")), str(last.get("message", "")), df


def render_practical_operation_overview_v10040(market: str) -> None:
    """Saved-file-only first screen summary for daily operation."""
    market_data, market_path = _ops_read_json(_PRACTICAL_DASHBOARD_MARKET_PATHS)
    pred_df, pred_path = _ops_read_csv(_PRACTICAL_DASHBOARD_PREDICTION_PATHS)
    no_buy_df, no_buy_path = _ops_read_csv(_PRACTICAL_DASHBOARD_NO_BUY_PATHS)
    portfolio_df, portfolio_path = _ops_read_csv(_PRACTICAL_DASHBOARD_PORTFOLIO_PATHS)
    perf_df, perf_path = _ops_read_csv(_PRACTICAL_DASHBOARD_PERFORMANCE_PATHS)

    top3 = _ops_build_top3_candidates(pred_df, no_buy_df, portfolio_df, market)
    new_buy_label, new_buy_reason = _ops_new_buy_label(market_data, no_buy_df, perf_df)
    today_action = _ops_today_action_text(market_data, top3, no_buy_df, portfolio_df)
    runner_df, runner_source = _ops_runner_status_summary()
    error_count, error_time, error_msg, error_df = _ops_recent_error_summary()

    st.markdown("#### 실전 운용판")
    st.caption("저장된 CSV·JSON 기준 요약입니다. 첫 화면에서는 외부 API, yfinance, 뉴스, 현재가 전체조회가 자동 실행되지 않습니다.")

    market_regime = str(market_data.get("market_regime", "데이터 없음"))
    market_risk = _ops_num(market_data.get("market_risk_score"), float("nan"))
    risk_text = "미확인" if pd.isna(market_risk) else f"{market_risk:.0f} / 100"
    risk_level = str(market_data.get("risk_level", "미확인"))
    recommended = str(market_data.get("recommended_action", "시장상태 데이터가 아직 없습니다. runner_market_regime 실행 필요"))
    new_allowed = market_data.get("new_buy_allowed", "")
    new_allowed_text = "가능" if str(new_allowed).lower() in {"true", "1", "yes"} else "원칙적 관망" if str(new_allowed).lower() in {"false", "0", "no"} else "미확인"
    main_reasons = market_data.get("main_reasons", [])
    if isinstance(main_reasons, list):
        main_reasons_text = " / ".join(str(x) for x in main_reasons[:4]) or "미확인"
    else:
        main_reasons_text = str(main_reasons) or "미확인"

    nb_levels = no_buy_df["no_buy_level"].astype(str) if not no_buy_df.empty and "no_buy_level" in no_buy_df.columns else pd.Series(dtype=str)
    strong_nb = int(nb_levels.eq("강한 매수금지").sum()) if not nb_levels.empty else 0
    blocked_nb = int(nb_levels.isin(["매수금지", "강한 매수금지"]).sum()) if not nb_levels.empty else 0
    caution_nb = int(nb_levels.eq("주의").sum()) if not nb_levels.empty else 0

    pf_actions = portfolio_df["portfolio_action"].astype(str) if not portfolio_df.empty and "portfolio_action" in portfolio_df.columns else pd.Series(dtype=str)
    pf_status = portfolio_df["data_status"].astype(str) if not portfolio_df.empty and "data_status" in portfolio_df.columns else pd.Series(dtype=str)
    pf_missing = int(pf_status.str.upper().eq("DATA_MISSING").sum()) if not pf_status.empty else 0
    pf_total = int(len(portfolio_df))

    row1 = st.columns(4)
    with row1[0]:
        st.metric("오늘 시장상태", market_regime, risk_level)
        st.caption(f"시장위험 점수: {risk_text}")
        st.caption(f"신규매수: {new_allowed_text}")
        st.caption(f"주요 사유: {main_reasons_text}")
