def render_native_daily_plan_page() -> None:
    market = _native_page_market_selector("daily_plan")
    inject_native_graft_css()
    _render_inner_page_heading("오늘의 실행 플랜")
    log_df = _native_market_filtered_log(market)
    batch = _native_latest_prediction_batch(log_df, market)
    if batch.empty:
        _native_show_prediction_table(batch, market, "오늘의 실행 플랜")
        return
    target_label = str(batch[_native_target_col(batch)].iloc[0]) if _native_target_col(batch) else "최근 배치"
    try:
        render_final_judgment_strip(batch, market, target_label)
    except Exception:
        pass
    try:
        render_execution_plan_panel(batch, log_df, market)
    except Exception:
        _native_show_prediction_table(batch, market, "오늘의 실행 플랜")


def _native_target_label(batch: pd.DataFrame) -> str:
    if batch is None or batch.empty:
        return "최근 배치"
    tcol = _native_target_col(batch)
    if tcol and tcol in batch.columns:
        try:
            return str(batch[tcol].iloc[0])
        except Exception:
            return "최근 배치"
    return "최근 배치"


def _native_operation_defaults(market: str) -> dict[str, Any]:
    default_account = 10000.0 if market == "미국주식" else 10000000.0
    account_size = operation_setting_float("account_capital", default_account) if "operation_setting_float" in globals() else default_account
    available_cash = operation_setting_float("available_cash", account_size) if "operation_setting_float" in globals() else account_size
    risk_pct = operation_setting_float("risk_per_trade_pct", 0.7) if "operation_setting_float" in globals() else 0.7
    max_position_pct = operation_setting_float("max_position_pct", 20.0) if "operation_setting_float" in globals() else 20.0
    allow_fractional = operation_setting_bool("allow_fractional_shares", False) if "operation_setting_bool" in globals() else False
    return {
        "account_size": account_size,
        "available_cash": available_cash,
        "risk_pct": risk_pct,
        "max_position_pct": max_position_pct,
        "allow_fractional": allow_fractional,
    }


def _native_build_order_plan(batch: pd.DataFrame, log_df: pd.DataFrame, market: str) -> pd.DataFrame:
    if batch is None or batch.empty:
        return pd.DataFrame()
    cfg = _native_operation_defaults(market)
    try:
        return build_execution_plan_df(
            pending_df=batch,
            log_df=log_df,
            market=market,
            account_size=cfg["account_size"],
            available_cash=cfg["available_cash"],
            risk_pct=cfg["risk_pct"],
            max_position_pct=cfg["max_position_pct"],
            allow_fractional=cfg["allow_fractional"],
        )
    except Exception:
        return pd.DataFrame()


def _native_build_buy_action(batch: pd.DataFrame, log_df: pd.DataFrame, market: str) -> pd.DataFrame:
    if batch is None or batch.empty:
        return pd.DataFrame()
    try:
        return add_buy_action_columns(batch, log_df=log_df, market=market)
    except Exception:
        return pd.DataFrame()


def _native_watchlist_coverage_df(batch: pd.DataFrame, market: str) -> pd.DataFrame:
    wl = _native_watchlist_df(market)
    if wl is None or wl.empty or "symbol" not in wl.columns:
        return pd.DataFrame()
    pred_symbols: set[str] = set()
    if batch is not None and not batch.empty:
        tcol = _native_ticker_col(batch)
        if tcol:
            for x in batch[tcol].astype(str).tolist():
                pred_symbols.add(display_symbol(x, market) if market == "미국주식" else normalize_ticker(x, market))
    rows = []
    for _, r in wl.iterrows():
        sym = display_symbol(r.get("symbol", ""), market) if market == "미국주식" else normalize_ticker(r.get("symbol", ""), market)
        name = sym if market == "미국주식" else korean_name_from_symbol(sym, r.get("name", ""))
        rows.append({
            "종목": sym,
            "표시명": name,
            "테마": r.get("theme", ""),
            "분류": r.get("group", ""),
            "예측반영": "반영" if sym in pred_symbols else "미반영",
        })
    return pd.DataFrame(rows)



