def _native_clean_text(value: Any, default: str = "-") -> str:
    s = str(value if value is not None else "").strip()
    if not s or s.lower() in {"nan", "none", "nat"}:
        return default
    return s


def _native_num_from_label(value: Any, default: float = np.nan) -> float:
    try:
        v = parse_price_label(value)
        return v if not np.isnan(v) else default
    except Exception:
        return safe_float(value, default)


def _native_percent_from_label(value: Any, default: float = np.nan) -> float:
    s = str(value or "").replace("%", "").replace("+", "").replace(",", "").strip()
    try:
        return float(s)
    except Exception:
        return default


