def _strong_watch_empty_reason(df: pd.DataFrame, market: str) -> str:
    """강한 관찰 후보 빈 화면 사유 (필터/데이터/임계값/컬럼)."""
    if df is None or df.empty:
        path = swing_scan_paths(market).get("all", "")
        return f"데이터 부족으로 후보 산출 불가 — 스윙 스캔 결과가 비어 있습니다. (`{path}`)"
    need = {"strong_watch_candidate", "weak_market_leader_flag"}
    missing = need - set(df.columns)
    if missing:
        return f"컬럼명 변경으로 필터 확인 필요 — 필요 컬럼 없음: {', '.join(sorted(missing))}"
    true_vals = {"true", "1", "1.0", "yes", "y"}
    sw = df["strong_watch_candidate"].astype(str).str.lower().isin(true_vals)
    wm = df["weak_market_leader_flag"].astype(str).str.lower().isin(true_vals)
    flagged = int((sw | wm).sum())
    if flagged == 0:
        sw_any = int(sw.sum())
        wm_any = int(wm.sum())
        if sw_any == 0 and wm_any == 0:
            return "strong_watch 조건 미충족 — 현재 시장 필터 기준 후보 없음"
        return "weak_market_leader_flag 조건 미충족 — 조건 충족 종목 없음"
    return "현재 시장 필터 기준 후보 없음 — 후보는 있으나 표시 조건에 맞는 행이 없습니다."


def _strong_watch_diagnostic_rows(df: pd.DataFrame, market: str) -> pd.DataFrame:
    true_vals = {"true", "1", "1.0", "yes", "y"}
    if df is None or df.empty:
        return pd.DataFrame([{"항목": "원본 rows", "값": 0}, {"항목": "사유", "값": _strong_watch_empty_reason(df, market)}])
    rows = [{"항목": "원본 rows", "값": int(len(df))}]
    for col in ("strong_watch_candidate", "weak_market_leader_flag"):
        if col in df.columns:
            n = int(df[col].astype(str).str.lower().isin(true_vals).sum())
            rows.append({"항목": f"{col}=True", "값": n})
        else:
            rows.append({"항목": f"{col} 컬럼", "값": "없음"})
    rows.append({"항목": "현재 사유", "값": _strong_watch_empty_reason(df, market)})
    return pd.DataFrame(rows)


def _swing_report_cache_sig(market: str) -> tuple[int, ...]:
    sig: list[int] = []
    paths = swing_scan_paths(market)
    for key in ("all", "a", "b", "c"):
        p = paths.get(key)
        if p and Path(p).exists():
            try:
                stt = Path(p).stat()
                sig.extend([int(stt.st_mtime_ns), int(stt.st_size)])
            except Exception:
                sig.append(0)
    sig.extend(_display_price_cache_sig(market))
    return tuple(sig)


def _filter_supported_display_rows(work: pd.DataFrame) -> tuple[pd.DataFrame, int]:
    """지원 종목만 우선 표시. 전부 걸러지면 원본을 유지해 부분 표시."""
    if work is None or work.empty:
        return pd.DataFrame(), 0
    mask = work.apply(_is_supported_stock_display_row, axis=1)
    filtered = work.loc[mask].copy()
    skipped = int((~mask).sum())
    if filtered.empty:
        return work.copy(), skipped
    return filtered, skipped


def _sort_buy_decision_candidate_frame(work: pd.DataFrame) -> pd.DataFrame:
    if work is None or work.empty:
        return pd.DataFrame()
    out = work.copy()
    if "score" in out.columns:
        out["_rank"] = pd.to_numeric(out["score"], errors="coerce").fillna(0)
        return out.sort_values("_rank", ascending=False)
    if "prob_up_5d" in out.columns:
        out["_rank"] = pd.to_numeric(out["prob_up_5d"], errors="coerce").fillna(0)
        return out.sort_values("_rank", ascending=False)
    out["_rank"] = range(len(out), 0, -1)
    return out.sort_values("_rank", ascending=False)


def _buy_decision_rank_row_from_series(row: pd.Series, market: str, rank: int) -> dict[str, Any]:
    mkt = str(row.get("market", market) or market)
    symbol = _candidate_display_symbol(
        _candidate_pick_display_value(row, ("symbol", "ticker", "code", "종목코드"), ""),
        mkt,
    )
    name = _candidate_pick_display_value(
        row,
        ("종목명", "name", "stock_name", "company_name", "display_name", "ticker", "symbol", "code", "종목코드"),
        symbol or "-",
    )
    stop_risk = _format_prob_percent_cell(row.get("prob_stop_5d", ""))
    exp_ret = _format_prob_percent_cell(row.get("expected_return_5d", row.get("prob_up_5d", "")))
    judgment = str(
        row.get(
            "risk_final_decision",
            row.get("final_judgment", row.get("final_decision_after_no_buy_filter", "-")),
        )
        or "-"
    )
    return {
        "순위": rank,
        "종목명": name,
        "종목코드": symbol or name,
        "시장": mkt,
        "현재가": _format_price_or_reason(row, "current_price", mkt, "현재가 미수신"),
        "가격상태": _candidate_pick_display_value(row, ("price_data_status", "데이터 상태"), "가격 기준 미산출"),
        "관찰 기준가": _format_price_or_reason(row, "basis_price", mkt, "가격 기준 미산출"),
        "매수가": _format_price_or_reason(row, "preferred_entry", mkt, "가격 기준 미산출"),
        "손절가": _format_price_or_reason(row, "stop_loss", mkt, "가격 기준 미산출"),
        "목표가": _format_price_or_reason(row, "take_profit1", mkt, "가격 기준 미산출"),
        "2차 목표가": _format_price_or_reason(row, "take_profit2", mkt, "가격 기준 미산출"),
        "손익비": _candidate_pick_display_value(row, ("rr", "손익비", "risk_reward", "active_scenario_risk_reward"), "가격 기준 미산출"),
        "현재가와 매수가 차이": _format_pct_or_reason(row.get("entry_gap_pct"), "가격 데이터 부족"),
        "목표가까지 여력": _format_pct_or_reason(row.get("target_upside_pct"), "예측값 없음"),
        "손절가까지 거리": _format_pct_or_reason(row.get("stop_distance_pct"), "예측값 없음"),
        "기대수익률": exp_ret,
        "손절위험": stop_risk,
        "최종 판단": judgment,
        "권장 조치": _action_from_row(row),
        "핵심 이유": str(
            row.get("display_group", row.get("candidate_group", row.get("future_probability_status", "-")))
            or "-"
        ),
    }


def _build_buy_decision_display_table(work: pd.DataFrame, market: str, *, limit: int = 80) -> pd.DataFrame:
    """종목 랭킹/매수 판단 표 — 행 단위 실패 시에도 가능한 만큼 채움."""
    if work is None or work.empty:
        return pd.DataFrame()
    work = _sort_buy_decision_candidate_frame(work)
    rows: list[dict[str, Any]] = []
    for i, (_, row) in enumerate(work.head(limit).iterrows(), start=1):
        try:
            rows.append(_buy_decision_rank_row_from_series(row, market, i))
        except Exception:
            sym = str(row.get("symbol", row.get("name", "-")) or "-")
            rows.append({
                "순위": i,
                "종목명": sym,
                "종목코드": sym,
                "시장": market,
                "현재가": "데이터 부족",
                "가격상태": "가격 기준 미산출",
                "관찰 기준가": "가격 기준 미산출",
                "매수가": "가격 기준 미산출",
                "손절가": "가격 기준 미산출",
                "목표가": "가격 기준 미산출",
                "2차 목표가": "가격 기준 미산출",
                "손익비": "가격 기준 미산출",
                "현재가와 매수가 차이": "가격 데이터 부족",
                "목표가까지 여력": "예측값 없음",
                "손절가까지 거리": "예측값 없음",
                "기대수익률": "-",
                "손절위험": "-",
                "최종 판단": "-",
                "권장 조치": "-",
                "핵심 이유": "데이터 부족",
            })
    return pd.DataFrame(rows)


def _build_buy_decision_display_table_partial(market: str, *, limit: int = 30) -> pd.DataFrame:
    """캐시/병합 실패 시 원본 후보 CSV에서 부분 표만 구성."""
    try:
        candidates = _load_swing_candidate_reports(market)
    except Exception:
        return pd.DataFrame()
    if candidates is None or candidates.empty:
        return pd.DataFrame()
    work, _ = _filter_supported_display_rows(candidates.copy())
    return _build_buy_decision_display_table(work, market, limit=limit)


@st.cache_data(ttl=120, show_spinner=False)
def _cached_buy_decision_display_table(market: str, cache_sig: tuple[int, ...]) -> pd.DataFrame:
    """매수 판단 화면용 — 저장된 스윙 리포트만 표시 (예측 파이프라인 미호출)."""
    _ = cache_sig
    candidates = _load_swing_candidate_reports(market)
    if candidates is None or candidates.empty:
        return pd.DataFrame()
    try:
        work = enrich_display_price_frame(candidates.copy(), market)
    except Exception:
        work = candidates.copy()
    work, _ = _filter_supported_display_rows(work)
    return _build_buy_decision_display_table(work, market)


