def render_native_symbol_search_chart_page() -> None:
    """워치리스트 밖 종목도 직접 검색해서 현재 차트를 확인하는 화면.
    - 미장: NVDA/TSLA/PLTR 등 티커 입력
    - 국장: 005930 또는 삼성전자 같은 종목명 입력 가능
    - 데이터는 기존 load_stock_data/normalize_ticker/display_symbol 흐름을 사용하므로 KIS 연결이 있으면 기존 우선순위를 따른다.
    """
    fallback_market = _effective_nav_market("symbol_search_chart")
    inject_native_graft_css()
    _render_inner_page_heading("종목 검색 / 현재 차트")
    st.caption(
        "watchlist에 없는 종목도 티커 또는 종목명으로 검색해 차트만 확인합니다. "
        "관심종목에 자동 추가하지 않으며 예측 기록에도 저장하지 않습니다."
    )

    ex_text = "예: NVDA, TSLA, PLTR" if fallback_market == "미국주식" else "예: 삼성전자, 005930, SK하이닉스, 000660"
    c1, c2, c3 = st.columns([1.55, 0.85, 0.85])
    with c1:
        query = st.text_input("종목명/티커 입력", value="", placeholder=ex_text, key=f"native_symbol_search_input_{fallback_market}")
    with c2:
        period_label = st.selectbox("조회 기간", ["3개월", "6개월", "1년", "2년", "5년"], index=2, key=f"native_symbol_search_period_{fallback_market}")
    with c3:
        candle_mode = st.selectbox("차트 기준", ["일봉", "주봉", "월봉"], index=0, key=f"native_symbol_search_interval_{fallback_market}")

    if not str(query or "").strip():
        st.info("검색할 종목명 또는 티커를 입력하세요.")
        return

    raw_query = str(query).strip()
    market = _infer_symbol_search_market(raw_query, fallback_market)
    if market == "한국주식":
        ticker = normalize_ticker(korean_symbol_from_name(raw_query), market)
        title_symbol = korean_name_from_symbol(ticker, raw_query)
    else:
        ticker = display_symbol(raw_query, "미국주식")
        title_symbol = ticker

    years_map = {"3개월": 0.25, "6개월": 0.5, "1년": 1.0, "2년": 2.0, "5년": 5.0}
    years = years_map.get(period_label, 1.0)

    with st.spinner(f"{title_symbol} 차트 불러오는 중..."):
        df = _load_stock_data_for_chart_cached(ticker, market, years)

    if df is None or df.empty or len(df) < 5:
        st.warning(f"{raw_query} 데이터를 불러오지 못했습니다. 티커/종목명을 확인하세요.")
        st.caption("차트 데이터 없음 — 다른 기간·종목으로 다시 시도해 주세요.")
        return

    try:
        df = calculate_indicators(df)
    except Exception:
        pass

    plot_df = df.copy()
    if candle_mode == "주봉":
        plot_df = plot_df.set_index(pd.to_datetime(plot_df["Date"])).resample("W-FRI").agg({"Open":"first", "High":"max", "Low":"min", "Close":"last", "Volume":"sum"}).dropna().reset_index().rename(columns={"index":"Date"})
        try: plot_df = calculate_indicators(plot_df)
        except Exception: pass
    elif candle_mode == "월봉":
        plot_df = plot_df.set_index(pd.to_datetime(plot_df["Date"])).resample("M").agg({"Open":"first", "High":"max", "Low":"min", "Close":"last", "Volume":"sum"}).dropna().reset_index().rename(columns={"index":"Date"})
        try: plot_df = calculate_indicators(plot_df)
        except Exception: pass

    last = plot_df.iloc[-1]
    prev_close = safe_float(plot_df.iloc[-2].get("Close"), safe_float(last.get("Close"))) if len(plot_df) >= 2 else safe_float(last.get("Close"))
    cur = safe_float(last.get("Close"), np.nan)
    chg = (cur / prev_close - 1) * 100 if prev_close and not np.isnan(cur) else np.nan

    m1, m2, m3, m4 = st.columns(4)
    m1.metric("조회 종목", title_symbol)
    m2.metric("최근 종가", fmt_price(cur, market), pct(chg) if not np.isnan(chg) else "-")
    m3.metric("RSI", f"{safe_float(last.get('RSI'), np.nan):.1f}" if not np.isnan(safe_float(last.get('RSI'), np.nan)) else "-")
    m4.metric("거래량배율", f"{safe_float(last.get('VOL_RATIO'), np.nan):.2f}배" if not np.isnan(safe_float(last.get('VOL_RATIO'), np.nan)) else "-")

    fig = go.Figure()
    fig.add_trace(go.Candlestick(
        x=plot_df["Date"], open=plot_df["Open"], high=plot_df["High"], low=plot_df["Low"], close=plot_df["Close"],
        name=str(ticker),
        increasing_line_color="#ef5350", decreasing_line_color="#26a69a",
    ))
    for ma in ["MA10", "MA20", "MA60", "MA120", "MA200"]:
        if ma in plot_df.columns:
            fig.add_trace(go.Scatter(x=plot_df["Date"], y=plot_df[ma], mode="lines", name=ma, line=dict(width=1.15)))
    fig.update_layout(
        title=dict(text=f"{title_symbol} · {period_label} · {candle_mode}", x=0.01, xanchor="left", y=0.98, yanchor="top"),
        template="plotly_dark", height=580,
        margin=dict(l=10, r=34, t=92, b=26), xaxis=dict(rangeslider=dict(visible=False), automargin=True), yaxis=dict(side="right", automargin=True),
        legend=dict(orientation="h", yanchor="bottom", y=1.05, xanchor="left", x=0),
    )
    st.plotly_chart(fig, use_container_width=True, config={"displayModeBar": False, "scrollZoom": False})
    render_chart_trade_levels_box(ticker, market, df)

    with st.expander("정규장 검증 기준", expanded=False):
        st.markdown("""
- 이 검색 차트는 조회용입니다. 예측 검증값은 별도 마감 업데이트에서 채웁니다.
- 미장·국장 모두 실제 검증값은 **정규장 일봉 OHLC** 기준입니다.
- 애프터마켓, 시간외 단일가, 24시간 거래 가격은 예측 성공률/오차율 계산에 섞지 않습니다.
""")



