def _read_error_review_csv(path: Path) -> pd.DataFrame:
    try:
        if not path.exists() or path.stat().st_size == 0:
            return pd.DataFrame()
        return read_csv_cached(path, dtype_str=True).fillna("")
    except Exception as exc:
        st.warning(f"{path.name} 파일을 읽지 못했습니다: {exc}")
        return pd.DataFrame()


def _review_learning_frame(limit: int | None = None) -> pd.DataFrame:
    try:
        from core.review_learning_engine import enrich_predictions_with_review

        df = load_prediction_log()
        if df.empty:
            return pd.DataFrame()
        if limit and len(df) > limit:
            df = df.tail(limit).copy()
        return enrich_predictions_with_review(df)
    except Exception as exc:
        try:
            log_app_event("review_learning", "warning", f"review frame build skipped: {exc}")
        except Exception:
            pass
        return pd.DataFrame()


def render_review_strategy_summary_card() -> None:
    try:
        from core.strategy_performance_engine import summarize_decision_performance

        df = _review_learning_frame(limit=500)
        if df.empty:
            st.info("복기 기반 전략 성과 데이터가 아직 부족합니다.")
            return
        reviewed = df[df.get("prediction_result", "").astype(str).ne("not_enough_data")].copy()
        perf = summarize_decision_performance(df)
        done_count = int(len(reviewed))
        pullback_rate = "-"
        breakout_rate = "-"
        wait_rate = "-"
        top_reason = "-"
        if not perf.empty:
            def _rate_for(decision: str) -> str:
                row = perf[perf["risk_final_decision"].astype(str).eq(decision)]
                if row.empty:
                    return "-"
                return f"{float(row.iloc[0].get('success_rate', 0)):.1f}%"

            pullback_rate = _rate_for("눌림목 매수 가능")
            breakout_rate = _rate_for("돌파 확인 후 접근")
            wait_rate = _rate_for("관망 우위")
        if "failure_reason" in df.columns:
            fail = df[df.get("prediction_result", "").astype(str).eq("fail")]
            if not fail.empty:
                reasons = fail["failure_reason"].astype(str)
                reasons = reasons[~reasons.isin(["", "정상 범위", "중립"])]
                if not reasons.empty:
                    top_reason = str(reasons.value_counts().index[0])
        cols = st.columns(5)
        cols[0].metric("최근 복기 완료", done_count)
        cols[1].metric("눌림목 성공률", pullback_rate)
        cols[2].metric("돌파 성공률", breakout_rate)
        cols[3].metric("관망 손실회피", wait_rate)
        cols[4].metric("최다 실패 이유", top_reason)
    except Exception as exc:
        st.caption(f"복기 기반 전략 성과 요약을 표시하지 못했습니다: {str(exc)[:120]}")


def render_review_strategy_performance_section(expanded: bool = False) -> None:
    with st.expander("복기 기반 전략 성과", expanded=expanded):
        try:
            from core.strategy_performance_engine import (
                generate_strategy_adjustment_notes,
                summarize_decision_performance,
                summarize_regime_performance,
            )
            from core.performance_penalty_engine import build_failure_profile

            df = _review_learning_frame()
            if df.empty:
                st.info("아직 복기 기반 전략 성과를 계산할 predictions.csv 데이터가 부족합니다.")
                return
            decision_perf = summarize_decision_performance(df)
            regime_perf = summarize_regime_performance(df)
            notes = generate_strategy_adjustment_notes(df)
            failure_profile = build_failure_profile(df)

            st.markdown("##### 요약")
            render_review_strategy_summary_card()

            tabs = st.tabs(["판단별 성과", "시장국면별 성과", "실패 이유 TOP5", "자동 감점", "전략 조정 노트", "최근 30개 복기"])
            with tabs[0]:
                if decision_perf.empty:
                    st.info("판단별 성과 데이터가 아직 부족합니다.")
                else:
                    st.dataframe(decision_perf, use_container_width=True, hide_index=True)
            with tabs[1]:
                if regime_perf.empty:
                    st.info("시장국면별 성과 데이터가 아직 부족합니다.")
                else:
                    st.dataframe(regime_perf, use_container_width=True, hide_index=True)
            with tabs[2]:
                if "failure_reason" not in df.columns:
                    st.info("failure_reason 컬럼이 아직 없습니다.")
                else:
                    fail = df[df.get("prediction_result", "").astype(str).eq("fail")]
                    reasons = fail["failure_reason"].astype(str) if not fail.empty else pd.Series(dtype=str)
                    reasons = reasons[~reasons.isin(["", "정상 범위", "중립"])]
                    if reasons.empty:
                        st.success("최근 복기 기준 뚜렷한 실패 이유가 아직 없습니다.")
                    else:
                        top = reasons.value_counts().head(5).reset_index()
                        top.columns = ["failure_reason", "count"]
                        st.dataframe(top, use_container_width=True, hide_index=True)
            with tabs[3]:
                high_risk = failure_profile.get("high_risk_conditions", {})
                risk_rows = []
                for key, stat in high_risk.items():
                    risk_rows.append({
                        "condition": stat.get("label", key),
                        "reviewed": stat.get("reviewed", 0),
                        "fail_count": stat.get("fail_count", 0),
                        "fail_rate": stat.get("fail_rate", 0),
                        "strong_penalty": stat.get("strong_penalty", False),
                    })
                risk_df = pd.DataFrame(risk_rows)
                if risk_df.empty:
                    st.info("최근 실패율 높은 조건을 계산할 복기 데이터가 아직 부족합니다.")
                else:
                    risk_df = risk_df.sort_values(["strong_penalty", "fail_rate", "reviewed"], ascending=[False, False, False]).head(8)
                    st.markdown("##### 최근 실패율 높은 조건 TOP")
                    st.dataframe(risk_df, use_container_width=True, hide_index=True)

                penalty_notes = failure_profile.get("penalty_notes", [])
                st.markdown("##### 자동 감점 적용 조건")
                if penalty_notes:
                    for note in penalty_notes[:8]:
                        st.info(note)
                else:
                    st.caption("최근 복기 기준으로 강한 자동 감점 조건은 아직 없습니다.")

                penalty_count = 0
                for path in (REPORT_DIR / "swing_candidates_us.csv", REPORT_DIR / "swing_candidates_kr.csv"):
                    try:
                        if path.exists() and path.stat().st_size > 0:
                            scan_df = pd.read_csv(path)
                            if "performance_penalty_score" in scan_df.columns:
                                penalty_count += int(pd.to_numeric(scan_df["performance_penalty_score"], errors="coerce").fillna(0).lt(0).sum())
                    except Exception:
                        continue
                st.metric("감점 적용 후보 수", penalty_count)
            with tabs[4]:
                for note in notes:
                    st.info(note)
            with tabs[5]:
                work = df.copy()
                if "created_at" in work.columns:
                    work["_created_at_sort"] = pd.to_datetime(work["created_at"], errors="coerce")
                    work = work.sort_values("_created_at_sort", ascending=False)
                elif "target_date" in work.columns:
                    work = work.sort_values("target_date", ascending=False)
                show_cols = [
                    "target_date", "market", "ticker", "risk_final_decision",
                    "prediction_result", "decision_success", "max_profit_pct", "max_drawdown_pct",
                    "entry_touched", "tp1_touched", "tp2_touched", "stop_touched",
                    "failure_reason", "review_tags",
                ]
                st.dataframe(work[[c for c in show_cols if c in work.columns]].head(30), use_container_width=True, hide_index=True)
        except Exception as exc:
            st.warning(f"복기 기반 전략 성과 표시 실패: {str(exc)[:160]}")


def render_prediction_error_review_page() -> None:
    """예측 실패 복기: 저장된 예측/실제값/모의매매 결과를 비교한 학습용 리포트."""
    from core.prediction_error_analysis import (
        MARKET_CONDITION_ERROR_SUMMARY,
        PREDICTION_ERROR_REPORT,
        TICKER_ERROR_PROFILE,
        run_error_analysis,
    )

    _render_inner_page_heading("예측 실패 복기", as_subheader=True)
    st.caption(PREDICTION_VALIDATION_HEADER)
    st.caption(
        "미래확률표에서 본 확률·가격 전망이 실제 장에서 어떻게 맞았는지 점검합니다. "
        "진입·관망·손절·익절 판단 유효성도 함께 봅니다. 예측 산출 로직은 변경하지 않습니다."
    )

    c1, c2 = st.columns([1, 3])
    with c1:
        if st.button("오차 분석 CSV 재생성", key="prediction_error_review_regenerate"):
            with st.spinner("예측 실패 복기 CSV를 생성하는 중입니다..."):
                res = run_error_analysis()
            st.success(
                "생성 완료: "
                f"복기 {res.get('report_rows', 0)}건 / "
                f"종목 프로필 {res.get('ticker_profile_rows', 0)}건 / "
                f"시장상태 요약 {res.get('market_summary_rows', 0)}건"
            )
    with c2:
        st.info(
            "`python app.py --runner error_analysis` 또는 "
            "`python runners/runner_error_analysis.py`로 같은 CSV를 갱신할 수 있습니다."
        )

    report = _read_error_review_csv(PREDICTION_ERROR_REPORT)
    profile = _read_error_review_csv(TICKER_ERROR_PROFILE)
    market_summary = _read_error_review_csv(MARKET_CONDITION_ERROR_SUMMARY)

    m1, m2, m3, m4 = st.columns(4)
    m1.metric("복기 대상", len(report))
    m2.metric("종목 프로필", len(profile))
    m3.metric("시장상태 요약", len(market_summary))
    if not report.empty and "failure_reason" in report.columns:
        fail_count = int((report["failure_reason"].astype(str) != "정상 범위").sum())
    else:
        fail_count = 0
    m4.metric("실패/개선 대상", fail_count)

    render_review_strategy_performance_section(expanded=False)

    if report.empty:
        st.warning("아직 예측 실패 복기 CSV가 없습니다. 위 버튼 또는 runner를 실행해 주세요.")
        return

    tabs = st.tabs([
        "예측 vs 실제 검증",
        "최근 20건 실패 사례",
        "종목별 오차 프로필",
        "시장상태별 실패 요약",
        "실패 원인 TOP5",
        "개선 제안",
    ])

    with tabs[0]:
        validation_df = prepare_prediction_validation_display(report, limit=80)
        if validation_df.empty:
            pred_log = load_prediction_log()
            validation_df = prepare_prediction_validation_display(pred_log, limit=80)
        if validation_df.empty:
            st.info(
                "아직 검증 가능한 실제 OHLC가 없습니다. 장 마감 후 실제값 업데이트를 실행한 뒤 "
                "「오차 분석 CSV 재생성」을 눌러 주세요."
            )
        else:
            st.caption("predictions.csv·prediction_error_report.csv 기준 — 미래확률표 예측가와 실제가 비교")
            st.dataframe(validation_df, use_container_width=True, hide_index=True)

    with tabs[1]:
        work = report.copy()
        if "failure_reason" in work.columns:
            work = work[work["failure_reason"].astype(str).ne("정상 범위")]
        if "target_date" in work.columns:
            work = work.sort_values("target_date", ascending=False)
        show_cols = [
            "target_date",
            "market",
            "ticker",
            "predicted_direction",
            "actual_direction",
            "direction_hit",
            "open_error_pct",
            "close_error_pct",
            "preferred_entry",
            "stop_loss",
            "take_profit1",
            "entry_touched",
            "stop_touched",
            "tp1_touched",
            "final_decision",
            "decision_result",
            "failure_reason",
            "suggested_adjustment",
        ]
        if work.empty:
            st.success("최근 복기 대상 중 뚜렷한 실패 사례가 없습니다.")
        else:
            st.dataframe(work[[c for c in show_cols if c in work.columns]].head(20), use_container_width=True, hide_index=True)

    with tabs[2]:
        if profile.empty:
            st.info("종목별 오차 프로필이 아직 없습니다.")
        else:
            st.dataframe(profile, use_container_width=True, hide_index=True)

    with tabs[3]:
        if market_summary.empty:
            st.info("시장상태별 실패 요약이 아직 없습니다.")
        else:
            st.dataframe(market_summary, use_container_width=True, hide_index=True)

    with tabs[4]:
        if "failure_reason" not in report.columns:
            st.info("failure_reason 컬럼이 없습니다.")
        else:
            reasons: list[str] = []
            for text in report["failure_reason"].astype(str):
                for part in text.split("/"):
                    reason = part.strip()
                    if reason and reason != "정상 범위":
                        reasons.append(reason)
            if not reasons:
                st.success("집계할 실패 원인이 없습니다.")
            else:
                top = pd.Series(reasons).value_counts().head(5).reset_index()
                top.columns = ["failure_reason", "count"]
                st.dataframe(top, use_container_width=True, hide_index=True)

    with tabs[5]:
        suggestions: list[str] = []
        for col in ["suggested_adjustment"]:
            if col in report.columns:
                for text in report[col].astype(str):
                    for part in text.split("/"):
                        item = part.strip()
                        if item and item != "현행 규칙 유지":
                            suggestions.append(item)
        if "recommended_rule_change" in market_summary.columns:
            for text in market_summary["recommended_rule_change"].astype(str):
                for part in text.split("/"):
                    item = part.strip()
                    if item and item != "현행 규칙 유지":
                        suggestions.append(item)
        if not suggestions:
            st.success("현재 표본 기준 추가 개선 제안이 없습니다.")
        else:
            sug = pd.Series(suggestions).value_counts().reset_index()
            sug.columns = ["개선 제안", "근거 건수"]
            st.dataframe(sug, use_container_width=True, hide_index=True)


def render_prediction_adjustment_page() -> None:
    """오차 프로필 기반 예측 보정값과 적용 결과."""
    from core.prediction_adjustment_engine import PREDICTION_ADJUSTMENTS, build_prediction_adjustments
    from core.prediction_error_analysis import PREDICTION_ERROR_REPORT

    _render_inner_page_heading("예측 보정", as_subheader=True)
    st.caption(PREDICTION_VALIDATION_HEADER)
    st.caption(
        "미래확률표·predictions.csv 예측가와 실제가 비교 결과를 바탕으로, "
        "저장 직전 후처리 보정값만 조정합니다. 예측 공식 자체는 변경하지 않습니다."
    )

    c1, c2 = st.columns([1, 3])
    with c1:
        if st.button("보정값 CSV 재생성", key="prediction_adjustment_regenerate"):
            with st.spinner("prediction_adjustments.csv 생성 중입니다..."):
                res = build_prediction_adjustments()
            st.success(f"생성 완료: {res.get('rows', 0)}건")
    with c2:
        if PREDICTION_ADJUSTMENTS.exists():
            st.info(f"최근 업데이트: {_file_mtime_kst(PREDICTION_ADJUSTMENTS)}")
        else:
            st.warning("prediction_adjustments.csv가 아직 없습니다. 위 버튼 또는 runner를 실행해 주세요.")

    adj = _read_error_review_csv(PREDICTION_ADJUSTMENTS)
    pred = load_prediction_log()

    m1, m2, m3, m4 = st.columns(4)
    m1.metric("보정 종목 수", len(adj))
    if not adj.empty and "confidence_penalty" in adj.columns:
        m2.metric("신뢰도 감점 대상", int((pd.to_numeric(adj["confidence_penalty"], errors="coerce").fillna(0) > 0).sum()))
    else:
        m2.metric("신뢰도 감점 대상", 0)
    if not adj.empty and "decision_downgrade" in adj.columns:
        m3.metric("판단 하향 대상", int((pd.to_numeric(adj["decision_downgrade"], errors="coerce").fillna(0) > 0).sum()))
    else:
        m3.metric("판단 하향 대상", 0)
    if not pred.empty and "adjustment_applied" in pred.columns:
        m4.metric("최근 예측 적용 행", int(pd.to_numeric(pred["adjustment_applied"], errors="coerce").fillna(0).sum()))
    else:
        m4.metric("최근 예측 적용 행", 0)
    if not adj.empty and "adjustment_reason" in adj.columns:
        weak_count = int(adj["adjustment_reason"].astype(str).str.contains("누적 데이터 부족|3건 미만", na=False, regex=True).sum())
        st.caption(f"누적 데이터 부족으로 보정 제외/약화된 종목: {weak_count}개")

    tabs = st.tabs([
        "예측 vs 실제 검증",
        "종목별 보정값",
        "보정 전/후 비교",
        "시장 필터 적용",
        "누적 데이터 부족",
        "보정 사유 TOP5",
    ])
    with tabs[0]:
        validation_df = prepare_prediction_validation_display(pred, limit=80)
        if validation_df.empty:
            err_report = _read_error_review_csv(PREDICTION_ERROR_REPORT)
            validation_df = prepare_prediction_validation_display(err_report, limit=80)
        if validation_df.empty:
            st.info("검증 표를 만들 실제 OHLC·예측 기록이 아직 없습니다.")
        else:
            st.caption("미래확률표와 동일한 predictions.csv 예측가 · 실제가 비교")
            st.dataframe(validation_df, use_container_width=True, hide_index=True)
    with tabs[1]:
        if adj.empty:
            st.info("표시할 보정값이 없습니다. 누적 복기 데이터가 쌓인 뒤 생성됩니다.")
        else:
            show_cols = [
                "market", "ticker", "total_cases", "direction_hit_rate", "avg_open_error_pct",
                "avg_close_error_pct", "entry_touch_rate", "stop_touch_rate", "tp1_touch_rate",
                "open_bias_adjustment_pct", "close_bias_adjustment_pct", "atr_multiplier_adjustment", "entry_adjustment_pct",
                "stop_adjustment_pct", "tp_adjustment_pct", "confidence_penalty", "decision_downgrade",
                "adjustment_reason", "updated_at",
            ]
            st.dataframe(adj[[c for c in show_cols if c in adj.columns]], use_container_width=True, hide_index=True)

    with tabs[2]:
        if pred.empty:
            st.info("예측 기록이 없습니다.")
        elif "adjustment_applied" not in pred.columns:
            st.info("아직 보정 적용 이후 저장된 예측 행이 없습니다.")
        else:
            applied = pred[pd.to_numeric(pred["adjustment_applied"], errors="coerce").fillna(0) > 0].copy()
            if applied.empty:
                st.info("보정 적용 행이 없습니다. 보정값 생성 후 다음 예측 runner부터 반영됩니다.")
            else:
                if "created_at" in applied.columns:
                    applied["_created_dt"] = pd.to_datetime(applied["created_at"], errors="coerce")
                    applied = applied.sort_values("_created_dt", ascending=False)
                show_cols = [
                    "created_at", "target_date", "market", "ticker", "pred_open_mid", "pred_close_mid",
                    "preferred_entry", "stop_loss", "take_profit1", "confidence_score",
                    "confidence_score_before_adjustment", "confidence_score_after_adjustment",
                    "open_bias_adjustment_pct", "close_bias_adjustment_pct", "entry_adjustment_pct",
                    "stop_adjustment_pct", "tp_adjustment_pct", "confidence_penalty",
                    "decision_downgrade", "final_decision_before_adjustment",
                    "final_decision_after_adjustment", "adjustment_reason",
                ]
                st.dataframe(applied[[c for c in show_cols if c in applied.columns]].head(50), use_container_width=True, hide_index=True)

    with tabs[3]:
        if pred.empty:
            st.info("예측 기록이 없습니다.")
        elif "market_filter_applied" not in pred.columns:
            st.info("아직 시장 필터 적용 이후 저장된 예측 행이 없습니다.")
        else:
            work = pred.copy()
            if "created_at" in work.columns:
                work["_created_dt"] = pd.to_datetime(work["created_at"], errors="coerce")
                work = work.sort_values("_created_dt", ascending=False)
            show_cols = [
                "created_at", "target_date", "ticker", "market", "market_regime", "market_risk_score",
                "market_filter_applied", "final_decision_before_market_filter",
                "final_decision_after_market_filter", "confidence_score_before_market_filter",
                "confidence_score_after_market_filter", "market_filter_reason",
            ]
            st.dataframe(work[[c for c in show_cols if c in work.columns]].head(80), use_container_width=True, hide_index=True)

    with tabs[4]:
        if adj.empty:
            st.info("보정값 파일이 없어 데이터 부족 여부를 판단할 수 없습니다.")
        elif "total_cases" not in adj.columns:
            st.info("total_cases 컬럼이 없습니다.")
        else:
            weak = adj[pd.to_numeric(adj["total_cases"], errors="coerce").fillna(0) < 3]
            if weak.empty:
                st.success("누적 데이터 3건 미만 종목은 없습니다.")
            else:
                st.info("아래 종목은 누적 데이터 부족으로 보정하지 않거나 약하게만 적용합니다.")
                st.dataframe(weak, use_container_width=True, hide_index=True)

    with tabs[5]:
        if adj.empty or "adjustment_reason" not in adj.columns:
            st.info("보정 사유를 집계할 데이터가 없습니다.")
        else:
            reasons: list[str] = []
            for text in adj["adjustment_reason"].astype(str):
                for part in text.split("/"):
                    item = part.strip()
                    if item:
                        reasons.append(item)
            if not reasons:
                st.info("보정 사유가 없습니다.")
            else:
                top = pd.Series(reasons).value_counts().head(5).reset_index()
                top.columns = ["보정 사유", "건수"]
                st.dataframe(top, use_container_width=True, hide_index=True)


def render_adjustment_performance_page() -> None:
    """보정 전/후 및 시장 필터 적용 후 성과 비교."""
    from core.adjustment_performance_engine import (
        BY_REGIME_FILE,
        BY_TICKER_FILE,
        REPORT_FILE,
        SUMMARY_FILE,
        run_adjustment_performance,
    )

    _render_inner_page_heading("보정 성과", as_subheader=True)
    st.caption(PREDICTION_VALIDATION_HEADER)
    st.caption(
        "미래확률표·predictions.csv의 예측가를 실제 OHLC와 비교한 뒤, "
        "보정 전·보정 후·시장 필터 후 판단의 성과 차이를 요약합니다."
    )

    c1, c2 = st.columns([1, 3])
    with c1:
        if st.button("성과 리포트 재생성", key="adjustment_performance_regenerate"):
            with st.spinner("보정 성과 CSV 생성 중입니다..."):
                res = run_adjustment_performance()
            st.success(f"생성 완료: {res.get('report_rows', 0)}건")
    with c2:
        if SUMMARY_FILE.exists():
            st.info(f"최근 업데이트: {_file_mtime_kst(SUMMARY_FILE)}")
        else:
            st.warning("adjustment_performance_summary.csv가 아직 없습니다. 위 버튼 또는 runner를 실행해 주세요.")

    report = _read_error_review_csv(REPORT_FILE)
    summary = _read_error_review_csv(SUMMARY_FILE)
    by_ticker = _read_error_review_csv(BY_TICKER_FILE)
    by_regime = _read_error_review_csv(BY_REGIME_FILE)

    if summary.empty:
        st.info("아직 성과 비교에 필요한 데이터가 부족합니다.")
    else:
        row = summary.iloc[0].to_dict()
        metrics = st.columns(5)
        metrics[0].metric("전체 케이스", row.get("total_cases", "0"))
        metrics[1].metric("보정 전 방향 적중률", row.get("raw_direction_hit_rate", "-"))
        metrics[2].metric("보정 후 방향 적중률", row.get("adjusted_direction_hit_rate", "-"))
        metrics[3].metric("시장필터 후 적중률", row.get("market_filtered_direction_hit_rate", "-"))
        metrics[4].metric("판정", row.get("summary_judgment", "데이터 부족"))

        metrics2 = st.columns(5)
        metrics2[0].metric("보정 전 평균 손익률", row.get("raw_avg_pnl_pct", "-"))
        metrics2[1].metric("보정 후 평균 손익률", row.get("adjusted_avg_pnl_pct", "-"))
        metrics2[2].metric("시장필터 후 손익률", row.get("market_filtered_avg_pnl_pct", "-"))
        metrics2[3].metric("손실 회피", row.get("loss_avoided_cases", "0"))
        metrics2[4].metric("기회 손실", row.get("missed_opportunity_cases", "0"))

    tabs = st.tabs(["최근 비교", "종목별 TOP", "악화 종목", "시장상태별 성과", "전체 요약"])
    with tabs[0]:
        if report.empty:
            st.info("아직 성과 비교에 필요한 실제 OHLC 데이터가 부족합니다.")
        else:
            work = report.copy()
