def render_no_buy_filter_page() -> None:
    """매수금지/강제 관망 위험 후보 요약."""
    from core.no_buy_filter_engine import NO_BUY_SUMMARY, save_no_buy_summary

    _render_inner_page_heading("매수금지 필터", as_subheader=True)
    st.caption("예측·보정·시장필터 이후 위험 조건이 강한 후보를 관망/매수금지 쪽으로 낮추는 후처리 필터입니다.")

    c1, c2 = st.columns([1, 3])
    with c1:
        if st.button("매수금지 요약 재생성", key="no_buy_filter_regenerate"):
            with st.spinner("no_buy_filter_summary.csv 생성 중입니다..."):
                res = save_no_buy_summary()
            st.success(f"생성 완료: {res.get('rows', 0)}건")
    with c2:
        if NO_BUY_SUMMARY.exists():
            st.info(f"최근 업데이트: {_file_mtime_kst(NO_BUY_SUMMARY)}")
        else:
            st.warning("no_buy_filter_summary.csv가 아직 없습니다. 위 버튼 또는 runner를 실행해 주세요.")

    df = _read_error_review_csv(NO_BUY_SUMMARY)
    if df.empty:
        st.info("아직 매수금지 필터 계산에 필요한 데이터가 부족합니다.")
        return

    work = df.copy()
    if "no_buy_score" in work.columns:
        work["no_buy_score_num"] = pd.to_numeric(work["no_buy_score"], errors="coerce").fillna(50)
    else:
        work["no_buy_score_num"] = 50
    m1, m2, m3, m4 = st.columns(4)
    levels = work["no_buy_level"].astype(str) if "no_buy_level" in work.columns else pd.Series("", index=work.index)
    applied_series = pd.to_numeric(work["no_buy_filter_applied"], errors="coerce").fillna(0) if "no_buy_filter_applied" in work.columns else pd.Series(0, index=work.index)
    m1.metric("매수금지 후보", int(levels.isin(["매수금지", "강한 매수금지"]).sum()))
    m2.metric("강한 매수금지", int(levels.eq("강한 매수금지").sum()))
    m3.metric("주의 후보", int(levels.eq("주의").sum()))
    m4.metric("판단 하향/적용", int(applied_series.sum()))

    show_cols = [
        "ticker", "market", "target_date", "no_buy_score", "no_buy_level", "no_buy_reasons",
        "final_decision_before_no_buy_filter", "final_decision_after_no_buy_filter",
        "market_regime", "market_risk_score",
    ]
    tabs = st.tabs(["위험 TOP10", "하향 종목", "사유 TOP5", "전체 표"])
    with tabs[0]:
        top = work.sort_values("no_buy_score_num", ascending=False).head(10)
        st.dataframe(top[[c for c in show_cols if c in top.columns]], use_container_width=True, hide_index=True)

    with tabs[1]:
        if {"final_decision_before_no_buy_filter", "final_decision_after_no_buy_filter"}.issubset(work.columns):
            degraded = work[work["final_decision_before_no_buy_filter"].astype(str) != work["final_decision_after_no_buy_filter"].astype(str)].copy()
        else:
            degraded = pd.DataFrame()
        if degraded.empty:
            st.info("현재 요약 기준 최종판단 하향 종목은 없습니다.")
        else:
            st.dataframe(degraded[[c for c in show_cols if c in degraded.columns]].head(80), use_container_width=True, hide_index=True)

    with tabs[2]:
        if "no_buy_reasons" not in work.columns:
            st.info("no_buy_reasons 컬럼이 없습니다.")
        else:
            reasons: list[str] = []
            for text in work["no_buy_reasons"].astype(str):
                for part in text.replace("|", "/").split("/"):
                    item = part.strip()
                    if item:
                        reasons.append(item)
            if not reasons:
                st.info("집계할 매수금지 사유가 없습니다.")
            else:
                top_reasons = pd.Series(reasons).value_counts().head(5).reset_index()
                top_reasons.columns = ["매수금지 사유", "건수"]
                st.dataframe(top_reasons, use_container_width=True, hide_index=True)

    with tabs[3]:
        with st.expander("매수금지 필터 전체 상세표", expanded=False):
            st.dataframe(work.drop(columns=["no_buy_score_num"], errors="ignore"), use_container_width=True, hide_index=True)


def render_portfolio_response_section() -> None:
    """보유종목별 유지/축소/손절/익절 대응 요약."""
    from core.portfolio_response_engine import PORTFOLIO_RESPONSE_SUMMARY, save_portfolio_response_summary

    st.subheader("보유종목 대응")
    st.caption("보유종목의 평균단가, 현재가 대체값, 최신 예측판단, 매수금지 필터, 시장상태를 종합해 대응 판단을 보조합니다.")

    c1, c2 = st.columns([1, 3])
    with c1:
        if st.button("보유종목 대응 재계산", key="portfolio_response_regenerate"):
            with st.spinner("portfolio_response_summary.csv 생성 중입니다..."):
                res = save_portfolio_response_summary()
            st.success(f"생성 완료: {res.get('rows', 0)}건")
    with c2:
        if PORTFOLIO_RESPONSE_SUMMARY.exists():
            st.info(f"최근 업데이트: {_file_mtime_kst(PORTFOLIO_RESPONSE_SUMMARY)}")
        else:
            st.warning("portfolio_response_summary.csv가 아직 없습니다. 위 버튼 또는 runner를 실행해 주세요.")

    df = _read_error_review_csv(PORTFOLIO_RESPONSE_SUMMARY)
    if df.empty:
        st.info("보유종목 대응 계산에 필요한 데이터가 부족합니다. holdings_kr.csv 또는 holdings_us.csv에 보유종목을 등록해 주세요.")
        return

    work = df.copy()
    if "holding_risk_score" in work.columns:
        work["holding_risk_score_num"] = pd.to_numeric(work["holding_risk_score"], errors="coerce").fillna(50)
    else:
        work["holding_risk_score_num"] = 50

    actions = work["portfolio_action"].astype(str) if "portfolio_action" in work.columns else pd.Series("", index=work.index)
    m1, m2, m3, m4, m5, m6 = st.columns(6)
    m1.metric("보유종목", int(len(work)))
    m2.metric("손절 우선", int(actions.eq("손절 우선").sum()))
    m3.metric("비중 축소", int(actions.eq("비중 축소 우선").sum()))
    m4.metric("추가매수 금지", int(actions.eq("추가매수 금지").sum()))
    m5.metric("익절 분할", int(actions.eq("익절 분할").sum()))
    m6.metric("보유 유지", int(actions.eq("보유 유지").sum()))

    show_cols = [
        "ticker", "market", "name", "avg_price", "quantity", "current_price",
        "unrealized_pnl_pct", "latest_final_decision", "no_buy_level",
        "market_regime", "holding_risk_score", "portfolio_action",
        "portfolio_action_reason",
    ]
    tabs = st.tabs(["대응표", "위험도 TOP10", "익절 분할 후보", "사유 TOP5", "전체 상세"])
    with tabs[0]:
        table = work[[c for c in show_cols if c in work.columns]].copy()
        st.dataframe(table, use_container_width=True, hide_index=True)

    with tabs[1]:
        top_risk = work.sort_values("holding_risk_score_num", ascending=False).head(10)
        st.dataframe(top_risk[[c for c in show_cols if c in top_risk.columns]], use_container_width=True, hide_index=True)

    with tabs[2]:
        tp = work[actions.eq("익절 분할")].copy()
        if tp.empty:
            st.info("현재 요약 기준 익절 분할 후보는 없습니다.")
        else:
            if "distance_to_tp1_pct" in tp.columns:
                tp["distance_to_tp1_pct_num"] = pd.to_numeric(tp["distance_to_tp1_pct"], errors="coerce")
                tp = tp.sort_values("distance_to_tp1_pct_num", ascending=True)
            st.dataframe(tp[[c for c in show_cols if c in tp.columns]].head(10), use_container_width=True, hide_index=True)

    with tabs[3]:
        if "portfolio_action_reason" not in work.columns:
            st.info("portfolio_action_reason 컬럼이 없습니다.")
        else:
            reasons: list[str] = []
            for text in work["portfolio_action_reason"].astype(str):
                for part in text.replace("|", "/").split("/"):
                    item = part.strip()
                    if item:
                        reasons.append(item)
            if not reasons:
                st.info("집계할 보유종목 대응 사유가 없습니다.")
            else:
                top_reasons = pd.Series(reasons).value_counts().head(5).reset_index()
                top_reasons.columns = ["대응 사유", "건수"]
                st.dataframe(top_reasons, use_container_width=True, hide_index=True)

    with tabs[4]:
        with st.expander("보유종목 대응 전체 상세표", expanded=False):
            st.dataframe(work.drop(columns=["holding_risk_score_num"], errors="ignore"), use_container_width=True, hide_index=True)

    with st.expander("포트폴리오 권장비중 평가", expanded=False):
        market_context: dict[str, Any] = {}
        try:
            market_json_path = _ops_first_existing_path([Path("data/market_regime_summary.json"), Path("market_regime_summary.json")])
            if market_json_path:
                market_context, _ = _ops_load_json_first([market_json_path])
        except Exception:
            market_context = {}
        render_portfolio_allocation_panel(work, market_context=market_context)


def render_sec_dart_disclosure_page() -> None:
    """SEC/DART 공시·재무 캐시를 수동 갱신하고 기존 판단 보드에 보조 재료로 표시한다."""
    from core.sec_dart_disclosure_engine import (
        DART_DOCUMENT_SUMMARY_CACHE,
        INVESTMENT_PURPOSES,
        KR_FINANCIAL_METRICS,
        SEC_CONFIG_PATH,
        SEC_RECENT_FILINGS,
        apply_investment_purpose_filter,
        build_dart_document_summary_cache,
        build_dart_original_text_cache_from_watchlist,
        build_kr_financial_metrics,
        build_kr_financial_metrics_from_dart,
        build_us_sec_watch_table,
        disclosure_cache_status,
        ensure_disclosure_files,
        load_sec_api_key,
        read_csv_safe,
    )

    ensure_disclosure_files()
    _render_inner_page_heading("SEC/DART 공시 체크", as_subheader=True)
    st.caption("무료 API 한도 보호를 위해 앱 첫 화면에서는 외부 API를 자동 호출하지 않습니다. 저장 캐시를 먼저 읽고, 버튼 또는 runner에서만 갱신합니다.")

    token, _cfg = load_sec_api_key()
    c1, c2, c3 = st.columns([1.2, 1.2, 2.2])
    with c1:
        st.metric("SEC API 키", "설정됨" if token else "미설정")
    with c2:
        status = disclosure_cache_status()
        st.metric("SEC 공시 캐시", f"{status.get('sec_recent_filings', {}).get('rows', 0)}건")
    with c3:
        st.caption(f"SEC 설정 파일: {SEC_CONFIG_PATH}")
        st.caption("sec_config.example.json을 참고해 sec_config.json에 키를 넣으면 수동 갱신이 가능합니다.")

    b1, b2, b3, b4 = st.columns(4)
    with b1:
        if st.button("SEC 최근 10-K/10-Q/8-K 수동 갱신", key="sec_recent_filings_manual_refresh"):
            with st.spinner("SEC 최근 공시 캐시 갱신 중입니다. 무료 한도 보호를 위해 최대 8개 심볼만 조회합니다..."):
                result = build_us_sec_watch_table(refresh=True, max_symbols=8, days=30)
            st.success(f"{result.get('message', '')} · 행 수 {result.get('rows', 0)}")
    with b2:
        if st.button("DART 원문 수동 수집", key="dart_original_text_manual_refresh"):
            with st.spinner("DART 최근 공시 원문을 수동 수집 중입니다. 최대 8개 종목/10개 문서만 조회합니다..."):
                result = build_dart_original_text_cache_from_watchlist(refresh=True, max_symbols=8, days=7, max_documents=10)
            st.success(f"{result.get('message', '')} · 행 수 {result.get('rows', 0)}")
    with b3:
        if st.button("DART 원문 요약 캐시 재계산", key="dart_document_summary_rebuild"):
            result = build_dart_document_summary_cache(refresh=False)
            st.success(f"{result.get('message', '')} · 행 수 {result.get('rows', 0)}")
    with b4:
        if st.button("한국 재무지표 캐시 재계산", key="kr_financial_metrics_rebuild"):
            result = build_kr_financial_metrics(refresh=False)
            st.success(f"{result.get('message', '')} · 행 수 {result.get('rows', 0)}")

    st.markdown("#### KIS 국장 수급")
    st.caption("한국주식 관심종목의 외국인·기관·개인 수급을 KIS Open API로 캐시하고 예측행/표준점수표 수급 항목에 반영합니다.")
