def _all_nav_page_ids(nav_groups: dict[str, list[tuple[str, str]]]) -> set[str]:
    return {page_id for entries in nav_groups.values() for _, page_id in entries}


def _inspection_legacy_sidebar_entries() -> list[tuple[str, str]]:
    """점검·복기 · 기타 — 운용/점검 상위 메뉴에 없는 기존 page_id 보존."""
    covered = _all_nav_page_ids(OPERATIONAL_NAV_GROUPS) | _all_nav_page_ids(INSPECTION_NAV_GROUPS)
    out: list[tuple[str, str]] = []
    seen: set[str] = set(covered)
    for _group, entries in SIDEBAR_NAV_GROUPS.items():
        for label, page_id in entries:
            if page_id in seen:
                continue
            seen.add(page_id)
            out.append((label, page_id))
    return out


def _admin_legacy_sidebar_entries() -> list[tuple[str, str]]:
    return _inspection_legacy_sidebar_entries()


# 점검·복기 네비에 기타 기존 기능 그룹 부착 (런타임 — mutable copy)
