def _app_screen_area() -> str:
    area = str(st.session_state.get(APP_SCREEN_AREA_KEY, APP_SCREEN_AREA_OPERATIONAL) or APP_SCREEN_AREA_OPERATIONAL)
    if area not in (APP_SCREEN_AREA_OPERATIONAL, APP_SCREEN_AREA_INSPECTION):
        return APP_SCREEN_AREA_OPERATIONAL
    return area


def _is_inspection_screen_area() -> bool:
    return _app_screen_area() == APP_SCREEN_AREA_INSPECTION


def _app_view_mode() -> str:
    return _app_screen_area()


def _is_admin_view_mode() -> bool:
    """점검·복기 화면이면 관리자용 UI(진단·원문) 허용."""
    return _is_inspection_screen_area()


