def _mode_status_label(value: Any) -> str:
    mapping = {
        "market_closed": "장외 시간",
        "pre_market_not_open": "미장 시작 전",
        "after_market": "장마감 후",
        "api_response_empty": "데이터 응답 없음",
        "no_orderbook_fields": "해당 데이터 미제공 가능",
        "endpoint_not_configured": "API 연결 확인 필요",
        "quote_partial_fallback": "보조 데이터 사용",
        "csv_fallback": "저장 데이터 사용",
        "missing": "미수신",
        "success": "정상",
        "OK_WITH_NOTICE": "정상, 일부 확인 안내 있음",
        "PASS_WITH_NOTICE": "정상, 일부 장외 시간 안내 있음",
        "CHECK_REQUIRED": "확인 필요",
        "WARNING": "확인 안내",
        "NOTICE": "안내",
        "OK": "정상",
    }
    if isinstance(value, (bool, np.bool_)):
        return "예" if bool(value) else "아니오"
    text = str(value or "").strip()
    if not text or text.lower() in {"nan", "none", "nat"}:
        return "-"
    return mapping.get(text, mapping.get(text.lower(), text))


def _mode_num(value: Any, default: float = 0.0) -> float:
    num = safe_float(value, np.nan)
    return default if math.isnan(num) else float(num)


def _mode_pct(value: Any) -> str:
    num = _mode_num(value, np.nan)
    if math.isnan(num):
        return "-"
    if 0 <= num <= 1:
        num *= 100
    return f"{num:.1f}%"


