def _parse_holding_price_value(raw: Any) -> float:
    """보유 평단/현재가 — $/원/쉼표 표기 파싱."""
    try:
        parsed = parse_price_label(raw)
        if not math.isnan(parsed):
            return float(parsed)
    except Exception:
        pass
    text = str(raw or "").strip().replace(",", "")
    if not text or text.lower() in {"-", "nan", "none", "nat"}:
        return np.nan
    for token in ("원", "$", "₩", "USD", "KRW"):
        text = text.replace(token, "")
    text = text.strip()
    try:
        return float(text)
    except Exception:
        return np.nan


def _holding_return_pct_display(avg: Any, current: Any, quantity: Any) -> tuple[str, str]:
    """(표시 수익률, 계산 불가 사유). 평가손익은 수량이 있을 때만."""
    avg_n = _parse_holding_price_value(avg)
    cur_n = _parse_holding_price_value(current)
    qty_n = safe_float(quantity, np.nan)
    if math.isnan(avg_n) or avg_n <= 0:
        return "-", "평균단가 없음"
    if math.isnan(cur_n) or cur_n <= 0:
        return "-", "현재가 미수신"
    pct_val = (cur_n / avg_n - 1.0) * 100.0
    pct_text = f"{pct_val:+.2f}%"
    if math.isnan(qty_n) or qty_n <= 0:
        return pct_text, "보유수량 없음 — 수익률만 표시, 평가손익 미표시"
    return pct_text, ""


def _holding_return_display_from_row(srow: Any) -> tuple[str, str]:
    """build_holdings_status 수익률이 '-'여도 평단·현재가로 화면 표시용 재계산."""
    avg_raw = srow.get("평단가", srow.get("avg_price", "")) if hasattr(srow, "get") else ""
    cur_raw = srow.get("현재가", srow.get("current_price", "")) if hasattr(srow, "get") else ""
    qty_raw = srow.get("수량", srow.get("quantity", srow.get("shares", ""))) if hasattr(srow, "get") else ""
    ret_pct, ret_note = _holding_return_pct_display(avg_raw, cur_raw, qty_raw)
    if ret_pct != "-":
        return ret_pct, ret_note
    csv_ret = str(srow.get("수익률", srow.get("unrealized_pnl_pct", "")) if hasattr(srow, "get") else "").strip()
    if csv_ret and csv_ret.lower() not in {"-", "nan", "none", "nat", ""}:
        return csv_ret, ""
    return ret_note or "계산 불가", ret_note


def _holding_pnl_display_from_row(srow: Any) -> str:
    """평가손익 — 수량이 있을 때만 계산, 없으면 기존 값 또는 '-'."""
    existing = str(srow.get("손익", "-") if hasattr(srow, "get") else "-").strip()
    if existing and existing not in {"-", "nan", "none", "nat"}:
        return existing
    avg_n = _parse_holding_price_value(srow.get("평단가", srow.get("avg_price", "")) if hasattr(srow, "get") else "")
    cur_n = _parse_holding_price_value(srow.get("현재가", srow.get("current_price", "")) if hasattr(srow, "get") else "")
    qty_n = safe_float(srow.get("수량", srow.get("quantity", srow.get("shares", ""))) if hasattr(srow, "get") else "", np.nan)
    if math.isnan(qty_n) or qty_n <= 0 or math.isnan(avg_n) or math.isnan(cur_n):
        return "-"
    pnl = (cur_n - avg_n) * qty_n
    mkt = str(srow.get("market", "") if hasattr(srow, "get") else "")
    if mkt == "한국주식":
        return f"{pnl:+,.0f}원"
    return f"${pnl:+,.2f}"


def _infer_symbol_search_market(query: str, fallback_market: str) -> str:
    raw = str(query or "").strip()
    if not raw:
        return fallback_market
    if any("\uac00" <= ch <= "\ud7a3" for ch in raw):
        code = korean_symbol_from_name(raw)
        if code and str(code).strip() and str(code).strip() != raw:
            return "한국주식"
    kr_code = normalize_ticker(raw, "한국주식")
    if kr_code.isdigit() and len(kr_code) == 6:
        return "한국주식"
    cleaned = re.sub(r"[^A-Za-z0-9.\-]", "", raw).upper()
    if re.fullmatch(r"[A-Z][A-Z0-9.\-]{0,9}", cleaned or ""):
        return "미국주식"
    return fallback_market


