def _render_general_risk_home(scope: pd.DataFrame, market_filter: str) -> None:
    _render_general_section_title("위험·주의 후보")
    mkt = _general_market_for_filter(market_filter)
    candidates = _load_swing_candidate_reports(mkt)
    c1, c2 = st.columns(2)
    with c1:
        st.markdown("**추격매수 위험**")
        if candidates is None or candidates.empty:
            st.info("추격매수 위험 후보가 없습니다.")
        else:
            render_chase_risk_table(candidates, limit=6, raw_key=f"home_chase_{market_filter}")
    with c2:
        st.markdown("**신규매수 주의**")
        if scope is None or scope.empty:
            st.info("신규매수 주의 종목이 없습니다.")
        else:
            text = scope.get("risk_final_decision", pd.Series("", index=scope.index)).astype(str) + " " + scope.get("candidate_group", pd.Series("", index=scope.index)).astype(str)
            caution = scope.loc[text.str.contains("금지|제외|관망|손절|축소", regex=True, na=False)].head(6)
            if caution.empty:
                st.success("신규매수 주의 종목이 없습니다.")
            else:
                st.dataframe(pd.DataFrame([{
                    "종목명": r.get("name") or r.get("symbol", "-"),
                    "이유": _decision_text(r),
                } for _, r in caution.iterrows()]), use_container_width=True, hide_index=True)
    c3, c4 = st.columns(2)
    with c3:
        st.markdown("**판단 보류**")
        if scope is None or scope.empty:
            st.info("판단 보류 종목이 없습니다.")
        else:
            pending = scope.loc[scope.apply(_is_pending_judgment_row, axis=1)].head(6)
            if pending.empty:
                st.success("판단 보류 종목이 없습니다.")
            else:
                st.dataframe(pd.DataFrame([{
                    "종목명": r.get("name") or r.get("symbol", "-"),
                    "사유": str(r.get("future_probability_status", r.get("display_group", "-")) or "-"),
                } for _, r in pending.iterrows()]), use_container_width=True, hide_index=True)
    with c4:
        st.markdown("**데이터 부족**")
        if scope is None or scope.empty:
            st.info("데이터 부족 종목이 없습니다.")
        else:
            need = scope.loc[_general_scope_action_mask(scope, "확인 필요")].head(6)
            if need.empty:
                st.success("데이터 부족으로 표시할 종목이 없습니다.")
            else:
                st.dataframe(pd.DataFrame([{
                    "종목명": r.get("name") or r.get("symbol", "-"),
                    "상태": _decision_text(r),
                } for _, r in need.iterrows()]), use_container_width=True, hide_index=True)


