def render_general_execution_plan_home(scope: pd.DataFrame, market_filter: str) -> None:
    """일반 모드 첫 페이지 — 빠른 실행 플랜.

    첫 화면은 저장된 후보/요약 파일만 읽어 빠르게 표시합니다.
    무거운 predictions 전체 로딩·랭킹 표 계산은 상세 화면/토글에서만 수행합니다.
    """
    try:
        from buy_candidate_dashboard import render_execution_plan_home
        render_execution_plan_home(_general_market_for_filter(market_filter))
        return
    except Exception as exc:
        _render_execution_plan_status_header(market_filter)
