def _pick_sidebar_nav_page_id(
    group: str,
    labels: list[str],
    nav_groups: dict[str, list[tuple[str, str]]] | None = None,
) -> str:
    """사이드바 하위 화면 라벨 → page_id (헬퍼 전용)."""
    groups = nav_groups or _sidebar_nav_groups_for_mode()
    label_to_id = {label: pid for label, pid in groups[group]}
    state_key = f"sidebar_nav_sub_{group}"
    default_label = labels[0]
    if state_key not in st.session_state or st.session_state[state_key] not in labels:
        st.session_state[state_key] = default_label
    return label_to_id[st.session_state[state_key]]


def _graft_sidebar_nav_group_select(group_names: list[str]) -> str:
    """사이드바 메뉴 그룹 선택 (대분류 라벨은 이 헬퍼에만 둠)."""
    if len(group_names) == 1:
        nav_group = group_names[0]
        st.session_state["sidebar_nav_group_v11"] = nav_group
        st.caption(nav_group)
        return nav_group
    return st.selectbox(
        "대분류",
        group_names,
        key="sidebar_nav_group_v11",
        help="기능을 용도별로 묶었습니다. 기능 삭제 없이 메뉴만 정리했습니다.",
    )


def _graft_sidebar_page_select(
    nav_group: str,
    nav_groups: dict[str, list[tuple[str, str]]],
) -> tuple[str, str]:
    """사이드바 화면 선택 → (page_id, sub_label)."""
    sub_labels = [label for label, _ in nav_groups[nav_group]]
    if len(sub_labels) > 1:
        st.selectbox(
            "화면",
            sub_labels,
            key=f"sidebar_nav_sub_{nav_group}",
        )
        page_id = _pick_sidebar_nav_page_id(nav_group, sub_labels, nav_groups)
        sub_label = _current_sidebar_nav_sub_label(nav_group, sub_labels)
    else:
        sub_label, page_id = nav_groups[nav_group][0]
        st.session_state[f"sidebar_nav_sub_{nav_group}"] = sub_label
    return page_id, sub_label


def _current_sidebar_nav_sub_label(group: str, labels: list[str]) -> str:
    state_key = f"sidebar_nav_sub_{group}"
    label = str(st.session_state.get(state_key, "") or "").strip()
    if label in labels:
        return label
    return labels[0] if labels else ""


def _latest_report_updated_at_label() -> str:
    for path in [
        REPORT_DIR / "intraday_realtime_summary.json",
        REPORT_DIR / "intraday_orderbook_summary.json",
        REPORT_DIR / "daily_quality_summary.json",
        REPORT_DIR / "catalyst_validation_summary.json",
    ]:
        data = _safe_report_json(path)
        updated_at = str(data.get("updated_at") or data.get("checked_at") or "").strip()
        if updated_at:
            return updated_at
    return "-"


def render_grafted_nav_header(page_id: str, sub_label: str, nav_group: str) -> None:
    """제목은 각 화면 _render_nav_page_title에서 표시 (중복·잘림 방지)."""
    return


# ══════════════════════════════════════════════
# New-version graft bridge
# - 기존 예측보드(app.py)는 그대로 본체로 유지
# - new 버전의 포트폴리오/매수판단/매도판단/일지/리포트 기능만 선택 호출
# ══════════════════════════════════════════════
def render_grafted_feature_router(bootstrap_placeholder: Any = None) -> bool:
    """new 버전에서 가져온 화면을 현재 app.py 실제 데이터 함수로 매핑한다."""
    try:
        _update_app_bootstrap_loading(bootstrap_placeholder, 1)
        ensure_operation_settings_loaded()
        st.session_state["_graft_router_sidebar_built"] = False
        sidebar_market: str | None = None
        area_options = [APP_SCREEN_AREA_OPERATIONAL, APP_SCREEN_AREA_INSPECTION]
        if st.session_state.get(APP_SCREEN_AREA_KEY) not in area_options:
            st.session_state[APP_SCREEN_AREA_KEY] = APP_SCREEN_AREA_OPERATIONAL
        nav_groups = _sidebar_nav_groups_for_mode()
        group_names = list(nav_groups.keys())
        if st.session_state.get("sidebar_nav_group_v11") not in group_names:
            st.session_state["sidebar_nav_group_v11"] = group_names[0]
        with st.sidebar:
            st.markdown(f"### {APP_SIDEBAR_BRAND}")
            st.caption(APP_NAME)
            st.divider()
            st.markdown("### 메뉴")
            nav_group = _graft_sidebar_nav_group_select(group_names)
            page_id, sub_label = _graft_sidebar_page_select(nav_group, nav_groups)
            st.caption(f"선택: **{sub_label}**")
            st.divider()
            if not _is_inspection_screen_area():
                try:
                    sidebar_market = _render_grafted_sidebar_market_filter()
                except Exception as exc:
                    st.caption(f"시장 필터: {str(exc)[:100]}")
                    sidebar_market = _graft_market_token_from_mode(_graft_sidebar_market_mode())
                st.divider()
                try:
                    _render_grafted_sidebar_watch_mini(sidebar_market)
                except Exception as exc:
                    st.caption(f"관심종목 미니차트: {str(exc)[:100]}")
            else:
                sidebar_market = None
                st.markdown("### 시장 필터")
                st.caption("점검·복기 화면에서는 시장 필터를 사용하지 않습니다.")
            st.divider()
            st.caption(f"마지막 갱신 {_latest_report_updated_at_label()}")
            st.divider()
            st.selectbox(
                "보기 모드",
                area_options,
                key=APP_SCREEN_AREA_KEY,
                help="일반 모드: 매수·보유·매도 판단 / 관리자 모드: 진단·복기·원본 확인",
            )
            _update_app_bootstrap_loading(bootstrap_placeholder, 2)
            st.session_state["_graft_router_sidebar_built"] = True
        sub_labels = [label for label, _ in nav_groups[nav_group]]
        sub_label = _current_sidebar_nav_sub_label(nav_group, sub_labels)
        st.session_state["_graft_nav_show_page_title"] = True
        _update_app_bootstrap_loading(bootstrap_placeholder, 3)
        if _is_inspection_screen_area():
            _inject_mode_dashboard_css(admin=True)
        else:
            _inject_operational_dashboard_css()
        _lazy_load_page_data(page_id, sidebar_market)
        render_grafted_nav_header(page_id, sub_label, nav_group)
        _dispatch_sidebar_nav_page(page_id)
        _update_app_bootstrap_loading(bootstrap_placeholder, 4)
        _clear_app_bootstrap_loading(bootstrap_placeholder)
        return True
    except Exception as exc:
        _clear_app_bootstrap_loading(bootstrap_placeholder)
        try:
            log_app_event(
                "nav_extension",
                "error",
                f"{type(exc).__name__}: {exc}",
                function_name="_render_grafted_sidebar_nav",
                market=str(st.session_state.get(APP_MARKET_KEY, "")),
                resolution="일반 모드에는 짧은 안내만 표시, 관리자 모드에서 상세 확인",
            )
        except Exception:
            pass
        _render_nav_extension_data_notice(exc)
        return True

