    render_prediction_cards(prediction, market, confidence, event_context)

    with st.expander("🧭 오차 보정 적용 결과", expanded=bool(prediction.get("adjustment_applied", 0))):
        before_decision = prediction.get("final_decision_before_adjustment", prediction.get("primary_action", ""))
        after_decision = prediction.get("final_decision_after_adjustment", prediction.get("primary_action", ""))
        applied_label = "적용" if int(safe_float(prediction.get("adjustment_applied", 0), 0)) else "미적용"
