# v9.9.55 final polish helpers
def chase_limit_price_v9955(entry: float, market: str) -> float:
    """우선진입가 대비 추격매수 금지 가격. 국장 2%, 미장 3% 기준."""
    try:
        entry = safe_float(entry, np.nan)
        if np.isnan(entry) or entry <= 0:
            return np.nan
        limit_rate = 0.02 if market == "한국주식" else 0.03
        return entry * (1 + limit_rate)
    except Exception:
        return np.nan


def tradeability_summary_v9955(view: pd.DataFrame, market: str) -> dict[str, Any]:
    """오늘 매매 가능성을 높음/보통/낮음/관망 우위로 요약."""
    result = {"label": "판단 보류", "score": 0, "reasons": []}
    try:
        if view is None or view.empty:
            return {"label": "관망 우위", "score": -5, "reasons": ["확정된 예측 기록이 없음"]}

        df = view.copy()
        conf = pd.to_numeric(df.get("보정신뢰도"), errors="coerce")
        fit = pd.to_numeric(df.get("매매적합도"), errors="coerce")
        rr = pd.to_numeric(df.get("손익비"), errors="coerce") if "손익비" in df.columns else pd.Series(np.nan, index=df.index)
        caution = df.get("주의사유", pd.Series("-", index=df.index)).astype(str)

        top = df.head(3).copy()
        top_conf = pd.to_numeric(top.get("보정신뢰도"), errors="coerce")
        top_fit = pd.to_numeric(top.get("매매적합도"), errors="coerce")
        top_rr = pd.to_numeric(top.get("손익비"), errors="coerce") if "손익비" in top.columns else pd.Series(np.nan, index=top.index)
        top_caution = top.get("주의사유", pd.Series("-", index=top.index)).astype(str)

        score = 0
        reasons = []

        avg_fit = safe_float(fit.mean(), np.nan)
        avg_conf = safe_float(conf.mean(), np.nan)
        top_good = int(((top_conf >= 70) & (top_fit >= 65) & ((top_rr >= 1.5) | top_rr.isna())).sum()) if not top.empty else 0
        warn_n = int((caution != "-").sum())

        if top_good >= 2:
            score += 3
            reasons.append("TOP 후보 중 조건 충족 종목 2개 이상")
        elif top_good == 1:
            score += 1
            reasons.append("TOP 후보 중 조건 충족 종목 1개")
        else:
            score -= 2
            reasons.append("TOP 후보 조건 충족 부족")

        if not np.isnan(avg_fit):
            if avg_fit >= 70:
                score += 2
                reasons.append(f"평균 매매적합도 양호 {avg_fit:.0f}점")
            elif avg_fit < 55:
                score -= 2
                reasons.append(f"평균 매매적합도 낮음 {avg_fit:.0f}점")

        if not np.isnan(avg_conf):
            if avg_conf >= 72:
                score += 1
                reasons.append(f"평균 보정신뢰도 양호 {avg_conf:.0f}점")
            elif avg_conf < 58:
                score -= 1
                reasons.append(f"평균 보정신뢰도 낮음 {avg_conf:.0f}점")

        if warn_n >= max(2, len(df) * 0.35):
            score -= 2
            reasons.append(f"주의사유 종목 다수 {warn_n}건")

        # 무효화/국장 리스크 사유가 있으면 보수 처리
        try:
            kr_reasons = st.session_state.get("kr_v9952_invalidation_reasons", [])
            if market == "한국주식" and kr_reasons:
                score -= min(3, len(kr_reasons))
                reasons.append("국장 검증 리스크 감지")
        except Exception:
            pass

        if score >= 4:
            label = "높음"
        elif score >= 1:
            label = "보통"
        elif score >= -2:
            label = "낮음"
        else:
            label = "관망 우위"

        result = {"label": label, "score": int(score), "reasons": reasons[:6]}
    except Exception as e:
        result = {"label": "판단 보류", "score": 0, "reasons": [f"매매 가능성 계산 오류: {e}"]}
    return result


def render_tradeability_banner_v9955(view: pd.DataFrame, market: str) -> None:
    """TOP 후보 위에 오늘 매매 가능성을 간단히 표시."""
    try:
        s = tradeability_summary_v9955(view, market)
        label = s.get("label", "판단 보류")
        score = s.get("score", 0)
        reasons = s.get("reasons", [])

        if label == "높음":
            st.success(f"🟢 오늘 매매 가능성: **{label}** · score {score:+d}")
        elif label == "보통":
            st.info(f"🔵 오늘 매매 가능성: **{label}** · score {score:+d}")
        elif label == "낮음":
            st.warning(f"🟠 오늘 매매 가능성: **{label}** · score {score:+d}")
        else:
            st.error(f"🔴 오늘 매매 가능성: **{label}** · score {score:+d}")

        if reasons:
            st.caption("판단 사유: " + " / ".join(reasons[:4]))
    except Exception as e:
        st.caption(f"매매 가능성 표시 오류: {e}")


