# v9.9.54 operation status helpers
def prediction_status_message_v9954(market: str) -> dict[str, Any]:
    """현재 시간대 기준 앱이 예측을 생성/고정/복기 중인지 한눈에 보여주는 상태값."""
    out = {
        "mode": "unknown",
        "title": "상태 확인 중",
        "body": "현재 세션 정보를 확인하고 있습니다.",
        "detail": "",
        "locked": False,
    }
    try:
        session = market_session_context(market)
        session_type = str(session.get("session", ""))
        session_label = str(session.get("session_label", ""))
        target_date = str(session.get("target_date", ""))

        if session_type == "regular":
            out.update({
                "mode": "locked",
                "title": "예측값 고정 상태",
                "body": "정규장 진행 중입니다. 장전 확정 예측가·진입가·손절가·익절가는 재생성하지 않습니다.",
                "detail": f"{session_label} · 대상일 {target_date} · 현재가/뉴스/공시/수급 리스크만 갱신",
                "locked": True,
            })
        elif session_type in {"pre", "preopen"} or "장전" in session_label:
            out.update({
                "mode": "preopen",
                "title": "장전 예측 준비/확정 구간",
                "body": "뉴스·프리마켓·시장흐름·공시를 반영해 장전 예측을 생성/갱신할 수 있는 시간대입니다.",
                "detail": f"{session_label} · 대상일 {target_date}",
                "locked": False,
            })
        elif session_type in {"after", "post", "closed"} or "마감" in session_label or "장마감" in session_label:
            out.update({
                "mode": "review",
                "title": "장마감 복기 구간",
                "body": "실제 시가·고가·저가·종가가 업데이트되면 예측오차와 가상손익을 검증합니다.",
                "detail": f"{session_label} · 대상일 {target_date}",
                "locked": False,
            })
        else:
            out.update({
                "mode": "idle",
                "title": "예측 대기/점검 구간",
                "body": "정규장 중이 아니므로 데이터 상태와 최근 예측 기록을 확인합니다.",
                "detail": f"{session_label} · 대상일 {target_date}",
                "locked": False,
            })
    except Exception as e:
        out.update({
            "mode": "error",
            "title": "상태 확인 실패",
            "body": "세션 상태 확인 중 오류가 발생했습니다.",
            "detail": str(e)[:120],
            "locked": False,
        })
    return out


def render_prediction_status_banner_v9954(market: str, log_df: pd.DataFrame | None = None) -> None:
    """앱 상단 상태 표시: 장중 고정/장전 생성/장마감 복기."""
    try:
        state = prediction_status_message_v9954(market)
        title = state.get("title", "")
        body = state.get("body", "")
        detail = state.get("detail", "")

        if state.get("mode") == "locked":
            st.info(f"🔒 **{title}**  \n{body}  \n{detail}")
        elif state.get("mode") == "review":
            st.success(f"📊 **{title}**  \n{body}  \n{detail}")
        elif state.get("mode") == "preopen":
            st.warning(f"⏱️ **{title}**  \n{body}  \n{detail}")
        else:
            st.caption(f"**{title}** · {body} · {detail}")

        # 최근 예측 기록 수를 짧게 안내
        try:
            session = market_session_context(market)
            target_date = str(session.get("target_date", ""))
            if log_df is not None and not log_df.empty and "market" in log_df.columns:
                df = log_df.copy()
                m = df["market"].astype(str) == str(market)
                if "target_date" in df.columns and target_date:
                    m = m & (df["target_date"].astype(str) == target_date)
                n = int(m.sum())
                if n == 0:
                    st.warning("오늘 확정된 예측 기록이 아직 없습니다. 장전 예측 생성 시간 이후 다시 실행하거나 관심종목/데이터 상태를 확인하세요.")
                else:
                    st.caption(f"현재 대상일 예측 기록: {n:,}건")
        except Exception:
            pass
    except Exception as e:
        st.caption(f"상태 표시 오류: {e}")


def render_kr_api_disconnected_notice_v9954() -> None:
    """국장 API 연결 전 오해 방지 안내."""
    try:
        with st.expander("🇰🇷 국장 수급 API 연결 상태", expanded=False):
            st.info("외국인·기관 수급 API는 아직 미연결 상태입니다. 현재 국장 판단은 시장지표/환율/전일 미장/DART/국내뉴스/예상체결가 수동 입력 기준으로 보조 판단합니다.")
            st.caption("내일 KIS Open API 또는 KRX Open API를 연결하면 외국인·기관 수급, 장중 수급 무효화 경고, 장마감 수급 복기까지 확장할 수 있습니다.")
    except Exception:
        pass


def summarize_startup_sync_result_v9954(result: dict[str, Any] | None) -> None:
    """자동 동기화가 무엇을 했는지 쉬운 문장으로 요약."""
    if not isinstance(result, dict) or not result:
        return
    try:
        updated = int(result.get("updated_actuals", 0) or 0)
        generated = int(result.get("generated", 0) or result.get("new_predictions", 0) or 0)
        upserted = int(result.get("upserted", 0) or result.get("updated_predictions", 0) or 0)
        locked = bool(result.get("prediction_locked", False))
        msg = str(result.get("message", "") or "")
        reason = str(result.get("prediction_lock_reason", "") or "")

        if locked:
            st.info(f"자동 동기화 결과: 실제값 {updated}건 업데이트 · 장중 예측값 고정 · 예측 재생성 없음")
            if reason:
                st.caption(reason)
        elif generated or upserted:
            st.success(f"자동 동기화 결과: 실제값 {updated}건 업데이트 · 예측 {generated + upserted}건 저장/갱신")
        elif msg:
            st.caption(f"자동 동기화 결과: {msg}")
    except Exception:
        pass

# v9.9.52 KR market 강화 helpers
def _v9952_safe_numeric_series(s):
    try:
        return pd.to_numeric(s, errors="coerce")
    except Exception:
        return pd.Series(dtype=float)


def kr_preopen_window_v9952(now_kst: datetime | None = None) -> bool:
    """국장 장 시작 10분 전 예상체결가 확인 구간."""
    try:
        now = now_kst or datetime.now(KST)
        if now.tzinfo is None:
            now = now.replace(tzinfo=KST)
        return now.weekday() < 5 and now.time() >= datetime.min.time().replace(hour=8, minute=50) and now.time() < datetime.min.time().replace(hour=9, minute=0)
    except Exception:
        return False


def kr_market_index_snapshot_v9952() -> dict[str, Any]:
    """국장 무효화 경고용 핵심 지표 스냅샷: 코스피/코스닥/환율/미국 반도체/나스닥."""
    out = {"score": 0, "reasons": [], "data": []}
    symbols = [
        ("^KS11", "코스피", "kr_index"),
        ("^KQ11", "코스닥", "kr_index"),
        ("KRW=X", "원/달러 환율", "fx"),
        ("^IXIC", "나스닥", "us_index"),
        ("SOXX", "미국 반도체 ETF", "us_sector"),
        ("CL=F", "WTI 유가", "commodity"),
        ("^TNX", "미국 10년물 금리", "yield"),
    ]
    try:
        for sym, label, kind in symbols:
            snap = fetch_extended_snapshot_with_fallback(sym) if "fetch_extended_snapshot_with_fallback" in globals() else fetch_extended_snapshot(sym)
            chg = safe_float(snap.get("change_pct"), np.nan)
            last = safe_float(snap.get("last_price"), np.nan)
            row = {
                "항목": label,
                "심볼": sym,
                "현재값": format_macro_value(sym, last) if "format_macro_value" in globals() else (f"{last:,.2f}" if not np.isnan(last) else "-"),
                "등락률": pct(chg) if not np.isnan(chg) else "-",
                "판정": "중립",
            }
            if np.isnan(chg):
                out["data"].append(row)
                continue

            if sym == "^KQ11" and chg <= -1.5:
                out["score"] -= 3
                row["판정"] = "코스닥 급락"
                out["reasons"].append(f"코스닥 약세 {chg:.2f}%")
            elif sym == "^KS11" and chg <= -1.2:
                out["score"] -= 2
                row["판정"] = "코스피 약세"
                out["reasons"].append(f"코스피 약세 {chg:.2f}%")
            elif sym == "KRW=X" and chg >= 0.45:
                out["score"] -= 3
                row["판정"] = "환율 부담"
                out["reasons"].append(f"원/달러 환율 상승 {chg:.2f}%")
            elif sym == "SOXX" and chg <= -1.3:
                out["score"] -= 2
                row["판정"] = "반도체 부담"
                out["reasons"].append(f"미국 반도체 ETF 약세 {chg:.2f}%")
            elif sym == "^IXIC" and chg <= -1.2:
                out["score"] -= 2
                row["판정"] = "미장 부담"
                out["reasons"].append(f"나스닥 약세 {chg:.2f}%")
            elif sym == "^TNX" and chg >= 1.0:
                out["score"] -= 1
                row["판정"] = "금리 부담"
                out["reasons"].append(f"미국 10년물 금리 상승 {chg:.2f}%")
            elif sym == "CL=F" and chg >= 2.0:
                out["score"] -= 1
                row["판정"] = "유가 부담"
                out["reasons"].append(f"WTI 유가 상승 {chg:.2f}%")
            elif sym in {"^KS11", "^KQ11"} and chg >= 0.8:
                out["score"] += 1
                row["판정"] = "국장 우호"
            elif sym == "SOXX" and chg >= 1.0:
                out["score"] += 1
                row["판정"] = "반도체 우호"

            out["data"].append(row)
    except Exception as e:
        out["reasons"].append(f"국장 지표 확인 실패: {str(e)[:80]}")
    out["score"] = int(max(-10, min(5, out.get("score", 0))))
    # dedupe reasons
    dedup = []
    for r in out["reasons"]:
        if r not in dedup:
            dedup.append(r)
    out["reasons"] = dedup[:6]
    return out


def kr_news_keyword_score_v9952(items: list[Any]) -> dict[str, Any]:
    """국장 뉴스/공시 제목 기반 호재·악재 키워드 점수."""
    risk_words = [
        "유상증자", "전환사채", "CB", "BW", "감자", "거래정지", "횡령", "배임",
        "실적 부진", "어닝쇼크", "수주 취소", "계약 해지", "공급계약 해지",
        "임상 실패", "투자주의", "투자경고", "단기과열", "관리종목", "상장폐지",
        "불성실공시", "압수수색", "검찰", "적자전환"
    ]
    good_words = [
        "수주", "공급계약", "실적 서프라이즈", "영업이익 증가", "흑자전환",
        "자사주", "배당 확대", "정부 정책", "수출 계약", "방산 계약",
        "원전 계약", "신규 계약", "증설", "승인", "인허가"
    ]
    score = 0
    reasons = []
    for raw in items or []:
        if isinstance(raw, dict):
            title = str(raw.get("title") or raw.get("제목") or raw.get("headline") or "")
        else:
            title = str(raw or "")
        if not title:
            continue
        risk_hit = [w for w in risk_words if w.lower() in title.lower()]
        good_hit = [w for w in good_words if w.lower() in title.lower()]
        if risk_hit:
            score -= min(5, 2 + len(risk_hit))
            reasons.append(f"악재 키워드({', '.join(risk_hit[:2])}): {title[:80]}")
        elif good_hit:
            score += min(3, 1 + len(good_hit))
            reasons.append(f"호재 키워드({', '.join(good_hit[:2])}): {title[:80]}")
    score = int(max(-10, min(6, score)))
    # prioritize risk reasons first
    risk_first = [r for r in reasons if r.startswith("악재")]
    good_next = [r for r in reasons if r.startswith("호재")]
    return {"score": score, "reasons": (risk_first + good_next)[:6]}


def kr_theme_strength_v9952(market_score: dict[str, Any] | None = None) -> pd.DataFrame:
    """관심종목 테마별 대략 강도. 전일 미장/환율/국내 지수 기반 힌트."""
    rows = []
    base_score = safe_float((market_score or {}).get("score"), 0)
    try:
        wl = load_watchlist_df("한국주식")
        if wl is None or wl.empty:
            return pd.DataFrame()
        sector_col = "sector_proxy" if "sector_proxy" in wl.columns else ("theme" if "theme" in wl.columns else None)
        if not sector_col:
            return pd.DataFrame()
        for theme, g in wl.groupby(sector_col):
            theme_s = str(theme or "기타")
            score = base_score
            lower = theme_s.lower()
            if any(k in lower for k in ["반도체", "hbm", "ai"]):
                # SOXX/나스닥 우호 여부 반영은 market_score reasons에 간접 반영
                score += 1
            if any(k in lower for k in ["조선", "방산", "원전", "전력"]):
                score += 1
            if any(k in lower for k in ["바이오", "2차전지", "로봇"]):
                score -= 1 if base_score < 0 else 0
            if score >= 2:
                label = "우호"
            elif score <= -3:
                label = "주의"
            elif score <= -1:
                label = "확인 필요"
            else:
                label = "중립"
            rows.append({
                "테마": theme_s,
                "관심종목수": int(len(g)),
                "테마강도": int(max(-10, min(5, score))),
                "판정": label,
            })
    except Exception:
        return pd.DataFrame()
    return pd.DataFrame(rows).sort_values(["테마강도", "관심종목수"], ascending=[False, False])


def render_kr_preopen_expected_price_panel_v9952(log_df: pd.DataFrame | None = None) -> None:
    """증권사 API 전 단계: 국장 장전 예상체결가 수동 입력/괴리율 체크."""
    with st.expander("🇰🇷 국장 장전 예상체결가 수동 체크", expanded=kr_preopen_window_v9952()):
        st.caption("증권사 실시간 API 연결 전까지는 08:50~09:00 예상체결가를 직접 입력해 진입가 대비 괴리율을 확인합니다.")
        try:
            wl = load_watchlist_df("한국주식")
            if wl is None or wl.empty or "symbol" not in wl.columns:
                st.info("국장 관심종목 파일을 먼저 확인하세요.")
                return
            options = []
            label_to_symbol = {}
            for _, r in wl.iterrows():
                sym = normalize_ticker(str(r.get("symbol", "")), "한국주식")
                if not sym:
                    continue
                nm = str(r.get("name", "") or korean_name_from_symbol(sym, sym))
                label = f"{nm} · {sym}"
                options.append(label)
                label_to_symbol[label] = sym
            if not options:
                st.info("국장 관심종목이 없습니다.")
                return
            col1, col2 = st.columns([1.3, 1.0])
            with col1:
                sel = st.selectbox("예상체결가 확인 종목", options, key="kr_preopen_symbol_v9952")
            symbol = label_to_symbol.get(sel, "")
            # Find latest preferred entry for symbol
            entry = np.nan
            stop = np.nan
            tp1 = np.nan
            if log_df is not None and not log_df.empty and "ticker" in log_df.columns:
                rows = log_df[(log_df.get("market", "").astype(str) == "한국주식") & (log_df["ticker"].astype(str).apply(lambda x: normalize_ticker(x, "한국주식")) == symbol)].copy()
                if not rows.empty:
                    if "created_at" in rows.columns:
                        rows["_dt"] = pd.to_datetime(rows["created_at"], errors="coerce")
                        rows = rows.sort_values("_dt", ascending=False)
                    latest = rows.iloc[0]
                    entry = safe_float(latest.get("preferred_entry", latest.get("우선진입가", np.nan)), np.nan)
                    stop = safe_float(latest.get("stop_loss", latest.get("손절가", np.nan)), np.nan)
                    tp1 = safe_float(latest.get("take_profit1", latest.get("1차익절가", np.nan)), np.nan)
            with col2:
                expected = st.number_input("장전 예상체결가", min_value=0.0, value=0.0, step=100.0, key=f"kr_expected_price_{symbol}_v9952")
            if expected <= 0:
                st.caption("예상체결가를 입력하면 진입가 대비 괴리율을 계산합니다.")
                return
            if not np.isnan(entry) and entry > 0:
                gap = (expected / entry - 1) * 100
                m1, m2, m3 = st.columns(3)
                m1.metric("우선진입가", fmt_price(entry, "한국주식"))
                m2.metric("예상체결가 괴리", f"{gap:+.2f}%")
                m3.metric("손절/익절", f"{fmt_price(stop, '한국주식') if not np.isnan(stop) else '-'} / {fmt_price(tp1, '한국주식') if not np.isnan(tp1) else '-'}")
                if gap >= 3:
                    st.warning("예상체결가가 우선진입가보다 높습니다. 추격매수 주의 또는 신규진입 보류가 유리합니다.")
                elif gap <= -3:
                    st.warning("예상체결가가 우선진입가보다 크게 낮습니다. 장전 악재/수급 이탈 여부 확인이 필요합니다.")
                else:
                    st.success("예상체결가가 우선진입가 근처입니다. 장 시작 후 체결 흐름 확인 후보입니다.")
            else:
                st.info("해당 종목의 최근 우선진입가 기록을 찾지 못했습니다. 예측 생성 후 다시 확인하세요.")
        except Exception as e:
            st.warning(f"예상체결가 패널 표시 중 오류: {e}")


def render_kr_market_enhanced_panel_v9952(log_df: pd.DataFrame | None = None, event_context: dict[str, Any] | None = None) -> dict[str, Any]:
    """국장 전용 검증 패널: 전일 미장/환율/국내 지수/국내 뉴스/테마/수급 힌트."""
    result = {"score": 0, "reasons": []}
    if "market" in globals():
        pass
    try:
        st.markdown("### ③-2 국장 전용 검증 · 미장/환율/수급/뉴스")
        st.caption("국장은 전일 미장, 환율, 외국인·기관 수급, 국내뉴스/DART 공시가 예측 무효화와 후보 압축에 중요합니다.")
        render_kr_api_disconnected_notice_v9954()
        snap = kr_market_index_snapshot_v9952()
        result["score"] += int(snap.get("score", 0))
        result["reasons"].extend(snap.get("reasons", []))
        if snap.get("data"):
            st.dataframe(pd.DataFrame(snap["data"]), use_container_width=True, hide_index=True)

        theme_df = kr_theme_strength_v9952(snap)
        if theme_df is not None and not theme_df.empty:
            with st.expander("국장 테마 강도 힌트", expanded=False):
                st.dataframe(theme_df, use_container_width=True, hide_index=True)

        # event/news reasons already collected through event_context
        should_warn, ev_reasons, risk_mult = invalidation_reasons_from_context_v9951(event_context)
        if ev_reasons:
            news_score = kr_news_keyword_score_v9952(ev_reasons)
            result["score"] += int(news_score.get("score", 0))
            result["reasons"].extend(news_score.get("reasons", []))
            with st.expander("국내뉴스·공시 리스크 힌트", expanded=False):
                for r in ev_reasons[:8]:
                    st.markdown(f"- {r}")

        render_kr_preopen_expected_price_panel_v9952(log_df)

        with st.expander("외국인·기관 수급 API 연결 안내", expanded=False):
            st.markdown("""
- **권장 1순위: 한국투자증권 KIS Open API**
  - 실시간/준실시간 국내주식 현재가, 호가, 체결, 일부 투자자/프로그램 관련 데이터 연결 후보
  - 장중 자동 무효화 경고까지 가려면 증권사 API가 가장 현실적입니다.
- **권장 2순위: KRX Open API**
  - 공식 통계성 데이터, 일별 투자자별 거래실적/시장 데이터 확인 후보
  - 장중 실시간보다는 장마감 후 검증·복기용에 가깝습니다.
- **보조: pykrx / 네이버금융 스크래핑**
  - 빠른 구현은 가능하지만 지연/차단/구조변경 리스크가 있어 핵심 로직의 유일한 소스로 쓰기 어렵습니다.
""")

        # summary
        dedup = []
        for r in result["reasons"]:
            if r and r not in dedup:
                dedup.append(r)
        result["reasons"] = dedup[:8]
        if result["score"] <= -4:
            st.error("국장 검증 결과: 리스크 우위 · 신규 진입 보수")
        elif result["score"] <= -1:
            st.warning("국장 검증 결과: 확인 필요 · 진입가 대기 우선")
        else:
            st.success("국장 검증 결과: 중립~우호 · 예측 후보 조건 확인")
        if result["reasons"]:
            st.caption("주요 사유: " + " / ".join(result["reasons"][:4]))
    except Exception as e:
        st.warning(f"국장 전용 검증 패널 오류: {e}")
    return result

# v9.9.51 prediction lock / invalidation helpers
def is_regular_market_session_v9951(market: str, now_kst: datetime | None = None) -> bool:
    """장중에는 장전 예측값을 재생성하지 않고 고정하기 위한 세션 판별."""
    try:
        session = market_session_context(market)
        return str(session.get("session", "")) == "regular"
    except Exception:
        return False


def prediction_generation_allowed_v9951(market: str, now_kst: datetime | None = None) -> tuple[bool, str]:
    """장전/장마감 후에는 예측 생성 가능, 정규장 중에는 예측값 고정."""
    try:
        session = market_session_context(market) if now_kst is None else (
            korean_session_context(now_kst) if market == "한국주식" else us_session_context(now_kst)
        )
        session_type = str(session.get("session", ""))
        session_label = str(session.get("session_label", ""))
        if session_type == "regular":
            et_hint = ""
            try:
                now_et = session.get("now_et")
                if market != "한국주식" and now_et is not None:
                    et_hint = f" [뉴욕 {now_et.strftime('%m/%d %H:%M')} ET · 정규 09:30~16:00 ET]"
            except Exception:
                pass
            return (
                False,
                f"{session_label}{et_hint} · 장중에는 장전 예측값을 고정하고 현재가/뉴스/리스크만 갱신합니다.",
            )
        return True, f"{session_label} · 예측 생성/갱신 가능 시간대입니다."
    except Exception as e:
        return True, f"세션 확인 실패로 기존 방식 유지: {e}"


def invalidation_reasons_from_context_v9951(event_context: dict[str, Any] | None) -> tuple[bool, list[str], float]:
    """뉴스/매크로/공시 이벤트에서 예측 무효화 가능 사유를 짧게 추출."""
    ctx = event_context or {}
    reasons: list[str] = []
    risk_mult = safe_float(ctx.get("risk_mult"), 1.0)

    event_names = [str(x).strip() for x in ctx.get("event_names", []) if str(x).strip()]
    event_types = [str(x).strip() for x in ctx.get("event_types", []) if str(x).strip()]
    news_items = [str(x).strip() for x in ctx.get("auto_news_items", []) if str(x).strip()]
    news_score = safe_float(ctx.get("auto_news_score"), 0.0)

    major_types = {"FOMC", "CPI", "PPI", "고용지표", "NEWS_ALARM", "NEWS_ALARM_BLOCK", "EARNINGS", "DART_RISK"}
    if risk_mult >= 1.40:
        reasons.append(f"이벤트 변동성 배수 상승: risk_mult {risk_mult:.2f}")

    for n, t in zip(event_names, event_types if len(event_types) == len(event_names) else [""] * len(event_names)):
        if n and n != "주요 이벤트 없음":
            if (t in major_types) or any(k in n.upper() for k in ["FOMC", "CPI", "PPI", "고용", "NEWS", "실적", "관세", "전쟁", "유가", "DART", "공시"]):
                reasons.append(f"{n}")

    if abs(news_score) >= 3:
        direction = "악재성" if news_score < 0 else "호재성"
        reasons.append(f"{direction} 뉴스 점수 감지: {news_score:+.0f}")

    for item in news_items[:3]:
        if item and item not in reasons:
            reasons.append(item)

    # 중복 제거
    deduped: list[str] = []
    for r in reasons:
        if r and r not in deduped:
            deduped.append(r)

    try:
        kr_extra = st.session_state.get("kr_v9952_invalidation_reasons", [])
        if kr_extra:
            for r in kr_extra:
                if r and r not in deduped:
                    deduped.append(str(r))
    except Exception:
        pass
    should_warn = bool(deduped) and (risk_mult >= 1.25 or abs(news_score) >= 2 or any("NEWS" in t for t in event_types) or len(deduped) > 0)
    return should_warn, deduped[:7], risk_mult


def render_prediction_invalidation_panel_v9951(market: str, event_context: dict[str, Any] | None) -> None:
    """장중에는 예측값을 바꾸지 않고, 예측 무효화 가능성만 이유와 함께 표시."""
    try:
        mode_label = "국장" if market == "한국주식" else "미장"
        session = market_session_context(market)
        session_type = str(session.get("session", ""))
        session_label = str(session.get("session_label", ""))
        should_warn, reasons, risk_mult = invalidation_reasons_from_context_v9951(event_context)

        if session_type != "regular":
            with st.expander("④ 예측 무효화 경고", expanded=False):
                st.caption(f"{mode_label} 현재 상태: {session_label}")
                st.info("정규장 진행 전/후입니다. 장전 예측 생성 또는 장마감 후 복기 기준으로 운용합니다.")
            return

        if should_warn:
            st.markdown("## ④ 예측 무효화 경고")
            st.error("장중 돌발 변수로 기존 장전 예측의 무효화 가능성이 있습니다. 예측가를 새로 바꾸는 대신 신규 진입 보류/비중 축소/손절 기준 확인을 우선합니다.")
            st.caption(f"{mode_label} 현재 상태: {session_label} · 기존 예측값 고정 · risk_mult {risk_mult:.2f}")
            st.markdown("**감지된 사유**")
            for r in reasons:
                st.markdown(f"- {r}")
        else:
            with st.expander("④ 예측 무효화 경고", expanded=False):
                st.caption(f"{mode_label} 현재 상태: {session_label} · 기존 예측값 고정")
                st.success("현재 자동 감지 기준에서는 장전 예측을 무효화할 만한 대형 이벤트가 뚜렷하지 않습니다.")
                st.caption("장중에는 예측가/진입가/손절가/익절가를 다시 계산하지 않고, 현재가·뉴스·공시·수급 리스크만 확인합니다.")
    except Exception as e:
        with st.expander("④ 예측 무효화 경고", expanded=False):
            st.warning(f"무효화 경고 표시 중 오류: {e}")

def run_app_startup_sync(market: str, max_items: int = 10, force: bool = False) -> dict[str, Any]:
    """앱 실행 시 1회 자동 동기화.

    순서:
    1) 지난 예측의 실제 OHLC 결과 업데이트
    2) 현재 target_date 예측을 중복 추가하지 않고 upsert 방식으로 저장/갱신

    Streamlit은 버튼/위젯 조작 때마다 재실행되므로, 같은 시장/대상일은 기본적으로 하루 1회만 자동 실행합니다.
    """
    result: dict[str, Any] = {
        "ran": False, "skipped": False, "market": market, "target_date": "",
        "updated_actuals": 0, "saved_or_updated_predictions": 0, "tried": 0,
        "message": "", "before": {}, "after": {},
    }
    try:
        session = market_session_context(market)
        target_date = session.get("target_date") or next_trading_day_auto(market, date.today())
        result["target_date"] = str(target_date)
        state_key = f"{market}:{target_date}"
        ss_key = f"startup_sync_done_{state_key}"
        state = read_startup_sync_state()
        if not force and (st.session_state.get(ss_key) or state.get("last_key") == state_key):
            result.update({"skipped": True, "message": f"이미 동기화 완료: {state_key}"})
            return result

        before = count_prediction_rows(market, target_date)
        result["before"] = before
        append_startup_sync_log(f"start market={market} target={target_date} force={force} before={before}")

        log_df = load_prediction_log()
        updated_df, updated_n = update_actual_results(log_df)
        result["updated_actuals"] = int(updated_n)

        # v9.9.51: 장중에는 장전 예측값을 고정한다.
        # 앱을 다시 열어도 현재 target_date의 예측가/진입가/손절가/익절가는 재생성하지 않는다.
        allowed_generate, lock_reason = prediction_generation_allowed_v9951(market)
        result["prediction_locked"] = not allowed_generate
        result["prediction_lock_reason"] = lock_reason
        if not force and not allowed_generate:
            after = count_prediction_rows(market, target_date)
            result["after"] = after
            result["ran"] = True
            result["message"] = (
                f"실제결과 {updated_n}건 업데이트 · 장중 예측값 고정 · "
                f"예측 재생성 없음 · 대상일 {target_date}"
            )
            state.update({
                "last_key": state_key,
                "last_market": market,
                "last_target_date": str(target_date),
                "last_run_at": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S KST"),
                "last_result": result,
            })
            write_startup_sync_state(state)
            st.session_state[ss_key] = True
            append_startup_sync_log(f"locked market={market} target={target_date} updated={updated_n} reason={lock_reason}")
            return result

        tickers = [normalize_ticker(t, market) for t in watchlist_symbols(market) if str(t).strip()]
        tickers = list(dict.fromkeys(tickers))
        if max_items and max_items > 0:
            tickers = tickers[:max_items]
        result["tried"] = int(len(tickers))

        if tickers:
            bench_df = fetch_benchmark_snapshots()
            event_context = build_auto_event_context(
                target=target_date,
                ticker="",
                manual_events=[],
                use_bls_macro=(market == "미국주식"),
                use_earnings=False,
                use_news=True,
                market=market,
            )
            saved_count, messages = auto_generate_predictions_for_watchlist(
                tickers=tickers,
                market=market,
                target_date=target_date,
                period_years=1.0,
                log_df=load_prediction_log(),
                bench_df=bench_df,
                event_context=event_context,
                max_items=len(tickers),
                target_coverage=0.75,
                upsert_existing=True,
            )
            result["saved_or_updated_predictions"] = int(saved_count)
            result["messages"] = messages[-8:]
        else:
            result["message"] = "관심종목이 비어 있어 예측 생성을 건너뜀"

        after = count_prediction_rows(market, target_date)
        result["after"] = after
        result["ran"] = True
        result["message"] = (
            f"동기화 완료 · 실제결과 {updated_n}건 업데이트 · "
            f"예측 {result['saved_or_updated_predictions']}건 저장/갱신 · 대상일 {target_date}"
        )
        state.update({
            "last_key": state_key,
            "last_market": market,
            "last_target_date": str(target_date),
            "last_run_at": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S KST"),
            "last_result": result,
        })
        write_startup_sync_state(state)
        st.session_state[ss_key] = True
        append_startup_sync_log(f"done market={market} target={target_date} updated={updated_n} saved={result['saved_or_updated_predictions']} after={after}")
        return result
    except Exception as e:
        result["message"] = f"동기화 실패: {e}"
        append_startup_sync_log(result["message"])
        return result


def _runner_print(message: str) -> None:
    try:
        print(message, flush=True)
    except UnicodeEncodeError:
        import sys

        encoding = getattr(sys.stdout, "encoding", None) or "utf-8"
        safe_message = str(message).encode(encoding, errors="backslashreplace").decode(encoding, errors="replace")
        print(safe_message, flush=True)


def _runner_try_swing_scan_after_predict(market: str, files_updated: list[str]) -> tuple[dict[str, Any] | None, str]:
    """예측 잠금·빈 watchlist와 무관하게 스윙 스캔을 시도한다. (swing_res, error_message)"""
    run_swing = str(os.environ.get("RUN_SWING_AFTER_PREDICT", "1") or "1").strip().lower() not in {"0", "false", "no", "off"}
    if not run_swing:
        return None, ""
    try:
        swing_limit = int(max(0, safe_float(os.environ.get("SWING_SCAN_LIMIT", "0"), 0)))
        res = run_swing_candidate_scan(market, max_symbols=swing_limit)
        stats = res.get("scan_stats") or {}
        _runner_print(
            f"[runner] swing_scan paths={res.get('paths')} scanned={res.get('scanned')} "
            f"universe_in={stats.get('input_universe_count', '-')}"
        )
        for _p in (res.get("paths") or {}).values():
            if _p:
                files_updated.append(str(_p))
        return res, ""
    except Exception as ex:
        _runner_print(f"[runner] swing_scan_error={ex}")
        try:
            log_app_event(
                "runner",
                "warning",
                f"swing_scan: {ex}",
                function_name="_runner_try_swing_scan_after_predict",
                market=market,
            )
        except Exception:
            pass
        return None, str(ex)[:500]


def run_headless_runner(action: str) -> int:
    """작업스케줄러용 headless runner. Streamlit 서버를 열지 않고 필요한 작업만 수행한다."""
    action = str(action or "").strip().lower()
    _runner_print(f"[runner] action={action} app_version={APP_VERSION}")
    _runner_print(f"[runner] cwd={Path.cwd()}")
    _runner_print(f"[runner] started_at={datetime.now(KST).strftime('%Y-%m-%d %H:%M:%S KST')}")

    try:
        REPORT_DIR.mkdir(exist_ok=True)
        BACKUP_DIR.mkdir(exist_ok=True)
        Path("logs").mkdir(exist_ok=True)

        if action == "prediction_adjustment":
            from core.prediction_adjustment_engine import build_prediction_adjustments

            res = build_prediction_adjustments()
            _runner_print(f"[runner] prediction_adjustment={json.dumps(res, ensure_ascii=False)}")
            _runner_print("[runner] done")
            return 0 if res.get("ok") else 2

        if action == "market_regime":
            from core.market_regime_engine import build_market_regime_summary

            res = build_market_regime_summary("한국주식", write=True)
            _runner_print(f"[runner] market_regime={json.dumps(res, ensure_ascii=False)}")
            _runner_print("[runner] done")
            return 0

        if action == "adjustment_performance":
            from core.adjustment_performance_engine import run_adjustment_performance

            res = run_adjustment_performance()
            _runner_print(f"[runner] adjustment_performance={json.dumps(res, ensure_ascii=False)}")
            _runner_print("[runner] done")
            return 0 if res.get("ok") else 2

        if action == "no_buy_filter":
            from core.no_buy_filter_engine import save_no_buy_summary

            res = save_no_buy_summary()
            _runner_print(f"[runner] no_buy_filter={json.dumps(res, ensure_ascii=False)}")
            _runner_print("[runner] done")
            return 0 if res.get("ok") else 2

        if action == "portfolio_response":
            from core.portfolio_response_engine import save_portfolio_response_summary

            res = save_portfolio_response_summary()
            _runner_print(f"[runner] portfolio_response={json.dumps(res, ensure_ascii=False)}")
            _runner_print("[runner] done")
            return 0 if res.get("ok") else 2

        if action == "error_analysis":
            from core.prediction_error_analysis import run_error_analysis

            res = run_error_analysis()
            _runner_print(f"[runner] error_analysis={json.dumps(res, ensure_ascii=False)}")
            _runner_print("[runner] done")
            return 0 if res.get("ok") else 2

        if action in {"us_swing_scan", "kr_swing_scan", "swing_scan"}:
            markets = (
                ["미국주식", "한국주식"]
                if action == "swing_scan"
                else ["미국주식" if action == "us_swing_scan" else "한국주식"]
            )
            limit = int(max(0, safe_float(os.environ.get("SWING_SCAN_LIMIT", "0"), 0)))
            for market in markets:
                result = run_swing_candidate_scan(market, max_symbols=limit)
                _runner_print(
                    "[runner] swing_scan_done "
                    f"market={result.get('market')} scanned={result.get('scanned')} "
                    f"A={result.get('a_count')} B={result.get('b_count')} C={result.get('c_count')} "
                    f"elapsed={result.get('elapsed_sec')}s"
                )
                _runner_print(f"[runner] swing_scan_paths={result.get('paths')}")
            _runner_print("[runner] done")
            return 0

        if action in {"us_sync", "kr_sync"}:
            market = "미국주식" if action == "us_sync" else "한국주식"
            session = market_session_context(market)
            target_date = session.get("target_date") or next_trading_day_auto(market, date.today())
            log_df = load_prediction_log()
            updated_df, updated_n = update_actual_results(log_df)
            allowed_generate, lock_reason = prediction_generation_allowed_v9951(market)
            if not allowed_generate:
                _runner_print(f"[runner] sync_locked updated={updated_n} target_date={target_date} reason={lock_reason}")
                _runner_print("[runner] done")
                return 0
            tickers = [normalize_ticker(t, market) for t in watchlist_symbols(market) if str(t).strip()]
            tickers = list(dict.fromkeys(tickers))
            bench_df = fetch_benchmark_snapshots()
            event_context = build_auto_event_context(
                target=target_date, ticker="", manual_events=[],
                use_bls_macro=(market == "미국주식"), use_earnings=False, use_news=True, market=market,
            )
            saved_count, messages = auto_generate_predictions_for_watchlist(
                tickers=tickers, market=market, target_date=target_date, period_years=1.0,
                log_df=load_prediction_log(), bench_df=bench_df, event_context=event_context,
                max_items=len(tickers), target_coverage=0.75, upsert_existing=True,
            )
            for msg in messages:
                _runner_print(f"[runner] {msg}")
            _runner_print(f"[runner] sync_done updated={updated_n} saved_or_updated={saved_count} tried={len(tickers)} target_date={target_date}")
            _runner_print("[runner] done")
            return 0

        if action in {"us_update", "kr_update", "update"}:
            log_df = load_prediction_log()
            updated_df, updated_n = update_actual_results(log_df)
            _runner_print(f"[runner] update_done updated={updated_n} rows={len(updated_df)}")
            try:
                from core.validation_engine import run_from_legacy_predictions

                validation_res = run_from_legacy_predictions(max_rows=1000)
                _runner_print(f"[runner] decision_system_export={json.dumps(validation_res, ensure_ascii=False)}")
            except Exception as validation_error:
                _runner_print(f"[runner] decision_system_export_skip={validation_error}")
            try:
                market_for_report = "미국주식" if action == "us_update" else "한국주식" if action == "kr_update" else "미국주식"
                paths = save_latest_order_reports(load_prediction_log(), market_for_report)
                _runner_print(f"[runner] latest_reports={paths}")
                bt_paths = save_backtest_snapshot_v9985(load_prediction_log(), market_for_report)
                _runner_print(f"[runner] backtest_snapshot={bt_paths}")
            except Exception as report_error:
                _runner_print(f"[runner] latest_report_skip={report_error}")
            _runner_print("[runner] done")
            return 0

        if action == "no_buy_self_check":
            chk = run_no_buy_rule_self_check()
            print(json.dumps(chk, ensure_ascii=False, indent=2), flush=True)
            return 0 if chk.get("all_passed") else 3

        if action in {"us_predict_lock_skip", "kr_predict_lock_skip"}:
            market = "미국주식" if action == "us_predict_lock_skip" else "한국주식"
            session = market_session_context(market)
            app_rel = compute_app_reliability_score(market, load_prediction_log())
            _runner_paper_and_status_finalize(
                market,
                result="skipped",
                skip_reason="runner_lock_file_present",
                files_updated=[],
                allowed_generate=True,
                lock_reason="",
                swing_res=None,
                app_rel=app_rel,
                session=session,
                runner_skip_reason="runner lock 파일로 인해 예측 본 실행 생략(.bat)",
                swing_scan_error="",
            )
            _runner_print("[runner] lock_skip status+paper written")
            return 0

        if action in {"us_predict", "kr_predict"}:
            market = "미국주식" if action == "us_predict" else "한국주식"
            files_updated: list[str] = []
            session = market_session_context(market)
            target_date = session["target_date"]
            app_rel = compute_app_reliability_score(market, load_prediction_log())
            allowed_generate, lock_reason = prediction_generation_allowed_v9951(market)
            force_predict = str(os.environ.get("RUNNER_FORCE_PREDICT", "") or "").strip().lower() in {"1", "true", "yes", "y", "on"}
            if force_predict and not allowed_generate:
                allowed_generate = True
                lock_reason = f"{lock_reason} · RUNNER_FORCE_PREDICT=1로 실패 복구 실행"
            if not allowed_generate:
                _runner_print(f"[runner] predict_locked target_date={target_date} reason={lock_reason}")
                swing_res, swing_err = _runner_try_swing_scan_after_predict(market, files_updated)
                swing_ok = bool(
                    swing_res
                    and isinstance(swing_res.get("df"), pd.DataFrame)
                    and not swing_res["df"].empty
                )
                paper_skip = "" if swing_ok else f"예측 생성 잠금: {lock_reason}"[:220]
                _runner_paper_and_status_finalize(
                    market,
                    result="partial",
                    skip_reason="prediction_generation_locked",
                    files_updated=files_updated,
                    allowed_generate=False,
                    lock_reason=lock_reason,
                    swing_res=swing_res,
                    app_rel=app_rel,
                    session=session,
                    saved_predictions=0,
                    tried=0,
                    runner_skip_reason=paper_skip,
                    swing_scan_error=swing_err,
                )
                _sync_decision_system_predict_runner_status(market, 0)
                _runner_print("[runner] done")
                return 0
            tickers = watchlist_symbols(market)
            tickers = [normalize_ticker(t, market) for t in tickers if str(t).strip()]
            tickers = list(dict.fromkeys(tickers))
            runner_max_items = int(max(0, safe_float(os.environ.get("RUNNER_MAX_ITEMS", "0"), 0)))
            if runner_max_items > 0:
                tickers = tickers[:runner_max_items]

            _runner_print(f"[runner] market={market}")
            _runner_print(f"[runner] session={session.get('session_label', '')}")
            _runner_print(f"[runner] target_date={target_date}")
            _runner_print(f"[runner] watchlist_count={len(tickers)}")

            if not tickers:
                _runner_print("[runner] watchlist is empty (predictions skipped; swing may still run)")
                swing_res, swing_err = _runner_try_swing_scan_after_predict(market, files_updated)
                swing_ok = bool(
                    swing_res
                    and isinstance(swing_res.get("df"), pd.DataFrame)
                    and not swing_res["df"].empty
                )
                paper_skip = "" if swing_ok else (
                    "국장 관심종목 없음 — 관심종목 예측 생략"
                    if market == "한국주식"
                    else "관심종목 심볼이 비어 있어 예측 배치 생략"
                )
                _runner_paper_and_status_finalize(
                    market,
                    result="partial",
                    skip_reason="empty_watchlist",
                    error_message="",
                    files_updated=files_updated,
                    allowed_generate=True,
                    lock_reason=lock_reason,
                    swing_res=swing_res,
                    app_rel=app_rel,
                    session=session,
                    saved_predictions=0,
                    tried=0,
                    runner_skip_reason=paper_skip,
                    swing_scan_error=swing_err,
                )
                _sync_decision_system_predict_runner_status(market, 0)
                return 0

            log_df = load_prediction_log()
            bench_df = fetch_benchmark_snapshots() if market == "미국주식" else fetch_benchmark_snapshots()
            bench_df = normalize_benchmark_df(bench_df) if market == "미국주식" else bench_df
            event_context = build_auto_event_context(
                target=target_date,
                ticker="",
                manual_events=[],
                use_bls_macro=(market == "미국주식"),
                use_earnings=False,
                use_news=True,
                market=market,
            )

            saved_count, messages = auto_generate_predictions_for_watchlist(
                tickers=tickers,
                market=market,
                target_date=target_date,
                period_years=1.0,
                log_df=log_df,
                bench_df=bench_df,
                event_context=event_context,
                max_items=len(tickers),
                target_coverage=0.75,
                upsert_existing=True,
            )

            for msg in messages:
                _runner_print(f"[runner] {msg}")

            _runner_print(f"[runner] predict_done saved={saved_count} tried={len(tickers)} target_date={target_date}")
            files_updated.append(str(PREDICTION_FILE))

            try:
                latest_log = load_prediction_log()
                report_path = save_daily_summary(latest_log, None, market)
                order_paths = save_latest_order_reports(latest_log, market)
                _runner_print(f"[runner] report={report_path}")
                _runner_print(f"[runner] latest_reports={order_paths}")
                files_updated.append(str(report_path))
                for _p in (order_paths or {}).values():
                    files_updated.append(str(_p))
            except Exception as report_error:
                _runner_print(f"[runner] report_skip={report_error}")

            swing_res, swing_err = _runner_try_swing_scan_after_predict(market, files_updated)

            try:
                bt_paths = save_backtest_snapshot_v9985(load_prediction_log(), market)
                _runner_print(f"[runner] backtest_snapshot={bt_paths}")
                for _p in (bt_paths or {}).values():
                    if _p and str(_p) not in {"{}", "nan"}:
                        files_updated.append(str(_p))
            except Exception as bt_err:
                _runner_print(f"[runner] backtest_snapshot_skip={bt_err}")

            run_swing_flag = str(os.environ.get("RUN_SWING_AFTER_PREDICT", "1") or "1").strip().lower() not in {
                "0",
                "false",
                "no",
                "off",
            }
            run_out = "success"
            if run_swing_flag and swing_res is not None and int(swing_res.get("a_count", 0)) == 0:
                run_out = "no_candidate"
            _runner_paper_and_status_finalize(
                market,
                result=run_out,
                files_updated=files_updated,
                allowed_generate=True,
                lock_reason=lock_reason,
                swing_res=swing_res,
                app_rel=app_rel,
                session=session,
                saved_predictions=int(saved_count),
                tried=len(tickers),
                swing_scan_error=swing_err,
            )
            _sync_decision_system_predict_runner_status(market, 0)
            _runner_print("[runner] done")
            return 0

        _runner_print(f"[runner] ERROR: unknown action {action}")
        return 2

    except Exception as e:
        import traceback
        log_app_event("runner", "error", f"{action}: {e}")
        _runner_print(f"[runner] ERROR: {e}")
        traceback.print_exc()
        try:
            if str(action).strip().lower() in {"us_predict", "kr_predict"}:
                mkt = "미국주식" if str(action).strip().lower() == "us_predict" else "한국주식"
                sess = market_session_context(mkt)
                app_rel = compute_app_reliability_score(mkt, load_prediction_log())
                _runner_paper_and_status_finalize(
                    mkt,
                    result="failed",
                    skip_reason="runner_exception",
                    error_message=str(e)[:500],
                    files_updated=[],
                    allowed_generate=True,
                    lock_reason="",
                    swing_res=None,
                    app_rel=app_rel,
                    session=sess,
                    skip_paper=True,
                    swing_scan_error="",
                )
                _sync_decision_system_predict_runner_status(mkt, 1)
        except Exception:
            pass
        return 1



