@st.cache_data(ttl=45, show_spinner=False)
def fetch_kr_naver_price_snapshot_v9922(symbol: str) -> dict[str, Any]:
    """국장 현재가/등락률은 yfinance가 느리거나 장중 지연될 수 있어 Naver를 우선 사용한다."""
    result = {"symbol": symbol, "used_symbol": symbol, "last_price": np.nan, "prev_close": np.nan, "change_pct": np.nan, "last_time": "", "source": "Naver Finance", "ok": False, "error": ""}
    try:
        import requests
        from bs4 import BeautifulSoup
        code = normalize_ticker(symbol, "한국주식").replace(".KS", "").replace(".KQ", "")
        url = f"https://finance.naver.com/item/main.naver?code={code}"
        headers = {"User-Agent": "Mozilla/5.0", "Referer": "https://finance.naver.com/"}
        r = requests.get(url, headers=headers, timeout=6)
        if r.status_code != 200:
            result["error"] = f"http_{r.status_code}"
            return result
        soup = BeautifulSoup(r.text, "html.parser")
        price_tag = soup.select_one("p.no_today span.blind")
        if not price_tag:
            result["error"] = "price_not_found"
            return result
        last_price = safe_float(price_tag.get_text(strip=True).replace(",", ""), np.nan)
        pct_val = np.nan
        # no_exday 안에는 전일대비 가격과 등락률 blind가 같이 들어오는 경우가 많다.
        blinds = [x.get_text(strip=True).replace(",", "") for x in soup.select("p.no_exday span.blind")]
        for b in blinds:
            if "%" in b or re.fullmatch(r"[-+]?\d+(\.\d+)?", b):
                try:
                    v = float(str(b).replace("%", ""))
                    if abs(v) <= 30:
                        pct_val = v
                except Exception:
                    pass
        text_all = soup.get_text(" ", strip=True)
        if np.isnan(pct_val):
            m = re.search(r"등락률\s*([+-]?\d+(?:\.\d+)?)%", text_all)
            if m:
                pct_val = safe_float(m.group(1), np.nan)
        result.update({
            "used_symbol": code,
            "last_price": last_price,
            "change_pct": pct_val,
            "last_time": datetime.now(KST).strftime("%m-%d %H:%M KST"),
            "source": "Naver Finance live/delayed",
            "ok": not np.isnan(last_price),
        })
        if not np.isnan(last_price) and not np.isnan(pct_val):
            try:
                result["prev_close"] = last_price / (1 + pct_val / 100)
            except Exception:
                pass
        return result
    except Exception as e:
        result["error"] = str(e)[:160]
        return result


def fetch_watch_snapshot(symbol: str, market: str) -> dict[str, Any]:  # type: ignore[override]
    if market == "한국주식":
        naver = fetch_kr_naver_price_snapshot_v9922(symbol)
        if bool(naver.get("ok")):
            return naver
    return _ORIG_fetch_watch_snapshot_v9922(symbol, market)


def kr_macro_score_lookup_v9922() -> dict[str, float]:
    """국장 테마점수 보정용 주요 지표 등락률."""
    out = {"kospi": 0.0, "kosdaq": 0.0, "soxx": 0.0, "qqq": 0.0, "oil": 0.0, "us10y": 0.0, "fx": 0.0}
    try:
        df = fetch_macro_dashboard_snapshots("한국주식")
        if isinstance(df, pd.DataFrame) and not df.empty:
            for _, r in df.iterrows():
                sym = str(r.get("심볼", ""))
                raw = str(r.get("등락률", "")).replace("%", "").replace("+", "").strip()
                val = safe_float(raw, 0.0)
                if sym == "^KS11": out["kospi"] = val
                elif sym == "^KQ11": out["kosdaq"] = val
                elif sym == "SOXX": out["soxx"] = val
                elif sym == "^IXIC": out["qqq"] = val
                elif sym == "CL=F": out["oil"] = val
                elif sym == "^TNX": out["us10y"] = val
                elif sym == "KRW=X": out["fx"] = val
    except Exception:
        pass
    return out


def korean_theme_score(symbol: str, meta: dict[str, Any], us_bench_df: pd.DataFrame, event_context: dict[str, Any]) -> int:  # type: ignore[override]
    base = _ORIG_korean_theme_score_v9922(symbol, meta, us_bench_df, event_context)
    theme = (str(meta.get("theme", "")) + " " + str(meta.get("sector_proxy", "")) + " " + str(meta.get("group", ""))).lower()
    macro = kr_macro_score_lookup_v9922()
    extra = 0
    # 반도체/HBM: 미국 반도체와 나스닥이 핵심 선행지표
    if any(k in theme for k in ["반도체", "hbm", "ai"]):
        extra += 1 if macro["soxx"] > 0.4 else -1 if macro["soxx"] < -0.8 else 0
        extra += 1 if macro["qqq"] > 0.4 else -1 if macro["qqq"] < -0.8 else 0
    # 항공: 유가/환율 부담
    if "항공" in theme:
        extra += 1 if macro["oil"] < -0.8 else -1 if macro["oil"] > 1.2 else 0
        extra += 1 if macro["fx"] < 0.2 else -1 if macro["fx"] > 0.5 else 0
    # 건설/2차전지: 금리 상승 부담
    if any(k in theme for k in ["건설", "2차전지", "전기차"]):
        extra += 1 if macro["us10y"] < -0.5 else -1 if macro["us10y"] > 0.5 else 0
    # 전력/조선/방산은 시장 강도와 테마 유지력 반영
    if any(k in theme for k in ["전력", "원전", "방산", "우주", "조선"]):
        extra += 1 if macro["kospi"] > 0.3 or macro["kosdaq"] > 0.4 else 0
    # 자동차/조선 수출주는 원화 약세가 단기 우호일 수 있으나 급등은 부담
    if any(k in theme for k in ["자동차", "조선"]):
        extra += 1 if 0.1 <= macro["fx"] <= 0.7 else -1 if macro["fx"] > 1.0 else 0
    if safe_float(event_context.get("risk_mult"), 1.0) >= 1.5:
        extra -= 1
    return int(max(-3, min(3, base + extra)))


def kr_session_status_label_v9922() -> tuple[str, str]:
    ctx = korean_session_context()
    sess = str(ctx.get("session", ""))
    if sess in {"before_preopen", "expected_open"}:
        return "장전", "예상체결가·전일 미장·환율 확인 우선"
    if sess == "regular":
        return "장중", "현재가·거래량·VWAP/20일선 이탈 여부 확인"
    if sess == "afterclose":
        return "마감 후", "실제 OHLC 업데이트 후 다음 거래일 예측 생성"
    return "휴장/대기", "다음 거래일 기준으로 준비"


def build_kr_realtime_watch_table_v9922(max_items: int = 9) -> pd.DataFrame:
    rows = []
    wl = load_watchlist_df("한국주식")
    meta_map = watchlist_meta_map("한국주식")
    for raw in watchlist_symbols("한국주식")[:max_items]:
        sym = normalize_ticker(raw, "한국주식")
        meta = meta_map.get(sym, {})
        snap = fetch_watch_snapshot(sym, "한국주식")
        chg = safe_float(snap.get("change_pct"), np.nan)
        price = safe_float(snap.get("last_price"), np.nan)
        rows.append({
            "종목": meta.get("name") or korean_name_from_symbol(sym),
            "코드": sym,
            "현재가": fmt_price(price, "한국주식") if not np.isnan(price) else "-",
            "등락률": pct(chg) if not np.isnan(chg) else "-",
            "테마": meta.get("theme", ""),
            "위험도": meta.get("risk_level", "중"),
            "데이터": snap.get("source", "-"),
        })
    return pd.DataFrame(rows)


def render_kr_focus_panel_v9922(log_df: pd.DataFrame) -> None:
    """국장 화면에서 미장보다 부족했던 실전 준비 정보를 상단에 추가."""
    try:
        ctx = korean_session_context()
        status, guide = kr_session_status_label_v9922()
        wl = load_watchlist_df("한국주식")
        cur_target = ctx.get("target_date", "-")
        kr_rows = 0
        today_rows = 0
        if log_df is not None and not log_df.empty:
            kr_df = log_df[log_df.get("market", "").astype(str).eq("한국주식")] if "market" in log_df.columns else pd.DataFrame()
            kr_rows = len(kr_df)
            if not kr_df.empty and "target_date" in kr_df.columns:
                today_rows = int(kr_df[kr_df["target_date"].astype(str).eq(str(cur_target))].shape[0])
        st.markdown("### 🇰🇷 국장 실전 보강판")
        a,b,c,d = st.columns(4)
        a.metric("국장 상태", status)
        b.metric("예측 대상일", str(cur_target))
        c.metric("관심종목", f"{len(wl)}개")
        d.metric("대상일 예측", f"{today_rows}건")
        st.caption(f"운영 기준: {guide} · 국장 누적 예측기록 {kr_rows}건")
        table = build_kr_realtime_watch_table_v9922(max_items=9)
        if not table.empty:
            with st.expander("🇰🇷 등록 관심종목 현재가/테마", expanded=False):
                st.dataframe(table, use_container_width=True, hide_index=True)
        else:
            st.caption("등록된 국장 관심종목 없음")
        if status == "장전":
            st.info("장전에는 08:50~09:00 예상체결가를 단일종목 분석 영역에 입력하면 시초가 보정이 강하게 반영됩니다.")
        elif status == "장중":
            st.info("장중에는 예측값을 확정값으로 보지 말고, 우선진입가와 현재가 괴리율·거래량·손절선을 먼저 확인하세요.")
    except Exception as e:
        st.caption(f"국장 보강판 표시 생략: {e}")


