def scan_candidate_tickers_kr(
    tickers: list[str],
    log_df: pd.DataFrame,
    bench_df: pd.DataFrame,
    event_context: dict[str, Any],
    max_count: int = 30,
    min_score: int = 0,
) -> pd.DataFrame:  # type: ignore[override]
    df = _ORIG_scan_candidate_tickers_kr_v9922(tickers, log_df, bench_df, event_context, max_count=max_count, min_score=min_score)
    if df is None or df.empty:
        return df
    # 국장 후보표에 장중 해석 컬럼 추가
    outlook = []
    for _, r in df.iterrows():
        reason = []
        try:
            chg = safe_float(str(r.get("전일대비", "")).replace("%", "").replace("+", ""), np.nan)
            vol_txt = str(r.get("거래량배율", "")).replace("배", "")
            vol = safe_float(vol_txt, np.nan)
            if not np.isnan(chg):
                if chg >= 3:
                    reason.append("추격주의")
                elif chg <= -3:
                    reason.append("급락 후 반등확인")
                elif chg > 0:
                    reason.append("양봉 흐름")
            if not np.isnan(vol):
                if vol >= 1.5:
                    reason.append("거래량 동반")
                elif vol < 0.7:
                    reason.append("거래량 부족")
        except Exception:
            pass
        outlook.append(" / ".join(reason) if reason else "조건 확인")
    df.insert(min(5, len(df.columns)), "장중체크", outlook)
    return df



