# ══════════════════════════════════════════════
APP_VERSION = str(APP_VERSION) + " + KR v9.9.23"

_ORIG_fetch_kr_naver_price_snapshot_v9923 = fetch_kr_naver_price_snapshot_v9922
_ORIG_render_kr_focus_panel_v9923 = render_kr_focus_panel_v9922
_ORIG_fetch_watch_snapshot_v9923 = fetch_watch_snapshot


@st.cache_data(ttl=25, show_spinner=False)
def fetch_kr_naver_price_snapshot_v9923(symbol: str) -> dict[str, Any]:
    """네이버금융 현재가/등락률 파싱 보강.
    v9.9.22의 현재가 우선 구조는 유지하되, 등락률을 더 안정적으로 읽는다.
    """
    base = _ORIG_fetch_kr_naver_price_snapshot_v9923(symbol)
    if bool(base.get("ok")) and not np.isnan(safe_float(base.get("change_pct"), np.nan)):
        return base
    try:
        import requests
        from bs4 import BeautifulSoup
        code = normalize_ticker(symbol, "한국주식").replace(".KS", "").replace(".KQ", "")
        url = f"https://finance.naver.com/item/main.naver?code={code}"
        headers = {"User-Agent": "Mozilla/5.0", "Referer": "https://finance.naver.com/"}
        r = requests.get(url, headers=headers, timeout=6)
        if r.status_code != 200:
            return base
        soup = BeautifulSoup(r.text, "html.parser")
        out = dict(base)
        price_tag = soup.select_one("p.no_today span.blind")
        if price_tag:
            out["last_price"] = safe_float(price_tag.get_text(strip=True).replace(",", ""), np.nan)
            out["ok"] = not np.isnan(safe_float(out.get("last_price"), np.nan))
        # 상승/하락 클래스와 blind를 같이 보고 등락률을 안정적으로 추출
        ex = soup.select_one("p.no_exday")
        pct_val = np.nan
        if ex:
            txt = ex.get_text(" ", strip=True)
            m = re.search(r"([+-]?\d+(?:\.\d+)?)\s*%", txt)
            if m:
                pct_val = safe_float(m.group(1), np.nan)
            if np.isnan(pct_val):
                blind_vals = [x.get_text(strip=True).replace(",", "") for x in ex.select("span.blind")]
                # 보통 [전일대비가격, 등락률] 순서로 들어온다. 30% 미만 숫자를 등락률 후보로 사용.
                for b in reversed(blind_vals):
                    v = safe_float(str(b).replace("%", ""), np.nan)
                    if not np.isnan(v) and abs(v) <= 30:
                        pct_val = v
                        break
            # no_down이면 음수 보정
            if not np.isnan(pct_val):
                cls = " ".join(ex.get("class", [])) + " " + str(ex)
                if "no_down" in cls and pct_val > 0:
                    pct_val = -pct_val
        if not np.isnan(pct_val):
            out["change_pct"] = pct_val
            lp = safe_float(out.get("last_price"), np.nan)
            if not np.isnan(lp) and lp > 0:
                try:
                    out["prev_close"] = lp / (1 + pct_val / 100)
                except Exception:
                    pass
        out["source"] = "Naver Finance live/delayed v9923"
        out["last_time"] = datetime.now(KST).strftime("%m-%d %H:%M KST")
        return out
    except Exception:
        return base


def fetch_watch_snapshot(symbol: str, market: str) -> dict[str, Any]:  # type: ignore[override]
    if market == "한국주식":
        naver = fetch_kr_naver_price_snapshot_v9923(symbol)
        if bool(naver.get("ok")):
            return naver
    return _ORIG_fetch_watch_snapshot_v9923(symbol, market)


def latest_prediction_batch_v9923(log_df: pd.DataFrame, market: str) -> pd.DataFrame:
    """현재 target_date 예측이 없으면 가장 최근 저장 배치를 반환한다."""
    if log_df is None or log_df.empty or "market" not in log_df.columns:
        return pd.DataFrame()
    df = log_df[log_df["market"].astype(str).eq(market)].copy()
    if df.empty:
        return df
    try:
        ctx = market_session_context(market)
        target = str(ctx.get("target_date", ""))
        if target and "target_date" in df.columns:
            cur = df[df["target_date"].astype(str).eq(target)].copy()
            if not cur.empty:
                return cur
    except Exception:
        pass
    if "created_at" in df.columns:
        df["_created_dt"] = pd.to_datetime(df["created_at"], errors="coerce")
        last_dt = df["_created_dt"].max()
        if pd.notna(last_dt):
            return df[df["_created_dt"].eq(last_dt)].drop(columns=["_created_dt"], errors="ignore")
    if "target_date" in df.columns:
        td = pd.to_datetime(df["target_date"], errors="coerce")
        if td.notna().any():
            last_target = str(td.max().date())
            return df[df["target_date"].astype(str).eq(last_target)].copy()
    return df.tail(20).copy()


def kr_data_health_v9923(log_df: pd.DataFrame) -> pd.DataFrame:
    rows = []
    ctx = korean_session_context()
    target = str(ctx.get("target_date", ""))
    if log_df is None or log_df.empty or "market" not in log_df.columns:
        return pd.DataFrame([{"항목":"predictions.csv", "상태":"기록 없음", "내용":"아직 국장 예측 기록이 없습니다."}])
    kr = log_df[log_df["market"].astype(str).eq("한국주식")].copy()
    rows.append({"항목":"국장 전체 예측 기록", "상태":"정상" if len(kr) else "부족", "내용":f"{len(kr)}건"})
    if kr.empty:
        return pd.DataFrame(rows)
    if "target_date" in kr.columns:
        cur_n = int(kr[kr["target_date"].astype(str).eq(target)].shape[0]) if target else 0
        rows.append({"항목":"현재 대상일 예측", "상태":"정상" if cur_n else "확인", "내용":f"대상일 {target or '-'} · {cur_n}건"})
    if "actual_close" in kr.columns:
        actual_n = int(pd.to_numeric(kr["actual_close"], errors="coerce").notna().sum())
        rows.append({"항목":"실제 종가 업데이트", "상태":"정상" if actual_n else "대기", "내용":f"actual_close 입력 {actual_n}건"})
    if "created_at" in kr.columns:
        dt = pd.to_datetime(kr["created_at"], errors="coerce").max()
        rows.append({"항목":"마지막 예측 저장", "상태":"정상" if pd.notna(dt) else "확인", "내용":dt.strftime("%Y-%m-%d %H:%M:%S") if pd.notna(dt) else "-"})
    return pd.DataFrame(rows)


def kr_action_from_gap_v9923(cur: float, entry: float, stop: float, tp1: float, rr1: float, conf: float, flags: str) -> str:
    if np.isnan(cur) or cur <= 0 or np.isnan(entry) or entry <= 0:
        return "가격 확인"
    gap = (cur / entry - 1) * 100
    flags = str(flags or "")
    if flags.strip() and flags != "-":
        return "주의 우선"
    if not np.isnan(stop) and cur <= stop:
        return "손절선 이탈"
    if gap >= 4.0:
        return "추격금지"
    if gap >= 2.0:
        return "돌파 확인"
    if -1.2 <= gap <= 1.2 and (np.isnan(rr1) or rr1 >= 1.2) and (np.isnan(conf) or conf >= 45):
        return "우선확인"
    if gap < -3.0:
        return "하락 안정 확인"
    return "대기"


def build_kr_intraday_decision_table_v9923(log_df: pd.DataFrame, limit: int = 9) -> pd.DataFrame:
    batch = latest_prediction_batch_v9923(log_df, "한국주식")
    if batch is None or batch.empty:
        return pd.DataFrame()
    meta_map = watchlist_meta_map("한국주식")
    rows = []
    for _, r in batch.iterrows():
        sym = normalize_ticker(r.get("ticker", r.get("종목", "")), "한국주식")
        if not sym:
            continue
        meta = meta_map.get(sym, {})
        snap = fetch_watch_snapshot(sym, "한국주식")
        cur = safe_float(snap.get("last_price"), np.nan)
        chg = safe_float(snap.get("change_pct"), np.nan)
        entry = safe_float(r.get("preferred_entry"), np.nan)
        stop = safe_float(r.get("stop_loss"), np.nan)
        tp1 = safe_float(r.get("take_profit1"), np.nan)
        rr1 = safe_float(r.get("rr1"), np.nan)
        conf = safe_float(r.get("confidence_score"), np.nan)
        flags = str(r.get("no_buy_flags", ""))
        gap = (cur / entry - 1) * 100 if not np.isnan(cur) and not np.isnan(entry) and entry > 0 else np.nan
        action = kr_action_from_gap_v9923(cur, entry, stop, tp1, rr1, conf, flags)
        score = 0
        if action == "우선확인": score += 30
        elif action == "돌파 확인": score += 18
        elif action == "대기": score += 8
        elif action in {"추격금지", "주의 우선", "손절선 이탈"}: score -= 20
        score += max(-20, min(20, safe_float(conf, 45) - 45)) if not np.isnan(conf) else 0
        score += min(18, max(-12, safe_float(rr1, 1.0) * 8)) if not np.isnan(rr1) else 0
        score += 6 if not np.isnan(chg) and 0 <= chg <= 3 else -5 if not np.isnan(chg) and chg >= 5 else 0
        rows.append({
            "점수": int(round(score)),
            "종목": meta.get("name") or korean_name_from_symbol(sym),
            "코드": sym,
            "현재가": fmt_price(cur, "한국주식") if not np.isnan(cur) else "-",
            "등락률": pct(chg) if not np.isnan(chg) else "-",
            "우선진입가": fmt_price(entry, "한국주식") if not np.isnan(entry) else "-",
            "괴리율": pct(gap) if not np.isnan(gap) else "-",
            "손절가": fmt_price(stop, "한국주식") if not np.isnan(stop) else "-",
            "1차익절": fmt_price(tp1, "한국주식") if not np.isnan(tp1) else "-",
            "손익비": f"1:{rr1:.2f}" if not np.isnan(rr1) else "-",
            "신뢰도": f"{conf:.0f}" if not np.isnan(conf) else "-",
            "장중판단": action,
            "주의": flags if flags.strip() else "-",
            "예측대상일": str(r.get("target_date", "")),
        })
    if not rows:
        return pd.DataFrame()
    return pd.DataFrame(rows).sort_values(["점수"], ascending=False).head(limit).reset_index(drop=True)


def render_kr_focus_panel_v9922(log_df: pd.DataFrame) -> None:  # type: ignore[override]
    """v9.9.22 보강판 위에 v9.9.23 국장 실전 보드를 추가한다."""
