def load_dart_api_key_v9924() -> str:
    """DART API key from env or dart_config.json."""
    key = os.environ.get("DART_API_KEY", "").strip()
    if key:
        return key
    try:
        if DART_CONFIG_FILE.exists():
            cfg = json.loads(DART_CONFIG_FILE.read_text(encoding="utf-8"))
            return str(cfg.get("api_key", "") or cfg.get("crtfc_key", "")).strip()
    except Exception:
        return ""
    return ""


def mask_dart_key_v9924(key: str) -> str:
    key = str(key or "").strip()
    if not key:
        return "미설정"
    if len(key) <= 8:
        return key[:2] + "****"
    return key[:4] + "****" + key[-4:]


def dart_status_v9924() -> dict[str, Any]:
    key = load_dart_api_key_v9924()
    return {
        "enabled": bool(key),
        "masked": mask_dart_key_v9924(key),
        "config_file": str(DART_CONFIG_FILE),
        "cache_file": str(DART_CORP_CACHE_FILE),
    }


@st.cache_data(ttl=60 * 60 * 24 * 7, show_spinner=False)
def fetch_dart_corp_code_map_v9924(api_key: str) -> pd.DataFrame:
    """Download/cache DART corpCode.xml and return stock_code -> corp_code map."""
    if not api_key:
        return pd.DataFrame()
    try:
        # Use local cache first if fresh enough.
        if DART_CORP_CACHE_FILE.exists():
            age_sec = datetime.now().timestamp() - DART_CORP_CACHE_FILE.stat().st_mtime
            if age_sec < 60 * 60 * 24 * 14:
                cached = pd.read_csv(DART_CORP_CACHE_FILE, dtype=str).fillna("")
                if not cached.empty and {"corp_code", "corp_name", "stock_code"}.issubset(set(cached.columns)):
                    return cached
    except Exception:
        pass

    try:
        import requests
        import zipfile
        import xml.etree.ElementTree as ET
        from io import BytesIO
        url = "https://opendart.fss.or.kr/api/corpCode.xml"
        r = requests.get(url, params={"crtfc_key": api_key}, timeout=15)
        if r.status_code != 200 or not r.content:
            return pd.DataFrame()
        z = zipfile.ZipFile(BytesIO(r.content))
        xml_name = z.namelist()[0]
        root = ET.fromstring(z.read(xml_name))
        rows = []
        for item in root.findall("list"):
            corp_code = (item.findtext("corp_code") or "").strip()
            corp_name = (item.findtext("corp_name") or "").strip()
            stock_code = (item.findtext("stock_code") or "").strip()
            if corp_code and stock_code:
                rows.append({"corp_code": corp_code, "corp_name": corp_name, "stock_code": stock_code.zfill(6)})
        df = pd.DataFrame(rows)
        if not df.empty:
            DART_CORP_CACHE_FILE.parent.mkdir(parents=True, exist_ok=True)
            df.to_csv(DART_CORP_CACHE_FILE, index=False, encoding="utf-8-sig")
        return df
    except Exception:
        return pd.DataFrame()


def dart_corp_code_for_symbol_v9924(symbol: str, api_key: str) -> tuple[str, str]:
    code = normalize_ticker(symbol, "한국주식").replace(".KS", "").replace(".KQ", "").zfill(6)
    df = fetch_dart_corp_code_map_v9924(api_key)
    if df is None or df.empty:
        return "", ""
    row = df[df["stock_code"].astype(str).str.zfill(6).eq(code)]
    if row.empty:
        return "", ""
    r = row.iloc[0]
    return str(r.get("corp_code", "")), str(r.get("corp_name", ""))


def classify_dart_disclosure_v9924(report_name: str) -> dict[str, Any]:
    """공시 제목 기반 보수적 분류. 점수는 -8~+8."""
    title = str(report_name or "")
    low = title.lower().replace(" ", "")
    score = 0
    label = "중립/확인"
    impact = "내용 확인 필요"
    action = "원문 확인"
    tags: list[str] = []

    positive_rules = [
        ("단일판매", 5, "수주/공급계약"),
        ("공급계약", 5, "수주/공급계약"),
        ("수주", 4, "수주"),
        ("자기주식취득", 4, "자사주 매입"),
        ("자사주", 3, "자사주"),
        ("현금ㆍ현물배당", 3, "배당"),
        ("배당", 2, "배당"),
        ("신규시설투자", 3, "투자 확대"),
        ("시설투자", 2, "투자"),
        ("무상증자", 3, "무상증자"),
    ]
    negative_rules = [
        ("유상증자", -7, "유상증자"),
        ("전환사채", -6, "전환사채"),
        ("신주인수권부사채", -6, "BW"),
        ("교환사채", -4, "EB"),
        ("감자", -7, "감자"),
        ("상장폐지", -8, "상장폐지"),
        ("관리종목", -7, "관리종목"),
        ("불성실공시", -6, "불성실공시"),
        ("횡령", -8, "횡령"),
        ("배임", -8, "배임"),
        ("소송", -4, "소송"),
        ("감사의견", -6, "감사의견"),
        ("매매거래정지", -8, "거래정지"),
        ("투자주의", -4, "투자주의"),
        ("투자경고", -6, "투자경고"),
        ("투자위험", -8, "투자위험"),
    ]
    neutral_rules = [
        ("잠정실적", 0, "실적"),
        ("영업실적", 0, "실적"),
        ("매출액또는손익구조", 0, "실적변동"),
        ("주요경영사항", 0, "주요경영사항"),
        ("기업설명회", 0, "IR"),
        ("최대주주변경", -2, "최대주주 변경"),
        ("임원ㆍ주요주주", -1, "지분 변동"),
    ]

    for key, val, tag in positive_rules:
        if key.lower().replace(" ", "") in low:
            score += val
            tags.append(tag)
    for key, val, tag in negative_rules:
        if key.lower().replace(" ", "") in low:
            score += val
            tags.append(tag)
    for key, val, tag in neutral_rules:
        if key.lower().replace(" ", "") in low:
            score += val
            tags.append(tag)

    score = int(max(-8, min(8, score)))
    if score >= 5:
        label = "호재 가능성 높음"
        impact = "수주/자사주/배당 등 긍정 공시 가능성"
        action = "추격 금지, 거래량 확인"
    elif score >= 2:
        label = "긍정 확인"
        impact = "긍정 재료 가능성"
        action = "원문 규모/기간 확인"
    elif score <= -6:
        label = "강한 리스크"
        impact = "희석/거래정지/감사의견/횡령·배임 등 위험 가능성"
        action = "신규매수 금지"
    elif score <= -3:
        label = "리스크 확인"
        impact = "희석·소송·규제성 리스크 가능성"
        action = "비중 축소/관망 우선"
    else:
        label = "중립/확인"
        impact = "공시 내용 확인 필요"
        action = "원문 확인"

    if not tags:
        tags = ["일반공시"]
    return {"score": score, "label": label, "impact": impact, "action": action, "tags": " / ".join(dict.fromkeys(tags))}


@st.cache_data(ttl=60 * 12, show_spinner=False)
def fetch_dart_recent_disclosures_for_symbol_v9924(symbol: str, days: int = 7, page_count: int = 20) -> list[dict[str, Any]]:
    """Recent DART disclosures for one KR symbol. Requires DART API key."""
    key = load_dart_api_key_v9924()
    if not key:
        return []
    try:
        import requests
        code = normalize_ticker(symbol, "한국주식").replace(".KS", "").replace(".KQ", "").zfill(6)
        corp_code, corp_name = dart_corp_code_for_symbol_v9924(code, key)
        if not corp_code:
            return []
        end = datetime.now(KST).date()
        begin = end - timedelta(days=max(1, int(days)))
        url = "https://opendart.fss.or.kr/api/list.json"
        params = {
            "crtfc_key": key,
            "corp_code": corp_code,
            "bgn_de": begin.strftime("%Y%m%d"),
            "end_de": end.strftime("%Y%m%d"),
            "page_no": 1,
            "page_count": max(1, min(100, int(page_count))),
            "sort": "date",
            "sort_mth": "desc",
        }
        r = requests.get(url, params=params, timeout=10)
        if r.status_code != 200:
            return []
        payload = r.json() or {}
        status = str(payload.get("status", ""))
        if status not in {"000", "013"}:  # 013 = no data
            return []
        rows = []
        for item in payload.get("list", []) or []:
            title = str(item.get("report_nm", "") or "").strip()
            cls = classify_dart_disclosure_v9924(title)
            rcp_no = str(item.get("rcept_no", "") or "")
            url_view = f"https://dart.fss.or.kr/dsaf001/main.do?rcpNo={rcp_no}" if rcp_no else ""
            rows.append({
                "code": code,
                "corp_code": corp_code,
                "corp_name": corp_name or str(item.get("corp_name", "")),
                "report_nm": title,
                "rcept_dt": str(item.get("rcept_dt", "")),
                "rcept_no": rcp_no,
                "url": url_view,
                "dart_score": cls["score"],
                "dart_label": cls["label"],
                "dart_impact": cls["impact"],
                "dart_action": cls["action"],
                "dart_tags": cls["tags"],
            })
        return rows
    except Exception:
        return []


def build_kr_dart_watch_table_v9924(max_symbols: int = 9, days: int = 7) -> pd.DataFrame:
    key = load_dart_api_key_v9924()
    if not key:
        return pd.DataFrame()
    symbols = watchlist_symbols("한국주식")[:max_symbols]
    rows: list[dict[str, Any]] = []
    for sym in symbols:
        disclosures = fetch_dart_recent_disclosures_for_symbol_v9924(sym, days=days, page_count=8)
        if disclosures:
            for d in disclosures[:3]:
                rows.append({
                    "종목": korean_name_from_symbol(sym),
                    "코드": normalize_ticker(sym, "한국주식").replace(".KS", "").replace(".KQ", ""),
                    "접수일": d.get("rcept_dt", ""),
                    "공시명": d.get("report_nm", ""),
                    "공시판단": d.get("dart_label", ""),
                    "점수": d.get("dart_score", 0),
                    "태그": d.get("dart_tags", ""),
                    "행동": d.get("dart_action", ""),
                    "원문": d.get("url", ""),
                })
        else:
            rows.append({
                "종목": korean_name_from_symbol(sym),
                "코드": normalize_ticker(sym, "한국주식").replace(".KS", "").replace(".KQ", ""),
                "접수일": "-",
                "공시명": "최근 공시 없음",
                "공시판단": "공시 없음",
                "점수": 0,
                "태그": "-",
                "행동": "가격/거래량 기준 확인",
                "원문": "",
            })
    if not rows:
        return pd.DataFrame()
    return pd.DataFrame(rows)


def latest_dart_signal_for_symbol_v9924(symbol: str, days: int = 7) -> dict[str, Any]:
    disclosures = fetch_dart_recent_disclosures_for_symbol_v9924(symbol, days=days, page_count=10)
    if not disclosures:
        return {"score": 0, "label": "최근 공시 없음", "title": "-", "action": "가격/거래량 기준", "tags": "-", "date": "-", "url": ""}
    # 리스크 공시는 가장 강한 음수 우선, 호재는 그 다음. 동일하면 최신 우선.
    def rank(d: dict[str, Any]) -> tuple[int, int, str]:
        sc = safe_float(d.get("dart_score"), 0)
        risk_priority = 1 if sc <= -3 else 0
        return (risk_priority, int(abs(sc)), str(d.get("rcept_dt", "")))
    d = sorted(disclosures, key=rank, reverse=True)[0]
    return {
        "score": int(safe_float(d.get("dart_score"), 0)),
        "label": str(d.get("dart_label", "")),
        "title": str(d.get("report_nm", "")),
        "action": str(d.get("dart_action", "")),
        "tags": str(d.get("dart_tags", "")),
        "date": str(d.get("rcept_dt", "")),
        "url": str(d.get("url", "")),
    }


def build_kr_intraday_decision_table_v9923(log_df: pd.DataFrame, limit: int = 9) -> pd.DataFrame:  # type: ignore[override]
    """v9.9.23 후보표에 DART 공시 점수/주의를 반영."""
    df = _ORIG_build_kr_intraday_decision_table_v9924(log_df, limit=max(limit, 9))
    if df is None or df.empty:
        return pd.DataFrame()
    out = df.copy()
    dart_scores = []
    dart_labels = []
    dart_titles = []
    dart_actions = []
    dart_dates = []
    for _, r in out.iterrows():
        code = str(r.get("코드", "") or r.get("종목", ""))
        sig = latest_dart_signal_for_symbol_v9924(code, days=7)
        sc = int(safe_float(sig.get("score"), 0))
        dart_scores.append(sc)
        dart_labels.append(sig.get("label", "-"))
        dart_titles.append(sig.get("title", "-"))
        dart_actions.append(sig.get("action", "-"))
        dart_dates.append(sig.get("date", "-"))
    out["공시점수"] = dart_scores
    out["공시판단"] = dart_labels
    out["최근공시"] = dart_titles
    out["공시행동"] = dart_actions
    out["공시일"] = dart_dates
    if "점수" in out.columns:
        base = pd.to_numeric(out["점수"], errors="coerce").fillna(0)
        # 공시 리스크는 강하게 반영, 호재는 과도한 추격을 막기 위해 절반만 반영.
        adj = []
        for s in dart_scores:
            adj.append(s * 2 if s < 0 else s)
        out["점수"] = (base + pd.Series(adj, index=out.index)).round().astype(int)
    # 강한 리스크 공시는 장중판단도 보수화
    if "장중판단" in out.columns:
        out.loc[pd.to_numeric(out["공시점수"], errors="coerce").fillna(0) <= -6, "장중판단"] = "공시 리스크"
        out.loc[pd.to_numeric(out["공시점수"], errors="coerce").fillna(0).between(-5, -3), "장중판단"] = "공시 확인"
    return out.sort_values("점수", ascending=False).head(limit).reset_index(drop=True)


def render_dart_setup_panel_v9924() -> None:
    status = dart_status_v9924()
    if status["enabled"]:
        st.success(f"DART API 연결됨: {status['masked']}")
        return
    st.warning("DART API 키가 없어 공시 자동 조회는 비활성화되어 있습니다. 키를 넣으면 관심종목 최근 공시가 국장 후보 점수에 반영됩니다.")
    st.caption("설정 방법: 앱 폴더에 dart_config.json을 만들거나 Windows 환경변수 DART_API_KEY를 설정하세요.")


def render_kr_dart_panel_v9924(expanded: bool = True) -> None:
    st.markdown("#### 📢 DART 공시 체크")
    status = dart_status_v9924()
    c1, c2, c3 = st.columns(3)
    c1.metric("DART 상태", "연결" if status["enabled"] else "미설정")
    c2.metric("조회 범위", "최근 7일")
    c3.metric("반영 방식", "후보 점수 보정")
    if not status["enabled"]:
        render_dart_setup_panel_v9924()
        return
    with st.spinner("DART 최근 공시를 조회 중입니다..."):
        table = build_kr_dart_watch_table_v9924(max_symbols=9, days=7)
    if table.empty:
        st.info("최근 공시를 불러오지 못했습니다. DART 키/네트워크/종목코드 매칭을 확인하세요.")
        return
    risk_n = int((pd.to_numeric(table["점수"], errors="coerce").fillna(0) < 0).sum()) if "점수" in table.columns else 0
    pos_n = int((pd.to_numeric(table["점수"], errors="coerce").fillna(0) > 0).sum()) if "점수" in table.columns else 0
    k1, k2, k3 = st.columns(3)
    k1.metric("리스크 공시", f"{risk_n}건")
    k2.metric("긍정 공시", f"{pos_n}건")
    k3.metric("전체 표시", f"{len(table)}건")
    show_cols = ["종목", "코드", "접수일", "공시명", "공시판단", "점수", "태그", "행동"]
    st.dataframe(table[[c for c in show_cols if c in table.columns]], use_container_width=True, hide_index=True)
    with st.expander("공시 원문 링크", expanded=False):
        link_rows = table[table.get("원문", pd.Series(dtype=str)).astype(str).str.len() > 0].copy() if "원문" in table.columns else pd.DataFrame()
        if link_rows.empty:
            st.caption("표시할 원문 링크가 없습니다.")
        else:
            for _, r in link_rows.head(20).iterrows():
                st.markdown(f"- **{r.get('종목','-')}** · {r.get('접수일','-')} · [{r.get('공시명','원문')}]({r.get('원문')})")


