_ORIG_fetch_market_shock_news_context_v9948 = fetch_market_shock_news_context
_ORIG_composite_quality_score_for_symbol_v9948 = composite_quality_score_for_symbol


@st.cache_data(ttl=60 * 8, show_spinner=False)
def fetch_kr_domestic_news_items_v9948(max_items: int = 60) -> list[dict[str, Any]]:
    items: list[dict[str, Any]] = []
    # 국내 주요 경제/증권 페이지 직접 후보
    page_sources = [
        "https://finance.naver.com/news/mainnews.naver",
        "https://finance.naver.com/news/news_list.naver?mode=LSS2D&section_id=101&section_id2=258",
        "https://www.yna.co.kr/economy/all",
        "https://www.hankyung.com/finance",
    ]
    for url in page_sources:
        for item in fetch_url_news_items_safe(url, max_items=18):
            if item.get("title"):
                item = dict(item)
                item["origin"] = item.get("origin", "kr_page")
                items.append(item)

    # Google News 한국어 보조 검색
    try:
        import feedparser
        from urllib.parse import quote_plus
        queries = [
            'when:1d 코스피 OR 코스닥 OR 환율 OR 외국인 OR 기관 순매수',
            'when:1d 반도체 OR HBM OR 조선 OR 방산 OR 원전 증시',
            'when:1d site:yna.co.kr 증시 OR 코스피 OR 코스닥',
            'when:1d site:hankyung.com 증시 OR 반도체 OR 환율',
            'when:1d site:finance.naver.com 증시 OR 코스피 OR 코스닥',
        ]
        for q in queries:
            url = f"https://news.google.com/rss/search?q={quote_plus(q)}&hl=ko&gl=KR&ceid=KR:ko"
            feed = feedparser.parse(url)
            for entry in getattr(feed, "entries", [])[:12]:
                title = strip_news_publisher_suffix(getattr(entry, "title", ""))
                if not title:
                    continue
                published = getattr(entry, "published", "") or getattr(entry, "updated", "")
                pub_ts = parse_news_time_to_kst(published)
                items.append({
                    "title": title,
                    "source": "Google News KR",
                    "time": format_news_time(published),
                    "published_raw": published,
                    "published_ts": pub_ts.isoformat() if pd.notna(pub_ts) else "",
                    "url": getattr(entry, "link", ""),
                    "origin": "kr_google_news",
                })
    except Exception:
        pass

    deduped, _ = dedupe_news_items(items, threshold=0.54)
    return deduped[:max_items]


def kr_headline_score_v9948(title: str) -> tuple[int, int, list[str]]:
    low = str(title or "").lower()
    relevance = 0
    sentiment = 0
    tags: list[str] = []
    positive = {
        "순매수": 3, "강세": 2, "상승": 2, "반등": 2, "수주": 3, "계약": 3,
        "실적 개선": 3, "최대 실적": 4, "증설": 2, "자사주": 2, "배당": 2,
        "외국인 매수": 4, "기관 매수": 3,
    }
    negative = {
        "순매도": 3, "약세": 2, "하락": 2, "급락": 4, "환율 상승": 3,
        "유상증자": 5, "전환사채": 4, "감자": 5, "거래정지": 5,
        "실적 부진": 3, "적자": 3, "공매도": 2, "외국인 매도": 4, "기관 매도": 3,
    }
    macro = {
        "코스피": 2, "코스닥": 2, "환율": 3, "원/달러": 3, "외국인": 3, "기관": 2,
        "반도체": 3, "hbm": 3, "조선": 2, "방산": 2, "원전": 2, "금리": 2,
        "연준": 2, "나스닥": 2, "미국 증시": 2,
    }
    for k, v in macro.items():
        if k in low:
            relevance += v
            tags.append(k)
    for k, v in positive.items():
        if k in low:
            relevance += v
            sentiment += 1
            tags.append(k)
    for k, v in negative.items():
        if k in low:
            relevance += v
            sentiment -= 1
            tags.append(k)
    return int(min(10, relevance)), 1 if sentiment > 0 else -1 if sentiment < 0 else 0, tags[:6]


def fetch_market_shock_news_context(market: str = "미국주식") -> dict[str, Any]:  # type: ignore[override]
    ctx = _ORIG_fetch_market_shock_news_context_v9948(market)
    if market != "한국주식":
        return ctx
    try:
        items = fetch_kr_domestic_news_items_v9948(max_items=80)
        if not items:
            return ctx

        scored = []
        for item in items:
            rel, sent, tags = kr_headline_score_v9948(str(item.get("title", "")))
            if rel >= 2:
                scored.append({
                    **item,
                    "relevance": rel,
                    "sentiment": sent,
                    "tags": tags,
                    "importance": importance_label_from_relevance(rel, sent, tags),
                })
        if not scored:
            return ctx
        scored = sorted(scored, key=lambda x: (safe_float(x.get("relevance"), 0), str(x.get("published_ts", ""))), reverse=True)
        add_score = int(max(-3, min(3, sum(int(x.get("sentiment", 0)) for x in scored[:12]))))
        source_items = list(ctx.get("auto_news_source_items", []) or []) + scored[:20]
        ctx["auto_news_source_items"] = enrich_news_quality_items_for_app(source_items)
        ctx["auto_news_items"] = list(ctx.get("auto_news_items", []) or []) + [f"[국내뉴스/{x.get('importance','중간')}] {x.get('title','')}" for x in scored[:6]]
        ctx["auto_news_score"] = int(max(-5, min(5, safe_float(ctx.get("auto_news_score"), 0) + add_score)))
        ctx["auto_news_label"] = f"국장 국내뉴스 보강 {ctx['auto_news_score']:+d}"
        ctx["auto_news_quality"] = f"국내뉴스 후보 {len(items)}건 · 시장관련 {len(scored)}건"
        ctx["auto_news_raw_count"] = int(safe_float(ctx.get("auto_news_raw_count"), 0) + len(items))
        ctx["auto_news_scored_count"] = int(safe_float(ctx.get("auto_news_scored_count"), 0) + len(scored))
        if abs(add_score) >= 2:
            ctx["event_names"] = list(ctx.get("event_names", [])) + ["국내 증시 뉴스 변동성"]
            ctx["event_types"] = list(ctx.get("event_types", [])) + ["KR_NEWS"]
            ctx["risk_mult"] = max(safe_float(ctx.get("risk_mult"), 1.0), 1.20)
        return _clean_event_context(ctx)
    except Exception:
        return ctx


@st.cache_data(ttl=60 * 15, show_spinner=False)
def fetch_kr_investor_flow_hint_v9948(symbol: str) -> dict[str, Any]:
    result = {"score": 0, "label": "수급 확인 제한", "summary": "네이버 수급 데이터 확인 제한", "ok": False}
    try:
        import requests
        code = normalize_ticker(symbol, "한국주식").replace(".KS", "").replace(".KQ", "")
        if not code.isdigit():
            return result
        url = f"https://finance.naver.com/item/frgn.naver?code={code}"
        headers = {"User-Agent": "Mozilla/5.0", "Accept-Language": "ko-KR,ko;q=0.9"}
        html = requests.get(url, headers=headers, timeout=7).text
        tables = pd.read_html(html)
        score = 0
        hints = []
        for table in tables[:4]:
            cols = " ".join(map(str, table.columns))
            txt = table.astype(str).to_string()
            if "외국인" in cols or "외국인" in txt:
                if "순매수" in txt or "매수" in txt:
                    score += 1
                    hints.append("외국인 수급 확인")
                break
        if score > 0:
            result.update({"score": min(3, score), "label": "수급 확인+", "summary": "네이버 외국인/기관 수급 페이지 확인", "ok": True})
        else:
            result.update({"score": 0, "label": "수급 중립/확인", "summary": "네이버 수급 페이지 조회 가능하나 방향성 자동판독 제한", "ok": True})
        return result
    except Exception:
        return result


def composite_quality_score_for_symbol(symbol: str, market: str, sector: str = "") -> dict[str, Any]:  # type: ignore[override]
    base = _ORIG_composite_quality_score_for_symbol_v9948(symbol, market, sector)
    if market != "한국주식":
        return base
    try:
        flow = fetch_kr_investor_flow_hint_v9948(symbol)
        add = int(safe_float(flow.get("score"), 0))
        total = int(max(-25, min(25, safe_float(base.get("quality_score"), 0) + add)))
        base = dict(base)
        base["quality_score"] = total
        base["supply_score"] = int(safe_float(base.get("supply_score"), 0) + add)
        base["supply_label"] = str(flow.get("label", base.get("supply_label", "-")))
        base["supply_summary"] = f"{base.get('supply_summary','-')} / {flow.get('summary','-')}"
        base["quality_summary"] = f"{base.get('quality_summary','-')} / {flow.get('summary','-')}"
        if total >= 12:
            base["quality_label"] = "품질 우호"
        elif total >= 4:
            base["quality_label"] = "품질 보통+"
        elif total <= -10:
            base["quality_label"] = "품질 위험"
        elif total <= -4:
            base["quality_label"] = "품질 부담"
        else:
            base["quality_label"] = "품질 중립"
        return base
    except Exception:
        return base


