# v9.9.62 KIS US + News + Latest Prediction Refresh
# - 미장 예측은 한국시간 22:20 프리마켓 최신 예측을 기준으로 같은 target_date를 갱신합니다.
# - 미장 실제값 비교는 KIS 해외주식 기간별시세를 우선 사용하고, 실패 시 기존 yfinance/Finnhub fallback을 유지합니다.
# - 국장/미장 뉴스 근거는 KIS 제목성 뉴스/시황을 보강 데이터로 합칩니다.
# - 주문/잔고/자동매매 기능은 추가하지 않습니다.
# ══════════════════════════════════════════════

KIS_US_EXCHANGE_FALLBACKS_V9962: dict[str, list[str]] = {
    "AAPL": ["NAS", "NYS", "AMS"], "MSFT": ["NAS", "NYS", "AMS"], "NVDA": ["NAS", "NYS", "AMS"],
    "AMD": ["NAS", "NYS", "AMS"], "AVGO": ["NAS", "NYS", "AMS"], "META": ["NAS", "NYS", "AMS"],
    "GOOGL": ["NAS", "NYS", "AMS"], "GOOG": ["NAS", "NYS", "AMS"], "AMZN": ["NAS", "NYS", "AMS"],
    "TSLA": ["NAS", "NYS", "AMS"], "PLTR": ["NYS", "NAS", "AMS"], "TSM": ["NYS", "NAS", "AMS"],
    "ASML": ["NAS", "NYS", "AMS"], "ARM": ["NAS", "NYS", "AMS"], "MU": ["NAS", "NYS", "AMS"],
    "SMCI": ["NAS", "NYS", "AMS"], "QQQ": ["NAS", "AMS", "NYS"], "SOXX": ["NAS", "AMS", "NYS"],
    "SMH": ["AMS", "NAS", "NYS"], "SPY": ["AMS", "NYS", "NAS"], "IWM": ["AMS", "NYS", "NAS"],
}


def kis_overseas_symbol_v9962(symbol: str) -> str:
    s = display_symbol(symbol, "미국주식") if "display_symbol" in globals() else str(symbol or "").upper().strip()
    s = str(s or "").upper().strip()
    s = s.replace("$", "").replace(".US", "")
    return s


def kis_overseas_exchange_candidates_v9962(symbol: str) -> list[str]:
    s = kis_overseas_symbol_v9962(symbol)
    if not s or s.startswith("^") or "=" in s or "-" in s:
        return []
    base = KIS_US_EXCHANGE_FALLBACKS_V9962.get(s, [])
    # 일반 주식/ETF는 거래소가 틀리면 실패하므로, 안전하게 NAS→NYS→AMS 순서로 재시도한다.
    for ex in ["NAS", "NYS", "AMS"]:
        if ex not in base:
            base.append(ex)
    return base


def kis_news_time_label_v9962(date_value: Any, time_value: Any) -> tuple[str, str]:
    d = str(date_value or "").strip()
    t = str(time_value or "").strip().zfill(6) if str(time_value or "").strip() else ""
    try:
        if len(d) == 8 and len(t) >= 4:
            ts = pd.to_datetime(f"{d}{t[:6]}", format="%Y%m%d%H%M%S", errors="coerce")
            if pd.notna(ts):
                # KIS 국내/해외 뉴스 시간은 HTS 표시시간 기준으로 보수적으로 KST 라벨 처리
                return ts.strftime("%m-%d %H:%M KST"), ts.isoformat()
        if len(d) == 8:
            ts = pd.to_datetime(d, format="%Y%m%d", errors="coerce")
            if pd.notna(ts):
                return ts.strftime("%m-%d KST"), ts.isoformat()
    except Exception:
        pass
    return "-", ""


@st.cache_data(ttl=20, show_spinner=False)
def fetch_kis_overseas_price_v9962(symbol: str) -> dict[str, Any]:
    """KIS overseas current/detail price. Read-only quotation API. US stocks/ETFs only."""
    result = {
        "ticker": symbol, "used_symbol": symbol, "exchange": "", "last_price": np.nan, "prev_close": np.nan,
        "change_abs": np.nan, "change_pct": np.nan, "open": np.nan, "high": np.nan, "low": np.nan,
        "last_time": "", "volume": np.nan, "source": "KIS Overseas Open API", "ok": False, "error": "",
    }
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            result["error"] = "kis_disabled"
            return result
        sym = kis_overseas_symbol_v9962(symbol)
        if not sym:
            result["error"] = "empty_symbol"
            return result
        import requests
        cfg = kis_config_v9960()
        url = f"{cfg.get('base_url')}/uapi/overseas-price/v1/quotations/price-detail"
        last_error = ""
        for ex in kis_overseas_exchange_candidates_v9962(sym):
            try:
                headers = kis_headers_v9960("HHDFS76200200")
                params = {"AUTH": "", "EXCD": ex, "SYMB": sym}
                res = requests.get(url, headers=headers, params=params, timeout=7)
                data = res.json() if res.text else {}
                if res.status_code == 401 or data.get("msg_cd") in {"EGW00123", "EGW00121", "EGW00110"}:
                    try:
                        KIS_TOKEN_CACHE_FILE.unlink(missing_ok=True)
                    except Exception:
                        pass
                    headers = kis_headers_v9960("HHDFS76200200")
                    res = requests.get(url, headers=headers, params=params, timeout=7)
                    data = res.json() if res.text else {}
                if res.status_code != 200 or data.get("rt_cd") != "0":
                    last_error = f"{ex}:{res.status_code}/{data.get('msg_cd','')}/{data.get('msg1','')}"
                    continue
                out = data.get("output") or {}
                last = safe_float(out.get("last"), np.nan)
                base = safe_float(out.get("base"), np.nan)
                if np.isnan(last) or last <= 0:
                    last_error = f"{ex}:empty_price"
                    continue
                result.update({
                    "ticker": sym,
                    "used_symbol": sym,
                    "exchange": ex,
                    "last_price": last,
                    "prev_close": base,
                    "open": safe_float(out.get("open"), np.nan),
                    "high": safe_float(out.get("high"), np.nan),
                    "low": safe_float(out.get("low"), np.nan),
                    "volume": safe_float(out.get("tvol"), np.nan),
                    "source": "KIS Overseas Open API",
                    "ok": True,
                    "error": "",
                    "last_time": datetime.now(KST).strftime("%m-%d %H:%M KST"),
                })
                if not np.isnan(base) and base > 0:
                    result["change_abs"] = last - base
                    result["change_pct"] = (last / base - 1) * 100
                return result
            except Exception as e:
                last_error = f"{ex}:{str(e)[:120]}"
                continue
        result["error"] = last_error or "kis_overseas_no_response"
        return result
    except Exception as e:
        result["error"] = str(e)[:160]
        return result


@st.cache_data(ttl=60 * 5, show_spinner=False)
def fetch_kis_overseas_daily_ohlcv_v9962(symbol: str, end_date: str | None = None, period_code: str = "0") -> pd.DataFrame:
    """KIS overseas daily/weekly/monthly price. Max about 100 rows. Returns Date/Open/High/Low/Close/Volume."""
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return pd.DataFrame()
        sym = kis_overseas_symbol_v9962(symbol)
        if not sym:
            return pd.DataFrame()
        import requests
        cfg = kis_config_v9960()
        url = f"{cfg.get('base_url')}/uapi/overseas-price/v1/quotations/dailyprice"
        bymd = str(end_date or datetime.now(KST).strftime("%Y%m%d")).replace("-", "")[:8]
        for ex in kis_overseas_exchange_candidates_v9962(sym):
            try:
                headers = kis_headers_v9960("HHDFS76240000")
                params = {"AUTH": "", "EXCD": ex, "SYMB": sym, "GUBN": str(period_code or "0"), "BYMD": bymd, "MODP": "1", "KEYB": ""}
                res = requests.get(url, headers=headers, params=params, timeout=8)
                data = res.json() if res.text else {}
                if res.status_code == 401 or data.get("msg_cd") in {"EGW00123", "EGW00121", "EGW00110"}:
                    try:
                        KIS_TOKEN_CACHE_FILE.unlink(missing_ok=True)
                    except Exception:
                        pass
                    headers = kis_headers_v9960("HHDFS76240000")
                    res = requests.get(url, headers=headers, params=params, timeout=8)
                    data = res.json() if res.text else {}
                if res.status_code != 200 or data.get("rt_cd") != "0":
                    continue
                rows = data.get("output2") or []
                if not rows:
                    continue
                df = pd.DataFrame(rows)
                if df.empty:
                    continue
                out = pd.DataFrame({
                    "Date": pd.to_datetime(df.get("xymd"), format="%Y%m%d", errors="coerce"),
                    "Open": pd.to_numeric(df.get("open"), errors="coerce"),
                    "High": pd.to_numeric(df.get("high"), errors="coerce"),
                    "Low": pd.to_numeric(df.get("low"), errors="coerce"),
                    "Close": pd.to_numeric(df.get("clos"), errors="coerce"),
                    "Volume": pd.to_numeric(df.get("tvol"), errors="coerce"),
                })
                out = out.dropna(subset=["Date", "Open", "High", "Low", "Close"]).sort_values("Date").reset_index(drop=True)
                if not out.empty:
                    out["_source"] = "KIS Overseas Open API"
                    out["_exchange"] = ex
                    return out
            except Exception:
                continue
        return pd.DataFrame()
    except Exception:
        return pd.DataFrame()


@st.cache_data(ttl=60 * 3, show_spinner=False)
def fetch_kis_domestic_news_titles_v9962(symbol: str = "", max_items: int = 40) -> list[dict[str, Any]]:
    """KIS domestic comprehensive market/disclosure titles. Title-level evidence only, not full articles."""
    items: list[dict[str, Any]] = []
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return items
        import requests
        cfg = kis_config_v9960()
        code = kis_domestic_code_v9960(symbol) if str(symbol or "").strip() else ""
        url = f"{cfg.get('base_url')}/uapi/domestic-stock/v1/quotations/news-title"
        headers = kis_headers_v9960("FHKST01011800")
        params = {
            "FID_NEWS_OFER_ENTP_CODE": "",
            "FID_COND_MRKT_CLS_CODE": "",
            "FID_INPUT_ISCD": code,
            "FID_TITL_CNTT": "",
            "FID_INPUT_DATE_1": "",
            "FID_INPUT_HOUR_1": "",
            "FID_RANK_SORT_CLS_CODE": "",
            "FID_INPUT_SRNO": "",
        }
        res = requests.get(url, headers=headers, params=params, timeout=7)
        data = res.json() if res.text else {}
        if res.status_code != 200 or data.get("rt_cd") != "0":
            return items
        raw = data.get("output") or []
        if isinstance(raw, dict):
            raw = [raw]
        for n in raw[:max_items]:
            title = str(n.get("hts_pbnt_titl_cntt", "") or "").strip()
            if not title:
                continue
            tm, iso = kis_news_time_label_v9962(n.get("data_dt"), n.get("data_tm"))
            items.append({
                "title": title,
                "source": "KIS 국내시황/공시",
                "time": tm,
                "published_ts": iso,
                "published_raw": f"{n.get('data_dt','')} {n.get('data_tm','')}",
                "url": "",
                "origin": "kis_domestic_news_title",
                "related_ticker": code,
                "dorg": str(n.get("dorg", "") or ""),
                "importance": "중간",
                "direction": "중립/변동성",
            })
    except Exception:
        return items
    return items


@st.cache_data(ttl=60 * 3, show_spinner=False)
def fetch_kis_overseas_news_titles_v9962(symbol: str = "", max_items: int = 40) -> list[dict[str, Any]]:
    """KIS overseas comprehensive news titles. Title-level evidence only."""
    items: list[dict[str, Any]] = []
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return items
        import requests
        cfg = kis_config_v9960()
        sym = kis_overseas_symbol_v9962(symbol) if str(symbol or "").strip() else ""
        url = f"{cfg.get('base_url')}/uapi/overseas-price/v1/quotations/news-title"
        headers = kis_headers_v9960("HHPSTH60100C1")
        params = {"INFO_GB": "", "CLASS_CD": "", "NATION_CD": "US", "EXCHANGE_CD": "", "SYMB": sym, "DATA_DT": "", "DATA_TM": "", "CTS": ""}
        res = requests.get(url, headers=headers, params=params, timeout=7)
        data = res.json() if res.text else {}
        if res.status_code != 200 or data.get("rt_cd") != "0":
            return items
        raw = data.get("output") or data.get("output1") or []
        if isinstance(raw, dict):
            raw = [raw]
        for n in raw[:max_items]:
            title = str(n.get("title") or n.get("titl") or n.get("news_titl") or n.get("hts_pbnt_titl_cntt") or "").strip()
            if not title:
                # 일부 응답은 필드명이 문서 예시와 다를 수 있어 제목 후보를 넓게 탐색
                for v in n.values():
                    sv = str(v or "").strip()
                    if len(sv) >= 8 and not sv.isdigit():
                        title = sv
                        break
            if not title:
                continue
            tm, iso = kis_news_time_label_v9962(n.get("data_dt") or n.get("DATA_DT"), n.get("data_tm") or n.get("DATA_TM"))
            items.append({
                "title": title,
                "source": "KIS 해외뉴스",
                "time": tm,
                "published_ts": iso,
                "published_raw": f"{n.get('data_dt','')} {n.get('data_tm','')}",
                "url": "",
                "origin": "kis_overseas_news_title",
                "related_ticker": sym,
                "importance": "중간",
                "direction": "중립/변동성",
            })
    except Exception:
        return items
    return items


@st.cache_data(ttl=60 * 2, show_spinner=False)
def fetch_kis_overseas_breaking_news_titles_v9962(symbol: str = "", max_items: int = 40) -> list[dict[str, Any]]:
    """KIS overseas breaking news titles. Title-level evidence only."""
    items: list[dict[str, Any]] = []
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return items
        import requests
        cfg = kis_config_v9960()
        sym = kis_overseas_symbol_v9962(symbol) if str(symbol or "").strip() else ""
        url = f"{cfg.get('base_url')}/uapi/overseas-price/v1/quotations/brknews-title"
        headers = kis_headers_v9960("FHKST01011801")
        params = {
            "FID_NEWS_OFER_ENTP_CODE": "0",
            "FID_COND_MRKT_CLS_CODE": "",
            "FID_INPUT_ISCD": sym,
            "FID_TITL_CNTT": "",
            "FID_INPUT_DATE_1": "",
            "FID_INPUT_HOUR_1": "",
            "FID_RANK_SORT_CLS_CODE": "",
            "FID_INPUT_SRNO": "",
            "FID_COND_SCR_DIV_CODE": "11801",
        }
        res = requests.get(url, headers=headers, params=params, timeout=7)
        data = res.json() if res.text else {}
        if res.status_code != 200 or data.get("rt_cd") != "0":
            return items
        raw = data.get("output") or []
        if isinstance(raw, dict):
            raw = [raw]
        for n in raw[:max_items]:
            title = str(n.get("hts_pbnt_titl_cntt", "") or "").strip()
            if not title:
                continue
            tm, iso = kis_news_time_label_v9962(n.get("data_dt"), n.get("data_tm"))
            items.append({
                "title": title,
                "source": "KIS 해외속보",
                "time": tm,
                "published_ts": iso,
                "published_raw": f"{n.get('data_dt','')} {n.get('data_tm','')}",
                "url": "",
                "origin": "kis_overseas_breaking_news_title",
                "related_ticker": sym,
                "dorg": str(n.get("dorg", "") or ""),
                "importance": "높음",
                "direction": "중립/변동성",
            })
    except Exception:
        return items
    return items


def _kis_score_news_items_v9962(items: list[dict[str, Any]], market: str) -> tuple[list[dict[str, Any]], int, int]:
    scored: list[dict[str, Any]] = []
    total_score = 0
    impact_count = 0
    for item in items or []:
        title = str(item.get("title", "") or "")
        if not title:
            continue
        try:
            if market == "한국주식" and "kr_headline_score_v9948" in globals():
                rel, sent, tags = kr_headline_score_v9948(title)
            else:
                rel, sent, tags = market_moving_headline_score(title)
            sev, direction, alarm_tags = news_alarm_severity(title) if "news_alarm_severity" in globals() else (0, 0, [])
            final_sent = direction if direction else sent
            local = max(-3, min(3, final_sent * max(1, int(max(rel, sev) / 4)))) if max(rel, sev) >= 3 else 0
            importance = "높음" if max(rel, sev) >= 7 else "중간" if max(rel, sev) >= 3 else "낮음"
            direction_label = "우호" if final_sent > 0 else "부담" if final_sent < 0 else "중립/변동성"
            total_score += local
            if importance != "낮음":
                impact_count += 1
            scored.append({**item, "importance": importance, "direction": direction_label, "severity": sev, "relevance": rel, "alarm_reasons": alarm_tags or tags})
        except Exception:
            scored.append(item)
    return scored, int(max(-5, min(5, total_score))), impact_count


# Preserve v9.9.61 functions for fallback/merge
_ORIG_fetch_extended_snapshot_v9962 = fetch_extended_snapshot
_ORIG_fetch_actual_day_v9962 = fetch_actual_day
_ORIG_fetch_market_shock_news_context_v9962 = fetch_market_shock_news_context
_ORIG_fetch_ticker_news_context_v9962 = fetch_ticker_news_context


def fetch_extended_snapshot(ticker: str) -> dict[str, Any]:  # type: ignore[override]
    """US plain stock/ETF: KIS overseas price first, then previous Finnhub/yfinance fallback."""
    try:
        s = kis_overseas_symbol_v9962(ticker)
        if s and is_finnhub_quote_symbol(s) and "kis_config_v9960" in globals() and kis_config_v9960().get("enabled"):
            kis = fetch_kis_overseas_price_v9962(s)
            if bool(kis.get("ok")):
                return kis
    except Exception:
        pass
    return _ORIG_fetch_extended_snapshot_v9962(ticker)


def fetch_actual_day(ticker: str, market: str, target_date: str | date) -> dict[str, Any] | None:  # type: ignore[override]
    """Actual OHLC comparison source. KR: existing KIS domestic. US: KIS overseas daily first."""
    if market == "미국주식" and "kis_config_v9960" in globals() and kis_config_v9960().get("enabled"):
        try:
            target = pd.to_datetime(target_date).date()
            # KIS overseas dailyprice uses BYMD as 기준일자 and returns recent rows up to that date.
            end = (target + timedelta(days=7)).strftime("%Y%m%d")
            df = fetch_kis_overseas_daily_ohlcv_v9962(ticker, end_date=end, period_code="0")
            if df is not None and not df.empty:
                tmp = df.copy()
                tmp["_date"] = pd.to_datetime(tmp["Date"], errors="coerce").dt.date
                exact = tmp[tmp["_date"].eq(target)]
                # 검증값은 반드시 target_date의 정규장 일봉 OHLC만 사용한다.
                # 애프터마켓/24시간 가격이나 다음 거래일 데이터를 actual 값으로 대체하지 않는다.
                if not exact.empty:
                    r = exact.iloc[0]
                    kis_actual = {
                        "actual_date": str(r["_date"]),
                        "actual_open": safe_float(r.get("Open"), np.nan),
                        "actual_high": safe_float(r.get("High"), np.nan),
                        "actual_low": safe_float(r.get("Low"), np.nan),
                        "actual_close": safe_float(r.get("Close"), np.nan),
                        "actual_volume": safe_float(r.get("Volume", 0.0), np.nan),
                        "actual_source": "KIS Overseas Open API · regular_session_daily_ohlc",
                        "actual_session": "regular",
                    }
                    if actual_ohlc_needs_confirmation_v9974(kis_actual):
                        fallback = _ORIG_fetch_actual_day_v9962(ticker, market, target_date)
                        if fallback and not actual_ohlc_needs_confirmation_v9974(fallback):
                            fallback = dict(fallback)
                            fallback["actual_source"] = f"{fallback.get('actual_source', 'yfinance')} · KIS flat OHLC fallback"
                            fallback["actual_quality_flag"] = "정상 일봉"
                            fallback["actual_quality_note"] = "KIS 미장 단일가형 OHLC 대신 fallback 정규장 일봉 사용"
                            return fallback
                        return mark_actual_ohlc_confirmation_v9974(
                            kis_actual,
                            "KIS 미장 일봉이 open=high=low=close 및 volume 0 형태라 정규장 OHLC 재확인 필요",
                        )
                    kis_actual["actual_quality_flag"] = "정상 일봉"
                    kis_actual["actual_quality_note"] = "KIS 정규장 일봉 기준"
                    return kis_actual
        except Exception:
            pass
    return _ORIG_fetch_actual_day_v9962(ticker, market, target_date)


def fetch_market_shock_news_context(market: str = "미국주식") -> dict[str, Any]:  # type: ignore[override]
    """Add KIS title-level market/news evidence to the existing news context."""
    ctx = _ORIG_fetch_market_shock_news_context_v9962(market)
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return ctx
        if market == "한국주식":
            items = fetch_kis_domestic_news_titles_v9962("", max_items=60)
            source_label = "KIS 국내시황/공시"
        else:
            items = fetch_kis_overseas_news_titles_v9962("", max_items=40) + fetch_kis_overseas_breaking_news_titles_v9962("", max_items=40)
            source_label = "KIS 해외뉴스/속보"
        if not items:
            return ctx
        scored, add_score, impact_count = _kis_score_news_items_v9962(items, market)
        source_items = list(ctx.get("auto_news_source_items", []) or []) + scored[:20]
        ctx["auto_news_source_items"] = enrich_news_quality_items_for_app(source_items)
        ctx["auto_news_items"] = list(ctx.get("auto_news_items", []) or []) + [f"[{source_label}/{x.get('importance','중간')}] {x.get('title','')}" for x in scored[:6]]
        ctx["auto_news_score"] = int(max(-5, min(5, safe_float(ctx.get("auto_news_score"), 0) + add_score)))
        ctx["auto_news_label"] = f"{source_label} 보강 {ctx['auto_news_score']:+d}"
        ctx["auto_news_quality"] = f"{source_label} {len(items)}건 · 영향 후보 {impact_count}건"
        ctx["auto_news_raw_count"] = int(safe_float(ctx.get("auto_news_raw_count"), 0) + len(items))
        ctx["auto_news_scored_count"] = int(safe_float(ctx.get("auto_news_scored_count"), 0) + impact_count)
        if abs(add_score) >= 2 or impact_count >= 2:
            ctx["event_names"] = list(ctx.get("event_names", [])) + [f"{source_label} 변동성"]
            ctx["event_types"] = list(ctx.get("event_types", [])) + ["KIS_NEWS"]
            ctx["risk_mult"] = max(safe_float(ctx.get("risk_mult"), 1.0), 1.20)
        return _clean_event_context(ctx)
    except Exception:
        return ctx


def fetch_ticker_news_context(ticker: str, lookback_hours: int = 72) -> dict[str, Any]:  # type: ignore[override]
    """Add KIS overseas title news to existing ticker-specific US news context."""
    ctx = _ORIG_fetch_ticker_news_context_v9962(ticker, lookback_hours)
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return ctx
        t = kis_overseas_symbol_v9962(ticker)
        if not t or not is_finnhub_quote_symbol(t):
            return ctx
        items = fetch_kis_overseas_news_titles_v9962(t, max_items=20) + fetch_kis_overseas_breaking_news_titles_v9962(t, max_items=20)
        if not items:
            return ctx
        scored, add_score, impact_count = _kis_score_news_items_v9962(items, "미국주식")
        ctx["auto_news_source_items"] = enrich_news_quality_items_for_app(list(ctx.get("auto_news_source_items", []) or []) + scored[:12])
        ctx["auto_news_items"] = list(ctx.get("auto_news_items", []) or []) + [f"[KIS 해외뉴스/{x.get('importance','중간')}] {x.get('title','')}" for x in scored[:4]]
        ctx["auto_news_score"] = int(max(-5, min(5, safe_float(ctx.get("auto_news_score"), 0) + add_score)))
        ctx["auto_news_label"] = f"KIS+기존뉴스 {ctx['auto_news_score']:+d} · {t}"
        ctx["auto_news_raw_count"] = int(safe_float(ctx.get("auto_news_raw_count"), 0) + len(items))
        ctx["auto_news_scored_count"] = int(safe_float(ctx.get("auto_news_scored_count"), 0) + impact_count)
        if abs(add_score) >= 2:
            ctx["event_names"] = list(ctx.get("event_names", [])) + [f"KIS 해외뉴스 자동감지({t})"]
            ctx["event_types"] = list(ctx.get("event_types", [])) + ["KIS_TICKER_NEWS"]
            ctx["risk_mult"] = max(safe_float(ctx.get("risk_mult"), 1.0), 1.25)
        return _clean_event_context(ctx)
    except Exception:
        return ctx


