# ══════════════════════════════════════════════
# v9.9.71 KR News Priority Patch
# - 국장은 KIS 종합 시황/공시 제목성 데이터 → 연합뉴스/연합뉴스TV RSS/OpenAPI 계열 → Google KR RSS 순서로 보강
# - KIS 뉴스 엔드포인트는 증권사 API 문서/권한 차이에 따라 응답 필드가 달라질 수 있어 best-effort로 처리
# - 실패해도 앱이 멈추지 않고 기존 국장 뉴스 RSS로 fallback
# ══════════════════════════════════════════════

@st.cache_data(ttl=60 * 5, show_spinner=False)
def fetch_kis_domestic_news_items_v9971(max_items: int = 40) -> list[dict[str, Any]]:
    """KIS domestic market/news/disclosure title feed, best-effort.

    한국투자 Open API 문서의 국내주식 > 업종/기타 영역에 있는
    '종합 시황/공시(제목)' 성격의 제목성 데이터를 우선 사용하려는 함수.
    계정 권한/실전·모의/문서 버전에 따라 URL·필드명이 달라질 수 있으므로
    실패 시 빈 리스트를 반환하고 다른 뉴스 소스로 자연스럽게 넘어간다.
    """
    items: list[dict[str, Any]] = []
    try:
        if not ("kis_config_v9960" in globals() and kis_config_v9960().get("enabled")):
            return items
        import requests
        cfg = kis_config_v9960()

        # 후보를 여러 개 둔다. 하나라도 정상 응답하면 제목성 데이터를 사용한다.
        # 일부 계정/문서 버전에서는 정확한 path/tr_id가 다를 수 있어 하드 실패하지 않는다.
        candidates = [
            {
                "url": f"{cfg['base_url']}/uapi/domestic-stock/v1/quotations/news-title",
                "tr_id": "FHKST01011800",
                "params": {"FID_NEWS_OFER_ENTP_CODE": "", "FID_COND_MRKT_CLS_CODE": "", "FID_INPUT_ISCD": "", "FID_INPUT_DATE_1": "", "FID_INPUT_HOUR_1": ""},
            },
            {
                "url": f"{cfg['base_url']}/uapi/domestic-stock/v1/quotations/news-title",
                "tr_id": "FHKST01011800",
                "params": {"FID_NEWS_OFER_ENTP_CODE": "", "FID_COND_MRKT_DIV_CODE": "J", "FID_INPUT_ISCD": "", "FID_INPUT_DATE_1": "", "FID_INPUT_HOUR_1": ""},
            },
            {
                "url": f"{cfg['base_url']}/uapi/domestic-stock/v1/quotations/inquire-news-title",
                "tr_id": "FHKST01011800",
                "params": {"FID_NEWS_OFER_ENTP_CODE": "", "FID_COND_MRKT_CLS_CODE": "", "FID_INPUT_ISCD": "", "FID_INPUT_DATE_1": "", "FID_INPUT_HOUR_1": ""},
            },
        ]

        def _extract_rows(payload: dict[str, Any]) -> list[dict[str, Any]]:
            rows: list[dict[str, Any]] = []
            for key in ["output", "output1", "output2", "output3"]:
                v = payload.get(key)
                if isinstance(v, list):
                    rows.extend([x for x in v if isinstance(x, dict)])
                elif isinstance(v, dict):
                    rows.append(v)
            return rows

        title_keys = [
            "news_titl", "hts_kor_isnm", "titl", "title", "news_title", "data_rank_name",
            "sj", "kor_titl", "news_name", "cntt", "body", "hts_kor_isnm",
        ]
        date_keys = ["data_dt", "news_dt", "stck_bsop_date", "date", "reg_date", "input_date"]
        time_keys = ["data_tm", "news_tm", "time", "reg_time", "input_hour", "hts_kor_isnm"]
        url_keys = ["url", "news_url", "link", "data_url"]
        source_keys = ["news_ofer_entp_name", "source", "entp_name", "provider", "pbnt_titl"]

        for cand in candidates:
            try:
                headers = kis_headers_v9960(cand["tr_id"])
                if not headers:
                    continue
                res = requests.get(cand["url"], headers=headers, params=cand["params"], timeout=8)
                data = res.json() if res.text else {}
                if res.status_code != 200 or str(data.get("rt_cd", "0")) not in {"0", ""}:
                    # 토큰 만료 가능성 한 번만 보정
                    if res.status_code in {401, 403} or str(data.get("msg_cd", "")).startswith("EGW"):
                        try:
                            KIS_TOKEN_CACHE_FILE.unlink(missing_ok=True)
                        except Exception:
                            pass
                        headers = kis_headers_v9960(cand["tr_id"])
                        res = requests.get(cand["url"], headers=headers, params=cand["params"], timeout=8)
                        data = res.json() if res.text else {}
                    if res.status_code != 200 or str(data.get("rt_cd", "0")) not in {"0", ""}:
                        continue
                rows = _extract_rows(data)
                for r in rows:
                    title = ""
                    for k in title_keys:
                        if str(r.get(k, "") or "").strip():
                            title = str(r.get(k, "") or "").strip()
                            break
                    title = " ".join(title.split())
                    if len(title) < 6 or len(title) > 180:
                        continue
                    src = "KIS 국내시황/공시"
                    for k in source_keys:
                        if str(r.get(k, "") or "").strip():
                            src = f"KIS · {str(r.get(k)).strip()}"
                            break
                    d = ""
                    tm = ""
                    for k in date_keys:
                        if str(r.get(k, "") or "").strip():
                            d = str(r.get(k, "") or "").strip()
                            break
                    for k in time_keys:
                        if str(r.get(k, "") or "").strip():
                            tm = str(r.get(k, "") or "").strip()
                            break
                    time_label = "-"
                    try:
                        if len(d) == 8:
                            hh = (tm + "000000")[:6] if tm else "000000"
                            dt = pd.to_datetime(d + hh, format="%Y%m%d%H%M%S", errors="coerce")
                            if pd.notna(dt):
                                time_label = dt.strftime("%m-%d %H:%M KST")
                    except Exception:
                        pass
                    link = ""
                    for k in url_keys:
                        if str(r.get(k, "") or "").strip():
                            link = str(r.get(k, "") or "").strip()
                            break
                    if title not in [x.get("title") for x in items]:
                        items.append({
                            "title": title,
                            "source": src,
                            "time": time_label,
                            "published_raw": (d + tm).strip(),
                            "published_ts": "",
                            "url": link,
                            "origin": "kis_domestic_news",
                        })
                    if len(items) >= max_items:
                        return items
                if items:
                    return items
            except Exception:
                continue
    except Exception:
        return []
    return items


@st.cache_data(ttl=60 * 5, show_spinner=False)
def fetch_yonhap_kr_news_items_v9971(max_items: int = 60) -> list[dict[str, Any]]:
    """연합뉴스/연합뉴스TV/연합인포맥스 계열 RSS 보강.

    공식/공개 RSS 또는 접근 가능한 RSS성 피드를 우선 사용하고, 실패하면 빈 리스트를 반환한다.
    """
    items: list[dict[str, Any]] = []
    try:
        import feedparser
        from urllib.parse import quote_plus
    except Exception:
        return items

    feeds = [
        # 연합뉴스TV RSS 페이지에서 제공하는 공개 RSS 계열. 실제 RSS URL은 사이트 개편 시 바뀔 수 있어 실패 허용.
        "https://www.yonhapnewstv.co.kr/browse/feed/",
        "https://m.yonhapnewstv.co.kr/browse/feed/",
        # 연합인포맥스/경제TV RSS 인덱스 계열은 국장·채권·환율 뉴스 보강에 유용하다.
        "https://news.einfomax.co.kr/rss/allArticle.xml",
        "https://news.einfomax.co.kr/rss/S1N1.xml",
        "https://news.einfomax.co.kr/rss/S1N2.xml",
    ]
    google_queries = [
        'when:1d site:yna.co.kr 코스피 OR 코스닥 OR 증시 OR 외국인 OR 기관',
        'when:1d site:yonhapnewstv.co.kr 코스피 OR 코스닥 OR 증시 OR 환율',
        'when:1d site:news.einfomax.co.kr 코스피 OR 코스닥 OR 환율 OR 채권 OR 외국인',
        'when:1d 연합뉴스 코스피 코스닥 증시 마감 외국인 기관',
    ]
    for q in google_queries:
        feeds.append(f"https://news.google.com/rss/search?q={quote_plus(q)}&hl=ko&gl=KR&ceid=KR:ko")

    try:
        for url in feeds:
            feed = feedparser.parse(url)
            for entry in getattr(feed, "entries", [])[:20]:
                title = getattr(entry, "title", "")
                if not title:
                    continue
                clean_title = strip_news_publisher_suffix(title)
                if len(clean_title) < 6:
                    continue
                published = getattr(entry, "published", "") or getattr(entry, "updated", "")
                pub_ts = parse_news_time_to_kst(published)
                link = getattr(entry, "link", "") or url
                source_name = "연합뉴스/인포맥스"
                low_link = str(link).lower()
                low_title = str(title).lower()
                if "yna.co.kr" in low_link or "yonhap" in low_link or "연합뉴스" in title:
                    source_name = "연합뉴스"
                elif "yonhapnewstv" in low_link:
                    source_name = "연합뉴스TV"
                elif "einfomax" in low_link or "인포맥스" in title:
                    source_name = "연합인포맥스"
                try:
                    src = getattr(entry, "source", {}) or {}
                    if isinstance(src, dict) and src.get("title") and source_name == "연합뉴스/인포맥스":
                        source_name = str(src.get("title"))
                except Exception:
                    pass
                if clean_title not in [x.get("title") for x in items]:
                    items.append({
                        "title": clean_title,
                        "source": source_name,
                        "time": format_news_time(published),
                        "published_raw": published,
                        "published_ts": pub_ts.isoformat() if pd.notna(pub_ts) else "",
                        "url": link,
                        "origin": "yonhap_kr_rss",
                    })
                if len(items) >= max_items:
                    return items
    except Exception:
        pass
    return items


# 기존 국장 RSS 함수에 KIS/연합뉴스 우선 소스를 덧붙여 덮어쓴다.
_ORIG_fetch_kr_macro_rss_items_safe_v9971 = fetch_kr_macro_rss_items_safe

def fetch_kr_macro_rss_items_safe(max_items: int = 80) -> list[dict[str, Any]]:  # type: ignore[override]
    items: list[dict[str, Any]] = []
    try:
        # 1순위: KIS 제목성 시황/공시
        for item in fetch_kis_domestic_news_items_v9971(max_items=40):
            if item.get("title") and item.get("title") not in [x.get("title") for x in items]:
                items.append(item)
        # 2순위: 연합뉴스/연합 계열
        for item in fetch_yonhap_kr_news_items_v9971(max_items=60):
            if item.get("title") and item.get("title") not in [x.get("title") for x in items]:
                items.append(item)
        # 3순위: 기존 Google KR RSS/경제뉴스
        for item in _ORIG_fetch_kr_macro_rss_items_safe_v9971(max_items=max_items):
            if item.get("title") and item.get("title") not in [x.get("title") for x in items]:
                items.append(item)
        return items[:max_items]
    except Exception:
        try:
            return _ORIG_fetch_kr_macro_rss_items_safe_v9971(max_items=max_items)
        except Exception:
            return items[:max_items]


