def _log_news_quality_error_v9973(where: str, exc: Exception) -> None:
    try:
        log_app_event("news_quality_v9973", "warning", f"{type(exc).__name__}: {str(exc)[:220]}", function_name=where)
    except Exception:
        return


def _contains_any_v9973(text: str, terms: tuple[str, ...]) -> bool:
    low = str(text or "").lower()
    return any(t in low for t in terms)


def _news_is_required_macro_v9973(item: dict[str, Any]) -> bool:
    return str(item.get("origin", "") or "") in {"required_macro_watch", "macro_event_context"}


def _news_text_full_v9973(item: dict[str, Any]) -> str:
    try:
        return _news_text_v9977(item)
    except Exception:
        return " ".join(str(item.get(k, "") or "") for k in ("title", "summary", "source", "related_ticker", "theme", "market"))


