def _news_story_key_v9973(item: dict[str, Any], market: str) -> str:
    origin = str(item.get("origin", "") or "")
    if origin in {"required_macro_watch", "macro_event_context"}:
        return f"{origin}:{market}"
    text = _news_text_full_v9973(item)
    bucket = _news_impact_bucket_v9981(item, market)
    symbols = []
    try:
        if market == "한국주식":
            symbols = _news_kr_symbol_hits_v9982(item)
        else:
            symbols = _news_us_symbol_hits_v9977(item, market)
    except Exception:
        symbols = []
    norm = normalize_news_title_for_dedupe(text)
    tokens = [t for t in norm.split() if t not in NEWS_DEDUPE_STOPWORDS]
    core = "_".join(tokens[:7])
    if symbols:
        return f"{market}:{bucket}:{'_'.join(symbols[:3])}"
    return f"{market}:{bucket}:{core}"


def _news_sort_key_v9973(item: dict[str, Any], market: str) -> tuple[float, float, float, float]:
    try:
        stock_score = safe_float(item.get("_stock_news_score"), _news_item_stock_relevance_v9974(item, market))
    except Exception:
        stock_score = 0.0
    return (
        stock_score,
        safe_float(item.get("_source_priority"), _news_source_priority_v9984(item, market)),
        safe_float(item.get("_published_score"), _news_item_time_score_v9974(item)),
        1.0 if str(item.get("importance", "")) == "높음" else 0.0,
    )


def _dedupe_news_by_impact_v9981(items: list[dict[str, Any]], market: str, limit: int) -> list[dict[str, Any]]:  # type: ignore[override]
    grouped: dict[str, dict[str, Any]] = {}
    macro_items: list[dict[str, Any]] = []
    for raw in items or []:
        item = dict(raw)
        if not _news_item_matches_market_v9982(item, market):
            continue
        if _news_is_required_macro_v9973(item):
            key = _news_story_key_v9973(item, market)
            if key not in {str(x.get("_story_key", "")) for x in macro_items}:
                item["_story_key"] = key
                macro_items.append(item)
            continue
        key = _news_story_key_v9973(item, market)
        old = grouped.get(key)
        if old is None:
            grouped[key] = item
            continue
        if _news_sort_key_v9973(item, market) > _news_sort_key_v9973(old, market):
            item["duplicate_sources"] = list(old.get("duplicate_sources", [])) + [{
                "title": str(old.get("title", "")),
                "source": str(old.get("source", "")),
                "url": str(old.get("url", "")),
                "time": str(old.get("time", "-")),
            }]
            grouped[key] = item
        else:
            dup = old.setdefault("duplicate_sources", [])
            dup.append({
                "title": str(item.get("title", "")),
                "source": str(item.get("source", "")),
                "url": str(item.get("url", "")),
                "time": str(item.get("time", "-")),
            })
    ranked = sorted(grouped.values(), key=lambda x: _news_sort_key_v9973(x, market), reverse=True)
    out = macro_items[:1] + ranked
    return out[:max(1, int(limit))]


_ORIG_stock_news_story_summary_v9973 = _stock_news_story_summary_v9980


def _stock_news_story_summary_v9980(item: dict[str, Any], market: str) -> str:  # type: ignore[override]
    title = str(item.get("title", "") or "")
    raw_summary = str(item.get("summary", "") or "")
    text = f"{title} {raw_summary}"
    low = text.lower()
    try:
        if market == "한국주식":
            if _is_generic_kr_index_news_v9973(item):
                return "단순 지수 상승 뉴스입니다. 종목 재료보다 외국인·기관 수급이 특정 업종으로 이어지는지 확인해야 합니다."
            if any(k in low for k in ("뉴욕증시", "나스닥", "nvidia", "엔비디아", "amd", "cpi")) and any(k in low for k in ("삼성전자", "sk하이닉스", "하이닉스", "반도체")):
                return "미국 기술주와 반도체 흐름이 국내 삼성전자·SK하이닉스 심리에 연결되는 뉴스입니다. 국장에서는 해당 종목 수급과 거래대금 확인이 우선입니다."
            return _ORIG_stock_news_story_summary_v9973(item, market)

        if any(k in low for k in ("cpi", "consumer price", "inflation", "물가", "인플레이션")):
            return "미국 물가 지표가 금리 기대를 흔들며 나스닥·성장주·반도체 변동성을 키운 뉴스입니다. CPI가 예상보다 높으면 추격매수보다 금리와 QQQ 안정 확인이 우선입니다."
        if any(k in low for k in ("fomc", "fed", "powell", "treasury", "yield", "rate", "연준", "파월", "국채", "금리")):
            return "연준·국채금리 경로가 바뀔 수 있는 뉴스입니다. 금리가 오르면 성장주 밸류에이션 부담이 커지고, 금리가 안정되면 반등 여지가 생깁니다."
        if any(k in low for k in ("nvidia", "nvda", "엔비디아", "amd", "semiconductor", "chip", "ai", "반도체")):
            return "AI·반도체 대형주 흐름에 영향을 주는 뉴스입니다. NVDA·AMD·SOXX/SMH가 함께 움직이는지 확인해야 합니다."
        return _ORIG_stock_news_story_summary_v9973(item, market)
    except Exception as exc:
        _log_news_quality_error_v9973("_stock_news_story_summary_v9980", exc)
        return "주가에 영향을 줄 수 있는 뉴스입니다. 제목보다 지수·섹터·거래량 반응을 함께 확인해야 합니다."


