def _v29_clean_number(value: Any, default: float = np.nan) -> float:
    try:
        text = "" if value is None else str(value)
        text = text.replace(",", "").replace("원", "").replace("$", "").replace("%", "")
        text = re.sub(r"[^0-9.\-]", "", text).strip()
        if text in {"", "-", ".", "-."}:
            return default
        out = float(text)
        return out if np.isfinite(out) else default
    except Exception:
        return default


def _v29_first_existing(row: Any, names: tuple[str, ...] | list[str], default: Any = "") -> Any:
    try:
        for name in names:
            if name in row and str(row.get(name, "")).strip() not in {"", "-", "N/A", "NA", "None", "nan", "가격 기준 미산출", "현재가 미수신"}:
                return row.get(name)
        lower_map = {str(c).strip().lower(): c for c in getattr(row, "index", [])}
        for name in names:
            key = lower_map.get(str(name).lower())
            if key is not None and str(row.get(key, "")).strip() not in {"", "-", "N/A", "NA", "None", "nan", "가격 기준 미산출", "현재가 미수신"}:
                return row.get(key)
    except Exception:
        pass
    return default


def _v29_candidate_symbol_from_display_row(row: Any, market: str) -> str:
    raw = _v29_first_existing(row, ("종목코드", "symbol", "ticker", "code", "종목", "종목명"), "")
    if market == "한국주식":
        try:
            raw = korean_symbol_from_name(str(raw))
        except Exception:
            pass
    return normalize_ticker(str(raw), market) if "normalize_ticker" in globals() else str(raw).strip().upper()


def _v29_prediction_series_from_display_row(row: Any, market: str) -> pd.Series:
    symbol = _v29_candidate_symbol_from_display_row(row, market)
    return pd.Series({
        "종목": symbol,
        "ticker": symbol,
        "symbol": symbol,
        "preferred_entry": _v29_clean_number(_v29_first_existing(row, ("매수가", "관찰 기준가", "우선진입가", "entry", "entry_price", "조건부 진입가"))),
        "stop_loss": _v29_clean_number(_v29_first_existing(row, ("손절가", "stop", "stop_loss"))),
        "take_profit1": _v29_clean_number(_v29_first_existing(row, ("목표가", "1차 목표가", "1차익절가", "tp1", "target_price"))),
        "take_profit2": _v29_clean_number(_v29_first_existing(row, ("2차 목표가", "2차익절가", "tp2", "take_profit2"))),
        "pred_open_mid": _v29_clean_number(_v29_first_existing(row, ("예상시초가", "pred_open_mid"))),
        "pred_close_low": _v29_clean_number(_v29_first_existing(row, ("예상종가하단", "pred_close_low"))),
        "pred_close_high": _v29_clean_number(_v29_first_existing(row, ("예상종가상단", "pred_close_high"))),
    })


def _v29_render_candidate_chart_flow(market: str, table: pd.DataFrame, *, key_prefix: str = "buy") -> None:
    if table is None or table.empty:
        return
    try:
        st.markdown("### 선택 종목 차트 · 기준가 흐름")
        st.caption("후보 표에서 하나를 고르면 아래에서 일봉/주봉/월봉 흐름과 매수가·손절가·목표가 기준을 바로 확인합니다.")
        labels: list[str] = []
        rows: list[pd.Series] = []
        seen: set[str] = set()
        for _, row in table.head(80).iterrows():
            sym = _v29_candidate_symbol_from_display_row(row, market)
            if not sym or sym in seen:
                continue
            seen.add(sym)
            name = str(_v29_first_existing(row, ("종목명", "종목", "name"), sym)).strip() or sym
            decision = str(_v29_first_existing(row, ("최종 판단", "권장 조치", "판단"), "")).strip()
            entry = _v29_first_existing(row, ("매수가", "관찰 기준가", "우선진입가"), "-")
            labels.append(f"{name} ({sym}) · {decision} · 진입 {entry}")
            rows.append(row)
        if not labels:
            return
        selected = st.selectbox("차트로 볼 후보 선택", labels, index=0, key=f"v29_{key_prefix}_candidate_chart_select_{market}")
        idx = labels.index(selected)
        s = _v29_prediction_series_from_display_row(rows[idx], market)
        m1, m2, m3, m4 = st.columns(4)
        m1.metric("선택 종목", str(s.get("symbol", "-")))
        m2.metric("진입 기준", fmt_price(s.get("preferred_entry"), market) if "fmt_price" in globals() else str(s.get("preferred_entry", "-")))
        m3.metric("손절 기준", fmt_price(s.get("stop_loss"), market) if "fmt_price" in globals() else str(s.get("stop_loss", "-")))
        m4.metric("1차 목표", fmt_price(s.get("take_profit1"), market) if "fmt_price" in globals() else str(s.get("take_profit1", "-")))
        try:
            render_selected_prediction_chart(s, market)
        except Exception as exc:
            st.info(f"차트 표시를 건너뜁니다: {exc}")
    except Exception as exc:
        st.caption(f"선택 후보 차트 표시 생략: {exc}")


def _v29_auto_accumulate_once() -> None:
    """앱 실행/runner 실행 시 v24 누적 지표를 한 번 갱신한다."""
    try:
        today_key = datetime.now(KST).strftime("%Y-%m-%d") if "KST" in globals() else datetime.now().strftime("%Y-%m-%d")
        key = f"_v29_auto_accumulate_done_{today_key}"
        # Streamlit 세션이 있으면 하루 1회만, runner에서는 매번 안전 갱신.
        if "st" in globals() and hasattr(st, "session_state"):
            if st.session_state.get(key):
                return
            st.session_state[key] = True
        from core.portfolio_history_engine import save_benchmark_daily_history, save_daily_portfolio_snapshot
        save_benchmark_daily_history()
        save_daily_portfolio_snapshot()
        try:
            from core.backtest_beta_engine import save_backtest_beta_summary
            save_backtest_beta_summary()
        except Exception:
            pass
        try:
            from core.news_cache_engine import summarize_news_cache
            summarize_news_cache()
        except Exception:
            pass
    except Exception:
        return


