        c1, c2, c3 = st.columns(3)
        c1.metric("보유 점검", f"{len(holdings_status):,}개" if isinstance(holdings_status, pd.DataFrame) else "0개")
        high_sell = 0
        top_reason = "-"
        if isinstance(sell_df, pd.DataFrame) and not sell_df.empty:
            high_sell = int((pd.to_numeric(sell_df.get("매도우선순위"), errors="coerce").fillna(0) >= 70).sum())
            top_reason = str(_v29_first_existing(sell_df.iloc[0], ("매도이유", "매도판단", "보유판단"), "-"))[:80]
        c2.metric("우선 매도/축소 체크", f"{high_sell:,}개")
        c3.metric("상위 사유", top_reason)
        st.caption("매도 화면은 매수 후보 순위와 분리해서 보유수익률·평단가·손절가·익절가 기준으로 다시 점수화합니다.")
