def _v29_run_final_metrics() -> dict[str, Any]:
    result: dict[str, Any] = {"status": "OK", "updated_at": datetime.now(KST).strftime("%Y-%m-%d %H:%M:%S") if "KST" in globals() else datetime.now().strftime("%Y-%m-%d %H:%M:%S")}
    from core.portfolio_history_engine import save_benchmark_daily_history, save_daily_portfolio_snapshot
    bench = save_benchmark_daily_history()
    result["benchmark_rows"] = int(len(bench)) if hasattr(bench, "__len__") else 0
    result["portfolio"] = save_daily_portfolio_snapshot()
    try:
        from core.backtest_beta_engine import save_backtest_beta_summary
        result["backtest_beta"] = save_backtest_beta_summary()
    except Exception as exc:
        result["backtest_beta"] = {"status": "ERROR", "error": str(exc)}
    try:
        from core.news_cache_engine import summarize_news_cache
        result["news_cache"] = summarize_news_cache()
    except Exception as exc:
        result["news_cache"] = {"status": "ERROR", "error": str(exc)}
    try:
        path = REPORT_DIR / "v29_final_update_status.json"
        path.parent.mkdir(parents=True, exist_ok=True)
        path.write_text(json.dumps(result, ensure_ascii=False, indent=2, default=str), encoding="utf-8")
    except Exception:
        pass
    return result


def run_headless_runner(action: str) -> int:  # type: ignore[override]
    normalized = str(action or "").strip().lower()
    if normalized in {"final_metrics", "v29_update", "auto_accumulate", "accumulate"}:
        try:
            res = _v29_run_final_metrics()
            _runner_print(f"[runner] v29_final_metrics={json.dumps(res, ensure_ascii=False, default=str)}") if "_runner_print" in globals() else print(json.dumps(res, ensure_ascii=False, default=str), flush=True)
            return 0 if res.get("status") == "OK" else 2
        except Exception as exc:
            print(f"[runner] v29_final_metrics_error={exc}", flush=True)
            return 1
    if _ORIG_run_headless_runner_v29 is not None:
        return _ORIG_run_headless_runner_v29(action)
    return 2


