APP_VERSION = str(APP_VERSION) + " + v30 autostart + v31 MA10/strong-watch-fix"


def _v30_read_auto_status() -> dict[str, Any]:
    try:
        from core.auto_accumulator_status_engine import read_status_for_display
        return read_status_for_display()
    except Exception as exc:
        return {"status": "ERROR", "error": str(exc), "data_files": {}}


def _v30_status_badge(status: str) -> str:
    s = str(status or "").upper().strip()
    if s == "OK":
        return "정상"
    if s in {"NO_STATUS", "NO_DATA", ""}:
        return "대기"
    return "확인 필요"


def _v30_render_auto_accumulator_status_panel(expanded: bool = False) -> None:
    """Show automatic accumulation status on the first screen."""
    try:
        status = _v30_read_auto_status()
        st.markdown("### 자동누적 상태판")
        st.caption("노트북이 켜져 있고 자동누적 프로세스가 실행 중이면 NAV, benchmark, 뉴스 캐시, 백테스트 요약이 주기적으로 갱신됩니다.")
        c1, c2, c3, c4 = st.columns(4)
        c1.metric("상태", _v30_status_badge(status.get("status", "")))
        c2.metric("마지막 실행", str(status.get("last_run_at") or status.get("updated_at") or "-"))
        c3.metric("마지막 성공", str(status.get("last_success_at") or "-"))
        c4.metric("다음 예상", str(status.get("next_run_estimated_at") or "-"))

        data_files = status.get("data_files", {}) if isinstance(status.get("data_files"), dict) else {}
        if data_files:
            rows = []
            labels = {
                "portfolio_daily_nav": "포트폴리오 NAV",
                "position_daily_snapshot": "보유 스냅샷",
                "benchmark_daily": "Benchmark daily",
                "news_cache": "뉴스 캐시",
                "backtest_beta_summary": "백테스트 beta",
            }
            for key, item in data_files.items():
                if not isinstance(item, dict):
                    continue
                rows.append({
                    "항목": labels.get(key, key),
                    "누적 row": item.get("rows", 0),
                    "수정 시각": item.get("modified_at", ""),
                    "파일": item.get("path", ""),
                })
            if rows:
                with st.expander("자동누적 데이터 파일 확인", expanded=expanded):
                    st.dataframe(pd.DataFrame(rows), use_container_width=True, hide_index=True)

        with st.expander("자동누적 실행/해제 방법", expanded=False):
            st.markdown(
                """
- 처음 한 번만 자동 시작 등록: `install_autostart.bat` 실행
- 자동 시작 해제: `uninstall_autostart.bat` 실행
- 지금 바로 수동 실행: PowerShell에서 `./start_auto_accumulator.bat` 실행
- 상태 1회 점검: `check_auto_accumulator_status.bat` 실행
                """
            )
            st.caption(f"상태 파일: {status.get('status_path', 'reports/auto_accumulator_status.json')} / 로그: {status.get('log_path', 'logs/auto_accumulator.log')} / 백업: {status.get('backup_root', 'backups')}")
            if status.get("error"):
                st.warning(f"상태판 오류: {status.get('error')}")
    except Exception as exc:
        try:
            st.caption(f"자동누적 상태판 표시 생략: {exc}")
        except Exception:
            pass


