APP_VERSION = str(APP_VERSION) + " + v33~v36 final learning/risk/status/cloud"


def _v36_safe_json(path: Path) -> dict[str, Any]:
    try:
        if not path.exists() or path.stat().st_size <= 0:
            return {}
        return json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return {}


def _v36_safe_csv(path: Path) -> pd.DataFrame:
    try:
        if not path.exists() or path.stat().st_size <= 0:
            return pd.DataFrame()
        for enc in ("utf-8-sig", "utf-8", "cp949"):
            try:
                return pd.read_csv(path, encoding=enc, low_memory=False).fillna("")
            except Exception:
                continue
    except Exception:
        pass
    return pd.DataFrame()


def _v36_run_all_updates_quick() -> dict[str, Any]:
    try:
        from run_v36_full_update import run_once
        return run_once()
    except Exception as exc:
        return {"status": "ERROR", "error": f"{type(exc).__name__}: {exc}"}


def _v36_metric_value(data: dict[str, Any], *keys: str, default: Any = "-") -> Any:
    for key in keys:
        if key in data and data.get(key) not in (None, ""):
            return data.get(key)
    return default


