try:
    _ORIG_dispatch_sidebar_nav_page_v36 = _dispatch_sidebar_nav_page
except Exception:
    _ORIG_dispatch_sidebar_nav_page_v36 = None


def _dispatch_sidebar_nav_page(page_id: str) -> None:  # type: ignore[override]
    if page_id == "page_v36_learning":
        render_v36_prediction_learning_page()
        return
    if page_id == "page_v36_risk":
        render_v36_risk_priority_page()
        return
    if page_id == "page_v36_api_status":
        render_v36_api_status_page()
        return
    if page_id == "page_v36_cloud":
        render_v36_cloud_readiness_page()
        return
    if _ORIG_dispatch_sidebar_nav_page_v36 is not None:
        return _ORIG_dispatch_sidebar_nav_page_v36(page_id)
    st.warning(f"알 수 없는 화면 ID: {page_id}")


try:
    _ORIG_run_headless_runner_v36 = run_headless_runner
except Exception:
    _ORIG_run_headless_runner_v36 = None


def run_headless_runner(action: str) -> int:  # type: ignore[override]
    normalized = str(action or "").strip().lower()
    if normalized in {"v36", "v36_update", "final_update", "learning_risk_status_cloud"}:
        res = _v36_run_all_updates_quick()
        print(json.dumps(res, ensure_ascii=False, indent=2, default=str), flush=True)
        return 0 if str(res.get("status", "")).upper() == "OK" else 2
    if _ORIG_run_headless_runner_v36 is not None:
        return _ORIG_run_headless_runner_v36(action)
    return 2



