# v37 Operational Consolidation
# - 일반 모드: 매수/매도에 직접 도움되는 화면만
# - 관리자 모드: 진단/원본/복기/설정 전용
# ══════════════════════════════════════════════


def _v37_market(key: str = "v37") -> str:
    try:
        return _effective_nav_market(key)
    except Exception:
        return "미국주식"


def _v37_safe_engine_call(func, *args, **kwargs):
    try:
        return func(*args, **kwargs)
    except Exception as exc:
        try:
            log_app_event("v37_operational", "error", f"{type(exc).__name__}: {exc}")
        except Exception:
            pass
        return pd.DataFrame()


def _v37_render_table(df: pd.DataFrame, *, empty: str = "표시할 데이터가 없습니다.", limit: int = 80) -> None:
    if df is None or not isinstance(df, pd.DataFrame) or df.empty:
        st.info(empty)
        return
    view = df.head(limit).copy()
    try:
        view = clean_user_display_frame(view)
    except Exception:
        pass
    st.dataframe(view, use_container_width=True, hide_index=True)


def render_v37_budget_quantity_page() -> None:
    """일반 모드 전용: 매수/매도 예산·권장수량 계산."""
    from core.operational_plus_engine import build_buy_budget_table, build_sell_budget_table, operation_settings

    market = _v37_market("v37_budget")
    inject_native_graft_css()
    _render_nav_page_title("예산·권장수량")
    st.caption("매수 후보와 보유 종목을 계좌금액·현금·1회 리스크·종목당 최대비중 기준으로 수량화합니다.")

    settings = operation_settings(market)
    c1, c2, c3, c4 = st.columns(4)
    c1.metric("계좌 기준", fmt_price(safe_float(settings.get("account_capital"), 0), market))
    c2.metric("사용 가능 현금", fmt_price(safe_float(settings.get("available_cash"), 0), market))
    c3.metric("1회 리스크", f"{safe_float(settings.get('risk_per_trade_pct'), 0):.2f}%")
    c4.metric("종목당 최대비중", f"{safe_float(settings.get('max_position_pct'), 0):.2f}%")
    st.caption("운용 기준 변경은 관리자 모드가 아니라 일반 모드의 ‘실전 운용 기준’에서만 조정해도 됩니다. 원본 설정 파일 점검은 관리자 모드로 분리했습니다.")

    if st.button("권장수량 리포트 갱신", key=f"v37_budget_refresh_{market}"):
        try:
            import subprocess, sys
            subprocess.run([sys.executable, "run_v37_operational_update.py"], check=False)
            st.success("v37 운용 리포트를 갱신했습니다. 표가 바로 바뀌지 않으면 새로고침하세요.")
        except Exception as exc:
            st.warning(f"갱신 스크립트 실행 실패: {exc}")

    tab_buy, tab_sell = st.tabs(["신규/추가 매수 수량", "보유/매도 수량"])
    with tab_buy:
        df = _v37_safe_engine_call(build_buy_budget_table, market)
        _v37_render_table(df, empty="매수 후보 CSV가 없거나 기준가 데이터가 부족합니다.", limit=60)
        st.caption("권장수량은 참고값입니다. 실제 주문 전 현재가, 호가, 뉴스, 이벤트, 손절폭을 다시 확인하세요.")
    with tab_sell:
        df = _v37_safe_engine_call(build_sell_budget_table, market)
        _v37_render_table(df, empty="보유종목 또는 매도 판단 데이터가 없습니다.", limit=80)
        st.caption("권장매도수량은 판단 문구 기준의 보수적 보조값입니다. 실제 매도는 체결가와 세금/수수료를 확인하세요.")


def render_v37_selected_chart_flow_page() -> None:
    """일반 모드 전용: 선택 종목 차트 아래 수급·호가·현재가 요약 표시."""
    from core.operational_plus_engine import symbol_options, build_selected_symbol_flow

    market = _v37_market("v37_selected_flow")
    inject_native_graft_css()
    _render_nav_page_title("선택 종목 차트·수급")
    st.caption("종목 하나를 선택하면 차트 바로 아래에 현재가·호가·수급·업종 흐름을 붙여 보여줍니다.")

    opts = symbol_options(market)
    default_symbol = opts[0] if opts else ("NVDA" if market == "미국주식" else "005930")
    c1, c2, c3 = st.columns([1.3, .7, .7])
    with c1:
        symbol = st.selectbox("후보/보유 종목 선택", opts or [default_symbol], index=0, key=f"v37_flow_symbol_{market}")
    with c2:
        period_label = st.selectbox("조회 기간", ["3개월", "6개월", "1년", "2년"], index=1, key=f"v37_flow_period_{market}")
    with c3:
        candle_mode = st.selectbox("봉 기준", ["일봉", "주봉", "월봉"], index=0, key=f"v37_flow_candle_{market}")

    raw_symbol = str(symbol or default_symbol).strip()
    ticker = normalize_ticker(korean_symbol_from_name(raw_symbol), market) if market == "한국주식" else display_symbol(raw_symbol, "미국주식")
    years = {"3개월": 0.25, "6개월": 0.5, "1년": 1.0, "2년": 2.0}.get(period_label, 0.5)
    with st.spinner(f"{ticker} 차트 불러오는 중..."):
        chart_df = _load_stock_data_for_chart_cached(ticker, market, years)
    if chart_df is None or chart_df.empty or len(chart_df) < 5:
        st.warning("차트 데이터를 불러오지 못했습니다. 그래도 아래 수급/호가 저장 리포트는 확인할 수 있습니다.")
    else:
        try:
            chart_df = calculate_indicators(chart_df)
        except Exception:
            pass
        plot_df = chart_df.copy()
        try:
            if candle_mode == "주봉":
                plot_df = plot_df.set_index(pd.to_datetime(plot_df["Date"])).resample("W-FRI").agg({"Open":"first", "High":"max", "Low":"min", "Close":"last", "Volume":"sum"}).dropna().reset_index().rename(columns={"index":"Date"})
                plot_df = calculate_indicators(plot_df)
            elif candle_mode == "월봉":
                plot_df = plot_df.set_index(pd.to_datetime(plot_df["Date"])).resample("M").agg({"Open":"first", "High":"max", "Low":"min", "Close":"last", "Volume":"sum"}).dropna().reset_index().rename(columns={"index":"Date"})
                plot_df = calculate_indicators(plot_df)
        except Exception:
            pass
        fig = go.Figure()
        fig.add_trace(go.Candlestick(
            x=plot_df["Date"], open=plot_df["Open"], high=plot_df["High"], low=plot_df["Low"], close=plot_df["Close"],
            name=str(ticker), increasing_line_color="#ef5350", decreasing_line_color="#26a69a",
        ))
        for ma in ["MA10", "MA20", "MA60", "MA120", "MA200"]:
            if ma in plot_df.columns:
                fig.add_trace(go.Scatter(x=plot_df["Date"], y=plot_df[ma], mode="lines", name=ma, line=dict(width=1.15)))
        try:
            _add_swing_markers_to_fig_v21(fig, plot_df, market, use_subplots=False)
        except Exception:
            pass
        fig.update_layout(
            title=dict(text=f"{ticker} · {period_label} · {candle_mode}", x=0.01, xanchor="left", y=0.98, yanchor="top"),
            template="plotly_dark", height=560, margin=dict(l=10, r=34, t=92, b=26),
            xaxis=dict(rangeslider=dict(visible=False), automargin=True), yaxis=dict(side="right", automargin=True),
            legend=dict(orientation="h", yanchor="bottom", y=1.05, xanchor="left", x=0),
        )
        st.plotly_chart(fig, use_container_width=True, config={"displayModeBar": False, "scrollZoom": False})
        try:
            render_chart_trade_levels_box(ticker, market, chart_df)
            _render_chart_technical_signal_panel_v21(ticker, market, chart_df)
        except Exception:
            pass

    st.markdown('<div class="mode-section-title">선택 종목 수급·호가·현재가 요약</div>', unsafe_allow_html=True)
    pack = build_selected_symbol_flow(market, ticker)
    _v37_render_table(pack.get("summary"), empty="저장된 장중 수급/호가 리포트가 없습니다. run_intraday_refresh를 실행하면 채워집니다.", limit=10)

    with st.expander("상세 저장 리포트", expanded=False):
        for title, key in [("후보/기준가", "candidate"), ("현재가", "quote"), ("호가", "orderbook"), ("수급", "flow"), ("업종", "sector")]:
            st.markdown(f"**{title}**")
            _v37_render_table(pack.get(key), empty=f"{title} 데이터 없음", limit=20)


