def _dispatch_sidebar_nav_page(page_id: str) -> None:  # type: ignore[override]
    if page_id == "page_v37_budget_quantity":
        render_v37_budget_quantity_page(); return
    if page_id == "page_v37_selected_chart_flow":
        render_v37_selected_chart_flow_page(); return
    if page_id == "page_v37_news_narrative":
        render_v37_news_narrative_page(); return
    if page_id == "page_v37_fundamental_kpi":
        render_v37_fundamental_kpi_page(); return
    if page_id == "page_v37_macro_regime":
        render_v37_macro_regime_page(); return
    if page_id == "page_v37_quant_backtest":
        render_v37_quant_backtest_page(); return
    if page_id == "page_v37_custom_screener":
        render_v37_custom_screener_page(); return
    if page_id == "page_v37_mode_structure":
        render_v37_mode_structure_page(); return
    if _ORIG_dispatch_sidebar_nav_page_v37 is not None:
        return _ORIG_dispatch_sidebar_nav_page_v37(page_id)
    st.warning(f"알 수 없는 화면 ID: {page_id}")


try:
    _ORIG_run_headless_runner_v37 = run_headless_runner
except Exception:
    _ORIG_run_headless_runner_v37 = None


def run_headless_runner(action: str) -> int:  # type: ignore[override]
    normalized = str(action or "").strip().lower()
    if normalized in {"v37", "v37_update", "operational_plus"}:
        try:
            import subprocess, sys
            completed = subprocess.run([sys.executable, "run_v37_operational_update.py"], check=False)
            return int(completed.returncode or 0)
        except Exception as exc:
            print(f"v37 update failed: {type(exc).__name__}: {exc}", flush=True)
            return 2
    if _ORIG_run_headless_runner_v37 is not None:
        return _ORIG_run_headless_runner_v37(action)
    return 2



