def _v40_market(key: str = "v40") -> str:
    try:
        return _effective_nav_market(key)
    except Exception:
        return "미국주식"


def _v40_engine_call(func, *args, **kwargs):
    try:
        return func(*args, **kwargs)
    except Exception as exc:
        try:
            log_app_event("v40_analysis", "error", f"{type(exc).__name__}: {exc}")
        except Exception:
            pass
        return pd.DataFrame()


