def render_v40_option_pricing_page() -> None:
    from core.v40_analysis_engine import build_option_pricing_table

    inject_native_graft_css()
    _render_nav_page_title("옵션 프라이싱 계산기")
    st.caption("Black-Scholes 기초 계산기입니다. 실시간 옵션 체인 자동 수집은 아직 아니며, 입력값 기반 이론가·Greeks만 계산합니다.")
    c1, c2, c3, c4, c5 = st.columns(5)
    with c1:
        S = st.number_input("기초자산 가격 S", min_value=0.01, value=100.0, step=1.0, key="v40_option_S")
    with c2:
        K = st.number_input("행사가 K", min_value=0.01, value=100.0, step=1.0, key="v40_option_K")
    with c3:
        sigma = st.number_input("IV/변동성 %", min_value=0.01, value=30.0, step=1.0, key="v40_option_sigma")
    with c4:
        days = st.number_input("만기 일수", min_value=1, value=30, step=1, key="v40_option_days")
    with c5:
        r = st.number_input("무위험금리 %", min_value=0.0, value=4.0, step=0.25, key="v40_option_r")
    q = st.number_input("배당수익률 %", min_value=0.0, value=0.0, step=0.25, key="v40_option_q")
    df = build_option_pricing_table(S=S, K=K, r_pct=r, sigma_pct=sigma, days=int(days), q_pct=q)
    _v37_render_table(df, empty="옵션 계산 결과가 없습니다.", limit=10)
    st.caption("실전 옵션 매매용 저평가/고평가 판단은 옵션 체인, 유동성, 미결제약정, 호가 스프레드 데이터가 추가로 필요합니다.")


def render_v40_monte_carlo_page() -> None:
    from core.v40_analysis_engine import monte_carlo_summary

    inject_native_graft_css()
    _render_nav_page_title("몬테카를로 시뮬레이션")
    st.caption("GBM 기반 기초 시뮬레이션입니다. 포트폴리오 상관계수/국면별 fat-tail은 이후 고도화 단계에서 확장합니다.")
    c1, c2, c3, c4 = st.columns(4)
    with c1:
        price = st.number_input("현재가", min_value=0.01, value=100.0, step=1.0, key="v40_mc_price")
    with c2:
        exp_ret = st.number_input("연 기대수익률 %", value=8.0, step=1.0, key="v40_mc_return")
    with c3:
        vol = st.number_input("연 변동성 %", min_value=0.01, value=30.0, step=1.0, key="v40_mc_vol")
    with c4:
        days = st.number_input("예상 기간(일)", min_value=1, value=60, step=5, key="v40_mc_days")
    sims = st.slider("시뮬레이션 횟수", 100, 10000, 1000, 100, key="v40_mc_sims")
    df = monte_carlo_summary(price, expected_return_pct=exp_ret, volatility_pct=vol, days=int(days), simulations=int(sims))
    _v37_render_table(df, empty="몬테카를로 계산 결과가 없습니다.", limit=20)
    st.caption("결과는 확률적 가정 기반 참고값입니다. 실제 시장은 정규분포보다 극단값이 자주 발생할 수 있습니다.")


