try:
    _ORIG_run_headless_runner_v40 = run_headless_runner
except Exception:
    _ORIG_run_headless_runner_v40 = None


def run_headless_runner(action: str) -> int:  # type: ignore[override]
    normalized = str(action or "").strip().lower()
    if normalized in {"v40", "v40_update", "analysis_v40", "full_v40"}:
        try:
            from core.v40_analysis_engine import save_v40_reports
            res = save_v40_reports()
            print(json.dumps(res, ensure_ascii=False, indent=2, default=str), flush=True)
            return 0 if str(res.get("status", "")).upper() == "OK" else 2
        except Exception as exc:
            print(f"v40 update failed: {type(exc).__name__}: {exc}", flush=True)
            return 2
    if _ORIG_run_headless_runner_v40 is not None:
        return _ORIG_run_headless_runner_v40(action)
    return 2



