# v41 Beginner-Friendly Operational Stabilization Patch
# - 일반모드/관리자모드 중복 메뉴 재정리
# - 매수위험/매수금지/추격위험 단일 화면 통합
# - 차트 고점·저점 표시를 기본 OFF + 최근 핵심점만 표시
# - 예산·권장수량 설정을 일반모드에서 바로 저장 가능
# - 선택 종목 수급표를 초보자용 해석 컬럼으로 정리
# ══════════════════════════════════════════════
APP_VERSION = str(APP_VERSION) + " + v41 beginner-friendly ops"


def _v41_save_operation_settings(market: str, settings: dict[str, Any]) -> None:
    """Save user operation settings in a market-specific JSON file."""
    try:
        path = Path("data/user_operation_settings.json")
        path.parent.mkdir(parents=True, exist_ok=True)
        raw: dict[str, Any] = {}
        if path.exists() and path.stat().st_size > 0:
            try:
                raw = json.loads(path.read_text(encoding="utf-8-sig"))
            except Exception:
                raw = {}
        key = "kr" if str(market).strip() == "한국주식" else "us"
        raw[key] = settings
        raw["updated_at"] = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        path.write_text(json.dumps(raw, ensure_ascii=False, indent=2), encoding="utf-8")
    except Exception as exc:
        raise RuntimeError(f"설정 저장 실패: {exc}")


def _v41_format_beginner_money(v: Any, market: str) -> str:
    try:
        return fmt_price(safe_float(v, 0), market)
    except Exception:
        return str(v)


def _add_swing_markers_to_fig_v21(fig: Any, df: pd.DataFrame | None, market: str, *, row: int = 1, col: int = 1, use_subplots: bool = True) -> None:  # type: ignore[override]
    """v41: show only the latest meaningful swing high/low and avoid text clutter."""
    try:
        high_df, low_df = _detect_swing_points_v21(df, window=4, max_points=1)
        if not high_df.empty:
            kwargs = dict(
                x=high_df["Date"],
                y=pd.to_numeric(high_df["High"], errors="coerce"),
                mode="markers",
                name="최근 고점",
                marker=dict(color="#ef4444", size=9, symbol="circle"),
                hovertemplate="최근 고점 %{y}<extra></extra>",
            )
            fig.add_trace(go.Scatter(**kwargs), row=row, col=col) if use_subplots else fig.add_trace(go.Scatter(**kwargs))
        if not low_df.empty:
            kwargs = dict(
                x=low_df["Date"],
                y=pd.to_numeric(low_df["Low"], errors="coerce"),
                mode="markers",
                name="최근 저점",
                marker=dict(color="#22c55e", size=9, symbol="circle"),
                hovertemplate="최근 저점 %{y}<extra></extra>",
            )
            fig.add_trace(go.Scatter(**kwargs), row=row, col=col) if use_subplots else fig.add_trace(go.Scatter(**kwargs))
    except Exception:
        return


