        with c4:
            max_pct = st.number_input("종목당 최대비중 %", min_value=1.0, max_value=100.0, value=float(safe_float(settings.get("max_position_pct"), 20.0)), step=1.0, key=f"v41_max_pct_{market}")
        allow_fractional = False
