def render_v37_selected_chart_flow_page() -> None:  # type: ignore[override]
    """v41: chart + flow page without duplicate/general confusion."""
    from core.operational_plus_engine import symbol_options, build_selected_symbol_flow

    market = _v37_market("v41_selected_flow")
    inject_native_graft_css()
    _render_nav_page_title("선택 종목 차트·수급")
    st.caption("관심종목 차트와 수급표를 한 화면으로 합쳤습니다. 일반모드에서는 이 화면 하나만 보면 됩니다.")

    opts = symbol_options(market)
    default_symbol = opts[0] if opts else ("NVDA" if market == "미국주식" else "005930")
    c1, c2, c3, c4 = st.columns([1.25, .7, .7, .9])
    with c1:
        symbol = st.selectbox("종목 선택", opts or [default_symbol], index=0, key=f"v41_flow_symbol_{market}")
    with c2:
        period_label = st.selectbox("조회 기간", ["3개월", "6개월", "1년", "2년"], index=1, key=f"v41_flow_period_{market}")
    with c3:
        candle_mode = st.selectbox("봉 기준", ["일봉", "주봉", "월봉"], index=0, key=f"v41_flow_candle_{market}")
    with c4:
        show_pivots = st.checkbox("최근 고점/저점 표시", value=False, key=f"v41_show_pivots_{market}", help="기본은 꺼두었습니다. 켜도 최근 고점 1개·저점 1개만 표시합니다.")

    raw_symbol = str(symbol or default_symbol).strip()
    ticker = normalize_ticker(korean_symbol_from_name(raw_symbol), market) if market == "한국주식" else display_symbol(raw_symbol, "미국주식")
    years = {"3개월": 0.25, "6개월": 0.5, "1년": 1.0, "2년": 2.0}.get(period_label, 0.5)
    with st.spinner(f"{ticker} 차트 불러오는 중..."):
        chart_df = _load_stock_data_for_chart_cached(ticker, market, years)
    if chart_df is None or chart_df.empty or len(chart_df) < 5:
        st.warning("차트 데이터를 불러오지 못했습니다. 아래 저장 리포트는 확인할 수 있습니다.")
    else:
        try:
            chart_df = calculate_indicators(chart_df)
        except Exception:
            pass
        plot_df = chart_df.copy()
        try:
            if candle_mode == "주봉":
                plot_df = plot_df.set_index(pd.to_datetime(plot_df["Date"])).resample("W-FRI").agg({"Open":"first", "High":"max", "Low":"min", "Close":"last", "Volume":"sum"}).dropna().reset_index().rename(columns={"index":"Date"})
                plot_df = calculate_indicators(plot_df)
            elif candle_mode == "월봉":
                plot_df = plot_df.set_index(pd.to_datetime(plot_df["Date"])).resample("M").agg({"Open":"first", "High":"max", "Low":"min", "Close":"last", "Volume":"sum"}).dropna().reset_index().rename(columns={"index":"Date"})
                plot_df = calculate_indicators(plot_df)
        except Exception:
            pass
        fig = go.Figure()
        fig.add_trace(go.Candlestick(
            x=plot_df["Date"], open=plot_df["Open"], high=plot_df["High"], low=plot_df["Low"], close=plot_df["Close"],
            name=str(ticker), increasing_line_color="#ef5350", decreasing_line_color="#26a69a",
        ))
        for ma in ["MA10", "MA20", "MA60", "MA120", "MA200"]:
            if ma in plot_df.columns:
                fig.add_trace(go.Scatter(x=plot_df["Date"], y=plot_df[ma], mode="lines", name=ma, line=dict(width=1.15)))
        if show_pivots:
            _add_swing_markers_to_fig_v21(fig, plot_df, market, use_subplots=False)
        fig.update_layout(
            title=dict(text=f"{ticker} · {period_label} · {candle_mode}", x=0.01, xanchor="left", y=0.98, yanchor="top"),
            template="plotly_dark", height=540, margin=dict(l=10, r=34, t=92, b=26),
            xaxis=dict(rangeslider=dict(visible=False), automargin=True), yaxis=dict(side="right", automargin=True),
            legend=dict(orientation="h", yanchor="bottom", y=1.05, xanchor="left", x=0),
        )
        st.plotly_chart(fig, use_container_width=True, config={"displayModeBar": False, "scrollZoom": False})
        try:
            render_chart_trade_levels_box(ticker, market, chart_df)
            _render_chart_technical_signal_panel_v21(ticker, market, chart_df)
        except Exception:
            pass

    st.markdown('<div class="mode-section-title">선택 종목 수급·호가·현재가 요약</div>', unsafe_allow_html=True)
    pack = build_selected_symbol_flow(market, ticker)
    _v37_render_table(pack.get("summary"), empty="저장된 장중 수급/호가 리포트가 없습니다. run_intraday_refresh를 실행하면 채워집니다.", limit=10)
    with st.expander("상세 원본 보기 — 필요할 때만", expanded=False):
        for title, key in [("후보/기준가", "candidate"), ("현재가", "quote"), ("호가", "orderbook"), ("수급", "flow"), ("업종", "sector")]:
            st.markdown(f"**{title}**")
            _v37_render_table(pack.get(key), empty=f"{title} 데이터 없음", limit=20)


def _v41_load_risk_candidates(market: str) -> pd.DataFrame:
    """Merge no-buy/chase/risk candidates into a single user-facing table."""
    try:
        from core.operational_plus_engine import load_candidate_pool
        df = load_candidate_pool(market, include_c=True)
    except Exception:
        df = pd.DataFrame()
    if df is None or df.empty:
        return pd.DataFrame()
    rows = []
    for _, r in df.iterrows():
        joined = " ".join(str(r.get(c, "")) for c in [
            "final_decision", "risk_final_decision", "grade", "exclude_reason", "hard_filter_reason",
            "aggressive_warnings", "trade_fit_warnings", "catalyst_warnings", "reason", "주의사유",
            "chase_risk", "intraday_chase_risk", "price_overheat_label", "no_buy_level",
        ] if c in r.index)
        risk_words = "추격|과열|고점|금지|제외|관망|주의|손절|리스크|손익비|대기"
        if not re.search(risk_words, joined):
            continue
        symbol = str(r.get("symbol", r.get("ticker", r.get("종목코드", r.get("종목", "-"))))).upper()
        name = r.get("name", r.get("종목명", r.get("company", "-")))
        risk_type = "주의"
        if re.search("금지|제외", joined):
            risk_type = "신규매수 제외"
        elif re.search("추격|과열|고점", joined):
            risk_type = "추격매수 위험"
        elif re.search("손익비|손절", joined):
            risk_type = "손익비/손절 확인"
        elif re.search("관망|대기", joined):
            risk_type = "관망/대기"
        rows.append({
            "종목코드": symbol,
            "종목명": name,
            "위험 구분": risk_type,
            "초보자 해석": "지금 바로 매수하기보다 가격·손익비·뉴스를 다시 확인해야 합니다.",
            "핵심 사유": re.sub(r"\s+", " ", joined).strip()[:220] or "위험 조건 확인 필요",
            "권장 행동": "신규매수 보류" if risk_type == "신규매수 제외" else "진입가 대기/분할만 검토",
        })
    out = pd.DataFrame(rows)
    if not out.empty:
        out = out.drop_duplicates(subset=["종목코드", "위험 구분"], keep="first")
    return out


def render_v41_buy_risk_page() -> None:
    market = _v37_market("v41_buy_risk")
    inject_native_graft_css()
    _render_nav_page_title("매수 위험·제외")
    st.caption("추격매수 위험, 매수금지, 신규매수 주의, 손익비 부족을 하나로 합친 화면입니다. 같은 내용을 여러 메뉴에서 중복 표시하지 않습니다.")
    df = _v41_load_risk_candidates(market)
    if df is None or df.empty:
        st.info("현재 저장 리포트 기준으로 매수 위험 후보가 없습니다. 단, 장전 업데이트 전이면 아직 계산되지 않은 상태일 수 있습니다.")
        with st.expander("왜 0개로 보일 수 있나요?", expanded=False):
            st.markdown("""
- 후보 리포트가 아직 생성되지 않은 경우
- A/B/C 스윙 후보 파일이 비어 있는 경우
- 위험 조건 컬럼명이 외부 데이터와 달라 아직 매칭되지 않은 경우
- 시장이 장외라 호가/수급 데이터가 부족한 경우

이 화면은 가짜 위험 후보를 만들지 않습니다. 대신 저장 리포트에 위험 사유가 있으면 한곳에 모아서 보여줍니다.
            """)
        return
    c1, c2, c3 = st.columns(3)
    c1.metric("전체 위험 후보", len(df))
    c2.metric("신규매수 제외", int(df["위험 구분"].astype(str).str.contains("제외", na=False).sum()))
    c3.metric("추격매수 위험", int(df["위험 구분"].astype(str).str.contains("추격", na=False).sum()))
    _v37_render_table(df, empty="매수 위험 후보가 없습니다.", limit=120)


