    for _, r in df.head(20).iterrows():
        _v60_card(str(r.get("제목", "뉴스 제목 없음")), str(r.get("매매 영향", "확인")), f"{r.get('요약','-')}<br><br>출처: {r.get('출처','-')}", str(r.get("초보자 해석", "가격·수급과 함께 확인하세요.")))

